INSERT INTO `source` VALUES
('24f0e0c6-3ff7-47f2-a4b4-0002071b960f','Deleting by ID list is generally faster when you know exactly which documents to remove.\nFilter-based deletion may require scanning the index to find matching documents; however, this is vector store implementation-specific.\nLarge deletion operations should be batched to avoid overwhelming the system.\nConsider using filter expressions when deleting based on document properties rather than collecting IDs first.',0x00,'asciidoc::vectordbs.adoc::Deleting Documents from Vector Store::Performance Considerations While Deleting Documents::0'),
('a126660c-cd43-4ec7-b34b-004913f1d30a','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/api/OpenAiApiIT.java\">OpenAiApiIT.java</a> tests provide some general examples of how to use the lightweight library.\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/api/tool/OpenAiApiToolFunctionCallIT.java\">OpenAiApiToolFunctionCallIT.java</a> tests show how to use the low-level API to call tool functions.\nBased on the <a href=\"https://platform.openai.com/docs/guides/function-calling/parallel-function-calling\">OpenAI Function Calling</a> tutorial.',0x00,'asciidoc::openai-chat.adoc::Low-level OpenAiApi Client::Low-level API Examples::0'),
('264f5833-80c8-4fb5-9678-0079a2ce2d40','Add the following dependency in your Maven project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-azure-cosmos-db-store&lt;/artifactId&gt;\n&lt;/dependency&gt;',0x00,'asciidoc::azure-cosmos-db.adoc::Manual Dependency Setup::0'),
('db133bf8-4a03-4da8-9acc-009ce25308a3','Removed inter-package dependency cycles in spring-ai-model (<a href=\"https://github.com/spring-projects/spring-ai/commit/ebfa5b9b2cc2ab0d20e25dc6128c4b1c9c327f89\">ebfa5b9</a>)\nMoved MessageAggregator to spring-ai-model module (<a href=\"https://github.com/spring-projects/spring-ai/commit/54e5c07428909ceec248e3bbd71e2df4b0812e49\">54e5c07</a>)\n\n\nDependencies\n\nRemoved unused json-path dependency in spring-ai-openai (<a href=\"https://github.com/spring-projects/spring-ai/commit/9de13d1b2fdb67219dc7afbf319ade789784f2b9\">9de13d1</a>)',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M8::Removed Implementations and APIs::1'),
('f3a91580-0e4e-4f43-b1a9-00badd3d17d5','To connect to MongoDB Atlas and use the <code>MongoDBAtlasVectorStore</code>, you need to provide access details for your instance.\nA simple configuration can be provided via Spring Boot&#8217;s <code>application.yml</code>:\n\nspring:\n  data:\n    mongodb:\n      uri: &lt;mongodb atlas connection string&gt;\n      database: &lt;database name&gt;\n  ai:\n    vectorstore:\n      mongodb:\n        initialize-schema: true\n        collection-name: custom_vector_store\n        index-name: custom_vector_index\n        path-name: custom_embedding\n        metadata-fields-to-filter: author,year\n\nProperties starting with <code>spring.ai.vectorstore.mongodb.*</code> are used to configure the <code>MongoDBAtlasVectorStore</code>:',0x00,'asciidoc::mongodb.adoc::Auto-configuration::Configuration Properties::0'),
('d8cd482d-c215-4d8e-955c-00cd78c9c152','/**\n * Retrieves documents from a vector store that are semantically similar to the input\n * query. It supports filtering based on metadata, similarity threshold, and top-k\n * results.\n *\n * <p>\n * Example usage: <pre>{@code\n * VectorStoreDocumentRetriever retriever = VectorStoreDocumentRetriever.builder()\n *     .vectorStore(vectorStore)\n *     .similarityThreshold(0.73)\n *     .topK(5)\n *     .filterExpression(filterExpression)\n *     .build();\n * List<Document> documents = retriever.retrieve(new Query(\"example query\"));\n * }</pre>\n *\n * <p>\n * The {@link #FILTER_EXPRESSION} context key can be used to provide a filter expression\n * for a specific query. This key accepts either a string representation of a filter\n * expression or a {@link Filter.Expression} object directly.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic final class VectorStoreDocumentRetriever implements DocumentRetriever {\n\n    public static final String FILTER_EXPRESSION = \"vector_store_filter_expression\";\n\n    private final VectorStore vectorStore;\n\n    private final Double similarityThreshold;\n\n    private final Integer topK;\n\n    // Supplier to allow for lazy evaluation of the filter expression,\n    // which may depend on the execution content. For example, you may want to\n    // filter dynamically based on the current user\'s identity or tenant ID.\n    private final Supplier<Filter.Expression> filterExpression;\n\n    public VectorStoreDocumentRetriever(VectorStore vectorStore, @Nullable Double similarityThreshold, @Nullable Integer topK, @Nullable Supplier<Filter.Expression> filterExpression) {\n        Assert.notNull(vectorStore, \"vectorStore cannot be null\");\n        Assert.isTrue(similarityThreshold == null || similarityThreshold >= 0.0, \"similarityThreshold must be equal to or greater than 0.0\");\n        Assert.isTrue(topK == null || topK > 0, \"topK must be greater than 0\");\n        this.vectorStore = vectorStore;\n        this.similarityThreshold = similarityThreshold != null ? similarityThreshold : SearchRequest.SIMILARITY_THRESHOLD_ACCEPT_ALL;\n        this.topK = topK != null ? topK : SearchRequest.DEFAULT_TOP_K;\n        this.filterExpression = filterExpression != null ? filterExpression : () -> null;\n    }\n\n    @Override\n    public List<Document> retrieve(Query query) {\n        Assert.notNull(query, \"query cannot be null\");\n        var requestFilterExpression = computeRequestFilterExpression(query);\n        var searchRequest = SearchRequest.builder().query(query.text()).filterExpression(requestFilterExpression).similarityThreshold(this.similarityThreshold).topK(this.topK).build();\n        return this.vectorStore.similaritySearch(searchRequest);\n    }\n\n    /**\n     * Computes the filter expression to use for the current request.\n     * <p>\n     * The filter expression can be provided in the query context using the\n     * {@link #FILTER_EXPRESSION} key. This key accepts either a string representation of\n     * a filter expression or a {@link Filter.Expression} object directly.\n     * <p>\n     * If no filter expression is provided in the context, the default filter expression\n     * configured for this retriever is used.\n     * @param query the query containing potential context with filter expression\n     * @return the filter expression to use for the request\n     */\n    private Filter.Expression computeRequestFilterExpression(Query query) {\n        var contextFilterExpression = query.context().get(FILTER_EXPRESSION);\n        if (contextFilterExpression != null) {\n            if (contextFilterExpression instanceof Filter.Expression) {\n                return (Filter.Expression) contextFilterExpression;\n            } else if (StringUtils.hasText(contextFilterExpression.toString())) {\n                return new FilterExpressionTextParser().parse(contextFilterExpression.toString());\n            }\n        }\n        return this.filterExpression.get();\n    }\n\n    public static Builder builder() {\n        return new Builder();\n    }\n\n    /**\n     * Builder for {@link VectorStoreDocumentRetriever}.\n     */\n    public static final class Builder {\n\n        private VectorStore vectorStore;\n\n        private Double similarityThreshold;\n\n        private Integer topK;\n\n        private Supplier<Filter.Expression> filterExpression;\n\n        private Builder() {\n        }\n\n        public Builder vectorStore(VectorStore vectorStore) {\n            this.vectorStore = vectorStore;\n            return this;\n        }\n\n        public Builder similarityThreshold(Double similarityThreshold) {\n            this.similarityThreshold = similarityThreshold;\n            return this;\n        }\n\n        public Builder topK(Integer topK) {\n            this.topK = topK;\n            return this;\n        }\n\n        public Builder filterExpression(Filter.Expression filterExpression) {\n            this.filterExpression = () -> filterExpression;\n            return this;\n        }\n\n        public Builder filterExpression(Supplier<Filter.Expression> filterExpression) {\n            this.filterExpression = filterExpression;\n            return this;\n        }\n\n        public VectorStoreDocumentRetriever build() {\n            return new VectorStoreDocumentRetriever(this.vectorStore, this.similarityThreshold, this.topK, this.filterExpression);\n        }\n    }\n}',0x01,'cu::VectorStoreDocumentRetriever.java'),
('49f774a4-34b2-4858-9ffb-00d8607a3ce8','The ChatClient fluent API provides an <code>AdvisorSpec</code> interface for configuring advisors.\nThis interface offers methods to add parameters, set multiple parameters at once, and add one or more advisors to the chain.\n\ninterface AdvisorSpec {\n    AdvisorSpec param(String k, Object v);\n    AdvisorSpec params(Map&lt;String, Object&gt; p);\n    AdvisorSpec advisors(Advisor... advisors);\n    AdvisorSpec advisors(List&lt;Advisor&gt; advisors);\n}\n\nThe order in which advisors are added to the chain is crucial, as it determines the sequence of their execution.\nEach advisor modifies the prompt or the context in some way, and the changes made by one advisor are passed on to the next in the chain.\n\nChatClient.builder(chatModel)\n    .build()\n    .prompt()\n    .advisors(\n        MessageChatMemoryAdvisor.builder(chatMemory).build(),\n        QuestionAnswerAdvisor.builder(vectorStore).build()\n    )\n    .user(userText)\n    .call()\n    .content();\n\nIn this configuration, the <code>MessageChatMemoryAdvisor</code> will be executed first, adding the conversation history to the prompt.\nThen, the <code>QuestionAnswerAdvisor</code> will perform its search based on the user&#8217;s question and the added conversation history, potentially providing more relevant results.\n\n<a href=\"ROOT:api/retrieval-augmented-generation.html#_questionansweradvisor\">Learn about Question Answer Advisor</a>',0x00,'asciidoc::chatclient.adoc::Advisors::Advisor Configuration in ChatClient::0'),
('4cfe34cc-2a31-4735-b7fb-00ee353230e4','If you&#8217;re currently using the Vertex AI Text Embeddings implementation (<code>spring-ai-vertex-ai-embedding</code>), you can migrate to Google GenAI with minimal changes:',0x00,'asciidoc::google-genai-embeddings-text.adoc::Migration from Vertex AI Text Embeddings::0'),
('534ed923-facc-4182-8d21-01091fb2bf52','The <code>ChatClient</code> is created using a <code>ChatClient.Builder</code> object.\nYou can obtain an autoconfigured <code>ChatClient.Builder</code> instance for any <a href=\"api/chatmodel.html\">ChatModel</a> Spring Boot autoconfiguration or create one programmatically.',0x00,'asciidoc::chatclient.adoc::Creating a ChatClient::0'),
('f5369bcc-0ba4-42b7-bf0f-011c526ed1d0','Instead of using the Spring Boot auto-configuration, you can manually configure the MariaDB vector store.\nFor this you need to add the following dependencies to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-boot-starter-jdbc&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.mariadb.jdbc&lt;/groupId&gt;\n    &lt;artifactId&gt;mariadb-java-client&lt;/artifactId&gt;\n    &lt;scope&gt;runtime&lt;/scope&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-mariadb-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThen create the <code>MariaDBVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore vectorStore(JdbcTemplate jdbcTemplate, EmbeddingModel embeddingModel) {\n    return MariaDBVectorStore.builder(jdbcTemplate, embeddingModel)\n        .dimensions(1536)                      // Optional: defaults to 1536\n        .distanceType(MariaDBDistanceType.COSINE) // Optional: defaults to COSINE\n        .schemaName(\"mydb\")                    // Optional: defaults to null\n        .vectorTableName(\"custom_vectors\")     // Optional: defaults to \"vector_store\"\n        .contentFieldName(\"text\")             // Optional: defaults to \"content\"\n        .embeddingFieldName(\"embedding\")      // Optional: defaults to \"embedding\"\n        .idFieldName(\"doc_id\")                // Optional: defaults to \"id\"\n        .metadataFieldName(\"meta\")           // Optional: defaults to \"metadata\"\n        .initializeSchema(true)               // Optional: defaults to false\n        .schemaValidation(true)              // Optional: defaults to false\n        .removeExistingVectorStoreTable(false) // Optional: defaults to false\n        .maxDocumentBatchSize(10000)         // Optional: defaults to 10000\n        .build();\n}\n\n// This can be any EmbeddingModel implementation\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}',0x00,'asciidoc::mariadb.adoc::Manual Configuration::0'),
('c0998010-3804-4cad-9e47-0170c2a7b9c4','/**\n * A component for augmenting an input query with additional data, useful to provide a\n * large language model with the necessary context to answer the user query.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic interface QueryAugmenter extends BiFunction<Query, List<Document>, Query> {\n\n    /**\n     * Augments the user query with contextual data.\n     * @param query The user query to augment\n     * @param documents The contextual data to use for augmentation\n     * @return The augmented query\n     */\n    Query augment(Query query, List<Document> documents);\n\n    default Query apply(Query query, List<Document> documents) {\n        return augment(query, documents);\n    }\n}',0x01,'cu::QueryAugmenter.java'),
('3b11d6ee-5786-4c99-9655-0171ba3153ae','You can turn a method into a tool by building a <code>MethodToolCallback</code> programmatically.\n\nclass DateTimeTools {\n\n    String getCurrentDateTime() {\n        return LocalDateTime.now().atZone(LocaleContextHolder.getTimeZone().toZoneId()).toString();\n    }\n\n}\n\nThe <code>MethodToolCallback.Builder</code> allows you to build a <code>MethodToolCallback</code> instance and provide key information about the tool:\n\n<code>toolDefinition</code>: The <code>ToolDefinition</code> instance that defines the tool name, description, and input schema. You can build it using the <code>ToolDefinition.Builder</code> class. Required.\n<code>toolMetadata</code>: The <code>ToolMetadata</code> instance that defines additional settings such as whether the result should be returned directly to the client, and the result converter to use. You can build it using the <code>ToolMetadata.Builder</code> class.\n<code>toolMethod</code>: The <code>Method</code> instance that represents the tool method. Required.\n<code>toolObject</code>: The object instance that contains the tool method. If the method is static, you can omit this parameter.\n<code>toolCallResultConverter</code>: The <code>ToolCallResultConverter</code> instance to use for converting the result of a tool call to a <code>String</code> object to send back to the AI model. If not provided, the default converter will be used (<code>DefaultToolCallResultConverter</code>).\n\n\nThe <code>ToolDefinition.Builder</code> allows you to build a <code>ToolDefinition</code> instance and define the tool name, description, and input schema:\n\n<code>name</code>: The name of the tool. If not provided, the method name will be used. AI models use this name to identify the tool when calling it. Therefore, it&#8217;s not allowed to have two tools with the same name in the same class. The name must be unique across all the tools available to the model for a specific chat request.\n<code>description</code>: The description for the tool, which can be used by the model to understand when and how to call the tool. If not provided, the method name will be used as the tool description. However, it&#8217;s strongly recommended to provide a detailed description because that&#8217;s paramount for the model to understand the tool&#8217;s purpose and how to use it. Failing in providing a good description can lead to the model not using the tool when it should or using it incorrectly.\n<code>inputSchema</code>: The JSON schema for the input parameters of the tool. If not provided, the schema will be generated automatically based on the method parameters. You can use the <code>@ToolParam</code> annotation to provide additional information about the input parameters, such as a description or whether the parameter is required or optional. By default, all input parameters are considered required. See <a href=\"#_json_schema\">JSON Schema</a> for more details.',0x00,'asciidoc::tools.adoc::Methods as Tools::Programmatic Specification: <code>MethodToolCallback</code>::0'),
('099091a9-dd0e-4a7f-ab2b-018a8fd34a08','OpenAI provides two mutually exclusive parameters for controlling token generation limits:\n\n\n\nThese parameters are <strong>mutually exclusive</strong>. Setting both will result in an API error from OpenAI.\n\nUsage Examples\n\n<strong>For non-reasoning models (gpt-4o, gpt-3.5-turbo):</strong>\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Explain quantum computing in simple terms.\",\n        OpenAiSdkChatOptions.builder()\n            .model(\"gpt-4o\")\n            .maxTokens(150)  // Use maxTokens for non-reasoning models\n        .build()\n    ));\n\n<strong>For reasoning models (o1, o3 series):</strong>\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Solve this complex math problem step by step: ...\",\n        OpenAiSdkChatOptions.builder()\n            .model(\"o1-preview\")\n            .maxCompletionTokens(1000)  // Use maxCompletionTokens for reasoning models\n        .build()\n    ));',0x00,'asciidoc::openai-sdk-chat.adoc::Auto-configuration::Token Limit Parameters: Model-Specific Usage::0'),
('40ba8822-d634-47fb-9c9a-01d4b0358f16','<div class=\"paragraph\">\n<p>This guide helps you migrate from the deprecated <code>FunctionCallback</code> API to the new <code>ToolCallback</code> API in Spring AI. For more information about the new APIs, check out the <a href=\"api/tools.html\">Tools Calling</a> documentation.</p>\n</div>',0x00,'asciidoc::tools-migration.adoc::0'),
('21ffd714-124e-40f1-9ead-026a8d44f95b','<div class=\"paragraph\">\n<p>Embeddings are numerical representations of text, images, or videos that capture relationships between inputs.</p>\n</div>\n<div class=\"paragraph\">\n<p>Embeddings work by converting text, image, and video into arrays of floating point numbers, called vectors.\nThese vectors are designed to capture the meaning of the text, images, and videos.\nThe length of the embedding array is called the vector&#8217;s dimensionality.</p>\n</div>\n<div class=\"paragraph\">\n<p>By calculating the numerical distance between the vector representations of two pieces of text, an application can determine the similarity between the objects used to generate the embedding vectors.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <code>EmbeddingModel</code> interface is designed for straightforward integration with embedding models in AI and machine learning.\nIts primary function is to convert text into numerical vectors, commonly referred to as embeddings.\nThese embeddings are crucial for various tasks such as semantic analysis and text classification.</p>\n</div>\n<div class=\"paragraph\">\n<p>The design of the EmbeddingModel interface centers around two primary goals:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p><strong>Portability</strong>: This interface ensures easy adaptability across various embedding models.\nIt allows developers to switch between different embedding techniques or models with minimal code changes.\nThis design aligns with Spring&#8217;s philosophy of modularity and interchangeability.</p>\n</li>\n<li>\n<p><strong>Simplicity</strong>: EmbeddingModel simplifies the process of converting text to embeddings.\nBy providing straightforward methods like <code>embed(String text)</code> and <code>embed(Document document)</code>, it takes the complexity out of dealing with raw text data and embedding algorithms. This design choice makes it easier for developers, especially those new to AI, to utilize embeddings in their applications without delving deep into the underlying mechanics.</p>\n</li>\n</ul>\n</div>',0x00,'asciidoc::embeddings.adoc::0'),
('07176554-4719-4cd8-9669-029e6c2d6062','To connect to OpenSearch and use the <code>OpenSearchVectorStore</code>, you need to provide access details for your instance.\nA simple configuration can be provided via Spring Boot&#8217;s <code>application.yml</code>:\n\nspring:\n  ai:\n    vectorstore:\n      opensearch:\n        uris: &lt;opensearch instance URIs&gt;\n        username: &lt;opensearch username&gt;\n        password: &lt;opensearch password&gt;\n        index-name: spring-ai-document-index\n        initialize-schema: true\n        similarity-function: cosinesimil\n        read-timeout: &lt;time to wait for response&gt;\n        connect-timeout: &lt;time to wait until connection established&gt;\n        path-prefix: &lt;custom path prefix&gt;\n        ssl-bundle: &lt;name of SSL bundle&gt;\n        aws:  # Only for Amazon OpenSearch Service\n          host: &lt;aws opensearch host&gt;\n          service-name: &lt;aws service name&gt;\n          access-key: &lt;aws access key&gt;\n          secret-key: &lt;aws secret key&gt;\n          region: &lt;aws region&gt;\n\nProperties starting with <code>spring.ai.vectorstore.opensearch.*</code> are used to configure the <code>OpenSearchVectorStore</code>:\n\n\n\n<div class=\"paragraph\">\n<p>You can control whether the AWS-specific OpenSearch auto-configuration is enabled using the <code>spring.ai.vectorstore.opensearch.aws.enabled</code> property.</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p>If this property is set to <code>false</code>, the non-AWS OpenSearch configuration is activated, even if AWS SDK classes are present on the classpath. This allows you to use self-managed or third-party OpenSearch clusters in environments where AWS SDKs are present for other services.</p>\n</li>\n<li>\n<p>If AWS SDK classes are not present, the non-AWS configuration is always used.</p>\n</li>\n<li>\n<p>If AWS SDK classes are present and the property is not set or set to <code>true</code>, the AWS-specific configuration is used by default.</p>\n</li>\n</ul>\n</div>\n<div class=\"paragraph\">\n<p>This fallback logic ensures that users have explicit control over the type of OpenSearch integration, preventing accidental activation of AWS-specific logic when not desired.</p>\n</div>\n\n<div class=\"paragraph\">\n<p>The <code>path-prefix</code> property allows you to specify a custom path prefix when OpenSearch is running behind a reverse proxy that uses a non-root path.\nFor example, if your OpenSearch instance is accessible at <code><a href=\"https://example.com/opensearch/\" class=\"bare\">https://example.com/opensearch/</a></code> instead of <code><a href=\"https://example.com/\" class=\"bare\">https://example.com/</a></code>, you would set <code>path-prefix: /opensearch</code>.</p>\n</div>\n\nThe following similarity functions are available:\n\n<code>cosinesimil</code> - Default, suitable for most use cases. Measures cosine similarity between vectors.\n<code>l1</code> - Manhattan distance between vectors.\n<code>l2</code> - Euclidean distance between vectors.\n<code>linf</code> - Chebyshev distance between vectors.',0x00,'asciidoc::opensearch.adoc::Auto-configuration::Configuration Properties::0'),
('8ebe1cc1-bc97-4cb2-940b-0399812736e7','A Redis Stack instance\n<code>EmbeddingModel</code> instance to compute the document embeddings. Several options are available:',0x00,'asciidoc::redis.adoc::Prerequisites::0'),
('ce1a0def-45ac-4296-abd8-039fc200bb6e','Here&#8217;s a complete example demonstrating prompt caching with cost tracking:\n\n// Create system content that will be reused multiple times\nString largeSystemPrompt = \"You are an expert software architect specializing in distributed systems...\";\n// (Ensure this is 1024+ tokens for cache effectiveness)\n\n// First request - creates cache\nChatResponse firstResponse = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(largeSystemPrompt),\n            new UserMessage(\"What is microservices architecture?\")\n        ),\n        BedrockChatOptions.builder()\n            .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(500)\n            .build()\n    )\n);\n\n// Access cache-related token usage from metadata\nInteger cacheWrite1 = (Integer) firstResponse.getMetadata()\n    .getMetadata()\n    .get(\"cacheWriteInputTokens\");\nInteger cacheRead1 = (Integer) firstResponse.getMetadata()\n    .getMetadata()\n    .get(\"cacheReadInputTokens\");\n\nSystem.out.println(\"Cache creation tokens: \" + cacheWrite1);\nSystem.out.println(\"Cache read tokens: \" + cacheRead1);\n\n// Second request with same system prompt - reads from cache\nChatResponse secondResponse = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(largeSystemPrompt),  // Same prompt - cache hit\n            new UserMessage(\"What are the benefits of event sourcing?\")\n        ),\n        BedrockChatOptions.builder()\n            .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(500)\n            .build()\n    )\n);\n\nInteger cacheWrite2 = (Integer) secondResponse.getMetadata()\n    .getMetadata()\n    .get(\"cacheWriteInputTokens\");\nInteger cacheRead2 = (Integer) secondResponse.getMetadata()\n    .getMetadata()\n    .get(\"cacheReadInputTokens\");\n\nSystem.out.println(\"Cache creation tokens: \" + cacheWrite2); // Should be 0\nSystem.out.println(\"Cache read tokens: \" + cacheRead2);      // Should be &gt; 0',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Usage Example::0'),
('4b086d9a-936e-4cb6-b75d-03d154ac4b42','/**\n * AbstractFilterExpressionConverter is an abstract class that implements the\n * FilterExpressionConverter interface. It provides default implementations for converting\n * a Filter.Expression into a string representation. All specific filter expression\n * converters should extend this abstract class and implement the remaining abstract\n * methods. Note: The class cannot be directly instantiated as it is abstract.\n *\n * @author Christian Tzolov\n */\npublic abstract class AbstractFilterExpressionConverter implements FilterExpressionConverter {\n\n    /**\n     * Create a new AbstractFilterExpressionConverter.\n     */\n    public AbstractFilterExpressionConverter() {\n    }\n\n    @Override\n    public String convertExpression(Expression expression) {\n        return this.convertOperand(expression);\n    }\n\n    /**\n     * Convert the given operand into a string representation.\n     * @param operand the operand to convert\n     * @return the string representation of the operand\n     */\n    protected String convertOperand(Operand operand) {\n        var context = new StringBuilder();\n        this.convertOperand(operand, context);\n        return context.toString();\n    }\n\n    /**\n     * Convert the given operand into a string representation.\n     * @param operand the operand to convert\n     * @param context the context to append the string representation to\n     */\n    protected void convertOperand(Operand operand, StringBuilder context) {\n        if (operand instanceof Filter.Group group) {\n            this.doGroup(group, context);\n        } else if (operand instanceof Filter.Key key) {\n            this.doKey(key, context);\n        } else if (operand instanceof Filter.Value value) {\n            this.doValue(value, context);\n        } else if (operand instanceof Filter.Expression expression) {\n            if ((expression.type() != ExpressionType.NOT && expression.type() != ExpressionType.AND && expression.type() != ExpressionType.OR) && !(expression.right() instanceof Filter.Value)) {\n                throw new RuntimeException(\"Non AND/OR expression must have Value right argument!\");\n            }\n            if (expression.type() == ExpressionType.NOT) {\n                this.doNot(expression, context);\n            } else {\n                this.doExpression(expression, context);\n            }\n        }\n    }\n\n    /**\n     * Convert the given expression into a string representation.\n     * @param expression the expression to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doNot(Filter.Expression expression, StringBuilder context) {\n        // Default behavior is to convert the NOT expression into its semantically\n        // equivalent negation expression.\n        // Effectively removing the NOT types form the boolean expression tree before\n        // passing it to the doExpression.\n        this.convertOperand(FilterHelper.negate(expression), context);\n    }\n\n    /**\n     * Convert the given expression into a string representation.\n     * @param expression the expression to convert\n     * @param context the context to append the string representation to\n     */\n    protected abstract void doExpression(Filter.Expression expression, StringBuilder context);\n\n    /**\n     * Convert the given key into a string representation.\n     * @param filterKey the key to convert\n     * @param context the context to append the string representation to\n     */\n    protected abstract void doKey(Filter.Key filterKey, StringBuilder context);\n\n    /**\n     * Convert the given value into a string representation.\n     * @param filterValue the value to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doValue(Filter.Value filterValue, StringBuilder context) {\n        if (filterValue.value() instanceof List list) {\n            doStartValueRange(filterValue, context);\n            int c = 0;\n            for (Object v : list) {\n                this.doSingleValue(v, context);\n                if (c++ < list.size() - 1) {\n                    this.doAddValueRangeSpitter(filterValue, context);\n                }\n            }\n            this.doEndValueRange(filterValue, context);\n        } else {\n            this.doSingleValue(filterValue.value(), context);\n        }\n    }\n\n    /**\n     * Convert the given value into a string representation.\n     * @param value the value to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doSingleValue(Object value, StringBuilder context) {\n        if (value instanceof String) {\n            context.append(String.format(\"\\\"%s\\\"\", value));\n        } else {\n            context.append(value);\n        }\n    }\n\n    /**\n     * Convert the given group into a string representation.\n     * @param group the group to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doGroup(Group group, StringBuilder context) {\n        this.doStartGroup(group, context);\n        this.convertOperand(group.content(), context);\n        this.doEndGroup(group, context);\n    }\n\n    /**\n     * Convert the given group into a string representation.\n     * @param group the group to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doStartGroup(Group group, StringBuilder context) {\n    }\n\n    /**\n     * Convert the given group into a string representation.\n     * @param group the group to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doEndGroup(Group group, StringBuilder context) {\n    }\n\n    /**\n     * Convert the given value range into a string representation.\n     * @param listValue the value range to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doStartValueRange(Filter.Value listValue, StringBuilder context) {\n        context.append(\"[\");\n    }\n\n    /**\n     * Convert the given value range into a string representation.\n     * @param listValue the value range to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doEndValueRange(Filter.Value listValue, StringBuilder context) {\n        context.append(\"]\");\n    }\n\n    /**\n     * Convert the given value range into a string representation.\n     * @param listValue the value range to convert\n     * @param context the context to append the string representation to\n     */\n    protected void doAddValueRangeSpitter(Filter.Value listValue, StringBuilder context) {\n        context.append(\",\");\n    }\n\n    // Utilities\n    /**\n     * Check if the given string has outer quotes.\n     * @param str the string to check\n     * @return true if the string has outer quotes, false otherwise\n     */\n    protected boolean hasOuterQuotes(String str) {\n        str = str.trim();\n        return (str.startsWith(\"\\\"\") && str.endsWith(\"\\\"\")) || (str.startsWith(\"\'\") && str.endsWith(\"\'\"));\n    }\n\n    /**\n     * Remove the outer quotes from the given string.\n     * @param in the string to remove the outer quotes from\n     * @return the string without the outer quotes\n     */\n    protected String removeOuterQuotes(String in) {\n        return in.substring(1, in.length() - 1);\n    }\n}',0x01,'cu::AbstractFilterExpressionConverter.java'),
('b4562551-3cdc-4da2-a22b-054b2f1e72ba','The vector database&#8217;s role is to store and facilitate similarity searches for these embeddings. It does not generate the embeddings itself. For creating vector embeddings, the <code>EmbeddingModel</code> should be utilized.\n\nThe <code>similaritySearch</code> methods in the interface allow for retrieving documents similar to a given query string. These methods can be fine-tuned by using the following parameters:\n\n<code>k</code>: An integer that specifies the maximum number of similar documents to return. This is often referred to as a \'top K\' search, or \'K nearest neighbors\' (KNN).\n<code>threshold</code>: A double value ranging from 0 to 1, where values closer to 1 indicate higher similarity. By default, if you set a threshold of 0.75, for instance, only documents with a similarity above this value are returned.\n<code>Filter.Expression</code>: A class used for passing a fluent DSL (Domain-Specific Language) expression that functions similarly to a \'where\' clause in SQL, but it applies exclusively to the metadata key-value pairs of a <code>Document</code>.\n<code>filterExpression</code>: An external DSL based on ANTLR4 that accepts filter expressions as strings. For example, with metadata keys like country, year, and <code>isActive</code>, you could use an expression such as: <code>country == \'UK\' &amp;&amp; year &gt;= 2020 &amp;&amp; isActive == true.</code>\n\n\nFind more information on the <code>Filter.Expression</code> in the <a href=\"#metadata-filters\">Metadata Filters</a> section.',0x00,'asciidoc::vectordbs.adoc::API Overview::SearchRequest Builder::1'),
('ca43a8eb-29d7-4c5e-a1bd-05d628dd81b8','<div class=\"paragraph\">\n<p>This section walks you through setting up the Elasticsearch <code>VectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://www.elastic.co/elasticsearch\">Elasticsearch</a> is an open source search and analytics engine based on the Apache Lucene library.</p>\n</div>',0x00,'asciidoc::elasticsearch.adoc::0'),
('fe72c673-d15d-405e-b186-067afa53d960','<strong>Reference:</strong> Yao, S., et al. (2023). \"Tree of Thoughts: Deliberate Problem Solving with Large Language Models.\" arXiv:2305.10601. <a href=\"https://arxiv.org/abs/2305.10601\">https://arxiv.org/abs/2305.10601</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.7 Tree of Thoughts (ToT)::1'),
('525c18b4-379b-4791-8b29-06b06f5dc690','Some AI Models provide dedicated configuration options to generate structured (usually JSON) output.\n\n<a href=\"api/chat/openai-chat.html#_structured_outputs\">OpenAI Structured Outputs</a> can ensure your model generates responses conforming strictly to your provided JSON Schema. You can choose between the <code>JSON_OBJECT</code> that guarantees the message the model generates is valid JSON or <code>JSON_SCHEMA</code> with a supplied schema that guarantees the model will generate a response that matches your supplied schema (<code>spring.ai.openai.chat.options.responseFormat</code> option).\n<a href=\"api/chat/azure-openai-chat.html\">Azure OpenAI</a> - provides a <code>spring.ai.azure.openai.chat.options.responseFormat</code> options specifying the format that the model must output. Setting to <code>{ \"type\": \"json_object\" }</code> enables JSON mode, which guarantees the message the model generates is valid JSON.\n<a href=\"api/chat/ollama-chat.html\">Ollama</a> - provides a <code>spring.ai.ollama.chat.options.format</code> option to specify the format to return a response in. Currently, the only accepted value is <code>json</code>.\n<a href=\"api/chat/mistralai-chat.html\">Mistral AI</a> - provides a <code>spring.ai.mistralai.chat.options.responseFormat</code> option to specify the format to return a response in. Setting it to <code>{ \"type\": \"json_object\" }</code> enables JSON mode, which guarantees the message the model generates is valid JSON.',0x00,'asciidoc::structured-output-converter.adoc::Native Structured Output::Built-in JSON mode::0'),
('49e57f4d-7e42-4c32-9ef1-06e83ba15cee','When building tools from a function with the programmatic approach, you can set the <code>returnDirect</code> attribute via the <code>ToolMetadata</code> interface and pass it to the <code>FunctionToolCallback.Builder</code>.\n\nToolMetadata toolMetadata = ToolMetadata.builder()\n    .returnDirect(true)\n    .build();\n\nSee <a href=\"#_functions_as_tools\">Functions as Tools</a> for more details.',0x00,'asciidoc::tools.adoc::Tool Specification::Return Direct::1'),
('062c05df-ecd3-49ed-aa8d-07165ebcc3b3','You can create an instance of <code>Filter.Expression</code> with a <code>FilterExpressionBuilder</code> that exposes a fluent API.\nA simple example is as follows:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\nExpression expression = this.b.eq(\"country\", \"BG\").build();\n\nYou can build up sophisticated expressions by using the following operators:\n\nEQUALS: \'==\'\nMINUS : \'-\'\nPLUS: \'+\'\nGT: \'&gt;\'\nGE: \'&gt;=\'\nLT: \'&lt;\'\nLE: \'&lt;=\'\nNE: \'!=\'\n\nYou can combine expressions by using the following operators:\n\nAND: \'AND\' | \'and\' | \'&amp;&amp;\';\nOR: \'OR\' | \'or\' | \'||\';\n\nConsidering the following example:\n\nExpression exp = b.and(b.eq(\"genre\", \"drama\"), b.gte(\"year\", 2020)).build();\n\nYou can also use the following operators:\n\nIN: \'IN\' | \'in\';\nNIN: \'NIN\' | \'nin\';\nNOT: \'NOT\' | \'not\';\n\nConsider the following example:\n\nExpression exp = b.and(b.in(\"genre\", \"drama\", \"documentary\"), b.not(b.lt(\"year\", 2020))).build();',0x00,'asciidoc::vectordbs.adoc::Metadata Filters::Filter.Expression::0'),
('2375b0c8-f076-4a46-a9e4-071a4d328a2f','Spring AI supports tool calling through a set of flexible abstractions that allow you to define, resolve, and execute tools in a consistent way. This section provides an overview of the main concepts and components of tool calling in Spring AI.\n\nWhen we want to make a tool available to the model, we include its definition in the chat request. Each tool definition comprises of a name, a description, and the schema of the input parameters.\nWhen the model decides to call a tool, it sends a response with the tool name and the input parameters modeled after the defined schema.\nThe application is responsible for using the tool name to identify and execute the tool with the provided input parameters.\nThe result of the tool call is processed by the application.\nThe application sends the tool call result back to the model.\nThe model generates the final response using the tool call result as additional context.\n\n\nTools are the building blocks of tool calling and they are modeled by the <code>ToolCallback</code> interface. Spring AI provides built-in support for specifying <code>ToolCallback</code>(s) from methods and functions, but you can always define your own <code>ToolCallback</code> implementations to support more use cases.\n\n<code>ChatModel</code> implementations transparently dispatch tool call requests to the corresponding <code>ToolCallback</code> implementations and will send the tool call results back to the model, which will ultimately generate the final response. They do so using the <code>ToolCallingManager</code> interface, which is responsible for managing the tool execution lifecycle.\n\nBoth <code>ChatClient</code> and <code>ChatModel</code> accept a list of <code>ToolCallback</code> objects to make the tools available to the model and the <code>ToolCallingManager</code> that will eventually execute them.\n\nBesides passing the <code>ToolCallback</code> objects directly, you can also pass a list of tool names, that will be resolved dynamically using the <code>ToolCallbackResolver</code> interface.\n\nThe following sections will go into more details about all these concepts and APIs, including how to customize and extend them to support more use cases.',0x00,'asciidoc::tools.adoc::Overview::0'),
('82ee0d9a-0cac-44f4-84e3-07239f609c88','AI models don&#8217;t have access to real-time information. Any question that assumes awareness of information such as the current date or weather forecast cannot be answered by the model. However, we can provide a tool that can retrieve this information, and let the model call this tool when access to real-time information is needed.\n\nLet&#8217;s implement a tool to get the current date and time in the user&#8217;s time zone in a <code>DateTimeTools</code> class. The tool will take no argument. The <code>LocaleContextHolder</code> from Spring Framework can provide the user&#8217;s time zone. The tool will be defined as a method annotated with <code>@Tool</code>. To help the model understand if and when to call this tool, we&#8217;ll provide a detailed description of what the tools does.\n\nimport java.time.LocalDateTime;\nimport org.springframework.ai.tool.annotation.Tool;\nimport org.springframework.context.i18n.LocaleContextHolder;\n\nclass DateTimeTools {\n\n    @Tool(description = \"Get the current date and time in the user\'s timezone\")\n    String getCurrentDateTime() {\n        return LocalDateTime.now().atZone(LocaleContextHolder.getTimeZone().toZoneId()).toString();\n    }\n\n}\n\nNext, let&#8217;s make the tool available to the model. In this example, we&#8217;ll use the <code>ChatClient</code> to interact with the model. We&#8217;ll provide the tool to the model by passing an instance of <code>DateTimeTools</code> via the <code>tools()</code> method. When the model needs to know the current date and time, it will request the tool to be called. Internally, the <code>ChatClient</code> will call the tool and return the result to the model, which will then use the tool call result to generate the final response to the original question.\n\nChatModel chatModel = ...\n\nString response = ChatClient.create(chatModel)\n        .prompt(\"What day is tomorrow?\")\n        .tools(new DateTimeTools())\n        .call()\n        .content();\n\nSystem.out.println(response);\n\nThe output will be something like:\n\nTomorrow is 2015-10-21.\n\nYou can retry asking the same question again. This time, don&#8217;t provide the tool to the model. The output will be something like:\n\nI am an AI and do not have access to real-time information. Please provide the current date so I can accurately determine what day tomorrow will be.\n\nWithout the tool, the model doesn&#8217;t know how to answer the question because it doesn&#8217;t have the ability to determine the current date and time.',0x00,'asciidoc::tools.adoc::Quick Start::Information Retrieval::0'),
('15dfface-226b-4fd2-9d35-0731cbce184c','The following snippet shows how to use <code>MapOutputConverter</code> to convert the model output to a list of numbers in a map.\n\nMap&lt;String, Object&gt; result = ChatClient.create(chatModel).prompt()\n        .user(u -&gt; u.text(\"Provide me a List of {subject}\")\n                    .param(\"subject\", \"an array of numbers from 1 to 9 under they key name \'numbers\'\"))\n        .call()\n        .entity(new ParameterizedTypeReference&lt;Map&lt;String, Object&gt;&gt;() {});\n\nor using the low-level <code>ChatModel</code> API directly:\n\nMapOutputConverter mapOutputConverter = new MapOutputConverter();\n\nString format = this.mapOutputConverter.getFormat();\nString template = \"\"\"\n        Provide me a List of {subject}\n        {format}\n        \"\"\";\n\nPrompt prompt = PromptTemplate.builder().template(this.template)\n.variables(Map.of(\"subject\", \"an array of numbers from 1 to 9 under they key name \'numbers\'\", \"format\", this.format)).build().create();\n\nGeneration generation = chatModel.call(this.prompt).getResult();\n\nMap&lt;String, Object&gt; result = this.mapOutputConverter.convert(this.generation.getOutput().getText());',0x00,'asciidoc::structured-output-converter.adoc::Using Converters::Map Output Converter::0'),
('b96d4535-bbfa-46eb-9186-087d1c170ac7','You can create a custom instance of <code>OpenAiApi</code> with your own <code>ApiKey</code> implementation using the builder pattern:\n\nApiKey customApiKey = new ApiKey() {\n    @Override\n    public String getValue() {\n        // Custom logic to retrieve API key\n        return \"your-api-key-here\";\n    }\n};\n\nOpenAiApi openAiApi = OpenAiApi.builder()\n    .apiKey(customApiKey)\n    .build();\n\n// Create a chat model with the custom OpenAiApi instance\nOpenAiChatModel chatModel = OpenAiChatModel.builder()\n    .openAiApi(openAiApi)\n    .build();\n// Build the ChatClient using the custom chat model\nChatClient openAiChatClient = ChatClient.builder(chatModel).build();\n\nThis is useful when you need to:\n\nRetrieve the API key from a secure key store\nRotate API keys dynamically\nImplement custom API key selection logic',0x00,'asciidoc::openai-chat.adoc::API Key Management::Custom API Key Configuration::0'),
('49e26f03-d57a-4b80-8a3a-08db2bee858c','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-openai</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the OpenAi chat model:\n\nspring.ai.openai.api-key=${NVIDIA_API_KEY}\nspring.ai.openai.base-url=https://integrate.api.nvidia.com\nspring.ai.openai.chat.options.model=meta/llama-3.1-70b-instruct\n\n# The NVIDIA LLM API doesn\'t support embeddings, so we need to disable it.\nspring.ai.openai.embedding.enabled=false\n\n# The NVIDIA LLM API requires this parameter to be set explicitly or server internal error will be thrown.\nspring.ai.openai.chat.options.max-tokens=2048\n\nreplace the <code>api-key</code> with your NVIDIA credentials.\n\nNVIDIA LLM API requires the <code>max-token</code> parameter to be explicitly set or server error will be thrown.\n\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final OpenAiChatModel chatModel;\n\n    @Autowired\n    public ChatController(OpenAiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::nvidia-chat.adoc::Sample Controller::0'),
('ad8ee97e-0789-4ba4-abcb-0920d1d1108c','You can leverage the generic, portable <a href=\"https://docs.spring.io/spring-ai/reference/api/vectordbs.html#_metadata_filters\">metadata filters</a> with the PgVector store.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"author\",\"john\", \"jill\"),\n        b.eq(\"article_type\", \"blog\")).build()).build());\n\nThese filter expressions are converted into PostgreSQL JSON path expressions for efficient metadata filtering.',0x00,'asciidoc::pgvector.adoc::Metadata filtering::0'),
('fae3077e-3922-47cd-980c-09a1e2220987','<a href=\"api/chat/anthropic-chat.html#_multimodal\">Anthropic Claude 3</a>\n<a href=\"api/chat/bedrock-converse.html#_multimodal\">AWS Bedrock Converse</a>\n<a href=\"api/chat/azure-openai-chat.html#_multimodal\">Azure Open AI (e.g. GPT-4o models)</a>\n<a href=\"api/chat/mistralai-chat.html#_multimodal\">Mistral AI (e.g. Mistral Pixtral models)</a>\n<a href=\"api/chat/ollama-chat.html#_multimodal\">Ollama (e.g. LLaVA, BakLLaVA, Llama3.2 models)</a>\n<a href=\"api/chat/openai-chat.html#_multimodal\">OpenAI (e.g. GPT-4 and GPT-4o models)</a>\n<a href=\"api/chat/vertexai-gemini-chat.html#_multimodal\">Vertex AI Gemini (e.g. gemini-1.5-pro-001, gemini-1.5-flash-001 models)</a>',0x00,'asciidoc::multimodality.adoc::Spring AI Multimodality::1'),
('d3e26ac6-7159-49c1-a85e-09a7b3c6f87e','<strong>When to Use:</strong>\n- Complex tasks where subtasks can&#8217;t be predicted upfront\n- Tasks requiring different approaches or perspectives\n- Situations needing adaptive problem-solving\n\npublic class OrchestratorWorkersWorkflow {\n    public WorkerResponse process(String taskDescription) {\n        // 1. Orchestrator analyzes task and determines subtasks\n        OrchestratorResponse orchestratorResponse = // ...\n\n        // 2. Workers process subtasks in parallel\n        List&lt;String&gt; workerResponses = // ...\n\n        // 3. Results are combined into final response\n        return new WorkerResponse(/*...*/);\n    }\n}\n\nUsage Example:\n\nChatClient chatClient = // ... initialize chat client\nOrchestratorWorkersWorkflow workflow = new OrchestratorWorkersWorkflow(chatClient);\n\nWorkerResponse response = workflow.process(\n    \"Generate both technical and user-friendly documentation for a REST API endpoint\"\n);\n\nSystem.out.println(\"Analysis: \" + response.analysis());\nSystem.out.println(\"Worker Outputs: \" + response.workerResponses());',0x00,'asciidoc::effective-agents.adoc::Agentic Systems::4. <a href=\"https://github.com/spring-projects/spring-ai-examples/tree/main/agentic-patterns/orchestrator-workers\">Orchestrator-Workers</a>::0'),
('91ef4450-40e5-4112-8193-0a1e780f3778','OpenAI models that offer vision multimodal support include <code>gpt-4</code>, <code>gpt-4o</code>, and <code>gpt-4o-mini</code>.\nRefer to the <a href=\"https://platform.openai.com/docs/guides/vision\">Vision</a> guide for more information.\n\nSpring AI&#8217;s <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/messages/Message.java\">Message</a> interface facilitates multimodal AI models by introducing the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-commons/src/main/java/org/springframework/ai/content/Media.java\">Media</a> type.\n\nBelow is a code example illustrating the fusion of user text with an image:\n\nvar imageResource = new ClassPathResource(\"/multimodal.test.png\");\n\nvar userMessage = new UserMessage(\n    \"Explain what do you see on this picture?\",\n    List.of(new Media(MimeTypeUtils.IMAGE_PNG, imageResource)));\n\nChatResponse response = chatModel.call(\n    new Prompt(userMessage,\n        OpenAiSdkChatOptions.builder()\n            .model(\"gpt-4o\")\n            .build()));\n\nOr using an image URL:\n\nvar userMessage = new UserMessage(\n    \"Explain what do you see on this picture?\",\n    List.of(Media.builder()\n        .mimeType(MimeTypeUtils.IMAGE_PNG)\n        .data(URI.create(\"https://docs.spring.io/spring-ai/reference/_images/multimodal.test.png\"))\n        .build()));\n\nChatResponse response = chatModel.call(new Prompt(userMessage));\n\nYou can pass multiple images as well.',0x00,'asciidoc::openai-sdk-chat.adoc::Multimodal::Vision::0'),
('dcea2f6d-511e-4eaa-8ef5-0a4328cbe497','If you are using the <code>ChatClient</code>, you can access the usage information using the <code>ChatResponse</code> object:\n\n// Create a chat prompt\nPrompt prompt = new Prompt(\"What is the weather like today?\");\n\n// Create a chat client\nChatClient chatClient = ChatClient.create(chatModel);\n\n// Get the chat response\nChatResponse response = chatClient.prompt(prompt)\n        .call()\n        .chatResponse();\n\n// Access the usage information\nUsage usage = response.getMetadata().getUsage();',0x00,'asciidoc::usage-handling.adoc::Key Changes::Using with ChatClient::0'),
('b373b611-a578-4892-bcdf-0a72ed2efaad','Create <a href=\"https://build.nvidia.com/explore/discover\">NVIDIA</a> account with sufficient credits.\nSelect a LLM Model to use. For example the <code>meta/llama-3.1-70b-instruct</code> in the screenshot below.\nFrom the selected model&#8217;s page, you can get the <code>api-key</code> for accessing this model.',0x00,'asciidoc::nvidia-chat.adoc::Prerequisite::0'),
('6e62b661-168d-469f-96e1-0a77c9e74078','You can use the following properties in your Spring Boot configuration to customize the Milvus vector store.',0x00,'asciidoc::milvus.adoc::Milvus VectorStore properties::0'),
('99d38a42-eccf-410d-9fe4-0a9ad93ba57d','/**\n * A component for combining documents retrieved based on multiple queries and from\n * multiple data sources into a single collection of documents. As part of the joining\n * process, it can also handle duplicate documents and reciprocal ranking strategies.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic interface DocumentJoiner extends Function<Map<Query, List<List<Document>>>, List<Document>> {\n\n    /**\n     * Joins documents retrieved across multiple queries and daa sources.\n     * @param documentsForQuery a map of queries and the corresponding list of documents\n     * retrieved\n     * @return a single collection of documents\n     */\n    List<Document> join(Map<Query, List<List<Document>>> documentsForQuery);\n\n    default List<Document> apply(Map<Query, List<List<Document>>> documentsForQuery) {\n        return join(documentsForQuery);\n    }\n}',0x01,'cu::DocumentJoiner.java'),
('df99a277-49ca-45f0-ba53-0aa45762c7cd','public enum Operation {\n\n    /**\n     * VectorStore add operation.\n     */\n    ADD(\"add\"),\n    /**\n     * VectorStore delete operation.\n     */\n    DELETE(\"delete\"),\n    /**\n     * VectorStore similarity search operation.\n     */\n    QUERY(\"query\");\n\n    public final String value;\n\n    Operation(String value) {\n        this.value = value;\n    }\n\n    public String value() {\n        return this.value;\n    }\n}',0x01,'cu::VectorStoreObservationContext.java'),
('89a27e03-ae45-46c0-8a85-0ac7e4640c5e','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai-sdk/src/main/java/org/springframework/ai/openaisdk/OpenAiSdkEmbeddingOptions.java\">OpenAiSdkEmbeddingOptions.java</a> provides the OpenAI configurations, such as the model to use, dimensions, and user identifier.\n\nThe default options can be configured using the <code>spring.ai.openai-sdk.embedding.options</code> properties as well.\n\nAt start-time use the <code>OpenAiSdkEmbeddingModel</code> constructor to set the default options used for all embedding requests.\nAt run-time you can override the default options, using a <code>OpenAiSdkEmbeddingOptions</code> instance as part of your <code>EmbeddingRequest</code>.\n\nFor example to override the default model name for a specific request:\n\nEmbeddingResponse embeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n        OpenAiSdkEmbeddingOptions.builder()\n            .model(\"text-embedding-3-large\")\n            .dimensions(1024)\n        .build()));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai-sdk/src/main/java/org/springframework/ai/openaisdk/OpenAiSdkEmbeddingOptions.java\">OpenAiSdkEmbeddingOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/embedding/EmbeddingOptions.java\">EmbeddingOptions</a> instance, created with the builder.',0x00,'asciidoc::openai-sdk-embeddings.adoc::Runtime Options::0'),
('e24bcad0-b3c2-41e7-b1e6-0b0f2de550e2','This diagram illustrates the unified interfaces, <code>ChatModel</code> and <code>StreamingChatModel</code>, are used for interacting with various AI chat models from different providers, allowing easy integration and switching between different AI services while maintaining a consistent API for the client application.\n\n<a href=\"api/chat/openai-chat.html\">OpenAI Chat Completion</a> (streaming, multi-modality &amp; function-calling support)\n<a href=\"api/chat/azure-openai-chat.html\">Microsoft Azure Open AI Chat Completion</a> (streaming &amp; function-calling support)\n<a href=\"api/chat/ollama-chat.html\">Ollama Chat Completion</a> (streaming, multi-modality &amp; function-calling support)\n<a href=\"api/chat/huggingface.html\">Hugging Face Chat Completion</a> (no streaming support)\n<a href=\"api/chat/vertexai-gemini-chat.html\">Google Vertex AI Gemini Chat Completion</a> (streaming, multi-modality &amp; function-calling support)\n<a href=\"api/bedrock.html\">Amazon Bedrock</a>\n<a href=\"api/chat/mistralai-chat.html\">Mistral AI Chat Completion</a> (streaming &amp; function-calling support)\n<a href=\"api/chat/anthropic-chat.html\">Anthropic Chat Completion</a> (streaming &amp; function-calling support)\n\n\nFind a detailed comparison of the available Chat Models in the <a href=\"api/chat/comparison.html\">Chat Models Comparison</a> section.',0x00,'asciidoc::chatmodel.adoc::Available Implementations::0'),
('a24b8801-71f4-48fc-b9b4-0b408186159a','<div class=\"imageblock right\">\n<div class=\"content\">\n<img src=\"vector_2d_coordinates.png\" alt=\"vector 2d coordinates\" width=\"150\">\n</div>\n</div>\n<div class=\"paragraph\">\n<p>Vectors have dimensionality and a direction.\nFor example, the following image depicts a two-dimensional vector \\$\\vec{a}\\$ in the cartesian coordinate system pictured as an arrow.</p>\n</div>\n<div class=\"paragraph\">\n<p>The head of the vector \\$\\vec{a}\\$ is at the point \\$(a_1, a_2)\\$.\nThe <strong>x</strong> coordinate value is \\$a_1\\$ and the <strong>y</strong> coordinate value is \\$a_2\\$. The coordinates are also referred to as the components of the vector.</p>\n</div>',0x00,'asciidoc::understand-vectordbs.adoc::0'),
('6337e358-11b1-487a-8362-0bca33ca7c36','/**\n * Default conventions to populate observations for vector store operations.\n *\n * @author Christian Tzolov\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic class DefaultVectorStoreObservationConvention implements VectorStoreObservationConvention {\n\n    public static final String DEFAULT_NAME = \"db.vector.client.operation\";\n\n    private final String name;\n\n    public DefaultVectorStoreObservationConvention() {\n        this(DEFAULT_NAME);\n    }\n\n    public DefaultVectorStoreObservationConvention(String name) {\n        this.name = name;\n    }\n\n    @Override\n    public String getName() {\n        return this.name;\n    }\n\n    @Override\n    @Nullable\n    public String getContextualName(VectorStoreObservationContext context) {\n        return \"%s %s\".formatted(context.getDatabaseSystem(), context.getOperationName());\n    }\n\n    @Override\n    public KeyValues getLowCardinalityKeyValues(VectorStoreObservationContext context) {\n        return KeyValues.of(springAiKind(), dbSystem(context), dbOperationName(context));\n    }\n\n    protected KeyValue springAiKind() {\n        return KeyValue.of(LowCardinalityKeyNames.SPRING_AI_KIND, SpringAiKind.VECTOR_STORE.value());\n    }\n\n    protected KeyValue dbSystem(VectorStoreObservationContext context) {\n        return KeyValue.of(LowCardinalityKeyNames.DB_SYSTEM, context.getDatabaseSystem());\n    }\n\n    protected KeyValue dbOperationName(VectorStoreObservationContext context) {\n        return KeyValue.of(LowCardinalityKeyNames.DB_OPERATION_NAME, context.getOperationName());\n    }\n\n    @Override\n    public KeyValues getHighCardinalityKeyValues(VectorStoreObservationContext context) {\n        var keyValues = KeyValues.empty();\n        keyValues = collectionName(keyValues, context);\n        keyValues = dimensions(keyValues, context);\n        keyValues = fieldName(keyValues, context);\n        keyValues = metadataFilter(keyValues, context);\n        keyValues = namespace(keyValues, context);\n        keyValues = queryContent(keyValues, context);\n        keyValues = similarityMetric(keyValues, context);\n        keyValues = similarityThreshold(keyValues, context);\n        keyValues = topK(keyValues, context);\n        return keyValues;\n    }\n\n    protected KeyValues collectionName(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (StringUtils.hasText(context.getCollectionName())) {\n            return keyValues.and(HighCardinalityKeyNames.DB_COLLECTION_NAME.asString(), context.getCollectionName());\n        }\n        return keyValues;\n    }\n\n    protected KeyValues dimensions(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (context.getDimensions() != null && context.getDimensions() > 0) {\n            return keyValues.and(HighCardinalityKeyNames.DB_VECTOR_DIMENSION_COUNT.asString(), \"\" + context.getDimensions());\n        }\n        return keyValues;\n    }\n\n    protected KeyValues fieldName(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (StringUtils.hasText(context.getFieldName())) {\n            return keyValues.and(HighCardinalityKeyNames.DB_VECTOR_FIELD_NAME.asString(), context.getFieldName());\n        }\n        return keyValues;\n    }\n\n    protected KeyValues metadataFilter(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (context.getQueryRequest() != null && context.getQueryRequest().getFilterExpression() != null) {\n            return keyValues.and(HighCardinalityKeyNames.DB_VECTOR_QUERY_FILTER.asString(), context.getQueryRequest().getFilterExpression().toString());\n        }\n        return keyValues;\n    }\n\n    protected KeyValues namespace(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (StringUtils.hasText(context.getNamespace())) {\n            return keyValues.and(HighCardinalityKeyNames.DB_NAMESPACE.asString(), context.getNamespace());\n        }\n        return keyValues;\n    }\n\n    protected KeyValues queryContent(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (context.getQueryRequest() != null && StringUtils.hasText(context.getQueryRequest().getQuery())) {\n            return keyValues.and(HighCardinalityKeyNames.DB_VECTOR_QUERY_CONTENT.asString(), context.getQueryRequest().getQuery());\n        }\n        return keyValues;\n    }\n\n    protected KeyValues similarityMetric(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (StringUtils.hasText(context.getSimilarityMetric())) {\n            return keyValues.and(HighCardinalityKeyNames.DB_SEARCH_SIMILARITY_METRIC.asString(), context.getSimilarityMetric());\n        }\n        return keyValues;\n    }\n\n    protected KeyValues similarityThreshold(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (context.getQueryRequest() != null && context.getQueryRequest().getSimilarityThreshold() >= 0) {\n            return keyValues.and(HighCardinalityKeyNames.DB_VECTOR_QUERY_SIMILARITY_THRESHOLD.asString(), String.valueOf(context.getQueryRequest().getSimilarityThreshold()));\n        }\n        return keyValues;\n    }\n\n    protected KeyValues topK(KeyValues keyValues, VectorStoreObservationContext context) {\n        if (context.getQueryRequest() != null && context.getQueryRequest().getTopK() > 0) {\n            return keyValues.and(HighCardinalityKeyNames.DB_VECTOR_QUERY_TOP_K.asString(), \"\" + context.getQueryRequest().getTopK());\n        }\n        return keyValues;\n    }\n}',0x01,'cu::DefaultVectorStoreObservationConvention.java'),
('a5fea162-0e3c-45c3-a536-0bdcd8e3df25','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions.java</a> class provides model configurations such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>OpenAiChatModel(api, options)</code> constructor or the <code>spring.ai.openai.chat.options.*</code> properties.\n\nAt run-time, you can override the default options by adding new, request-specific options to the <code>Prompt</code> call.\nFor example, to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        OpenAiChatOptions.builder()\n            .model(\"gpt-4o\")\n            .temperature(0.4)\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::openai-chat.adoc::Runtime Options::0'),
('947e9c8a-a1ad-451e-b478-0c89d18fb4fb','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-ollama/src/main/java/org/springframework/ai/ollama/api/OllamaChatOptions.java\">OllamaChatOptions.java</a> class provides model configurations, such as the model to use, the temperature, thinking mode, etc.\n\nThe <code>OllamaOptions</code> class has been deprecated. Use <code>OllamaChatOptions</code> for chat models and <code>OllamaEmbeddingOptions</code> for embedding models instead. The new classes provide type-safe, model-specific configuration options.\n\nOn start-up, the default options can be configured with the <code>OllamaChatModel(api, options)</code> constructor or the <code>spring.ai.ollama.chat.options.*</code> properties.\n\nAt run-time, you can override the default options by adding new, request-specific options to the <code>Prompt</code> call.\nFor example, to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        OllamaChatOptions.builder()\n            .model(OllamaModel.LLAMA3_1)\n            .temperature(0.4)\n            .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-ollama/src/main/java/org/springframework/ai/ollama/api/OllamaChatOptions.java\">OllamaChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::ollama-chat.adoc::Runtime Options::0'),
('92aa5e34-e916-412a-bc18-0d1d5fc9070b','These changes are part of a broader effort to improve and extend the tool calling capabilities in Spring AI. Among the other things, the new API moves from \"functions\" to \"tools\" terminology to better align with industry conventions. This involves several API changes while maintaining backward compatibility through deprecated methods.',0x00,'asciidoc::tools-migration.adoc::Overview of Changes::0'),
('6978876a-d696-4691-8777-0d2249aefb35','Step-back prompting breaks complex requests into simpler steps by first acquiring background knowledge. This technique encourages the model to first \"step back\" from the immediate question to consider the broader context, fundamental principles, or general knowledge relevant to the problem before addressing the specific query.\n\nBy decomposing complex problems into more manageable components and establishing foundational knowledge first, the model can provide more accurate responses to difficult questions.\n\n// Implementation of Section 2.4: Step-back prompting\npublic void pt_step_back_prompting(ChatClient.Builder chatClientBuilder) {\n    // Set common options for the chat client\n    var chatClient = chatClientBuilder\n            .defaultOptions(ChatOptions.builder()\n                    .model(\"claude-3-7-sonnet-latest\")\n                    .temperature(1.0)\n                    .topK(40)\n                    .topP(0.8)\n                    .maxTokens(1024)\n                    .build())\n            .build();\n\n    // First get high-level concepts\n    String stepBack = chatClient\n            .prompt(\"\"\"\n                    Based on popular first-person shooter action games, what are\n                    5 fictional key settings that contribute to a challenging and\n                    engaging level storyline in a first-person shooter video game?\n                    \"\"\")\n            .call()\n            .content();\n\n    // Then use those concepts in the main task\n    String story = chatClient\n            .prompt()\n            .user(u -&gt; u.text(\"\"\"\n                    Write a one paragraph storyline for a new level of a first-\n                    person shooter video game that is challenging and engaging.\n\n                    Context: {step-back}\n                    \"\"\")\n                    .param(\"step-back\", stepBack))\n            .call()\n            .content();\n}\n\nStep-back prompting is particularly effective for complex reasoning tasks, problems requiring specialized domain knowledge, and when you want more comprehensive and thoughtful responses rather than immediate answers.\n\n<strong>Reference:</strong> Zheng, Z., et al. (2023). \"Take a Step Back: Evoking Reasoning via Abstraction in Large Language Models.\" arXiv:2310.06117. <a href=\"https://arxiv.org/abs/2310.06117\">https://arxiv.org/abs/2310.06117</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.4 Step-Back Prompting::0'),
('ebe7f59c-8537-4ecc-9f73-0d4f6359aa05','<div class=\"paragraph\">\n<p>This section walks you through setting up the Weaviate VectorStore to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://weaviate.io/\">Weaviate</a> is an open-source vector database that allows you to store data objects and vector embeddings from your favorite ML-models and scale seamlessly into billions of data objects.\nIt provides tools to store document embeddings, content, and metadata and to search through those embeddings, including metadata filtering.</p>\n</div>',0x00,'asciidoc::weaviate.adoc::0'),
('f482bbc0-00bc-4fe6-b505-0d8cd74679d1','GitHub Models is automatically detected when using the GitHub Models base URL. You&#8217;ll need to create a GitHub Personal Access Token (PAT) with the <code>models:read</code> scope.\n\nspring.ai.openai-sdk.base-url=https://models.inference.ai.azure.com\nspring.ai.openai-sdk.api-key=github_pat_XXXXXXXXXXX\n\nOr using environment variables:\n\nexport OPENAI_BASE_URL=https://models.inference.ai.azure.com\nexport OPENAI_API_KEY=github_pat_XXXXXXXXXXX\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) in your properties:\n\nspring.ai.openai-sdk.api-key=${OPENAI_API_KEY}',0x00,'asciidoc::openai-sdk-embeddings.adoc::Authentication::Using GitHub Models::0'),
('f814fac2-95fd-4faf-940d-0dd45ece4520','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::groq-chat.adoc::Prerequisites::Add Repositories and BOM::0'),
('30f038b1-08f9-4294-a89d-0deee8321ed5','The prefix <code>spring.ai.ollama</code> is the property prefix to configure the connection to Ollama\n\n\n\nHere are the properties for initializing the Ollama integration and <a href=\"#auto-pulling-models\">auto-pulling models</a>.',0x00,'asciidoc::ollama-embeddings.adoc::Auto-configuration::Base Properties::0'),
('a5cb84a6-fdf7-4ea0-91ef-0e12cabf32a1','/**\n * High-cardinality observation key names for vector store operations.\n */\npublic enum HighCardinalityKeyNames implements KeyName {\n\n    // DB General\n    /**\n     * The name of a collection (table, container) within the database.\n     */\n    DB_COLLECTION_NAME {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_COLLECTION_NAME.value();\n        }\n    }\n    ,\n    /**\n     * The namespace of the database.\n     */\n    DB_NAMESPACE {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_NAMESPACE.value();\n        }\n    }\n    ,\n    // DB Search\n    /**\n     * The metric used in similarity search.\n     */\n    DB_SEARCH_SIMILARITY_METRIC {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_SEARCH_SIMILARITY_METRIC.value();\n        }\n    }\n    ,\n    // DB Vector\n    /**\n     * The dimension of the vector.\n     */\n    DB_VECTOR_DIMENSION_COUNT {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_VECTOR_DIMENSION_COUNT.value();\n        }\n    }\n    ,\n    /**\n     * The name field as of the vector (e.g. a field name).\n     */\n    DB_VECTOR_FIELD_NAME {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_VECTOR_FIELD_NAME.value();\n        }\n    }\n    ,\n    /**\n     * The content of the search query being executed.\n     */\n    DB_VECTOR_QUERY_CONTENT {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_VECTOR_QUERY_CONTENT.value();\n        }\n    }\n    ,\n    /**\n     * The metadata filters used in the search query.\n     */\n    DB_VECTOR_QUERY_FILTER {\n\n        @Override\n        public String asString() {\n            return \"db.vector.query.filter\";\n        }\n    }\n    ,\n    /**\n     * Similarity threshold that accepts all search scores. A threshold value of 0.0\n     * means any similarity is accepted or disable the similarity threshold filtering.\n     * A threshold value of 1.0 means an exact match is required.\n     */\n    DB_VECTOR_QUERY_SIMILARITY_THRESHOLD {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_VECTOR_QUERY_SIMILARITY_THRESHOLD.value();\n        }\n    }\n    ,\n    /**\n     * The top-k most similar vectors returned by a query.\n     */\n    DB_VECTOR_QUERY_TOP_K {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_VECTOR_QUERY_TOP_K.value();\n        }\n    }\n\n}',0x01,'cu::VectorStoreObservationDocumentation.java'),
('4ce3c5ad-2455-4cd7-8797-0e9ac30c1669','<div class=\"paragraph\">\n<p>This section walks you through setting up <code>RedisVectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://redis.io\">Redis</a> is an open source (BSD licensed), in-memory data structure store used as a database, cache, message broker, and streaming engine. Redis provides data structures such as strings, hashes, lists, sets, sorted sets with range queries, bitmaps, hyperloglogs, geospatial indexes, and streams.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://redis.io/docs/interact/search-and-query/\">Redis Search and Query</a> extends the core features of Redis OSS and allows you to use Redis as a vector database:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p>Store vectors and the associated metadata within hashes or JSON documents</p>\n</li>\n<li>\n<p>Retrieve vectors</p>\n</li>\n<li>\n<p>Perform vector searches</p>\n</li>\n</ul>\n</div>',0x00,'asciidoc::redis.adoc::0'),
('721c581d-706c-4296-ac82-0eab43c88f48','// Implementation of Section 2.3.3: Contextual prompting\npublic void pt_contextual_prompting(ChatClient chatClient) {\n    String articleSuggestions = chatClient\n            .prompt()\n            .user(u -&gt; u.text(\"\"\"\n                    Suggest 3 topics to write an article about with a few lines of\n                    description of what this article should contain.\n\n                    Context: {context}\n                    \"\"\")\n                    .param(\"context\", \"You are writing for a blog about retro 80\'s arcade video games.\"))\n            .call()\n            .content();\n}\n\nSpring AI makes contextual prompting clean with the param() method to inject context variables. This technique is particularly valuable when the model needs specific domain knowledge, when adapting responses to particular audiences or scenarios, and for ensuring responses are aligned with particular constraints or requirements.\n\n<strong>Reference:</strong> Liu, P., et al. (2021). \"What Makes Good In-Context Examples for GPT-3?\" arXiv:2101.06804. <a href=\"https://arxiv.org/abs/2101.06804\">https://arxiv.org/abs/2101.06804</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.3 System, contextual and role prompting::2'),
('93aab8ec-75d3-4105-9d32-0edc89df6f8a','Pinecone Account: Before you start, sign up for a <a href=\"https://app.pinecone.io/\">Pinecone account</a>.\nPinecone Project: Once registered, generate an API key and create and index. You&#8217;ll need these details for configuration.\n<code>EmbeddingModel</code> instance to compute the document embeddings. Several options are available:\n\n\nTo set up <code>PineconeVectorStore</code>, gather the following details from your Pinecone account:\n\nPinecone API Key\nPinecone Index Name\nPinecone Namespace\n\n\n<div class=\"paragraph\">\n<p>This information is available to you in the Pinecone UI portal.\nThe namespace support is not available in the Pinecone free tier.</p>\n</div>',0x00,'asciidoc::pinecone.adoc::Prerequisites::0'),
('c653d13d-5705-4e14-b49f-0eecfaac3b64','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatModel.java\">OpenAiChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"#low-level-api\">[low-level-api]</a> to connect to the OpenAI service.\n\nAdd the <code>spring-ai-openai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>OpenAiChatModel</code> and use it for text generations:\n\nvar openAiApi = new OpenAiApi(\"https://api.groq.com/openai\", System.getenv(\"GROQ_API_KEY\"));\nvar openAiChatOptions = OpenAiChatOptions.builder()\n            .model(\"llama3-70b-8192\")\n            .temperature(0.4)\n            .maxTokens(200)\n        .build();\nvar chatModel = new OpenAiChatModel(this.openAiApi, this.openAiChatOptions);\n\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; response = this.chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>OpenAiChatOptions</code> provides the configuration information for the chat requests.\nThe <code>OpenAiChatOptions.Builder</code> is fluent options builder.',0x00,'asciidoc::groq-chat.adoc::Manual Configuration::0'),
('717a1f9b-48bb-486a-90b1-0f372737b4e1','<div class=\"paragraph\">\n<p>The Extract, Transform, and Load (ETL) framework serves as the backbone of data processing within the Retrieval Augmented Generation (RAG) use case.</p>\n</div>\n<div class=\"paragraph\">\n<p>The ETL pipeline orchestrates the flow from raw data sources to a structured vector store, ensuring data is in the optimal format for retrieval by the AI model.</p>\n</div>\n<div class=\"paragraph\">\n<p>The RAG use case is text to augment the capabilities of generative models by retrieving relevant information from a body of data to enhance the quality and relevance of the generated output.</p>\n</div>',0x00,'asciidoc::etl-pipeline.adoc::0'),
('7ab6eb5c-7e8b-4761-b872-0f98de857704','This section serves as a guide to the <code>VectorStore</code> interface and its associated classes within the Spring AI framework.\n\nSpring AI offers an abstracted API for interacting with vector databases through the <code>VectorStore</code> interface and its read-only counterpart, the <code>VectorStoreRetriever</code> interface.',0x00,'asciidoc::vectordbs.adoc::API Overview::0'),
('09df7e1e-5cf3-48fa-aa17-0f997fbea693','@SuppressWarnings(\"CheckReturnValue\")\npublic static class CompareContext extends ParserRuleContext {\n\n    public TerminalNode EQUALS() {\n        return getToken(FiltersParser.EQUALS, 0);\n    }\n\n    public TerminalNode GT() {\n        return getToken(FiltersParser.GT, 0);\n    }\n\n    public TerminalNode GE() {\n        return getToken(FiltersParser.GE, 0);\n    }\n\n    public TerminalNode LT() {\n        return getToken(FiltersParser.LT, 0);\n    }\n\n    public TerminalNode LE() {\n        return getToken(FiltersParser.LE, 0);\n    }\n\n    public TerminalNode NE() {\n        return getToken(FiltersParser.NE, 0);\n    }\n\n    public CompareContext(ParserRuleContext parent, int invokingState) {\n        super(parent, invokingState);\n    }\n\n    @Override\n    public int getRuleIndex() {\n        return RULE_compare;\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterCompare(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitCompare(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitCompare(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('e1f81518-1ca1-4f95-bd9a-0fcd1765f291','Spring AI supports Optical Character Recognition (OCR) with Mistral AI. This allows you to extract text and image data from documents.',0x00,'asciidoc::mistralai-chat.adoc::Mistral AI OCR::0'),
('b352517b-c7be-43dd-8f18-0fe4e42ce512','We are transitioning the project&#8217;s Group ID:\n\n<strong>FROM</strong>: <code>org.springframework.experimental.ai</code>\n<strong>TO</strong>: <code>org.springframework.ai</code>\n\n\nArtifacts will still be hosted in the snapshot repository as shown below.\n\nThe main branch will move to the version <code>0.8.0-SNAPSHOT</code>.\nIt will be unstable for a week or two.\nPlease use the 0.7.1-SNAPSHOT if you don&#8217;t want to be on the bleeding edge.\n\nYou can access <code>0.7.1-SNAPSHOT</code> artifacts as before and still access <a href=\"https://markpollack.github.io/spring-ai-0.7.1/\">0.7.1-SNAPSHOT Documentation</a>.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 0.8.0::December 1, 2023::0'),
('c7e92462-ba9c-4253-b034-0ff3e204cbc7','The following methods are deprecated and will be removed in a future release:\n\n<code>ChatClient.Builder.defaultFunctions(String&#8230;&#8203;)</code>\n<code>ChatClient.Builder.defaultFunctions(FunctionCallback&#8230;&#8203;)</code>\n<code>ChatClient.RequestSpec.functions()</code>\n\n\nUse their <code>tools</code> counterparts instead.',0x00,'asciidoc::tools-migration.adoc::Deprecated Methods::0'),
('c8531bef-032b-4b69-9870-101ac9d85bd2','Spring AI 1.0.0 and later versions are available in Maven Central.\nNo additional repository configuration is required. Just make sure you have Maven Central enabled in your build file.\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;!-- Maven Central is included by default in Maven builds.\n     You usually don’t need to configure it explicitly,\n     but it\'s shown here for clarity. --&gt;\n&lt;repositories&gt;\n    &lt;repository&gt;\n        &lt;id&gt;central&lt;/id&gt;\n        &lt;url&gt;https://repo.maven.apache.org/maven2&lt;/url&gt;\n    &lt;/repository&gt;\n&lt;/repositories&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">repositories {\n    mavenCentral()\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>',0x00,'asciidoc::getting-started.adoc::Artifact Repositories::Releases - Use Maven Central::0'),
('abfd66a4-f137-4a3d-b91a-103c4d3aea3d','Multimodality refers to a model&#8217;s ability to simultaneously understand and process information from various sources, including text, pdf, images, data formats.',0x00,'asciidoc::anthropic-chat.adoc::Multimodal::0'),
('b28e4f50-4d5b-403c-b1aa-1040652afe82','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-azure-openai/src/main/java/org/springframework/ai/azure/openai/AzureOpenAiChatModel.java\">AzureOpenAiChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"https://learn.microsoft.com/en-us/java/api/overview/azure/ai-openai-readme?view=azure-java-preview\">Azure OpenAI Java Client</a>.\n\nTo enable it, add the <code>spring-ai-azure-openai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-azure-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-azure-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThe <code>spring-ai-azure-openai</code> dependency also provide the access to the <code>AzureOpenAiChatModel</code>. For more information about the <code>AzureOpenAiChatModel</code> refer to the <a href=\"../chat/azure-openai-chat.html\">Azure OpenAI Chat</a> section.\n\nNext, create an <code>AzureOpenAiChatModel</code> instance and use it to generate text responses:\n\nvar openAIClientBuilder = new OpenAIClientBuilder()\n  .credential(new AzureKeyCredential(System.getenv(\"AZURE_OPENAI_API_KEY\")))\n  .endpoint(System.getenv(\"AZURE_OPENAI_ENDPOINT\"));\n\nvar openAIChatOptions = AzureOpenAiChatOptions.builder()\n  .deploymentName(\"gpt-5\")\n  .temperature(0.4)\n  .maxCompletionTokens(200)\n  .build();\n\nvar chatModel = AzureOpenAiChatModel.builder()\n				.openAIClientBuilder(openAIClientBuilder)\n				.defaultOptions(openAIChatOptions)\n				.build();\n\nChatResponse response = chatModel.call(\n  new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; streamingResponses = chatModel.stream(\n  new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nthe <code>gpt-4o</code> is actually the <code>Deployment Name</code> as presented in the Azure AI Portal.',0x00,'asciidoc::azure-openai-chat.adoc::Manual Configuration::0'),
('5449f241-1a5b-4aa4-b463-106e70dcdf29','Instead of using the Spring Boot auto-configuration you can manually configure the Typesense vector store. For this you need to add the <code>spring-ai-typesense-store</code> to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-typesense-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-typesense-store\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nCreate a Typesense <code>Client</code> bean:\n\n@Bean\npublic Client typesenseClient() {\n    List&lt;Node&gt; nodes = new ArrayList&lt;&gt;();\n    nodes.add(new Node(\"http\", \"localhost\", \"8108\"));\n    Configuration configuration = new Configuration(nodes, Duration.ofSeconds(5), \"xyz\");\n    return new Client(configuration);\n}\n\nThen create the <code>TypesenseVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore vectorStore(Client client, EmbeddingModel embeddingModel) {\n    return TypesenseVectorStore.builder(client, embeddingModel)\n        .collectionName(\"custom_vectors\")     // Optional: defaults to \"vector_store\"\n        .embeddingDimension(1536)            // Optional: defaults to 1536\n        .initializeSchema(true)              // Optional: defaults to false\n        .batchingStrategy(new TokenCountBatchingStrategy()) // Optional: defaults to TokenCountBatchingStrategy\n        .build();\n}\n\n// This can be any EmbeddingModel implementation\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}',0x00,'asciidoc::typesense.adoc::Manual Configuration::0'),
('2aa6373b-feb0-4966-8623-1078852a5b03','The Chain Workflow pattern exemplifies the principle of breaking down complex tasks into simpler, more manageable steps.\n\n<strong>When to Use:</strong>\n- Tasks with clear sequential steps\n- When you want to trade latency for higher accuracy\n- When each step builds on the previous step&#8217;s output\n\nHere&#8217;s a practical example from Spring AI&#8217;s implementation:\n\npublic class ChainWorkflow {\n    private final ChatClient chatClient;\n    private final String[] systemPrompts;\n\n    public String chain(String userInput) {\n        String response = userInput;\n        for (String prompt : systemPrompts) {\n            String input = String.format(\"{%s}\\n {%s}\", prompt, response);\n            response = chatClient.prompt(input).call().content();\n        }\n        return response;\n    }\n}\n\nThis implementation demonstrates several key principles:\n\nEach step has a focused responsibility\nOutput from one step becomes input for the next\nThe chain is easily extensible and maintainable',0x00,'asciidoc::effective-agents.adoc::Agentic Systems::1. <a href=\"https://github.com/spring-projects/spring-ai-examples/tree/main/agentic-patterns/chain-workflow\">Chain Workflow</a>::0'),
('8f764754-84ad-4d39-97a9-10b14bda8cd1','Spring AI 1.0.0-M7 is the last milestone release before the RC1 and GA releases. It introduces several important changes to artifact IDs, package names, and module structure that will be maintained in the final release.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M7::Overview of Changes::0'),
('54fb101e-0d76-4536-9461-10c9eaa7c7dd','<strong>Active vs Completed</strong>: <code><strong><em>active_count</code> shows in-flight calls; the <code>_seconds</em></strong></code> series reflect only completed calls.',0x00,'asciidoc::index.adoc::More Metrics Reference::Chat Client Metrics::0'),
('5f92da21-99fd-4044-85f0-113f1bb50610','All the main operations of the tool calling features are logged at the <code>DEBUG</code> level. You can enable the logging by setting the log level to <code>DEBUG</code> for the <code>org.springframework.ai</code> package.',0x00,'asciidoc::tools.adoc::Observability::Logging::0'),
('4912ef03-abf6-4196-a726-1193552970ac','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::bedrock-titan-embedding.adoc::Prerequisites::Add Repositories and BOM::0'),
('5cb7c6db-68fc-4d5e-8ed8-119672ea2f53','/**\n * Similarity search request. Use the {@link SearchRequest#builder()} to create the\n * instance of a {@link SearchRequest}.\n *\n * @author Christian Tzolov\n * @author Thomas Vitale\n * @author Ilayaperumal Gopinathan\n */\npublic class SearchRequest {\n\n    /**\n     * Similarity threshold that accepts all search scores. A threshold value of 0.0 means\n     * any similarity is accepted or disable the similarity threshold filtering. A\n     * threshold value of 1.0 means an exact match is required.\n     */\n    public static final double SIMILARITY_THRESHOLD_ACCEPT_ALL = 0.0;\n\n    /**\n     * Default value for the top \'k\' similar results to return.\n     */\n    public static final int DEFAULT_TOP_K = 4;\n\n    /**\n     * Default value is empty string.\n     */\n    private String query = \"\";\n\n    private int topK = DEFAULT_TOP_K;\n\n    private double similarityThreshold = SIMILARITY_THRESHOLD_ACCEPT_ALL;\n\n    @Nullable\n    private Filter.Expression filterExpression;\n\n    /**\n     * Copy an existing {@link SearchRequest.Builder} instance.\n     * @param originalSearchRequest {@link SearchRequest} instance to copy.\n     * @return Returns new {@link SearchRequest.Builder} instance.\n     */\n    public static Builder from(SearchRequest originalSearchRequest) {\n        return builder().query(originalSearchRequest.getQuery()).topK(originalSearchRequest.getTopK()).similarityThreshold(originalSearchRequest.getSimilarityThreshold()).filterExpression(originalSearchRequest.getFilterExpression());\n    }\n\n    public SearchRequest() {\n    }\n\n    protected SearchRequest(SearchRequest original) {\n        this.query = original.query;\n        this.topK = original.topK;\n        this.similarityThreshold = original.similarityThreshold;\n        this.filterExpression = original.filterExpression;\n    }\n\n    public String getQuery() {\n        return this.query;\n    }\n\n    public int getTopK() {\n        return this.topK;\n    }\n\n    public double getSimilarityThreshold() {\n        return this.similarityThreshold;\n    }\n\n    @Nullable\n    public Filter.Expression getFilterExpression() {\n        return this.filterExpression;\n    }\n\n    public boolean hasFilterExpression() {\n        return this.filterExpression != null;\n    }\n\n    @Override\n    public String toString() {\n        return \"SearchRequest{\" + \"query=\'\" + this.query + \'\\\'\' + \", topK=\" + this.topK + \", similarityThreshold=\" + this.similarityThreshold + \", filterExpression=\" + this.filterExpression + \'}\';\n    }\n\n    @Override\n    public boolean equals(Object o) {\n        if (this == o) {\n            return true;\n        }\n        if (o == null || getClass() != o.getClass()) {\n            return false;\n        }\n        SearchRequest that = (SearchRequest) o;\n        return this.topK == that.topK && Double.compare(that.similarityThreshold, this.similarityThreshold) == 0 && Objects.equals(this.query, that.query) && Objects.equals(this.filterExpression, that.filterExpression);\n    }\n\n    @Override\n    public int hashCode() {\n        return Objects.hash(this.query, this.topK, this.similarityThreshold, this.filterExpression);\n    }\n\n    /**\n     * Builder for creating the SearchRequest instance.\n     * @return the builder.\n     */\n    public static Builder builder() {\n        return new Builder();\n    }\n\n    /**\n     * SearchRequest Builder.\n     */\n    public static final class Builder {\n\n        private final SearchRequest searchRequest = new SearchRequest();\n\n        /**\n         * @param query Text to use for embedding similarity comparison.\n         * @return this builder.\n         */\n        public Builder query(String query) {\n            Assert.notNull(query, \"Query can not be null.\");\n            this.searchRequest.query = query;\n            return this;\n        }\n\n        /**\n         * @param topK the top \'k\' similar results to return.\n         * @return this builder.\n         */\n        public Builder topK(int topK) {\n            Assert.isTrue(topK >= 0, \"TopK should be positive.\");\n            this.searchRequest.topK = topK;\n            return this;\n        }\n\n        /**\n         * Similarity threshold score to filter the search response by. Only documents\n         * with similarity score equal or greater than the \'threshold\' will be returned.\n         * Note that this is a post-processing step performed on the client not the server\n         * side. A threshold value of 0.0 means any similarity is accepted or disable the\n         * similarity threshold filtering. A threshold value of 1.0 means an exact match\n         * is required.\n         * @param threshold The lower bound of the similarity score.\n         * @return this builder.\n         */\n        public Builder similarityThreshold(double threshold) {\n            Assert.isTrue(threshold >= 0 && threshold <= 1, \"Similarity threshold must be in [0,1] range.\");\n            this.searchRequest.similarityThreshold = threshold;\n            return this;\n        }\n\n        /**\n         * Sets disables the similarity threshold by setting it to 0.0 - all results are\n         * accepted.\n         * @return this builder.\n         */\n        public Builder similarityThresholdAll() {\n            this.searchRequest.similarityThreshold = 0.0;\n            return this;\n        }\n\n        /**\n         * Retrieves documents by query embedding similarity and matching the filters.\n         * Value of \'null\' means that no metadata filters will be applied to the search.\n         *\n         * For example if the {@link Document#getMetadata()} schema is:\n         *\n         * <pre>{@code\n         * &#123;\n         * \"country\": <Text>,\n         * \"city\": <Text>,\n         * \"year\": <Number>,\n         * \"price\": <Decimal>,\n         * \"isActive\": <Boolean>\n         * &#125;\n         * }</pre>\n         *\n         * you can constrain the search result to only UK countries with isActive=true and\n         * year equal or greater 2020. You can build this such metadata filter\n         * programmatically like this:\n         *\n         * <pre>{@code\n         * var exp = new Filter.Expression(AND,\n         * 		new Expression(EQ, new Key(\"country\"), new Value(\"UK\")),\n         * 		new Expression(AND,\n         * 				new Expression(GTE, new Key(\"year\"), new Value(2020)),\n         * 				new Expression(EQ, new Key(\"isActive\"), new Value(true))));\n         * }</pre>\n         *\n         * The {@link Filter.Expression} is portable across all vector stores.<br/>\n         *\n         * The {@link FilterExpressionBuilder} is a DSL creating expressions\n         * programmatically:\n         *\n         * <pre>{@code\n         * var b = new FilterExpressionBuilder();\n         * var exp = b.and(\n         * 		b.eq(\"country\", \"UK\"),\n         * 		b.and(\n         * 			b.gte(\"year\", 2020),\n         * 			b.eq(\"isActive\", true)));\n         * }</pre>\n         *\n         * The {@link FilterExpressionTextParser} converts textual, SQL like filter\n         * expression language into {@link Filter.Expression}:\n         *\n         * <pre>{@code\n         * var parser = new FilterExpressionTextParser();\n         * var exp = parser.parse(\"country == \'UK\' && isActive == true && year >=2020\");\n         * }</pre>\n         * @param expression {@link Filter.Expression} instance used to define the\n         * metadata filter criteria. The \'null\' value stands for no expression filters.\n         * @return this builder.\n         */\n        public Builder filterExpression(@Nullable Filter.Expression expression) {\n            this.searchRequest.filterExpression = expression;\n            return this;\n        }\n\n        /**\n         * Document metadata filter expression. For example if your\n         * {@link Document#getMetadata()} has a schema like:\n         *\n         * <pre>{@code\n         * &#123;\n         * \"country\": <Text>,\n         * \"city\": <Text>,\n         * \"year\": <Number>,\n         * \"price\": <Decimal>,\n         * \"isActive\": <Boolean>\n         * &#125;\n         * }</pre>\n         *\n         * then you can constrain the search result with metadata filter expressions like:\n         *\n         * <pre>{@code\n         * country == \'UK\' && year >= 2020 && isActive == true\n         * Or\n         * country == \'BG\' && (city NOT IN [\'Sofia\', \'Plovdiv\'] || price < 134.34)\n         * }</pre>\n         *\n         * This ensures that the response contains only embeddings that match the\n         * specified filer criteria. <br/>\n         *\n         * The declarative, SQL like, filter syntax is portable across all vector stores\n         * supporting the filter search feature.<br/>\n         *\n         * The {@link FilterExpressionTextParser} is used to convert the text filter\n         * expression into {@link Filter.Expression}.\n         * @param textExpression declarative, portable, SQL like, metadata filter syntax.\n         * The \'null\' value stands for no expression filters.\n         * @return this.builder\n         */\n        public Builder filterExpression(@Nullable String textExpression) {\n            this.searchRequest.filterExpression = (textExpression != null) ? new FilterExpressionTextParser().parse(textExpression) : null;\n            return this;\n        }\n\n        public SearchRequest build() {\n            return this.searchRequest;\n        }\n    }\n}',0x01,'cu::SearchRequest.java'),
('fff671e1-db1d-4f6e-862f-11aaa15218e3','Legal Document Analysis\n\nAnalyze contracts and legal documents while maintaining source attribution:\n\nCitationDocument contract = CitationDocument.builder()\n    .pdfFile(\"merger-agreement.pdf\")\n    .title(\"Merger Agreement 2024\")\n    .citationsEnabled(true)\n    .build();\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What are the key termination clauses in this contract?\",\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .maxTokens(2000)\n            .citationDocuments(contract)\n            .build()\n    )\n);\n\n// Citations will reference specific pages in the PDF\n\nCustomer Support Knowledge Base\n\nProvide accurate customer support answers with verifiable sources:\n\nCitationDocument kbArticle1 = CitationDocument.builder()\n    .plainText(loadKnowledgeBaseArticle(\"authentication\"))\n    .title(\"Authentication Guide\")\n    .citationsEnabled(true)\n    .build();\n\nCitationDocument kbArticle2 = CitationDocument.builder()\n    .plainText(loadKnowledgeBaseArticle(\"billing\"))\n    .title(\"Billing FAQ\")\n    .citationsEnabled(true)\n    .build();\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"How do I reset my password and update my billing information?\",\n        AnthropicChatOptions.builder()\n            .model(\"claude-3-7-sonnet-latest\")\n            .citationDocuments(kbArticle1, kbArticle2)\n            .build()\n    )\n);\n\n// Citations show which KB articles were referenced\n\nResearch and Compliance\n\nGenerate reports that require source citations for compliance:\n\nCitationDocument clinicalStudy = CitationDocument.builder()\n    .pdfFile(\"clinical-trial-results.pdf\")\n    .title(\"Clinical Trial Phase III Results\")\n    .citationsEnabled(true)\n    .build();\n\nCitationDocument regulatoryGuidance = CitationDocument.builder()\n    .plainText(loadRegulatoryDocument())\n    .title(\"FDA Guidance Document\")\n    .citationsEnabled(true)\n    .build();\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Summarize the efficacy findings and regulatory implications.\",\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .maxTokens(3000)\n            .citationDocuments(clinicalStudy, regulatoryGuidance)\n            .build()\n    )\n);\n\n// Citations provide audit trail for compliance',0x00,'asciidoc::anthropic-chat.adoc::Citations::Real-World Use Cases::0'),
('146a7aee-943c-4fe5-a600-11fb75c11b63','When using the default behavior, Spring AI will automatically intercept any tool call request from the model, call the tool and return the result to the model. All of this is done transparently for you by each <code>ChatModel</code> implementation using a <code>ToolCallingManager</code>.\n\nWhen we want to make a tool available to the model, we include its definition in the chat request (<code>Prompt</code>) and invoke the <code>ChatModel</code> API which sends the request to the AI model.\nWhen the model decides to call a tool, it sends a response (<code>ChatResponse</code>) with the tool name and the input parameters modeled after the defined schema.\nThe <code>ChatModel</code> sends the tool call request to the <code>ToolCallingManager</code> API.\nThe <code>ToolCallingManager</code> is responsible for identifying the tool to call and executing it with the provided input parameters.\nThe result of the tool call is returned to the <code>ToolCallingManager</code>.\nThe <code>ToolCallingManager</code> returns the tool execution result back to the <code>ChatModel</code>.\nThe <code>ChatModel</code> sends the tool execution result back to the AI model (<code>ToolResponseMessage</code>).\nThe AI model generates the final response using the tool call result as additional context and sends it back to the caller (<code>ChatResponse</code>) via the <code>ChatClient</code>.\n\n\nCurrently, the internal messages exchanged with the model regarding the tool execution are not exposed to the user. If you need to access these messages, you should use the user-controlled tool execution approach.\n\nThe logic determining whether a tool call is eligible for execution is handled by the <code>ToolExecutionEligibilityPredicate</code> interface. By default, the tool execution eligibility is determined by checking if the <code>internalToolExecutionEnabled</code> attribute of <code>ToolCallingChatOptions</code> is set to <code>true</code> (the default value), and if the <code>ChatResponse</code> contains any tool calls.\n\npublic class DefaultToolExecutionEligibilityPredicate implements ToolExecutionEligibilityPredicate {\n\n	@Override\n	public boolean test(ChatOptions promptOptions, ChatResponse chatResponse) {\n		return ToolCallingChatOptions.isInternalToolExecutionEnabled(promptOptions) &amp;&amp; chatResponse != null\n				&amp;&amp; chatResponse.hasToolCalls();\n	}\n\n}\n\nYou can provide your custom implementation of <code>ToolExecutionEligibilityPredicate</code> when creating the <code>ChatModel</code> bean.',0x00,'asciidoc::tools.adoc::Tool Execution::Framework-Controlled Tool Execution::0'),
('c793b9c3-7283-40e4-9675-12397e317525','<a href=\"https://docs.perplexity.ai/home\">Documentation Home</a>\n<a href=\"https://docs.perplexity.ai/api-reference/chat-completions\">API Reference</a>\n<a href=\"https://docs.perplexity.ai/guides/getting-started\">Getting Started</a>\n<a href=\"https://docs.perplexity.ai/guides/rate-limits\">Rate Limits</a>',0x00,'asciidoc::perplexity-chat.adoc::References::0'),
('7e54907b-8c31-4467-9487-12768ea9ac44','You often want to return an entity class that is mapped from the returned <code>String</code>.\nThe <code>entity()</code> method provides this functionality.\n\nFor example, given the Java record:\n\nrecord ActorFilms(String actor, List&lt;String&gt; movies) {}\n\nYou can easily map the AI model&#8217;s output to this record using the <code>entity()</code> method, as shown below:\n\nActorFilms actorFilms = chatClient.prompt()\n    .user(\"Generate the filmography for a random actor.\")\n    .call()\n    .entity(ActorFilms.class);\n\nThere is also an overloaded <code>entity</code> method with the signature <code>entity(ParameterizedTypeReference&lt;T&gt; type)</code> that lets you specify types such as generic Lists:\n\nList&lt;ActorFilms&gt; actorFilms = chatClient.prompt()\n    .user(\"Generate the filmography of 5 movies for Tom Hanks and Bill Murray.\")\n    .call()\n    .entity(new ParameterizedTypeReference&lt;List&lt;ActorFilms&gt;&gt;() {});\n\nNative Structured Output\n\nAs more AI models support structured output natively, you can take advantage of this feature by using the <code>AdvisorParams.ENABLE_NATIVE_STRUCTURED_OUTPUT</code> advisor parameter when calling the <code>ChatClient</code>.\nYou can use the <code>defaultAdvisors()</code> method on the <code>ChatClient.Builder</code> to set this parameter globally for all calls or set it per call as shown below:\n\nActorFilms actorFilms = chatClient.prompt()\n    .advisors(AdvisorParams.ENABLE_NATIVE_STRUCTURED_OUTPUT)\n    .user(\"Generate the filmography for a random actor.\")\n    .call()\n    .entity(ActorFilms.class);\n\nSome AI models such as OpenAI don&#8217;t support arrays of objects natively.\nIn such cases, you can use the Spring AI default structured output conversion.',0x00,'asciidoc::chatclient.adoc::ChatClient Responses::Returning an Entity::0'),
('ce8ef686-52aa-49b4-a86f-1286cbd17316','In this example, if the <code>JsonReader</code> is configured with <code>\"description\"</code> as the <code>jsonKeysToUse</code>, it will create <code>Document</code> objects where the content is the value of the \"description\" field for each bike in the array.\n\nNotes\n\nThe <code>JsonReader</code> uses Jackson for JSON parsing.\nIt can handle large JSON files efficiently by using streaming for arrays.\nIf multiple keys are specified in <code>jsonKeysToUse</code>, the content will be a concatenation of the values for those keys.\nThe reader is flexible and can be adapted to various JSON structures by customizing the <code>jsonKeysToUse</code> and <code>JsonMetadataGenerator</code>.',0x00,'asciidoc::etl-pipeline.adoc::DocumentReaders::JSON::1'),
('e592adc7-bc45-4af8-9aeb-1293e78d0dcb','/**\n * Builder interface for creating VectorStore instances. Implements a fluent builder\n * pattern for configuring observation-related settings.\n *\n * @param <T> the concrete builder type, enabling method chaining with the correct\n * return type\n */\ninterface Builder<T extends Builder<T>> {\n\n    /**\n     * Sets the registry for collecting observations and metrics. Defaults to\n     * {@link ObservationRegistry#NOOP} if not specified.\n     * @param observationRegistry the registry to use for observations\n     * @return the builder instance for method chaining\n     */\n    T observationRegistry(ObservationRegistry observationRegistry);\n\n    /**\n     * Sets a custom convention for creating observations. If not specified,\n     * {@link DefaultVectorStoreObservationConvention} will be used.\n     * @param convention the custom observation convention to use\n     * @return the builder instance for method chaining\n     */\n    T customObservationConvention(VectorStoreObservationConvention convention);\n\n    /**\n     * Sets the batching strategy.\n     * @param batchingStrategy the strategy to use\n     * @return the builder instance for method chaining\n     */\n    T batchingStrategy(BatchingStrategy batchingStrategy);\n\n    /**\n     * Builds and returns a new VectorStore instance with the configured settings.\n     * @return a new VectorStore instance\n     */\n    VectorStore build();\n}',0x01,'cu::VectorStore.java'),
('14a583d2-a7e0-4926-beaf-12c28c09f0e0','Spring AI Ollama can automatically pull models when they are not available in your Ollama instance.\nThis feature is particularly useful for development and testing as well as for deploying your applications to new environments.\n\nYou can also pull, by name, any of the thousands, free, <a href=\"https://huggingface.co/models?library=gguf&amp;sort=trending\">GGUF Hugging Face Models</a>.\n\nThere are three strategies for pulling models:\n\n<code>always</code> (defined in <code>PullModelStrategy.ALWAYS</code>): Always pull the model, even if it&#8217;s already available. Useful to ensure you&#8217;re using the latest version of the model.\n<code>when_missing</code> (defined in <code>PullModelStrategy.WHEN_MISSING</code>): Only pull the model if it&#8217;s not already available. This may result in using an older version of the model.\n<code>never</code> (defined in <code>PullModelStrategy.NEVER</code>): Never pull the model automatically.\n\n\nDue to potential delays while downloading models, automatic pulling is not recommended for production environments. Instead, consider assessing and pre-downloading the necessary models in advance.\n\nAll models defined via configuration properties and default options can be automatically pulled at startup time.\nYou can configure the pull strategy, timeout, and maximum number of retries using configuration properties:\n\nspring:\n  ai:\n    ollama:\n      init:\n        pull-model-strategy: always\n        timeout: 60s\n        max-retries: 1\n\nThe application will not complete its initialization until all specified models are available in Ollama. Depending on the model size and internet connection speed, this may significantly slow down your application&#8217;s startup time.\n\nYou can initialize additional models at startup, which is useful for models used dynamically at runtime:\n\nspring:\n  ai:\n    ollama:\n      init:\n        pull-model-strategy: always\n        chat:\n          additional-models:\n            - llama3.2\n            - qwen2.5\n\nIf you want to apply the pulling strategy only to specific types of models, you can exclude chat models from the initialization task:\n\nspring:\n  ai:\n    ollama:\n      init:\n        pull-model-strategy: always\n        chat:\n          include: false\n\nThis configuration will apply the pulling strategy to all models except chat models.',0x00,'asciidoc::ollama-chat.adoc::Auto-pulling Models::0'),
('0884d76f-6295-4e84-b4b7-130fcaaae4cc','To create an advisor, implement either <code>CallAdvisor</code> or <code>StreamAdvisor</code> (or both). The key method to implement is <code>nextCall()</code> for non-streaming or <code>nextStream()</code> for streaming advisors.',0x00,'asciidoc::advisors.adoc::Implementing an Advisor::0'),
('614ae480-8d36-4b8b-8a84-132d3f72ba74','<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=postgresml (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match postgresml)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.postgresml.embedding</code> is property prefix that configures the <code>EmbeddingModel</code> implementation for PostgresML embeddings.\n\n\n\nAll properties prefixed with <code>spring.ai.postgresml.embedding.options</code> can be overridden at runtime by adding a request specific <a href=\"#embedding-options\">Runtime Options</a> to the <code>EmbeddingRequest</code> call.',0x00,'asciidoc::postgresml-embeddings.adoc::Auto-configuration::Embedding Properties::0'),
('4b819142-95d1-48db-a10f-1445d225e180','The <code>JsoupDocumentReader</code> processes HTML documents, converting them into a list of <code>Document</code> objects using the JSoup library.\n\nExample\n\n@Component\nclass MyHtmlReader {\n\n    private final Resource resource;\n\n    MyHtmlReader(@Value(\"classpath:/my-page.html\") Resource resource) {\n        this.resource = resource;\n    }\n\n    List&lt;Document&gt; loadHtml() {\n        JsoupDocumentReaderConfig config = JsoupDocumentReaderConfig.builder()\n            .selector(\"article p\") // Extract paragraphs within &lt;article&gt; tags\n            .charset(\"ISO-8859-1\")  // Use ISO-8859-1 encoding\n            .includeLinkUrls(true) // Include link URLs in metadata\n            .metadataTags(List.of(\"author\", \"date\")) // Extract author and date meta tags\n            .additionalMetadata(\"source\", \"my-page.html\") // Add custom metadata\n            .build();\n\n        JsoupDocumentReader reader = new JsoupDocumentReader(this.resource, config);\n        return reader.get();\n    }\n}\n\nThe <code>JsoupDocumentReaderConfig</code> allows you to customize the behavior of the <code>JsoupDocumentReader</code>:\n\n<code>charset</code>:  Specifies the character encoding of the HTML document (defaults to \"UTF-8\").\n<code>selector</code>:  A JSoup CSS selector to specify which elements to extract text from (defaults to \"body\").\n<code>separator</code>:  The string used to join text from multiple selected elements (defaults to \"\\n\").\n<code>allElements</code>:  If <code>true</code>, extracts all text from the <code>&lt;body&gt;</code> element, ignoring the <code>selector</code> (defaults to <code>false</code>).\n<code>groupByElement</code>: If <code>true</code>, creates a separate <code>Document</code> for each element matched by the <code>selector</code> (defaults to <code>false</code>).\n<code>includeLinkUrls</code>:  If <code>true</code>, extracts absolute link URLs and adds them to the metadata (defaults to <code>false</code>).\n<code>metadataTags</code>:  A list of <code>&lt;meta&gt;</code> tag names to extract content from (defaults to <code>[\"description\", \"keywords\"]</code>).\n<code>additionalMetadata</code>:  Allows you to add custom metadata to all created <code>Document</code> objects.\n\n\nSample Document: my-page.html',0x00,'asciidoc::etl-pipeline.adoc::DocumentReaders::HTML (JSoup)::0'),
('b335bdbd-2fe8-4a86-8d36-147ccd5ddfd7','<code>MessageWindowChatMemory</code> maintains a window of messages up to a specified maximum size. When the number of messages exceeds the maximum, older messages are removed while preserving system messages. The default window size is 20 messages.\n\nMessageWindowChatMemory memory = MessageWindowChatMemory.builder()\n    .maxMessages(10)\n    .build();\n\nThis is the default message type used by Spring AI to auto-configure a <code>ChatMemory</code> bean.',0x00,'asciidoc::chat-memory.adoc::Memory Types::Message Window Chat Memory::0'),
('f45db730-bc32-4721-b225-1488a26a4534','<div class=\"paragraph\">\n<p>If you see an error like <code>Caused by: ai.onnxruntime.OrtException: Supplied array is ragged,..</code>, you need to also enable the tokenizer padding in <code>application.properties</code> as follows:</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre>spring.ai.embedding.transformer.tokenizer.options.padding=true</pre>\n</div>\n</div>\n\n<div class=\"paragraph\">\n<p>If you get an error like <code>The generative output names don&#8217;t contain expected: last_hidden_state. Consider one of the available model outputs: token_embeddings, &#8230;&#8203;.</code>, you need to set the model output name to a correct value per your models.\nConsider the names listed in the error message.\nFor example:</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre>spring.ai.embedding.transformer.onnx.modelOutputName=token_embeddings</pre>\n</div>\n</div>\n\n<div class=\"paragraph\">\n<p>If you get an error like <code>ai.onnxruntime.OrtException: Error code - ORT_FAIL - message: Deserialize tensor onnx::MatMul_10319 failed.GetFileLength for ./model.onnx_data failed:Invalid fd was supplied: -1</code>,\nthat means that you model is larger than 2GB and is serialized in two files: <code>model.onnx</code> and <code>model.onnx_data</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <code>model.onnx_data</code> is called <a href=\"https://onnx.ai/onnx/repo-docs/ExternalData.html#external-data\">External Data</a> and is expected to be under the same directory of the <code>model.onnx</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>Currently the only workaround is to copy the large <code>model.onnx_data</code> in the folder you run your Boot application.</p>\n</div>\n\n<div class=\"paragraph\">\n<p>If you get an error like <code>ai.onnxruntime.OrtException: Error code - ORT_EP_FAIL - message: Failed to find CUDA shared provider</code>,\nthat means that you are using the GPU parameters <code>spring.ai.embedding.transformer.onnx.gpuDeviceId</code> , but the onnxruntime_gpu dependency are missing.</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre>&lt;dependency&gt;\n    &lt;groupId&gt;com.microsoft.onnxruntime&lt;/groupId&gt;\n    &lt;artifactId&gt;onnxruntime_gpu&lt;/artifactId&gt;\n&lt;/dependency&gt;</pre>\n</div>\n</div>\n<div class=\"paragraph\">\n<p>Please select the appropriate onnxruntime_gpu version based on the CUDA version(<a href=\"https://onnxruntime.ai/docs/get-started/with-java.html\">ONNX Java Runtime</a>).</p>\n</div>',0x00,'asciidoc::onnx.adoc::Auto-configuration::Errors and special cases::0'),
('4209e99c-7825-479a-ac4f-14e105c52d74','public class SearchRequest {\n\n	public static final double SIMILARITY_THRESHOLD_ACCEPT_ALL = 0.0;\n\n	public static final int DEFAULT_TOP_K = 4;\n\n	private String query = \"\";\n\n	private int topK = DEFAULT_TOP_K;\n\n	private double similarityThreshold = SIMILARITY_THRESHOLD_ACCEPT_ALL;\n\n	@Nullable\n	private Filter.Expression filterExpression;\n\n    public static Builder from(SearchRequest originalSearchRequest) {\n		return builder().query(originalSearchRequest.getQuery())\n			.topK(originalSearchRequest.getTopK())\n			.similarityThreshold(originalSearchRequest.getSimilarityThreshold())\n			.filterExpression(originalSearchRequest.getFilterExpression());\n	}\n\n	public static class Builder {\n\n		private final SearchRequest searchRequest = new SearchRequest();\n\n		public Builder query(String query) {\n			Assert.notNull(query, \"Query can not be null.\");\n			this.searchRequest.query = query;\n			return this;\n		}\n\n		public Builder topK(int topK) {\n			Assert.isTrue(topK &gt;= 0, \"TopK should be positive.\");\n			this.searchRequest.topK = topK;\n			return this;\n		}\n\n		public Builder similarityThreshold(double threshold) {\n			Assert.isTrue(threshold &gt;= 0 &amp;&amp; threshold &lt;= 1, \"Similarity threshold must be in [0,1] range.\");\n			this.searchRequest.similarityThreshold = threshold;\n			return this;\n		}\n\n		public Builder similarityThresholdAll() {\n			this.searchRequest.similarityThreshold = 0.0;\n			return this;\n		}\n\n		public Builder filterExpression(@Nullable Filter.Expression expression) {\n			this.searchRequest.filterExpression = expression;\n			return this;\n		}\n\n		public Builder filterExpression(@Nullable String textExpression) {\n			this.searchRequest.filterExpression = (textExpression != null)\n					? new FilterExpressionTextParser().parse(textExpression) : null;\n			return this;\n		}\n\n		public SearchRequest build() {\n			return this.searchRequest;\n		}\n\n	}\n\n	public String getQuery() {...}\n	public int getTopK() {...}\n	public double getSimilarityThreshold() {...}\n	public Filter.Expression getFilterExpression() {...}\n}\n\nTo insert data into the vector database, encapsulate it within a <code>Document</code> object.\nThe <code>Document</code> class encapsulates content from a data source, such as a PDF or Word document, and includes text represented as a string.\nIt also contains metadata in the form of key-value pairs, including details such as the filename.\n\nUpon insertion into the vector database, the text content is transformed into a numerical array, or a <code>float[]</code>, known as vector embeddings, using an embedding model. Embedding models, such as <a href=\"https://en.wikipedia.org/wiki/Word2vec\">Word2Vec</a>, <a href=\"https://en.wikipedia.org/wiki/GloVe_(machine_learning)\">GLoVE</a>, and <a href=\"https://en.wikipedia.org/wiki/BERT_(language_model)\">BERT</a>, or OpenAI&#8217;s <code>text-embedding-ada-002</code>, are used to convert words, sentences, or paragraphs into these vector embeddings.',0x00,'asciidoc::vectordbs.adoc::API Overview::SearchRequest Builder::0'),
('1b3db859-ae7d-4592-9f45-15002e9709ae','Spring AI supports passing additional contextual information to tools through the <code>ToolContext</code> API. This feature allows you to provide extra, user-provided data that can be used within the tool execution along with the tool arguments passed by the AI model.\n\nclass CustomerTools {\n\n    @Tool(description = \"Retrieve customer information\")\n    Customer getCustomerInfo(Long id, ToolContext toolContext) {\n        return customerRepository.findById(id, toolContext.getContext().get(\"tenantId\"));\n    }\n\n}\n\nThe <code>ToolContext</code> is populated with the data provided by the user when invoking <code>ChatClient</code>.\n\nChatModel chatModel = ...\n\nString response = ChatClient.create(chatModel)\n        .prompt(\"Tell me more about the customer with ID 42\")\n        .tools(new CustomerTools())\n        .toolContext(Map.of(\"tenantId\", \"acme\"))\n        .call()\n        .content();\n\nSystem.out.println(response);\n\nNone of the data provided in the <code>ToolContext</code> is sent to the AI model.\n\nSimilarly, you can define tool context data when invoking the <code>ChatModel</code> directly.\n\nChatModel chatModel = ...\nToolCallback[] customerTools = ToolCallbacks.from(new CustomerTools());\nChatOptions chatOptions = ToolCallingChatOptions.builder()\n    .toolCallbacks(customerTools)\n    .toolContext(Map.of(\"tenantId\", \"acme\"))\n    .build();\nPrompt prompt = new Prompt(\"Tell me more about the customer with ID 42\", chatOptions);\nchatModel.call(prompt);\n\nIf the <code>toolContext</code> option is set both in the default options and in the runtime options, the resulting <code>ToolContext</code> will be the merge of the two,\nwhere the runtime options take precedence over the default options.',0x00,'asciidoc::tools.adoc::Tool Specification::Tool Context::0'),
('5cece3bd-31da-4e6c-8df5-1586f72e3482','/**\n * Helper class providing various boolean transformation.\n *\n * @author Christian Tzolov\n */\npublic final class FilterHelper {\n\n    private static final Map<ExpressionType, ExpressionType> TYPE_NEGATION_MAP = Map.of(ExpressionType.AND, ExpressionType.OR, ExpressionType.OR, ExpressionType.AND, ExpressionType.EQ, ExpressionType.NE, ExpressionType.NE, ExpressionType.EQ, ExpressionType.GT, ExpressionType.LTE, ExpressionType.GTE, ExpressionType.LT, ExpressionType.LT, ExpressionType.GTE, ExpressionType.LTE, ExpressionType.GT, ExpressionType.IN, ExpressionType.NIN, ExpressionType.NIN, ExpressionType.IN);\n\n    private FilterHelper() {\n    }\n\n    /**\n     * Transforms the input expression into a semantically equivalent one with negation\n     * operators propagated thought the expression tree by following the negation rules:\n     *\n     * <pre>\n     * 	NOT(NOT(a)) = a\n     *\n     * 	NOT(a AND b) = NOT(a) OR NOT(b)\n     * 	NOT(a OR b) = NOT(a) AND NOT(b)\n     *\n     * 	NOT(a EQ b) = a NE b\n     * 	NOT(a NE b) = a EQ b\n     *\n     * 	NOT(a GT b) = a LTE b\n     * 	NOT(a GTE b) = a LT b\n     *\n     * 	NOT(a LT b) = a GTE b\n     * 	NOT(a LTE b) = a GT b\n     *\n     * 	NOT(a IN [...]) = a NIN [...]\n     * 	NOT(a NIN [...]) = a IN [...]\n     * </pre>\n     * @param operand Filter expression to negate.\n     * @return Returns an negation of the input expression.\n     */\n    public static Filter.Operand negate(Filter.Operand operand) {\n        if (operand instanceof Filter.Group group) {\n            Operand inEx = negate(group.content());\n            if (inEx instanceof Filter.Group inEx2) {\n                inEx = inEx2.content();\n            }\n            return new Filter.Group((Expression) inEx);\n        } else if (operand instanceof Filter.Expression exp) {\n            switch(exp.type()) {\n                case // NOT(NOT(a)) = a\n                NOT:\n                    return negate(exp.left());\n                // NOT(a AND b) = NOT(a) OR NOT(b)\n                case AND:\n                case // NOT(a OR b) = NOT(a) AND NOT(b)\n                OR:\n                    return new Filter.Expression(TYPE_NEGATION_MAP.get(exp.type()), negate(exp.left()), negate(exp.right()));\n                // NOT(e EQ b) = e NE b\n                case EQ:\n                // NOT(e NE b) = e EQ b\n                case NE:\n                // NOT(e GT b) = e LTE b\n                case GT:\n                // NOT(e GTE b) = e LT b\n                case GTE:\n                // NOT(e LT b) = e GTE b\n                case LT:\n                case // NOT(e LTE b) = e GT b\n                LTE:\n                    return new Filter.Expression(TYPE_NEGATION_MAP.get(exp.type()), exp.left(), exp.right());\n                // NOT(e IN [...]) = e NIN [...]\n                case IN:\n                case // NOT(e NIN [...]) = e IN [...]\n                NIN:\n                    return new Filter.Expression(TYPE_NEGATION_MAP.get(exp.type()), exp.left(), exp.right());\n                default:\n                    throw new IllegalArgumentException(\"Unknown expression type: \" + exp.type());\n            }\n        } else {\n            throw new IllegalArgumentException(\"Can not negate operand of type: \" + operand.getClass());\n        }\n    }\n\n    /**\n     * Expands the IN into a semantically equivalent boolean expressions of ORs of EQs.\n     * Useful for providers that don\'t provide native IN support.\n     *\n     * For example the <pre>\n     * foo IN [\"bar1\", \"bar2\", \"bar3\"]\n     * </pre>\n     *\n     * expression is equivalent to\n     *\n     * <pre>\n     * {@code foo == \"bar1\" || foo == \"bar2\" || foo == \"bar3\" (e.g. OR(foo EQ \"bar1\" OR(foo EQ \"bar2\" OR(foo EQ \"bar3\")))}\n     * </pre>\n     * @param exp input IN expression.\n     * @param context Output native expression.\n     * @param filterExpressionConverter {@link FilterExpressionConverter} used to compose\n     * the OR and EQ expanded expressions.\n     */\n    public static void expandIn(Expression exp, StringBuilder context, FilterExpressionConverter filterExpressionConverter) {\n        Assert.isTrue(exp.type() == ExpressionType.IN, \"Expected IN expressions but was: \" + exp.type());\n        expandInNinExpressions(ExpressionType.OR, ExpressionType.EQ, exp, context, filterExpressionConverter);\n    }\n\n    /**\n     * Expands the NIN (e.g. NOT IN) into a semantically equivalent boolean expressions of\n     * ANDs of NEs. Useful for providers that don\'t provide native NIN support.<br/>\n     *\n     * For example the\n     *\n     * <pre>\n     * foo NIN [\"bar1\", \"bar2\", \"bar3\"] (or foo NOT IN [\"bar1\", \"bar2\", \"bar3\"])\n     * </pre>\n     *\n     * express is equivalent to\n     *\n     * <pre>\n     * {@code foo != \"bar1\" && foo != \"bar2\" && foo != \"bar3\" (e.g. AND(foo NE \"bar1\" AND( foo NE \"bar2\" OR(foo NE \"bar3\"))) )}\n     * </pre>\n     * @param exp input NIN expression.\n     * @param context Output native expression.\n     * @param filterExpressionConverter {@link FilterExpressionConverter} used to compose\n     * the AND and NE expanded expressions.\n     */\n    public static void expandNin(Expression exp, StringBuilder context, FilterExpressionConverter filterExpressionConverter) {\n        Assert.isTrue(exp.type() == ExpressionType.NIN, \"Expected NIN expressions but was: \" + exp.type());\n        expandInNinExpressions(ExpressionType.AND, ExpressionType.NE, exp, context, filterExpressionConverter);\n    }\n\n    private static void expandInNinExpressions(Filter.ExpressionType outerExpressionType, Filter.ExpressionType innerExpressionType, Expression exp, StringBuilder context, FilterExpressionConverter expressionConverter) {\n        if (exp.right() instanceof Filter.Value value) {\n            if (value.value() instanceof List list) {\n                // 1. foo IN [\"bar1\", \"bar2\", \"bar3\"] is equivalent to foo == \"bar1\" ||\n                // foo == \"bar2\" || foo == \"bar3\"\n                // or equivalent to OR(foo == \"bar1\" OR( foo == \"bar2\" OR(foo == \"bar3\")))\n                // 2. foo IN [\"bar1\", \"bar2\", \"bar3\"] is equivalent to foo != \"bar1\" &&\n                // foo != \"bar2\" && foo != \"bar3\"\n                // or equivalent to AND(foo != \"bar1\" AND( foo != \"bar2\" OR(foo !=\n                // \"bar3\")))\n                List<Filter.Expression> eqExprs = new ArrayList<>();\n                for (Object o : list) {\n                    eqExprs.add(new Filter.Expression(innerExpressionType, exp.left(), new Filter.Value(o)));\n                }\n                context.append(expressionConverter.convertExpression(aggregate(outerExpressionType, eqExprs)));\n            } else {\n                // 1. foo IN [\"bar\"] is equivalent to foo == \"BAR\"\n                // 2. foo NIN [\"bar\"] is equivalent to foo != \"BAR\"\n                context.append(expressionConverter.convertExpression(new Filter.Expression(innerExpressionType, exp.left(), exp.right())));\n            }\n        } else {\n            throw new IllegalStateException(\"Filter IN right expression should be of Filter.Value type but was \" + exp.right().getClass());\n        }\n    }\n\n    /**\n     * Recursively aggregates a list of expression into a binary tree with \'aggregateType\'\n     * join nodes.\n     * @param aggregateType type all tree splits.\n     * @param expressions list of expressions to aggregate.\n     * @return Returns a binary tree expression.\n     */\n    private static Filter.Expression aggregate(Filter.ExpressionType aggregateType, List<Filter.Expression> expressions) {\n        if (expressions.size() == 1) {\n            return expressions.get(0);\n        }\n        return new Filter.Expression(aggregateType, expressions.get(0), aggregate(aggregateType, expressions.subList(1, expressions.size())));\n    }\n}',0x01,'cu::FilterHelper.java'),
('7436bbba-703d-4e78-bcd9-1599513edc20','Perplexity supports several models optimized for search-enhanced conversational AI. Refer to <a href=\"https://docs.perplexity.ai/guides/model-cards\">Supported Models</a> for details.',0x00,'asciidoc::perplexity-chat.adoc::Supported Models::0'),
('1f52977a-e861-46cb-ad9a-15d2fb2e7898','<div class=\"paragraph\">\n<p>This section walks you through setting up <code>TypesenseVectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://typesense.org\">Typesense</a> is an open source typo tolerant search engine that is optimized for instant sub-50ms searches while providing an intuitive developer experience. It provides vector search capabilities that allow you to store and query high-dimensional vectors alongside your regular search data.</p>\n</div>',0x00,'asciidoc::typesense.adoc::0'),
('6aaafad5-86aa-4532-b80c-161078bfa800','The main approach for passing tools to a model is by providing the <code>ToolCallback</code>(s) when invoking the <code>ChatClient</code> or the <code>ChatModel</code>,\nusing one of the strategies described in <a href=\"#_methods_as_tools\">Methods as Tools</a> and <a href=\"#_functions_as_tools\">Functions as Tools</a>.\n\nHowever, Spring AI also supports resolving tools dynamically at runtime using the <code>ToolCallbackResolver</code> interface.\n\npublic interface ToolCallbackResolver {\n\n	/**\n	 * Resolve the {@link ToolCallback} for the given tool name.\n	 */\n	@Nullable\n	ToolCallback resolve(String toolName);\n\n}\n\nWhen using this approach:\n\nOn the client-side, you provide the tool names to the <code>ChatClient</code> or the <code>ChatModel</code> instead of the <code>ToolCallback</code>(s).\nOn the server-side, a <code>ToolCallbackResolver</code> implementation is responsible for resolving the tool names to the corresponding <code>ToolCallback</code> instances.\n\n\nBy default, Spring AI relies on a <code>DelegatingToolCallbackResolver</code> that delegates the tool resolution to a list of <code>ToolCallbackResolver</code> instances:\n\nThe <code>SpringBeanToolCallbackResolver</code> resolves tools from Spring beans of type <code>Function</code>, <code>Supplier</code>, <code>Consumer</code>, or <code>BiFunction</code>. See <a href=\"#_dynamic_specification_bean\">Dynamic Specification: <code>@Bean</code></a> for more details.\nThe <code>StaticToolCallbackResolver</code> resolves tools from a static list of <code>ToolCallback</code> instances. When using the Spring Boot Autoconfiguration, this resolver is automatically configured with all the beans of type <code>ToolCallback</code> defined in the application context.\n\n\nIf you rely on the Spring Boot Autoconfiguration, you can customize the resolution logic by providing a custom <code>ToolCallbackResolver</code> bean.\n\n@Bean\nToolCallbackResolver toolCallbackResolver(List&lt;FunctionCallback&gt; toolCallbacks) {\n    StaticToolCallbackResolver staticToolCallbackResolver = new StaticToolCallbackResolver(toolCallbacks);\n    return new DelegatingToolCallbackResolver(List.of(staticToolCallbackResolver));\n}\n\nThe <code>ToolCallbackResolver</code> is used internally by the <code>ToolCallingManager</code> to resolve tools dynamically at runtime, supporting both <a href=\"#_framework_controlled_tool_execution\">Framework-Controlled Tool Execution</a> and <a href=\"#_user_controlled_tool_execution\">User-Controlled Tool Execution</a>.',0x00,'asciidoc::tools.adoc::Tool Resolution::0'),
('d0217c92-1bd3-436f-91e5-169d3d922e46','The configuration section outlines how to set up and tune your Large Language Model (LLM) with Spring AI.\nIt covers selecting the right LLM provider for your use case and configuring important generation parameters that control the quality, style, and format of model outputs.',0x00,'asciidoc::prompt-engineering-patterns.adoc::1. Configuration::0'),
('36466b00-349c-4225-a6f8-1752156dc837','Spring AI provides a read-only interface called <code>VectorStoreRetriever</code> that exposes only the document retrieval functionality:\n\n@FunctionalInterface\npublic interface VectorStoreRetriever {\n\n    List&lt;Document&gt; similaritySearch(SearchRequest request);\n\n    default List&lt;Document&gt; similaritySearch(String query) {\n        return this.similaritySearch(SearchRequest.builder().query(query).build());\n    }\n}\n\nThis functional interface is designed for use cases where you only need to retrieve documents from a vector store without performing any mutation operations. It follows the principle of least privilege by exposing only the necessary functionality for document retrieval.',0x00,'asciidoc::vectordbs.adoc::API Overview::VectorStoreRetriever Interface::0'),
('b218dafa-c8c3-4569-b30c-17cbf07421d3','You can leverage the generic, portable <a href=\"https://docs.spring.io/spring-ai/reference/api/vectordbs.html#_metadata_filters\">metadata filters</a> with the <code>OracleVectorStore</code>.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"author\",\"john\", \"jill\"),\n        b.eq(\"article_type\", \"blog\")).build()).build());\n\nThese filter expressions are converted into the equivalent <code>OracleVectorStore</code> filters.',0x00,'asciidoc::oracle.adoc::Metadata filtering::0'),
('8573d5ae-31c0-444d-9580-1806f031ec26','You can configure extra parameters using Spring Boot properties.\nEach property under <code>spring.ai.openai.chat.options.extra-body</code> becomes a top-level parameter in the request:\n\nspring.ai.openai.base-url=http://localhost:8000/v1\nspring.ai.openai.chat.options.model=meta-llama/Llama-3-8B-Instruct\nspring.ai.openai.chat.options.temperature=0.7\nspring.ai.openai.chat.options.extra-body.top_k=50\nspring.ai.openai.chat.options.extra-body.repetition_penalty=1.1\n\nThis configuration would produce a JSON request like:\n\n{\n  \"model\": \"meta-llama/Llama-3-8B-Instruct\",\n  \"temperature\": 0.7,\n  \"top_k\": 50,\n  \"repetition_penalty\": 1.1,\n  \"messages\": [...]\n}',0x00,'asciidoc::openai-chat.adoc::Using Extra Parameters with OpenAI-Compatible Servers::Configuration with Properties::0'),
('ccb17a77-3e33-4a3d-992c-18b18070156f','Use the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/postgresml/PostgresMlEmbeddingOptions.java\">PostgresMlEmbeddingOptions.java</a> to configure the <code>PostgresMlEmbeddingModel</code> with options, such as the model to use and etc.\n\nOn start you can pass a <code>PostgresMlEmbeddingOptions</code> to the <code>PostgresMlEmbeddingModel</code> constructor to configure the default options used for all embedding requests.\n\nAt run-time you can override the default options, using a <code>PostgresMlEmbeddingOptions</code> in your <code>EmbeddingRequest</code>.\n\nFor example to override the default model name for a specific request:\n\nEmbeddingResponse embeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n            PostgresMlEmbeddingOptions.builder()\n                .transformer(\"intfloat/e5-small\")\n                .vectorType(VectorType.PG_ARRAY)\n                .kwargs(Map.of(\"device\", \"gpu\"))\n                .build()));',0x00,'asciidoc::postgresml-embeddings.adoc::Runtime Options::0'),
('3388d979-3ba4-4342-961e-18f72bc24d17','The <code>KeywordMetadataEnricher</code> requires a functioning <code>ChatModel</code> to generate keywords.\nThe keyword count must be 1 or greater.\nThe enricher adds the \"excerpt_keywords\" metadata field to each processed document.\nThe generated keywords are returned as a comma-separated string.\nThis enricher is particularly useful for improving document searchability and for generating tags or categories for documents.\nIn the Builder pattern, if the <code>keywordsTemplate</code> parameter is set, the <code>keywordCount</code> parameter will be ignored.',0x00,'asciidoc::etl-pipeline.adoc::Transformers::KeywordMetadataEnricher::1'),
('3b5863d2-0df1-4aab-8d64-1919bfa0cc5d','/**\n * Builder for {@link VectorStoreDocumentRetriever}.\n */\npublic static final class Builder {\n\n    private VectorStore vectorStore;\n\n    private Double similarityThreshold;\n\n    private Integer topK;\n\n    private Supplier<Filter.Expression> filterExpression;\n\n    private Builder() {\n    }\n\n    public Builder vectorStore(VectorStore vectorStore) {\n        this.vectorStore = vectorStore;\n        return this;\n    }\n\n    public Builder similarityThreshold(Double similarityThreshold) {\n        this.similarityThreshold = similarityThreshold;\n        return this;\n    }\n\n    public Builder topK(Integer topK) {\n        this.topK = topK;\n        return this;\n    }\n\n    public Builder filterExpression(Filter.Expression filterExpression) {\n        this.filterExpression = () -> filterExpression;\n        return this;\n    }\n\n    public Builder filterExpression(Supplier<Filter.Expression> filterExpression) {\n        this.filterExpression = filterExpression;\n        return this;\n    }\n\n    public VectorStoreDocumentRetriever build() {\n        return new VectorStoreDocumentRetriever(this.vectorStore, this.similarityThreshold, this.topK, this.filterExpression);\n    }\n}',0x01,'cu::VectorStoreDocumentRetriever.java'),
('13e21535-f299-4d1a-a687-191b8528e284','The prefix <code>spring.ai.ollama</code> is the property prefix to configure the connection to Ollama.\n\n\n\nHere are the properties for initializing the Ollama integration and <a href=\"#auto-pulling-models\">auto-pulling models</a>.',0x00,'asciidoc::ollama-chat.adoc::Auto-configuration::Base Properties::0'),
('4a3f4021-4529-4f80-a071-1945d0db8d7b','Spring AI Ollama can automatically pull models when they are not available in your Ollama instance.\nThis feature is particularly useful for development and testing as well as for deploying your applications to new environments.\n\nYou can also pull, by name, any of the thousands, free, <a href=\"https://huggingface.co/models?library=gguf&amp;sort=trending\">GGUF Hugging Face Models</a>.\n\nThere are three strategies for pulling models:\n\n<code>always</code> (defined in <code>PullModelStrategy.ALWAYS</code>): Always pull the model, even if it&#8217;s already available. Useful to ensure you&#8217;re using the latest version of the model.\n<code>when_missing</code> (defined in <code>PullModelStrategy.WHEN_MISSING</code>): Only pull the model if it&#8217;s not already available. This may result in using an older version of the model.\n<code>never</code> (defined in <code>PullModelStrategy.NEVER</code>): Never pull the model automatically.\n\n\nDue to potential delays while downloading models, automatic pulling is not recommended for production environments. Instead, consider assessing and pre-downloading the necessary models in advance.\n\nAll models defined via configuration properties and default options can be automatically pulled at startup time.\nYou can configure the pull strategy, timeout, and maximum number of retries using configuration properties:\n\nspring:\n  ai:\n    ollama:\n      init:\n        pull-model-strategy: always\n        timeout: 60s\n        max-retries: 1\n\nThe application will not complete its initialization until all specified models are available in Ollama. Depending on the model size and internet connection speed, this may significantly slow down your application&#8217;s startup time.\n\nYou can initialize additional models at startup, which is useful for models used dynamically at runtime:\n\nspring:\n  ai:\n    ollama:\n      init:\n        pull-model-strategy: always\n        embedding:\n          additional-models:\n            - mxbai-embed-large\n            - nomic-embed-text\n\nIf you want to apply the pulling strategy only to specific types of models, you can exclude embedding models from the initialization task:\n\nspring:\n  ai:\n    ollama:\n      init:\n        pull-model-strategy: always\n        embedding:\n          include: false\n\nThis configuration will apply the pulling strategy to all models except embedding models.',0x00,'asciidoc::ollama-embeddings.adoc::Auto-pulling Models::0'),
('d9c7dddd-c453-49fd-ba62-19525647169e','You can also configure default metadata at the ChatClient builder level:\n\n@Configuration\nclass Config {\n    @Bean\n    ChatClient chatClient(ChatClient.Builder builder) {\n        return builder\n            .defaultSystem(s -&gt; s.text(\"You are a helpful assistant\")\n                .metadata(\"assistantType\", \"general\")\n                .metadata(\"version\", \"1.0\"))\n            .defaultUser(u -&gt; u.text(\"Default user context\")\n                .metadata(\"sessionId\", \"default-session\"))\n            .build();\n    }\n}',0x00,'asciidoc::chatclient.adoc::Message Metadata::Default Metadata Support::0'),
('612d75a2-6a83-4348-a8b6-199342ead270','/**\n * @author Christian Tzolov\n */\npublic class PineconeFilterExpressionConverterTests {\n\n    FilterExpressionConverter converter = new PineconeFilterExpressionConverter();\n\n    @Test\n    public void testEQ() {\n        // country == \"BG\"\n        String vectorExpr = this.converter.convertExpression(new Expression(EQ, new Key(\"country\"), new Value(\"BG\")));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"country\\\": {\\\"$eq\\\": \\\"BG\\\"}}\");\n    }\n\n    @Test\n    public void tesEqAndGte() {\n        // genre == \"drama\" AND year >= 2020\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(EQ, new Key(\"genre\"), new Value(\"drama\")), new Expression(GTE, new Key(\"year\"), new Value(2020))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"genre\\\": {\\\"$eq\\\": \\\"drama\\\"}},{\\\"year\\\": {\\\"$gte\\\": 2020}}]}\");\n    }\n\n    @Test\n    public void tesIn() {\n        // genre in [\"comedy\", \"documentary\", \"drama\"]\n        String vectorExpr = this.converter.convertExpression(new Expression(IN, new Key(\"genre\"), new Value(List.of(\"comedy\", \"documentary\", \"drama\"))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"genre\\\": {\\\"$in\\\": [\\\"comedy\\\",\\\"documentary\\\",\\\"drama\\\"]}}\");\n    }\n\n    @Test\n    public void testNe() {\n        // year >= 2020 OR country == \"BG\" AND city != \"Sofia\"\n        String vectorExpr = this.converter.convertExpression(new Expression(OR, new Expression(GTE, new Key(\"year\"), new Value(2020)), new Expression(AND, new Expression(EQ, new Key(\"country\"), new Value(\"BG\")), new Expression(NE, new Key(\"city\"), new Value(\"Sofia\")))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$or\\\": [{\\\"year\\\": {\\\"$gte\\\": 2020}},{\\\"$and\\\": [{\\\"country\\\": {\\\"$eq\\\": \\\"BG\\\"}},{\\\"city\\\": {\\\"$ne\\\": \\\"Sofia\\\"}}]}]}\");\n    }\n\n    @Test\n    public void testGroup() {\n        // (year >= 2020 OR country == \"BG\") AND city NIN [\"Sofia\", \"Plovdiv\"]\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Group(new Expression(OR, new Expression(GTE, new Key(\"year\"), new Value(2020)), new Expression(EQ, new Key(\"country\"), new Value(\"BG\")))), new Expression(NIN, new Key(\"city\"), new Value(List.of(\"Sofia\", \"Plovdiv\")))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"$or\\\": [{\\\"year\\\": {\\\"$gte\\\": 2020}},{\\\"country\\\": {\\\"$eq\\\": \\\"BG\\\"}}]},{\\\"city\\\": {\\\"$nin\\\": [\\\"Sofia\\\",\\\"Plovdiv\\\"]}}]}\");\n    }\n\n    @Test\n    public void tesBoolean() {\n        // isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(AND, new Expression(EQ, new Key(\"isOpen\"), new Value(true)), new Expression(GTE, new Key(\"year\"), new Value(2020))), new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"$and\\\": [{\\\"isOpen\\\": {\\\"$eq\\\": true}},{\\\"year\\\": {\\\"$gte\\\": 2020}}]},{\\\"country\\\": {\\\"$in\\\": [\\\"BG\\\",\\\"NL\\\",\\\"US\\\"]}}]}\");\n    }\n\n    @Test\n    public void testDecimal() {\n        // temperature >= -15.6 && temperature <= +20.13\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(GTE, new Key(\"temperature\"), new Value(-15.6)), new Expression(LTE, new Key(\"temperature\"), new Value(20.13))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"temperature\\\": {\\\"$gte\\\": -15.6}},{\\\"temperature\\\": {\\\"$lte\\\": 20.13}}]}\");\n    }\n\n    @Test\n    public void testComplexIdentifiers() {\n        String vectorExpr = this.converter.convertExpression(new Expression(EQ, new Key(\"\\\"country 1 2 3\\\"\"), new Value(\"BG\")));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"country 1 2 3\\\": {\\\"$eq\\\": \\\"BG\\\"}}\");\n        vectorExpr = this.converter.convertExpression(new Expression(EQ, new Key(\"\'country 1 2 3\'\"), new Value(\"BG\")));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"country 1 2 3\\\": {\\\"$eq\\\": \\\"BG\\\"}}\");\n    }\n\n    @Test\n    public void testNumericValues() {\n        // score > 85\n        String vectorExpr = this.converter.convertExpression(new Expression(GT, new Key(\"score\"), new Value(85)));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"score\\\": {\\\"$gt\\\": 85}}\");\n    }\n\n    @Test\n    public void testLessThan() {\n        // priority < 10\n        String vectorExpr = this.converter.convertExpression(new Expression(LT, new Key(\"priority\"), new Value(10)));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"priority\\\": {\\\"$lt\\\": 10}}\");\n    }\n\n    @Test\n    public void testNotInWithNumbers() {\n        // status NIN [100, 200, 404]\n        String vectorExpr = this.converter.convertExpression(new Expression(NIN, new Key(\"status\"), new Value(List.of(100, 200, 404))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"status\\\": {\\\"$nin\\\": [100,200,404]}}\");\n    }\n\n    @Test\n    public void testComplexAndOrCombination() {\n        // (category == \"A\" OR category == \"B\") AND (value >= 50 AND value <= 100)\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Group(new Expression(OR, new Expression(EQ, new Key(\"category\"), new Value(\"A\")), new Expression(EQ, new Key(\"category\"), new Value(\"B\")))), new Group(new Expression(AND, new Expression(GTE, new Key(\"value\"), new Value(50)), new Expression(LTE, new Key(\"value\"), new Value(100))))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"$or\\\": [{\\\"category\\\": {\\\"$eq\\\": \\\"A\\\"}},{\\\"category\\\": {\\\"$eq\\\": \\\"B\\\"}}]},{\\\"$and\\\": [{\\\"value\\\": {\\\"$gte\\\": 50}},{\\\"value\\\": {\\\"$lte\\\": 100}}]}]}\");\n    }\n\n    @Test\n    public void testNestedGroups() {\n        // ((type == \"premium\" AND level > 5) OR (type == \"basic\" AND level > 10)) AND\n        // active == true\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Group(new Expression(OR, new Group(new Expression(AND, new Expression(EQ, new Key(\"type\"), new Value(\"premium\")), new Expression(GT, new Key(\"level\"), new Value(5)))), new Group(new Expression(AND, new Expression(EQ, new Key(\"type\"), new Value(\"basic\")), new Expression(GT, new Key(\"level\"), new Value(10)))))), new Expression(EQ, new Key(\"active\"), new Value(true))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"$or\\\": [{\\\"$and\\\": [{\\\"type\\\": {\\\"$eq\\\": \\\"premium\\\"}},{\\\"level\\\": {\\\"$gt\\\": 5}}]},{\\\"$and\\\": [{\\\"type\\\": {\\\"$eq\\\": \\\"basic\\\"}},{\\\"level\\\": {\\\"$gt\\\": 10}}]}]},{\\\"active\\\": {\\\"$eq\\\": true}}]}\");\n    }\n\n    @Test\n    public void testMixedDataTypes() {\n        // name == \"test\" AND count >= 5 AND enabled == true AND ratio <= 0.95\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(AND, new Expression(AND, new Expression(EQ, new Key(\"name\"), new Value(\"test\")), new Expression(GTE, new Key(\"count\"), new Value(5))), new Expression(EQ, new Key(\"enabled\"), new Value(true))), new Expression(LTE, new Key(\"ratio\"), new Value(0.95))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"$and\\\": [{\\\"$and\\\": [{\\\"name\\\": {\\\"$eq\\\": \\\"test\\\"}},{\\\"count\\\": {\\\"$gte\\\": 5}}]},{\\\"enabled\\\": {\\\"$eq\\\": true}}]},{\\\"ratio\\\": {\\\"$lte\\\": 0.95}}]}\");\n    }\n\n    @Test\n    public void testInWithMixedTypes() {\n        // tag IN [\"A\", \"B\", \"C\"]\n        String vectorExpr = this.converter.convertExpression(new Expression(IN, new Key(\"tag\"), new Value(List.of(\"A\", \"B\", \"C\"))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"tag\\\": {\\\"$in\\\": [\\\"A\\\",\\\"B\\\",\\\"C\\\"]}}\");\n    }\n\n    @Test\n    public void testNegativeNumbers() {\n        // balance >= -100.0 AND balance <= -10.0\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(GTE, new Key(\"balance\"), new Value(-100.0)), new Expression(LTE, new Key(\"balance\"), new Value(-10.0))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"balance\\\": {\\\"$gte\\\": -100.0}},{\\\"balance\\\": {\\\"$lte\\\": -10.0}}]}\");\n    }\n\n    @Test\n    public void testSpecialCharactersInValues() {\n        // description == \"Item with spaces & symbols!\"\n        String vectorExpr = this.converter.convertExpression(new Expression(EQ, new Key(\"description\"), new Value(\"Item with spaces & symbols!\")));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"description\\\": {\\\"$eq\\\": \\\"Item with spaces & symbols!\\\"}}\");\n    }\n\n    @Test\n    public void testMultipleOrConditions() {\n        // status == \"pending\" OR status == \"processing\" OR status == \"completed\"\n        String vectorExpr = this.converter.convertExpression(new Expression(OR, new Expression(OR, new Expression(EQ, new Key(\"status\"), new Value(\"pending\")), new Expression(EQ, new Key(\"status\"), new Value(\"processing\"))), new Expression(EQ, new Key(\"status\"), new Value(\"completed\"))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$or\\\": [{\\\"$or\\\": [{\\\"status\\\": {\\\"$eq\\\": \\\"pending\\\"}},{\\\"status\\\": {\\\"$eq\\\": \\\"processing\\\"}}]},{\\\"status\\\": {\\\"$eq\\\": \\\"completed\\\"}}]}\");\n    }\n\n    @Test\n    public void testSingleElementList() {\n        // category IN [\"single\"]\n        String vectorExpr = this.converter.convertExpression(new Expression(IN, new Key(\"category\"), new Value(List.of(\"single\"))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"category\\\": {\\\"$in\\\": [\\\"single\\\"]}}\");\n    }\n\n    @Test\n    public void testZeroValues() {\n        // quantity == 0 AND price > 0\n        String vectorExpr = this.converter.convertExpression(new Expression(AND, new Expression(EQ, new Key(\"quantity\"), new Value(0)), new Expression(GT, new Key(\"price\"), new Value(0))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$and\\\": [{\\\"quantity\\\": {\\\"$eq\\\": 0}},{\\\"price\\\": {\\\"$gt\\\": 0}}]}\");\n    }\n\n    @Test\n    public void testComplexNestedExpression() {\n        // (priority >= 1 AND priority <= 5) OR (urgent == true AND category NIN [\"low\",\n        // \"medium\"])\n        String vectorExpr = this.converter.convertExpression(new Expression(OR, new Group(new Expression(AND, new Expression(GTE, new Key(\"priority\"), new Value(1)), new Expression(LTE, new Key(\"priority\"), new Value(5)))), new Group(new Expression(AND, new Expression(EQ, new Key(\"urgent\"), new Value(true)), new Expression(NIN, new Key(\"category\"), new Value(List.of(\"low\", \"medium\")))))));\n        assertThat(vectorExpr).isEqualTo(\"{\\\"$or\\\": [{\\\"$and\\\": [{\\\"priority\\\": {\\\"$gte\\\": 1}},{\\\"priority\\\": {\\\"$lte\\\": 5}}]},{\\\"$and\\\": [{\\\"urgent\\\": {\\\"$eq\\\": true}},{\\\"category\\\": {\\\"$nin\\\": [\\\"low\\\",\\\"medium\\\"]}}]}]}\");\n    }\n}',0x01,'cu::PineconeFilterExpressionConverterTests.java'),
('5b9003ca-acd2-40fd-9aa5-19b24eb8712f','<div class=\"quoteblock\">\n<blockquote>\n<div class=\"paragraph\">\n<p>\"All things that are naturally connected ought to be taught in combination\" - John Amos Comenius, \"Orbis Sensualium Pictus\", 1658</p>\n</div>\n</blockquote>\n</div>\n<div class=\"paragraph\">\n<p>Humans  process knowledge, simultaneously across multiple modes of data inputs.\nThe way we learn, our experiences are all multimodal.\nWe don&#8217;t have just vision, just audio and just text.</p>\n</div>\n<div class=\"paragraph\">\n<p>Contrary to those principles, the Machine Learning was often focused on specialized models tailored to process a single modality.\nFor instance, we developed audio models for tasks like text-to-speech or speech-to-text, and computer vision models for tasks such as object detection and classification.</p>\n</div>\n<div class=\"paragraph\">\n<p>However, a new wave of multimodal large language models starts to emerge.\nExamples include OpenAI&#8217;s GPT-4o , Google&#8217;s Vertex AI Gemini 1.5, Anthropic&#8217;s Claude3, and open source offerings Llama3.2, LLaVA and BakLLaVA are able to accept multiple inputs, including text images, audio and video and generate text responses by integrating these inputs.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nThe multimodal large language model (LLM) features enable the models to process and generate text in conjunction with other modalities such as images, audio, or video.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::multimodality.adoc::0'),
('507d23f5-0fc8-4e02-b186-19b4078e43df','You can also specify extra parameters at runtime using the options builder:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Tell me a creative story\",\n        OpenAiChatOptions.builder()\n            .model(\"meta-llama/Llama-3-8B-Instruct\")\n            .temperature(0.7)\n            .extraBody(Map.of(\n                \"top_k\", 50,\n                \"repetition_penalty\", 1.1,\n                \"frequency_penalty\", 0.5\n            ))\n            .build()\n    ));',0x00,'asciidoc::openai-chat.adoc::Using Extra Parameters with OpenAI-Compatible Servers::Runtime Configuration with Builder::0'),
('5df8b30c-81b8-46ef-873d-19c9e3465977','/**\n * DSL builder for {@link Filter.Expression} instances. Here are some common examples:\n *\n * <pre>{@code\n * var b = new FilterExpressionBuilder();\n *\n * // 1: country == \"BG\"\n * var exp1 = b.eq(\"country\", \"BG\");\n *\n * // 2: genre == \"drama\" AND year >= 2020\n * var exp2 = b.and(b.eq(\"genre\", \"drama\"), b.gte(\"year\", 2020));\n *\n * // 3: genre in [\"comedy\", \"documentary\", \"drama\"]\n * var exp3 = b.in(\"genre\", \"comedy\", \"documentary\", \"drama\");\n *\n * // 4: year >= 2020 OR country == \"BG\" AND city != \"Sofia\"\n * var exp4 = b.and(b.or(b.gte(\"year\", 2020), b.eq(\"country\", \"BG\")), b.ne(\"city\", \"Sofia\"));\n *\n * // 5: (year >= 2020 OR country == \"BG\") AND city NIN [\"Sofia\", \"Plovdiv\"]\n * var exp5 = b.and(b.group(b.or(b.gte(\"year\", 2020), b.eq(\"country\", \"BG\"))), b.nin(\"city\", \"Sofia\", \"Plovdiv\"));\n *\n * // 6: isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]\n * var exp6 = b.and(b.and(b.eq(\"isOpen\", true), b.gte(\"year\", 2020)), b.in(\"country\", \"BG\", \"NL\", \"US\"));\n *\n * }</pre>\n *\n * This builder DSL mimics the common\n * <a href=\"https://www.baeldung.com/hibernate-criteria-queries\">Criteria Queries</a>\n * syntax.\n *\n * @author Christian Tzolov\n */\npublic class FilterExpressionBuilder {\n\n    public Op eq(String key, Object value) {\n        return new Op(new Filter.Expression(ExpressionType.EQ, new Key(key), new Value(value)));\n    }\n\n    public Op ne(String key, Object value) {\n        return new Op(new Filter.Expression(ExpressionType.NE, new Key(key), new Value(value)));\n    }\n\n    public Op gt(String key, Object value) {\n        return new Op(new Filter.Expression(ExpressionType.GT, new Key(key), new Value(value)));\n    }\n\n    public Op gte(String key, Object value) {\n        return new Op(new Filter.Expression(ExpressionType.GTE, new Key(key), new Value(value)));\n    }\n\n    public Op lt(String key, Object value) {\n        return new Op(new Filter.Expression(ExpressionType.LT, new Key(key), new Value(value)));\n    }\n\n    public Op lte(String key, Object value) {\n        return new Op(new Filter.Expression(ExpressionType.LTE, new Key(key), new Value(value)));\n    }\n\n    public Op and(Op left, Op right) {\n        return new Op(new Filter.Expression(ExpressionType.AND, left.expression, right.expression));\n    }\n\n    public Op or(Op left, Op right) {\n        return new Op(new Filter.Expression(ExpressionType.OR, left.expression, right.expression));\n    }\n\n    public Op in(String key, Object... values) {\n        return this.in(key, List.of(values));\n    }\n\n    public Op in(String key, List<Object> values) {\n        return new Op(new Filter.Expression(ExpressionType.IN, new Key(key), new Value(values)));\n    }\n\n    public Op nin(String key, Object... values) {\n        return this.nin(key, List.of(values));\n    }\n\n    public Op nin(String key, List<Object> values) {\n        return new Op(new Filter.Expression(ExpressionType.NIN, new Key(key), new Value(values)));\n    }\n\n    public Op group(Op content) {\n        return new Op(new Filter.Group(content.build()));\n    }\n\n    public Op not(Op content) {\n        return new Op(new Filter.Expression(ExpressionType.NOT, content.expression, null));\n    }\n\n    public record Op(Filter.Operand expression) {\n\n        public Filter.Expression build() {\n            if (this.expression instanceof Filter.Group group) {\n                // Remove the top-level grouping.\n                return group.content();\n            } else if (this.expression instanceof Filter.Expression exp) {\n                return exp;\n            }\n            throw new RuntimeException(\"Invalid expression: \" + this.expression);\n        }\n    }\n}',0x01,'cu::FilterExpressionBuilder.java'),
('9c487b0e-cc26-4b34-9bf4-1ac8b791c02e','The following code demonstrates how to set up the <code>CosmosDBVectorStore</code> with auto-configuration:\n\npackage com.example.demo;\n\nimport io.micrometer.observation.ObservationRegistry;\nimport org.slf4j.Logger;\nimport org.slf4j.LoggerFactory;\nimport org.springframework.ai.document.Document;\nimport org.springframework.ai.vectorstore.SearchRequest;\nimport org.springframework.ai.vectorstore.VectorStore;\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.boot.autoconfigure.EnableAutoConfiguration;\nimport org.springframework.boot.CommandLineRunner;\nimport org.springframework.boot.SpringApplication;\nimport org.springframework.boot.autoconfigure.SpringBootApplication;\nimport org.springframework.context.annotation.Bean;\nimport org.springframework.context.annotation.Lazy;\n\nimport java.util.List;\nimport java.util.Map;\nimport java.util.UUID;\n\nimport static org.assertj.core.api.Assertions.assertThat;\n\n@SpringBootApplication\n@EnableAutoConfiguration\npublic class DemoApplication implements CommandLineRunner {\n\n    private static final Logger log = LoggerFactory.getLogger(DemoApplication.class);\n\n    @Lazy\n    @Autowired\n    private VectorStore vectorStore;\n\n    public static void main(String[] args) {\n        SpringApplication.run(DemoApplication.class, args);\n    }\n\n    @Override\n    public void run(String... args) throws Exception {\n        Document document1 = new Document(UUID.randomUUID().toString(), \"Sample content1\", Map.of(\"key1\", \"value1\"));\n        Document document2 = new Document(UUID.randomUUID().toString(), \"Sample content2\", Map.of(\"key2\", \"value2\"));\n		this.vectorStore.add(List.of(document1, document2));\n        List&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Sample content\").topK(1).build());\n\n        log.info(\"Search results: {}\", results);\n\n        // Remove the documents from the vector store\n		this.vectorStore.delete(List.of(document1.getId(), document2.getId()));\n    }\n\n    @Bean\n    public ObservationRegistry observationRegistry() {\n        return ObservationRegistry.create();\n    }\n}',0x00,'asciidoc::azure-cosmos-db.adoc::Setting up Azure Cosmos DB Vector Store with Auto Configuration::0'),
('156592a9-da14-4093-92f4-1afc181946ba','Spring AI uses Micrometer. Base metric names use dots (e.g., <code>gen_ai.client.operation</code>), which Prometheus exports with underscores and standard suffixes:\n\n<strong>Timers</strong> → <code>&lt;base&gt;_seconds_count</code>, <code>&lt;base&gt;_seconds_sum</code>, <code>&lt;base&gt;_seconds_max</code>, and (when supported) <code>&lt;base&gt;_active_count</code>\n<strong>Counters</strong> → <code>&lt;base&gt;_total</code> (monotonic)\n\n\n<div class=\"paragraph\">\n<p>The following shows how base metric names expand to Prometheus time series.</p>\n</div>\n<table class=\"tableblock frame-all grid-all stripes-even stretch\">\n<colgroup>\n<col style=\"width: 40%;\">\n<col style=\"width: 60%;\">\n</colgroup>\n<thead>\n<tr>\n<th class=\"tableblock halign-left valign-top\">Base metric name</th>\n<th class=\"tableblock halign-left valign-top\">Exported time series</th>\n</tr>\n</thead>\n<tbody>\n<tr>\n<td class=\"tableblock halign-left valign-top\"><p class=\"tableblock\"><code>gen_ai.client.operation</code></p></td>\n<td class=\"tableblock halign-left valign-top\"><p class=\"tableblock\"><code>gen_ai_client_operation_seconds_count</code><br>\n<code>gen_ai_client_operation_seconds_sum</code><br>\n<code>gen_ai_client_operation_seconds_max</code><br>\n<code>gen_ai_client_operation_active_count</code></p></td>\n</tr>\n<tr>\n<td class=\"tableblock halign-left valign-top\"><p class=\"tableblock\"><code>db.vector.client.operation</code></p></td>\n<td class=\"tableblock halign-left valign-top\"><p class=\"tableblock\"><code>db_vector_client_operation_seconds_count</code><br>\n<code>db_vector_client_operation_seconds_sum</code><br>\n<code>db_vector_client_operation_seconds_max</code><br>\n<code>db_vector_client_operation_active_count</code></p></td>\n</tr>\n</tbody>\n</table>\n\nReferences\n\nOpenTelemetry — <a href=\"https://opentelemetry.io/docs/specs/semconv/gen-ai/\">Semantic Conventions for Generative AI (overview)</a>\nMicrometer — <a href=\"https://docs.micrometer.io/micrometer/reference/concepts/naming.html\">Naming Meters</a>',0x00,'asciidoc::index.adoc::More Metrics Reference::Metric Naming Conventions::0'),
('1972911f-9779-4f20-81c1-1b2943944269','To get started with Spring AI and MongoDB:\n\nSee the <a href=\"https://www.mongodb.com/docs/atlas/atlas-vector-search/ai-integrations/spring-ai/#std-label-spring-ai\">Getting Started guide for Spring AI Integration</a>.\nFor a comprehensive code example demonstrating Retrieval Augmented Generation (RAG) with Spring AI and MongoDB, refer to this <a href=\"https://www.mongodb.com/developer/languages/java/retrieval-augmented-generation-spring-ai/\">detailed tutorial</a>.',0x00,'asciidoc::mongodb.adoc::Tutorials and Code Examples::0'),
('bdcc1f83-c681-416a-8fb1-1b8486805954','<div class=\"paragraph\">\n<p>Spring AI supports the various AI language models from MiniMax. You can interact with MiniMax language models and create a multilingual conversational assistant based on MiniMax models.</p>\n</div>',0x00,'asciidoc::minimax-embeddings.adoc::0'),
('a1d7976b-90a5-4edf-81c1-1c4933c50630','public static final class SimpleVectorStoreBuilder extends AbstractVectorStoreBuilder<SimpleVectorStoreBuilder> {\n\n    private SimpleVectorStoreBuilder(EmbeddingModel embeddingModel) {\n        super(embeddingModel);\n    }\n\n    @Override\n    public SimpleVectorStore build() {\n        return new SimpleVectorStore(this);\n    }\n}',0x01,'cu::SimpleVectorStore.java'),
('ab85dd94-17eb-49e0-a50c-1c4be8bc1f26','The Neo4j Vector Store implementation provides access to the underlying native Neo4j client (<code>Driver</code>) through the <code>getNativeClient()</code> method:\n\nNeo4jVectorStore vectorStore = context.getBean(Neo4jVectorStore.class);\nOptional&lt;Driver&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    Driver driver = nativeClient.get();\n    // Use the native client for Neo4j-specific operations\n}\n\nThe native client gives you access to Neo4j-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::neo4j.adoc::Accessing the Native Client::0'),
('2e76b72a-8193-4322-8177-1c975154c0b2','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::minimax-chat.adoc::Prerequisites::Add Repositories and BOM::0'),
('39419f9b-ac2b-4066-9fd0-1d2bbccbc812','In each round of the conversation, the model outputs the CoT (reasoning_content) and the final answer (content). In the next round of the conversation, the CoT from previous rounds is not concatenated into the context, as illustrated in the following diagram:\n\nPlease note that if the reasoning_content field is included in the sequence of input messages, the API will return a 400 error. Therefore, you should remove the reasoning_content field from the API response before making the API request, as demonstrated in the API example.\n\npublic String deepSeekReasonerMultiRoundExample() {\n    List&lt;Message&gt; messages = new ArrayList&lt;&gt;();\n    messages.add(new UserMessage(\"9.11 and 9.8, which is greater?\"));\n    DeepSeekChatOptions promptOptions = DeepSeekChatOptions.builder()\n            .model(DeepSeekApi.ChatModel.DEEPSEEK_REASONER.getValue())\n            .build();\n\n    Prompt prompt = new Prompt(messages, promptOptions);\n    ChatResponse response = chatModel.call(prompt);\n\n    DeepSeekAssistantMessage deepSeekAssistantMessage = (DeepSeekAssistantMessage) response.getResult().getOutput();\n    String reasoningContent = deepSeekAssistantMessage.getReasoningContent();\n    String text = deepSeekAssistantMessage.getText();\n\n    messages.add(AssistantMessage.builder().content(Objects.requireNonNull(text)).build());\n    messages.add(new UserMessage(\"How many Rs are there in the word \'strawberry\'?\"));\n    Prompt prompt2 = new Prompt(messages, promptOptions);\n    ChatResponse response2 = chatModel.call(prompt2);\n\n    DeepSeekAssistantMessage deepSeekAssistantMessage2 = (DeepSeekAssistantMessage) response2.getResult().getOutput();\n    String reasoningContent2 = deepSeekAssistantMessage2.getReasoningContent();\n    return deepSeekAssistantMessage2.getText();\n}',0x00,'asciidoc::deepseek-chat.adoc::Reasoning Model Multi-round Conversation::0'),
('0653befa-a494-42ac-b759-1dd42af7bf58','Self-consistency is particularly valuable for high-stakes decisions, complex reasoning tasks, and when you need more confident answers than a single response can provide. The trade-off is increased computational cost and latency due to multiple API calls.\n\n<strong>Reference:</strong> Wang, X., et al. (2022). \"Self-Consistency Improves Chain of Thought Reasoning in Language Models.\" arXiv:2203.11171. <a href=\"https://arxiv.org/abs/2203.11171\">https://arxiv.org/abs/2203.11171</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.6 Self-Consistency::1'),
('0bda8781-35c0-4f18-8a90-1dfe8f575232','Embeddings are numerical representations of text, images, or videos that capture relationships between inputs.\n\nEmbeddings work by converting text, image, and video into arrays of floating point numbers, called vectors.\nThese vectors are designed to capture the meaning of the text, images, and videos.\nThe length of the embedding array is called the vector&#8217;s dimensionality.\n\nBy calculating the numerical distance between the vector representations of two pieces of text, an application can determine the similarity between the objects used to generate the embedding vectors.\n\nAs a Java developer exploring AI, it&#8217;s not necessary to comprehend the intricate mathematical theories or the specific implementations behind these vector representations.\nA basic understanding of their role and function within AI systems suffices, particularly when you&#8217;re integrating AI functionalities into your applications.\n\nEmbeddings are particularly relevant in practical applications like the Retrieval Augmented Generation (RAG) pattern.\nThey enable the representation of data as points in a semantic space, which is akin to the 2-D space of Euclidean geometry, but in higher dimensions.\nThis means just like how points on a plane in Euclidean geometry can be close or far based on their coordinates, in a semantic space, the proximity of points reflects the similarity in meaning.\nSentences about similar topics are positioned closer in this multi-dimensional space, much like points lying close to each other on a graph.\nThis proximity aids in tasks like text classification, semantic search, and even product recommendations, as it allows the AI to discern and group related concepts based on their \"location\" in this expanded semantic landscape.\n\nYou can think of this semantic space as a vector.',0x00,'asciidoc::concepts.adoc::Embeddings::0'),
('c38a6ff9-3638-49f8-b4f8-1e21ba3d1270','To authenticate with the OpenAI service (not Azure), provide an OpenAI API key.\nThis will automatically set the endpoint to <a href=\"https://api.openai.com/v1\" class=\"bare\">https://api.openai.com/v1</a>.\n\nWhen using this approach, set the <code>spring.ai.azure.openai.chat.options.deployment-name</code> property to the name of the <a href=\"https://platform.openai.com/docs/models\">OpenAI model</a> you wish to use.\n\nIn your application configuration:\n\nspring.ai.azure.openai.openai-api-key=&lt;your-azure-openai-key&gt;\nspring.ai.azure.openai.chat.options.deployment-name=&lt;openai-model-name&gt;\n\nUsing environment variables with SpEL:\n\n# In application.yml\nspring:\n  ai:\n    azure:\n      openai:\n        openai-api-key: ${AZURE_OPENAI_API_KEY}\n        chat:\n          options:\n            deployment-name: ${OPENAI_MODEL_NAME}\n\n# In your environment or .env file\nexport AZURE_OPENAI_API_KEY=&lt;your-openai-key&gt;\nexport OPENAI_MODEL_NAME=&lt;openai-model-name&gt;',0x00,'asciidoc::azure-openai-embeddings.adoc::Prerequisites::OpenAI Key::0'),
('ffaff434-c70e-4e82-8865-1e29759fd7ee','Zero-shot prompting involves asking an AI to perform a task without providing any examples. This approach tests the model&#8217;s ability to understand and execute instructions from scratch. Large language models are trained on vast corpora of text, allowing them to understand what tasks like \"translation,\" \"summarization,\" or \"classification\" entail without explicit demonstrations.\n\nZero-shot is ideal for straightforward tasks where the model likely has seen similar examples during training, and when you want to minimize prompt length. However, performance may vary depending on task complexity and how well the instructions are formulated.\n\n// Implementation of Section 2.1: General prompting / zero shot (page 15)\npublic void pt_zero_shot(ChatClient chatClient) {\n    enum Sentiment {\n        POSITIVE, NEUTRAL, NEGATIVE\n    }\n\n    Sentiment reviewSentiment = chatClient.prompt(\"\"\"\n            Classify movie reviews as POSITIVE, NEUTRAL or NEGATIVE.\n            Review: \"Her\" is a disturbing study revealing the direction\n            humanity is headed if AI is allowed to keep evolving,\n            unchecked. I wish there were more movies like this masterpiece.\n            Sentiment:\n            \"\"\")\n            .options(ChatOptions.builder()\n                    .model(\"claude-3-7-sonnet-latest\")\n                    .temperature(0.1)\n                    .maxTokens(5)\n                    .build())\n            .call()\n            .entity(Sentiment.class);\n\n    System.out.println(\"Output: \" + reviewSentiment);\n}\n\nThis example shows how to classify a movie review sentiment without providing examples. Note the low temperature (0.1) for more deterministic results and the direct <code>.entity(Sentiment.class)</code> mapping to a Java enum.\n\n<strong>Reference:</strong> Brown, T. B., et al. (2020). \"Language Models are Few-Shot Learners.\" arXiv:2005.14165. <a href=\"https://arxiv.org/abs/2005.14165\">https://arxiv.org/abs/2005.14165</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.1 Zero-Shot Prompting::0'),
('fbef158c-ce02-4e88-b420-1e6825f863d0','/**\n * Context used to store metadata for vector store operations.\n *\n * @author Christian Tzolov\n * @author Thomas Vitale\n * @author Ilayaperumal Gopinathan\n * @since 1.0.0\n */\npublic class VectorStoreObservationContext extends Observation.Context {\n\n    private final String databaseSystem;\n\n    // COMMON\n    private final String operationName;\n\n    @Nullable\n    private String collectionName;\n\n    @Nullable\n    private Integer dimensions;\n\n    @Nullable\n    private String fieldName;\n\n    @Nullable\n    private String namespace;\n\n    @Nullable\n    private String similarityMetric;\n\n    @Nullable\n    private SearchRequest queryRequest;\n\n    // SEARCH\n    @Nullable\n    private List<Document> queryResponse;\n\n    public VectorStoreObservationContext(String databaseSystem, String operationName) {\n        Assert.hasText(databaseSystem, \"databaseSystem cannot be null or empty\");\n        Assert.hasText(operationName, \"operationName cannot be null or empty\");\n        this.databaseSystem = databaseSystem;\n        this.operationName = operationName;\n    }\n\n    public static Builder builder(String databaseSystem, String operationName) {\n        return new Builder(databaseSystem, operationName);\n    }\n\n    public static Builder builder(String databaseSystem, Operation operation) {\n        return builder(databaseSystem, operation.value);\n    }\n\n    public String getDatabaseSystem() {\n        return this.databaseSystem;\n    }\n\n    public String getOperationName() {\n        return this.operationName;\n    }\n\n    @Nullable\n    public String getCollectionName() {\n        return this.collectionName;\n    }\n\n    public void setCollectionName(@Nullable String collectionName) {\n        this.collectionName = collectionName;\n    }\n\n    @Nullable\n    public Integer getDimensions() {\n        return this.dimensions;\n    }\n\n    public void setDimensions(@Nullable Integer dimensions) {\n        this.dimensions = dimensions;\n    }\n\n    @Nullable\n    public String getFieldName() {\n        return this.fieldName;\n    }\n\n    public void setFieldName(@Nullable String fieldName) {\n        this.fieldName = fieldName;\n    }\n\n    @Nullable\n    public String getNamespace() {\n        return this.namespace;\n    }\n\n    public void setNamespace(@Nullable String namespace) {\n        this.namespace = namespace;\n    }\n\n    @Nullable\n    public String getSimilarityMetric() {\n        return this.similarityMetric;\n    }\n\n    public void setSimilarityMetric(@Nullable String similarityMetric) {\n        this.similarityMetric = similarityMetric;\n    }\n\n    @Nullable\n    public SearchRequest getQueryRequest() {\n        return this.queryRequest;\n    }\n\n    public void setQueryRequest(@Nullable SearchRequest queryRequest) {\n        this.queryRequest = queryRequest;\n    }\n\n    @Nullable\n    public List<Document> getQueryResponse() {\n        return this.queryResponse;\n    }\n\n    public void setQueryResponse(@Nullable List<Document> queryResponse) {\n        this.queryResponse = queryResponse;\n    }\n\n    public enum Operation {\n\n        /**\n         * VectorStore add operation.\n         */\n        ADD(\"add\"),\n        /**\n         * VectorStore delete operation.\n         */\n        DELETE(\"delete\"),\n        /**\n         * VectorStore similarity search operation.\n         */\n        QUERY(\"query\");\n\n        public final String value;\n\n        Operation(String value) {\n            this.value = value;\n        }\n\n        public String value() {\n            return this.value;\n        }\n    }\n\n    public static final class Builder {\n\n        private final VectorStoreObservationContext context;\n\n        public Builder(String databaseSystem, String operationName) {\n            this.context = new VectorStoreObservationContext(databaseSystem, operationName);\n        }\n\n        public Builder collectionName(String collectionName) {\n            this.context.setCollectionName(collectionName);\n            return this;\n        }\n\n        public Builder dimensions(Integer dimensions) {\n            this.context.setDimensions(dimensions);\n            return this;\n        }\n\n        public Builder fieldName(@Nullable String fieldName) {\n            this.context.setFieldName(fieldName);\n            return this;\n        }\n\n        public Builder namespace(String namespace) {\n            this.context.setNamespace(namespace);\n            return this;\n        }\n\n        public Builder queryRequest(SearchRequest request) {\n            this.context.setQueryRequest(request);\n            return this;\n        }\n\n        public Builder queryResponse(List<Document> documents) {\n            this.context.setQueryResponse(documents);\n            return this;\n        }\n\n        public Builder similarityMetric(String similarityMetric) {\n            this.context.setSimilarityMetric(similarityMetric);\n            return this;\n        }\n\n        public VectorStoreObservationContext build() {\n            return this.context;\n        }\n    }\n}',0x01,'cu::VectorStoreObservationContext.java'),
('f8648a55-87fa-4344-8b3a-1e6876c22a19','You can register custom Java functions with the AzureOpenAiChatModel and have the model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.\nRead more about <a href=\"api/tools.html\">Tool Calling</a>.',0x00,'asciidoc::azure-openai-chat.adoc::Function Calling::0'),
('09b94faf-d3cc-49fc-af8a-1e9ccf22e6d8','Retry Properties\n\nThe prefix <code>spring.ai.retry</code> is used as the property prefix that lets you configure the retry mechanism for the Mistral AI Embedding model.\n\n\n\nConnection Properties\n\nThe prefix <code>spring.ai.mistralai</code> is used as the property prefix that lets you connect to MistralAI.\n\n\n\nConfiguration Properties\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=mistral (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match mistral)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.mistralai.embedding</code> is property prefix that configures the <code>EmbeddingModel</code> implementation for MistralAI.\n\n\n\nYou can override the common <code>spring.ai.mistralai.base-url</code> and <code>spring.ai.mistralai.api-key</code> for the <code>ChatModel</code> and <code>EmbeddingModel</code> implementations.\nThe <code>spring.ai.mistralai.embedding.base-url</code> and <code>spring.ai.mistralai.embedding.api-key</code> properties if set take precedence over the common properties.\nSimilarly, the <code>spring.ai.mistralai.chat.base-url</code> and <code>spring.ai.mistralai.chat.api-key</code> properties if set take precedence over the common properties.\nThis is useful if you want to use different MistralAI accounts for different models and different model endpoints.\n\nAll properties prefixed with <code>spring.ai.mistralai.embedding.options</code> can be overridden at runtime by adding a request specific <a href=\"#embedding-options\">Runtime Options</a> to the <code>EmbeddingRequest</code> call.',0x00,'asciidoc::mistralai-embeddings.adoc::Auto-configuration::Embedding Properties::0'),
('90b239ff-d8fc-4029-89e0-1eb00197b846','The <code>tool_choice</code> parameter allows you to control how the model uses the provided tools. This feature gives you fine-grained control over tool execution behavior.\n\nFor complete API details, see the <a href=\"https://docs.anthropic.com/en/api/messages#body-tool-choice\">Anthropic tool_choice documentation</a>.\n\nTool Choice Options\n\nSpring AI provides four tool choice strategies through the <code>AnthropicApi.ToolChoice</code> interface:\n\n<strong><code>ToolChoiceAuto</code></strong> (default): The model automatically decides whether to use tools or respond with text\n<strong><code>ToolChoiceAny</code></strong>: The model must use at least one of the available tools\n<strong><code>ToolChoiceTool</code></strong>: The model must use a specific tool by name\n<strong><code>ToolChoiceNone</code></strong>: The model cannot use any tools\n\n\nDisabling Parallel Tool Use\n\nAll tool choice options (except <code>ToolChoiceNone</code>) support a <code>disableParallelToolUse</code> parameter. When set to <code>true</code>, the model will output at most one tool use.\n\nUsage Examples\n\nAuto Mode (Default Behavior)\n\nLet the model decide whether to use tools:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What\'s the weather in San Francisco?\",\n        AnthropicChatOptions.builder()\n            .toolChoice(new AnthropicApi.ToolChoiceAuto())\n            .toolCallbacks(weatherToolCallback)\n            .build()\n    )\n);\n\nForce Tool Use (Any)\n\nRequire the model to use at least one tool:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What\'s the weather?\",\n        AnthropicChatOptions.builder()\n            .toolChoice(new AnthropicApi.ToolChoiceAny())\n            .toolCallbacks(weatherToolCallback, calculatorToolCallback)\n            .build()\n    )\n);\n\nForce Specific Tool\n\nRequire the model to use a specific tool by name:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What\'s the weather in San Francisco?\",\n        AnthropicChatOptions.builder()\n            .toolChoice(new AnthropicApi.ToolChoiceTool(\"get_weather\"))\n            .toolCallbacks(weatherToolCallback, calculatorToolCallback)\n            .build()\n    )\n);\n\nDisable Tool Use\n\nPrevent the model from using any tools:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What\'s the weather in San Francisco?\",\n        AnthropicChatOptions.builder()\n            .toolChoice(new AnthropicApi.ToolChoiceNone())\n            .toolCallbacks(weatherToolCallback)\n            .build()\n    )\n);\n\nDisable Parallel Tool Use\n\nForce the model to use only one tool at a time:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What\'s the weather in San Francisco and what\'s 2+2?\",\n        AnthropicChatOptions.builder()\n            .toolChoice(new AnthropicApi.ToolChoiceAuto(true)) // disableParallelToolUse = true\n            .toolCallbacks(weatherToolCallback, calculatorToolCallback)\n            .build()\n    )\n);\n\nUsing ChatClient API',0x00,'asciidoc::anthropic-chat.adoc::Tool/Function Calling::Tool Choice::0'),
('8af92b89-462e-4b38-aa8b-1eb004f51c48','Portable <code>Model API</code> across AI providers for <code>Chat</code>, <code>Text to Image</code>, <code>Audio Transcription</code>, <code>Text to Speech</code>, and <code>Embedding</code> models.\nBoth <code>synchronous</code> and <code>stream</code> API options are supported.\nDropping down to access model specific features is also supported.\n\nWith support for AI Models from OpenAI, Microsoft, Amazon, Google, Amazon Bedrock, Hugging Face and more.',0x00,'asciidoc::index.adoc::Introduction::AI Model API::0'),
('1cffb9fb-8bbf-4a7b-9281-1f3c33978bd0','@SuppressWarnings(\"CheckReturnValue\")\npublic static class CompareExpressionContext extends BooleanExpressionContext {\n\n    public IdentifierContext identifier() {\n        return getRuleContext(IdentifierContext.class, 0);\n    }\n\n    public CompareContext compare() {\n        return getRuleContext(CompareContext.class, 0);\n    }\n\n    public ConstantContext constant() {\n        return getRuleContext(ConstantContext.class, 0);\n    }\n\n    public CompareExpressionContext(BooleanExpressionContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterCompareExpression(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitCompareExpression(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitCompareExpression(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('37a74789-b169-4344-9f08-1f907bd8e6c1','The <code>OCIEmbeddingOptions</code> provides the configuration information for the embedding requests.\nThe <code>OCIEmbeddingOptions</code> offers a builder to create the options.\n\nAt start time use the <code>OCIEmbeddingOptions</code> constructor to set the  default options used for all embedding requests.\nAt run-time you can override the default options, by passing a <code>OCIEmbeddingOptions</code> instance with your to the  <code>EmbeddingRequest</code> request.\n\nFor example to override the default model name for a specific request:\n\nEmbeddingResponse embeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n        OCIEmbeddingOptions.builder()\n            .model(\"my-other-embedding-model\")\n            .build()\n));',0x00,'asciidoc::oci-genai-embeddings.adoc::Runtime Options::0'),
('ee7560b5-a0b5-4a37-92e3-2025d6eb0109','// Cache conversation history with ChatClient and memory\nChatClient chatClient = ChatClient.builder(chatModel)\n    .defaultSystem(\"You are a personalized career counselor...\")\n    .defaultAdvisors(MessageChatMemoryAdvisor.builder(chatMemory)\n        .conversationId(conversationId)\n        .build())\n    .build();\n\nString response = chatClient.prompt()\n    .user(\"What career advice would you give me?\")\n    .options(BedrockChatOptions.builder()\n        .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n        .cacheOptions(BedrockCacheOptions.builder()\n            .strategy(BedrockCacheStrategy.CONVERSATION_HISTORY)\n            .build())\n        .maxTokens(500)\n        .build())\n    .call()\n    .content();\n\nUsing ChatClient Fluent API\n\nString response = ChatClient.create(chatModel)\n    .prompt()\n    .system(\"You are an expert document analyst...\")\n    .user(\"Analyze this large document: \" + document)\n    .options(BedrockChatOptions.builder()\n        .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n        .cacheOptions(BedrockCacheOptions.builder()\n            .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n            .build())\n        .build())\n    .call()\n    .content();',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Enabling Prompt Caching::1'),
('7e4e230d-e98f-4306-9f81-203fa8f51059','<span class=\"image right\"><img src=\"advisors-recursive.png\" alt=\"Advisors Recursive\" width=\"230\"></span>\nRecursive advisors are a special type of advisor that can loop through the downstream advisor chain multiple times.\nThis pattern is useful when you need to repeatedly call the LLM until a certain condition is met, such as:\n\nExecuting tool calls in a loop until no more tools need to be called\nValidating structured output and retrying if validation fails\nImplementing Evaluation logic with modifications to the request\nImplementing retry logic with modifications to the request\n\n\nThe <code>CallAdvisorChain.copy(CallAdvisor after)</code> method is the key utility that enables recursive advisor patterns.\nIt creates a new advisor chain that contains only the advisors that come after the specified advisor in the original chain\nand allows the recursive advisor to call this sub-chain as needed.\nThis approach ensures that:\n\nThe recursive advisor can loop through the remaining advisors in the chain\nOther advisors in the chain can observe and intercept each iteration\nThe advisor chain maintains proper ordering and observability\nThe recursive advisor doesn&#8217;t re-execute advisors that came before it',0x00,'asciidoc::advisors-recursive.adoc::What is a Recursive Advisor?::0'),
('400ed583-f563-4598-a481-2042becb2d3a','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::mistralai-chat.adoc::Prerequisites::Add Repositories and BOM::0'),
('f5c9f1b1-be3a-4dae-9b41-20463b575864','The new API provides better separation between tool definition and implementation.\nTool definitions can be reused across different implementations.\nThe builder pattern has been simplified for common use cases.\nBetter support for method-based tools with improved error handling.',0x00,'asciidoc::tools-migration.adoc::Additional Notes::0'),
('33c1882b-59ad-4f83-a946-206c7338e9fe','<div class=\"paragraph\">\n<p>The Spring AI Advisors API provides a flexible and powerful way to intercept, modify, and enhance AI-driven interactions in your Spring applications.\nBy leveraging the Advisors API, developers can create more sophisticated, reusable, and maintainable AI components.</p>\n</div>\n<div class=\"paragraph\">\n<p>The key benefits include encapsulating recurring Generative AI patterns, transforming data sent to and from Large Language Models (LLMs), and providing portability across various models and use cases.</p>\n</div>\n<div class=\"paragraph\">\n<p>You can configure existing advisors using the <a href=\"api/chatclient.html#_advisor_configuration_in_chatclient\">ChatClient API</a> as shown in the following example:</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-java\" data-lang=\"java\">ChatMemory chatMemory = ... // Initialize your chat memory store\nVectorStore vectorStore = ... // Initialize your vector store\n\nvar chatClient = ChatClient.builder(chatModel)\n    .defaultAdvisors(\n        MessageChatMemoryAdvisor.builder(chatMemory).build(), // chat-memory advisor\n        QuestionAnswerAdvisor.builder(vectorStore).build()    // RAG advisor\n    )\n    .build();\n\nvar conversationId = \"678\";\n\nString response = this.chatClient.prompt()\n    // Set advisor parameters at runtime\n    .advisors(advisor -&gt; advisor.param(ChatMemory.CONVERSATION_ID, conversationId))\n    .user(userText)\n    .call()\n	.content();</code></pre>\n</div>\n</div>\n<div class=\"paragraph\">\n<p>It is recommend to register the advisors at build time using builder&#8217;s <code>defaultAdvisors()</code> method.</p>\n</div>\n<div class=\"paragraph\">\n<p>Advisors also participate in the Observability stack, so you can view metrics and traces related to their execution.</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p><a href=\"ROOT:api/retrieval-augmented-generation.html#_questionansweradvisor\">Learn about Question Answer Advisor</a></p>\n</li>\n<li>\n<p><a href=\"ROOT:api/chat-memory.html#_memory_in_chat_client\">Learn about Chat Memory Advisor</a></p>\n</li>\n</ul>\n</div>',0x00,'asciidoc::advisors.adoc::0'),
('099b1730-f765-4cb7-83fc-206c8a6ab587','Multimodality refers to a model&#8217;s ability to simultaneously understand and process information from various (input) sources, including <code>text</code>, <code>pdf</code>, <code>images</code>, <code>audio</code>, and other data formats.',0x00,'asciidoc::vertexai-gemini-chat.adoc::Multimodal::0'),
('d0b1e1b0-13d2-4873-945d-20bf395c8ff5','@SuppressWarnings(\"CheckReturnValue\")\npublic static class LongConstantContext extends ConstantContext {\n\n    public TerminalNode INTEGER_VALUE() {\n        return getToken(FiltersParser.INTEGER_VALUE, 0);\n    }\n\n    public TerminalNode LONG_SUFFIX() {\n        return getToken(FiltersParser.LONG_SUFFIX, 0);\n    }\n\n    public TerminalNode MINUS() {\n        return getToken(FiltersParser.MINUS, 0);\n    }\n\n    public TerminalNode PLUS() {\n        return getToken(FiltersParser.PLUS, 0);\n    }\n\n    public LongConstantContext(ConstantContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterLongConstant(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitLongConstant(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitLongConstant(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('0df4abae-4e6f-437d-bf8c-20ceb3b8b827','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::openai-embeddings.adoc::Prerequisites::Add Repositories and BOM::0'),
('ccc79fdd-889e-460c-840c-2108a2287520','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-mistral-ai</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file under the <code>src/main/resources</code> directory to enable and configure the Mistral AI chat model:\n\nspring.ai.mistralai.api-key=YOUR_API_KEY\nspring.ai.mistralai.chat.options.model=mistral-small\nspring.ai.mistralai.chat.options.temperature=0.7\n\nReplace the <code>api-key</code> with your Mistral AI credentials.\n\nThis will create a <code>MistralAiChatModel</code> implementation that you can inject into your classes.\nHere is an example of a simple <code>@RestController</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final MistralAiChatModel chatModel;\n\n    @Autowired\n    public ChatController(MistralAiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map&lt;String,String&gt; generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        var prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::mistralai-chat.adoc::Sample Controller (Auto-configuration)::0'),
('a2906bd2-0ec2-4e6b-9667-215e55e628d1','/**\n * A component for transforming the input query to make it more effective for retrieval\n * tasks, addressing challenges such as poorly formed queries, ambiguous terms, complex\n * vocabulary, or unsupported languages.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic interface QueryTransformer extends Function<Query, Query> {\n\n    /**\n     * Transforms the given query according to the implemented strategy.\n     * @param query The original query to transform\n     * @return The transformed query\n     */\n    Query transform(Query query);\n\n    default Query apply(Query query) {\n        return transform(query);\n    }\n}',0x01,'cu::QueryTransformer.java'),
('90a79552-7fb5-4609-bffc-2221d50b375c','Create a new Spring Boot project and add the <code>spring-ai-starter-model-bedrock-converse</code> to your dependencies.\n\nAdd an <code>application.properties</code> file under <code>src/main/resources</code>:\n\nspring.ai.bedrock.aws.region=eu-central-1\nspring.ai.bedrock.aws.timeout=10m\nspring.ai.bedrock.aws.access-key=${AWS_ACCESS_KEY_ID}\nspring.ai.bedrock.aws.secret-key=${AWS_SECRET_ACCESS_KEY}\n# session token is only required for temporary credentials\nspring.ai.bedrock.aws.session-token=${AWS_SESSION_TOKEN}\n\nspring.ai.bedrock.converse.chat.options.temperature=0.8\nspring.ai.bedrock.converse.chat.options.top-k=15\n\nHere&#8217;s an example controller using the chat model:\n\n@RestController\npublic class ChatController {\n\n    private final ChatClient chatClient;\n\n    @Autowired\n    public ChatController(ChatClient.Builder builder) {\n        this.chatClient = builder.build();\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatClient.prompt(message).call().content());\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n    public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return this.chatClient.prompt(message).stream().content();\n    }\n}',0x00,'asciidoc::bedrock-converse.adoc::Sample Controller::0'),
('c695d3ce-646c-455b-b99c-2238010c2bff','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-vertex-ai-embedding/src/main/java/org/springframework/ai/vertexai/embedding/VertexAiMultimodalEmbeddingModel.java\">VertexAiMultimodalEmbeddingModel</a> implements the <code>DocumentEmbeddingModel</code>.\n\nAdd the <code>spring-ai-vertex-ai-embedding</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-vertex-ai-embedding&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-vertex-ai-embedding\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>VertexAiMultimodalEmbeddingModel</code> and use it for embeddings generations:\n\nVertexAiEmbeddingConnectionDetails connectionDetails =\n    VertexAiEmbeddingConnectionDetails.builder()\n        .projectId(System.getenv(&lt;VERTEX_AI_GEMINI_PROJECT_ID&gt;))\n        .location(System.getenv(&lt;VERTEX_AI_GEMINI_LOCATION&gt;))\n        .build();\n\nVertexAiMultimodalEmbeddingOptions options = VertexAiMultimodalEmbeddingOptions.builder()\n    .model(VertexAiMultimodalEmbeddingOptions.DEFAULT_MODEL_NAME)\n    .build();\n\nvar embeddingModel = new VertexAiMultimodalEmbeddingModel(this.connectionDetails, this.options);\n\nMedia imageMedial = new Media(MimeTypeUtils.IMAGE_PNG, new ClassPathResource(\"/test.image.png\"));\nMedia videoMedial = new Media(new MimeType(\"video\", \"mp4\"), new ClassPathResource(\"/test.video.mp4\"));\n\nvar document = new Document(\"Explain what do you see on this video?\", List.of(this.imageMedial, this.videoMedial), Map.of());\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n	.embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));\n\nDocumentEmbeddingRequest embeddingRequest = new DocumentEmbeddingRequest(List.of(this.document),\n        EmbeddingOptions.EMPTY);\n\nEmbeddingResponse embeddingResponse = multiModelEmbeddingModel.call(this.embeddingRequest);\n\nassertThat(embeddingResponse.getResults()).hasSize(3);',0x00,'asciidoc::vertexai-embeddings-multimodal.adoc::Manual Configuration::0'),
('24dc549c-6c2c-4ad5-acbc-2276b08cce55','/**\n * Unit tests for {@link DefaultVectorStoreObservationConvention}.\n *\n * @author Christian Tzolov\n * @author Thomas Vitale\n */\nclass DefaultVectorStoreObservationConventionTests {\n\n    private final DefaultVectorStoreObservationConvention observationConvention = new DefaultVectorStoreObservationConvention();\n\n    @Test\n    void shouldHaveName() {\n        assertThat(this.observationConvention.getName()).isEqualTo(DefaultVectorStoreObservationConvention.DEFAULT_NAME);\n    }\n\n    @Test\n    void shouldHaveContextualName() {\n        VectorStoreObservationContext observationContext = VectorStoreObservationContext.builder(\"my-database\", VectorStoreObservationContext.Operation.QUERY).build();\n        assertThat(this.observationConvention.getContextualName(observationContext)).isEqualTo(\"my-database query\");\n    }\n\n    @Test\n    void supportsOnlyVectorStoreObservationContext() {\n        VectorStoreObservationContext observationContext = VectorStoreObservationContext.builder(\"my-database\", VectorStoreObservationContext.Operation.QUERY).build();\n        assertThat(this.observationConvention.supportsContext(observationContext)).isTrue();\n        assertThat(this.observationConvention.supportsContext(new Observation.Context())).isFalse();\n    }\n\n    @Test\n    void shouldHaveRequiredKeyValues() {\n        VectorStoreObservationContext observationContext = VectorStoreObservationContext.builder(\"my_database\", VectorStoreObservationContext.Operation.QUERY).build();\n        assertThat(this.observationConvention.getLowCardinalityKeyValues(observationContext)).contains(KeyValue.of(LowCardinalityKeyNames.SPRING_AI_KIND.asString(), SpringAiKind.VECTOR_STORE.value()), KeyValue.of(LowCardinalityKeyNames.DB_OPERATION_NAME.asString(), \"query\"), KeyValue.of(LowCardinalityKeyNames.DB_SYSTEM.asString(), \"my_database\"));\n    }\n\n    @Test\n    void shouldHaveOptionalKeyValues() {\n        VectorStoreObservationContext observationContext = VectorStoreObservationContext.builder(\"my-database\", VectorStoreObservationContext.Operation.QUERY).collectionName(\"COLLECTION_NAME\").dimensions(696).fieldName(\"FIELD_NAME\").namespace(\"NAMESPACE\").similarityMetric(\"SIMILARITY_METRIC\").queryRequest(SearchRequest.builder().query(\"VDB QUERY\").filterExpression(\"country == \'UK\' && year >= 2020\").build()).build();\n        List<Document> queryResponseDocs = List.of(new Document(\"doc1\"), new Document(\"doc2\"));\n        observationContext.setQueryResponse(queryResponseDocs);\n        assertThat(this.observationConvention.getLowCardinalityKeyValues(observationContext)).contains(KeyValue.of(LowCardinalityKeyNames.DB_OPERATION_NAME.asString(), VectorStoreObservationContext.Operation.QUERY.value));\n        assertThat(this.observationConvention.getHighCardinalityKeyValues(observationContext)).contains(KeyValue.of(HighCardinalityKeyNames.DB_COLLECTION_NAME.asString(), \"COLLECTION_NAME\"), KeyValue.of(HighCardinalityKeyNames.DB_VECTOR_DIMENSION_COUNT.asString(), \"696\"), KeyValue.of(HighCardinalityKeyNames.DB_VECTOR_FIELD_NAME.asString(), \"FIELD_NAME\"), KeyValue.of(HighCardinalityKeyNames.DB_NAMESPACE.asString(), \"NAMESPACE\"), KeyValue.of(HighCardinalityKeyNames.DB_SEARCH_SIMILARITY_METRIC.asString(), \"SIMILARITY_METRIC\"), KeyValue.of(HighCardinalityKeyNames.DB_VECTOR_QUERY_CONTENT.asString(), \"VDB QUERY\"), KeyValue.of(HighCardinalityKeyNames.DB_VECTOR_QUERY_FILTER.asString(), \"Expression[type=AND, left=Expression[type=EQ, left=Key[key=country], right=Value[value=UK]], right=Expression[type=GTE, left=Key[key=year], right=Value[value=2020]]]\"));\n    }\n\n    @Test\n    void shouldNotHaveKeyValuesWhenMissing() {\n        VectorStoreObservationContext observationContext = VectorStoreObservationContext.builder(\"my-database\", VectorStoreObservationContext.Operation.QUERY).build();\n        assertThat(this.observationConvention.getHighCardinalityKeyValues(observationContext).stream().map(KeyValue::getKey).toList()).doesNotContain(HighCardinalityKeyNames.DB_COLLECTION_NAME.asString(), HighCardinalityKeyNames.DB_VECTOR_DIMENSION_COUNT.asString(), HighCardinalityKeyNames.DB_VECTOR_FIELD_NAME.asString(), HighCardinalityKeyNames.DB_NAMESPACE.asString(), HighCardinalityKeyNames.DB_SEARCH_SIMILARITY_METRIC.asString(), HighCardinalityKeyNames.DB_VECTOR_QUERY_CONTENT.asString(), HighCardinalityKeyNames.DB_VECTOR_QUERY_FILTER.asString());\n    }\n}',0x01,'cu::DefaultVectorStoreObservationConventionTests.java'),
('23134bf1-35a5-445c-9718-2387f41ab4d2','The response from the AI model is a rich structure defined by the type <code><a href=\"api/chatmodel.html#ChatResponse\">ChatResponse</a></code>.\nIt includes metadata about how the response was generated and can also contain multiple responses, known as <a href=\"api/chatmodel.html#Generation\">Generation</a>s, each with its own metadata.\nThe metadata includes the number of tokens (each token is approximately 3/4 of a word) used to create the response.\nThis information is important because hosted AI models charge based on the number of tokens used per request.\n\nAn example to return the <code>ChatResponse</code> object that contains the metadata is shown below by invoking <code>chatResponse()</code> after the <code>call()</code> method.\n\nChatResponse chatResponse = chatClient.prompt()\n    .user(\"Tell me a joke\")\n    .call()\n    .chatResponse();',0x00,'asciidoc::chatclient.adoc::ChatClient Responses::Returning a ChatResponse::0'),
('fde4ff45-8c07-4fc8-9d82-23a98220c342','If you are not using Spring Boot, you can manually configure the ZhiPuAI Embedding Model.\nFor this add the <code>spring-ai-zhipuai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-zhipuai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-zhipuai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThe <code>spring-ai-zhipuai</code> dependency provides access also to the <code>ZhiPuAiChatModel</code>.\nFor more information about the <code>ZhiPuAiChatModel</code> refer to the <a href=\"../chat/zhipuai-chat.html\">ZhiPuAI Chat Client</a> section.\n\nNext, create an <code>ZhiPuAiEmbeddingModel</code> instance and use it to compute the similarity between two input texts:\n\nvar zhiPuAiApi = new ZhiPuAiApi(System.getenv(\"ZHIPUAI_API_KEY\"));\n\nvar embeddingModel = new ZhiPuAiEmbeddingModel(api, MetadataMode.EMBED,\n				ZhiPuAiEmbeddingOptions.builder()\n						.model(\"embedding-3\")\n						.dimensions(1536)\n						.build());\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n	.embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));\n\nThe <code>ZhiPuAiEmbeddingOptions</code> provides the configuration information for the embedding requests.\nThe options class offers a <code>builder()</code> for easy options creation.',0x00,'asciidoc::zhipuai-embeddings.adoc::Manual Configuration::0'),
('87fa6a21-c23f-45d0-8b7f-23b0598c6e7f','You can use the following properties in your Spring Boot configuration to customize the SAP Hana vector store.\nIt uses <code>spring.datasource.<strong></code> properties to configure the Hana datasource and the <code>spring.ai.vectorstore.hanadb.</strong></code> properties to configure the Hana vector store.',0x00,'asciidoc::hana.adoc::HanaCloudVectorStore Properties::0'),
('d417a803-79c0-4459-a15b-23c6010d8cc8','Ollama supports thinking mode for reasoning models that can emit their internal reasoning process before providing a final answer. This feature is available for models like Qwen3, DeepSeek-v3.1, DeepSeek R1, and GPT-OSS.\n\nThinking mode helps you understand the model&#8217;s reasoning process and can improve response quality for complex problems.\n\n<strong>Default Behavior (Ollama 0.12+)</strong>: Thinking-capable models (such as <code>qwen3:*-thinking</code>, <code>deepseek-r1</code>, <code>deepseek-v3.1</code>) <strong>auto-enable thinking by default</strong> when the think option is not explicitly set. Standard models (such as <code>qwen2.5:*</code>, <code>llama3.2</code>) do not enable thinking by default. To explicitly control this behavior, use <code>.enableThinking()</code> or <code>.disableThinking()</code>.',0x00,'asciidoc::ollama-chat.adoc::Thinking Mode (Reasoning)::0'),
('b3b1375a-0ffe-465c-b610-245aaf0d85c3','Here&#8217;s a complete example showing how to track usage with OpenAI&#8217;s ChatModel:\n\n@SpringBootConfiguration\npublic class Configuration {\n\n        @Bean\n        public OpenAiApi chatCompletionApi() {\n            return OpenAiApi.builder()\n                .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n                .build();\n        }\n\n        @Bean\n        public OpenAiChatModel openAiClient(OpenAiApi openAiApi) {\n            return OpenAiChatModel.builder()\n                .openAiApi(openAiApi)\n                .build();\n        }\n\n    }\n\n@Service\npublic class ChatService {\n\n    private final OpenAiChatModel chatModel;\n\n    public ChatService(OpenAiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    public void demonstrateUsage() {\n        // Create a chat prompt\n        Prompt prompt = new Prompt(\"What is the weather like today?\");\n\n        // Get the chat response\n        ChatResponse response = this.chatModel.call(prompt);\n\n        // Access the usage information\n        Usage usage = response.getMetadata().getUsage();\n\n        // Get standard usage metrics\n        System.out.println(\"Prompt Tokens: \" + usage.getPromptTokens());\n        System.out.println(\"Completion Tokens: \" + usage.getCompletionTokens());\n        System.out.println(\"Total Tokens: \" + usage.getTotalTokens());\n\n        // Access native OpenAI usage data with detailed token information\n        if (usage.getNativeUsage() instanceof org.springframework.ai.openai.api.OpenAiApi.Usage) {\n            org.springframework.ai.openai.api.OpenAiApi.Usage nativeUsage =\n                (org.springframework.ai.openai.api.OpenAiApi.Usage) usage.getNativeUsage();\n\n            // Detailed prompt token information\n            System.out.println(\"Prompt Tokens Details:\");\n            System.out.println(\"- Audio Tokens: \" + nativeUsage.promptTokensDetails().audioTokens());\n            System.out.println(\"- Cached Tokens: \" + nativeUsage.promptTokensDetails().cachedTokens());\n\n            // Detailed completion token information\n            System.out.println(\"Completion Tokens Details:\");\n            System.out.println(\"- Reasoning Tokens: \" + nativeUsage.completionTokenDetails().reasoningTokens());\n            System.out.println(\"- Accepted Prediction Tokens: \" + nativeUsage.completionTokenDetails().acceptedPredictionTokens());\n            System.out.println(\"- Audio Tokens: \" + nativeUsage.completionTokenDetails().audioTokens());\n            System.out.println(\"- Rejected Prediction Tokens: \" + nativeUsage.completionTokenDetails().rejectedPredictionTokens());\n        }\n    }\n}',0x00,'asciidoc::usage-handling.adoc::Key Changes::Using with ChatModel::0'),
('1de75c43-5777-4c3d-a96b-249ef3a434c5','You will need to create an API with OpenAI to access ChatGPT models.\n\nCreate an account at <a href=\"https://platform.openai.com/signup\">OpenAI signup page</a> and generate the token on the <a href=\"https://platform.openai.com/account/api-keys\">API Keys page</a>.\n\nThe Spring AI project defines a configuration property named <code>spring.ai.openai.api-key</code> that you should set to the value of the <code>API Key</code> obtained from openai.com.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.openai.api-key=&lt;your-openai-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference a custom environment variable:\n\n# In application.yml\nspring:\n  ai:\n    openai:\n      api-key: ${OPENAI_API_KEY}\n\n# In your environment or .env file\nexport OPENAI_API_KEY=&lt;your-openai-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"OPENAI_API_KEY\");',0x00,'asciidoc::openai-chat.adoc::Prerequisites::0'),
('748d0a8d-ffbe-4299-8271-2529c8f959b6','Spring AI provides strategic cache placement through the <code>BedrockCacheStrategy</code> enum:\n\n<code>NONE</code>: Disables prompt caching completely (default)\n<code>SYSTEM_ONLY</code>: Caches only the system message content\n<code>TOOLS_ONLY</code>: Caches tool definitions only (Claude models only)\n<code>SYSTEM_AND_TOOLS</code>: Caches both system message and tool definitions (Claude models only)\n<code>CONVERSATION_HISTORY</code>: Caches entire conversation history in chat memory scenarios\n\n\nThis strategic approach ensures optimal cache breakpoint placement while staying within AWS Bedrock&#8217;s 4-breakpoint limit.\n\n<div class=\"paragraph\">\n<p><strong>Amazon Nova Limitations</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Amazon Nova models (Nova Micro, Lite, Pro, Premier) only support caching for <code>system</code> and <code>messages</code> content.\nThey do <strong>not</strong> support caching for <code>tools</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>If you attempt to use <code>TOOLS_ONLY</code> or <code>SYSTEM_AND_TOOLS</code> strategies with Nova models, AWS will return a <code>ValidationException</code>.\nUse <code>SYSTEM_ONLY</code> strategy for Amazon Nova models.</p>\n</div>',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Cache Strategies::0'),
('f0a418c7-a611-4031-9acc-252f16bf9a87','Most models (Qwen3, DeepSeek-v3.1, DeepSeek R1) support simple boolean enable/disable:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"How many letter \'r\' are in the word \'strawberry\'?\",\n        OllamaChatOptions.builder()\n            .model(\"qwen3\")\n            .enableThinking()\n            .build()\n    ));\n\n// Access the thinking process\nString thinking = response.getResult().getMetadata().get(\"thinking\");\nString answer = response.getResult().getOutput().getContent();\n\nYou can also disable thinking explicitly:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What is 2+2?\",\n        OllamaChatOptions.builder()\n            .model(\"deepseek-r1\")\n            .disableThinking()\n            .build()\n    ));',0x00,'asciidoc::ollama-chat.adoc::Thinking Mode (Reasoning)::Enabling Thinking Mode::0'),
('7ec6b91c-9257-4d26-845c-257dcccd7c06','<div class=\"paragraph\">\n<p>The <code>TransformersEmbeddingModel</code> is an <code>EmbeddingModel</code> implementation that locally computes <a href=\"https://www.sbert.net/examples/applications/computing-embeddings/README.html#sentence-embeddings-with-transformers\">sentence embeddings</a> using a selected <a href=\"https://www.sbert.net/\">sentence transformer</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>You can use any <a href=\"https://huggingface.co/spaces/mteb/leaderboard\">HuggingFace Embedding model</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>It uses <a href=\"https://www.sbert.net/docs/pretrained_models.html\">pre-trained</a> transformer models, serialized into the <a href=\"https://onnx.ai/\">Open Neural Network Exchange (ONNX)</a> format.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://djl.ai/\">Deep Java Library</a> and the Microsoft <a href=\"https://onnxruntime.ai/docs/get-started/with-java.html\">ONNX Java Runtime</a> libraries are applied to run the ONNX models and compute the embeddings in Java.</p>\n</div>',0x00,'asciidoc::onnx.adoc::0'),
('f4e57557-a2b6-4195-b60e-25a3cd761b36','In version 1.0.0-M6, the <code>delete</code> method in the <code>VectorStore</code> interface has been modified to be a void operation instead of returning an <code>Optional&lt;Boolean&gt;</code>.\nIf your code previously checked the return value of the delete operation, you&#8217;ll need to remove this check.\nThe operation now throws an exception if the deletion fails, providing more direct error handling.\n\nBefore 1.0.0-M6:\n\nOptional&lt;Boolean&gt; result = vectorStore.delete(ids);\nif (result.isPresent() &amp;&amp; result.get()) {\n    // handle successful deletion\n}\n\nIn 1.0.0-M6 and later:\n\nvectorStore.delete(ids);\n// deletion successful if no exception is thrown',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M6::Vector Store API changes::0'),
('d538bc45-93d1-45a1-8bad-25ab17c2123a','Spring AI provides two built-in recursive advisors that demonstrate this pattern:',0x00,'asciidoc::advisors-recursive.adoc::Built-in Recursive Advisors::0'),
('d3100a3d-39e2-488f-bd03-25c340cbf4fa','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OpenAI Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::perplexity-chat.adoc::Auto-configuration::0'),
('02c7f171-e7b4-416a-947c-26035c2c574d','The 1.0.0-SNAPSHOT includes changes to artifact IDs, package names, and module structure.\n\nFor details, refer to:\n- <a href=\"upgrade-notes.html#common-artifact-id-changes\">Common Artifact ID Changes</a>\n- <a href=\"upgrade-notes.html#common-package-changes\">Common Package Changes</a>\n- <a href=\"upgrade-notes.html#common-module-structure\">Common Module Structure</a>',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-SNAPSHOT::Artifact ID, Package, and Module Changes::0'),
('845c0441-392e-4447-8676-264700f5afb9','Observability features are currently supported only for <code>ChatModel</code> implementations from the following AI model\nproviders: Anthropic, Azure OpenAI, Mistral AI, Ollama, OpenAI, Vertex AI, MiniMax, Moonshot, QianFan, Zhipu AI.\nAdditional AI model providers will be supported in a future release.\n\nThe <code>gen_ai.client.operation</code> observations are recorded when calling the ChatModel <code>call</code> or <code>stream</code> methods.\nThey measure the time spent on method completion and propagate the related tracing information.\n\nThe <code>gen_ai.client.token.usage</code> metrics measures number of input and output tokens used by a single model call.\n\n\n\n\n\nFor measuring user tokens, the previous table lists the values present in an observation trace.\nUse the metric name <code>gen_ai.client.token.usage</code> that is provided by the <code>ChatModel</code>.',0x00,'asciidoc::index.adoc::Chat Model::0'),
('81cb7420-0b08-44a4-88c7-264bc69985e8','Creating effective prompts involves establishing the context of the request and substituting parts of the request with values specific to the user&#8217;s input.\n\nThis process uses traditional text-based template engines for prompt creation and management.\nSpring AI employs the OSS library <a href=\"https://www.stringtemplate.org/\">StringTemplate</a> for this purpose.\n\nFor instance, consider the simple prompt template:\n\nTell me a {adjective} joke about {content}.\n\nIn Spring AI, prompt templates can be likened to the \"View\" in Spring MVC architecture.\nA model object, typically a <code>java.util.Map</code>, is provided to populate placeholders within the template.\nThe \"rendered\" string becomes the content of the prompt supplied to the AI model.\n\nThere is considerable variability in the specific data format of the prompt sent to the model.\nInitially starting as simple strings, prompts have evolved to include multiple messages, where each string in each message represents a distinct role for the model.',0x00,'asciidoc::concepts.adoc::Prompts::Prompt Templates::0'),
('86f0d9d9-8bd6-479a-9cf4-266e35696437','<code>CosmosDBChatMemoryRepository</code> is a built-in implementation that uses Azure Cosmos DB NoSQL API to store messages. It is suitable for applications that require a globally distributed, highly scalable document database for chat memory persistence. The repository uses the conversation ID as the partition key to ensure efficient data distribution and fast retrieval.\n\nFirst, add the following dependency to your project:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-chat-memory-repository-cosmos-db&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-chat-memory-repository-cosmos-db\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nSpring AI provides auto-configuration for the <code>CosmosDBChatMemoryRepository</code>, which you can use directly in your application.\n\n@Autowired\nCosmosDBChatMemoryRepository chatMemoryRepository;\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nIf you&#8217;d rather create the <code>CosmosDBChatMemoryRepository</code> manually, you can do so by providing a <code>CosmosDBChatMemoryRepositoryConfig</code> instance:\n\nChatMemoryRepository chatMemoryRepository = CosmosDBChatMemoryRepository\n    .create(CosmosDBChatMemoryRepositoryConfig.builder()\n        .withCosmosClient(cosmosAsyncClient)\n        .withDatabaseName(\"chat-memory-db\")\n        .withContainerName(\"conversations\")\n        .build());\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nConfiguration Properties\n\n\n\nAuthentication\n\nThe Cosmos DB Chat Memory Repository supports two authentication methods:\n\n<strong>Key-based authentication</strong>: Provide the <code>spring.ai.chat.memory.repository.cosmosdb.key</code> property with your Cosmos DB primary or secondary key.\n<strong>Azure Identity authentication</strong>: When no key is provided, the repository uses Azure Identity (<code>DefaultAzureCredential</code>) to authenticate with managed identity, service principal, or other Azure credential sources.\n\n\nSchema Initialization\n\nThe auto-configuration will automatically create the specified database and container if they don&#8217;t exist. The container is configured with the conversation ID as the partition key (<code>/conversationId</code>) to ensure optimal performance for chat memory operations. No manual schema setup is required.',0x00,'asciidoc::chat-memory.adoc::Memory Storage::CosmosDBChatMemoryRepository::0'),
('f10c2de7-f409-470b-8040-26a0bb5791fd','The following types are not currently supported as parameters or return types for methods used as tools:\n\n<code>Optional</code>\nAsynchronous types (e.g. <code>CompletableFuture</code>, <code>Future</code>)\nReactive types (e.g. <code>Flow</code>, <code>Mono</code>, <code>Flux</code>)\nFunctional types (e.g. <code>Function</code>, <code>Supplier</code>, <code>Consumer</code>).\n\n\nFunctional types are supported using the function-based tool specification approach. See <a href=\"#_functions_as_tools\">Functions as Tools</a> for more details.',0x00,'asciidoc::tools.adoc::Methods as Tools::Method Tool Limitations::0'),
('4abede45-ba16-4683-abab-26afc0a462de','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-vertex-ai-embedding</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the VertexAi chat model:\n\nspring.ai.vertex.ai.embedding.project-id=&lt;YOUR_PROJECT_ID&gt;\nspring.ai.vertex.ai.embedding.location=&lt;YOUR_PROJECT_LOCATION&gt;\nspring.ai.vertex.ai.embedding.text.options.model=text-embedding-004\n\nThis will create a <code>VertexAiTextEmbeddingModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the embedding model for embeddings generations.\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::vertexai-embeddings-text.adoc::Sample Controller::0'),
('a85ec0a3-26df-47c1-afca-26cc553d4e95','Thinking mode works with streaming responses as well:\n\nFlux&lt;ChatResponse&gt; stream = chatModel.stream(\n    new Prompt(\n        \"Explain quantum entanglement\",\n        OllamaChatOptions.builder()\n            .model(\"qwen3\")\n            .enableThinking()\n            .build()\n    ));\n\nstream.subscribe(response -&gt; {\n    String thinking = response.getResult().getMetadata().get(\"thinking\");\n    String content = response.getResult().getOutput().getContent();\n\n    if (thinking != null &amp;&amp; !thinking.isEmpty()) {\n        System.out.println(\"[Thinking] \" + thinking);\n    }\n    if (content != null &amp;&amp; !content.isEmpty()) {\n        System.out.println(\"[Response] \" + content);\n    }\n});\n\nWhen thinking is disabled or not set, the <code>thinking</code> metadata field will be null or empty.',0x00,'asciidoc::ollama-chat.adoc::Thinking Mode (Reasoning)::Streaming with Thinking::0'),
('c812b58a-30bc-42b6-9dda-26ef18250a16','You can access the similarity score for each document through the <code>getScore()</code> method:\n\nList&lt;Document&gt; results = vectorStore.similaritySearch(\n    SearchRequest.builder()\n        .query(\"Spring AI\")\n        .topK(5)\n        .build());\n\nfor (Document doc : results) {\n    double score = doc.getScore();  // Value between 0.0 and 1.0\n    System.out.println(\"Document: \" + doc.getText());\n    System.out.println(\"Similarity Score: \" + score);\n}',0x00,'asciidoc::mariadb.adoc::Similarity Scores::Accessing Scores::0'),
('073d2b34-9474-4375-a9d2-273970277f53','Head on over to <a href=\"https://start.spring.io/\">start.spring.io</a> and select the AI Models and Vector Stores that you want to use in your new applications.',0x00,'asciidoc::getting-started.adoc::Spring Initializr::0'),
('890e76e3-3b1c-4077-850a-2764e1d97c18','For keyless authentication using Microsoft Entra ID (formerly Azure Active Directory), set <em>only</em> the <code>spring.ai.azure.openai.endpoint</code> configuration property and <em>not</em> the api-key property mentioned above.\n\nFinding only the endpoint property, your application will evaluate several different options for retrieving credentials and an <code>OpenAIClient</code> instance will be created using the token credentials.\n\nIt is no longer necessary to create a <code>TokenCredential</code> bean; it is configured for you automatically.',0x00,'asciidoc::azure-openai-chat.adoc::Prerequisites::Microsoft Entra ID::0'),
('9e09c634-1765-401e-97ea-27949d9fa991','Internally the various <code>EmbeddingModel</code> implementations use different low-level libraries and APIs to perform the embedding tasks. The following are some of the available implementations of the <code>EmbeddingModel</code> implementations:\n\n<a href=\"api/embeddings/openai-embeddings.html\">Spring AI OpenAI Embeddings</a>\n<a href=\"api/embeddings/azure-openai-embeddings.html\">Spring AI Azure OpenAI Embeddings</a>\n<a href=\"api/embeddings/ollama-embeddings.html\">Spring AI Ollama Embeddings</a>\n<a href=\"api/embeddings/onnx.html\">Spring AI Transformers (ONNX) Embeddings</a>\n<a href=\"api/embeddings/postgresml-embeddings.html\">Spring AI PostgresML Embeddings</a>\n<a href=\"api/embeddings/bedrock-cohere-embedding.html\">Spring AI Bedrock Cohere Embeddings</a>\n<a href=\"api/embeddings/bedrock-titan-embedding.html\">Spring AI Bedrock Titan Embeddings</a>\n<a href=\"api/embeddings/vertexai-embeddings-text.html\">Spring AI VertexAI Embeddings</a>\n<a href=\"api/embeddings/mistralai-embeddings.html\">Spring AI Mistral AI Embeddings</a>\n<a href=\"api/embeddings/oci-genai-embeddings.html\">Spring AI Oracle Cloud Infrastructure GenAI Embeddings</a>',0x00,'asciidoc::embeddings.adoc::Available Implementations::0'),
('af52dfc7-47b4-413f-a61b-27a0838c6278','public static class FilterExpressionParseException extends RuntimeException {\n\n    public FilterExpressionParseException(String message, Throwable cause) {\n        super(message, cause);\n    }\n}',0x01,'cu::FilterExpressionTextParser.java'),
('094719e4-7987-4cf1-9183-27ef93fdb48d','You can register custom Java Tools with the <code>AnthropicChatModel</code> and have the Anthropic Claude model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.\nRead more about <a href=\"api/tools.html\">Tool Calling</a>.',0x00,'asciidoc::anthropic-chat.adoc::Tool/Function Calling::0'),
('1530f6bf-50d9-4057-884f-283b69909637','The <code>TokenTextSplitter</code> is an implementation of <code>TextSplitter</code> that splits text into chunks based on token count, using the CL100K_BASE encoding.\n\nUsage\n\n@Component\nclass MyTokenTextSplitter {\n\n    public List&lt;Document&gt; splitDocuments(List&lt;Document&gt; documents) {\n        TokenTextSplitter splitter = new TokenTextSplitter();\n        return splitter.apply(documents);\n    }\n\n    public List&lt;Document&gt; splitCustomized(List&lt;Document&gt; documents) {\n        TokenTextSplitter splitter = new TokenTextSplitter(1000, 400, 10, 5000, true);\n        return splitter.apply(documents);\n    }\n}\n\nConstructor Options\n\nThe <code>TokenTextSplitter</code> provides two constructor options:\n\n<code>TokenTextSplitter()</code>: Creates a splitter with default settings.\n<code>TokenTextSplitter(int defaultChunkSize, int minChunkSizeChars, int minChunkLengthToEmbed, int maxNumChunks, boolean keepSeparator)</code>\n\n\nParameters\n\n<code>defaultChunkSize</code>: The target size of each text chunk in tokens (default: 800).\n<code>minChunkSizeChars</code>: The minimum size of each text chunk in characters (default: 350).\n<code>minChunkLengthToEmbed</code>: The minimum length of a chunk to be included (default: 5).\n<code>maxNumChunks</code>: The maximum number of chunks to generate from a text (default: 10000).\n<code>keepSeparator</code>: Whether to keep separators (like newlines) in the chunks (default: true).\n\n\nBehavior\n\nThe <code>TokenTextSplitter</code> processes text content as follows:\n\nIt encodes the input text into tokens using the CL100K_BASE encoding.\nIt splits the encoded text into chunks based on the <code>defaultChunkSize</code>.\nFor each chunk:\nThis process continues until all tokens are processed or <code>maxNumChunks</code> is reached.\nAny remaining text is added as a final chunk if it&#8217;s longer than <code>minChunkLengthToEmbed</code>.\n\n\nExample\n\nDocument doc1 = new Document(\"This is a long piece of text that needs to be split into smaller chunks for processing.\",\n        Map.of(\"source\", \"example.txt\"));\nDocument doc2 = new Document(\"Another document with content that will be split based on token count.\",\n        Map.of(\"source\", \"example2.txt\"));\n\nTokenTextSplitter splitter = new TokenTextSplitter();\nList&lt;Document&gt; splitDocuments = this.splitter.apply(List.of(this.doc1, this.doc2));\n\nfor (Document doc : splitDocuments) {\n    System.out.println(\"Chunk: \" + doc.getContent());\n    System.out.println(\"Metadata: \" + doc.getMetadata());\n}\n\nNotes',0x00,'asciidoc::etl-pipeline.adoc::Transformers::TokenTextSplitter::0'),
('43738785-20e6-4ca0-ac98-287d483336e6','The following class diagram illustrates the ETL interfaces and implementations.',0x00,'asciidoc::etl-pipeline.adoc::ETL Interfaces::ETL Class Diagram::0'),
('8e6d2021-000b-4e4b-bd06-2898a7132731','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>OpenAiChatModel(api, options)</code> constructor or the <code>spring.ai.openai.chat.options.*</code> properties.\n\nAt run-time you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example, to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        OpenAiChatOptions.builder()\n            .model(\"ai/gemma3:4B-F16\")\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::dmr-chat.adoc::Runtime Options::0'),
('035a9949-7638-46be-b452-28b5c7ad638c','A running Milvus instance. The following options are available:\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>MilvusVectorStore</code>.',0x00,'asciidoc::milvus.adoc::Prerequisites::0'),
('95fde9db-69e8-4894-962e-28cbaeead908','By default, the Titan embedding model is disabled.\nTo enable it, set the <code>spring.ai.model.embedding</code> property to <code>bedrock-titan</code> in your application configuration:\n\nspring.ai.model.embedding=bedrock-titan\n\nAlternatively, you can use Spring Expression Language (SpEL) to reference an environment variable:\n\n# In application.yml\nspring:\n  ai:\n    model:\n      embedding: ${AI_MODEL_EMBEDDING}\n\n# In your environment or .env file\nexport AI_MODEL_EMBEDDING=bedrock-titan\n\nYou can also set this property using Java system properties when starting your application:\n\njava -Dspring.ai.model.embedding=bedrock-titan -jar your-application.jar',0x00,'asciidoc::bedrock-titan-embedding.adoc::Auto-configuration::Enable Titan Embedding Support::0'),
('159371d9-6d67-44d6-acc5-28e208e1b552','You can use a custom template renderer by implementing the <code>TemplateRenderer</code> interface and passing it to the <code>PromptTemplate</code> constructor. You can also keep using the default <code>StTemplateRenderer</code>, but with a custom configuration.\n\nBy default, template variables are identified by the <code>{}</code> syntax. If you&#8217;re planning to include JSON in your prompt, you might want to use a different syntax to avoid conflicts with JSON syntax. For example, you can use the <code>&lt;</code> and <code>&gt;</code> delimiters.\n\nPromptTemplate promptTemplate = PromptTemplate.builder()\n    .renderer(StTemplateRenderer.builder().startDelimiterToken(\'&lt;\').endDelimiterToken(\'&gt;\').build())\n    .template(\"\"\"\n            Tell me the names of 5 movies whose soundtrack was composed by &lt;composer&gt;.\n            \"\"\")\n    .build();\n\nString prompt = promptTemplate.render(Map.of(\"composer\", \"John Williams\"));',0x00,'asciidoc::prompt.adoc::Example Usage::Using a custom template renderer::0'),
('7b600479-8f06-489e-828d-293d542c03c9','The configuration prefix for the Chroma Vector Store has been changes from <code>spring.ai.vectorstore.chroma.store</code> to <code>spring.ai.vectorstore.chroma</code> in order to align with the naming conventions of other vector stores.\nThe default value of the <code>initialize-schema</code> property on vector stores capable of initializing a schema is now set to <code>false</code>.\nThis implies that the applications now need to explicitly opt-in for schema initialization on supported vector stores, if the schema is expected to be created at application startup.\nNot all vector stores support this property.\nSee the corresponding vector store documentation for more details.\nThe following are the vector stores that currently don&#8217;t support the <code>initialize-schema</code> property.\nIn Bedrock Jurassic 2, the chat options <code>countPenalty</code>, <code>frequencyPenalty</code>, and <code>presencePenalty</code>\nhave been renamed to <code>countPenaltyOptions</code>, <code>frequencyPenaltyOptions</code>, and <code>presencePenaltyOptions</code>.\nFurthermore, the type of the chat option <code>stopSequences</code> have been changed from <code>String[]</code> to <code>List&lt;String&gt;</code>.\nIn Azure OpenAI, the type of the chat options <code>frequencyPenalty</code> and <code>presencePenalty</code>\nhas been changed from <code>Double</code> to <code>Float</code>, consistently with all the other implementations.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0.M2::0'),
('731ee8e5-985f-4ae8-a3d8-29646a054ef0','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OpenAI Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::nvidia-chat.adoc::Auto-configuration::0'),
('61c6ab2b-2588-48e3-882c-29b9457ab553','After specifying the <code>stream()</code> method on <code>ChatClient</code>, there are a few options for the response type:\n\n<code>Flux&lt;String&gt; content()</code>: Returns a <code>Flux</code> of the string being generated by the AI model.\n<code>Flux&lt;ChatResponse&gt; chatResponse()</code>: Returns a <code>Flux</code> of the <code>ChatResponse</code> object, which contains additional metadata about the response.\n<code>Flux&lt;ChatClientResponse&gt; chatClientResponse()</code>: returns a <code>Flux</code> of the <code>ChatClientResponse</code> object that contains the <code>ChatResponse</code> object and the ChatClient execution context, giving you access to additional data used during the execution of advisors (e.g. the relevant documents retrieved in a RAG flow).',0x00,'asciidoc::chatclient.adoc::stream() return values::0'),
('f62de38e-57e8-43e2-be88-29baf672eae8','@SuppressWarnings(\"CheckReturnValue\")\npublic static class AndExpressionContext extends BooleanExpressionContext {\n\n    public BooleanExpressionContext left;\n\n    public Token operator;\n\n    public BooleanExpressionContext right;\n\n    public List<BooleanExpressionContext> booleanExpression() {\n        return getRuleContexts(BooleanExpressionContext.class);\n    }\n\n    public BooleanExpressionContext booleanExpression(int i) {\n        return getRuleContext(BooleanExpressionContext.class, i);\n    }\n\n    public TerminalNode AND() {\n        return getToken(FiltersParser.AND, 0);\n    }\n\n    public AndExpressionContext(BooleanExpressionContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterAndExpression(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitAndExpression(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitAndExpression(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('839d5ee6-6241-44d8-9081-2a639481d46d','The PGVector Store implementation provides access to the underlying native JDBC client (<code>JdbcTemplate</code>) through the <code>getNativeClient()</code> method:\n\nPgVectorStore vectorStore = context.getBean(PgVectorStore.class);\nOptional&lt;JdbcTemplate&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    JdbcTemplate jdbc = nativeClient.get();\n    // Use the native client for PostgreSQL-specific operations\n}\n\nThe native client gives you access to PostgreSQL-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::pgvector.adoc::Accessing the Native Client::0'),
('f6e98a7c-50dc-4729-bfbb-2aa501ecd132','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::minimax-embeddings.adoc::Prerequisites::Add Repositories and BOM::0'),
('615d8f78-bb3a-4bf8-b3cb-2af16717b9ef','<div class=\"paragraph\">\n<p>In a recent research publication, <a href=\"https://www.anthropic.com/research/building-effective-agents\">Building Effective Agents</a>, Anthropic shared valuable insights about building effective Large Language Model (LLM) agents. What makes this research particularly interesting is its emphasis on simplicity and composability over complex frameworks. Let&#8217;s explore how these principles translate into practical implementations using <a href=\"https://docs.spring.io/spring-ai/reference/index.html\">Spring AI</a>.</p>\n</div>\n<div class=\"imageblock\">\n<div class=\"content\">\n<img src=\"https://raw.githubusercontent.com/spring-io/spring-io-static/refs/heads/main/blog/tzolov/spring-ai-agentic-systems.jpg\" alt=\"Agent Systems\" width=\"350\">\n</div>\n</div>\n<div class=\"paragraph\">\n<p>While the pattern descriptions and diagrams are sourced from Anthropic&#8217;s original publication, we&#8217;ll focus on how to implement these patterns using Spring AI&#8217;s features for model portability and structured output. We recommend reading the original paper first.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://github.com/spring-projects/spring-ai-examples/tree/main/agentic-patterns\">agentic-patterns</a> directory in the spring-ai-examples repository contains all the code for the examples that follow.</p>\n</div>',0x00,'asciidoc::effective-agents.adoc::0'),
('5fb2c4a6-e1ae-4143-a91c-2affcc1744ec','First you need access to PostgreSQL instance with enabled <code>vector</code>, <code>hstore</code> and <code>uuid-ossp</code> extensions.\n\nYou can run a PGvector database as a Spring Boot dev service via <a href=\"api/docker-compose.html\">Docker Compose</a> or <a href=\"api/testcontainers.html\">Testcontainers</a>. In alternative, the <a href=\"#_run_postgres_pgvector_db_locally\">setup local Postgres/PGVector</a> appendix shows how to set up a DB locally with a Docker container.\n\nOn startup with the schema initialization feature explicitly enabled, the <code>PgVectorStore</code> will attempt to install the required database extensions and create the required <code>vector_store</code> table with an index if not existing.\n\nOptionally, you can do this manually like so:\n\nCREATE EXTENSION IF NOT EXISTS vector;\nCREATE EXTENSION IF NOT EXISTS hstore;\nCREATE EXTENSION IF NOT EXISTS \"uuid-ossp\";\n\nCREATE TABLE IF NOT EXISTS vector_store (\n	id uuid DEFAULT uuid_generate_v4() PRIMARY KEY,\n	content text,\n	metadata json,\n	embedding vector(1536) // 1536 is the default embedding dimension\n);\n\nCREATE INDEX ON vector_store USING HNSW (embedding vector_cosine_ops);\n\nreplace the <code>1536</code> with the actual embedding dimension if you are using a different dimension. PGvector supports at most 2000 dimensions for HNSW indexes.\n\nNext, if required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>PgVectorStore</code>.',0x00,'asciidoc::pgvector.adoc::Prerequisites::0'),
('19cc3188-a641-42ff-9923-2b94175d7256','You can leverage the generic, portable <a href=\"https://docs.spring.io/spring-ai/reference/api/vectordbs.html#_metadata_filters\">metadata filters</a> with the Milvus store.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"author\",\"john\", \"jill\"),\n        b.eq(\"article_type\", \"blog\")).build()).build());\n\nThese filter expressions are converted into the equivalent Milvus filters.',0x00,'asciidoc::milvus.adoc::Metadata filtering::0'),
('9b9b60f6-8d92-4531-b7da-2ba73e76f5f5','The Milvus Vector Store implementation provides access to the underlying native Milvus client (<code>MilvusServiceClient</code>) through the <code>getNativeClient()</code> method:\n\nMilvusVectorStore vectorStore = context.getBean(MilvusVectorStore.class);\nOptional&lt;MilvusServiceClient&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    MilvusServiceClient client = nativeClient.get();\n    // Use the native client for Milvus-specific operations\n}\n\nThe native client gives you access to Milvus-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::milvus.adoc::Accessing the Native Client::0'),
('8e013905-8778-45bd-ba6a-2bc4fd24903c','ChatClient.create(chatModel)\n    .prompt(\"What\'s the weather like in Copenhagen?\")\n    .toolNames(\"currentWeather\")\n    .call()\n    .content();\n\nAdding Default Tools to <code>ChatClient</code>\n\nWhen using the dynamic specification approach, you can add default tools to a <code>ChatClient.Builder</code> by passing the tool name to the <code>defaultToolNames()</code> method.\nIf both default and runtime tools are provided, the runtime tools will completely override the default tools.\n\nDefault tools are shared across all the chat requests performed by all the <code>ChatClient</code> instances built from the same <code>ChatClient.Builder</code>. They are useful for tools that are commonly used across different chat requests, but they can also be dangerous if not used carefully, risking to make them available when they shouldn&#8217;t.\n\nChatModel chatModel = ...\nChatClient chatClient = ChatClient.builder(chatModel)\n    .defaultToolNames(\"currentWeather\")\n    .build();\n\nAdding Tools to <code>ChatModel</code>\n\nWhen using the dynamic specification approach, you can pass the tool name to the <code>toolNames()</code> method of the <code>ToolCallingChatOptions</code> you use to call the <code>ChatModel</code>. The tool will only be available for the specific chat request it&#8217;s added to.\n\nChatModel chatModel = ...\nChatOptions chatOptions = ToolCallingChatOptions.builder()\n    .toolNames(\"currentWeather\")\n    .build();\nPrompt prompt = new Prompt(\"What\'s the weather like in Copenhagen?\", chatOptions);\nchatModel.call(prompt);\n\nAdding Default Tools to <code>ChatModel</code>\n\nWhen using the dynamic specification approach, you can add default tools to <code>ChatModel</code> at construction time by passing the tool name to the <code>toolNames()</code> method of the <code>ToolCallingChatOptions</code> instance used to create the <code>ChatModel</code>.\nIf both default and runtime tools are provided, the runtime tools will completely override the default tools.\n\nDefault tools are shared across all the chat requests performed by that <code>ChatModel</code> instance. They are useful for tools that are commonly used across different chat requests, but they can also be dangerous if not used carefully, risking to make them available when they shouldn&#8217;t.\n\nChatModel chatModel = OllamaChatModel.builder()\n    .ollamaApi(OllamaApi.builder().build())\n    .defaultOptions(ToolCallingChatOptions.builder()\n            .toolNames(\"currentWeather\")\n            .build())\n    .build();',0x00,'asciidoc::tools.adoc::Functions as Tools::Dynamic Specification: <code>@Bean</code>::1'),
('f5abd53e-0616-4af8-b995-2bd790335445','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Elasticsearch Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-elasticsearch&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-elasticsearch\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\n<div class=\"paragraph\">\n<p>For spring-boot versions pre 3.3.0 it&#8217;s necessary to explicitly add the elasticsearch-java dependency with version &gt; 8.13.3, otherwise the older version used will be incompatible with the queries performed:</p>\n</div>\n<div class=\"exampleblock\">\n<div class=\"content\">\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;co.elastic.clients&lt;/groupId&gt;\n    &lt;artifactId&gt;elasticsearch-java&lt;/artifactId&gt;\n    &lt;version&gt;8.13.3&lt;/version&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'co.elastic.clients:elasticsearch-java:8.13.3\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n</div>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.',0x00,'asciidoc::elasticsearch.adoc::Auto-configuration::0'),
('e5ad8314-0ea8-4f0f-90cf-2bfea416f415','The <code>ChatClient</code> fluent API allows you to create a prompt in three distinct ways using an overloaded <code>prompt</code> method to initiate the fluent API:\n\n<code>prompt()</code>: This method with no arguments lets you start using the fluent API, allowing you to build up user, system, and other parts of the prompt.\n<code>prompt(Prompt prompt)</code>: This method accepts a <code>Prompt</code> argument, letting you pass in a <code>Prompt</code> instance that you have created using the Prompt&#8217;s non-fluent APIs.\n<code>prompt(String content)</code>: This is a convenience method similar to the previous overload. It takes the user&#8217;s text content.',0x00,'asciidoc::chatclient.adoc::ChatClient Fluent API::0'),
('76cf9c79-4283-4b67-83ee-2c323fecf7d5','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/api/OpenAiFileApi.java\">OpenAiFileApi</a> provides a lightweight Java client for the OpenAI Files API, enabling file management operations such as uploading, listing, retrieving, deleting files, and accessing file contents. <a href=\"https://platform.openai.com/docs/api-reference/files\">OpenAI File API</a>\n\nHere is a simple snippet showing how to use the API programmatically:\n\nOpenAiFileApi openAiFileApi = OpenAiFileApi.builder()\n			.apiKey(new SimpleApiKey(System.getenv(\"OPENAI_API_KEY\")))\n			.build();\n\n// Upload a file\nbyte[] fileBytes = Files.readAllBytes(Paths.get(\"evals.jsonl\"));\nOpenAiFileApi.UploadFileRequest uploadRequest = OpenAiFileApi.UploadFileRequest.builder()\n			.file(fileBytes)\n			.fileName(\"evals-data.jsonl\")\n			.purpose(OpenAiFileApi.Purpose.EVALS)\n			.build();\nResponseEntity&lt;OpenAiFileApi.FileObject&gt; uploadResponse = openAiFileApi.uploadFile(uploadRequest);\n\n// List files\nOpenAiFileApi.ListFileRequest listRequest = OpenAiFileApi.ListFileRequest.builder()\n			.purpose(OpenAiFileApi.Purpose.EVALS)\n			.build();\nResponseEntity&lt;OpenAiFileApi.FileObjectResponse&gt; listResponse = openAiFileApi.listFiles(listRequest);\n\n// Retrieve file information\nResponseEntity&lt;OpenAiFileApi.FileObject&gt; fileInfo = openAiFileApi.retrieveFile(\"file-id\");\n\n// Delete a file\nResponseEntity&lt;OpenAiFileApi.DeleteFileResponse&gt; deleteResponse = openAiFileApi.deleteFile(\"file-id\");\n\n// Retrieve file content\nResponseEntity&lt;String&gt; fileContent = openAiFileApi.retrieveFileContent(\"file-id\");',0x00,'asciidoc::openai-chat.adoc::Low-level OpenAiFileApi Client::0'),
('75dd425f-451c-4510-a8d9-2c5e17702bc8','public static final class Builder {\n\n    private String text;\n\n    private List<Message> history = List.of();\n\n    private Map<String, Object> context = Map.of();\n\n    private Builder() {\n    }\n\n    public Builder text(String text) {\n        this.text = text;\n        return this;\n    }\n\n    public Builder history(List<Message> history) {\n        this.history = history;\n        return this;\n    }\n\n    public Builder history(Message... history) {\n        this.history = List.of(history);\n        return this;\n    }\n\n    public Builder context(Map<String, Object> context) {\n        this.context = context;\n        return this;\n    }\n\n    public Query build() {\n        return new Query(this.text, this.history, this.context);\n    }\n}',0x01,'cu::Query.java'),
('a84488b8-0c91-460e-934a-2c702555365e','<strong>Reference:</strong> Chen, M., et al. (2021). \"Evaluating Large Language Models Trained on Code.\" arXiv:2107.03374. <a href=\"https://arxiv.org/abs/2107.03374\">https://arxiv.org/abs/2107.03374</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.9 Code Prompting::2'),
('b4ea07c8-849e-4cd9-a80b-2c741ae151a5','<div class=\"paragraph\">\n<p>Provides Bedrock Titan Embedding model.\n<a href=\"https://aws.amazon.com/bedrock/titan/\">Amazon Titan</a> foundation models (FMs) provide customers with a breadth of high-performing image, multimodal embeddings, and text model choices, via a fully managed API.\nAmazon Titan models are created by AWS and pretrained on large datasets, making them powerful, general-purpose models built to support a variety of use cases, while also supporting the responsible use of AI.\nUse them as is or privately customize them with your own data.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nBedrock Titan Embedding supports Text and Image embedding.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nBedrock Titan Embedding does NOT support batch embedding.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://aws.amazon.com/bedrock/titan/\">AWS Bedrock Titan Model Page</a> and <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/what-is-bedrock.html\">Amazon Bedrock User Guide</a> contains detailed information on how to use the AWS hosted model.</p>\n</div>',0x00,'asciidoc::bedrock-titan-embedding.adoc::0'),
('2b940a20-3d05-499c-a142-2c7551364ee8','The dependency hierarchy can be summarized as:\n\n<code>spring-ai-commons</code> (foundation)\n<code>spring-ai-model</code> (depends on commons)\n<code>spring-ai-vector-store</code> and <code>spring-ai-client-chat</code> (both depend on model)\n<code>spring-ai-advisors-vector-store</code> and <code>spring-ai-rag</code> (depend on both client-chat and vector-store)\n<code>spring-ai-model-chat-memory-*</code> modules (depend on client-chat)',0x00,'asciidoc::upgrade-notes.adoc::Common Changes Across Versions::Dependency Structure::0'),
('eb295fc8-9fa4-4fa1-87a9-2c82dce3e21c','<strong>Active (<code>*_active_count</code>)</strong> — instantaneous gauge of in-progress operations (concurrency/load).\n<strong>Completed (<code>*_seconds_sum|count|max</code>)</strong> — statistics for operations that have finished:\n<code>_seconds_sum / _seconds_count</code> → average latency\n<code>_seconds_max</code> → high-water mark since last scrape (subject to registry behavior)',0x00,'asciidoc::index.adoc::More Metrics Reference::Understanding Active vs Completed::0'),
('6b29f8f4-866c-4da7-9b71-2ce687768ade','Before submitting a PR, please run the following commands to ensure proper formatting and Javadoc processing\n\n./mvnw spring-javaformat:apply javadoc:javadoc -Pjavadoc\n\nThe <code>-Pjavadoc</code> is a profile that enables Javadoc processing so as to avoid a long build time when developing.',0x00,'asciidoc::contribution-guidelines.adoc::Code Formatting and Javadoc::0'),
('8bccba40-d62c-4432-aed4-2d15e8daec8a','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::azure-openai-chat.adoc::Prerequisites::Add Repositories and BOM::0'),
('0deaa78d-f62a-4dbf-a166-2d6b65a3657e','A simple example taken from the <a href=\"https://github.com/Azure-Samples/spring-ai-azure-workshop/blob/main/2-README-prompt-templating.md\">AI Workshop on PromptTemplates</a> is shown below.\n\nPromptTemplate promptTemplate = new PromptTemplate(\"Tell me a {adjective} joke about {topic}\");\n\nPrompt prompt = promptTemplate.create(Map.of(\"adjective\", adjective, \"topic\", topic));\n\nreturn chatModel.call(prompt).getResult();\n\nAnother example taken from the <a href=\"https://github.com/Azure-Samples/spring-ai-azure-workshop/blob/main/3-README-prompt-roles.md\">AI Workshop on Roles</a> is shown below.\n\nString userText = \"\"\"\n    Tell me about three famous pirates from the Golden Age of Piracy and why they did.\n    Write at least a sentence for each pirate.\n    \"\"\";\n\nMessage userMessage = new UserMessage(userText);\n\nString systemText = \"\"\"\n  You are a helpful AI assistant that helps people find information.\n  Your name is {name}\n  You should reply to the user\'s request with your name and also in the style of a {voice}.\n  \"\"\";\n\nSystemPromptTemplate systemPromptTemplate = new SystemPromptTemplate(systemText);\nMessage systemMessage = systemPromptTemplate.createMessage(Map.of(\"name\", name, \"voice\", voice));\n\nPrompt prompt = new Prompt(List.of(userMessage, systemMessage));\n\nList&lt;Generation&gt; response = chatModel.call(prompt).getResults();\n\nThis shows how you can build up the <code>Prompt</code> instance by using the <code>SystemPromptTemplate</code> to create a <code>Message</code> with the system role passing in placeholder values.\nThe message with the role <code>user</code> is then combined with the message of the role <code>system</code> to form the prompt.\nThe prompt is then passed to the ChatModel to get a generative response.',0x00,'asciidoc::prompt.adoc::Example Usage::0'),
('2c7c50f0-63af-4398-9656-2d72d08afa84','To authenticate with the OpenAI service (not Azure), provide an OpenAI API key. This will automatically set the endpoint to <a href=\"https://api.openai.com/v1\" class=\"bare\">https://api.openai.com/v1</a>.\n\nWhen using this approach, set the <code>spring.ai.azure.openai.chat.options.deployment-name</code> property to the name of the <a href=\"https://platform.openai.com/docs/models\">OpenAI model</a> you wish to use.\n\nIn your application configuration:\n\nspring.ai.azure.openai.openai-api-key=&lt;your-azure-openai-key&gt;\nspring.ai.azure.openai.chat.options.deployment-name=&lt;openai-model-name&gt;\n\nUsing environment variables with SpEL:\n\n# In application.yml\nspring:\n  ai:\n    azure:\n      openai:\n        openai-api-key: ${AZURE_OPENAI_API_KEY}\n        chat:\n          options:\n            deployment-name: ${AZURE_OPENAI_MODEL_NAME}\n\n# In your environment or .env file\nexport AZURE_OPENAI_API_KEY=&lt;your-openai-key&gt;\nexport AZURE_OPENAI_MODEL_NAME=&lt;openai-model-name&gt;',0x00,'asciidoc::azure-openai-chat.adoc::Prerequisites::OpenAI Key::0'),
('f0042458-8f5b-411a-9b70-2d9b43e6b380','<div class=\"paragraph\">\n<p><a href=\"https://www.anthropic.com/\">Anthropic Claude</a> is a family of foundational AI models that can be used in a variety of applications.\nFor developers and businesses, you can leverage the API access and build directly on top of <a href=\"https://www.anthropic.com/api\">Anthropic&#8217;s AI infrastructure</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>Spring AI supports the Anthropic <a href=\"https://docs.anthropic.com/claude/reference/messages_post\">Messaging API</a> for sync and streaming text generations.</p>\n</div>\n<div class=\"admonitionblock tip\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Tip</div>\n</td>\n<td class=\"content\">\nAnthropic&#8217;s Claude models are also available through Amazon Bedrock Converse.\nSpring AI provides dedicated <a href=\"api/chat/bedrock-converse.html\">Amazon Bedrock Converse Anthropic</a> client implementations as well.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::anthropic-chat.adoc::0'),
('ddc58ec5-e088-4596-995e-2e4838e9505c','To connect to Typesense and use the <code>TypesenseVectorStore</code> you need to provide access details for your instance.\nA simple configuration can be provided via Spring Boot&#8217;s <code>application.yml</code>:\n\nspring:\n  ai:\n    vectorstore:\n      typesense:\n        initialize-schema: true\n        collection-name: vector_store\n        embedding-dimension: 1536\n        client:\n          protocol: http\n          host: localhost\n          port: 8108\n          api-key: xyz\n\nProperties starting with <code>spring.ai.vectorstore.typesense.*</code> are used to configure the <code>TypesenseVectorStore</code>:',0x00,'asciidoc::typesense.adoc::Auto-configuration::Configuration Properties::0'),
('d7883716-2faa-484c-897e-2ee0de06d618','Text-to-Speech (TTS) API Migration\n\nThe OpenAI Text-to-Speech implementation has been migrated from provider-specific classes to shared interfaces. This enables writing portable code that works across multiple TTS providers (OpenAI, ElevenLabs, and future providers).\n\nRemoved Classes\n\nThe following deprecated classes have been removed from the <code>org.springframework.ai.openai.audio.speech</code> package:\n\n<code>SpeechModel</code> → Use <code>TextToSpeechModel</code> (from <code>org.springframework.ai.audio.tts</code>)\n<code>StreamingSpeechModel</code> → Use <code>StreamingTextToSpeechModel</code> (from <code>org.springframework.ai.audio.tts</code>)\n<code>SpeechPrompt</code> → Use <code>TextToSpeechPrompt</code> (from <code>org.springframework.ai.audio.tts</code>)\n<code>SpeechResponse</code> → Use <code>TextToSpeechResponse</code> (from <code>org.springframework.ai.audio.tts</code>)\n<code>SpeechMessage</code> → Use <code>TextToSpeechMessage</code> (from <code>org.springframework.ai.audio.tts</code>)\n<code>Speech</code> (in <code>org.springframework.ai.openai.audio.speech</code>) → Use <code>Speech</code> (from <code>org.springframework.ai.audio.tts</code>)\n\n\nAdditionally, the <code>speed</code> parameter type changed from <code>Float</code> to <code>Double</code> across all OpenAI TTS components for consistency with other TTS providers.\n\nMigration Steps\n\n<strong>Update Imports</strong>: Replace all imports from <code>org.springframework.ai.openai.audio.speech.<strong></code> with <code>org.springframework.ai.audio.tts.</strong></code>\n<strong>Update Type References</strong>: Replace all occurrences of the old class names with the new ones:\n<strong>Update Speed Parameter</strong>: Change from <code>Float</code> to <code>Double</code>:\n<strong>Update Dependency Injection</strong>: If you inject <code>SpeechModel</code>, update to <code>TextToSpeechModel</code>:\n\n\nBenefits\n\n<strong>Portability</strong>: Write code once, switch between OpenAI, ElevenLabs, or other TTS providers easily\n<strong>Consistency</strong>: Same patterns as ChatModel and other Spring AI abstractions\n<strong>Type Safety</strong>: Improved type hierarchy with proper interface implementations\n<strong>Future-Proof</strong>: New TTS providers will automatically work with your existing code\n\n\nAdditional Resources\n\nFor a comprehensive migration guide with detailed code examples, see:\n\n<a href=\"api/audio/speech/openai-speech.html#_migration_guide\">OpenAI TTS Migration Guide</a>\n<a href=\"api/audio/speech.html#_writing_provider_agnostic_code\">Writing Provider-Agnostic TTS Code</a>',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.1.0-RC1::Breaking Changes::0'),
('b667a228-6d60-4c64-b40f-2eedbc6ec89e','This will create a <code>EmbeddingModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the <code>EmbeddingModel</code> implementation.\n\nspring.ai.oci.genai.embedding.model=&lt;your model&gt;\nspring.ai.oci.genai.embedding.compartment=&lt;your model compartment&gt;\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::oci-genai-embeddings.adoc::Sample Code::0'),
('00407bc4-db42-490f-a978-2ef6343bc3be','To connect to Weaviate and use the <code>WeaviateVectorStore</code>, you need to provide access details for your instance.\nConfiguration can be provided via Spring Boot&#8217;s <em>application.properties</em>:\n\nspring.ai.vectorstore.weaviate.host=&lt;host_of_your_weaviate_instance&gt;\nspring.ai.vectorstore.weaviate.scheme=&lt;http_or_https&gt;\nspring.ai.vectorstore.weaviate.api-key=&lt;your_api_key&gt;\n# API key if needed, e.g. OpenAI\nspring.ai.openai.api-key=&lt;api-key&gt;\n\nIf you prefer to use environment variables for sensitive information like API keys, you have multiple options:',0x00,'asciidoc::weaviate.adoc::Configuration::0'),
('31be4968-27d3-4148-9445-2f09ecf6cf97','Spring AI provides Spring Boot auto-configuration for the Weaviate Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-weaviate&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-weaviate\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nPlease have a look at the list of <a href=\"#_weaviatevectorstore_properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean.\nRefer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nHere is an example of the required bean:\n\n@Bean\npublic EmbeddingModel embeddingModel() {\n    // Retrieve API key from a secure source or environment variable\n    String apiKey = System.getenv(\"OPENAI_API_KEY\");\n\n    // Can be any other EmbeddingModel implementation\n    return new OpenAiEmbeddingModel(OpenAiApi.builder().apiKey(apiKey).build());\n}\n\nNow you can auto-wire the <code>WeaviateVectorStore</code> as a vector store in your application.',0x00,'asciidoc::weaviate.adoc::Auto-configuration::0'),
('433f5886-7b5f-4f07-9c13-2f72f06b82d1','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-zhipuai/src/main/java/org/springframework/ai/zhipuai/ZhiPuAiEmbeddingOptions.java\">ZhiPuAiEmbeddingOptions.java</a> provides the ZhiPuAI configurations, such as the model to use and etc.\n\nThe default options can be configured using the <code>spring.ai.zhipuai.embedding.options</code> properties as well.\n\nAt start-time use the <code>ZhiPuAiEmbeddingModel</code> constructor to set the  default options used for all embedding requests.\nAt run-time you can override the default options, using a <code>ZhiPuAiEmbeddingOptions</code> instance as part of your <code>EmbeddingRequest</code>.\n\nFor example to override the default model name for a specific request:\n\nEmbeddingResponse embeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n        ZhiPuAiEmbeddingOptions.builder()\n            .model(\"Different-Embedding-Model-Deployment-Name\")\n        .build()));',0x00,'asciidoc::zhipuai-embeddings.adoc::Runtime Options::0'),
('bbd95676-945d-477b-8e94-2f84997beee8','<div class=\"paragraph\">\n<p>Spring AI supports the ZhiPuAI&#8217;s text embeddings models.\nZhiPuAI’s text embeddings measure the relatedness of text strings.\nAn embedding is a vector (list) of floating point numbers. The distance between two vectors measures their relatedness. Small distances suggest high relatedness and large distances suggest low relatedness.</p>\n</div>',0x00,'asciidoc::zhipuai-embeddings.adoc::0'),
('e1ecd2b7-e9f8-4456-90d3-3016f55f4f03','For Chroma Cloud, you need to provide the tenant and database names from your Chroma Cloud instance. Here&#8217;s an example configuration:\n\n# Chroma Cloud connection\nspring.ai.vectorstore.chroma.client.host=api.trychroma.com\nspring.ai.vectorstore.chroma.client.port=443\nspring.ai.vectorstore.chroma.client.key-token=&lt;your-chroma-cloud-api-key&gt;\n\n# Chroma Cloud tenant and database (required)\nspring.ai.vectorstore.chroma.tenant-name=&lt;your-tenant-id&gt;\nspring.ai.vectorstore.chroma.database-name=&lt;your-database-name&gt;\n\n# Collection configuration\nspring.ai.vectorstore.chroma.collection-name=my-collection\nspring.ai.vectorstore.chroma.initialize-schema=true\n\n<div class=\"paragraph\">\n<p>For Chroma Cloud:\n- The host should be <code>api.trychroma.com</code>\n- The port should be <code>443</code> (HTTPS)\n- You must provide your API key via <code>key-token</code>\n- The tenant and database names must match your Chroma Cloud configuration\n- Set <code>initialize-schema=true</code> to automatically create the collection if it doesn&#8217;t exist (it won&#8217;t recreate existing tenant/database)</p>\n</div>',0x00,'asciidoc::chroma.adoc::Auto-configuration::Chroma Cloud Configuration::0'),
('aa50cc58-4b82-4b12-8d26-301ca1178cb6','The output of AI models traditionally arrives as a <code>java.lang.String</code>, even if you ask for the reply to be in JSON.\nIt may be a correct JSON, but it is not a JSON data structure. It is just a string.\nAlso, asking &#8220;for JSON&#8221; as part of the prompt is not 100% accurate.\n\nThis intricacy has led to the emergence of a specialized field involving the creation of prompts to yield the intended output, followed by converting the resulting simple string into a usable data structure for application integration.\n\nThe <a href=\"api/structured-output-converter.html#_structuredoutputconverter\">Structured output conversion</a> employs meticulously crafted prompts, often necessitating multiple interactions with the model to achieve the desired formatting.',0x00,'asciidoc::concepts.adoc::Structured Output::0'),
('e9a2c003-b33a-450e-9139-305c93eb36e0','Some vector stores require their backend schema to be initialized before usage.\nIt will not be initialized for you by default.\nYou must opt-in, by passing a <code>boolean</code> for the appropriate constructor argument or, if using Spring Boot, setting the appropriate <code>initialize-schema</code> property to <code>true</code> in <code>application.properties</code> or <code>application.yml</code>.\nCheck the documentation for the vector store you are using for the specific property name.',0x00,'asciidoc::vectordbs.adoc::Schema Initialization::0'),
('43ab228f-ea35-449e-8e43-306efb032fb3','/**\n * Augments the user query with contextual data from the content of the provided\n * documents.\n *\n * <p>\n * Example usage: <pre>{@code\n * QueryAugmenter augmenter = ContextualQueryAugmenter.builder()\n *    .allowEmptyContext(false)\n *    .build();\n * Query augmentedQuery = augmenter.augment(query, documents);\n * }</pre>\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic final class ContextualQueryAugmenter implements QueryAugmenter {\n\n    private static final Logger logger = LoggerFactory.getLogger(ContextualQueryAugmenter.class);\n\n    private static final PromptTemplate DEFAULT_PROMPT_TEMPLATE = new PromptTemplate(\"\"\"\n        Context information is below.\n        \n        ---------------------\n        {context}\n        ---------------------\n        \n        Given the context information and no prior knowledge, answer the query.\n        \n        Follow these rules:\n        \n        1. If the answer is not in the context, just say that you don\'t know.\n        2. Avoid statements like \"Based on the context...\" or \"The provided information...\".\n        \n        Query: {query}\n        \n        Answer:\n        \"\"\");\n\n    private static final PromptTemplate DEFAULT_EMPTY_CONTEXT_PROMPT_TEMPLATE = new PromptTemplate(\"\"\"\n        The user query is outside your knowledge base.\n        Politely inform the user that you can\'t answer it.\n        \"\"\");\n\n    private static final boolean DEFAULT_ALLOW_EMPTY_CONTEXT = false;\n\n    /**\n     * Default document formatter that just joins document text with newlines\n     */\n    private static final Function<List<Document>, String> DEFAULT_DOCUMENT_FORMATTER = documents -> documents.stream().map(Document::getText).collect(Collectors.joining(System.lineSeparator()));\n\n    private final PromptTemplate promptTemplate;\n\n    private final PromptTemplate emptyContextPromptTemplate;\n\n    private final boolean allowEmptyContext;\n\n    private final Function<List<Document>, String> documentFormatter;\n\n    public ContextualQueryAugmenter(@Nullable PromptTemplate promptTemplate, @Nullable PromptTemplate emptyContextPromptTemplate, @Nullable Boolean allowEmptyContext, @Nullable Function<List<Document>, String> documentFormatter) {\n        this.promptTemplate = promptTemplate != null ? promptTemplate : DEFAULT_PROMPT_TEMPLATE;\n        this.emptyContextPromptTemplate = emptyContextPromptTemplate != null ? emptyContextPromptTemplate : DEFAULT_EMPTY_CONTEXT_PROMPT_TEMPLATE;\n        this.allowEmptyContext = allowEmptyContext != null ? allowEmptyContext : DEFAULT_ALLOW_EMPTY_CONTEXT;\n        this.documentFormatter = documentFormatter != null ? documentFormatter : DEFAULT_DOCUMENT_FORMATTER;\n        PromptAssert.templateHasRequiredPlaceholders(this.promptTemplate, \"query\", \"context\");\n    }\n\n    @Override\n    public Query augment(Query query, List<Document> documents) {\n        Assert.notNull(query, \"query cannot be null\");\n        Assert.notNull(documents, \"documents cannot be null\");\n        logger.debug(\"Augmenting query with contextual data\");\n        if (documents.isEmpty()) {\n            return augmentQueryWhenEmptyContext(query);\n        }\n        // 1. Collect content from documents.\n        String documentContext = this.documentFormatter.apply(documents);\n        // 2. Define prompt parameters.\n        Map<String, Object> promptParameters = Map.of(\"query\", query.text(), \"context\", documentContext);\n        // 3. Augment user prompt with document context.\n        return new Query(this.promptTemplate.render(promptParameters));\n    }\n\n    private Query augmentQueryWhenEmptyContext(Query query) {\n        if (this.allowEmptyContext) {\n            logger.debug(\"Empty context is allowed. Returning the original query.\");\n            return query;\n        }\n        logger.debug(\"Empty context is not allowed. Returning a specific query for empty context.\");\n        return new Query(this.emptyContextPromptTemplate.render());\n    }\n\n    public static Builder builder() {\n        return new Builder();\n    }\n\n    public static final class Builder {\n\n        private PromptTemplate promptTemplate;\n\n        private PromptTemplate emptyContextPromptTemplate;\n\n        private Boolean allowEmptyContext;\n\n        private Function<List<Document>, String> documentFormatter;\n\n        public Builder promptTemplate(PromptTemplate promptTemplate) {\n            this.promptTemplate = promptTemplate;\n            return this;\n        }\n\n        public Builder emptyContextPromptTemplate(PromptTemplate emptyContextPromptTemplate) {\n            this.emptyContextPromptTemplate = emptyContextPromptTemplate;\n            return this;\n        }\n\n        public Builder allowEmptyContext(Boolean allowEmptyContext) {\n            this.allowEmptyContext = allowEmptyContext;\n            return this;\n        }\n\n        public Builder documentFormatter(Function<List<Document>, String> documentFormatter) {\n            this.documentFormatter = documentFormatter;\n            return this;\n        }\n\n        public ContextualQueryAugmenter build() {\n            return new ContextualQueryAugmenter(this.promptTemplate, this.emptyContextPromptTemplate, this.allowEmptyContext, this.documentFormatter);\n        }\n    }\n}',0x01,'cu::ContextualQueryAugmenter.java'),
('5cae390b-9246-4c61-8fd0-30b3cf1006f3','Spring AI 1.0.0-M7 now uses MCP Java SDK version 0.9.0, which includes significant changes from previous versions. If you&#8217;re using MCP in your applications, you&#8217;ll need to update your code to accommodate these changes.\n\nKey changes include:\n\nInterface Renaming\n\n<code>ClientMcpTransport</code> → <code>McpClientTransport</code>\n<code>ServerMcpTransport</code> → <code>McpServerTransport</code>\n<code>DefaultMcpSession</code> → <code>McpClientSession</code> or <code>McpServerSession</code>\nAll <code>*Registration</code> classes → <code>*Specification</code> classes\n\n\nServer Creation Changes\n\nUse <code>McpServerTransportProvider</code> instead of <code>ServerMcpTransport</code>\n\n\n// Before\nServerMcpTransport transport = new WebFluxSseServerTransport(objectMapper, \"/mcp/message\");\nvar server = McpServer.sync(transport)\n    .serverInfo(\"my-server\", \"1.0.0\")\n    .build();\n\n// After\nMcpServerTransportProvider transportProvider = new WebFluxSseServerTransportProvider(objectMapper, \"/mcp/message\");\nvar server = McpServer.sync(transportProvider)\n    .serverInfo(\"my-server\", \"1.0.0\")\n    .build();\n\nHandler Signature Changes\n\nAll handlers now receive an <code>exchange</code> parameter as their first argument:\n\n// Before\n.tool(calculatorTool, args -&gt; new CallToolResult(\"Result: \" + calculate(args)))\n\n// After\n.tool(calculatorTool, (exchange, args) -&gt; new CallToolResult(\"Result: \" + calculate(args)))\n\nClient Interaction via Exchange\n\nMethods previously available on the server are now accessed through the exchange object:\n\n// Before\nClientCapabilities capabilities = server.getClientCapabilities();\nCreateMessageResult result = server.createMessage(new CreateMessageRequest(...));\n\n// After\nClientCapabilities capabilities = exchange.getClientCapabilities();\nCreateMessageResult result = exchange.createMessage(new CreateMessageRequest(...));\n\nRoots Change Handlers\n\n// Before\n.rootsChangeConsumers(List.of(\n    roots -&gt; System.out.println(\"Roots changed: \" + roots)\n))\n\n// After\n.rootsChangeHandlers(List.of(\n    (exchange, roots) -&gt; System.out.println(\"Roots changed: \" + roots)\n))\n\nFor a complete guide to migrating MCP code, refer to the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-docs/src/main/antora/modules/ROOT/pages/mcp-migration.adoc\">MCP Migration Guide</a>.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M7::MCP Java SDK Upgrade to 0.9.0::0'),
('e8c3aab3-c576-495e-be70-30bf84314cf6','Few-shot prompting provides the model with one or more examples to help guide its responses, particularly useful for tasks requiring specific output formats. By showing the model examples of desired input-output pairs, it can learn the pattern and apply it to new inputs without explicit parameter updates.\n\nOne-shot provides a single example, which is useful when examples are costly or when the pattern is relatively simple. Few-shot uses multiple examples (typically 3-5) to help the model better understand patterns in more complex tasks or to illustrate different variations of correct outputs.\n\n// Implementation of Section 2.2: One-shot &amp; few-shot (page 16)\npublic void pt_one_shot_few_shots(ChatClient chatClient) {\n    String pizzaOrder = chatClient.prompt(\"\"\"\n            Parse a customer\'s pizza order into valid JSON\n\n            EXAMPLE 1:\n            I want a small pizza with cheese, tomato sauce, and pepperoni.\n            JSON Response:\n            ```\n            {\n                \"size\": \"small\",\n                \"type\": \"normal\",\n                \"ingredients\": [\"cheese\", \"tomato sauce\", \"pepperoni\"]\n            }\n            ```\n\n            EXAMPLE 2:\n            Can I get a large pizza with tomato sauce, basil and mozzarella.\n            JSON Response:\n            ```\n            {\n                \"size\": \"large\",\n                \"type\": \"normal\",\n                \"ingredients\": [\"tomato sauce\", \"basil\", \"mozzarella\"]\n            }\n            ```\n\n            Now, I would like a large pizza, with the first half cheese and mozzarella.\n            And the other tomato sauce, ham and pineapple.\n            \"\"\")\n            .options(ChatOptions.builder()\n                    .model(\"claude-3-7-sonnet-latest\")\n                    .temperature(0.1)\n                    .maxTokens(250)\n                    .build())\n            .call()\n            .content();\n}\n\nFew-shot prompting is especially effective for tasks requiring specific formatting, handling edge cases, or when the task definition might be ambiguous without examples. The quality and diversity of the examples significantly impact performance.\n\n<strong>Reference:</strong> Brown, T. B., et al. (2020). \"Language Models are Few-Shot Learners.\" arXiv:2005.14165. <a href=\"https://arxiv.org/abs/2005.14165\">https://arxiv.org/abs/2005.14165</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.2 One-Shot &amp; Few-Shot Prompting::0'),
('56727bf7-9f04-44c7-8ec1-30dd8732f21b','The structure of the <code>ChatResponse</code> class is as follows:\n\npublic class ChatResponse implements ModelResponse&lt;Generation&gt; {\n\n    private final ChatResponseMetadata chatResponseMetadata;\n	private final List&lt;Generation&gt; generations;\n\n	@Override\n	public ChatResponseMetadata getMetadata() {...}\n\n    @Override\n	public List&lt;Generation&gt; getResults() {...}\n\n    // other methods omitted\n}\n\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/model/ChatResponse.java\">ChatResponse</a> class holds the AI Model&#8217;s output, with each <code>Generation</code> instance containing one of potentially multiple outputs resulting from a single prompt.\n\nThe <code>ChatResponse</code> class also carries a <code>ChatResponseMetadata</code> metadata about the AI Model&#8217;s response.',0x00,'asciidoc::chatmodel.adoc::API Overview::ChatResponse::0'),
('ce32aed2-dd51-4222-b00d-3108fd80f6a9','Retry Properties\n\nThe prefix <code>spring.ai.retry</code> is used as the property prefix that lets you configure the retry mechanism for the OpenAI Embedding model.\n\n\n\nConnection Properties\n\nThe prefix <code>spring.ai.openai</code> is used as the property prefix that lets you connect to OpenAI.\n\n\n\nFor users that belong to multiple organizations (or are accessing their projects through their legacy user API key), optionally, you can specify which organization and project is used for an API request.\nUsage from these API requests will count as usage for the specified organization and project.\n\nConfiguration Properties\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=openai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match openai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.openai.embedding</code> is property prefix that configures the <code>EmbeddingModel</code> implementation for OpenAI.\n\n\n\nYou can override the common <code>spring.ai.openai.base-url</code> and <code>spring.ai.openai.api-key</code> for the <code>ChatModel</code> and <code>EmbeddingModel</code> implementations.\nThe <code>spring.ai.openai.embedding.base-url</code> and <code>spring.ai.openai.embedding.api-key</code> properties if set take precedence over the common properties.\nSimilarly, the <code>spring.ai.openai.chat.base-url</code> and <code>spring.ai.openai.chat.api-key</code> properties if set take precedence over the common properties.\nThis is useful if you want to use different OpenAI accounts for different models and different model endpoints.\n\nAll properties prefixed with <code>spring.ai.openai.embedding.options</code> can be overridden at runtime by adding a request specific <a href=\"#embedding-options\">Runtime Options</a> to the <code>EmbeddingRequest</code> call.',0x00,'asciidoc::openai-embeddings.adoc::Auto-configuration::Embedding Properties::0'),
('458d1548-2f27-41ec-bed7-318881541ac2','@Autowired VectorStore vectorStore;\n\n// ...\n\nList &lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to Milvus Vector Store\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::milvus.adoc::Dependencies::1'),
('f17d8383-4f4c-42cf-a6a5-325157f8c57e','/**\n * SearchRequest Builder.\n */\npublic static final class Builder {\n\n    private final SearchRequest searchRequest = new SearchRequest();\n\n    /**\n     * @param query Text to use for embedding similarity comparison.\n     * @return this builder.\n     */\n    public Builder query(String query) {\n        Assert.notNull(query, \"Query can not be null.\");\n        this.searchRequest.query = query;\n        return this;\n    }\n\n    /**\n     * @param topK the top \'k\' similar results to return.\n     * @return this builder.\n     */\n    public Builder topK(int topK) {\n        Assert.isTrue(topK >= 0, \"TopK should be positive.\");\n        this.searchRequest.topK = topK;\n        return this;\n    }\n\n    /**\n     * Similarity threshold score to filter the search response by. Only documents\n     * with similarity score equal or greater than the \'threshold\' will be returned.\n     * Note that this is a post-processing step performed on the client not the server\n     * side. A threshold value of 0.0 means any similarity is accepted or disable the\n     * similarity threshold filtering. A threshold value of 1.0 means an exact match\n     * is required.\n     * @param threshold The lower bound of the similarity score.\n     * @return this builder.\n     */\n    public Builder similarityThreshold(double threshold) {\n        Assert.isTrue(threshold >= 0 && threshold <= 1, \"Similarity threshold must be in [0,1] range.\");\n        this.searchRequest.similarityThreshold = threshold;\n        return this;\n    }\n\n    /**\n     * Sets disables the similarity threshold by setting it to 0.0 - all results are\n     * accepted.\n     * @return this builder.\n     */\n    public Builder similarityThresholdAll() {\n        this.searchRequest.similarityThreshold = 0.0;\n        return this;\n    }\n\n    /**\n     * Retrieves documents by query embedding similarity and matching the filters.\n     * Value of \'null\' means that no metadata filters will be applied to the search.\n     *\n     * For example if the {@link Document#getMetadata()} schema is:\n     *\n     * <pre>{@code\n     * &#123;\n     * \"country\": <Text>,\n     * \"city\": <Text>,\n     * \"year\": <Number>,\n     * \"price\": <Decimal>,\n     * \"isActive\": <Boolean>\n     * &#125;\n     * }</pre>\n     *\n     * you can constrain the search result to only UK countries with isActive=true and\n     * year equal or greater 2020. You can build this such metadata filter\n     * programmatically like this:\n     *\n     * <pre>{@code\n     * var exp = new Filter.Expression(AND,\n     * 		new Expression(EQ, new Key(\"country\"), new Value(\"UK\")),\n     * 		new Expression(AND,\n     * 				new Expression(GTE, new Key(\"year\"), new Value(2020)),\n     * 				new Expression(EQ, new Key(\"isActive\"), new Value(true))));\n     * }</pre>\n     *\n     * The {@link Filter.Expression} is portable across all vector stores.<br/>\n     *\n     * The {@link FilterExpressionBuilder} is a DSL creating expressions\n     * programmatically:\n     *\n     * <pre>{@code\n     * var b = new FilterExpressionBuilder();\n     * var exp = b.and(\n     * 		b.eq(\"country\", \"UK\"),\n     * 		b.and(\n     * 			b.gte(\"year\", 2020),\n     * 			b.eq(\"isActive\", true)));\n     * }</pre>\n     *\n     * The {@link FilterExpressionTextParser} converts textual, SQL like filter\n     * expression language into {@link Filter.Expression}:\n     *\n     * <pre>{@code\n     * var parser = new FilterExpressionTextParser();\n     * var exp = parser.parse(\"country == \'UK\' && isActive == true && year >=2020\");\n     * }</pre>\n     * @param expression {@link Filter.Expression} instance used to define the\n     * metadata filter criteria. The \'null\' value stands for no expression filters.\n     * @return this builder.\n     */\n    public Builder filterExpression(@Nullable Filter.Expression expression) {\n        this.searchRequest.filterExpression = expression;\n        return this;\n    }\n\n    /**\n     * Document metadata filter expression. For example if your\n     * {@link Document#getMetadata()} has a schema like:\n     *\n     * <pre>{@code\n     * &#123;\n     * \"country\": <Text>,\n     * \"city\": <Text>,\n     * \"year\": <Number>,\n     * \"price\": <Decimal>,\n     * \"isActive\": <Boolean>\n     * &#125;\n     * }</pre>\n     *\n     * then you can constrain the search result with metadata filter expressions like:\n     *\n     * <pre>{@code\n     * country == \'UK\' && year >= 2020 && isActive == true\n     * Or\n     * country == \'BG\' && (city NOT IN [\'Sofia\', \'Plovdiv\'] || price < 134.34)\n     * }</pre>\n     *\n     * This ensures that the response contains only embeddings that match the\n     * specified filer criteria. <br/>\n     *\n     * The declarative, SQL like, filter syntax is portable across all vector stores\n     * supporting the filter search feature.<br/>\n     *\n     * The {@link FilterExpressionTextParser} is used to convert the text filter\n     * expression into {@link Filter.Expression}.\n     * @param textExpression declarative, portable, SQL like, metadata filter syntax.\n     * The \'null\' value stands for no expression filters.\n     * @return this.builder\n     */\n    public Builder filterExpression(@Nullable String textExpression) {\n        this.searchRequest.filterExpression = (textExpression != null) ? new FilterExpressionTextParser().parse(textExpression) : null;\n        return this;\n    }\n\n    public SearchRequest build() {\n        return this.searchRequest;\n    }\n}',0x01,'cu::SearchRequest.java'),
('85586756-4e7d-497b-aa40-3251b2d2a429','Non-streaming advisors work with complete requests and responses.\nStreaming advisors handle requests and responses as continuous streams, using reactive programming concepts (e.g., Flux for responses).\n\n\n@Override\npublic Flux&lt;ChatClientResponse&gt; adviseStream(ChatClientRequest chatClientRequest, StreamAdvisorChain chain) {\n\n    return  Mono.just(chatClientRequest)\n            .publishOn(Schedulers.boundedElastic())\n            .map(request -&gt; {\n                // This can be executed by blocking and non-blocking Threads.\n                // Advisor before next section\n            })\n            .flatMapMany(request -&gt; chain.nextStream(request))\n            .map(response -&gt; {\n                // Advisor after next section\n            });\n}',0x00,'asciidoc::advisors.adoc::Implementing an Advisor::Streaming vs Non-Streaming::0'),
('b75a2131-b8c7-4693-96f3-32d72bf6f58f','You can use custom environment variable names and reference them in your application configuration:\n\n# In application.yml\nspring:\n  ai:\n    vectorstore:\n      weaviate:\n        host: ${WEAVIATE_HOST}\n        scheme: ${WEAVIATE_SCHEME}\n        api-key: ${WEAVIATE_API_KEY}\n    openai:\n      api-key: ${OPENAI_API_KEY}\n\n# In your environment or .env file\nexport WEAVIATE_HOST=&lt;host_of_your_weaviate_instance&gt;\nexport WEAVIATE_SCHEME=&lt;http_or_https&gt;\nexport WEAVIATE_API_KEY=&lt;your_api_key&gt;\nexport OPENAI_API_KEY=&lt;api-key&gt;',0x00,'asciidoc::weaviate.adoc::Configuration::Option 1: Using Spring Expression Language (SpEL)::0'),
('bcbf0cba-a9a2-4dbd-9d16-33084ba52b74','Retrieval modules are responsible for querying data systems like vector store and retrieving the most relevant documents.\n\nDocument Search\n\nComponent responsible for retrieving <code>Documents</code> from an underlying data source, such as a search engine, a vector store,\na database, or a knowledge graph.\n\nVectorStoreDocumentRetriever\n\nA <code>VectorStoreDocumentRetriever</code> retrieves documents from a vector store that are semantically similar to the input\nquery. It supports filtering based on metadata, similarity threshold, and top-k results.\n\nDocumentRetriever retriever = VectorStoreDocumentRetriever.builder()\n    .vectorStore(vectorStore)\n    .similarityThreshold(0.73)\n    .topK(5)\n    .filterExpression(new FilterExpressionBuilder()\n        .eq(\"genre\", \"fairytale\")\n        .build())\n    .build();\nList&lt;Document&gt; documents = retriever.retrieve(new Query(\"What is the main character of the story?\"));\n\nThe filter expression can be static or dynamic. For dynamic filter expressions, you can pass a <code>Supplier</code>.\n\nDocumentRetriever retriever = VectorStoreDocumentRetriever.builder()\n    .vectorStore(vectorStore)\n    .filterExpression(() -&gt; new FilterExpressionBuilder()\n        .eq(\"tenant\", TenantContextHolder.getTenantIdentifier())\n        .build())\n    .build();\nList&lt;Document&gt; documents = retriever.retrieve(new Query(\"What are the KPIs for the next semester?\"));\n\nYou can also provide a request-specific filter expression via the <code>Query</code> API, using the <code>FILTER_EXPRESSION</code> parameter.\nIf both the request-specific and the retriever-specific filter expressions are provided, the request-specific filter expression takes precedence.\n\nQuery query = Query.builder()\n    .text(\"Who is Anacletus?\")\n    .context(Map.of(VectorStoreDocumentRetriever.FILTER_EXPRESSION, \"location == \'Whispering Woods\'\"))\n    .build();\nList&lt;Document&gt; retrievedDocuments = documentRetriever.retrieve(query);\n\nDocument Join\n\nA component for combining documents retrieved based on multiple queries and from multiple data sources into\na single collection of documents. As part of the joining process, it can also handle duplicate documents and reciprocal\nranking strategies.\n\nConcatenationDocumentJoiner\n\nA <code>ConcatenationDocumentJoiner</code> combines documents retrieved based on multiple queries and from multiple data sources\nby concatenating them into a single collection of documents. In case of duplicate documents, the first occurrence is kept.\nThe score of each document is kept as is.\n\nMap&lt;Query, List&lt;List&lt;Document&gt;&gt;&gt; documentsForQuery = ...\nDocumentJoiner documentJoiner = new ConcatenationDocumentJoiner();\nList&lt;Document&gt; documents = documentJoiner.join(documentsForQuery);',0x00,'asciidoc::retrieval-augmented-generation.adoc::Modules::Retrieval::0'),
('d7bfb0a3-1183-4a2e-a30a-33a162fd4c88','Chat Client and Advisors\n\nThe main changes that impact end user code are:\n\nIn <code>VectorStoreChatMemoryAdvisor</code>:\nThe constant <code>CHAT_MEMORY_CONVERSATION_ID_KEY</code> has been renamed to <code>CONVERSATION_ID</code> and moved from <code>AbstractChatMemoryAdvisor</code> to the <code>ChatMemory</code> interface. Update your imports to use <code>org.springframework.ai.chat.memory.ChatMemory.CONVERSATION_ID</code>.\n\n\nSelf-contained Templates in Advisors\n\nThe built-in advisors that perform prompt augmentation have been updated to use self-contained templates. The goal is for each advisor to be able to perform templating operations without affecting nor being affected by templating and prompt decisions in other advisors.\n\n<strong>If you were providing custom templates for the following advisors, you&#8217;ll need to update them to ensure all expected placeholders are included.</strong>\n\nThe <code>QuestionAnswerAdvisor</code> expects a template with the following placeholders (see <a href=\"api/retrieval-augmented-generation.html#_questionansweradvisor\">more details</a>):\nThe <code>PromptChatMemoryAdvisor</code> expects a template with the following placeholders (see <a href=\"api/chat-memory.html#_promptchatmemoryadvisor\">more details</a>):\nThe <code>VectorStoreChatMemoryAdvisor</code> expects a template with the following placeholders (see <a href=\"api/chat-memory.html#_vectorstorechatmemoryadvisor\">more details</a>):\n\n\nObservability\n\nRefactored content observation to use logging instead of tracing (<a href=\"https://github.com/spring-projects/spring-ai/commit/ca843e85887aa1da6300c77550c379c103500897\">ca843e8</a>)\n\n\nChat Memory Repository Module and Autoconfiguration Renaming\n\nWe&#8217;ve standardized the naming pattern for chat memory components by adding the repository suffix throughout the codebase. This change affects Cassandra, JDBC, and Neo4j implementations, impacting artifact IDs, Java package names, and class names for clarity.\n\nArtifact IDs\n\nAll memory-related artifacts now follow a consistent pattern:\n\n<code>spring-ai-model-chat-memory-<strong></code> → <code>spring-ai-model-chat-memory-repository-</strong></code>\n<code>spring-ai-autoconfigure-model-chat-memory-<strong></code> → <code>spring-ai-autoconfigure-model-chat-memory-repository-</strong></code>\n<code>spring-ai-starter-model-chat-memory-<strong></code> → <code>spring-ai-starter-model-chat-memory-repository-</strong></code>\n\n\nJava Packages\n\nPackage paths now include <code>.repository.</code> segment\nExample: <code>org.springframework.ai.chat.memory.jdbc</code> → <code>org.springframework.ai.chat.memory.repository.jdbc</code>\n\n\nConfiguration Classes\n\nMain autoconfiguration classes now use the <code>Repository</code> suffix\nExample: <code>JdbcChatMemoryAutoConfiguration</code> → <code>JdbcChatMemoryRepositoryAutoConfiguration</code>\n\n\nProperties',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-RC1::Breaking Changes::0'),
('25b4e186-da01-4b49-841c-33a45bcfb84a','Spring AI has enhanced its Model Usage handling by introducing <code>getNativeUsage()</code> method in the Usage interface and providing a <code>DefaultUsage</code> implementation.\nThis change simplifies how different AI models can track and report their usage metrics while maintaining consistency across the framework.',0x00,'asciidoc::usage-handling.adoc::Overview::0'),
('bbeb82e8-239e-4195-8164-33ffaec47ab5','The following configuration properties are available for the Cosmos DB vector store:',0x00,'asciidoc::azure-cosmos-db.adoc::Configuration Properties::0'),
('29582ab5-bc1d-4185-892c-343e4ebbff2c','To configure Pinecone in your application, you can use the following setup:\n\n@Bean\npublic VectorStore pineconeVectorStore(EmbeddingModel embeddingModel) {\n    return PineconeVectorStore.builder(embeddingModel)\n            .apiKey(PINECONE_API_KEY)\n            .indexName(PINECONE_INDEX_NAME)\n            .namespace(PINECONE_NAMESPACE) // the free tier doesn\'t support namespaces.\n            .contentFieldName(CUSTOM_CONTENT_FIELD_NAME) // optional field to store the original content. Defaults to `document_content`\n            .build();\n}\n\nIn your main code, create some documents:\n\nList&lt;Document&gt; documents = List.of(\n	new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n	new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n	new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\nAdd the documents to Pinecone:\n\nvectorStore.add(documents);\n\nAnd finally, retrieve documents similar to a query:\n\nList&lt;Document&gt; results = vectorStore.similaritySearch(SearchRequest.query(\"Spring\").topK(5).build());\n\nIf all goes well, you should retrieve the document containing the text \"Spring AI rocks!!\".',0x00,'asciidoc::pinecone.adoc::Manual Configuration::Sample Code::0'),
('31f9f5d0-fb41-48fe-a637-34497a478ed5','The prompt caching implementation in Spring AI follows these key design principles:\n\n<strong>Strategic Cache Placement</strong>: Cache breakpoints are automatically placed at optimal locations based on the chosen strategy, ensuring compliance with Anthropic&#8217;s 4-breakpoint limit.\n<strong>Provider Portability</strong>: Cache configuration is done through <code>AnthropicChatOptions</code> rather than individual messages, preserving compatibility when switching between different AI providers.\n<strong>Thread Safety</strong>: The cache breakpoint tracking is implemented with thread-safe mechanisms to handle concurrent requests correctly.\n<strong>Automatic Content Ordering</strong>: The implementation ensures proper on-the-wire ordering of JSON content blocks and cache controls according to Anthropic&#8217;s API requirements.\n<strong>Aggregate Eligibility Checking</strong>: For <code>CONVERSATION_HISTORY</code>, the implementation considers all message types (user, assistant, tool) within the last ~20 content blocks when determining if the combined content meets the minimum token threshold for caching.',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Implementation Details::0'),
('3355f21b-4f18-4cae-b6bb-34b20d22c247','<div class=\"paragraph\">\n<p>This section walks you through setting up <code>CosmosDBVectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>',0x00,'asciidoc::azure-cosmos-db.adoc::0'),
('fb8e01a6-c17d-4d27-aa3f-3556b87b33ed','/**\n * Represents a query in the context of a Retrieval Augmented Generation (RAG) flow.\n *\n * @param text the text of the query\n * @param history the messages in the conversation history\n * @param context the context of the query\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic record Query(String text, List<Message> history, Map<String, Object> context) {\n\n    public Query {\n        Assert.hasText(text, \"text cannot be null or empty\");\n        Assert.notNull(history, \"history cannot be null\");\n        Assert.noNullElements(history, \"history elements cannot be null\");\n        Assert.notNull(context, \"context cannot be null\");\n        Assert.noNullElements(context.keySet(), \"context keys cannot be null\");\n    }\n\n    public Query(String text) {\n        this(text, List.of(), Map.of());\n    }\n\n    public Builder mutate() {\n        return new Builder().text(this.text).history(this.history).context(this.context);\n    }\n\n    public static Builder builder() {\n        return new Builder();\n    }\n\n    public static final class Builder {\n\n        private String text;\n\n        private List<Message> history = List.of();\n\n        private Map<String, Object> context = Map.of();\n\n        private Builder() {\n        }\n\n        public Builder text(String text) {\n            this.text = text;\n            return this;\n        }\n\n        public Builder history(List<Message> history) {\n            this.history = history;\n            return this;\n        }\n\n        public Builder history(Message... history) {\n            this.history = List.of(history);\n            return this;\n        }\n\n        public Builder context(Map<String, Object> context) {\n            this.context = context;\n            return this;\n        }\n\n        public Query build() {\n            return new Query(this.text, this.history, this.context);\n        }\n    }\n}',0x01,'cu::Query.java'),
('271d76d0-ff32-4bab-bf73-3588bb975b85','In Spring AI, tools are modeled via the <code>ToolCallback</code> interface. In the previous sections, we&#8217;ve seen how to define tools from methods and functions using the built-in support provided by Spring AI (see <a href=\"#_methods_as_tools\">Methods as Tools</a> and <a href=\"#_functions_as_tools\">Functions as Tools</a>). This section will dive deeper into the tool specification and how to customize and extend it to support more use cases.',0x00,'asciidoc::tools.adoc::Tool Specification::0'),
('4f74c6c4-b5cb-4bdd-b777-359067ea4848','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-google-genai/src/main/java/org/springframework/ai/google/genai/GoogleGenAiChatOptions.java\">GoogleGenAiChatOptions.java</a> provides model configurations, such as the temperature, the topK, etc.\n\nOn start-up, the default options can be configured with the <code>GoogleGenAiChatModel(client, options)</code> constructor or the <code>spring.ai.google.genai.chat.options.*</code> properties.\n\nAt runtime, you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example, to override the default temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        GoogleGenAiChatOptions.builder()\n            .temperature(0.4)\n        .build()\n    ));\n\nIn addition to the model specific <code>GoogleGenAiChatOptions</code> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::google-genai-chat.adoc::Runtime options::0'),
('9a25f2d3-ed0d-42e3-83ca-35ecc4b65912','Instead of using the Spring Boot auto-configuration, you can manually configure the <code>OracleVectorStore</code>.\nFor this you need to add the Oracle JDBC driver and <code>JdbcTemplate</code> auto-configuration dependencies to your project:\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-boot-starter-jdbc&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n	&lt;groupId&gt;com.oracle.database.jdbc&lt;/groupId&gt;\n	&lt;artifactId&gt;ojdbc11&lt;/artifactId&gt;\n	&lt;scope&gt;runtime&lt;/scope&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-oracle-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nTo configure the <code>OracleVectorStore</code> in your application, you can use the following setup:\n\n@Bean\npublic VectorStore vectorStore(JdbcTemplate jdbcTemplate, EmbeddingModel embeddingModel) {\n    return OracleVectorStore.builder(jdbcTemplate, embeddingModel)\n        .tableName(\"my_vectors\")\n        .indexType(OracleVectorStoreIndexType.IVF)\n        .distanceType(OracleVectorStoreDistanceType.COSINE)\n        .dimensions(1536)\n        .searchAccuracy(95)\n        .initializeSchema(true)\n        .build();\n}',0x00,'asciidoc::oracle.adoc::Manual Configuration::0'),
('b405c4f8-a242-4365-bbfa-36194abe823c','You will need to create an API with ZhiPuAI to access ZhiPu AI language models.\n\nCreate an account at <a href=\"https://open.bigmodel.cn/login\">ZhiPu AI registration page</a> (or <a href=\"https://chat.z.ai/auth\">Z.ai registration page</a>) and generate the token on the <a href=\"https://open.bigmodel.cn/usercenter/apikeys\">API Keys page</a> (or <a href=\"https://z.ai/manage-apikey/apikey-list\">Z.ai API Keys page</a>).\n\nThe Spring AI project defines a configuration property named <code>spring.ai.zhipuai.api-key</code> that you should set to the value of the <code>API Key</code> obtained from the API Keys page.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.zhipuai.api-key=&lt;your-zhipuai-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference a custom environment variable:\n\n# In application.yml\nspring:\n  ai:\n    zhipuai:\n      api-key: ${ZHIPUAI_API_KEY}\n\n# In your environment or .env file\nexport ZHIPUAI_API_KEY=&lt;your-zhipuai-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"ZHIPUAI_API_KEY\");',0x00,'asciidoc::zhipuai-chat.adoc::Prerequisites::0'),
('64540391-c42c-4b41-ab71-36262d76d3a9','<div class=\"paragraph\">\n<p>The artifact IDs for Spring AI starter modules have been renamed since version 1.0.0.M7. Dependency names should now follow updated naming patterns for models, vector stores, and MCP starters.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OpenAI Chat Client.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor add the following to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::dmr-chat.adoc::Auto-configuration::0'),
('3d535451-e969-4b81-a38b-36643d07c832','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-minimax/src/main/java/org/springframework/ai/minimax/MiniMaxChatModel.java\">MiniMaxChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"#low-level-api\">Low-level MiniMaxApi Client</a> to connect to the MiniMax service.\n\nAdd the <code>spring-ai-minimax</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-minimax&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-minimax\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>MiniMaxChatModel</code> and use it for text generations:\n\nvar miniMaxApi = new MiniMaxApi(System.getenv(\"MINIMAX_API_KEY\"));\n\nvar chatModel = new MiniMaxChatModel(this.miniMaxApi, MiniMaxChatOptions.builder()\n                .model(MiniMaxApi.ChatModel.ABAB_6_5_S_Chat.getValue())\n                .temperature(0.4)\n                .maxTokens(200)\n                .build());\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; streamResponse = this.chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>MiniMaxChatOptions</code> provides the configuration information for the chat requests.\nThe <code>MiniMaxChatOptions.Builder</code> is fluent options builder.',0x00,'asciidoc::minimax-chat.adoc::Manual Configuration::0'),
('5c43b40a-c87a-4e26-82a0-36665972be49','The <code>Usage</code> interface now includes a new method:\n\nObject getNativeUsage();\n\nThis method allows access to the model-specific native usage data, enabling more detailed usage tracking when needed.',0x00,'asciidoc::usage-handling.adoc::Key Changes::Usage Interface Enhancement::0'),
('899b0860-8f43-4bc9-8f0e-36bbfe69843b','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OCI GenAI Cohere Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-oci-genai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-oci-genai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::cohere-chat.adoc::Auto-configuration::0'),
('64057766-a41c-4fd1-a554-37367da5cf83','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Azure OpenAI Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-azure-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-azure-openai\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThe Azure OpenAI Chat Client is created using the <a href=\"https://github.com/Azure/azure-sdk-for-java/blob/main/sdk/openai/azure-ai-openai/src/main/java/com/azure/ai/openai/OpenAIClientBuilder.java\">OpenAIClientBuilder</a> provided by the Azure SDK. Spring AI allows to customize the builder by providing <a href=\"https://github.com/spring-projects/spring-ai/blob/main/auto-configurations/models/spring-ai-autoconfigure-model-azure-openai/src/main/java/org/springframework/ai/model/azure/openai/autoconfigure/AzureOpenAIClientBuilderCustomizer.java\">AzureOpenAIClientBuilderCustomizer</a> beans.\n\nA customizer might be used for example to change the default response timeout:\n\n@Configuration\npublic class AzureOpenAiConfig {\n\n	@Bean\n	public AzureOpenAIClientBuilderCustomizer responseTimeoutCustomizer() {\n		return openAiClientBuilder -&gt; {\n			HttpClientOptions clientOptions = new HttpClientOptions()\n					.setResponseTimeout(Duration.ofMinutes(5));\n			openAiClientBuilder.httpClient(HttpClient.createDefault(clientOptions));\n		};\n	}\n\n}',0x00,'asciidoc::azure-openai-chat.adoc::Auto-configuration::0'),
('65c5544d-304a-4006-a6f6-374757f855fa','The interface <code>ChatMemory</code> represents a storage for chat conversation memory.\nIt provides methods to add messages to a conversation, retrieve messages from a conversation, and clear the conversation history.\n\nThere is currently one built-in implementation: <code>MessageWindowChatMemory</code>.\n\n<code>MessageWindowChatMemory</code> is a chat memory implementation that maintains a window of messages up to a specified maximum size (default: 20 messages).\nWhen the number of messages exceeds this limit, older messages are evicted, but system messages are preserved.\nIf a new system message is added, all previous system messages are removed from memory.\nThis ensures that the most recent context is always available for the conversation while keeping memory usage bounded.\n\nThe <code>MessageWindowChatMemory</code> is backed by the <code>ChatMemoryRepository</code> abstraction which provides storage implementations for the chat conversation memory.\nThere are several implementations available, including the <code>InMemoryChatMemoryRepository</code>, <code>JdbcChatMemoryRepository</code>, <code>CassandraChatMemoryRepository</code> and <code>Neo4jChatMemoryRepository</code>.\n\nFor more details and usage examples, see the <a href=\"api/chat-memory.html\">Chat Memory</a> documentation.',0x00,'asciidoc::chatclient.adoc::Chat Memory::0'),
('fe22afbc-9fdd-4ff4-81a7-379d99335844','/**\n * @author Jemin Huh\n */\nclass SimpleVectorStoreWithFilterTests {\n\n    @TempDir(cleanup = CleanupMode.ON_SUCCESS)\n    Path tempDir;\n\n    private SimpleVectorStore vectorStore;\n\n    private EmbeddingModel mockEmbeddingModel;\n\n    @BeforeEach\n    void setUp() {\n        this.mockEmbeddingModel = mock(EmbeddingModel.class);\n        when(this.mockEmbeddingModel.dimensions()).thenReturn(3);\n        when(this.mockEmbeddingModel.embed(any(String.class))).thenReturn(new float[] { 0.1f, 0.2f, 0.3f });\n        when(this.mockEmbeddingModel.embed(any(Document.class))).thenReturn(new float[] { 0.1f, 0.2f, 0.3f });\n        this.vectorStore = SimpleVectorStore.builder(this.mockEmbeddingModel).build();\n    }\n\n    @Test\n    void shouldAddAndRetrieveDocumentWithFilter() {\n        Document doc = Document.builder().id(\"1\").text(\"test content\").metadata(Map.of(\"country\", \"BG\", \"year\", 2020, \"activationDate\", \"1970-01-01T00:00:02Z\")).build();\n        this.vectorStore.add(List.of(doc));\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(\"country == \'BG\'\").build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"test content\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(\"country == \'KR\'\").build());\n        assertThat(results).hasSize(0);\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(\"country == \'BG\' && year == 2020\").build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"test content\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(\"country == \'BG\' && year == 2024\").build());\n        assertThat(results).hasSize(0);\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(\"country in [\'BG\', \'NL\']\").build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"test content\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(\"country in [\'KR\', \'NL\']\").build());\n        assertThat(results).hasSize(0);\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(2000)))).build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"test content\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(3000)))).build());\n        assertThat(results).hasSize(0);\n    }\n\n    @Test\n    void shouldAddMultipleDocumentsWithFilter() {\n        List<Document> docs = Arrays.asList(Document.builder().id(\"1\").text(\"first\").metadata(Map.of(\"country\", \"BG\", \"year\", 2020, \"activationDate\", \"1970-01-01T00:00:02Z\")).build(), Document.builder().id(\"2\").text(\"second\").metadata(Map.of(\"country\", \"KR\", \"year\", 2022, \"activationDate\", \"1970-01-01T00:00:03Z\")).build());\n        this.vectorStore.add(docs);\n        List<Document> results = this.vectorStore.similaritySearch(\"first\");\n        assertThat(results).hasSize(2).extracting(Document::getId).containsExactlyInAnyOrder(\"1\", \"2\");\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(\"country == \'BG\'\").build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"first\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(\"country == \'NL\'\").build());\n        assertThat(results).hasSize(0);\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(\"country == \'BG\' && year == 2020\").build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"first\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(\"country == \'KR\' && year == 2022\").build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"2\");\n            assertThat(result.getText()).isEqualTo(\"second\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(\"country == \'KR\' && year == 2024\").build());\n        assertThat(results).hasSize(0);\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(\"country in [\'BG\', \'NL\']\").build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"first\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(\"country in [\'KR\', \'NL\']\").build());\n        assertThat(results).hasSize(1);\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(2000)))).build());\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"first\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"first\").filterExpression(new Filter.Expression(AND, new Filter.Expression(GTE, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(2000))), new Filter.Expression(LTE, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(3000))))).build());\n        assertThat(results).hasSize(2).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"first\");\n            assertThat(result.getMetadata()).hasSize(4);\n            assertThat(result.getMetadata()).containsEntry(\"distance\", 2.220446049250313E-16);\n        });\n        results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test content\").filterExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(3000)))).build());\n        assertThat(results).hasSize(1);\n    }\n\n    @Test\n    void shouldFilterByStringEquality() {\n        Document doc = Document.builder().id(\"1\").text(\"sample content\").metadata(Map.of(\"category\", \"category1\")).build();\n        this.vectorStore.add(List.of(doc));\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"sample\").filterExpression(\"category == \'category1\'\").build());\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getId()).isEqualTo(\"1\");\n    }\n\n    @Test\n    void shouldFilterByNumericEquality() {\n        Document doc = Document.builder().id(\"1\").text(\"item description\").metadata(Map.of(\"value\", 1)).build();\n        this.vectorStore.add(List.of(doc));\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"item\").filterExpression(\"value == 1\").build());\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getMetadata()).containsEntry(\"value\", 1);\n    }\n\n    @Test\n    void shouldFilterWithInCondition() {\n        Document doc1 = Document.builder().id(\"1\").text(\"entry\").metadata(Map.of(\"status\", \"active\")).build();\n        Document doc2 = Document.builder().id(\"2\").text(\"entry\").metadata(Map.of(\"status\", \"inactive\")).build();\n        this.vectorStore.add(List.of(doc1, doc2));\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"entry\").filterExpression(\"status in [\'active\', \'pending\']\").build());\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getId()).isEqualTo(\"1\");\n    }\n\n    @Test\n    void shouldFilterByNumericRange() {\n        List<Document> docs = Arrays.asList(Document.builder().id(\"1\").text(\"entity\").metadata(Map.of(\"value\", 1)).build(), Document.builder().id(\"2\").text(\"entity\").metadata(Map.of(\"value\", 2)).build(), Document.builder().id(\"3\").text(\"entity\").metadata(Map.of(\"value\", 3)).build());\n        this.vectorStore.add(docs);\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"entity\").filterExpression(\"value >= 1 && value <= 1\").build());\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getId()).isEqualTo(\"1\");\n    }\n\n    @Test\n    void shouldReturnEmptyResultsWhenNoDocumentsMatchFilter() {\n        Document doc = Document.builder().id(\"1\").text(\"test\").metadata(Map.of(\"type\", \"document\")).build();\n        this.vectorStore.add(List.of(doc));\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"test\").filterExpression(\"type == \'image\'\").build());\n        assertThat(results).isEmpty();\n    }\n\n    @Test\n    void shouldFilterByBooleanValue() {\n        List<Document> docs = Arrays.asList(Document.builder().id(\"1\").text(\"instance\").metadata(Map.of(\"enabled\", true)).build(), Document.builder().id(\"2\").text(\"instance\").metadata(Map.of(\"enabled\", false)).build());\n        this.vectorStore.add(docs);\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"instance\").filterExpression(\"enabled == true\").build());\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getId()).isEqualTo(\"1\");\n    }\n\n    @Test\n    void shouldFilterByNotEqual() {\n        List<Document> docs = Arrays.asList(Document.builder().id(\"1\").text(\"item\").metadata(Map.of(\"classification\", \"typeA\")).build(), Document.builder().id(\"2\").text(\"item\").metadata(Map.of(\"classification\", \"typeB\")).build());\n        this.vectorStore.add(docs);\n        List<Document> results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"item\").filterExpression(\"classification != \'typeB\'\").build());\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getId()).isEqualTo(\"1\");\n    }\n}',0x01,'cu::SimpleVectorStoreWithFilterTests.java'),
('0a55973c-b43c-4df6-ad6d-37e9066688e0','When developing prompts, it&#8217;s important to integrate several key components to ensure clarity and effectiveness:\n\n<strong>Instructions</strong>: Offer clear and direct instructions to the AI, similar to how you would communicate with a person. This clarity is essential for helping the AI \"understand\" what is expected.\n<strong>External Context</strong>: Include relevant background information or specific guidance for the AI&#8217;s response when necessary. This \"external context\" frames the prompt and aids the AI in grasping the overall scenario.\n<strong>User Input</strong>: This is the straightforward part - the user&#8217;s direct request or question forming the core of the prompt.\n<strong>Output Indicator</strong>: This aspect can be tricky. It involves specifying the desired format for the AI&#8217;s response, such as JSON. However, be aware that the AI might not always adhere strictly to this format. For instance, it might prepend a phrase like \"here is your JSON\" before the actual JSON data, or sometimes generate a JSON-like structure that is not accurate.\n\n\nProviding the AI with examples of the anticipated question and answer format can be highly beneficial when crafting prompts.\nThis practice helps the AI \"understand\" the structure and intent of your query, leading to more precise and relevant responses.\nWhile this documentation does not delve deeply into these techniques, they provide a starting point for further exploration in AI prompt engineering.\n\nFollowing is a list of resources for further investigation.\n\nSimple Techniques\n\n<strong><a href=\"https://www.promptingguide.ai/introduction/examples.en#text-summarization\">Text Summarization</a></strong>:<br>\nReduces extensive text into concise summaries, capturing key points and main ideas while omitting less critical details.\n<strong><a href=\"https://www.promptingguide.ai/introduction/examples.en#question-answering\">Question Answering</a></strong>:<br>\nFocuses on deriving specific answers from provided text, based on user-posed questions. It&#8217;s about pinpointing and extracting relevant information in response to queries.\n<strong><a href=\"https://www.promptingguide.ai/introduction/examples.en#text-classification\">Text Classification</a></strong>:<br>\nSystematically categorizes text into predefined categories or groups, analyzing the text and assigning it to the most fitting category based on its content.\n<strong><a href=\"https://www.promptingguide.ai/introduction/examples.en#conversation\">Conversation</a></strong>:<br>\nCreates interactive dialogues where the AI can engage in back-and-forth communication with users, simulating a natural conversation flow.\n<strong><a href=\"https://www.promptingguide.ai/introduction/examples.en#code-generation\">Code Generation</a></strong>:<br>\nGenerates functional code snippets based on specific user requirements or descriptions, translating natural language instructions into executable code.\n\n\nAdvanced Techniques',0x00,'asciidoc::prompt.adoc::Prompt Engineering::Creating effective prompts::0'),
('5ffa204f-ba06-47a0-a964-382266deec49','The 1.0.0-SNAPSHOT version includes significant changes to artifact IDs, package names, and module structure. This section provides guidance specific to using the SNAPSHOT version.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-SNAPSHOT::Overview::0'),
('d98486bd-04cd-4501-aecd-387a7b6d30c7','More implementations may be supported in future releases.\n\nIf you have a vector database that needs to be supported by Spring AI, open an issue on GitHub or, even better, submit a pull request with an implementation.\n\nInformation on each of the <code>VectorStore</code> implementations can be found in the subsections of this chapter.',0x00,'asciidoc::vectordbs.adoc::VectorStore Implementations::2'),
('1465a5b6-1489-4472-a5db-392ea0a93ede','The <a href=\"https://docs.aws.amazon.com/nova/latest/userguide/modalities-video.html\">Amazon Nova models</a> allow you to include a single video in the payload, which can be provided either in base64 format or through an Amazon S3 URI.\n\nCurrently, Bedrock Nova supports the videos of <code>video/x-matroska</code>, <code>video/quicktime</code>, <code>video/mp4</code>, <code>video/webm</code>, <code>video/x-flv</code>, <code>video/mpeg</code>, <code>video/x-ms-wmv</code> and <code>video/3gpp</code> mime types.\n\nSpring AI&#8217;s <code>Message</code> interface supports multimodal AI models by introducing the <code>Media</code> type.\nIt contains data and information about media attachments in messages, using Spring&#8217;s <code>org.springframework.util.MimeType</code> and a <code>java.lang.Object</code> for the raw media data.\n\nBelow is a simple code example, demonstrating the combination of user text with a video.\n\nString response = ChatClient.create(chatModel)\n    .prompt()\n    .user(u -&gt; u.text(\"Explain what do you see in this video?\")\n        .media(Media.Format.VIDEO_MP4, new ClassPathResource(\"/test.video.mp4\")))\n    .call()\n    .content();\n\nlogger.info(response);\n\nIt takes as an input the <code>test.video.mp4</code> image:\n\nalong with the text message \"Explain what do you see in this video?\", and generates a response something like:\n\nThe video shows a group of baby chickens, also known as chicks, huddled together on a surface\n...',0x00,'asciidoc::bedrock-converse.adoc::Multimodal::Video::0'),
('1c45ef14-7bcd-4a07-bd0e-395cb2b98350','You can turn a functional type (<code>Function</code>, <code>Supplier</code>, <code>Consumer</code>, or <code>BiFunction</code>) into a tool by building a <code>FunctionToolCallback</code> programmatically.\n\npublic class WeatherService implements Function&lt;WeatherRequest, WeatherResponse&gt; {\n    public WeatherResponse apply(WeatherRequest request) {\n        return new WeatherResponse(30.0, Unit.C);\n    }\n}\n\npublic enum Unit { C, F }\npublic record WeatherRequest(String location, Unit unit) {}\npublic record WeatherResponse(double temp, Unit unit) {}\n\nThe <code>FunctionToolCallback.Builder</code> allows you to build a <code>FunctionToolCallback</code> instance and provide key information about the tool:\n\n<code>name</code>: The name of the tool. AI models use this name to identify the tool when calling it. Therefore, it&#8217;s not allowed to have two tools with the same name in the same context. The name must be unique across all the tools available to the model for a specific chat request. Required.\n<code>toolFunction</code>: The functional object that represents the tool method (<code>Function</code>, <code>Supplier</code>, <code>Consumer</code>, or <code>BiFunction</code>). Required.\n<code>description</code>: The description for the tool, which can be used by the model to understand when and how to call the tool. If not provided, the method name will be used as the tool description. However, it&#8217;s strongly recommended to provide a detailed description because that&#8217;s paramount for the model to understand the tool&#8217;s purpose and how to use it. Failing in providing a good description can lead to the model not using the tool when it should or using it incorrectly.\n<code>inputType</code>: The type of the function input. Required.\n<code>inputSchema</code>: The JSON schema for the input parameters of the tool. If not provided, the schema will be generated automatically based on the <code>inputType</code>. You can use the <code>@ToolParam</code> annotation to provide additional information about the input parameters, such as a description or whether the parameter is required or optional. By default, all input parameters are considered required. See <a href=\"#_json_schema\">JSON Schema</a> for more details.\n<code>toolMetadata</code>: The <code>ToolMetadata</code> instance that defines additional settings such as whether the result should be returned directly to the client, and the result converter to use. You can build it using the <code>ToolMetadata.Builder</code> class.\n<code>toolCallResultConverter</code>: The <code>ToolCallResultConverter</code> instance to use for converting the result of a tool call to a <code>String</code> object to send back to the AI model. If not provided, the default converter will be used (<code>DefaultToolCallResultConverter</code>).\n\n\nThe <code>ToolMetadata.Builder</code> allows you to build a <code>ToolMetadata</code> instance and define additional settings for the tool:',0x00,'asciidoc::tools.adoc::Functions as Tools::Programmatic Specification: <code>FunctionToolCallback</code>::0'),
('ba8a4002-c187-4352-80bc-39716a557186','The prefix <code>spring.ai.oci.genai</code> is the property prefix to configure the connection to OCI GenAI.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=oci-genai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match oci-genai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.oci.genai.embedding</code> is the property prefix that configures the <code>EmbeddingModel</code> implementation for OCI GenAI\n\n\n\nAll properties prefixed with <code>spring.ai.oci.genai.embedding.options</code> can be overridden at runtime by adding a request specific <a href=\"#embedding-options\">Runtime Options</a> to the <code>EmbeddingRequest</code> call.',0x00,'asciidoc::oci-genai-embeddings.adoc::Auto-configuration::Embedding Properties::0'),
('797cab5b-69ee-4eb1-a88f-39b2ff5253bd','The <code>VectorStoreRetriever</code> interface is particularly useful in RAG applications, where you need to retrieve relevant documents to provide context for an AI model:\n\n@Service\npublic class RagService {\n\n    private final VectorStoreRetriever retriever;\n    private final ChatModel chatModel;\n\n    public RagService(VectorStoreRetriever retriever, ChatModel chatModel) {\n        this.retriever = retriever;\n        this.chatModel = chatModel;\n    }\n\n    public String generateResponse(String userQuery) {\n        // Retrieve relevant documents\n        List&lt;Document&gt; relevantDocs = retriever.similaritySearch(userQuery);\n\n        // Extract content from documents to use as context\n        String context = relevantDocs.stream()\n            .map(Document::getContent)\n            .collect(Collectors.joining(\"\\n\\n\"));\n\n        // Generate response using the retrieved context\n        String prompt = \"Context information:\\n\" + context + \"\\n\\nUser query: \" + userQuery;\n        return chatModel.generate(prompt);\n    }\n}\n\nThis pattern allows for a clean separation between the retrieval component and the generation component in RAG applications.',0x00,'asciidoc::vectordbs.adoc::Retrieval Operations with VectorStoreRetriever::Integration with RAG Applications::0'),
('7a604c64-8155-457c-91e0-39ca0644ac8d','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nAdd the GemFire VectorStore Spring Boot starter to you project&#8217;s Maven build file <code>pom.xml</code>:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-gemfire&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> file\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-gemfire\'\n}',0x00,'asciidoc::gemfire.adoc::Auto-configuration::0'),
('012bd165-0ba7-4d4e-a0aa-3a4d26090426','@SuppressWarnings(\"CheckReturnValue\")\npublic static class OrExpressionContext extends BooleanExpressionContext {\n\n    public BooleanExpressionContext left;\n\n    public Token operator;\n\n    public BooleanExpressionContext right;\n\n    public List<BooleanExpressionContext> booleanExpression() {\n        return getRuleContexts(BooleanExpressionContext.class);\n    }\n\n    public BooleanExpressionContext booleanExpression(int i) {\n        return getRuleContext(BooleanExpressionContext.class, i);\n    }\n\n    public TerminalNode OR() {\n        return getToken(FiltersParser.OR, 0);\n    }\n\n    public OrExpressionContext(BooleanExpressionContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterOrExpression(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitOrExpression(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitOrExpression(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('bd904cae-1539-47bf-82d2-3a4ec9e65342','Currently, Anthropic Claude 3 supports the <code>base64</code> source type for <code>images</code>, and the <code>image/jpeg</code>, <code>image/png</code>, <code>image/gif</code>, and <code>image/webp</code> media types.\nCheck the <a href=\"https://docs.anthropic.com/claude/docs/vision\">Vision guide</a> for more information.\nAnthropic Claude 3.5 Sonnet also supports the <code>pdf</code> source type for <code>application/pdf</code> files.\n\nSpring AI&#8217;s <code>Message</code> interface supports multimodal AI models by introducing the Media type.\nThis type contains data and information about media attachments in messages, using Spring&#8217;s <code>org.springframework.util.MimeType</code> and a <code>java.lang.Object</code> for the raw media data.\n\nBelow is a simple code example extracted from <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-anthropic/src/test/java/org/springframework/ai/anthropic/AnthropicChatModelIT.java\">AnthropicChatModelIT.java</a>, demonstrating the combination of user text with an image.\n\nvar imageData = new ClassPathResource(\"/multimodal.test.png\");\n\nvar userMessage = new UserMessage(\"Explain what do you see on this picture?\",\n        List.of(new Media(MimeTypeUtils.IMAGE_PNG, this.imageData)));\n\nChatResponse response = chatModel.call(new Prompt(List.of(this.userMessage)));\n\nlogger.info(response.getResult().getOutput().getContent());\n\nIt takes as an input the <code>multimodal.test.png</code> image:\n\nalong with the text message \"Explain what do you see on this picture?\", and generates a response something like:\n\nThe image shows a close-up view of a wire fruit basket containing several pieces of fruit.\n...',0x00,'asciidoc::anthropic-chat.adoc::Multimodal::Images::0'),
('934f200a-2747-46ed-b40e-3b24a2371af8','OpenAI provides two mutually exclusive parameters for controlling token generation limits:\n\n\n\nThese parameters are <strong>mutually exclusive</strong>. Setting both will result in an API error from OpenAI.\n\nUsage Examples\n\n<strong>For non-reasoning models (gpt-4o, gpt-3.5-turbo):</strong>\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Explain quantum computing in simple terms.\",\n        OpenAiChatOptions.builder()\n            .model(\"gpt-4o\")\n            .maxTokens(150)  // Use maxTokens for non-reasoning models\n        .build()\n    ));\n\n<strong>For reasoning models (o1, o3 series):</strong>\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Solve this complex math problem step by step: ...\",\n        OpenAiChatOptions.builder()\n            .model(\"o1-preview\")\n            .maxCompletionTokens(1000)  // Use maxCompletionTokens for reasoning models\n        .build()\n    ));\n\n<strong>Builder Pattern Validation:</strong>\nThe OpenAI ChatOptions builder automatically enforces mutual exclusivity with a \"last-set-wins\" approach:\n\n// This will automatically clear maxTokens and use maxCompletionTokens\nOpenAiChatOptions options = OpenAiChatOptions.builder()\n    .maxTokens(100)           // Set first\n    .maxCompletionTokens(200) // This clears maxTokens and logs a warning\n    .build();\n\n// Result: maxTokens = null, maxCompletionTokens = 200',0x00,'asciidoc::openai-chat.adoc::Auto-configuration::Token Limit Parameters: Model-Specific Usage::0'),
('3375ab51-56b4-4277-8c12-3b293bc0f79e','<a href=\"https://azure.microsoft.com/en-us/services/cosmos-db/\">Azure Cosmos DB</a> is Microsoft&#8217;s globally distributed cloud-native database service designed for mission-critical applications.\nIt offers high availability, low latency, and the ability to scale horizontally to meet modern application demands.\nIt was built from the ground up with global distribution, fine-grained multi-tenancy, and horizontal scalability at its core.\nIt is a foundational service in Azure, used by most of Microsoft’s mission critical applications at global scale, including Teams, Skype, Xbox Live, Office 365, Bing, Azure Active Directory, Azure Portal, Microsoft Store, and many others.\nIt is also used by thousands of external customers including OpenAI for ChatGPT and other mission-critical AI applications that require elastic scale, turnkey global distribution, and low latency and high availability across the planet.',0x00,'asciidoc::azure-cosmos-db.adoc::What is Azure Cosmos DB?::0'),
('be57decc-7678-471e-932a-3b62cab23600','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Ollama chat integration.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n   &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n   &lt;artifactId&gt;spring-ai-starter-model-ollama&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-ollama\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::ollama-chat.adoc::Auto-configuration::0'),
('eae28312-a542-40c5-91ae-3ba6aa819daa','Token Usage\n\n\n\nLabels',0x00,'asciidoc::index.adoc::More Metrics Reference::Chat Model Metrics (Model provider execution)::0'),
('3d7f6bb9-1a97-4054-a23c-3ba6f1552ffe','The MiniMax model supported the web search feature. The web search feature allows you to search the web for information and return the results in the chat response.\n\nAbout web search follow the <a href=\"https://platform.minimaxi.com/document/ChatCompletion%20v2\">MiniMax ChatCompletion</a> for further information.\n\nHere is a simple snippet how to use the web search:\n\nUserMessage userMessage = new UserMessage(\n        \"How many gold medals has the United States won in total at the 2024 Olympics?\");\n\nList&lt;Message&gt; messages = new ArrayList&lt;&gt;(List.of(this.userMessage));\n\nList&lt;MiniMaxApi.FunctionTool&gt; functionTool = List.of(MiniMaxApi.FunctionTool.webSearchFunctionTool());\n\nMiniMaxChatOptions options = MiniMaxChatOptions.builder()\n    .model(MiniMaxApi.ChatModel.ABAB_6_5_S_Chat.value)\n    .tools(this.functionTool)\n    .build();\n\n\n// Sync request\nChatResponse response = chatModel.call(new Prompt(this.messages, this.options));\n\n// Streaming request\nFlux&lt;ChatResponse&gt; streamResponse = chatModel.stream(new Prompt(this.messages, this.options));\n\nMiniMaxApi Samples\n\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-minimax/src/test/java/org/springframework/ai/minimax/api/MiniMaxApiIT.java\">MiniMaxApiIT.java</a> test provides some general examples how to use the lightweight library.\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-minimax/src/test/java/org/springframework/ai/minimax/api/MiniMaxApiToolFunctionCallIT.java\">MiniMaxApiToolFunctionCallIT.java</a> test shows how to use the low-level API to call tool functions.&gt;',0x00,'asciidoc::minimax-chat.adoc::Manual Configuration::WebSearch chat::0'),
('f3168534-0b68-4895-ba4e-3bee80a9a03a','Transforms a batch of documents as part of the processing workflow.\n\npublic interface DocumentTransformer extends Function&lt;List&lt;Document&gt;, List&lt;Document&gt;&gt; {\n\n    default List&lt;Document&gt; transform(List&lt;Document&gt; transform) {\n		return apply(transform);\n	}\n}',0x00,'asciidoc::etl-pipeline.adoc::ETL Interfaces::DocumentTransformer::0'),
('cae68c4c-6e58-49c7-94f2-3bf35c4b19b1','Connection Properties\n\nThe prefix <code>spring.ai.oci.genai</code> is the property prefix to configure the connection to OCI GenAI.\n\n\n\nConfiguration Properties\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the chat auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.chat</code>.\nTo enable, spring.ai.model.chat=oci-genai (It is enabled by default)\nTo disable, spring.ai.model.chat=none (or any value which doesn&#8217;t match oci-genai)\nThis change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.oci.genai.cohere.chat</code> is the property prefix that configures the <code>ChatModel</code> implementation for OCI GenAI Cohere Chat.\n\n\n\nAll properties prefixed with <code>spring.ai.oci.genai.cohere.chat.options</code> can be overridden at runtime by adding a request specific <a href=\"#chat-options\">Runtime Options</a> to the <code>Prompt</code> call.',0x00,'asciidoc::cohere-chat.adoc::Auto-configuration::Chat Properties::0'),
('57dbab51-a827-4ac0-96aa-3c352da65eec','Per-Message TTL (5m or 1h)\n\nBy default, cached content uses a 5-minute TTL.\nYou can set a 1-hour TTL for specific message types.\nWhen 1-hour TTL is used, Spring AI automatically sets the required Anthropic beta header.\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        List.of(new SystemMessage(largeSystemPrompt)),\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .cacheOptions(AnthropicCacheOptions.builder()\n                .strategy(AnthropicCacheStrategy.SYSTEM_ONLY)\n                .messageTypeTtl(MessageType.SYSTEM, AnthropicCacheTtl.ONE_HOUR)\n                .build())\n            .maxTokens(500)\n            .build()\n    )\n);\n\nExtended TTL uses Anthropic beta feature <code>extended-cache-ttl-2025-04-11</code>.\n\nCache Eligibility Filters\n\nControl when cache breakpoints are used by setting minimum content lengths and an optional token-based length function:\n\nAnthropicCacheOptions cache = AnthropicCacheOptions.builder()\n    .strategy(AnthropicCacheStrategy.CONVERSATION_HISTORY)\n    .messageTypeMinContentLength(MessageType.SYSTEM, 1024)\n    .messageTypeMinContentLength(MessageType.USER, 1024)\n    .messageTypeMinContentLength(MessageType.ASSISTANT, 1024)\n    .contentLengthFunction(text -&gt; MyTokenCounter.count(text))\n    .build();\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        List.of(/* messages */),\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .cacheOptions(cache)\n            .build()\n    )\n);\n\nTool Definitions are always considered for caching if <code>SYSTEM_AND_TOOLS</code> strategy is used, regardless of content length.',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Advanced Caching Options::0'),
('9c52858b-8936-4121-944e-3c64a933c234','The <code>StructuredOutputConverter</code> interface allows you to obtain structured output, such as mapping the output to a Java class or an array of values from the text-based AI Model output.\nThe interface definition is:\n\npublic interface StructuredOutputConverter&lt;T&gt; extends Converter&lt;String, T&gt;, FormatProvider {\n\n}\n\nIt combines the Spring <a href=\"https://docs.spring.io/spring-framework/docs/current/javadoc-api/org/springframework/core/convert/converter/Converter.html\">Converter&lt;String, T&gt;</a> interface and the <code>FormatProvider</code> interface\n\npublic interface FormatProvider {\n	String getFormat();\n}\n\nThe following diagram shows the data flow when using the structured output API.\n\nThe <code>FormatProvider</code> supplies specific formatting guidelines to the AI Model, enabling it to produce text outputs that can be converted into the designated target type <code>T</code> using the <code>Converter</code>. Here is an example of such formatting instructions:\n\n  Your response should be in JSON format.\n  The data structure for the JSON should match this Java class: java.util.HashMap\n  Do not include any explanations, only provide a RFC8259 compliant JSON response following this format without deviation.\n\nThe format instructions are most often appended to the end of the user input using the <a href=\"api/prompt.html#_prompttemplate\">PromptTemplate</a> like this:\n\n    StructuredOutputConverter outputConverter = ...\n    String userInputTemplate = \"\"\"\n        ... user text input ....\n        {format}\n        \"\"\"; // user input with a \"format\" placeholder.\n    Prompt prompt = new Prompt(\n            PromptTemplate.builder()\n						.template(this.userInputTemplate)\n						.variables(Map.of(..., \"format\", this.outputConverter.getFormat())) // replace the \"format\" placeholder with the converter\'s format.\n						.build().createMessage()\n    );\n\nThe Converter&lt;String, T&gt; is responsible to transform output text from the model into instances of the specified type <code>T</code>.',0x00,'asciidoc::structured-output-converter.adoc::Structured Output API::0'),
('ec8ce10a-7052-4356-8479-3c9762896baf','@SuppressWarnings(\"CheckReturnValue\")\npublic static class InExpressionContext extends BooleanExpressionContext {\n\n    public IdentifierContext identifier() {\n        return getRuleContext(IdentifierContext.class, 0);\n    }\n\n    public TerminalNode IN() {\n        return getToken(FiltersParser.IN, 0);\n    }\n\n    public ConstantArrayContext constantArray() {\n        return getRuleContext(ConstantArrayContext.class, 0);\n    }\n\n    public InExpressionContext(BooleanExpressionContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterInExpression(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitInExpression(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitInExpression(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('0b1bab2d-0bd7-4063-b6fe-3cbb54e28cea','public class VectorStoreRuntimeHints implements RuntimeHintsRegistrar {\n\n    @Override\n    public void registerHints(@NonNull RuntimeHints hints, @Nullable ClassLoader classLoader) {\n        for (var r : Set.of(\"antlr4/org/springframework/ai/vectorstore/filter/antlr4/Filters.g4\")) {\n            hints.resources().registerResource(new ClassPathResource(r));\n        }\n    }\n}',0x01,'cu::VectorStoreRuntimeHints.java'),
('0d26e3a6-e33a-4453-a4e9-3d0e1f835944','<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=ollama (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match ollama)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.ollama.embedding.options</code> is the property prefix that configures the Ollama embedding model.\nIt includes the Ollama request (advanced) parameters such as the <code>model</code>, <code>keep-alive</code>, and <code>truncate</code> as well as the Ollama model <code>options</code> properties.\n\nHere are the advanced request parameter for the Ollama embedding model:\n\n\n\nThe remaining <code>options</code> properties are based on the <a href=\"https://github.com/ollama/ollama/blob/main/docs/modelfile.md#valid-parameters-and-values\">Ollama Valid Parameters and Values</a> and <a href=\"https://github.com/ollama/ollama/blob/main/api/types.go\">Ollama Types</a>. The default values are based on: <a href=\"https://github.com/ollama/ollama/blob/b538dc3858014f94b099730a592751a5454cab0a/api/types.go#L364\">Ollama type defaults</a>.\n\n\n\nAll properties prefixed with <code>spring.ai.ollama.embedding.options</code> can be overridden at runtime by adding a request specific <a href=\"#embedding-options\">Runtime Options</a> to the <code>EmbeddingRequest</code> call.',0x00,'asciidoc::ollama-embeddings.adoc::Auto-configuration::Embedding Properties::0'),
('fbd896d2-8a11-4ebb-8414-3d2e4df7c6ac','Instead of using the Spring Boot auto-configuration, you can manually configure the Elasticsearch vector store. For this you need to add the <code>spring-ai-elasticsearch-store</code> to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-elasticsearch-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-elasticsearch-store\'\n}\n\nCreate an Elasticsearch <code>RestClient</code> bean.\nRead the <a href=\"https://www.elastic.co/guide/en/elasticsearch/client/java-api-client/current/java-rest-low-usage-initialization.html\">Elasticsearch Documentation</a> for more in-depth information about the configuration of a custom RestClient.\n\n@Bean\npublic RestClient restClient() {\n    return RestClient.builder(new HttpHost(\"&lt;host&gt;\", 9200, \"http\"))\n        .setDefaultHeaders(new Header[]{\n            new BasicHeader(\"Authorization\", \"Basic &lt;encoded username and password&gt;\")\n        })\n        .build();\n}\n\nThen create the <code>ElasticsearchVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore vectorStore(RestClient restClient, EmbeddingModel embeddingModel) {\n    ElasticsearchVectorStoreOptions options = new ElasticsearchVectorStoreOptions();\n    options.setIndexName(\"custom-index\");    // Optional: defaults to \"spring-ai-document-index\"\n    options.setSimilarity(COSINE);           // Optional: defaults to COSINE\n    options.setDimensions(1536);             // Optional: defaults to model dimensions or 1536\n\n    return ElasticsearchVectorStore.builder(restClient, embeddingModel)\n        .options(options)                     // Optional: use custom options\n        .initializeSchema(true)               // Optional: defaults to false\n        .batchingStrategy(new TokenCountBatchingStrategy()) // Optional: defaults to TokenCountBatchingStrategy\n        .build();\n}\n\n// This can be any EmbeddingModel implementation\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}',0x00,'asciidoc::elasticsearch.adoc::Manual Configuration::0'),
('f64a189a-7e1a-42d3-889d-3d636baaa0fb','<div class=\"paragraph\">\n<p><a href=\"https://groq.com/\">Groq</a> is an extremely fast,  LPU™ based, AI Inference Engine that support various <a href=\"https://console.groq.com/docs/models\">AI Models</a>,\nsupports <code>Tool/Function Calling</code> and exposes a <code>OpenAI API</code> compatible endpoint.</p>\n</div>\n<div class=\"paragraph\">\n<p>Spring AI integrates with the <a href=\"https://groq.com/\">Groq</a> by reusing the existing <a href=\":api/chat/openai-chat.html\">OpenAI</a> client.\nFor this you need to obtain a <a href=\"https://console.groq.com/keys\">Groq Api Key</a>, set the base-url to <a href=\"https://api.groq.com/openai\" class=\"bare\">https://api.groq.com/openai</a> and select one of the\nprovided <a href=\"https://console.groq.com/docs/models\">Groq models</a>.</p>\n</div>\n<div class=\"imageblock text-center\">\n<div class=\"content\">\n<img src=\"spring-ai-groq-integration.jpg\" alt=\"spring ai groq integration\">\n</div>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nThe Groq API is not fully compatible with the OpenAI API.\nBe aware for the following <a href=\"https://console.groq.com/docs/openai\">compatibility constrains</a>.\nAdditionally, currently Groq doesn&#8217;t support multimodal messages.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"paragraph\">\n<p>Check the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/chat/proxy/GroqWithOpenAiChatModelIT.java\">GroqWithOpenAiChatModelIT.java</a> tests\nfor examples of using Groq with Spring AI.</p>\n</div>',0x00,'asciidoc::groq-chat.adoc::0'),
('0677005c-8ea8-4b55-89f0-3d92fe9d22af','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatModel.java\">OpenAiChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"#low-level-api\">Low-level OpenAiApi Client</a> to connect to the OpenAI service.\n\nAdd the <code>spring-ai-openai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create an <code>OpenAiChatModel</code> and use it for text generations:\n\nvar openAiApi = OpenAiApi.builder()\n            .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n            .build();\nvar openAiChatOptions = OpenAiChatOptions.builder()\n            .model(\"gpt-3.5-turbo\")\n            .temperature(0.4)\n            .maxTokens(200)\n            .build();\nvar chatModel = new OpenAiChatModel(this.openAiApi, this.openAiChatOptions);\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; response = this.chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>OpenAiChatOptions</code> provides the configuration information for the chat requests.\nThe <code>OpenAiApi.Builder</code> and <code>OpenAiChatOptions.Builder</code> are fluent options-builders for API client and chat config respectively.',0x00,'asciidoc::openai-chat.adoc::Manual Configuration::0'),
('df19b719-db40-4ce8-bd34-3ddc9d5abfe7','<div class=\"paragraph\">\n<p>Practical implementations of Prompt Engineering techniques based on the comprehensive <a href=\"https://www.kaggle.com/whitepaper-prompt-engineering\">Prompt Engineering Guide</a>.\nThe guide covers the theory, principles, and patterns of effective prompt engineering, while here we demonstrate how to translate those concepts into working Java code using Spring AI&#8217;s fluent <a href=\":api/chatclient.html\">ChatClient API</a>.\nThe demo source code used in this article is available at: <a href=\"https://github.com/spring-projects/spring-ai-examples/tree/main/prompt-engineering/prompt-engineering-patterns\">Prompt Engineering Patterns Examples</a>.</p>\n</div>',0x00,'asciidoc::prompt-engineering-patterns.adoc::0'),
('93c38df2-89c7-48fc-b65f-3de236872ee2','<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nEXPERIMENTAL. Used for experimental purposes only. Not compatible yet with the <code>VectorStores</code>.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"paragraph\">\n<p>Vertex AI supports two types of embeddings models, text and multimodal.\nThis document describes how to create a multimodal embedding using the Vertex AI <a href=\"https://cloud.google.com/vertex-ai/generative-ai/docs/embeddings/get-multimodal-embeddings\">Multimodal embeddings API</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>The multimodal embeddings model generates 1408-dimension vectors based on the input you provide, which can include a combination of image, text, and video data.\nThe embedding vectors can then be used for subsequent tasks like image classification or video content moderation.</p>\n</div>\n<div class=\"paragraph\">\n<p>The image embedding vector and text embedding vector are in the same semantic space with the same dimensionality.\nConsequently, these vectors can be used interchangeably for use cases like searching image by text, or searching video by image.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nThe VertexAI Multimodal API imposes the <a href=\"https://cloud.google.com/vertex-ai/generative-ai/docs/embeddings/get-multimodal-embeddings#api-limits\">following limits</a>.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"admonitionblock tip\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Tip</div>\n</td>\n<td class=\"content\">\nFor text-only embedding use cases, we recommend using the <a href=\"api/embeddings/vertexai-embeddings-text.html\">Vertex AI text-embeddings model</a> instead.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::vertexai-embeddings-multimodal.adoc::0'),
('621bb6aa-bb17-4cef-b2dd-3e10b9fd5cff','The <code>Spring AI</code> project aims to streamline the development of applications that incorporate artificial intelligence functionality without unnecessary complexity.\n\nThe project draws inspiration from notable Python projects, such as LangChain and LlamaIndex, but Spring AI is not a direct port of those projects.\nThe project was founded with the belief that the next wave of Generative AI applications will not be only for Python developers but will be ubiquitous across many programming languages.\n\nSpring AI addresses the fundamental challenge of AI integration: <code>Connecting your enterprise Data and APIs with AI Models</code>.\n\nSpring AI provides abstractions that serve as the foundation for developing AI applications.\nThese abstractions have multiple implementations, enabling easy component swapping with minimal code changes.\n\nSpring AI provides the following features:\n\nPortable API support across AI providers for Chat, text-to-image, and Embedding models. Both synchronous and streaming API options are supported. Access to model-specific features is also available.\nSupport for all major <a href=\"api/index.html\">AI Model providers</a> such as Anthropic, OpenAI, Microsoft, Amazon, Google, and Ollama. Supported model types include:\n<a href=\"api/structured-output-converter.html\">Structured Outputs</a> - Mapping of AI Model output to POJOs.\nSupport for all major <a href=\"api/vectordbs.html\">Vector Database providers</a> such as Apache Cassandra, Azure Cosmos DB, Azure Vector Search, Chroma, Elasticsearch, GemFire, MariaDB, Milvus, MongoDB Atlas, Neo4j, OpenSearch, Oracle, PostgreSQL/PGVector, Pinecone, Qdrant, Redis, SAP Hana, Typesense and Weaviate.\nPortable API across Vector Store providers, including a novel SQL-like metadata filter API.\n<a href=\"api/tools.html\">Tools/Function Calling</a> - Permits the model to request the execution of client-side tools and functions, thereby accessing necessary real-time information as required and taking action.\n<a href=\"observability/index.html\">Observability</a> - Provides insights into AI-related operations.\nDocument ingestion <a href=\"api/etl-pipeline.html\">ETL framework</a> for Data Engineering.\n<a href=\"api/testing.html\">AI Model Evaluation</a> - Utilities to help evaluate generated content and protect against hallucinated response.\nSpring Boot Auto Configuration and Starters for AI Models and Vector Stores.\n<a href=\"api/chatclient.html\">ChatClient API</a> - Fluent API for communicating with AI Chat Models, idiomatically similar to the WebClient and RestClient APIs.\n<a href=\"api/advisors.html\">Advisors API</a> - Encapsulates recurring Generative AI patterns, transforms data sent to and from Language Models (LLMs), and provides portability across various models and use cases.\nSupport for <a href=\"api/chatclient.html#_chat_memory\">Chat Conversation Memory</a> and <a href=\"api/chatclient.html#_retrieval_augmented_generation\">Retrieval Augmented Generation (RAG)</a>.',0x00,'asciidoc::index.adoc::0'),
('368fd313-b78e-40ca-b34c-3e12d2066a67','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Anthropic Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> file:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-anthropic&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-anthropic\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::anthropic-chat.adoc::Auto-configuration::0'),
('2b4a4222-a87f-4d0c-97c9-3e2743112595','The Coherence Vector Store implementation provides access to the underlying native Coherence client (<code>Session</code>) through the <code>getNativeClient()</code> method:\n\nCoherenceVectorStore vectorStore = context.getBean(CoherenceVectorStore.class);\nOptional&lt;Session&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    Session session = nativeClient.get();\n    // Use the native client for Coherence-specific operations\n}\n\nThe native client gives you access to Coherence-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::coherence.adoc::Accessing the Native Client::0'),
('679281e0-0531-49ed-bbe1-3e3787d44906','@SuppressWarnings(\"CheckReturnValue\")\npublic static class NinExpressionContext extends BooleanExpressionContext {\n\n    public IdentifierContext identifier() {\n        return getRuleContext(IdentifierContext.class, 0);\n    }\n\n    public ConstantArrayContext constantArray() {\n        return getRuleContext(ConstantArrayContext.class, 0);\n    }\n\n    public TerminalNode NOT() {\n        return getToken(FiltersParser.NOT, 0);\n    }\n\n    public TerminalNode IN() {\n        return getToken(FiltersParser.IN, 0);\n    }\n\n    public TerminalNode NIN() {\n        return getToken(FiltersParser.NIN, 0);\n    }\n\n    public NinExpressionContext(BooleanExpressionContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterNinExpression(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitNinExpression(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitNinExpression(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('e4e05ce3-8797-485a-a5f8-3ee7177dbbfd','You can automate the upgrade process to 1.0.0-M8 using an OpenRewrite recipe.\nThis recipe helps apply many of the necessary code changes for this version.\nFind the recipe and usage instructions at <a href=\"https://github.com/arconia-io/arconia-migrations/blob/main/docs/spring-ai.md\">Arconia Spring AI Migrations</a>.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M8::0'),
('3f9177ac-d68d-4f6c-97ba-3eefee4784ed','<div class=\"paragraph\">\n<p>This section walks you through setting up the PGvector <code>VectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://github.com/pgvector/pgvector\">PGvector</a> is an open-source extension for PostgreSQL that enables storing and searching over machine learning-generated embeddings. It provides different capabilities that let users identify both exact and approximate nearest neighbors. It is designed to work seamlessly with other PostgreSQL features, including indexing and querying.</p>\n</div>',0x00,'asciidoc::pgvector.adoc::0'),
('896b90e0-db12-472e-a3b9-3f0b1dc6efac','Spring AI provides Spring Boot auto-configuration for the OpenAI SDK Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai-sdk&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai-sdk\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::openai-sdk-embeddings.adoc::Auto-configuration::0'),
('ff98f8b8-d141-480d-a99b-3f0ce934a2cb','<div class=\"paragraph\">\n<p>Spring AI builds upon the observability features in the Spring ecosystem to provide insights into AI-related operations.</p>\n</div>\n<div class=\"paragraph\">\n<p>The spring-boot-actuator module is required for enabling observability.\nAdd the Spring Boot Actuator dependency to your project&#8217;s Maven <code>pom.xml</code> build file:</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;\n &lt;artifactId&gt;spring-boot-starter-actuator&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n<div class=\"paragraph\">\n<p>or to your Gradle <code>build.gradle</code> build file.</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.boot:spring-boot-starter-actuator\'\n}</code></pre>\n</div>\n</div>\n<div class=\"paragraph\">\n<p>Spring AI provides metrics and tracing capabilities for its core components: <code>ChatClient</code> (including <code>Advisor</code>),\n<code>ChatModel</code>, <code>EmbeddingModel</code>, <code>ImageModel</code>, and <code>VectorStore</code>.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nLow cardinality keys will be added to metrics and traces, while high cardinality keys will only be added to traces.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"admonitionblock warning\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Warning</div>\n</td>\n<td class=\"content\">\n<div class=\"paragraph\">\n<p><strong>1.0.0-RC1 Breaking Changes</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Following configuration properties have been renamed to better reflect their purpose:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p><code>spring.ai.chat.client.observations.include-prompt</code> → <code>spring.ai.chat.client.observations.log-prompt</code></p>\n</li>\n<li>\n<p><code>spring.ai.chat.observations.include-prompt</code> → <code>spring.ai.chat.observations.log-prompt</code></p>\n</li>\n<li>\n<p><code>spring.ai.chat.observations.include-completion</code> → <code>spring.ai.chat.observations.log-completion</code></p>\n</li>\n<li>\n<p><code>spring.ai.image.observations.include-prompt</code> → <code>spring.ai.image.observations.log-prompt</code></p>\n</li>\n<li>\n<p><code>spring.ai.vectorstore.observations.include-query-response</code> → <code>spring.ai.vectorstore.observations.log-query-response</code></p>\n</li>\n</ul>\n</div>\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::index.adoc::0'),
('dc5851d1-b468-4278-baf4-3f58eccbc63b','For keyless authentication using Microsoft Entra ID (formerly Azure Active Directory), set <em>only</em> the <code>spring.ai.azure.openai.endpoint</code> configuration property and <em>not</em> the api-key property mentioned above.\n\nFinding only the endpoint property, your application will evaluate several different options for retrieving credentials and an <code>OpenAIClient</code> instance will be created using the token credentials.\n\nIt is no longer necessary to create a <code>TokenCredential</code> bean; it is configured for you automatically.',0x00,'asciidoc::azure-openai-embeddings.adoc::Prerequisites::Microsoft Entra ID::0'),
('2a1d30ab-bf05-4edb-b3af-3f72e7fc3d57','Here is the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/model/ChatModel.java\">ChatModel</a> interface definition:\n\npublic interface ChatModel extends Model&lt;Prompt, ChatResponse&gt;, StreamingChatModel {\n\n	default String call(String message) {...}\n\n    @Override\n	ChatResponse call(Prompt prompt);\n}\n\nThe <code>call()</code> method with a <code>String</code> parameter simplifies initial use, avoiding the complexities of the more sophisticated <code>Prompt</code> and <code>ChatResponse</code> classes.\nIn real-world applications, it is more common to use the <code>call()</code> method that takes a <code>Prompt</code> instance and returns a <code>ChatResponse</code>.',0x00,'asciidoc::chatmodel.adoc::API Overview::ChatModel::0'),
('d5b14b0f-2005-4a0c-b1bb-3f72f637b553','Tokens are essential in how AI models process text, acting as a bridge that converts words (as we understand them) into a format that AI models can process.\nThis conversion occurs in two stages: words are transformed into tokens upon input, and these tokens are then converted back into words in the output.\n\nTokenization, the process of breaking down text into tokens, is fundamental to how AI models comprehend and process language.\nThe AI model works with this tokenized format to understand and respond to prompts.\n\nTo better understand tokens, think of them as portions of words. Typically, a token represents about three-quarters of a word. For instance, the complete works of Shakespeare, totaling roughly 900,000 words, would translate to around 1.2 million tokens.\n\nExperiment with the <a href=\"https://platform.openai.com/tokenizer\">OpenAI Tokenizer UI</a> to see how words are converted into tokens.\n\nTokens have practical implications beyond their technical role in AI processing, especially regarding billing and model capabilities:\n\nBilling: AI model services often bill based on token usage. Both the input (prompt) and the output (response) contribute to the total token count, making shorter prompts more cost-effective.\nModel Limits: Different AI models have varying token limits, defining their \"context window\" – the maximum amount of information they can process at a time. For example, GPT-3&#8217;s limit is 4K tokens, while other models like Claude 2 and Meta Llama 2 have limits of 100K tokens, and some research models can handle up to 1 million tokens.\nContext Window: A model&#8217;s token limit determines its context window. Inputs exceeding this limit are not processed by the model. It&#8217;s crucial to send only the minimal effective set of information for processing. For example, when inquiring about \"Hamlet,\" there&#8217;s no need to include tokens from all of Shakespeare&#8217;s other works.\nResponse Metadata: The metadata of a response from an AI model includes the number of tokens used, a vital piece of information for managing usage and costs.',0x00,'asciidoc::prompt.adoc::Tokens::0'),
('5a4c1760-98bd-41cc-b6fc-3fca7d39490d','public record Op(Filter.Operand expression) {\n\n    public Filter.Expression build() {\n        if (this.expression instanceof Filter.Group group) {\n            // Remove the top-level grouping.\n            return group.content();\n        } else if (this.expression instanceof Filter.Expression exp) {\n            return exp;\n        }\n        throw new RuntimeException(\"Invalid expression: \" + this.expression);\n    }\n}',0x01,'cu::FilterExpressionBuilder.java'),
('7b4423f3-13f7-4d98-92e9-3fe20599b869','The prompt caching implementation in Spring AI follows these key design principles:\n\n<strong>Strategic Cache Placement</strong>: Cache breakpoints are automatically placed at optimal locations based on the chosen strategy, ensuring compliance with AWS Bedrock&#8217;s 4-breakpoint limit.\n<strong>Provider Portability</strong>: Cache configuration is done through <code>BedrockChatOptions</code> rather than individual messages, preserving compatibility when switching between different AI providers.\n<strong>Thread Safety</strong>: The cache breakpoint tracking is implemented with thread-safe mechanisms to handle concurrent requests correctly.\n<strong>UNION Type Pattern</strong>: AWS SDK uses UNION types where cache points are added as separate blocks rather than properties.\nThis is different from direct API approaches but ensures type safety and API compliance.\n<strong>Incremental Caching</strong>: The <code>CONVERSATION_HISTORY</code> strategy places cache breakpoints on the last user message, enabling incremental caching where each conversation turn builds on the previous cached prefix.',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Implementation Details::0'),
('fa5c0749-afbf-47db-a2de-403eaa39c20b','Tree of Thoughts (ToT) is an advanced reasoning framework that extends Chain of Thought by exploring multiple reasoning paths simultaneously. It treats problem-solving as a search process where the model generates different intermediate steps, evaluates their promise, and explores the most promising paths.\n\nThis technique is particularly powerful for complex problems with multiple possible approaches or when the solution requires exploring various alternatives before finding the optimal path.\n\n<div class=\"paragraph\">\n<p>The original \"Prompt Engineering\" guide doesn&#8217;t provide implementation examples for ToT, likely due to its complexity. Below is a simplified example that demonstrates the core concept.</p>\n</div>\n\nGame Solving ToT Example:\n\n// Implementation of Section 2.7: Tree of Thoughts (ToT) - Game solving example\npublic void pt_tree_of_thoughts_game(ChatClient chatClient) {\n    // Step 1: Generate multiple initial moves\n    String initialMoves = chatClient\n            .prompt(\"\"\"\n                    You are playing a game of chess. The board is in the starting position.\n                    Generate 3 different possible opening moves. For each move:\n                    1. Describe the move in algebraic notation\n                    2. Explain the strategic thinking behind this move\n                    3. Rate the move\'s strength from 1-10\n                    \"\"\")\n            .options(ChatOptions.builder()\n                    .temperature(0.7)\n                    .build())\n            .call()\n            .content();\n\n    // Step 2: Evaluate and select the most promising move\n    String bestMove = chatClient\n            .prompt()\n            .user(u -&gt; u.text(\"\"\"\n                    Analyze these opening moves and select the strongest one:\n                    {moves}\n\n                    Explain your reasoning step by step, considering:\n                    1. Position control\n                    2. Development potential\n                    3. Long-term strategic advantage\n\n                    Then select the single best move.\n                    \"\"\").param(\"moves\", initialMoves))\n            .call()\n            .content();\n\n    // Step 3: Explore future game states from the best move\n    String gameProjection = chatClient\n            .prompt()\n            .user(u -&gt; u.text(\"\"\"\n                    Based on this selected opening move:\n                    {best_move}\n\n                    Project the next 3 moves for both players. For each potential branch:\n                    1. Describe the move and counter-move\n                    2. Evaluate the resulting position\n                    3. Identify the most promising continuation\n\n                    Finally, determine the most advantageous sequence of moves.\n                    \"\"\").param(\"best_move\", bestMove))\n            .call()\n            .content();\n}',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.7 Tree of Thoughts (ToT)::0'),
('ba9e70ff-33cf-427f-a51a-403f3dc1ece3','/**\n * A functional interface that provides read-only access to vector store retrieval\n * operations. This interface extracts only the document retrieval functionality from\n * {@link VectorStore}, ensuring that mutation operations (add, delete) are not exposed.\n *\n * <p>\n * This is useful when you want to provide retrieval-only access to a vector store,\n * following the principle of least privilege by not exposing write operations.\n *\n * @author Mark Pollack\n * @since 1.0.0\n */\n@FunctionalInterface\npublic interface VectorStoreRetriever {\n\n    /**\n     * Retrieves documents by query embedding similarity and metadata filters to retrieve\n     * exactly the number of nearest-neighbor results that match the request criteria.\n     * @param request Search request for set search parameters, such as the query text,\n     * topK, similarity threshold and metadata filter expressions.\n     * @return Returns documents that match the query request conditions.\n     */\n    List<Document> similaritySearch(SearchRequest request);\n\n    /**\n     * Retrieves documents by query embedding similarity using the default\n     * {@link SearchRequest}\'s search criteria.\n     * @param query Text to use for embedding similarity comparison.\n     * @return Returns a list of documents that have embeddings similar to the query text\n     * embedding.\n     */\n    default List<Document> similaritySearch(String query) {\n        return this.similaritySearch(SearchRequest.builder().query(query).build());\n    }\n}',0x01,'cu::VectorStoreRetriever.java'),
('5bff66de-416e-4ef2-9756-4064d5690117','Create a CassandraVectorStore instance as a Spring Bean:\n\n@Bean\npublic VectorStore vectorStore(CqlSession session, EmbeddingModel embeddingModel) {\n    return CassandraVectorStore.builder(embeddingModel)\n        .session(session)\n        .keyspace(\"my_keyspace\")\n        .table(\"my_vectors\")\n        .build();\n}\n\nOnce you have the vector store instance, you can add documents and perform searches:\n\n// Add documents\nvectorStore.add(List.of(\n    new Document(\"1\", \"content1\", Map.of(\"key1\", \"value1\")),\n    new Document(\"2\", \"content2\", Map.of(\"key2\", \"value2\"))\n));\n\n// Search with filters\nList&lt;Document&gt; results = vectorStore.similaritySearch(\n    SearchRequest.query(\"search text\")\n        .withTopK(5)\n        .withSimilarityThreshold(0.7f)\n        .withFilterExpression(\"metadata.key1 == \'value1\'\")\n);',0x00,'asciidoc::apache-cassandra.adoc::Usage::Basic Usage::0'),
('3fe46025-54ad-4a5b-bd74-40ee493d4839','To enable native structured output, use the <code>AdvisorParams.ENABLE_NATIVE_STRUCTURED_OUTPUT</code> parameter:\n\nActorsFilms actorsFilms = ChatClient.create(chatModel).prompt()\n    .advisors(AdvisorParams.ENABLE_NATIVE_STRUCTURED_OUTPUT)\n    .user(\"Generate the filmography for a random actor.\")\n    .call()\n    .entity(ActorsFilms.class);\n\nYou can also set this globally using <code>defaultAdvisors()</code> on the <code>ChatClient.Builder</code>:\n\n@Bean\nChatClient chatClient(ChatClient.Builder builder) {\n    return builder\n        .defaultAdvisors(AdvisorParams.ENABLE_NATIVE_STRUCTURED_OUTPUT)\n        .build();\n}',0x00,'asciidoc::structured-output-converter.adoc::Native Structured Output::Using Native Structured Output::0'),
('465d3535-8c1f-4d33-999d-40ff406f11fb','You can leverage the generic, portable <a href=\"https://docs.spring.io/spring-ai/reference/api/vectordbs.html#_metadata_filters\">metadata filters</a> with ChromaVector store as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n                    SearchRequest.builder()\n                            .query(\"The World\")\n                            .topK(TOP_K)\n                            .similarityThreshold(SIMILARITY_THRESHOLD)\n                            .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n                    .query(\"The World\")\n                    .topK(TOP_K)\n                    .similarityThreshold(SIMILARITY_THRESHOLD)\n                    .filterExpression(b.and(\n                            b.in(\"john\", \"jill\"),\n                            b.eq(\"article_type\", \"blog\")).build()).build());\n\nThose (portable) filter expressions get automatically converted into the proprietary Chroma <code>where</code> <a href=\"https://docs.trychroma.com/usage-guide#using-where-filters\">filter expressions</a>.\n\nFor example, this portable filter expression:\n\nauthor in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\n\nis converted into the proprietary Chroma format\n\n{\"$and\":[\n	{\"author\": {\"$in\": [\"john\", \"jill\"]}},\n	{\"article_type\":{\"$eq\":\"blog\"}}]\n}',0x00,'asciidoc::chroma.adoc::Metadata filtering::0'),
('86338f9f-94cb-4954-b10c-410158d36421','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Azure Ollama Embedding Model.\nTo enable it add the following dependency to your Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n   &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n   &lt;artifactId&gt;spring-ai-starter-model-ollama&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-ollama\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\nSpring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the Repositories section to add these repositories to your build system.',0x00,'asciidoc::ollama-embeddings.adoc::Auto-configuration::0'),
('40886f3b-2c2e-45d8-aca7-4113951e3840','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Azure MiniMax Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-minimax&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-minimax\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::minimax-embeddings.adoc::Auto-configuration::0'),
('f92f662e-234b-4793-930b-416b6fc229a3','<div class=\"paragraph\">\n<p>This section describes core concepts that Spring AI uses. We recommend reading it closely to understand the ideas behind how Spring AI is implemented.</p>\n</div>',0x00,'asciidoc::concepts.adoc::0'),
('ca803fd8-7a2d-433e-885d-417e64e16c4c','Since HanaDB vector store support does not provide the autoconfiguration module, you also need to provide the vector store bean in your application, as shown below, as an example.\n\n@Bean\npublic VectorStore hanaCloudVectorStore(CricketWorldCupRepository cricketWorldCupRepository,\n        EmbeddingModel embeddingModel) {\n\n    return HanaCloudVectorStore.builder(cricketWorldCupRepository, embeddingModel)\n        .tableName(\"CRICKET_WORLD_CUP\")\n        .topK(1)\n        .build();\n}\n\nUse a <code>contextual</code> pdf file from wikipedia\n\n\nGo to <a href=\"https://en.wikipedia.org/wiki/Cricket_World_Cup\">wikipedia</a> and <a href=\"https://en.wikipedia.org/w/index.php?title=Special:DownloadAsPdf&amp;page=Cricket_World_Cup&amp;action=show-download-screen\">download</a> <code>Cricket World Cup</code> page as a PDF file.\n\nUpload this PDF file using the file-upload REST endpoint that we created in the previous step.',0x00,'asciidoc::hana.adoc::Build a Sample RAG application::Create an <code>Entity</code> class named <code>CricketWorldCup</code> that extends from <code>HanaVectorEntity</code>:::3'),
('7ed84c16-f33d-4ee8-aaf7-41fe689ad435','Refer to <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/getting-started.html\">Getting started with Amazon Bedrock</a> for setting up API access\n\nObtain AWS credentials: If you don&#8217;t have an AWS account and AWS CLI configured yet, this video guide can help you configure it: <a href=\"https://youtu.be/gswVHTrRX8I?si=buaY7aeI0l3-bBVb\">AWS CLI &amp; SDK Setup in Less Than 4 Minutes!</a>. You should be able to obtain your access and security keys.\nEnable the Models to use: Go to <a href=\"https://us-east-1.console.aws.amazon.com/bedrock/home\">Amazon Bedrock</a> and from the <a href=\"https://us-east-1.console.aws.amazon.com/bedrock/home?region=us-east-1#/modelaccess\">Model Access</a> menu on the left, configure access to the models you are going to use.',0x00,'asciidoc::bedrock-converse.adoc::Prerequisites::0'),
('b330514f-c07b-43d5-a474-4216abfaacb3','Prompts serve as the foundation for the language-based inputs that guide an AI model to produce specific outputs.\nFor those familiar with ChatGPT, a prompt might seem like merely the text entered into a dialog box that is sent to the API.\nHowever, it encompasses much more than that.\nIn many AI Models, the text for the prompt is not just a simple string.\n\nChatGPT&#8217;s API has multiple text inputs within a prompt, with each text input being assigned a role.\nFor example, there is the system role, which tells the model how to behave and sets the context for the interaction.\nThere is also the user role, which is typically the input from the user.\n\nCrafting effective prompts is both an art and a science.\nChatGPT was designed for human conversations.\nThis is quite a departure from using something like SQL to \"ask a question\".\nOne must communicate with the AI model akin to conversing with another person.\n\nSuch is the importance of this interaction style that the term \"Prompt Engineering\" has emerged as its own discipline.\nThere is a burgeoning collection of techniques that improve the effectiveness of prompts.\nInvesting time in crafting a prompt can drastically improve the resulting output.\n\nSharing prompts has become a communal practice, and there is active academic research being done on this subject.\nAs an example of how counter-intuitive it can be to create an effective prompt (for example, contrasting with SQL), a <a href=\"https://arxiv.org/abs/2205.11916\">recent research paper</a> found that one of the most effective prompts you can use starts with the phrase, &#8220;Take a deep breath and work on this step by step.&#8221;\nThat should give you an indication of why language is so important.\nWe do not yet fully understand how to make the most effective use of previous iterations of this technology, such as ChatGPT 3.5, let alone new versions that are being developed.',0x00,'asciidoc::concepts.adoc::Prompts::0'),
('222a1923-fff9-4641-83a6-4250be4f8f3e','/**\n * Documented conventions for vector store observations.\n *\n * @author Christian Tzolov\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic enum VectorStoreObservationDocumentation implements ObservationDocumentation {\n\n    /**\n     * Vector Store observations for clients.\n     */\n    AI_VECTOR_STORE {\n\n        @Override\n        public Class<? extends ObservationConvention<? extends Observation.Context>> getDefaultConvention() {\n            return DefaultVectorStoreObservationConvention.class;\n        }\n\n        @Override\n        public KeyName[] getLowCardinalityKeyNames() {\n            return LowCardinalityKeyNames.values();\n        }\n\n        @Override\n        public KeyName[] getHighCardinalityKeyNames() {\n            return HighCardinalityKeyNames.values();\n        }\n    }\n    ;\n\n    /**\n     * Low-cardinality observation key names for vector store operations.\n     */\n    public enum LowCardinalityKeyNames implements KeyName {\n\n        /**\n         * Spring AI kind.\n         */\n        SPRING_AI_KIND {\n\n            @Override\n            public String asString() {\n                return \"spring.ai.kind\";\n            }\n        }\n        ,\n        /**\n         * The name of the operation or command being executed.\n         */\n        DB_OPERATION_NAME {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_OPERATION_NAME.value();\n            }\n        }\n        ,\n        /**\n         * The database management system (DBMS) product as identified by the client\n         * instrumentation.\n         */\n        DB_SYSTEM {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_SYSTEM.value();\n            }\n        }\n\n    }\n\n    /**\n     * High-cardinality observation key names for vector store operations.\n     */\n    public enum HighCardinalityKeyNames implements KeyName {\n\n        // DB General\n        /**\n         * The name of a collection (table, container) within the database.\n         */\n        DB_COLLECTION_NAME {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_COLLECTION_NAME.value();\n            }\n        }\n        ,\n        /**\n         * The namespace of the database.\n         */\n        DB_NAMESPACE {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_NAMESPACE.value();\n            }\n        }\n        ,\n        // DB Search\n        /**\n         * The metric used in similarity search.\n         */\n        DB_SEARCH_SIMILARITY_METRIC {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_SEARCH_SIMILARITY_METRIC.value();\n            }\n        }\n        ,\n        // DB Vector\n        /**\n         * The dimension of the vector.\n         */\n        DB_VECTOR_DIMENSION_COUNT {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_VECTOR_DIMENSION_COUNT.value();\n            }\n        }\n        ,\n        /**\n         * The name field as of the vector (e.g. a field name).\n         */\n        DB_VECTOR_FIELD_NAME {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_VECTOR_FIELD_NAME.value();\n            }\n        }\n        ,\n        /**\n         * The content of the search query being executed.\n         */\n        DB_VECTOR_QUERY_CONTENT {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_VECTOR_QUERY_CONTENT.value();\n            }\n        }\n        ,\n        /**\n         * The metadata filters used in the search query.\n         */\n        DB_VECTOR_QUERY_FILTER {\n\n            @Override\n            public String asString() {\n                return \"db.vector.query.filter\";\n            }\n        }\n        ,\n        /**\n         * Similarity threshold that accepts all search scores. A threshold value of 0.0\n         * means any similarity is accepted or disable the similarity threshold filtering.\n         * A threshold value of 1.0 means an exact match is required.\n         */\n        DB_VECTOR_QUERY_SIMILARITY_THRESHOLD {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_VECTOR_QUERY_SIMILARITY_THRESHOLD.value();\n            }\n        }\n        ,\n        /**\n         * The top-k most similar vectors returned by a query.\n         */\n        DB_VECTOR_QUERY_TOP_K {\n\n            @Override\n            public String asString() {\n                return VectorStoreObservationAttributes.DB_VECTOR_QUERY_TOP_K.value();\n            }\n        }\n\n    }\n}',0x01,'cu::VectorStoreObservationDocumentation.java'),
('3f754c6b-3569-4a79-8b04-42f667c0fac7','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Google GenAI Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-google-genai-embedding&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-google-genai-embedding\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::google-genai-embeddings-text.adoc::Auto-configuration::0'),
('fca8608a-c0dd-497f-8a1c-43303b4864fe','The Vertex AI Gemini model supports tool calling (in Google Gemini context, it&#8217;s called <code>function calling</code>) capabilities, allowing models to use tools during conversations.\nHere&#8217;s an example of how to define and use <code>@Tool</code>-based tools:\n\npublic class WeatherService {\n\n    @Tool(description = \"Get the weather in location\")\n    public String weatherByLocation(@ToolParam(description= \"City or state name\") String location) {\n        ...\n    }\n}\n\nString response = ChatClient.create(this.chatModel)\n        .prompt(\"What\'s the weather like in Boston?\")\n        .tools(new WeatherService())\n        .call()\n        .content();\n\nYou can use the java.util.function beans as tools as well:\n\n@Bean\n@Description(\"Get the weather in location. Return temperature in 36°F or 36°C format.\")\npublic Function&lt;Request, Response&gt; weatherFunction() {\n    return new MockWeatherService();\n}\n\nString response = ChatClient.create(this.chatModel)\n        .prompt(\"What\'s the weather like in Boston?\")\n        .toolNames(\"weatherFunction\")\n        .inputType(Request.class)\n        .call()\n        .content();\n\nFind more in <a href=\"api/tools.html\">Tools</a> documentation.',0x00,'asciidoc::vertexai-gemini-chat.adoc::Tool Calling::0'),
('128a9ab2-0eec-4839-a61e-4372ac7fbb62','@SuppressWarnings(\"CheckReturnValue\")\npublic static class DecimalConstantContext extends ConstantContext {\n\n    public TerminalNode DECIMAL_VALUE() {\n        return getToken(FiltersParser.DECIMAL_VALUE, 0);\n    }\n\n    public TerminalNode MINUS() {\n        return getToken(FiltersParser.MINUS, 0);\n    }\n\n    public TerminalNode PLUS() {\n        return getToken(FiltersParser.PLUS, 0);\n    }\n\n    public DecimalConstantContext(ConstantContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterDecimalConstant(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitDecimalConstant(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitDecimalConstant(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('b2119aef-26e1-4537-abb7-43866764b5ff','The prefix <code>spring.ai.bedrock.aws</code> is the property prefix to configure the connection to AWS Bedrock.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=bedrock-cohere (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match bedrock-cohere)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.bedrock.cohere.embedding</code> (defined in <code>BedrockCohereEmbeddingProperties</code>) is the property prefix that configures the embedding model implementation for Cohere.\n\n\n\nWhen accessing Cohere via Amazon Bedrock, the functionality of truncating is not available.  This is an issue with Amazon Bedrock.   The Spring AI class <code>BedrockCohereEmbeddingModel</code> will truncate to 2048 character length, which is the maximum supported by the model.\n\nLook at the <a href=\"https://github.com/spring-projects/spring-ai/blob/056b95a00efa5b014a1f488329fbd07a46c02378/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/cohere/api/CohereEmbeddingBedrockApi.java#L150\">CohereEmbeddingModel</a> for other model IDs.\nSupported values are: <code>cohere.embed-multilingual-v3</code> and <code>cohere.embed-english-v3</code>.\nModel ID values can also be found in the <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/model-ids-arns.html\">AWS Bedrock documentation for base model IDs</a>.\n\nAll properties prefixed with <code>spring.ai.bedrock.cohere.embedding.options</code> can be overridden at runtime by adding a request specific <a href=\"#embedding-options\">Runtime Options</a> to the <code>EmbeddingRequest</code> call.',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Auto-configuration::Embedding Properties::0'),
('28a2e5b6-7600-4366-a8d2-43eef37c7ffc','ChatModel chatModel = // initialize your chat model\nSummaryMetadataEnricher enricher = new SummaryMetadataEnricher(chatModel,\n    List.of(SummaryType.PREVIOUS, SummaryType.CURRENT, SummaryType.NEXT));\n\nDocument doc1 = new Document(\"Content of document 1\");\nDocument doc2 = new Document(\"Content of document 2\");\n\nList&lt;Document&gt; enrichedDocs = enricher.apply(List.of(this.doc1, this.doc2));\n\n// Check the metadata of the enriched documents\nfor (Document doc : enrichedDocs) {\n    System.out.println(\"Current summary: \" + doc.getMetadata().get(\"section_summary\"));\n    System.out.println(\"Previous summary: \" + doc.getMetadata().get(\"prev_section_summary\"));\n    System.out.println(\"Next summary: \" + doc.getMetadata().get(\"next_section_summary\"));\n}\n\nThe provided example demonstrates the expected behavior:\n\nFor a list of two documents, both documents receive a <code>section_summary</code>.\nThe first document receives a <code>next_section_summary</code> but no <code>prev_section_summary</code>.\nThe second document receives a <code>prev_section_summary</code> but no <code>next_section_summary</code>.\nThe <code>section_summary</code> of the first document matches the <code>prev_section_summary</code> of the second document.\nThe <code>next_section_summary</code> of the first document matches the <code>section_summary</code> of the second document.\n\n\nNotes\n\nThe <code>SummaryMetadataEnricher</code> requires a functioning <code>ChatModel</code> to generate summaries.\nThe enricher can handle document lists of any size, properly handling edge cases for the first and last documents.\nThis enricher is particularly useful for creating context-aware summaries, allowing for better understanding of document relationships in a sequence.\nThe <code>MetadataMode</code> parameter allows control over how existing metadata is incorporated into the summary generation process.',0x00,'asciidoc::etl-pipeline.adoc::Transformers::SummaryMetadataEnricher::1'),
('dd1cf8fa-e48d-48a2-abfe-43fb411c8b90','The following example shows how to use <code>BeanOutputConverter</code> to generate the filmography for an actor.\n\nThe target record representing actor&#8217;s filmography:\n\nrecord ActorsFilms(String actor, List&lt;String&gt; movies) {\n}\n\nHere is how to apply the BeanOutputConverter using the high-level, fluent <code>ChatClient</code> API:\n\nActorsFilms actorsFilms = ChatClient.create(chatModel).prompt()\n        .user(u -&gt; u.text(\"Generate the filmography of 5 movies for {actor}.\")\n                    .param(\"actor\", \"Tom Hanks\"))\n        .call()\n        .entity(ActorsFilms.class);\n\nor using the low-level <code>ChatModel</code> API directly:\n\nBeanOutputConverter&lt;ActorsFilms&gt; beanOutputConverter =\n    new BeanOutputConverter&lt;&gt;(ActorsFilms.class);\n\nString format = this.beanOutputConverter.getFormat();\n\nString actor = \"Tom Hanks\";\n\nString template = \"\"\"\n        Generate the filmography of 5 movies for {actor}.\n        {format}\n        \"\"\";\n\nGeneration generation = chatModel.call(\n    PromptTemplate.builder().template(this.template).variables(Map.of(\"actor\", this.actor, \"format\", this.format)).build().create()).getResult();\n\nActorsFilms actorsFilms = this.beanOutputConverter.convert(this.generation.getOutput().getText());',0x00,'asciidoc::structured-output-converter.adoc::Using Converters::Bean Output Converter::0'),
('b55d2d66-adb0-46ec-8cf3-4443e72ffb2d','If you are not using Spring Boot, you can manually configure the OpenAI Embedding Model.\nFor this add the <code>spring-ai-openai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThe <code>spring-ai-openai</code> dependency provides access also to the <code>OpenAiChatModel</code>.\nFor more information about the <code>OpenAiChatModel</code> refer to the <a href=\"../chat/openai-chat.html\">OpenAI Chat Client</a> section.\n\nNext, create an <code>OpenAiEmbeddingModel</code> instance and use it to compute the similarity between two input texts:\n\nvar openAiApi = OpenAiApi.builder()\n                .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n                .build();\n\nvar embeddingModel = new OpenAiEmbeddingModel(\n		this.openAiApi,\n        MetadataMode.EMBED,\n        OpenAiEmbeddingOptions.builder()\n                .model(\"text-embedding-ada-002\")\n                .user(\"user-6\")\n                .build(),\n        RetryUtils.DEFAULT_RETRY_TEMPLATE);\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n        .embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));\n\nThe <code>OpenAiEmbeddingOptions</code> provides the configuration information for the embedding requests.\nThe api and options class offers a <code>builder()</code> for easy options creation.',0x00,'asciidoc::openai-embeddings.adoc::Manual Configuration::0'),
('6209d5be-43ca-463a-9aee-44c230918ec7','@SuppressWarnings(\"CheckReturnValue\")\npublic static class TextConstantContext extends ConstantContext {\n\n    public List<TerminalNode> QUOTED_STRING() {\n        return getTokens(FiltersParser.QUOTED_STRING);\n    }\n\n    public TerminalNode QUOTED_STRING(int i) {\n        return getToken(FiltersParser.QUOTED_STRING, i);\n    }\n\n    public TextConstantContext(ConstantContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterTextConstant(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitTextConstant(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitTextConstant(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('14cf0055-85d0-4823-a7ac-44d7d152e8b4','ChatModel chatModel = ...\nToolCallback toolCallback = ...\nChatOptions chatOptions = ToolCallingChatOptions.builder()\n    .toolCallbacks(toolCallback)\n    .build():\nPrompt prompt = new Prompt(\"What day is tomorrow?\", chatOptions);\nchatModel.call(prompt);\n\nAdding Default Tools to <code>ChatModel</code>\n\nWhen using the programmatic specification approach, you can add default tools to a <code>ChatModel</code> at construction time by passing the <code>MethodToolCallback</code> instance to the <code>toolCallbacks()</code> method of the <code>ToolCallingChatOptions</code> instance used to create the <code>ChatModel</code>.\nIf both default and runtime tools are provided, the runtime tools will completely override the default tools.\n\nDefault tools are shared across all the chat requests performed by that <code>ChatModel</code> instance. They are useful for tools that are commonly used across different chat requests, but they can also be dangerous if not used carefully, risking to make them available when they shouldn&#8217;t.\n\nToolCallback toolCallback = ...\nChatModel chatModel = OllamaChatModel.builder()\n    .ollamaApi(OllamaApi.builder().build())\n    .defaultOptions(ToolCallingChatOptions.builder()\n            .toolCallbacks(toolCallback)\n            .build())\n    .build();',0x00,'asciidoc::tools.adoc::Methods as Tools::Programmatic Specification: <code>MethodToolCallback</code>::3'),
('cb6136d5-17c9-47a8-8ee4-44d94618444c','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-anthropic/src/main/java/org/springframework/ai/anthropic/AnthropicChatOptions.java\">AnthropicChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the max token count, etc.\n\nOn start-up, the default options can be configured with the <code>AnthropicChatModel(api, options)</code> constructor or the <code>spring.ai.anthropic.chat.options.*</code> properties.\n\nAt run-time you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        AnthropicChatOptions.builder()\n            .model(\"claude-3-7-sonnet-latest\")\n            .temperature(0.4)\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-anthropic/src/main/java/org/springframework/ai/anthropic/AnthropicChatOptions.java\">AnthropicChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::anthropic-chat.adoc::Runtime Options::0'),
('3f285ddc-df96-48b3-845a-44f3f976bfa6','/**\n * The {@code VectorStore} interface defines the operations for managing and querying\n * documents in a vector database. It extends {@link DocumentWriter} to support document\n * writing operations. Vector databases are specialized for AI applications, performing\n * similarity searches based on vector representations of data rather than exact matches.\n * This interface allows for adding, deleting, and searching documents based on their\n * similarity to a given query.\n */\npublic interface VectorStore extends DocumentWriter, VectorStoreRetriever {\n\n    default String getName() {\n        return this.getClass().getSimpleName();\n    }\n\n    /**\n     * Adds list of {@link Document}s to the vector store.\n     * @param documents the list of documents to store. Throws an exception if the\n     * underlying provider checks for duplicate IDs.\n     */\n    void add(List<Document> documents);\n\n    @Override\n    default void accept(List<Document> documents) {\n        add(documents);\n    }\n\n    /**\n     * Deletes documents from the vector store.\n     * @param idList list of document ids for which documents will be removed.\n     */\n    void delete(List<String> idList);\n\n    /**\n     * Deletes documents from the vector store based on filter criteria.\n     * @param filterExpression Filter expression to identify documents to delete\n     * @throws IllegalStateException if the underlying delete causes an exception\n     */\n    void delete(Filter.Expression filterExpression);\n\n    /**\n     * Deletes documents from the vector store using a string filter expression. Converts\n     * the string filter to an Expression object and delegates to\n     * {@link #delete(Filter.Expression)}.\n     * @param filterExpression String representation of the filter criteria\n     * @throws IllegalArgumentException if the filter expression is null\n     * @throws IllegalStateException if the underlying delete causes an exception\n     */\n    default void delete(String filterExpression) {\n        SearchRequest searchRequest = SearchRequest.builder().filterExpression(filterExpression).build();\n        Filter.Expression textExpression = searchRequest.getFilterExpression();\n        Assert.notNull(textExpression, \"Filter expression must not be null\");\n        this.delete(textExpression);\n    }\n\n    /**\n     * Returns the native client if available in this vector store implementation.\n     *\n     * Note on usage: 1. Returns empty Optional when no native client is available 2. Due\n     * to Java type erasure, runtime type checking is not possible\n     *\n     * Example usage: When working with implementation with known native client:\n     * Optional<NativeClientType> client = vectorStore.getNativeClient();\n     *\n     * Note: Using Optional<?> will return the native client if one exists, rather than an\n     * empty Optional. For type safety, prefer using the specific client type.\n     * @return Optional containing native client if available, empty Optional otherwise\n     * @param <T> The type of the native client\n     */\n    default <T> Optional<T> getNativeClient() {\n        return Optional.empty();\n    }\n\n    /**\n     * Builder interface for creating VectorStore instances. Implements a fluent builder\n     * pattern for configuring observation-related settings.\n     *\n     * @param <T> the concrete builder type, enabling method chaining with the correct\n     * return type\n     */\n    interface Builder<T extends Builder<T>> {\n\n        /**\n         * Sets the registry for collecting observations and metrics. Defaults to\n         * {@link ObservationRegistry#NOOP} if not specified.\n         * @param observationRegistry the registry to use for observations\n         * @return the builder instance for method chaining\n         */\n        T observationRegistry(ObservationRegistry observationRegistry);\n\n        /**\n         * Sets a custom convention for creating observations. If not specified,\n         * {@link DefaultVectorStoreObservationConvention} will be used.\n         * @param convention the custom observation convention to use\n         * @return the builder instance for method chaining\n         */\n        T customObservationConvention(VectorStoreObservationConvention convention);\n\n        /**\n         * Sets the batching strategy.\n         * @param batchingStrategy the strategy to use\n         * @return the builder instance for method chaining\n         */\n        T batchingStrategy(BatchingStrategy batchingStrategy);\n\n        /**\n         * Builds and returns a new VectorStore instance with the configured settings.\n         * @return a new VectorStore instance\n         */\n        VectorStore build();\n    }\n}',0x01,'cu::VectorStore.java'),
('48670029-c1b9-4a3f-95b3-45b3edabe4bb','You can customize the database and container names using the configuration properties mentioned above.',0x00,'asciidoc::chat-memory.adoc::Memory Storage::CosmosDBChatMemoryRepository::1'),
('4175e8f2-ae89-4aca-aa08-463b75896cf0','The <code>Usage</code> record provides detailed information about cache-related token consumption.\nTo access Anthropic-specific cache metrics, use the <code>getNativeUsage()</code> method:\n\nAnthropicApi.Usage usage = (AnthropicApi.Usage) response.getMetadata()\n    .getUsage().getNativeUsage();\n\nCache-specific metrics include:\n\n<code>cacheCreationInputTokens()</code>: Returns the number of tokens used when creating a cache entry\n<code>cacheReadInputTokens()</code>: Returns the number of tokens read from an existing cache entry\n\n\nWhen you first send a cached prompt:\n- <code>cacheCreationInputTokens()</code> will be greater than 0\n- <code>cacheReadInputTokens()</code> will be 0\n\nWhen you send the same cached prompt again:\n- <code>cacheCreationInputTokens()</code> will be 0\n- <code>cacheReadInputTokens()</code> will be greater than 0',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Token Usage Tracking::0'),
('b39eb02e-9044-41c3-87fb-468f11c84975','/**\n * Uses a large language model to compress a conversation history and a follow-up query\n * into a standalone query that captures the essence of the conversation.\n * <p>\n * This transformer is useful when the conversation history is long and the follow-up\n * query is related to the conversation context.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic class CompressionQueryTransformer implements QueryTransformer {\n\n    private static final Logger logger = LoggerFactory.getLogger(CompressionQueryTransformer.class);\n\n    private static final PromptTemplate DEFAULT_PROMPT_TEMPLATE = new PromptTemplate(\"\"\"\n        Given the following conversation history and a follow-up query, your task is to synthesize\n        a concise, standalone query that incorporates the context from the history.\n        Ensure the standalone query is clear, specific, and maintains the user\'s intent.\n        \n        Conversation history:\n        {history}\n        \n        Follow-up query:\n        {query}\n        \n        Standalone query:\n        \"\"\");\n\n    private final ChatClient chatClient;\n\n    private final PromptTemplate promptTemplate;\n\n    public CompressionQueryTransformer(ChatClient.Builder chatClientBuilder, @Nullable PromptTemplate promptTemplate) {\n        Assert.notNull(chatClientBuilder, \"chatClientBuilder cannot be null\");\n        this.chatClient = chatClientBuilder.build();\n        this.promptTemplate = promptTemplate != null ? promptTemplate : DEFAULT_PROMPT_TEMPLATE;\n        PromptAssert.templateHasRequiredPlaceholders(this.promptTemplate, \"history\", \"query\");\n    }\n\n    @Override\n    public Query transform(Query query) {\n        Assert.notNull(query, \"query cannot be null\");\n        logger.debug(\"Compressing conversation history and follow-up query into a standalone query\");\n        var compressedQueryText = this.chatClient.prompt().user(user -> user.text(this.promptTemplate.getTemplate()).param(\"history\", formatConversationHistory(query.history())).param(\"query\", query.text())).call().content();\n        if (!StringUtils.hasText(compressedQueryText)) {\n            logger.warn(\"Query compression result is null/empty. Returning the input query unchanged.\");\n            return query;\n        }\n        return query.mutate().text(compressedQueryText).build();\n    }\n\n    private String formatConversationHistory(List<Message> history) {\n        if (history.isEmpty()) {\n            return \"\";\n        }\n        return history.stream().filter(message -> message.getMessageType().equals(MessageType.USER) || message.getMessageType().equals(MessageType.ASSISTANT)).map(message -> \"%s: %s\".formatted(message.getMessageType(), message.getText())).collect(Collectors.joining(\"\\n\"));\n    }\n\n    public static Builder builder() {\n        return new Builder();\n    }\n\n    public static final class Builder {\n\n        private ChatClient.Builder chatClientBuilder;\n\n        @Nullable\n        private PromptTemplate promptTemplate;\n\n        private Builder() {\n        }\n\n        public Builder chatClientBuilder(ChatClient.Builder chatClientBuilder) {\n            this.chatClientBuilder = chatClientBuilder;\n            return this;\n        }\n\n        public Builder promptTemplate(PromptTemplate promptTemplate) {\n            this.promptTemplate = promptTemplate;\n            return this;\n        }\n\n        public CompressionQueryTransformer build() {\n            return new CompressionQueryTransformer(this.chatClientBuilder, this.promptTemplate);\n        }\n    }\n}',0x01,'cu::CompressionQueryTransformer.java'),
('fd15fc82-1d2f-4387-b3c0-46cfa8abc68e','The <code>Usage</code> interface and its default implementation <code>DefaultUsage</code> have undergone the following changes:\n\nMethod Rename:\nType Changes:\n\n\nRequired Actions\n\nReplace all calls to <code>getGenerationTokens()</code> with <code>getCompletionTokens()</code>\nUpdate <code>DefaultUsage</code> constructor calls:\n\n\n// Old (M5)\nnew DefaultUsage(Long promptTokens, Long generationTokens, Long totalTokens)\n\n// New (M6)\nnew DefaultUsage(Integer promptTokens, Integer completionTokens, Integer totalTokens)\n\nFor more information on handling Usage, refer <a href=\"api/usage-handling.html\">here</a>\n\nJSON Ser/Deser changes\n\nWhile M6 maintains backward compatibility for JSON deserialization of the <code>generationTokens</code> field, this field will be removed in M7. Any persisted JSON documents using the old field name should be updated to use <code>completionTokens</code>.\n\nExample of the new JSON format:\n\n{\n  \"promptTokens\": 100,\n  \"completionTokens\": 50,\n  \"totalTokens\": 150\n}',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M6::Changes to Usage Interface and DefaultUsage Implementation::0'),
('b2c46b2c-e4ae-45cd-8551-4731eb156492','<div class=\"paragraph\">\n<p><a href=\"https://docs.api.nvidia.com/nim/reference/llm-apis\">NVIDIA LLM API</a> is a proxy AI Inference Engine offering a wide range of models from <a href=\"https://docs.api.nvidia.com/nim/reference/llm-apis#models\">various providers</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>Spring AI integrates with the NVIDIA LLM API by reusing the existing <a href=\":api/chat/openai-chat.html\">OpenAI</a> client.\nFor this you need to set the base-url to <code>https://integrate.api.nvidia.com</code>, select one of the provided <a href=\"https://docs.api.nvidia.com/nim/reference/llm-apis#model\">LLM models</a> and get an <code>api-key</code> for it.</p>\n</div>\n<div class=\"imageblock text-center\">\n<div class=\"content\">\n<img src=\"spring-ai-nvidia-llm-api-1.jpg\" alt=\"spring ai nvidia llm api 1\">\n</div>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nNVIDIA LLM API requires the <code>max-tokens</code> parameter to be explicitly set or server error will be thrown.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"paragraph\">\n<p>Check the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/chat/proxy/NvidiaWithOpenAiChatModelIT.java\">NvidiaWithOpenAiChatModelIT.java</a> tests\nfor examples of using NVIDIA LLM API with Spring AI.</p>\n</div>',0x00,'asciidoc::nvidia-chat.adoc::0'),
('f7bb5c90-11b3-40a3-a051-473a5f21b516','Refer to the <a href=\"api/bedrock.html\">Spring AI documentation on Amazon Bedrock</a> for setting up API access.',0x00,'asciidoc::bedrock-titan-embedding.adoc::Prerequisites::0'),
('ea119df6-e8d2-4888-b971-477ccb8d8520','Spring AI provides flexible API key management through the <code>ApiKey</code> interface and its implementations. The default implementation, <code>SimpleApiKey</code>, is suitable for most use cases, but you can also create custom implementations for more complex scenarios.',0x00,'asciidoc::openai-chat.adoc::API Key Management::0'),
('6bf18932-c104-49c0-8db4-47e11c0f1de6','The <code>TikaDocumentReader</code> uses Apache Tika to extract text from a variety of document formats, such as PDF, DOC/DOCX, PPT/PPTX, and HTML. For a comprehensive list of supported formats, refer to the  <a href=\"https://tika.apache.org/3.1.0/formats.html\">Tika documentation</a>.\n\nDependencies\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-tika-document-reader&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-tika-document-reader\'\n}\n\nExample\n\n@Component\nclass MyTikaDocumentReader {\n\n    private final Resource resource;\n\n    MyTikaDocumentReader(@Value(\"classpath:/word-sample.docx\")\n                            Resource resource) {\n        this.resource = resource;\n    }\n\n    List&lt;Document&gt; loadText() {\n        TikaDocumentReader tikaDocumentReader = new TikaDocumentReader(this.resource);\n        return tikaDocumentReader.read();\n    }\n}',0x00,'asciidoc::etl-pipeline.adoc::DocumentReaders::Tika (DOCX, PPTX, HTML&#8230;&#8203;)::0'),
('3d68cbbe-4c3a-48e6-9bbe-47ffebc72314','<div class=\"paragraph\">\n<p><a href=\"https://docs.docker.com/desktop/features/model-runner/\">Docker Model Runner</a> is an AI Inference Engine offering a wide range of models from <a href=\"https://hub.docker.com/u/ai\">various providers</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>Spring AI integrates with the Docker Model Runner by reusing the existing <a href=\":api/chat/openai-chat.html\">OpenAI</a> backed <code>ChatClient</code>.\nTo do this, set the base URL to <code><a href=\"http://localhost:12434/engines\" class=\"bare\">http://localhost:12434/engines</a></code> and select one of the provided <a href=\"https://hub.docker.com/u/ai\">LLM models</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>Check the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/chat/proxy/DockerModelRunnerWithOpenAiChatModelIT.java\">DockerModelRunnerWithOpenAiChatModelIT.java</a> tests\nfor examples of how to use the Docker Model Runner with Spring AI.</p>\n</div>',0x00,'asciidoc::dmr-chat.adoc::0'),
('71be1fa1-dcaa-41a6-a304-48b426ac2dc6','/**\n * Component responsible for retrieving {@link Document}s from an underlying data source,\n * such as a search engine, a vector store, a database, or a knowledge graph.\n *\n * @author Christian Tzolov\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic interface DocumentRetriever extends Function<Query, List<Document>> {\n\n    /**\n     * Retrieves relevant documents from an underlying data source based on the given\n     * query.\n     * @param query The query to use for retrieving documents\n     * @return The list of relevant documents\n     */\n    List<Document> retrieve(Query query);\n\n    default List<Document> apply(Query query) {\n        return retrieve(query);\n    }\n}',0x01,'cu::DocumentRetriever.java'),
('0ea8c9b7-59cb-4f94-9c89-492d2c1b3e43','You will need to create an API with Mistral AI to access Mistral AI language models.\n\nCreate an account at <a href=\"https://auth.mistral.ai/ui/registration\">Mistral AI registration page</a> and generate the token on the <a href=\"https://console.mistral.ai/api-keys/\">API Keys page</a>.\n\nThe Spring AI project defines a configuration property named <code>spring.ai.mistralai.api-key</code> that you should set to the value of the <code>API Key</code> obtained from console.mistral.ai.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.mistralai.api-key=&lt;your-mistralai-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference a custom environment variable:\n\n# In application.yml\nspring:\n  ai:\n    mistralai:\n      api-key: ${MISTRALAI_API_KEY}\n\n# In your environment or .env file\nexport MISTRALAI_API_KEY=&lt;your-mistralai-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"MISTRALAI_API_KEY\");',0x00,'asciidoc::mistralai-chat.adoc::Prerequisites::0'),
('e1c739a3-fdfd-480b-bfce-498c46608c1a','<div class=\"paragraph\">\n<p>Prompts are the inputs that guide an AI model to generate specific outputs.\nThe design and phrasing of these prompts significantly influence the model&#8217;s responses.</p>\n</div>\n<div class=\"paragraph\">\n<p>At the lowest level of interaction with AI models in Spring AI, handling prompts in Spring AI is somewhat similar to managing the \"View\" in Spring MVC.\nThis involves creating extensive text with placeholders for dynamic content.\nThese placeholders are then replaced based on user requests or other code in the application.\nAnother analogy is a SQL statement that contain placeholders for certain expressions.</p>\n</div>\n<div class=\"paragraph\">\n<p>As Spring AI evolves, it will introduce higher levels of abstraction for interacting with AI models.\nThe foundational classes described in this section can be likened to JDBC in terms of their role and functionality.\nThe <code>ChatModel</code> class, for instance, is analogous to the core JDBC library in the JDK.\nThe <code>ChatClient</code> class can be likened to the <code>JdbcClient</code>, built on top of <code>ChatModel</code> and providing more advanced constructs via <code>Advisor</code>\nto consider past interactions with the model, augment the prompt with additional contextual documents, and introduce agentic behavior.</p>\n</div>\n<div class=\"paragraph\">\n<p>The structure of prompts has evolved over time within the AI field.\nInitially, prompts were simple strings.\nOver time, they grew to include placeholders for specific inputs, like \"USER:\", which the AI model recognizes.\nOpenAI have introduced even more structure to prompts by categorizing multiple message strings into distinct roles before they are processed by the AI model.</p>\n</div>',0x00,'asciidoc::prompt.adoc::0'),
('59ea1ed4-0af9-4d78-8120-49c58343d8f9','Spring AI allows you to configure your response format programmatically using the <code>OllamaChatOptions</code> builder.\n\nUsing the Chat Options Builder\n\nYou can set the response format programmatically with the <code>OllamaChatOptions</code> builder as shown below:\n\nString jsonSchema = \"\"\"\n        {\n            \"type\": \"object\",\n            \"properties\": {\n                \"steps\": {\n                    \"type\": \"array\",\n                    \"items\": {\n                        \"type\": \"object\",\n                        \"properties\": {\n                            \"explanation\": { \"type\": \"string\" },\n                            \"output\": { \"type\": \"string\" }\n                        },\n                        \"required\": [\"explanation\", \"output\"],\n                        \"additionalProperties\": false\n                    }\n                },\n                \"final_answer\": { \"type\": \"string\" }\n            },\n            \"required\": [\"steps\", \"final_answer\"],\n            \"additionalProperties\": false\n        }\n        \"\"\";\n\nPrompt prompt = new Prompt(\"how can I solve 8x + 7 = -23\",\n        OllamaChatOptions.builder()\n            .model(OllamaModel.LLAMA3_2.getName())\n            .format(new ObjectMapper().readValue(jsonSchema, Map.class))\n            .build());\n\nChatResponse response = this.ollamaChatModel.call(this.prompt);\n\nIntegrating with BeanOutputConverter Utilities\n\nYou can leverage existing <a href=\":api/structured-output-converter.html#_bean_output_converter\">BeanOutputConverter</a> utilities to automatically generate the JSON Schema from your domain objects and later convert the structured response into domain-specific instances:\n\nrecord MathReasoning(\n    @JsonProperty(required = true, value = \"steps\") Steps steps,\n    @JsonProperty(required = true, value = \"final_answer\") String finalAnswer) {\n\n    record Steps(\n        @JsonProperty(required = true, value = \"items\") Items[] items) {\n\n        record Items(\n            @JsonProperty(required = true, value = \"explanation\") String explanation,\n            @JsonProperty(required = true, value = \"output\") String output) {\n        }\n    }\n}\n\nvar outputConverter = new BeanOutputConverter&lt;&gt;(MathReasoning.class);\n\nPrompt prompt = new Prompt(\"how can I solve 8x + 7 = -23\",\n        OllamaChatOptions.builder()\n            .model(OllamaModel.LLAMA3_2.getName())\n            .format(outputConverter.getJsonSchemaMap())\n            .build());\n\nChatResponse response = this.ollamaChatModel.call(this.prompt);\nString content = this.response.getResult().getOutput().getText();\n\nMathReasoning mathReasoning = this.outputConverter.convert(this.content);\n\nEnsure you use the <code>@JsonProperty(required = true,&#8230;&#8203;)</code>  annotation for generating a schema that accurately marks fields as <code>required</code>.\nAlthough this is optional for JSON Schema, it&#8217;s recommended for the structured response to function correctly.',0x00,'asciidoc::ollama-chat.adoc::Structured Outputs::Configuration::0'),
('a9904466-3b12-4e5f-8904-49e75ce9fe8f','When a tool call fails, the exception is propagated as a <code>ToolExecutionException</code> which can be caught to handle the error.\nA <code>ToolExecutionExceptionProcessor</code> can be used to handle a <code>ToolExecutionException</code> with two outcomes: either producing an error message to be sent back to the AI model or throwing an exception to be handled by the caller.\n\n@FunctionalInterface\npublic interface ToolExecutionExceptionProcessor {\n\n	/**\n	 * Convert an exception thrown by a tool to a String that can be sent back to the AI\n	 * model or throw an exception to be handled by the caller.\n	 */\n	String process(ToolExecutionException exception);\n\n}\n\nIf you&#8217;re using any of the Spring AI Spring Boot Starters, <code>DefaultToolExecutionExceptionProcessor</code> is the autoconfigured implementation of the <code>ToolExecutionExceptionProcessor</code> interface. By default, the error message of <code>RuntimeException</code> is sent back to the model, while checked exceptions and Errors (e.g., <code>IOException</code>, <code>OutOfMemoryError</code>) are always thrown. The <code>DefaultToolExecutionExceptionProcessor</code> constructor lets you set the <code>alwaysThrow</code> attribute to <code>true</code> or <code>false</code>. If <code>true</code>, an exception will be thrown instead of sending an error message back to the model.\n\nYou can use the <code>`spring.ai.tools.throw-exception-on-error</code> property to control the behavior of the <code>DefaultToolExecutionExceptionProcessor</code> bean:\n\n\n\n@Bean\nToolExecutionExceptionProcessor toolExecutionExceptionProcessor() {\n    return new DefaultToolExecutionExceptionProcessor(true);\n}\n\nIf you defined your own <code>ToolCallback</code> implementation, make sure to throw a <code>ToolExecutionException</code> when an error occurs as part of the tool execution logic in the <code>call()</code> method.\n\nThe <code>ToolExecutionExceptionProcessor</code> is used internally by the default <code>ToolCallingManager</code> (<code>DefaultToolCallingManager</code>) to handle exceptions during tool execution. See <a href=\"#_tool_execution\">Tool Execution</a> for more details about the tool execution lifecycle.',0x00,'asciidoc::tools.adoc::Tool Execution::Exception Handling::0'),
('bfe9cbb3-f973-47da-941c-4b38f1e8ea8b','Spring AI implements a Modular RAG architecture inspired by the concept of modularity detailed in the paper\n\"<a href=\"https://arxiv.org/abs/2407.21059\">Modular RAG: Transforming RAG Systems into LEGO-like Reconfigurable Frameworks</a>\".',0x00,'asciidoc::retrieval-augmented-generation.adoc::Modules::0'),
('ceaf59f3-6dc2-47e4-b750-4b3a82bac68e','The prefix <code>spring.ai.vertex.ai.embedding</code> is used as the property prefix that lets you connect to VertexAI Embedding API.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding.multimodal=vertexai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding.multimodal=none (or any value which doesn&#8217;t match vertexai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.vertex.ai.embedding.multimodal</code> is the property prefix that lets you configure the embedding model implementation for VertexAI Multimodal Embedding.',0x00,'asciidoc::vertexai-embeddings-multimodal.adoc::Auto-configuration::Embedding Properties::0'),
('7b146598-a8af-47d5-9681-4b3f1e3add30','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nFor dependency management, we recommend using the Spring AI BOM as explained in the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section.\n\nAdd these dependencies to your project:\n\nFor just the Cassandra Vector Store:\n\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-cassandra-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nOr, for everything you need in a RAG application (using the default ONNX Embedding Model):\n\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-cassandra&lt;/artifactId&gt;\n&lt;/dependency&gt;',0x00,'asciidoc::apache-cassandra.adoc::Dependencies::0'),
('b51f411a-c465-4205-949f-4b54ef5e996e','<code>@ToolParam(required = false)</code> from Spring AI\n<code>@JsonProperty(required = false)</code> from Jackson\n<code>@Schema(required = false)</code> from Swagger\n<code>@Nullable</code> from Spring Framework.\n\n\nThis approach works for both methods and functions, and you can use it recursively for nested types.\n\nclass CustomerTools {\n\n    @Tool(description = \"Update customer information\")\n    void updateCustomerInfo(Long id, String name, @ToolParam(required = false) String email) {\n        System.out.println(\"Updated info for customer with id: \" + id);\n    }\n\n}\n\nDefining the correct required status for the input parameter is crucial to mitigate the risk of hallucinations and ensure the model provides the right input when calling the tool. In the previous example, the <code>email</code> parameter is optional, which means the model can call the tool without providing a value for it. If the parameter was required, the model would have to provide a value for it when calling the tool. And if no value existed, the model would probably make one up, leading to hallucinations.',0x00,'asciidoc::tools.adoc::Tool Specification::JSON Schema::1'),
('5c88e595-1104-431f-a3c0-4b5e0438be64','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-zhipuai</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the ZhiPuAi chat model:\n\nspring.ai.zhipuai.api-key=YOUR_API_KEY\nspring.ai.zhipuai.chat.options.model=glm-4-air\nspring.ai.zhipuai.chat.options.temperature=0.7\n\nreplace the <code>api-key</code> with your ZhiPuAI credentials.\n\nThis will create a <code>ZhiPuAiChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final ZhiPuAiChatModel chatModel;\n\n    @Autowired\n    public ChatController(ZhiPuAiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(value = \"/ai/generateStream\", produces = MediaType.TEXT_EVENT_STREAM_VALUE)\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        var prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::zhipuai-chat.adoc::Sample Controller::0'),
('38f9eb83-e73f-49b9-b561-4b7f4b654db0','Code prompting refers to specialized techniques for code-related tasks. These techniques leverage LLMs\' ability to understand and generate programming languages, enabling them to write new code, explain existing code, debug issues, and translate between languages.\n\nEffective code prompting typically involves clear specifications, appropriate context (libraries, frameworks, style guidelines), and sometimes examples of similar code. Temperature settings tend to be lower (0.1-0.3) for more deterministic outputs.',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.9 Code Prompting::0'),
('c6042cec-a9ca-49a6-8f73-4b894c019293','If Docker complains about resources, then execute:\n\ndocker system prune --all --force --volumes',0x00,'asciidoc::milvus.adoc::Troubleshooting::0'),
('0adc4a88-5281-4ea6-a3a3-4be1e99d6cc1','<strong>When to Use:</strong>\n- Clear evaluation criteria exist\n- Iterative refinement provides measurable value\n- Tasks benefit from multiple rounds of critique\n\npublic class EvaluatorOptimizerWorkflow {\n    public RefinedResponse loop(String task) {\n        Generation generation = generate(task, context);\n        EvaluationResponse evaluation = evaluate(generation.response(), task);\n        return new RefinedResponse(finalSolution, chainOfThought);\n    }\n}\n\nUsage Example:\n\nChatClient chatClient = // ... initialize chat client\nEvaluatorOptimizerWorkflow workflow = new EvaluatorOptimizerWorkflow(chatClient);\n\nRefinedResponse response = workflow.loop(\n    \"Create a Java class implementing a thread-safe counter\"\n);\n\nSystem.out.println(\"Final Solution: \" + response.solution());\nSystem.out.println(\"Evolution: \" + response.chainOfThought());',0x00,'asciidoc::effective-agents.adoc::Agentic Systems::5. <a href=\"https://github.com/spring-projects/spring-ai-examples/tree/main/agentic-patterns/evaluator-optimizer\">Evaluator-Optimizer</a>::0'),
('559bca5f-7be3-41b4-976f-4ca5a298e9d0','If you&#8217;re currently using the Vertex AI Gemini implementation (<code>spring-ai-vertex-ai-gemini</code>), you can migrate to Google GenAI with minimal changes:',0x00,'asciidoc::google-genai-chat.adoc::Migration from Vertex AI Gemini::0'),
('f11b3a6a-0b2a-4019-9503-4d1dcb40c9e9','If you are not using Spring Boot, you can manually configure the OpenAI Embedding Model.\nFor this add the <code>spring-ai-mistral-ai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-mistral-ai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-mistral-ai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThe <code>spring-ai-mistral-ai</code> dependency provides access also to the <code>MistralAiChatModel</code>.\nFor more information about the <code>MistralAiChatModel</code> refer to the <a href=\"../chat/mistralai-chat.html\">MistralAI Chat Client</a> section.\n\nNext, create an <code>MistralAiEmbeddingModel</code> instance and use it to compute the similarity between two input texts:\n\nvar mistralAiApi = new MistralAiApi(System.getenv(\"MISTRAL_AI_API_KEY\"));\n\nvar embeddingModel = new MistralAiEmbeddingModel(this.mistralAiApi,\n        MistralAiEmbeddingOptions.builder()\n                .withModel(\"mistral-embed\")\n                .withEncodingFormat(\"float\")\n                .build());\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n        .embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));\n\nThe <code>MistralAiEmbeddingOptions</code> provides the configuration information for the embedding requests.\nThe options class offers a <code>builder()</code> for easy options creation.',0x00,'asciidoc::mistralai-embeddings.adoc::Manual Configuration::0'),
('c7130cd7-d240-4f52-8d06-4d2412bc88de','/**\n * Mark interface representing the supported expression types: {@link Key},\n * {@link Value}, {@link Expression} and {@link Group}.\n */\npublic interface Operand {\n}',0x01,'cu::Filter.java'),
('05ca7c6b-46e0-47a1-920b-4d2fda1421f8','If you run PGvector as a Spring Boot dev service via <a href=\"https://docs.spring.io/spring-boot/reference/features/dev-services.html#features.dev-services.docker-compose\">Docker Compose</a>\nor <a href=\"https://docs.spring.io/spring-boot/reference/features/dev-services.html#features.dev-services.testcontainers\">Testcontainers</a>,\nyou don&#8217;t need to configure URL, username and password since they are autoconfigured by Spring Boot.\n\nCheck the list of <a href=\"#pgvector-properties\">configuration parameters</a> to learn about the default values and configuration options.\n\nNow you can auto-wire the <code>VectorStore</code> in your application and use it\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList&lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to PGVector\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::pgvector.adoc::Auto-Configuration::1'),
('d7bd3872-e591-4661-96db-4d67fde079c6','You can leverage the generic portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with Typesense store as well.\n\nFor example you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(\"country in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"country\", \"UK\", \"NL\"),\n        b.gte(\"year\", 2020)).build()).build());\n\nThose (portable) filter expressions get automatically converted into <a href=\"https://typesense.org/docs/0.24.0/api/search.html#filter-parameters\">Typesense Search Filters</a>.\n\nFor example this portable filter expression:\n\ncountry in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\n\nis converted into the proprietary Typesense filter format:\n\ncountry: [\'UK\', \'NL\'] &amp;&amp; year: &gt;=2020\n\n<div class=\"paragraph\">\n<p>If you are not retrieving the documents in the expected order or the search results are not as expected, check the embedding model you are using.</p>\n</div>\n<div class=\"paragraph\">\n<p>Embedding models can have a significant impact on the search results (i.e. make sure if your data is in Spanish to use a Spanish or multilingual embedding model).</p>\n</div>',0x00,'asciidoc::typesense.adoc::Metadata Filtering::0'),
('cb300402-6d53-4a05-9f38-4de5d4fb20ad','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Hugging Face Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-huggingface&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-huggingface\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::huggingface.adoc::Auto-configuration::0'),
('e0333990-9d79-44d0-9fad-4e9a0456a660','You will need to create an API key with DeepSeek to access DeepSeek language models.\n\nCreate an account at <a href=\"https://platform.deepseek.com/sign_up\">DeepSeek registration page</a> and generate a token on the <a href=\"https://platform.deepseek.com/api_keys\">API Keys page</a>.\n\nThe Spring AI project defines a configuration property named <code>spring.ai.deepseek.api-key</code> that you should set to the value of the <code>API Key</code> obtained from the API Keys page.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.deepseek.api-key=&lt;your-deepseek-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference a custom environment variable:\n\n# In application.yml\nspring:\n  ai:\n    deepseek:\n      api-key: ${DEEPSEEK_API_KEY}\n\n# In your environment or .env file\nexport DEEPSEEK_API_KEY=&lt;your-deepseek-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"DEEPSEEK_API_KEY\");',0x00,'asciidoc::deepseek-chat.adoc::Prerequisites::0'),
('47d199e2-fe65-4fc0-bf1b-4f3314487d90','@SuppressWarnings({ \"all\", \"warnings\", \"unchecked\", \"unused\", \"cast\", \"CheckReturnValue\", \"this-escape\" })\npublic class FiltersLexer extends Lexer {\n\n    protected static final DFA[] _decisionToDFA;\n\n    protected static final PredictionContextCache _sharedContextCache = new PredictionContextCache();\n\n    public static final int LONG_SUFFIX = 1, WHERE = 2, DOT = 3, COMMA = 4, LEFT_SQUARE_BRACKETS = 5, RIGHT_SQUARE_BRACKETS = 6, LEFT_PARENTHESIS = 7, RIGHT_PARENTHESIS = 8, EQUALS = 9, MINUS = 10, PLUS = 11, GT = 12, GE = 13, LT = 14, LE = 15, NE = 16, AND = 17, OR = 18, IN = 19, NIN = 20, NOT = 21, BOOLEAN_VALUE = 22, QUOTED_STRING = 23, INTEGER_VALUE = 24, DECIMAL_VALUE = 25, IDENTIFIER = 26, WS = 27;\n\n    public static String[] channelNames = { \"DEFAULT_TOKEN_CHANNEL\", \"HIDDEN\" };\n\n    public static String[] modeNames = { \"DEFAULT_MODE\" };\n\n    private static String[] makeRuleNames() {\n        return new String[] { \"LONG_SUFFIX\", \"WHERE\", \"DOT\", \"COMMA\", \"LEFT_SQUARE_BRACKETS\", \"RIGHT_SQUARE_BRACKETS\", \"LEFT_PARENTHESIS\", \"RIGHT_PARENTHESIS\", \"EQUALS\", \"MINUS\", \"PLUS\", \"GT\", \"GE\", \"LT\", \"LE\", \"NE\", \"AND\", \"OR\", \"IN\", \"NIN\", \"NOT\", \"BOOLEAN_VALUE\", \"QUOTED_STRING\", \"INTEGER_VALUE\", \"DECIMAL_VALUE\", \"IDENTIFIER\", \"DECIMAL_DIGITS\", \"DIGIT\", \"LETTER\", \"WS\" };\n    }\n\n    public static final String[] ruleNames = makeRuleNames();\n\n    private static String[] makeLiteralNames() {\n        return new String[] { null, null, null, \"\'.\'\", \"\',\'\", \"\'[\'\", \"\']\'\", \"\'(\'\", \"\')\'\", \"\'==\'\", \"\'-\'\", \"\'+\'\", \"\'>\'\", \"\'>=\'\", \"\'<\'\", \"\'<=\'\", \"\'!=\'\" };\n    }\n\n    private static final String[] _LITERAL_NAMES = makeLiteralNames();\n\n    private static String[] makeSymbolicNames() {\n        return new String[] { null, \"LONG_SUFFIX\", \"WHERE\", \"DOT\", \"COMMA\", \"LEFT_SQUARE_BRACKETS\", \"RIGHT_SQUARE_BRACKETS\", \"LEFT_PARENTHESIS\", \"RIGHT_PARENTHESIS\", \"EQUALS\", \"MINUS\", \"PLUS\", \"GT\", \"GE\", \"LT\", \"LE\", \"NE\", \"AND\", \"OR\", \"IN\", \"NIN\", \"NOT\", \"BOOLEAN_VALUE\", \"QUOTED_STRING\", \"INTEGER_VALUE\", \"DECIMAL_VALUE\", \"IDENTIFIER\", \"WS\" };\n    }\n\n    private static final String[] _SYMBOLIC_NAMES = makeSymbolicNames();\n\n    public static final Vocabulary VOCABULARY = new VocabularyImpl(_LITERAL_NAMES, _SYMBOLIC_NAMES);\n\n    /**\n     * @deprecated Use {@link #VOCABULARY} instead.\n     */\n    @Deprecated\n    public static final String[] tokenNames;\n\n    static {\n        tokenNames = new String[_SYMBOLIC_NAMES.length];\n        for (int i = 0; i < tokenNames.length; i++) {\n            tokenNames[i] = VOCABULARY.getLiteralName(i);\n            if (tokenNames[i] == null) {\n                tokenNames[i] = VOCABULARY.getSymbolicName(i);\n            }\n            if (tokenNames[i] == null) {\n                tokenNames[i] = \"<INVALID>\";\n            }\n        }\n    }\n\n    @Override\n    @Deprecated\n    public String[] getTokenNames() {\n        return tokenNames;\n    }\n\n    @Override\n    public Vocabulary getVocabulary() {\n        return VOCABULARY;\n    }\n\n    public FiltersLexer(CharStream input) {\n        super(input);\n        _interp = new LexerATNSimulator(this, _ATN, _decisionToDFA, _sharedContextCache);\n    }\n\n    @Override\n    public String getGrammarFileName() {\n        return \"Filters.g4\";\n    }\n\n    @Override\n    public String[] getRuleNames() {\n        return ruleNames;\n    }\n\n    @Override\n    public String getSerializedATN() {\n        return _serializedATN;\n    }\n\n    @Override\n    public String[] getChannelNames() {\n        return channelNames;\n    }\n\n    @Override\n    public String[] getModeNames() {\n        return modeNames;\n    }\n\n    @Override\n    public ATN getATN() {\n        return _ATN;\n    }\n\n    public static final String _serializedATN = \"\\u0004\\u0000\\u001b\\u00ef\\u0006\\uffff\\uffff\\u0002\\u0000\\u0007\\u0000\\u0002\" + \"\\u0001\\u0007\\u0001\\u0002\\u0002\\u0007\\u0002\\u0002\\u0003\\u0007\\u0003\\u0002\" + \"\\u0004\\u0007\\u0004\\u0002\\u0005\\u0007\\u0005\\u0002\\u0006\\u0007\\u0006\\u0002\" + \"\\u0007\\u0007\\u0007\\u0002\\b\\u0007\\b\\u0002\\t\\u0007\\t\\u0002\\n\\u0007\\n\\u0002\" + \"\\u000b\\u0007\\u000b\\u0002\\f\\u0007\\f\\u0002\\r\\u0007\\r\\u0002\\u000e\\u0007\\u000e\" + \"\\u0002\\u000f\\u0007\\u000f\\u0002\\u0010\\u0007\\u0010\\u0002\\u0011\\u0007\\u0011\" + \"\\u0002\\u0012\\u0007\\u0012\\u0002\\u0013\\u0007\\u0013\\u0002\\u0014\\u0007\\u0014\" + \"\\u0002\\u0015\\u0007\\u0015\\u0002\\u0016\\u0007\\u0016\\u0002\\u0017\\u0007\\u0017\" + \"\\u0002\\u0018\\u0007\\u0018\\u0002\\u0019\\u0007\\u0019\\u0002\\u001a\\u0007\\u001a\" + \"\\u0002\\u001b\\u0007\\u001b\\u0002\\u001c\\u0007\\u001c\\u0002\\u001d\\u0007\\u001d\" + \"\\u0001\\u0000\\u0001\\u0000\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\" + \"\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\\u0001\" + \"\\u0003\\u0001J\\b\\u0001\\u0001\\u0002\\u0001\\u0002\\u0001\\u0003\\u0001\\u0003\" + \"\\u0001\\u0004\\u0001\\u0004\\u0001\\u0005\\u0001\\u0005\\u0001\\u0006\\u0001\\u0006\" + \"\\u0001\\u0007\\u0001\\u0007\\u0001\\b\\u0001\\b\\u0001\\b\\u0001\\t\\u0001\\t\\u0001\" + \"\\n\\u0001\\n\\u0001\\u000b\\u0001\\u000b\\u0001\\f\\u0001\\f\\u0001\\f\\u0001\\r\\u0001\" + \"\\r\\u0001\\u000e\\u0001\\u000e\\u0001\\u000e\\u0001\\u000f\\u0001\\u000f\\u0001\\u000f\" + \"\\u0001\\u0010\\u0001\\u0010\\u0001\\u0010\\u0001\\u0010\\u0001\\u0010\\u0001\\u0010\" + \"\\u0001\\u0010\\u0001\\u0010\\u0003\\u0010t\\b\\u0010\\u0001\\u0011\\u0001\\u0011\" + \"\\u0001\\u0011\\u0001\\u0011\\u0001\\u0011\\u0001\\u0011\\u0003\\u0011|\\b\\u0011\" + \"\\u0001\\u0012\\u0001\\u0012\\u0001\\u0012\\u0001\\u0012\\u0003\\u0012\\u0082\\b\\u0012\" + \"\\u0001\\u0013\\u0001\\u0013\\u0001\\u0013\\u0001\\u0013\\u0001\\u0013\\u0001\\u0013\" + \"\\u0003\\u0013\\u008a\\b\\u0013\\u0001\\u0014\\u0001\\u0014\\u0001\\u0014\\u0001\\u0014\" + \"\\u0001\\u0014\\u0001\\u0014\\u0003\\u0014\\u0092\\b\\u0014\\u0001\\u0015\\u0001\\u0015\" + \"\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\" + \"\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\" + \"\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0001\\u0015\\u0003\\u0015\\u00a6\\b\\u0015\" + \"\\u0001\\u0016\\u0001\\u0016\\u0001\\u0016\\u0001\\u0016\\u0005\\u0016\\u00ac\\b\\u0016\" + \"\\n\\u0016\\f\\u0016\\u00af\\t\\u0016\\u0001\\u0016\\u0001\\u0016\\u0001\\u0016\\u0001\" + \"\\u0016\\u0001\\u0016\\u0005\\u0016\\u00b6\\b\\u0016\\n\\u0016\\f\\u0016\\u00b9\\t\\u0016\" + \"\\u0001\\u0016\\u0003\\u0016\\u00bc\\b\\u0016\\u0001\\u0017\\u0004\\u0017\\u00bf\\b\" + \"\\u0017\\u000b\\u0017\\f\\u0017\\u00c0\\u0001\\u0018\\u0001\\u0018\\u0001\\u0019\\u0001\" + \"\\u0019\\u0003\\u0019\\u00c7\\b\\u0019\\u0001\\u0019\\u0001\\u0019\\u0001\\u0019\\u0005\" + \"\\u0019\\u00cc\\b\\u0019\\n\\u0019\\f\\u0019\\u00cf\\t\\u0019\\u0001\\u001a\\u0004\\u001a\" + \"\\u00d2\\b\\u001a\\u000b\\u001a\\f\\u001a\\u00d3\\u0001\\u001a\\u0001\\u001a\\u0005\" + \"\\u001a\\u00d8\\b\\u001a\\n\\u001a\\f\\u001a\\u00db\\t\\u001a\\u0001\\u001a\\u0001\\u001a\" + \"\\u0004\\u001a\\u00df\\b\\u001a\\u000b\\u001a\\f\\u001a\\u00e0\\u0003\\u001a\\u00e3\" + \"\\b\\u001a\\u0001\\u001b\\u0001\\u001b\\u0001\\u001c\\u0001\\u001c\\u0001\\u001d\\u0004\" + \"\\u001d\\u00ea\\b\\u001d\\u000b\\u001d\\f\\u001d\\u00eb\\u0001\\u001d\\u0001\\u001d\" + \"\\u0000\\u0000\\u001e\\u0001\\u0001\\u0003\\u0002\\u0005\\u0003\\u0007\\u0004\\t\\u0005\" + \"\\u000b\\u0006\\r\\u0007\\u000f\\b\\u0011\\t\\u0013\\n\\u0015\\u000b\\u0017\\f\\u0019\" + \"\\r\\u001b\\u000e\\u001d\\u000f\\u001f\\u0010!\\u0011#\\u0012%\\u0013\\\'\\u0014)\\u0015\" + \"+\\u0016-\\u0017/\\u00181\\u00193\\u001a5\\u00007\\u00009\\u0000;\\u001b\\u0001\" + \"\\u0000\\u0006\\u0002\\u0000LLll\\u0002\\u0000\\\'\\\'\\\\\\\\\\u0002\\u0000\\\"\\\"\\\\\\\\\\u0001\" + \"\\u000009\\u0002\\u0000AZaz\\u0003\\u0000\\t\\n\\r\\r  \\u0105\\u0000\\u0001\\u0001\" + \"\\u0000\\u0000\\u0000\\u0000\\u0003\\u0001\\u0000\\u0000\\u0000\\u0000\\u0005\\u0001\" + \"\\u0000\\u0000\\u0000\\u0000\\u0007\\u0001\\u0000\\u0000\\u0000\\u0000\\t\\u0001\\u0000\" + \"\\u0000\\u0000\\u0000\\u000b\\u0001\\u0000\\u0000\\u0000\\u0000\\r\\u0001\\u0000\\u0000\" + \"\\u0000\\u0000\\u000f\\u0001\\u0000\\u0000\\u0000\\u0000\\u0011\\u0001\\u0000\\u0000\" + \"\\u0000\\u0000\\u0013\\u0001\\u0000\\u0000\\u0000\\u0000\\u0015\\u0001\\u0000\\u0000\" + \"\\u0000\\u0000\\u0017\\u0001\\u0000\\u0000\\u0000\\u0000\\u0019\\u0001\\u0000\\u0000\" + \"\\u0000\\u0000\\u001b\\u0001\\u0000\\u0000\\u0000\\u0000\\u001d\\u0001\\u0000\\u0000\" + \"\\u0000\\u0000\\u001f\\u0001\\u0000\\u0000\\u0000\\u0000!\\u0001\\u0000\\u0000\\u0000\" + \"\\u0000#\\u0001\\u0000\\u0000\\u0000\\u0000%\\u0001\\u0000\\u0000\\u0000\\u0000\\\'\" + \"\\u0001\\u0000\\u0000\\u0000\\u0000)\\u0001\\u0000\\u0000\\u0000\\u0000+\\u0001\\u0000\" + \"\\u0000\\u0000\\u0000-\\u0001\\u0000\\u0000\\u0000\\u0000/\\u0001\\u0000\\u0000\\u0000\" + \"\\u00001\\u0001\\u0000\\u0000\\u0000\\u00003\\u0001\\u0000\\u0000\\u0000\\u0000;\" + \"\\u0001\\u0000\\u0000\\u0000\\u0001=\\u0001\\u0000\\u0000\\u0000\\u0003I\\u0001\\u0000\" + \"\\u0000\\u0000\\u0005K\\u0001\\u0000\\u0000\\u0000\\u0007M\\u0001\\u0000\\u0000\\u0000\" + \"\\tO\\u0001\\u0000\\u0000\\u0000\\u000bQ\\u0001\\u0000\\u0000\\u0000\\rS\\u0001\\u0000\" + \"\\u0000\\u0000\\u000fU\\u0001\\u0000\\u0000\\u0000\\u0011W\\u0001\\u0000\\u0000\\u0000\" + \"\\u0013Z\\u0001\\u0000\\u0000\\u0000\\u0015\\\\\\u0001\\u0000\\u0000\\u0000\\u0017\" + \"^\\u0001\\u0000\\u0000\\u0000\\u0019`\\u0001\\u0000\\u0000\\u0000\\u001bc\\u0001\" + \"\\u0000\\u0000\\u0000\\u001de\\u0001\\u0000\\u0000\\u0000\\u001fh\\u0001\\u0000\\u0000\" + \"\\u0000!s\\u0001\\u0000\\u0000\\u0000#{\\u0001\\u0000\\u0000\\u0000%\\u0081\\u0001\" + \"\\u0000\\u0000\\u0000\\\'\\u0089\\u0001\\u0000\\u0000\\u0000)\\u0091\\u0001\\u0000\" + \"\\u0000\\u0000+\\u00a5\\u0001\\u0000\\u0000\\u0000-\\u00bb\\u0001\\u0000\\u0000\\u0000\" + \"/\\u00be\\u0001\\u0000\\u0000\\u00001\\u00c2\\u0001\\u0000\\u0000\\u00003\\u00c6\" + \"\\u0001\\u0000\\u0000\\u00005\\u00e2\\u0001\\u0000\\u0000\\u00007\\u00e4\\u0001\\u0000\" + \"\\u0000\\u00009\\u00e6\\u0001\\u0000\\u0000\\u0000;\\u00e9\\u0001\\u0000\\u0000\\u0000\" + \"=>\\u0007\\u0000\\u0000\\u0000>\\u0002\\u0001\\u0000\\u0000\\u0000?@\\u0005W\\u0000\" + \"\\u0000@A\\u0005H\\u0000\\u0000AB\\u0005E\\u0000\\u0000BC\\u0005R\\u0000\\u0000\" + \"CJ\\u0005E\\u0000\\u0000DE\\u0005w\\u0000\\u0000EF\\u0005h\\u0000\\u0000FG\\u0005\" + \"e\\u0000\\u0000GH\\u0005r\\u0000\\u0000HJ\\u0005e\\u0000\\u0000I?\\u0001\\u0000\" + \"\\u0000\\u0000ID\\u0001\\u0000\\u0000\\u0000J\\u0004\\u0001\\u0000\\u0000\\u0000\" + \"KL\\u0005.\\u0000\\u0000L\\u0006\\u0001\\u0000\\u0000\\u0000MN\\u0005,\\u0000\\u0000\" + \"N\\b\\u0001\\u0000\\u0000\\u0000OP\\u0005[\\u0000\\u0000P\\n\\u0001\\u0000\\u0000\" + \"\\u0000QR\\u0005]\\u0000\\u0000R\\f\\u0001\\u0000\\u0000\\u0000ST\\u0005(\\u0000\" + \"\\u0000T\\u000e\\u0001\\u0000\\u0000\\u0000UV\\u0005)\\u0000\\u0000V\\u0010\\u0001\" + \"\\u0000\\u0000\\u0000WX\\u0005=\\u0000\\u0000XY\\u0005=\\u0000\\u0000Y\\u0012\\u0001\" + \"\\u0000\\u0000\\u0000Z[\\u0005-\\u0000\\u0000[\\u0014\\u0001\\u0000\\u0000\\u0000\" + \"\\\\]\\u0005+\\u0000\\u0000]\\u0016\\u0001\\u0000\\u0000\\u0000^_\\u0005>\\u0000\\u0000\" + \"_\\u0018\\u0001\\u0000\\u0000\\u0000`a\\u0005>\\u0000\\u0000ab\\u0005=\\u0000\\u0000\" + \"b\\u001a\\u0001\\u0000\\u0000\\u0000cd\\u0005<\\u0000\\u0000d\\u001c\\u0001\\u0000\" + \"\\u0000\\u0000ef\\u0005<\\u0000\\u0000fg\\u0005=\\u0000\\u0000g\\u001e\\u0001\\u0000\" + \"\\u0000\\u0000hi\\u0005!\\u0000\\u0000ij\\u0005=\\u0000\\u0000j \\u0001\\u0000\\u0000\" + \"\\u0000kl\\u0005A\\u0000\\u0000lm\\u0005N\\u0000\\u0000mt\\u0005D\\u0000\\u0000\" + \"no\\u0005a\\u0000\\u0000op\\u0005n\\u0000\\u0000pt\\u0005d\\u0000\\u0000qr\\u0005\" + \"&\\u0000\\u0000rt\\u0005&\\u0000\\u0000sk\\u0001\\u0000\\u0000\\u0000sn\\u0001\\u0000\" + \"\\u0000\\u0000sq\\u0001\\u0000\\u0000\\u0000t\\\"\\u0001\\u0000\\u0000\\u0000uv\\u0005\" + \"O\\u0000\\u0000v|\\u0005R\\u0000\\u0000wx\\u0005o\\u0000\\u0000x|\\u0005r\\u0000\" + \"\\u0000yz\\u0005|\\u0000\\u0000z|\\u0005|\\u0000\\u0000{u\\u0001\\u0000\\u0000\\u0000\" + \"{w\\u0001\\u0000\\u0000\\u0000{y\\u0001\\u0000\\u0000\\u0000|$\\u0001\\u0000\\u0000\" + \"\\u0000}~\\u0005I\\u0000\\u0000~\\u0082\\u0005N\\u0000\\u0000\\u007f\\u0080\\u0005\" + \"i\\u0000\\u0000\\u0080\\u0082\\u0005n\\u0000\\u0000\\u0081}\\u0001\\u0000\\u0000\" + \"\\u0000\\u0081\\u007f\\u0001\\u0000\\u0000\\u0000\\u0082&\\u0001\\u0000\\u0000\\u0000\" + \"\\u0083\\u0084\\u0005N\\u0000\\u0000\\u0084\\u0085\\u0005I\\u0000\\u0000\\u0085\\u008a\" + \"\\u0005N\\u0000\\u0000\\u0086\\u0087\\u0005n\\u0000\\u0000\\u0087\\u0088\\u0005i\" + \"\\u0000\\u0000\\u0088\\u008a\\u0005n\\u0000\\u0000\\u0089\\u0083\\u0001\\u0000\\u0000\" + \"\\u0000\\u0089\\u0086\\u0001\\u0000\\u0000\\u0000\\u008a(\\u0001\\u0000\\u0000\\u0000\" + \"\\u008b\\u008c\\u0005N\\u0000\\u0000\\u008c\\u008d\\u0005O\\u0000\\u0000\\u008d\\u0092\" + \"\\u0005T\\u0000\\u0000\\u008e\\u008f\\u0005n\\u0000\\u0000\\u008f\\u0090\\u0005o\" + \"\\u0000\\u0000\\u0090\\u0092\\u0005t\\u0000\\u0000\\u0091\\u008b\\u0001\\u0000\\u0000\" + \"\\u0000\\u0091\\u008e\\u0001\\u0000\\u0000\\u0000\\u0092*\\u0001\\u0000\\u0000\\u0000\" + \"\\u0093\\u0094\\u0005T\\u0000\\u0000\\u0094\\u0095\\u0005R\\u0000\\u0000\\u0095\\u0096\" + \"\\u0005U\\u0000\\u0000\\u0096\\u00a6\\u0005E\\u0000\\u0000\\u0097\\u0098\\u0005t\" + \"\\u0000\\u0000\\u0098\\u0099\\u0005r\\u0000\\u0000\\u0099\\u009a\\u0005u\\u0000\\u0000\" + \"\\u009a\\u00a6\\u0005e\\u0000\\u0000\\u009b\\u009c\\u0005F\\u0000\\u0000\\u009c\\u009d\" + \"\\u0005A\\u0000\\u0000\\u009d\\u009e\\u0005L\\u0000\\u0000\\u009e\\u009f\\u0005S\" + \"\\u0000\\u0000\\u009f\\u00a6\\u0005E\\u0000\\u0000\\u00a0\\u00a1\\u0005f\\u0000\\u0000\" + \"\\u00a1\\u00a2\\u0005a\\u0000\\u0000\\u00a2\\u00a3\\u0005l\\u0000\\u0000\\u00a3\\u00a4\" + \"\\u0005s\\u0000\\u0000\\u00a4\\u00a6\\u0005e\\u0000\\u0000\\u00a5\\u0093\\u0001\\u0000\" + \"\\u0000\\u0000\\u00a5\\u0097\\u0001\\u0000\\u0000\\u0000\\u00a5\\u009b\\u0001\\u0000\" + \"\\u0000\\u0000\\u00a5\\u00a0\\u0001\\u0000\\u0000\\u0000\\u00a6,\\u0001\\u0000\\u0000\" + \"\\u0000\\u00a7\\u00ad\\u0005\\\'\\u0000\\u0000\\u00a8\\u00ac\\b\\u0001\\u0000\\u0000\" + \"\\u00a9\\u00aa\\u0005\\\\\\u0000\\u0000\\u00aa\\u00ac\\t\\u0000\\u0000\\u0000\\u00ab\" + \"\\u00a8\\u0001\\u0000\\u0000\\u0000\\u00ab\\u00a9\\u0001\\u0000\\u0000\\u0000\\u00ac\" + \"\\u00af\\u0001\\u0000\\u0000\\u0000\\u00ad\\u00ab\\u0001\\u0000\\u0000\\u0000\\u00ad\" + \"\\u00ae\\u0001\\u0000\\u0000\\u0000\\u00ae\\u00b0\\u0001\\u0000\\u0000\\u0000\\u00af\" + \"\\u00ad\\u0001\\u0000\\u0000\\u0000\\u00b0\\u00bc\\u0005\\\'\\u0000\\u0000\\u00b1\\u00b7\" + \"\\u0005\\\"\\u0000\\u0000\\u00b2\\u00b6\\b\\u0002\\u0000\\u0000\\u00b3\\u00b4\\u0005\" + \"\\\\\\u0000\\u0000\\u00b4\\u00b6\\t\\u0000\\u0000\\u0000\\u00b5\\u00b2\\u0001\\u0000\" + \"\\u0000\\u0000\\u00b5\\u00b3\\u0001\\u0000\\u0000\\u0000\\u00b6\\u00b9\\u0001\\u0000\" + \"\\u0000\\u0000\\u00b7\\u00b5\\u0001\\u0000\\u0000\\u0000\\u00b7\\u00b8\\u0001\\u0000\" + \"\\u0000\\u0000\\u00b8\\u00ba\\u0001\\u0000\\u0000\\u0000\\u00b9\\u00b7\\u0001\\u0000\" + \"\\u0000\\u0000\\u00ba\\u00bc\\u0005\\\"\\u0000\\u0000\\u00bb\\u00a7\\u0001\\u0000\\u0000\" + \"\\u0000\\u00bb\\u00b1\\u0001\\u0000\\u0000\\u0000\\u00bc.\\u0001\\u0000\\u0000\\u0000\" + \"\\u00bd\\u00bf\\u00037\\u001b\\u0000\\u00be\\u00bd\\u0001\\u0000\\u0000\\u0000\\u00bf\" + \"\\u00c0\\u0001\\u0000\\u0000\\u0000\\u00c0\\u00be\\u0001\\u0000\\u0000\\u0000\\u00c0\" + \"\\u00c1\\u0001\\u0000\\u0000\\u0000\\u00c10\\u0001\\u0000\\u0000\\u0000\\u00c2\\u00c3\" + \"\\u00035\\u001a\\u0000\\u00c32\\u0001\\u0000\\u0000\\u0000\\u00c4\\u00c7\\u00039\" + \"\\u001c\\u0000\\u00c5\\u00c7\\u0005_\\u0000\\u0000\\u00c6\\u00c4\\u0001\\u0000\\u0000\" + \"\\u0000\\u00c6\\u00c5\\u0001\\u0000\\u0000\\u0000\\u00c7\\u00cd\\u0001\\u0000\\u0000\" + \"\\u0000\\u00c8\\u00cc\\u00039\\u001c\\u0000\\u00c9\\u00cc\\u00037\\u001b\\u0000\\u00ca\" + \"\\u00cc\\u0005_\\u0000\\u0000\\u00cb\\u00c8\\u0001\\u0000\\u0000\\u0000\\u00cb\\u00c9\" + \"\\u0001\\u0000\\u0000\\u0000\\u00cb\\u00ca\\u0001\\u0000\\u0000\\u0000\\u00cc\\u00cf\" + \"\\u0001\\u0000\\u0000\\u0000\\u00cd\\u00cb\\u0001\\u0000\\u0000\\u0000\\u00cd\\u00ce\" + \"\\u0001\\u0000\\u0000\\u0000\\u00ce4\\u0001\\u0000\\u0000\\u0000\\u00cf\\u00cd\\u0001\" + \"\\u0000\\u0000\\u0000\\u00d0\\u00d2\\u00037\\u001b\\u0000\\u00d1\\u00d0\\u0001\\u0000\" + \"\\u0000\\u0000\\u00d2\\u00d3\\u0001\\u0000\\u0000\\u0000\\u00d3\\u00d1\\u0001\\u0000\" + \"\\u0000\\u0000\\u00d3\\u00d4\\u0001\\u0000\\u0000\\u0000\\u00d4\\u00d5\\u0001\\u0000\" + \"\\u0000\\u0000\\u00d5\\u00d9\\u0005.\\u0000\\u0000\\u00d6\\u00d8\\u00037\\u001b\\u0000\" + \"\\u00d7\\u00d6\\u0001\\u0000\\u0000\\u0000\\u00d8\\u00db\\u0001\\u0000\\u0000\\u0000\" + \"\\u00d9\\u00d7\\u0001\\u0000\\u0000\\u0000\\u00d9\\u00da\\u0001\\u0000\\u0000\\u0000\" + \"\\u00da\\u00e3\\u0001\\u0000\\u0000\\u0000\\u00db\\u00d9\\u0001\\u0000\\u0000\\u0000\" + \"\\u00dc\\u00de\\u0005.\\u0000\\u0000\\u00dd\\u00df\\u00037\\u001b\\u0000\\u00de\\u00dd\" + \"\\u0001\\u0000\\u0000\\u0000\\u00df\\u00e0\\u0001\\u0000\\u0000\\u0000\\u00e0\\u00de\" + \"\\u0001\\u0000\\u0000\\u0000\\u00e0\\u00e1\\u0001\\u0000\\u0000\\u0000\\u00e1\\u00e3\" + \"\\u0001\\u0000\\u0000\\u0000\\u00e2\\u00d1\\u0001\\u0000\\u0000\\u0000\\u00e2\\u00dc\" + \"\\u0001\\u0000\\u0000\\u0000\\u00e36\\u0001\\u0000\\u0000\\u0000\\u00e4\\u00e5\\u0007\" + \"\\u0003\\u0000\\u0000\\u00e58\\u0001\\u0000\\u0000\\u0000\\u00e6\\u00e7\\u0007\\u0004\" + \"\\u0000\\u0000\\u00e7:\\u0001\\u0000\\u0000\\u0000\\u00e8\\u00ea\\u0007\\u0005\\u0000\" + \"\\u0000\\u00e9\\u00e8\\u0001\\u0000\\u0000\\u0000\\u00ea\\u00eb\\u0001\\u0000\\u0000\" + \"\\u0000\\u00eb\\u00e9\\u0001\\u0000\\u0000\\u0000\\u00eb\\u00ec\\u0001\\u0000\\u0000\" + \"\\u0000\\u00ec\\u00ed\\u0001\\u0000\\u0000\\u0000\\u00ed\\u00ee\\u0006\\u001d\\u0000\" + \"\\u0000\\u00ee<\\u0001\\u0000\\u0000\\u0000\\u0016\\u0000Is{\\u0081\\u0089\\u0091\" + \"\\u00a5\\u00ab\\u00ad\\u00b5\\u00b7\\u00bb\\u00c0\\u00c6\\u00cb\\u00cd\\u00d3\\u00d9\" + \"\\u00e0\\u00e2\\u00eb\\u0001\\u0000\\u0001\\u0000\";\n\n    public static final ATN _ATN = new ATNDeserializer().deserialize(_serializedATN.toCharArray());\n\n    static {\n        _decisionToDFA = new DFA[_ATN.getNumberOfDecisions()];\n        for (int i = 0; i < _ATN.getNumberOfDecisions(); i++) {\n            _decisionToDFA[i] = new DFA(_ATN.getDecisionState(i), i);\n        }\n    }\n}',0x01,'cu::FiltersLexer.java'),
('218baed6-2546-49ef-a1e3-4f6d5b21d8f1','After specifying the <code>call()</code> method on <code>ChatClient</code>, there are a few different options for the response type.\n\n<code>String content()</code>: returns the String content of the response\n<code>ChatResponse chatResponse()</code>: returns the <code>ChatResponse</code> object that contains multiple generations and also metadata about the response, for example how many token were used to create the response.\n<code>ChatClientResponse chatClientResponse()</code>: returns a <code>ChatClientResponse</code> object that contains the <code>ChatResponse</code> object and the ChatClient execution context, giving you access to additional data used during the execution of advisors (e.g. the relevant documents retrieved in a RAG flow).\n<code>entity()</code> to return a Java type\n<code>responseEntity()</code> to return both the <code>ChatResponse</code> and a Java type. This is useful when you need access to both the complete AI model response (with metadata and generations) and the structured output entity in a single call.\n\n\nYou can also invoke the <code>stream()</code> method instead of <code>call()</code>.\n\nCalling the <code>call()</code> method does not actually trigger the AI model execution. Instead, it only instructs Spring AI whether to use synchronous or streaming calls.\nThe actual AI model invocation occurs when methods such as <code>content()</code>, <code>chatResponse()</code>, and <code>responseEntity()</code> are called.',0x00,'asciidoc::chatclient.adoc::call() return values::0'),
('f7bbf648-734b-4b19-8e57-4f81194d52b3','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::oci-genai-embeddings.adoc::Prerequisites::Add Repositories and BOM::0'),
('84ebdb51-416b-4f69-9a7d-4fa68e55d846','The <code>RateLimit</code> interface provides access to actual information returned by an AI provider on your API usage when making AI requests.\n\ninterface RateLimit {\n\n	Long getRequestsLimit();\n\n	Long getRequestsRemaining();\n\n	Duration getRequestsReset();\n\n	Long getTokensLimit();\n\n	Long getTokensRemaining();\n\n	Duration getTokensReset();\n\n}\n\n<code>requestsLimit</code> and <code>requestsRemaining</code> let you know how many AI requests, based on the AI provider plan you chose when you signed up, that you can make in total along with your remaining balance within the given timeframe. <code>requestsReset</code> returns a <code>Duration</code> of time before the timeframe expires and your limits reset based on your chosen plan.\n\nThe methods for <code>tokensLimit</code>, <code>tokensRemaining</code> and <code>tokensReset</code> are similar to the methods for requests, but focus on token limits, balance and resets instead.\n\nThe <code>RateLimit</code> instance can be acquired from the <code>GenerationMetadata</code>, like so:\n\nRateLimit rateLimit = generationMetadata.getRateLimit();\n\nLong tokensRemaining = this.rateLimit.getTokensRemaining();\n\n// do something interesting with the RateLimit metadata\n\nFor AI providers like OpenAI, the rate limit metadata is returned in <a href=\"https://platform.openai.com/docs/guides/rate-limits/rate-limits-in-headers\">HTTP headers</a> from their (REST) API accessible through HTTP clients, like OkHttp.\n\nBecause this can be potentially a costly operation, the collection of rate limit AI metadata must be explicitly enabled. You can enable this collection with a Spring AI property in Spring Boot application.properties; for example:\n\n# Spring Boot application.properties\nspring.ai.openai.metadata.rate-limit-metrics-enabled=true',0x00,'asciidoc::aimetadata.adoc::RateLimit::0'),
('f53e65e0-1553-4554-bbcb-500b39e5962e','<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">OpenAI Embedding</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n   &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n   &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Azure AI Embedding</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n &lt;artifactId&gt;spring-ai-starter-model-azure-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Local Sentence Transformers Embedding</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n &lt;artifactId&gt;spring-ai-starter-model-transformers&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>',0x00,'asciidoc::azure.adoc::Dependencies::1. Select an Embeddings interface implementation. You can choose between:::0'),
('c7dbdee7-2448-4ed5-92e9-502f16388441','To use just the <code>GemFireVectorStore</code>, without Spring Boot&#8217;s Auto-configuration add the following dependency to your project’s Maven <code>pom.xml</code>:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-gemfire-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nFor Gradle users, add the following to your <code>build.gradle</code> file under the dependencies block to use just the <code>GemFireVectorStore</code>:\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-gemfire-store\'\n}',0x00,'asciidoc::gemfire.adoc::Manual Configuration::0'),
('3fb6e4b1-e54f-4fd6-8679-505cbee2c800','For more complex use cases, you can configure additional settings in your Spring Bean:\n\n@Bean\npublic VectorStore vectorStore(CqlSession session, EmbeddingModel embeddingModel) {\n    return CassandraVectorStore.builder(embeddingModel)\n        .session(session)\n        .keyspace(\"my_keyspace\")\n        .table(\"my_vectors\")\n        // Configure primary keys\n        .partitionKeys(List.of(\n            new SchemaColumn(\"id\", DataTypes.TEXT),\n            new SchemaColumn(\"category\", DataTypes.TEXT)\n        ))\n        .clusteringKeys(List.of(\n            new SchemaColumn(\"timestamp\", DataTypes.TIMESTAMP)\n        ))\n        // Add metadata columns with optional indexing\n        .addMetadataColumns(\n            new SchemaColumn(\"category\", DataTypes.TEXT, SchemaColumnTags.INDEXED),\n            new SchemaColumn(\"score\", DataTypes.DOUBLE)\n        )\n        // Customize column names\n        .contentColumnName(\"text\")\n        .embeddingColumnName(\"vector\")\n        // Performance tuning\n        .fixedThreadPoolExecutorSize(32)\n        // Schema management\n        .initializeSchema(true)\n        // Custom batching strategy\n        .batchingStrategy(new TokenCountBatchingStrategy())\n        .build();\n}',0x00,'asciidoc::apache-cassandra.adoc::Usage::Advanced Configuration::0'),
('031e6d15-cad2-48fe-9436-506dcc06a207','You can register custom Java functions or methods with the <code>OpenAiSdkChatModel</code> and have the OpenAI model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions/tools.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.\nRead more about <a href=\"api/tools.html\">Tool Calling</a>.\n\nExample usage:\n\nvar chatOptions = OpenAiSdkChatOptions.builder()\n    .toolCallbacks(List.of(\n        FunctionToolCallback.builder(\"getCurrentWeather\", new WeatherService())\n            .description(\"Get the weather in location\")\n            .inputType(WeatherService.Request.class)\n            .build()))\n    .build();\n\nChatResponse response = chatModel.call(\n    new Prompt(\"What\'s the weather like in San Francisco?\", chatOptions));',0x00,'asciidoc::openai-sdk-chat.adoc::Tool Calling::0'),
('b710c50f-0092-4fa8-a7b9-50e1da8fa5e3','<div class=\"paragraph\">\n<p>The <code>ChatClient</code> offers a fluent API for communicating with an AI Model.\nIt supports both a synchronous and streaming programming model.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\n<div class=\"paragraph\">\n<p>See the <a href=\"api/chatclient.html#_implementation_notes\">Implementation Notes</a> at the bottom of this document related to the combined use of imperative and reactive programming models in <code>ChatClient</code></p>\n</div>\n</td>\n</tr>\n</table>\n</div>\n<div class=\"paragraph\">\n<p>The fluent API has methods for building up the constituent parts of a <a href=\"api/prompt.html#_prompt\">Prompt</a> that is passed to the AI model as input.\nThe <code>Prompt</code> contains the instructional text to guide the AI model&#8217;s output and behavior. From the API point of view, prompts consist of a collection of messages.</p>\n</div>\n<div class=\"paragraph\">\n<p>The AI model processes two main types of messages: user messages, which are direct inputs from the user, and system messages, which are generated by the system to guide the conversation.</p>\n</div>\n<div class=\"paragraph\">\n<p>These messages often contain placeholders that are substituted at runtime based on user input to customize the response of the AI model to the user input.</p>\n</div>\n<div class=\"paragraph\">\n<p>There are also Prompt options that can be specified, such as the name of the AI Model to use and the temperature setting that controls the randomness or creativity of the generated output.</p>\n</div>',0x00,'asciidoc::chatclient.adoc::0'),
('fa1150c4-7677-4200-9bf9-50e6592696a1','Retry Properties\n\nThe prefix <code>spring.ai.retry</code> is used as the property prefix that lets you configure the retry mechanism for the OpenAI chat model.\n\n\n\nConnection Properties\n\nThe prefix <code>spring.ai.openai</code> is used as the property prefix that lets you connect to OpenAI.\n\n\n\nConfiguration Properties\n\n<div class=\"paragraph\">\n<p>Enabling and disabling chat auto-configurations is now done via top level properties with the prefix <code>spring.ai.model.chat</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, <code>spring.ai.model.chat=openai</code> (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, <code>spring.ai.model.chat=none</code> (or any value which doesn&#8217;t match openai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change allows for the configuration of multiple models in your application.</p>\n</div>\n\nThe prefix <code>spring.ai.openai.chat</code> is the property prefix that lets you configure the chat model implementation for OpenAI.\n\n\n\nAll properties prefixed with <code>spring.ai.openai.chat.options</code> can be overridden at runtime by adding a request specific <a href=\"#chat-options\">Runtime Options</a> to the <code>Prompt</code> call.',0x00,'asciidoc::dmr-chat.adoc::Auto-configuration::Chat Properties::0'),
('37bf22b4-fac4-4dc1-96ad-510acef3004f','Docker Model Runner supports Tool/Function calling when selecting a model that supports it.\n\nYou can register custom Java functions with your ChatModel and have the provided model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique for connecting the LLM capabilities with external tools and APIs.',0x00,'asciidoc::dmr-chat.adoc::Function Calling::0'),
('63fc7a9a-dcfb-47f8-a23e-513a5e9edeed','<a href=\"api/vectordbs/understand-vectordbs.html\">Understanding Vectors</a>',0x00,'asciidoc::vectordbs.adoc::Understanding Vectors::0'),
('a1a1fd72-fab1-410c-8823-518c12ed1813','// Load comprehensive product knowledge\nString knowledgeBase = \"\"\"\n    PRODUCT DOCUMENTATION:\n    - API endpoints and authentication methods\n    - Common troubleshooting procedures\n    - Billing and subscription details\n    - Integration guides and examples\n    - Known issues and workarounds\n    \"\"\" + loadProductDocs(); // ~2500 tokens\n\n@Service\npublic class CustomerSupportService {\n\n    public String handleCustomerQuery(String customerQuery, String customerId) {\n        ChatResponse response = chatModel.call(\n            new Prompt(\n                List.of(\n                    new SystemMessage(\"You are a helpful customer support agent. \" +\n                        \"Use this knowledge base to provide accurate solutions: \" + knowledgeBase),\n                    new UserMessage(\"Customer \" + customerId + \" asks: \" + customerQuery)\n                ),\n                AnthropicChatOptions.builder()\n                    .model(\"claude-sonnet-4\")\n                    .cacheOptions(AnthropicCacheOptions.builder()\n                        .strategy(AnthropicCacheStrategy.SYSTEM_ONLY)\n                        .build())\n                    .maxTokens(600)\n                    .build()\n            )\n        );\n\n        return response.getResult().getOutput().getText();\n    }\n}\n\n// Knowledge base is cached across all customer queries\n// Multiple support agents can benefit from the same cached content',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Real-World Use Cases::3'),
('4369f554-87e7-45d2-b758-5232911ef56b','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nAdd the <code>spring-ai-starter-model-bedrock</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n  &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n  &lt;artifactId&gt;spring-ai-starter-model-bedrock&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-bedrock\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::bedrock-titan-embedding.adoc::Auto-configuration::0'),
('579005a2-043a-467b-ae71-52567f2d769c','There are several scenarios where you might need to work with multiple chat models in a single application:\n\nUsing different models for different types of tasks (e.g., a powerful model for complex reasoning and a faster, cheaper model for simpler tasks)\nImplementing fallback mechanisms when one model service is unavailable\nA/B testing different models or configurations\nProviding users with a choice of models based on their preferences\nCombining specialized models (one for code generation, another for creative content, etc.)\n\n\nBy default, Spring AI autoconfigures a single <code>ChatClient.Builder</code> bean.\nHowever, you may need to work with multiple chat models in your application.\nHere&#8217;s how to handle this scenario:\n\nIn all cases, you need to disable the <code>ChatClient.Builder</code> autoconfiguration by setting the property <code>spring.ai.chat.client.enabled=false</code>.\n\nThis allows you to create multiple <code>ChatClient</code> instances manually.\n\nMultiple ChatClients with a Single Model Type\n\nThis section covers a common use case where you need to create multiple ChatClient instances that all use the same underlying model type but with different configurations.\n\n// Create ChatClient instances programmatically\nChatModel myChatModel = ... // already autoconfigured by Spring Boot\nChatClient chatClient = ChatClient.create(myChatModel);\n\n// Or use the builder for more control\nChatClient.Builder builder = ChatClient.builder(myChatModel);\nChatClient customChatClient = builder\n    .defaultSystemPrompt(\"You are a helpful assistant.\")\n    .build();\n\nChatClients for Different Model Types\n\nWhen working with multiple AI models, you can define separate <code>ChatClient</code> beans for each model:\n\nimport org.springframework.ai.chat.ChatClient;\nimport org.springframework.context.annotation.Bean;\nimport org.springframework.context.annotation.Configuration;\n\n@Configuration\npublic class ChatClientConfig {\n\n    @Bean\n    public ChatClient openAiChatClient(OpenAiChatModel chatModel) {\n        return ChatClient.create(chatModel);\n    }\n\n    @Bean\n    public ChatClient anthropicChatClient(AnthropicChatModel chatModel) {\n        return ChatClient.create(chatModel);\n    }\n}\n\nYou can then inject these beans into your application components using the <code>@Qualifier</code> annotation:',0x00,'asciidoc::chatclient.adoc::Creating a ChatClient::Working with Multiple Chat Models::0'),
('626901c7-9eae-4726-9ca3-527bfc7d7ee7','You can pass in an SQL-like filter expressions as a <code>String</code> to one of the <code>similaritySearch</code> overloads.\n\nConsider the following examples:\n\n<code>\"country == \'BG\'\"</code>\n<code>\"genre == \'drama\' &amp;&amp; year &gt;= 2020\"</code>\n<code>\"genre in [\'comedy\', \'documentary\', \'drama\']\"</code>',0x00,'asciidoc::vectordbs.adoc::Metadata Filters::Filter String::0'),
('b6a69233-6c23-4b72-886c-5295823057e0','The <code>ChatClient</code> fluent API lets you provide user and system text as templates with variables that are replaced at runtime.\n\nString answer = ChatClient.create(chatModel).prompt()\n    .user(u -&gt; u\n            .text(\"Tell me the names of 5 movies whose soundtrack was composed by {composer}\")\n            .param(\"composer\", \"John Williams\"))\n    .call()\n    .content();\n\nInternally, the ChatClient uses the <code>PromptTemplate</code> class to handle the user and system text and replace the variables with the values provided at runtime relying on a given <code>TemplateRenderer</code> implementation.\nBy default, Spring AI uses the <code>StTemplateRenderer</code> implementation, which is based on the open-source <a href=\"https://www.stringtemplate.org/\">StringTemplate</a> engine developed by Terence Parr.\n\nSpring AI also provides a <code>NoOpTemplateRenderer</code> for cases where no template processing is desired.\n\nThe <code>TemplateRenderer</code> configured directly on the <code>ChatClient</code> (via <code>.templateRenderer()</code>) applies only to the prompt content defined directly in the <code>ChatClient</code> builder chain (e.g., via <code>.user()</code>, <code>.system()</code>).\nIt does <strong>not</strong> affect templates used internally by <a href=\"api/retrieval-augmented-generation.html#_questionansweradvisor\">Advisors</a> like <code>QuestionAnswerAdvisor</code>, which have their own template customization mechanisms (see <a href=\"api/retrieval-augmented-generation.html#_custom_template\">Custom Advisor Templates</a>).\n\nIf you&#8217;d rather use a different template engine, you can provide a custom implementation of the <code>TemplateRenderer</code> interface directly to the ChatClient. You can also keep using the default <code>StTemplateRenderer</code>, but with a custom configuration.\n\nFor example, by default, template variables are identified by the <code>{}</code> syntax.\nIf you&#8217;re planning to include JSON in your prompt, you might want to use a different syntax to avoid conflicts with JSON syntax. For example, you can use the <code>&lt;</code> and <code>&gt;</code> delimiters.\n\nString answer = ChatClient.create(chatModel).prompt()\n    .user(u -&gt; u\n            .text(\"Tell me the names of 5 movies whose soundtrack was composed by &lt;composer&gt;\")\n            .param(\"composer\", \"John Williams\"))\n    .templateRenderer(StTemplateRenderer.builder().startDelimiterToken(\'&lt;\').endDelimiterToken(\'&gt;\').build())\n    .call()\n    .content();',0x00,'asciidoc::chatclient.adoc::Prompt Templates::0'),
('ee174a5a-f63e-493f-800e-5313023a3e1d','A running OpenSearch instance. The following options are available:\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>OpenSearchVectorStore</code>.',0x00,'asciidoc::opensearch.adoc::Prerequisites::0'),
('68cb8810-5e4b-4a99-bb2c-531e7e16129f','You can use the following properties in your Spring Boot configuration to customize the Apache Cassandra vector store.',0x00,'asciidoc::apache-cassandra.adoc::Configuration Properties::0'),
('79bcd847-b42a-4efd-9fd4-53795014e2a0','Moving the <code>prompt</code> and <code>messages</code> and <code>metadata</code> packages to subpackages of <code>org.springframework.ai.chat</code>\nNew functionality is <strong>text to image</strong> clients. Classes are <code>OpenAiImageModel</code> and <code>StabilityAiImageModel</code>. See the integration tests for usage, docs are coming soon.\nA new package <code>model</code> that contains interfaces and base classes to support creating AI Model Clients for any input/output data type combination. At the moment, the chat and image model packages implement this. We will be updating the embedding package to this new model soon.\nA new \"portable options\" design pattern. We wanted to provide as much portability in the <code>ModelCall</code> as possible across different chat based AI Models. There is a common set of generation options and then those that are specific to a model provider. A sort of \"duck typing\" approach is used. <code>ModelOptions</code> in the model package is a marker interface indicating implementations of this class will provide the options for a model. See <code>ImageOptions</code>, a subinterface that defines portable options across all text&#8594;image <code>ImageModel</code> implementations. Then <code>StabilityAiImageOptions</code> and <code>OpenAiImageOptions</code> provide the options specific to each model provider. All options classes are created via a fluent API builder, all can be passed into the portable <code>ImageModel</code> API. These option data types are used in autoconfiguration/configuration properties for the <code>ImageModel</code> implementations.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 0.8.0::January 24, 2024 Update::0'),
('b5dd62b2-37ca-4508-8a86-539e41f140c4','The <code>TokenCountBatchingStrategy</code> checks if any single document exceeds the configured maximum and throws an <code>IllegalArgumentException</code> if it does.\nBy setting a very high limit in the batching strategy, we ensure that this check never fails.\nDocuments or batches exceeding the model&#8217;s limit are silently truncated and processed by the embedding model&#8217;s auto-truncation feature.\n\n\nBest Practices\n\nWhen using auto-truncation:\n\nSet the batching strategy&#8217;s max input token count to be at least 5-10x larger than the model&#8217;s actual limit to avoid premature exceptions from the batching strategy.\nMonitor your logs for truncation warnings from the embedding model (note: not all models log truncation events).\nConsider the implications of silent truncation on your embedding quality.\nTest with sample documents to ensure truncated embeddings still meet your requirements.\nDocument this configuration for future maintainers, as it is non-standard.\n\n\nWhile auto-truncation prevents errors, it can result in incomplete embeddings. Important information at the end of long documents may be lost. If your application requires all content to be embedded, split documents into smaller chunks before embedding.\n\nSpring Boot Auto-Configuration\n\nIf you&#8217;re using Spring Boot auto-configuration, you must provide a custom <code>BatchingStrategy</code> bean to override the default one that comes with Spring AI:\n\n@Bean\npublic BatchingStrategy customBatchingStrategy() {\n    // This bean will override the default BatchingStrategy\n    return new TokenCountBatchingStrategy(\n            EncodingType.CL100K_BASE,\n            132900,  // Much higher than model\'s actual limit\n            0.1\n    );\n}\n\nThe presence of this bean in your application context will automatically replace the default batching strategy used by all vector stores.',0x00,'asciidoc::vectordbs.adoc::Batching Strategy::Working with Auto-Truncation::1'),
('402a9c91-5f92-4eae-ade5-541a8b18249c','The input arguments and result from the tool call are not exported by default, as they can be potentially sensitive.\n\nSpring AI supports exporting tool call arguments and result data as span attributes.\n\n\n\nIf you enable the inclusion of the tool call arguments and result in the observations, there&#8217;s a risk of exposing sensitive or private information. Please, be careful!',0x00,'asciidoc::index.adoc::Tool Calling::Tool Call Arguments and Result Data::0'),
('54df5882-19ed-499f-b72c-546eec8d0205','Spring AI provides strategic cache placement through the <code>AnthropicCacheStrategy</code> enum.\nEach strategy automatically places cache breakpoints at optimal locations while staying within Anthropic&#8217;s 4-breakpoint limit.\n\n\n\nDue to Anthropic&#8217;s cascade invalidation, changing tool definitions will invalidate ALL downstream cache breakpoints (system, messages).\nTool stability is critical when using <code>SYSTEM_AND_TOOLS</code> or <code>CONVERSATION_HISTORY</code> strategies.',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Cache Strategies::0'),
('401e3f84-478f-4f24-8299-548ba7c99031','@SuppressWarnings(\"CheckReturnValue\")\npublic static class GroupExpressionContext extends BooleanExpressionContext {\n\n    public TerminalNode LEFT_PARENTHESIS() {\n        return getToken(FiltersParser.LEFT_PARENTHESIS, 0);\n    }\n\n    public BooleanExpressionContext booleanExpression() {\n        return getRuleContext(BooleanExpressionContext.class, 0);\n    }\n\n    public TerminalNode RIGHT_PARENTHESIS() {\n        return getToken(FiltersParser.RIGHT_PARENTHESIS, 0);\n    }\n\n    public GroupExpressionContext(BooleanExpressionContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterGroupExpression(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitGroupExpression(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitGroupExpression(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('8fd3ec63-fc34-49f0-9fdf-5499fbfe1f23','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-vertex-ai-gemini/src/main/java/org/springframework/ai/vertexai/gemini/VertexAiGeminiChatModel.java\">VertexAiGeminiChatModel</a> implements the <code>ChatModel</code> and uses the <code>VertexAI</code> to connect to the Vertex AI Gemini service.\n\nAdd the <code>spring-ai-vertex-ai-gemini</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-vertex-ai-gemini&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-vertex-ai-gemini\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>VertexAiGeminiChatModel</code> and use it for text generations:\n\nVertexAI vertexApi =  new VertexAI(projectId, location);\n\nvar chatModel = new VertexAiGeminiChatModel(this.vertexApi,\n    VertexAiGeminiChatOptions.builder()\n        .model(ChatModel.GEMINI_2_0_FLASH)\n        .temperature(0.4)\n    .build());\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>VertexAiGeminiChatOptions</code> provides the configuration information for the chat requests.\nThe <code>VertexAiGeminiChatOptions.Builder</code> is fluent options builder.',0x00,'asciidoc::vertexai-gemini-chat.adoc::Manual Configuration::0'),
('a298236b-9193-4e10-b4a3-54ec1a335200','The simplest way to delete documents is by providing a list of document IDs:\n\nvoid delete(List&lt;String&gt; idList);\n\nThis method removes all documents whose IDs match those in the provided list.\nIf any ID in the list doesn&#8217;t exist in the store, it will be ignored.\n\n// Create and add document\nDocument document = new Document(\"The World is Big\",\n    Map.of(\"country\", \"Netherlands\"));\nvectorStore.add(List.of(document));\n\n// Delete document by ID\nvectorStore.delete(List.of(document.getId()));',0x00,'asciidoc::vectordbs.adoc::Deleting Documents from Vector Store::Delete by Document IDs::0'),
('73668cf1-83bf-48e8-9124-55526971f592','/**\n * @author Christian Tzolov\n */\npublic class FilterHelperTests {\n\n    @Test\n    public void negateEQ() {\n        assertThat(new FilterExpressionTextParser().parse(\"NOT key == \'UK\' \")).isEqualTo(new Filter.Expression(ExpressionType.NOT, new Filter.Expression(ExpressionType.EQ, new Key(\"key\"), new Value(\"UK\")), null));\n        assertThat(FilterHelper.negate(new FilterExpressionTextParser().parse(\"NOT key == \'UK\' \"))).isEqualTo(new Filter.Expression(ExpressionType.NE, new Key(\"key\"), new Value(\"UK\")));\n        assertThat(FilterHelper.negate(new FilterExpressionTextParser().parse(\"NOT (key == \'UK\') \"))).isEqualTo(new Filter.Group(new Filter.Expression(ExpressionType.NE, new Key(\"key\"), new Value(\"UK\"))));\n    }\n\n    @Test\n    public void negateNE() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key != \'UK\' \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.EQ, new Key(\"key\"), new Value(\"UK\")));\n    }\n\n    @Test\n    public void negateGT() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key > 13 \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.LTE, new Key(\"key\"), new Value(13)));\n    }\n\n    @Test\n    public void negateGTE() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key >= 13 \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.LT, new Key(\"key\"), new Value(13)));\n    }\n\n    @Test\n    public void negateLT() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key < 13 \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.GTE, new Key(\"key\"), new Value(13)));\n    }\n\n    @Test\n    public void negateLTE() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key <= 13 \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.GT, new Key(\"key\"), new Value(13)));\n    }\n\n    @Test\n    public void negateIN() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key IN [11, 12, 13] \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.NIN, new Key(\"key\"), new Value(List.of(11, 12, 13))));\n    }\n\n    @Test\n    public void negateNIN() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key NIN [11, 12, 13] \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.IN, new Key(\"key\"), new Value(List.of(11, 12, 13))));\n    }\n\n    @Test\n    public void negateNIN2() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT key NOT IN [11, 12, 13] \");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Expression(ExpressionType.IN, new Key(\"key\"), new Value(List.of(11, 12, 13))));\n    }\n\n    @Test\n    public void negateAND() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT(key >= 11 AND key < 13)\");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Group(new Filter.Expression(ExpressionType.OR, new Filter.Expression(ExpressionType.LT, new Key(\"key\"), new Value(11)), new Filter.Expression(ExpressionType.GTE, new Key(\"key\"), new Value(13)))));\n    }\n\n    @Test\n    public void negateOR() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT(key >= 11 OR key < 13)\");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Group(new Filter.Expression(ExpressionType.AND, new Filter.Expression(ExpressionType.LT, new Key(\"key\"), new Value(11)), new Filter.Expression(ExpressionType.GTE, new Key(\"key\"), new Value(13)))));\n    }\n\n    @Test\n    public void negateNot() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT NOT(key >= 11)\");\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Group(new Filter.Expression(ExpressionType.LT, new Key(\"key\"), new Value(11))));\n    }\n\n    @Test\n    public void negateNestedNot() {\n        var exp = new FilterExpressionTextParser().parse(\"NOT(NOT(key >= 11))\");\n        assertThat(exp).isEqualTo(new Filter.Expression(ExpressionType.NOT, new Filter.Group(new Filter.Expression(ExpressionType.NOT, new Filter.Group(new Filter.Expression(ExpressionType.GTE, new Key(\"key\"), new Value(11)))))));\n        assertThat(FilterHelper.negate(exp)).isEqualTo(new Filter.Group(new Filter.Expression(ExpressionType.LT, new Key(\"key\"), new Value(11))));\n    }\n\n    @Test\n    public void expandIN() {\n        var exp = new FilterExpressionTextParser().parse(\"key IN [11, 12, 13] \");\n        assertThat(new InNinTestConverter().convertExpression(exp)).isEqualTo(\"key EQ 11 OR key EQ 12 OR key EQ 13\");\n    }\n\n    @Test\n    public void expandNIN() {\n        var exp1 = new FilterExpressionTextParser().parse(\"key NIN [11, 12, 13] \");\n        var exp2 = new FilterExpressionTextParser().parse(\"key NOT IN [11, 12, 13] \");\n        assertThat(exp1).isEqualTo(exp2);\n        assertThat(new InNinTestConverter().convertExpression(exp1)).isEqualTo(\"key NE 11 AND key NE 12 AND key NE 13\");\n    }\n\n    private static class InNinTestConverter extends PrintFilterExpressionConverter {\n\n        @Override\n        public void doExpression(Expression expression, StringBuilder context) {\n            if (expression.type() == ExpressionType.IN) {\n                FilterHelper.expandIn(expression, context, this);\n            } else if (expression.type() == ExpressionType.NIN) {\n                FilterHelper.expandNin(expression, context, this);\n            } else {\n                super.doExpression(expression, context);\n            }\n        }\n    }\n}',0x01,'cu::FilterHelperTests.java'),
('cdc23c66-3d66-4d4f-97f3-556daca1e54c','A running Neo4j (5.15+) instance. The following options are available:\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>Neo4jVectorStore</code>.',0x00,'asciidoc::neo4j.adoc::Prerequisites::0'),
('c5edcc72-8078-403f-acfd-5574c92de6ed','The <code>spring.ai.chat.client</code> observations are recorded when a ChatClient <code>call()</code> or <code>stream()</code> operations are invoked.\nThey measure the time spent performing the invocation and propagate the related tracing information.',0x00,'asciidoc::index.adoc::Chat Client::0'),
('baab33c1-5a54-41ad-9e4a-5594a99a0e82','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai-sdk/src/main/java/org/springframework/ai/openaisdk/OpenAiSdkEmbeddingModel.java\">OpenAiSdkEmbeddingModel</a> implements the <code>EmbeddingModel</code> and uses the official OpenAI Java SDK to connect to the OpenAI service.\n\nIf you are not using Spring Boot auto-configuration, you can manually configure the OpenAI SDK Embedding Model.\nFor this add the <code>spring-ai-openai-sdk</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-openai-sdk&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file:\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-openai-sdk\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThe <code>spring-ai-openai-sdk</code> dependency provides access also to the <code>OpenAiSdkChatModel</code> and <code>OpenAiSdkImageModel</code>.\nFor more information about the <code>OpenAiSdkChatModel</code> refer to the <a href=\"api/chat/openai-sdk-chat.html\">OpenAI SDK Chat</a> section.\n\nNext, create an <code>OpenAiSdkEmbeddingModel</code> instance and use it to compute the similarity between two input texts:\n\nvar embeddingOptions = OpenAiSdkEmbeddingOptions.builder()\n    .model(\"text-embedding-ada-002\")\n    .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n    .build();\n\nvar embeddingModel = new OpenAiSdkEmbeddingModel(embeddingOptions);\n\nEmbeddingResponse embeddingResponse = embeddingModel\n    .embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));\n\nThe <code>OpenAiSdkEmbeddingOptions</code> provides the configuration information for the embedding requests.\nThe options class offers a <code>builder()</code> for easy options creation.',0x00,'asciidoc::openai-sdk-embeddings.adoc::Manual Configuration::0'),
('98874a80-0e01-40f1-ae43-55d72acc75f9','Alternatively, you can access environment variables in your Java code:\n\nString weaviateApiKey = System.getenv(\"WEAVIATE_API_KEY\");\nString openAiApiKey = System.getenv(\"OPENAI_API_KEY\");\n\nIf you choose to create a shell script to manage your environment variables, be sure to run it prior to starting your application by \"sourcing\" the file, i.e. <code>source &lt;your_script_name&gt;.sh</code>.',0x00,'asciidoc::weaviate.adoc::Configuration::Option 2: Accessing Environment Variables Programmatically::0'),
('ba550d2a-71c5-4f9b-8e46-55f67f65cc2d','Custom Template\n\nThe <code>VectorStoreChatMemoryAdvisor</code> uses a default template to augment the system message with the retrieved conversation memory. You can customize this behavior by providing your own <code>PromptTemplate</code> object via the <code>.promptTemplate()</code> builder method.\n\nThe <code>PromptTemplate</code> provided here customizes how the advisor merges retrieved memory with the system message. This is distinct from configuring a <code>TemplateRenderer</code> on the <code>ChatClient</code> itself (using <code>.templateRenderer()</code>), which affects the rendering of the initial user/system prompt content <strong>before</strong> the advisor runs. See <a href=\"api/chatclient.html#_prompt_templates\">ChatClient Prompt Templates</a> for more details on client-level template rendering.\n\nThe custom <code>PromptTemplate</code> can use any <code>TemplateRenderer</code> implementation (by default, it uses <code>StPromptTemplate</code> based on the <a href=\"https://www.stringtemplate.org/\">StringTemplate</a> engine). The important requirement is that the template must contain the following two placeholders:\n\nan <code>instructions</code> placeholder to receive the original system message.\na <code>long_term_memory</code> placeholder to receive the retrieved conversation memory.',0x00,'asciidoc::chat-memory.adoc::Memory in Chat Client::VectorStoreChatMemoryAdvisor::0'),
('17769414-e72c-4eff-b25c-562e858b7806','Starting 1.0.0-M6, Spring AI transitioned to using Amazon Bedrock&#8217;s Converse API for all Chat conversation implementations in Spring AI.\nAll the Amazon Bedrock Chat models are removed except the Embedding models for Cohere and Titan.\n\nRefer to <a href=\"api/chat/bedrock-converse.html\">Bedrock Converse</a> documentation for using the chat models.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M6::Removal of deprecated Amazon Bedrock chat models::0'),
('163aadf5-69a4-4e73-af7c-56b5fa01f254','The following features are not yet supported in the OpenAI SDK implementation:\n\nAudio speech generation (TTS)\nAudio transcription\nModeration API\nFile API operations\n\n\nThese features are available in the <a href=\"api/chat/openai-chat.html\">Spring AI OpenAI</a> implementation.',0x00,'asciidoc::openai-sdk-chat.adoc::Limitations::0'),
('0edf5290-cc1c-4c2e-b58a-572b1aea195c','A running MariaDB (11.7+) instance. The following options are available:\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>MariaDBVectorStore</code>.',0x00,'asciidoc::mariadb.adoc::Prerequisites::0'),
('8994cb17-ec95-4f45-a1b0-5750b0b7111a','To use the Mistral AI OCR API, you will need to add the <code>spring-ai-mistral-ai</code> dependency to your project.\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-mistral-ai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-mistral-ai\'\n}',0x00,'asciidoc::mistralai-chat.adoc::Prerequisites::Add Dependencies::0'),
('64d0fbef-d15f-4da0-b691-577d42158f40','Observability features are currently supported only for <code>ImageModel</code> implementations from the following AI model\nproviders: OpenAI.\nAdditional AI model providers will be supported in a future release.\n\nThe <code>gen_ai.client.operation</code> observations are recorded on image model method calls.\nThey measure the time spent on method completion and propagate the related tracing information.\n\nThe <code>gen_ai.client.token.usage</code> metrics measures number of input and output tokens used by a single model call.\n\n\n\n\n\nFor measuring user tokens, the previous table lists the values present in an observation trace.\nUse the metric name <code>gen_ai.client.token.usage</code> that is provided by the <code>ImageModel</code>.',0x00,'asciidoc::index.adoc::Image Model::0'),
('ddc38d08-4f1a-49c8-8f3e-57d34fcababc','@Configuration\npublic class ChatClientExample {\n\n    @Bean\n    CommandLineRunner cli(\n            @Qualifier(\"openAiChatClient\") ChatClient openAiChatClient,\n            @Qualifier(\"anthropicChatClient\") ChatClient anthropicChatClient) {\n\n        return args -&gt; {\n            var scanner = new Scanner(System.in);\n            ChatClient chat;\n\n            // Model selection\n            System.out.println(\"\\nSelect your AI model:\");\n            System.out.println(\"1. OpenAI\");\n            System.out.println(\"2. Anthropic\");\n            System.out.print(\"Enter your choice (1 or 2): \");\n\n            String choice = scanner.nextLine().trim();\n\n            if (choice.equals(\"1\")) {\n                chat = openAiChatClient;\n                System.out.println(\"Using OpenAI model\");\n            } else {\n                chat = anthropicChatClient;\n                System.out.println(\"Using Anthropic model\");\n            }\n\n            // Use the selected chat client\n            System.out.print(\"\\nEnter your question: \");\n            String input = scanner.nextLine();\n            String response = chat.prompt(input).call().content();\n            System.out.println(\"ASSISTANT: \" + response);\n\n            scanner.close();\n        };\n    }\n}\n\nMultiple OpenAI-Compatible API Endpoints\n\nThe <code>OpenAiApi</code> and <code>OpenAiChatModel</code> classes provide a <code>mutate()</code> method that allows you to create variations of existing instances with different properties.\nThis is particularly useful when you need to work with multiple OpenAI-compatible APIs.',0x00,'asciidoc::chatclient.adoc::Creating a ChatClient::Working with Multiple Chat Models::1'),
('c7c7a731-72c8-4624-a013-57db7c9fec8e','Multimodality refers to a model&#8217;s ability to simultaneously understand and process information from various sources, including text, images, audio, and other data formats.\nOpenAI supports text, vision, and audio input modalities.',0x00,'asciidoc::openai-chat.adoc::Multimodal::0'),
('1908cb95-c874-4412-98df-57f6fd4fb53a','<div class=\"paragraph\">\n<p><a href=\"https://www.oracle.com/artificial-intelligence/generative-ai/generative-ai-service/\">OCI GenAI Service</a> offers text embedding with on-demand models, or dedicated AI clusters.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://docs.oracle.com/en-us/iaas/Content/generative-ai/embed-models.htm\">OCI Embedding Models Page</a> and <a href=\"https://docs.oracle.com/en-us/iaas/Content/generative-ai/use-playground-embed.htm\">OCI Text Embeddings Page</a> provide detailed information about using and hosting embedding models on OCI.</p>\n</div>',0x00,'asciidoc::oci-genai-embeddings.adoc::0'),
('923944d0-fdb2-4fa9-8b5a-57ffada13e39','You can leverage the generic, portable <a href=\"https://docs.spring.io/spring-ai/reference/api/vectordbs.html#_metadata_filters\">metadata filters</a> with AzureVectorStore as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n   SearchRequest.builder()\n      .query(\"The World\")\n      .topK(TOP_K)\n      .similarityThreshold(SIMILARITY_THRESHOLD)\n      .filterExpression(\"country in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\").build());\n\nor programmatically using the expression DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n      .query(\"The World\")\n      .topK(TOP_K)\n      .similarityThreshold(SIMILARITY_THRESHOLD)\n      .filterExpression(b.and(\n         b.in(\"country\", \"UK\", \"NL\"),\n         b.gte(\"year\", 2020)).build()).build());\n\nThe portable filter expressions get automatically converted into the proprietary Azure Search <a href=\"https://learn.microsoft.com/en-us/azure/search/search-query-odata-filter\">OData filters</a>. For example, the following portable filter expression:\n\ncountry in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\n\nis converted into the following Azure OData <a href=\"https://learn.microsoft.com/en-us/azure/search/search-query-odata-filter\">filter expression</a>:\n\n$filter search.in(meta_country, \'UK,NL\', \',\') and meta_year ge 2020',0x00,'asciidoc::azure.adoc::Sample Code::Metadata filtering::0'),
('faebd305-4d8a-4eea-9c5a-58a3bde01eba','Azure Subscription: You will need an <a href=\"https://azure.microsoft.com/en-us/free/\">Azure subscription</a> to use any Azure service.\nAzure AI Search Service: Create an <a href=\"https://portal.azure.com/#create/Microsoft.Search\">AI Search service</a>. Once the service is created, obtain the admin apiKey from the <code>Keys</code> section under <code>Settings</code> and retrieve the endpoint from the <code>Url</code> field under the <code>Overview</code> section.\n(Optional) Azure OpenAI Service: Create an Azure <a href=\"https://portal.azure.com/#create/Microsoft.AIServicesOpenAI\">OpenAI service</a>. <strong>NOTE:</strong> You may have to fill out a separate form to gain access to Azure Open AI services. Once the service is created, obtain the endpoint and apiKey from the <code>Keys and Endpoint</code> section under <code>Resource Management</code>.',0x00,'asciidoc::azure.adoc::Prerequisites::0'),
('0cdc3170-a5ec-47d9-b107-58bca4b87f61','<div class=\"paragraph\">\n<p>Provides Bedrock Cohere Embedding model.\nIntegrate generative AI capabilities into essential apps and workflows that improve business outcomes.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://aws.amazon.com/bedrock/cohere-command-embed/\">AWS Bedrock Cohere Model Page</a> and <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/what-is-bedrock.html\">Amazon Bedrock User Guide</a> contains detailed information on how to use the AWS hosted model.</p>\n</div>',0x00,'asciidoc::bedrock-cohere-embedding.adoc::0'),
('4ccd6c80-c5f5-4be9-b119-58d886725b6d','Mistral is OpenAI API-compatible and you can use the <a href=\"api/chat/openai-chat.html\">Spring AI OpenAI</a> client to talk to Mistrial.\nFor this, you need to configure the OpenAI base URL to the Mistral AI platform: <code>spring.ai.openai.chat.base-url=https://api.mistral.ai</code>, and select a Mistral model: <code>spring.ai.openai.chat.options.model=mistral-small-latest</code> and set the Mistral AI API key: <code>spring.ai.openai.chat.api-key=&lt;YOUR MISTRAL API KEY</code>.\n\nCheck the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/chat/proxy/MistralWithOpenAiChatModelIT.java\">MistralWithOpenAiChatModelIT.java</a> tests for examples of using Mistral over Spring AI OpenAI.',0x00,'asciidoc::mistralai-chat.adoc::OpenAI API Compatibility::0'),
('910ed20d-3418-4690-ab9b-58db0e40ab11','All deletion methods may throw exceptions in case of errors:\n\nThe best practice is to wrap delete operations in try-catch blocks:\n\ntry {\n    vectorStore.delete(\"country == \'Bulgaria\'\");\n}\ncatch (Exception  e) {\n    logger.error(\"Invalid filter expression\", e);\n}',0x00,'asciidoc::vectordbs.adoc::Deleting Documents from Vector Store::Error Handling When Calling the Delete API::0'),
('b4bdf702-322e-49f6-97df-58efbd5c8e3a','You can use the following properties in your Spring Boot configuration to customize the Pinecone vector store.',0x00,'asciidoc::pinecone.adoc::Auto-configuration::Configuration properties::0'),
('8b94a81b-3526-42ef-96cc-59148d4329c0','Mistral AI models that offer vision multimodal support include <code>pixtral-large-latest</code>.\nRefer to the <a href=\"https://docs.mistral.ai/capabilities/vision/\">Vision</a> guide for more information.\n\nThe Mistral AI <a href=\"https://docs.mistral.ai/api/#tag/chat/operation/chat_completion_v1_chat_completions_post\">User Message API</a> can incorporate a list of base64-encoded images or image urls with the message.\nSpring AI’s <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-client-chat/src/main/java/org/springframework/ai/chat/messages/Message.java\">Message</a> interface facilitates multimodal AI models by introducing the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-commons/src/main/java/org/springframework/ai/content/Media.java\">Media</a> type.\nThis type encompasses data and details regarding media attachments in messages, utilizing Spring’s <code>org.springframework.util.MimeType</code> and a <code>org.springframework.core.io.Resource</code> for the raw media data.\n\nBelow is a code example excerpted from <code>MistralAiChatModelIT.java</code>, illustrating the fusion of user text with an image.\n\nvar imageResource = new ClassPathResource(\"/multimodal.test.png\");\n\nvar userMessage = new UserMessage(\"Explain what do you see on this picture?\",\n        new Media(MimeTypeUtils.IMAGE_PNG, this.imageResource));\n\nChatResponse response = chatModel.call(new Prompt(this.userMessage,\n        ChatOptions.builder().model(MistralAiApi.ChatModel.PIXTRAL_LARGE.getValue()).build()));\n\nor the image URL equivalent:\n\nvar userMessage = new UserMessage(\"Explain what do you see on this picture?\",\n        new Media(MimeTypeUtils.IMAGE_PNG,\n                URI.create(\"https://docs.spring.io/spring-ai/reference/_images/multimodal.test.png\")));\n\nChatResponse response = chatModel.call(new Prompt(this.userMessage,\n        ChatOptions.builder().model(MistralAiApi.ChatModel.PIXTRAL_LARGE.getValue()).build()));\n\nYou can pass multiple images as well.\n\nThe example shows a model taking as an input the <code>multimodal.test.png</code> image:\n\nalong with the text message \"Explain what do you see on this picture?\", and generating a response like this:\n\nThis is an image of a fruit bowl with a simple design. The bowl is made of metal with curved wire edges that\ncreate an open structure, allowing the fruit to be visible from all angles. Inside the bowl, there are two\nyellow bananas resting on top of what appears to be a red apple. The bananas are slightly overripe, as\nindicated by the brown spots on their peels. The bowl has a metal ring at the top, likely to serve as a handle\nfor carrying. The bowl is placed on a flat surface with a neutral-colored background that provides a clear\nview of the fruit inside.',0x00,'asciidoc::mistralai-chat.adoc::Multimodal::Vision::0'),
('4cacac2f-a685-4afb-a4e5-59a7ceaf1490','<div class=\"paragraph\">\n<p>This section will walk you through setting up the Chroma VectorStore to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://docs.trychroma.com/\">Chroma</a> is the open-source embedding database. It gives you the tools to store document embeddings, content, and metadata and to search through those embeddings, including metadata filtering.</p>\n</div>',0x00,'asciidoc::chroma.adoc::0'),
('4e520831-20b7-4e38-9d65-59c0a89f00a5','The <code>JsonReader</code> processes JSON documents, converting them into a list of <code>Document</code> objects.\n\nExample\n\n@Component\nclass MyJsonReader {\n\n	private final Resource resource;\n\n    MyJsonReader(@Value(\"classpath:bikes.json\") Resource resource) {\n        this.resource = resource;\n    }\n\n	List&lt;Document&gt; loadJsonAsDocuments() {\n        JsonReader jsonReader = new JsonReader(this.resource, \"description\", \"content\");\n        return jsonReader.get();\n	}\n}\n\nConstructor Options\n\nThe <code>JsonReader</code> provides several constructor options:\n\n<code>JsonReader(Resource resource)</code>\n<code>JsonReader(Resource resource, String&#8230;&#8203; jsonKeysToUse)</code>\n<code>JsonReader(Resource resource, JsonMetadataGenerator jsonMetadataGenerator, String&#8230;&#8203; jsonKeysToUse)</code>\n\n\nParameters\n\n<code>resource</code>: A Spring <code>Resource</code> object pointing to the JSON file.\n<code>jsonKeysToUse</code>: An array of keys from the JSON that should be used as the text content in the resulting <code>Document</code> objects.\n<code>jsonMetadataGenerator</code>: An optional <code>JsonMetadataGenerator</code> to create metadata for each <code>Document</code>.\n\n\nBehavior\n\nThe <code>JsonReader</code> processes JSON content as follows:\n\nIt can handle both JSON arrays and single JSON objects.\nFor each JSON object (either in an array or a single object):\n\n\nUsing JSON Pointers\n\nThe <code>JsonReader</code> now supports retrieving specific parts of a JSON document using JSON Pointers. This feature allows you to easily extract nested data from complex JSON structures.\n\nThe <code>get(String pointer)</code> method\n\npublic List&lt;Document&gt; get(String pointer)\n\nThis method allows you to use a JSON Pointer to retrieve a specific part of the JSON document.\n\nParameters\n\n<code>pointer</code>: A JSON Pointer string (as defined in RFC 6901) to locate the desired element within the JSON structure.\n\n\nReturn Value\n\nReturns a <code>List&lt;Document&gt;</code> containing the documents parsed from the JSON element located by the pointer.\n\n\nBehavior\n\nThe method uses the provided JSON Pointer to navigate to a specific location in the JSON structure.\nIf the pointer is valid and points to an existing element:\nIf the pointer is invalid or points to a non-existent element, it throws an <code>IllegalArgumentException</code>.\n\n\nExample\n\nJsonReader jsonReader = new JsonReader(resource, \"description\");\nList&lt;Document&gt; documents = this.jsonReader.get(\"/store/books/0\");\n\nExample JSON Structure\n\n[\n  {\n    \"id\": 1,\n    \"brand\": \"Trek\",\n    \"description\": \"A high-performance mountain bike for trail riding.\"\n  },\n  {\n    \"id\": 2,\n    \"brand\": \"Cannondale\",\n    \"description\": \"An aerodynamic road bike for racing enthusiasts.\"\n  }\n]',0x00,'asciidoc::etl-pipeline.adoc::DocumentReaders::JSON::0'),
('088e28b3-7570-4836-9c4b-59ff2a248875','public static final class Builder {\n\n    private ChatClient.Builder chatClientBuilder;\n\n    @Nullable\n    private PromptTemplate promptTemplate;\n\n    private String targetLanguage;\n\n    private Builder() {\n    }\n\n    public Builder chatClientBuilder(ChatClient.Builder chatClientBuilder) {\n        this.chatClientBuilder = chatClientBuilder;\n        return this;\n    }\n\n    public Builder promptTemplate(PromptTemplate promptTemplate) {\n        this.promptTemplate = promptTemplate;\n        return this;\n    }\n\n    public Builder targetLanguage(String targetLanguage) {\n        this.targetLanguage = targetLanguage;\n        return this;\n    }\n\n    public TranslationQueryTransformer build() {\n        return new TranslationQueryTransformer(this.chatClientBuilder, this.promptTemplate, this.targetLanguage);\n    }\n}',0x01,'cu::TranslationQueryTransformer.java'),
('6c4c4a72-aca0-4f08-97cf-5a1f50eae03b','This will create a <code>EmbeddingModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the <code>EmbeddingModel</code> implementation.\n\nspring.ai.zhipuai.api-key=YOUR_API_KEY\nspring.ai.zhipuai.embedding.options.model=embedding-2\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::zhipuai-embeddings.adoc::Sample Controller::0'),
('609431f8-e248-42ea-b492-5a656c41398e','A technique termed Retrieval Augmented Generation (RAG) has emerged to address the challenge of incorporating relevant data into prompts for accurate AI model responses.\n\nThe approach involves a batch processing style programming model, where the job reads unstructured data from your documents, transforms it, and then writes it into a vector database.\nAt a high level, this is an ETL (Extract, Transform and Load) pipeline.\nThe vector database is used in the retrieval part of RAG technique.\n\nAs part of loading the unstructured data into the vector database, one of the most important transformations is to split the original document into smaller pieces.\nThe procedure of splitting the original document into smaller pieces has two important steps:\n\nSplit the document into parts while preserving the semantic boundaries of the content.\nFor example, for a document with paragraphs and tables, one should avoid splitting the document in the middle of a paragraph or table.\nFor code, avoid splitting the code in the middle of a method&#8217;s implementation.\nSplit the document&#8217;s parts further into parts whose size is a small percentage of the AI Model&#8217;s token limit.\n\n\nThe next phase in RAG is processing user input.\nWhen a user&#8217;s question is to be answered by an AI model, the question and all the &#8220;similar&#8221; document pieces are placed into the prompt that is sent to the AI model.\nThis is the reason to use a vector database. It is very good at finding similar content.\n\nThe <a href=\":api/etl-pipeline.html\">ETL Pipeline</a> provides further information about orchestrating the flow of extracting data from data sources and storing it in a structured vector store, ensuring data is in the optimal format for retrieval when passing it to the AI model.\nThe <a href=\":api/chatclient.html#_retrieval_augmented_generation\">ChatClient - RAG</a> explains how to use the <code>QuestionAnswerAdvisor</code> to enable the RAG capability in your application.',0x00,'asciidoc::concepts.adoc::Bringing Your Data &amp; APIs to the AI Model::Retrieval Augmented Generation::0'),
('a7f28ebc-d574-468d-a66b-5a6729cdbef7','The <code>MarkdownDocumentReader</code> processes Markdown documents, converting them into a list of <code>Document</code> objects.\n\nExample\n\n@Component\nclass MyMarkdownReader {\n\n    private final Resource resource;\n\n    MyMarkdownReader(@Value(\"classpath:code.md\") Resource resource) {\n        this.resource = resource;\n    }\n\n    List&lt;Document&gt; loadMarkdown() {\n        MarkdownDocumentReaderConfig config = MarkdownDocumentReaderConfig.builder()\n            .withHorizontalRuleCreateDocument(true)\n            .withIncludeCodeBlock(false)\n            .withIncludeBlockquote(false)\n            .withAdditionalMetadata(\"filename\", \"code.md\")\n            .build();\n\n        MarkdownDocumentReader reader = new MarkdownDocumentReader(this.resource, config);\n        return reader.get();\n    }\n}\n\nThe <code>MarkdownDocumentReaderConfig</code> allows you to customize the behavior of the MarkdownDocumentReader:\n\n<code>horizontalRuleCreateDocument</code>: When set to <code>true</code>, horizontal rules in the Markdown will create new <code>Document</code> objects.\n<code>includeCodeBlock</code>: When set to <code>true</code>, code blocks will be included in the same <code>Document</code> as the surrounding text. When <code>false</code>, code blocks create separate <code>Document</code> objects.\n<code>includeBlockquote</code>: When set to <code>true</code>, blockquotes will be included in the same <code>Document</code> as the surrounding text. When <code>false</code>, blockquotes create separate <code>Document</code> objects.\n<code>additionalMetadata</code>: Allows you to add custom metadata to all created <code>Document</code> objects.\n\n\nSample Document: code.md\n\nThis is a Java sample application:\n\n```java\npackage com.example.demo;\n\nimport org.springframework.boot.SpringApplication;\nimport org.springframework.boot.autoconfigure.SpringBootApplication;\n\n@SpringBootApplication\npublic class DemoApplication {\n    public static void main(String[] args) {\n        SpringApplication.run(DemoApplication.class, args);\n    }\n}\n```\n\nMarkdown also provides the possibility to `use inline code formatting throughout` the entire sentence.\n\n---\n\nAnother possibility is to set block code without specific highlighting:\n\n```\n./mvnw spring-javaformat:apply\n```\n\nBehavior: The MarkdownDocumentReader processes the Markdown content and creates Document objects based on the configuration:\n\nHeaders become metadata in the Document objects.\nParagraphs become the content of Document objects.\nCode blocks can be separated into their own Document objects or included with surrounding text.\nBlockquotes can be separated into their own Document objects or included with surrounding text.\nHorizontal rules can be used to split the content into separate Document objects.\n\n\nThe reader preserves formatting like inline code, lists, and text styling within the content of the Document objects.',0x00,'asciidoc::etl-pipeline.adoc::DocumentReaders::Markdown::0'),
('829e2516-e278-4297-b67f-5a7796475344','For Microsoft Foundry :\n\nvar chatOptions = OpenAiSdkChatOptions.builder()\n    .baseUrl(\"https://your-resource.openai.azure.com\")\n    .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n    .deploymentName(\"gpt-4\")\n    .azureOpenAIServiceVersion(AzureOpenAIServiceVersion.V2024_10_01_PREVIEW)\n    .azure(true)  // Enables Microsoft Foundry mode\n    .build();\n\nvar chatModel = new OpenAiSdkChatModel(chatOptions);\n\nMicrosoft Foundry supports passwordless authentication. Add the <code>com.azure:azure-identity</code> dependency to your project. If you don&#8217;t provide an API key, the implementation will automatically attempt to use Azure credentials from your environment.',0x00,'asciidoc::openai-sdk-chat.adoc::Manual Configuration::Microsoft Foundry Configuration::0'),
('248dcfea-c04a-444d-becd-5ad9853d0ff6','The following types are not currently supported as input or output types for functions used as tools:\n\nPrimitive types\n<code>Optional</code>\nCollection types (e.g. <code>List</code>, <code>Map</code>, <code>Array</code>, <code>Set</code>)\nAsynchronous types (e.g. <code>CompletableFuture</code>, <code>Future</code>)\nReactive types (e.g. <code>Flow</code>, <code>Mono</code>, <code>Flux</code>).\n\n\nPrimitive types and collections are supported using the method-based tool specification approach. See <a href=\"#_methods_as_tools\">Methods as Tools</a> for more details.',0x00,'asciidoc::tools.adoc::Functions as Tools::Function Tool Limitations::0'),
('a62049b6-1a5f-44e1-b685-5b07846f3833','The combination of Anthropic&#8217;s research insights and Spring AI&#8217;s practical implementations provides a powerful framework for building effective LLM-based systems.\n\nBy following these patterns and principles, developers can create robust, maintainable, and effective AI applications that deliver real value while avoiding unnecessary complexity.\n\nThe key is to remember that sometimes the simplest solution is the most effective. Start with basic patterns, understand your use case thoroughly, and only add complexity when it demonstrably improves your system&#8217;s performance or capabilities.',0x00,'asciidoc::effective-agents.adoc::Conclusion::0'),
('850a5fcb-39f7-4cb8-b3b7-5c292222f0df','The following OpenAi Autoconfiguration chat properties have changed\n\nfrom <code>spring.ai.openai.model</code> to <code>spring.ai.openai.chat.options.model</code>.\nfrom <code>spring.ai.openai.temperature</code> to <code>spring.ai.openai.chat.options.temperature</code>.\n\n\nFind updated documentation about the OpenAi properties: <a href=\"https://docs.spring.io/spring-ai/reference/api/chat/openai-chat.html\" class=\"bare\">https://docs.spring.io/spring-ai/reference/api/chat/openai-chat.html</a>',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 0.8.0::January 13, 2024 Update::0'),
('0f4e99a0-e839-4253-9b9b-5c4104100216','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-minimax/src/main/java/org/springframework/ai/minimax/MiniMaxEmbeddingOptions.java\">MiniMaxEmbeddingOptions.java</a> provides the MiniMax configurations, such as the model to use and etc.\n\nThe default options can be configured using the <code>spring.ai.minimax.embedding.options</code> properties as well.\n\nAt start-time use the <code>MiniMaxEmbeddingModel</code> constructor to set the  default options used for all embedding requests.\nAt run-time you can override the default options, using a <code>MiniMaxEmbeddingOptions</code> instance as part of your <code>EmbeddingRequest</code>.\n\nFor example to override the default model name for a specific request:\n\nEmbeddingResponse embeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n        MiniMaxEmbeddingOptions.builder()\n            .model(\"Different-Embedding-Model-Deployment-Name\")\n        .build()));',0x00,'asciidoc::minimax-embeddings.adoc::Runtime Options::0'),
('dcb6447d-58f2-4298-bcfa-5c43db57e372','In addition to the similarity score, the raw distance value is still available in the document metadata:\n\nfor (Document doc : results) {\n    double score = doc.getScore();\n    float distance = (Float) doc.getMetadata().get(\"distance\");\n\n    System.out.println(\"Score: \" + score + \", Distance: \" + distance);\n}',0x00,'asciidoc::mariadb.adoc::Similarity Scores::Distance Metadata::0'),
('cc1ee3b8-4a95-4baa-abf8-5cf56f6f6d18','Install the <a href=\"https://cloud.google.com/sdk/docs/install\">gcloud</a> CLI, appropriate for you OS.\nAuthenticate by running the following command.\nReplace <code>PROJECT_ID</code> with your Google Cloud project ID and <code>ACCOUNT</code> with your Google Cloud username.\n\n\ngcloud config set project &lt;PROJECT_ID&gt; &amp;&amp;\ngcloud auth application-default login &lt;ACCOUNT&gt;',0x00,'asciidoc::vertexai-embeddings-multimodal.adoc::Prerequisites::0'),
('82921046-8390-4014-9639-5d5649a02201','The prefix <code>spring.ai.azure.openai</code> is the property prefix to configure the connection to Azure OpenAI.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the chat auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.chat</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.chat=azure-openai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.chat=none (or any value which doesn&#8217;t match azure-openai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.azure.openai.chat</code> is the property prefix that configures the <code>ChatModel</code> implementation for Azure OpenAI.\n\n\n\nAll properties prefixed with <code>spring.ai.azure.openai.chat.options</code> can be overridden at runtime by adding a request specific <a href=\"#chat-options\">Runtime Options</a> to the <code>Prompt</code> call.',0x00,'asciidoc::azure-openai-chat.adoc::Auto-configuration::Chat Properties::0'),
('f8974c29-a3ce-45d9-8c18-5e0880bd9b92','A key component for prompt templating in Spring AI is the <code>PromptTemplate</code> class, designed to facilitate the creation of structured prompts that are then sent to the AI model for processing\n\npublic class PromptTemplate implements PromptTemplateActions, PromptTemplateMessageActions {\n\n    // Other methods to be discussed later\n}\n\nThis class uses the <code>TemplateRenderer</code> API to render templates. By default, Spring AI uses the <code>StTemplateRenderer</code> implementation, which is based on the open-source <a href=\"https://www.stringtemplate.org/\">StringTemplate</a> engine developed by Terence Parr. Template variables are identified by the <code>{}</code> syntax, but you can configure the delimiters to use other syntax as well.\n\npublic interface TemplateRenderer extends BiFunction&lt;String, Map&lt;String, Object&gt;, String&gt; {\n\n	@Override\n	String apply(String template, Map&lt;String, Object&gt; variables);\n\n}\n\nSpring AI uses the <code>TemplateRenderer</code> interface to handle the actual substitution of variables into the template string.\nThe default implementation uses <a href=\"#StringTemplate\">[StringTemplate]</a>.\nYou can provide your own implementation of <code>TemplateRenderer</code> if you need custom logic.\nFor scenarios where no template rendering is required (e.g., the template string is already complete), you can use the provided <code>NoOpTemplateRenderer</code>.\n\nPromptTemplate promptTemplate = PromptTemplate.builder()\n    .renderer(StTemplateRenderer.builder().startDelimiterToken(\'&lt;\').endDelimiterToken(\'&gt;\').build())\n    .template(\"\"\"\n            Tell me the names of 5 movies whose soundtrack was composed by &lt;composer&gt;.\n            \"\"\")\n    .build();\n\nString prompt = promptTemplate.render(Map.of(\"composer\", \"John Williams\"));\n\nThe interfaces implemented by this class support different aspects of prompt creation:\n\n<code>PromptTemplateStringActions</code> focuses on creating and rendering prompt strings, representing the most basic form of prompt generation.\n\n<code>PromptTemplateMessageActions</code> is tailored for prompt creation through the generation and manipulation of <code>Message</code> objects.\n\n<code>PromptTemplateActions</code> is designed to return the <code>Prompt</code> object, which can be passed to <code>ChatModel</code> for generating a response.\n\nWhile these interfaces might not be used extensively in many projects, they show the different approaches to prompt creation.\n\nThe implemented interfaces are\n\npublic interface PromptTemplateStringActions {\n\n	String render();\n\n	String render(Map&lt;String, Object&gt; model);\n\n}\n\nThe method <code>String render()</code>: Renders a prompt template into a final string format without external input, suitable for templates without placeholders or dynamic content.',0x00,'asciidoc::prompt.adoc::API Overview::PromptTemplate::0'),
('bbda2d68-4951-42ee-a202-5e4d69c2acbe','<div class=\"paragraph\">\n<p>This section walks you through setting up the Qdrant <code>VectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://www.qdrant.tech/\">Qdrant</a> is an open-source, high-performance vector search engine/database. It uses HNSW (Hierarchical Navigable Small World) algorithm for efficient k-NN search operations and provides advanced filtering capabilities for metadata-based queries.</p>\n</div>',0x00,'asciidoc::qdrant.adoc::0'),
('a30ff773-4a2e-4e66-af55-5e76c894b180','Below are the steps to provision SAP Hana Database using a trial account\n\nLet&#8217;s start with creating a <a href=\"https://temp-mail.org/en/\">temporary email</a> for registration purposes\n\nDon&#8217;t close the above window, otherwise a new email id would get generated.\n\nGo to <a href=\"https://sap.com/\">sap.com</a> and navigate to <code>products</code> &#8594; <code>Trials and Demos</code>\n\nClick <code>Advanced Trials</code>\n\nClick <code>SAP BTP Trial</code>\n\nClick <code>Start your free 90-day trial</code>\n\nPaste the <code>temporary email id</code> that we created in the first step, and click <code>Next</code>\n\nWe fill in our details and click <code>Submit</code>\n\nIt&#8217;s time to check the inbox of our temporary email account\n\nNotice that there is an email received in our temporary email account\n\nOpen the email and <code>click to activate</code> the trial account\n\nIt will prompt to create a <code>password</code>. Provide a password and click <code>Submit</code>\n\nThe trial account is now created. Click to <code>start the trial</code>\n\nProvide your phone number and click <code>Continue</code>\n\nWe receive an OTP on the phone number. Provide the <code>code</code> and click <code>continue</code>\n\nSelect the <code>region</code> as <code>US East (VA) - AWS</code>\n\nClick <code>Continue</code>\n\nThe <code>SAP BTP trial</code> account is ready. Click <code>Go to your Trial account</code>\n\nClick the <code>Trial</code> sub-account\n\nOpen <code>Instances and Subscriptions</code>\n\nIt&#8217;s time to create a subscription. Click the <code>Create</code> button\n\nWhile creating a subscription, Select <code>service</code> as <code>SAP Hana Cloud</code> and <code>Plan</code> as <code>tools</code> and click <code>Create</code>\n\nNotice that <code>SAP Hana Cloud</code> subscription is now created. Click <code>Users</code> on the left panel\n\nSelect the username (temporary email that we supplied earlier) and click <code>Assign Role Collection</code>\n\nSearch <code>hana</code> and select all the 3 role collections that gets displayed. Click <code>Assign Role Collection</code>\n\nOur <code>user</code> now has all the 3 role collections. Click <code>Instances and Subscriptions</code>\n\nNow, click <code>SAP Hana Cloud</code> application under subscriptions\n\nThere are no instances yet. Let&#8217;s click <code>Create Instance</code>\n\nSelect Type as <code>SAP HANA Cloud, SAP HANA Database</code>. Click <code>Next Step</code>\n\nProvide <code>Instance Name</code>, <code>Description</code>, <code>password</code> for DBADMIN administrator.\nSelect the latest version <code>2024.2 (QRC 1/2024)</code>. Click <code>Next Step</code>\n\nKeep everything as default. Click <code>Next Step</code>\n\nClick <code>Next Step</code>\n\nSelect <code>Allow all IP addresses</code> and click <code>Next Step</code>\n\nClick <code>Review and Create</code>\n\nClick <code>Create Instance</code>',0x00,'asciidoc::hanadb-provision-a-trial-account.adoc::Provision SAP HANA Cloud trial account::0'),
('f2d96b85-3bda-4f38-9bd7-5efbafc74b89','The <code>stream()</code> method lets you get an asynchronous response as shown below:\n\nFlux&lt;String&gt; output = chatClient.prompt()\n    .user(\"Tell me a joke\")\n    .stream()\n    .content();\n\nYou can also stream the <code>ChatResponse</code> using the method <code>Flux&lt;ChatResponse&gt; chatResponse()</code>.\n\nIn the future, we will offer a convenience method that will let you return a Java entity with the reactive <code>stream()</code> method.\nIn the meantime, you should use the <a href=\"api/structured-output-converter.html#StructuredOutputConverter\">Structured Output Converter</a> to convert the aggregated response explicitly as shown below.\nThis also demonstrates the use of parameters in the fluent API that will be discussed in more detail in a later section of the documentation.\n\nvar converter = new BeanOutputConverter&lt;&gt;(new ParameterizedTypeReference&lt;List&lt;ActorsFilms&gt;&gt;() {});\n\nFlux&lt;String&gt; flux = this.chatClient.prompt()\n    .user(u -&gt; u.text(\"\"\"\n                        Generate the filmography for a random actor.\n                        {format}\n                      \"\"\")\n            .param(\"format\", this.converter.getFormat()))\n    .stream()\n    .content();\n\nString content = this.flux.collectList().block().stream().collect(Collectors.joining());\n\nList&lt;ActorsFilms&gt; actorFilms = this.converter.convert(this.content);',0x00,'asciidoc::chatclient.adoc::ChatClient Responses::Streaming Responses::0'),
('3385347a-12e4-4a1c-a36a-5f4086c722ce','Pre-Retrieval modules are responsible for processing the user query to achieve the best possible retrieval results.\n\nQuery Transformation\n\nA component for transforming the input query to make it more effective for retrieval tasks, addressing challenges\nsuch as poorly formed queries, ambiguous terms, complex vocabulary, or unsupported languages.\n\nWhen using a <code>QueryTransformer</code>, it&#8217;s recommended to configure the <code>ChatClient.Builder</code> with a low temperature (e.g., 0.0) to ensure more deterministic and accurate results, improving retrieval quality.  The default temperature for most chat models is typically too high for optimal query transformation, leading to reduced retrieval effectiveness.\n\nCompressionQueryTransformer\n\nA <code>CompressionQueryTransformer</code> uses a large language model to compress a conversation history and a follow-up query\ninto a standalone query that captures the essence of the conversation.\n\nThis transformer is useful when the conversation history is long and the follow-up query is related\nto the conversation context.\n\nQuery query = Query.builder()\n        .text(\"And what is its second largest city?\")\n        .history(new UserMessage(\"What is the capital of Denmark?\"),\n                new AssistantMessage(\"Copenhagen is the capital of Denmark.\"))\n        .build();\n\nQueryTransformer queryTransformer = CompressionQueryTransformer.builder()\n        .chatClientBuilder(chatClientBuilder)\n        .build();\n\nQuery transformedQuery = queryTransformer.transform(query);\n\nThe prompt used by this component can be customized via the <code>promptTemplate()</code> method available in the builder.\n\nRewriteQueryTransformer\n\nA <code>RewriteQueryTransformer</code> uses a large language model to rewrite a user query to provide better results when\nquerying a target system, such as a vector store or a web search engine.\n\nThis transformer is useful when the user query is verbose, ambiguous, or contains irrelevant information\nthat may affect the quality of the search results.\n\nQuery query = new Query(\"I\'m studying machine learning. What is an LLM?\");\n\nQueryTransformer queryTransformer = RewriteQueryTransformer.builder()\n        .chatClientBuilder(chatClientBuilder)\n        .build();\n\nQuery transformedQuery = queryTransformer.transform(query);\n\nThe prompt used by this component can be customized via the <code>promptTemplate()</code> method available in the builder.\n\nTranslationQueryTransformer\n\nA <code>TranslationQueryTransformer</code> uses a large language model to translate a query to a target language that is supported\nby the embedding model used to generate the document embeddings. If the query is already in the target language,\nit is returned unchanged. If the language of the query is unknown, it is also returned unchanged.\n\nThis transformer is useful when the embedding model is trained on a specific language and the user query\nis in a different language.',0x00,'asciidoc::retrieval-augmented-generation.adoc::Modules::Pre-Retrieval::0'),
('cde824c2-9893-41f2-b0af-5f813a1e7284','The Pinecone Vector Store implementation provides access to the underlying native Pinecone client (<code>PineconeConnection</code>) through the <code>getNativeClient()</code> method:\n\nPineconeVectorStore vectorStore = context.getBean(PineconeVectorStore.class);\nOptional&lt;PineconeConnection&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    PineconeConnection client = nativeClient.get();\n    // Use the native client for Pinecone-specific operations\n}\n\nThe native client gives you access to Pinecone-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::pinecone.adoc::Accessing the Native Client::0'),
('bbdf30bf-97c3-465c-abc7-5f8fab2e4ed0','Manages the final stage of the ETL process, preparing documents for storage.\n\npublic interface DocumentWriter extends Consumer&lt;List&lt;Document&gt;&gt; {\n\n    default void write(List&lt;Document&gt; documents) {\n		accept(documents);\n	}\n}',0x00,'asciidoc::etl-pipeline.adoc::ETL Interfaces::DocumentWriter::0'),
('140abae2-7ffc-4b3a-8ce4-5fd80a0917d5','public final class SpringAIVectorStoreTypes {\n\n    private SpringAIVectorStoreTypes() {\n        // Avoids instantiation\n    }\n\n    public static final String VECTOR_STORE_PREFIX = \"spring.ai.vectorstore\";\n\n    public static final String TYPE = VECTOR_STORE_PREFIX + \".type\";\n\n    public static final String AZURE = \"azure\";\n\n    public static final String AZURE_COSMOS_DB = \"azure-cosmos-db\";\n\n    public static final String CASSANDRA = \"cassandra\";\n\n    public static final String CHROMA = \"chroma\";\n\n    public static final String ELASTICSEARCH = \"elasticsearch\";\n\n    public static final String GEMFIRE = \"gemfire\";\n\n    public static final String HANADB = \"hanadb\";\n\n    public static final String MARIADB = \"mariadb\";\n\n    public static final String MILVUS = \"milvus\";\n\n    public static final String MONGODB_ATLAS = \"mongodb-atlas\";\n\n    public static final String NEO4J = \"neo4j\";\n\n    public static final String OPENSEARCH = \"opensearch\";\n\n    public static final String ORACLE = \"oracle\";\n\n    public static final String PGVECTOR = \"pgvector\";\n\n    public static final String PINECONE = \"pinecone\";\n\n    public static final String QDRANT = \"qdrant\";\n\n    public static final String REDIS = \"redis\";\n\n    public static final String TYPESENSE = \"typesense\";\n\n    public static final String WEAVIATE = \"weaviate\";\n}',0x01,'cu::SpringAIVectorStoreTypes.java'),
('8c72f1f5-82b9-4d76-ae77-5ff19fc82b35','/**\n * Uses a large language model to rewrite a user query to provide better results when\n * querying a target system, such as a vector store or a web search engine.\n * <p>\n * This transformer is useful when the user query is verbose, ambiguous, or contains\n * irrelevant information that may affect the quality of the search results.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n * @see <a href=\"https://arxiv.org/pdf/2305.14283\">arXiv:2305.14283</a>\n */\npublic class RewriteQueryTransformer implements QueryTransformer {\n\n    private static final Logger logger = LoggerFactory.getLogger(RewriteQueryTransformer.class);\n\n    private static final PromptTemplate DEFAULT_PROMPT_TEMPLATE = new PromptTemplate(\"\"\"\n        Given a user query, rewrite it to provide better results when querying a {target}.\n        Remove any irrelevant information, and ensure the query is concise and specific.\n        \n        Original query:\n        {query}\n        \n        Rewritten query:\n        \"\"\");\n\n    private static final String DEFAULT_TARGET = \"vector store\";\n\n    private final ChatClient chatClient;\n\n    private final PromptTemplate promptTemplate;\n\n    private final String targetSearchSystem;\n\n    public RewriteQueryTransformer(ChatClient.Builder chatClientBuilder, @Nullable PromptTemplate promptTemplate, @Nullable String targetSearchSystem) {\n        Assert.notNull(chatClientBuilder, \"chatClientBuilder cannot be null\");\n        this.chatClient = chatClientBuilder.build();\n        this.promptTemplate = promptTemplate != null ? promptTemplate : DEFAULT_PROMPT_TEMPLATE;\n        this.targetSearchSystem = targetSearchSystem != null ? targetSearchSystem : DEFAULT_TARGET;\n        PromptAssert.templateHasRequiredPlaceholders(this.promptTemplate, \"target\", \"query\");\n    }\n\n    @Override\n    public Query transform(Query query) {\n        Assert.notNull(query, \"query cannot be null\");\n        logger.debug(\"Rewriting query to optimize for querying a {}.\", this.targetSearchSystem);\n        var rewrittenQueryText = this.chatClient.prompt().user(user -> user.text(this.promptTemplate.getTemplate()).param(\"target\", this.targetSearchSystem).param(\"query\", query.text())).call().content();\n        if (!StringUtils.hasText(rewrittenQueryText)) {\n            logger.warn(\"Query rewrite result is null/empty. Returning the input query unchanged.\");\n            return query;\n        }\n        return query.mutate().text(rewrittenQueryText).build();\n    }\n\n    public static Builder builder() {\n        return new Builder();\n    }\n\n    public static final class Builder {\n\n        private ChatClient.Builder chatClientBuilder;\n\n        @Nullable\n        private PromptTemplate promptTemplate;\n\n        @Nullable\n        private String targetSearchSystem;\n\n        private Builder() {\n        }\n\n        public Builder chatClientBuilder(ChatClient.Builder chatClientBuilder) {\n            this.chatClientBuilder = chatClientBuilder;\n            return this;\n        }\n\n        public Builder promptTemplate(PromptTemplate promptTemplate) {\n            this.promptTemplate = promptTemplate;\n            return this;\n        }\n\n        public Builder targetSearchSystem(String targetSearchSystem) {\n            this.targetSearchSystem = targetSearchSystem;\n            return this;\n        }\n\n        public RewriteQueryTransformer build() {\n            return new RewriteQueryTransformer(this.chatClientBuilder, this.promptTemplate, this.targetSearchSystem);\n        }\n    }\n}',0x01,'cu::RewriteQueryTransformer.java'),
('6f8dc6aa-b826-4031-8bff-5ffcbb3490ed','The research publication makes an important architectural distinction between two types of agentic systems:\n\n<strong>Workflows</strong>: Systems where LLMs and tools are orchestrated through predefined code paths (e.g., prescriptive systems)\n<strong>Agents</strong>: Systems where LLMs dynamically direct their own processes and tool usage\n\n\nThe key insight is that while fully autonomous agents might seem appealing, workflows often provide better predictability and consistency for well-defined tasks. This aligns perfectly with enterprise requirements where reliability and maintainability are crucial.\n\nLet&#8217;s examine how Spring AI implements these concepts through five fundamental patterns, each serving specific use cases:',0x00,'asciidoc::effective-agents.adoc::Agentic Systems::0'),
('19c56380-d7e8-43c4-a451-6033b6defec4','Notice that the provisioning of <code>SAP Hana Database</code> instance has started. It takes some time to provision - please be patient.\n\nOnce the instance is provisioned (status is displayed as <code>Running</code>) we can get the datasource url (<code>SQL Endpoint</code>) by clicking the instance and selecting <code>Connections</code>\n\nWe navigate to <code>SAP Hana Database Explorer</code> by click the <code>&#8230;&#8203;</code>\n\nProvide the administrator credentials and click <code>OK</code>\n\nOpen SQL console and create the table <code>CRICKET_WORLD_CUP</code> using the following DDL statement:\n\nCREATE TABLE CRICKET_WORLD_CUP (\n    _ID VARCHAR2(255) PRIMARY KEY,\n    CONTENT CLOB,\n    EMBEDDING REAL_VECTOR(1536)\n)\n\nNavigate to <code>hana_dev_db &#8594; Catalog &#8594; Tables</code> to find our table <code>CRICKET_WORLD_CUP</code>\n\nRight-click on the table and click <code>Open Data</code>\n\nNotice that the table data is now displayed. There are now rows as we didn&#8217;t create any embeddings yet.\n\nNext steps: <a href=\"api/vectordbs/hana.html\">SAP Hana Vector Engine</a>',0x00,'asciidoc::hanadb-provision-a-trial-account.adoc::Provision SAP HANA Cloud trial account::1'),
('0083c02d-0437-46a3-bb19-60476b7dc556','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-google-genai</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the Google GenAI chat model:',0x00,'asciidoc::google-genai-chat.adoc::Sample Controller::0'),
('33a40fa3-bb00-42ba-9732-607c1a51cb68','The <code>TokenTextSplitter</code> uses the CL100K_BASE encoding from the <code>jtokkit</code> library, which is compatible with newer OpenAI models.\nThe splitter attempts to create semantically meaningful chunks by breaking at sentence boundaries where possible.\nMetadata from the original documents is preserved and copied to all chunks derived from that document.\nThe content formatter (if set) from the original document is also copied to the derived chunks if <code>copyContentFormatter</code> is set to <code>true</code> (default behavior).\nThis splitter is particularly useful for preparing text for large language models that have token limits, ensuring that each chunk is within the model&#8217;s processing capacity.',0x00,'asciidoc::etl-pipeline.adoc::Transformers::TokenTextSplitter::1'),
('0227316e-1034-4fd2-aa7e-60bd12245335','Include citation documents in your chat options:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"When was the Eiffel Tower built and how tall is it?\",\n        AnthropicChatOptions.builder()\n            .model(\"claude-3-7-sonnet-latest\")\n            .maxTokens(1024)\n            .citationDocuments(document)\n            .build()\n    )\n);\n\nMultiple Documents\n\nYou can provide multiple documents for Claude to reference:\n\nCitationDocument parisDoc = CitationDocument.builder()\n    .plainText(\"Paris is the capital city of France with a population of 2.1 million.\")\n    .title(\"Paris Information\")\n    .citationsEnabled(true)\n    .build();\n\nCitationDocument eiffelDoc = CitationDocument.builder()\n    .plainText(\"The Eiffel Tower was designed by Gustave Eiffel for the 1889 World\'s Fair.\")\n    .title(\"Eiffel Tower History\")\n    .citationsEnabled(true)\n    .build();\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What is the capital of France and who designed the Eiffel Tower?\",\n        AnthropicChatOptions.builder()\n            .model(\"claude-3-7-sonnet-latest\")\n            .citationDocuments(parisDoc, eiffelDoc)\n            .build()\n    )\n);',0x00,'asciidoc::anthropic-chat.adoc::Citations::Using Citations in Requests::0'),
('8533bfaa-1b00-4672-85a8-60ffd7cbbec9','For prompt engineering, you will start by choosing a model.\nSpring AI supports <a href=\":api/chat/comparison.html\">multiple LLM providers</a> (such as OpenAI, Anthropic, Google Vertex AI, AWS Bedrock, Ollama and more), letting you switch providers without changing application code - just update your configuration.\nJust add the selected starter dependency <code>spring-ai-starter-model-&lt;MODEL-PROVIDER-NAME&gt;</code>.\nFor example, here is how to enable Anthropic Claude API:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-anthropic&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nYou can specify the LLM model name like this:\n\n.options(ChatOptions.builder()\n        .model(\"claude-3-7-sonnet-latest\")  // Use Anthropic\'s Claude model\n        .build())\n\nFind detailed information for enabling each model in the <a href=\":api/chatmodel.html\">reference docs</a>.',0x00,'asciidoc::prompt-engineering-patterns.adoc::1. Configuration::LLM Provider Selection::0'),
('ae115dee-0c25-46f6-a763-619d5652c08a','To connect to Neo4j and use the <code>Neo4jVectorStore</code>, you need to provide access details for your instance.\nA simple configuration can be provided via Spring Boot&#8217;s <code>application.yml</code>:\n\nspring:\n  neo4j:\n    uri: &lt;neo4j instance URI&gt;\n    authentication:\n      username: &lt;neo4j username&gt;\n      password: &lt;neo4j password&gt;\n  ai:\n    vectorstore:\n      neo4j:\n        initialize-schema: true\n        database-name: neo4j\n        index-name: custom-index\n        embedding-dimension: 1536\n        distance-type: cosine\n\nThe Spring Boot properties starting with <code>spring.neo4j.*</code> are used to configure the Neo4j client:\n\n\n\nProperties starting with <code>spring.ai.vectorstore.neo4j.*</code> are used to configure the <code>Neo4jVectorStore</code>:\n\n\n\nThe following distance functions are available:\n\n<code>cosine</code> - Default, suitable for most use cases. Measures cosine similarity between vectors.\n<code>euclidean</code> - Euclidean distance between vectors. Lower values indicate higher similarity.',0x00,'asciidoc::neo4j.adoc::Auto-configuration::Configuration Properties::0'),
('b399eedd-d1df-44ff-bb19-6201dda5e114','You can register custom Java functions with the <code>OpenAiChatModel</code> and have the OpenAI model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.\nRead more about <a href=\"api/tools.html\">Tool Calling</a>.',0x00,'asciidoc::openai-chat.adoc::Function Calling::0'),
('6c126128-2f61-4ed5-93ed-628de3dfcb19','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::vertexai-embeddings-multimodal.adoc::Prerequisites::Add Repositories and BOM::0'),
('02c06c81-49cd-4db9-ba17-62c52cfedc39','Before:\n\nFunctionCallback.builder()\n    .method(\"getWeatherInLocation\", String.class, Unit.class)\n    .description(\"Get the weather in location\")\n    .targetClass(TestFunctionClass.class)\n    .build()\n\nAfter:\n\nvar toolMethod = ReflectionUtils.findMethod(TestFunctionClass.class, \"getWeatherInLocation\");\n\nMethodToolCallback.builder()\n    .toolDefinition(ToolDefinition.builder(toolMethod)\n        .description(\"Get the weather in location\")\n        .build())\n    .toolMethod(toolMethod)\n    .build()\n\nOr with the declarative approach:\n\nclass WeatherTools {\n\n    @Tool(description = \"Get the weather in location\")\n    public void getWeatherInLocation(String location, Unit unit) {\n        // ...\n    }\n\n}\n\nAnd you can use the same <code>ChatClient#tools()</code> API to register method-based tool callbacks:\n\nString response = ChatClient.create(chatModel)\n    .prompt()\n    .user(\"What\'s the weather like in San Francisco?\")\n    .tools(MethodToolCallback.builder()\n        .toolDefinition(ToolDefinition.builder(toolMethod)\n            .description(\"Get the weather in location\")\n            .build())\n        .toolMethod(toolMethod)\n        .build())\n    .call()\n    .content();\n\nOr with the declarative approach:\n\nString response = ChatClient.create(chatModel)\n    .prompt()\n    .user(\"What\'s the weather like in San Francisco?\")\n    .tools(new WeatherTools())\n    .call()\n    .content();',0x00,'asciidoc::tools-migration.adoc::Migration Examples::3. Method-Based Function Callbacks::0'),
('cfb7dc3c-1c51-425e-b8b1-62e55cf9969f','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-vertex-ai-gemini</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the VertexAi chat model:\n\nspring.ai.vertex.ai.gemini.project-id=PROJECT_ID\nspring.ai.vertex.ai.gemini.location=LOCATION\nspring.ai.vertex.ai.gemini.chat.options.model=gemini-2.0-flash\nspring.ai.vertex.ai.gemini.chat.options.temperature=0.5\n\nReplace the <code>project-id</code> with your Google Cloud Project ID and <code>location</code> is Google Cloud Region\nlike <code>us-central1</code>, <code>europe-west1</code>, etc&#8230;&#8203;\n\n<div class=\"paragraph\">\n<p>Each model has its own set of supported regions, you can find the list of supported regions in the model page.</p>\n</div>\n<div class=\"paragraph\">\n<p>For example, model=<code>gemini-2.5-flash</code> is currently available in <code>us-central1</code> region only, you must set location=<code>us-central1</code>,\nfollowing the model page <a href=\"https://cloud.google.com/vertex-ai/generative-ai/docs/models/gemini/2-5-flash\">Gemini 2.5 Flash - Supported Regions</a>.</p>\n</div>\n\nThis will create a <code>VertexAiGeminiChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final VertexAiGeminiChatModel chatModel;\n\n    @Autowired\n    public ChatController(VertexAiGeminiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::vertexai-gemini-chat.adoc::Sample Controller::0'),
('c2120462-3edb-45c4-bd01-62faee7ae731','The result of a tool call is serialized using a <code>ToolCallResultConverter</code> and then sent back to the AI model. The <code>ToolCallResultConverter</code> interface provides a way to convert the result of a tool call to a <code>String</code> object.\n\nThe interface provides the following method:\n\n@FunctionalInterface\npublic interface ToolCallResultConverter {\n\n	/**\n	 * Given an Object returned by a tool, convert it to a String compatible with the\n	 * given class type.\n	 */\n	String convert(@Nullable Object result, @Nullable Type returnType);\n\n}\n\nThe result must be a serializable type. By default, the result is serialized to JSON using Jackson (<code>DefaultToolCallResultConverter</code>), but you can customize the serialization process by providing your own <code>ToolCallResultConverter</code> implementation.\n\nSpring AI relies on the <code>ToolCallResultConverter</code> in both method and function tools.\n\nMethod Tool Call Result Conversion\n\nWhen building tools from a method with the declarative approach, you can provide a custom <code>ToolCallResultConverter</code> to use for the tool by setting the <code>resultConverter()</code> attribute of the <code>@Tool</code> annotation.\n\nclass CustomerTools {\n\n    @Tool(description = \"Retrieve customer information\", resultConverter = CustomToolCallResultConverter.class)\n    Customer getCustomerInfo(Long id) {\n        return customerRepository.findById(id);\n    }\n\n}\n\nIf using the programmatic approach, you can provide a custom <code>ToolCallResultConverter</code> to use for the tool by setting the <code>resultConverter()</code> attribute of the <code>MethodToolCallback.Builder</code>.\n\nSee <a href=\"#_methods_as_tools\">Methods as Tools</a> for more details.\n\nFunction Tool Call Result Conversion\n\nWhen building tools from a function using the programmatic approach, you can provide a custom <code>ToolCallResultConverter</code> to use for the tool by setting the <code>resultConverter()</code> attribute of the <code>FunctionToolCallback.Builder</code>.\n\nSee <a href=\"#_functions_as_tools\">Functions as Tools</a> for more details.',0x00,'asciidoc::tools.adoc::Tool Specification::Result Conversion::0'),
('cce7b846-900c-4412-a019-633faf079b92','You will need to create an API with MiniMax to access MiniMax language models.\n\nCreate an account at <a href=\"https://www.minimaxi.com/login\">MiniMax registration page</a> and generate the token on the <a href=\"https://www.minimaxi.com/user-center/basic-information/interface-key\">API Keys page</a>.\n\nThe Spring AI project defines a configuration property named <code>spring.ai.minimax.api-key</code> that you should set to the value of the <code>API Key</code> obtained from the API Keys page.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.minimax.api-key=&lt;your-minimax-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference an environment variable:\n\n# In application.yml\nspring:\n  ai:\n    minimax:\n      api-key: ${MINIMAX_API_KEY}\n\n# In your environment or .env file\nexport MINIMAX_API_KEY=&lt;your-minimax-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"MINIMAX_API_KEY\");',0x00,'asciidoc::minimax-chat.adoc::Prerequisites::0'),
('8f8fd0b3-d87f-402c-b11f-63809e7efba8','Spring AI auto-configures a <code>ChatMemory</code> bean that you can use directly in your application. By default, it uses an in-memory repository to store messages (<code>InMemoryChatMemoryRepository</code>) and a <code>MessageWindowChatMemory</code> implementation to manage the conversation history. If a different repository is already configured (e.g., Cassandra, JDBC, or Neo4j), Spring AI will use that instead.\n\n@Autowired\nChatMemory chatMemory;\n\nThe following sections will describe further the different memory types and repositories available in Spring AI.',0x00,'asciidoc::chat-memory.adoc::Quick Start::0'),
('314937ec-7fb9-461f-935e-6386ce8b71b3','For model version 004 and later, you can reduce the embedding dimensions for storage optimization:\n\nGoogleGenAiTextEmbeddingOptions options = GoogleGenAiTextEmbeddingOptions.builder()\n    .model(\"text-embedding-004\")\n    .dimensions(256)  // Reduce from default 768 to 256 dimensions\n    .build();',0x00,'asciidoc::google-genai-embeddings-text.adoc::Dimension Reduction::0'),
('c982d1c1-b581-4dec-956f-63aabd5fe9f5','<div class=\"paragraph\">\n<p>Spring AI supports the PostgresML text embeddings models.</p>\n</div>\n<div class=\"paragraph\">\n<p>Embeddings are a numeric representation of text.\nThey are used to represent words and sentences as vectors, an array of numbers.\nEmbeddings can be used to find similar pieces of text, by comparing the similarity of the numeric vectors using a distance measure, or they can be used as input features for other machine learning models, since most algorithms can&#8217;t use text directly.</p>\n</div>\n<div class=\"paragraph\">\n<p>Many pre-trained LLMs can be used to generate embeddings from text within PostgresML.\nYou can browse all the <a href=\"https://huggingface.co/models?library=sentence-transformers\">models</a> available to find the best solution on Hugging Face.</p>\n</div>',0x00,'asciidoc::postgresml-embeddings.adoc::0'),
('af1dd6db-e4f0-40fc-bf88-63bf85f5fc2c','Instead of using the Spring Boot auto-configuration, you can manually configure the <code>MilvusVectorStore</code>.\nTo add the following dependencies to your project:\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-milvus-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nTo configure MilvusVectorStore in your application, you can use the following setup:\n\n	@Bean\n	public VectorStore vectorStore(MilvusServiceClient milvusClient, EmbeddingModel embeddingModel) {\n		return MilvusVectorStore.builder(milvusClient, embeddingModel)\n				.collectionName(\"test_vector_store\")\n				.databaseName(\"default\")\n				.indexType(IndexType.IVF_FLAT)\n				.metricType(MetricType.COSINE)\n				.batchingStrategy(new TokenCountBatchingStrategy())\n				.initializeSchema(true)\n				.build();\n	}\n\n	@Bean\n	public MilvusServiceClient milvusClient() {\n		return new MilvusServiceClient(ConnectParam.newBuilder()\n			.withAuthorization(\"minioadmin\", \"minioadmin\")\n			.withUri(milvusContainer.getEndpoint())\n			.build());\n	}',0x00,'asciidoc::milvus.adoc::Dependencies::Manual Configuration::0'),
('cf5ed293-7a84-48e4-8c1d-63f451620a28','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-openai</code> to your pom (or gradle) dependencies.\n\nAdd an <code>application.properties</code> file under the <code>src/main/resources</code> directory to enable and configure the OpenAi chat model:\n\nspring.ai.openai.api-key=YOUR_API_KEY\nspring.ai.openai.chat.options.model=gpt-4o\nspring.ai.openai.chat.options.temperature=0.7\n\nReplace the <code>api-key</code> with your OpenAI credentials.\n\nThis will create an <code>OpenAiChatModel</code> implementation that you can inject into your classes.\nHere is an example of a simple <code>@RestController</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final OpenAiChatModel chatModel;\n\n    @Autowired\n    public ChatController(OpenAiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map&lt;String,String&gt; generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::openai-chat.adoc::Sample Controller::0'),
('53e550e0-dbb5-4374-9ac5-64564f8324a7','GoogleGenAiEmbeddingConnectionDetails connectionDetails =\n    GoogleGenAiEmbeddingConnectionDetails.builder()\n        .projectId(System.getenv(\"GOOGLE_CLOUD_PROJECT\"))\n        .location(System.getenv(\"GOOGLE_CLOUD_LOCATION\"))\n        .build();\n\nGoogleGenAiTextEmbeddingOptions options = GoogleGenAiTextEmbeddingOptions.builder()\n    .model(GoogleGenAiTextEmbeddingOptions.DEFAULT_MODEL_NAME)\n    .taskType(TaskType.RETRIEVAL_DOCUMENT)\n    .build();\n\nvar embeddingModel = new GoogleGenAiTextEmbeddingModel(connectionDetails, options);\n\nEmbeddingResponse embeddingResponse = embeddingModel\n	.embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));',0x00,'asciidoc::google-genai-embeddings-text.adoc::Manual Configuration::Using Vertex AI::0'),
('5d933ae7-ea63-4a33-bcc3-649317737bca','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-zhipuai/src/main/java/org/springframework/ai/zhipuai/api/ZhiPuAiApi.java\">ZhiPuAiApi</a> provides is lightweight Java client for <a href=\"https://open.bigmodel.cn/dev/api\">ZhiPu AI API</a>.\n\nHere is a simple snippet how to use the api programmatically:\n\nZhiPuAiApi zhiPuAiApi =\n    new ZhiPuAiApi(System.getenv(\"ZHIPU_AI_API_KEY\"));\n\nChatCompletionMessage chatCompletionMessage =\n    new ChatCompletionMessage(\"Hello world\", Role.USER);\n\n// Sync request\nResponseEntity&lt;ChatCompletion&gt; response = this.zhiPuAiApi.chatCompletionEntity(\n    new ChatCompletionRequest(List.of(this.chatCompletionMessage), ZhiPuAiApi.ChatModel.GLM_4_Air.getValue(), 0.7, false));\n\n// Streaming request\nFlux&lt;ChatCompletionChunk&gt; streamResponse = this.zhiPuAiApi.chatCompletionStream(\n        new ChatCompletionRequest(List.of(this.chatCompletionMessage), ZhiPuAiApi.ChatModel.GLM_4_Air.getValue(), 0.7, true));\n\nFollow the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-zhipuai/src/main/java/org/springframework/ai/zhipuai/api/ZhiPuAiApi.java\">ZhiPuAiApi.java</a>\'s JavaDoc for further information.\n\nZhiPuAiApi Samples\n\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-zhipuai/src/test/java/org/springframework/ai/zhipuai/api/ZhiPuAiApiIT.java\">ZhiPuAiApiIT.java</a> test provides some general examples how to use the lightweight library.',0x00,'asciidoc::zhipuai-chat.adoc::Manual Configuration::Low-level ZhiPuAiApi Client::0'),
('5961b303-3499-473b-ac85-64dc8de342fb','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-deepseek/src/main/java/org/springframework/ai/deepseek/DeepSeekChatOptions.java\">DeepSeekChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the frequency penalty, etc.\n\nOn startup, the default options can be configured with the <code>DeepSeekChatModel(api, options)</code> constructor or the <code>spring.ai.deepseek.chat.options.*</code> properties.\n\nAt runtime, you can override the default options by adding new, request-specific options to the <code>Prompt</code> call.\nFor example, to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates. Please provide the JSON response without any code block markers such as ```json```.\",\n        DeepSeekChatOptions.builder()\n            .withModel(DeepSeekApi.ChatModel.DEEPSEEK_CHAT.getValue())\n            .withTemperature(0.8f)\n        .build()\n    ));\n\nIn addition to the model-specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-deepseek/src/main/java/org/springframework/ai/deepseek/DeepSeekChatOptions.java\">DeepSeekChatOptions</a>, you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::deepseek-chat.adoc::Runtime Options::0'),
('0dff896b-9858-4f74-9750-651abbeba276','Before:\n\nFunctionCallingOptions.builder()\n    .model(modelName)\n    .function(\"weatherFunction\")\n    .build()\n\nAfter:\n\nToolCallingChatOptions.builder()\n    .model(modelName)\n    .toolNames(\"weatherFunction\")\n    .build()',0x00,'asciidoc::tools-migration.adoc::Migration Examples::4. Options Configuration::0'),
('7cea3dbf-5876-4fd5-8529-65227577019a','The <code>ToolCallback</code> interface provides a way to define a tool that can be called by the AI model, including both definition and execution logic. It&#8217;s the main interface to implement when you want to define a tool from scratch. For example, you can define a <code>ToolCallback</code> from an MCP Client (using the Model Context Protocol) or a <code>ChatClient</code> (to build a modular agentic application).\n\nThe interface provides the following methods:\n\npublic interface ToolCallback {\n\n	/**\n	 * Definition used by the AI model to determine when and how to call the tool.\n	 */\n	ToolDefinition getToolDefinition();\n\n	/**\n	 * Metadata providing additional information on how to handle the tool.\n	 */\n	ToolMetadata getToolMetadata();\n\n    /**\n	 * Execute tool with the given input and return the result to send back to the AI model.\n	 */\n	String call(String toolInput);\n\n    /**\n	 * Execute tool with the given input and context, and return the result to send back to the AI model.\n	 */\n	String call(String toolInput, ToolContext tooContext);\n\n}\n\nSpring AI provides built-in implementations for tool methods (<code>MethodToolCallback</code>) and tool functions (<code>FunctionToolCallback</code>).',0x00,'asciidoc::tools.adoc::Tool Specification::Tool Callback::0'),
('88558516-b859-42ad-bf45-65601e6d4b59','<strong>SDK</strong>: Google GenAI uses the new <code>com.google.genai.Client</code> instead of <code>com.google.cloud.vertexai.VertexAI</code>\n<strong>Authentication</strong>: Supports both API key and Google Cloud credentials\n<strong>Package Names</strong>: Classes are in <code>org.springframework.ai.google.genai</code> instead of <code>org.springframework.ai.vertexai.gemini</code>\n<strong>Property Prefix</strong>: Uses <code>spring.ai.google.genai</code> instead of <code>spring.ai.vertex.ai.gemini</code>',0x00,'asciidoc::google-genai-chat.adoc::Migration from Vertex AI Gemini::Key Differences::0'),
('c3c70090-b04f-4da7-a42a-6586177e193a','It is mandatory to have the following Couchbase services activated: Data, Query, Index, Search. While Data and Search could be enough, Query and Index are necessary to support the complete metadata filtering mechanism.',0x00,'asciidoc::couchbase.adoc::Limitations::0'),
('594f2fc7-b646-49c0-b5ba-65c7d5e5ba26','<div class=\"paragraph\">\n<p>The <a href=\"https://docs.oracle.com/en/database/oracle/oracle-database/23/vecse/overview-ai-vector-search.html\">AI Vector Search</a> capabilities of the Oracle Database 23ai (23.4+) are available as a Spring AI <code>VectorStore</code> to help you to store document embeddings and perform similarity searches. Of course, all other features are also available.</p>\n</div>\n<div class=\"admonitionblock tip\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Tip</div>\n</td>\n<td class=\"content\">\nThe <a href=\"#_run_oracle_database_23ai_locally\">Run Oracle Database 23ai locally</a> appendix shows how to start a database with a lightweight Docker container.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::oracle.adoc::0'),
('4e2c0e57-b593-43bd-95d3-6614feced7b9','AI models are algorithms designed to process and generate information, often mimicking human cognitive functions.\nBy learning patterns and insights from large datasets, these models can make predictions, text, images, or other outputs, enhancing various applications across industries.\n\nThere are many different types of AI models, each suited for a specific use case.\nWhile ChatGPT and its generative AI capabilities have captivated users through text input and output, many models and companies offer diverse inputs and outputs.\nBefore ChatGPT, many people were fascinated by text-to-image generation models such as Midjourney and Stable Diffusion.\n\nThe following table categorizes several models based on their input and output types:\n\nSpring AI currently supports models that process input and output as language, image, and audio.\nThe last row in the previous table, which accepts text as input and outputs numbers, is more commonly known as embedding text and represents the internal data structures used in an AI model.\nSpring AI has support for embeddings to enable more advanced use cases.\n\nWhat sets models like GPT apart is their pre-trained nature, as indicated by the \"P\" in GPT—Chat Generative Pre-trained Transformer.\nThis pre-training feature transforms AI into a general developer tool that does not require an extensive machine learning or model training background.',0x00,'asciidoc::concepts.adoc::Models::0'),
('c553cf85-2aed-449a-9d9e-6616d6afae32','Here&#8217;s a simple example of how to use Docker Model Runner function calling with Spring AI:\n\nspring.ai.openai.api-key=test\nspring.ai.openai.base-url=http://localhost:12434/engines\nspring.ai.openai.chat.options.model=ai/gemma3:4B-F16\n\n@SpringBootApplication\npublic class DockerModelRunnerLlmApplication {\n\n    public static void main(String[] args) {\n        SpringApplication.run(DockerModelRunnerLlmApplication.class, args);\n    }\n\n    @Bean\n    CommandLineRunner runner(ChatClient.Builder chatClientBuilder) {\n        return args -&gt; {\n            var chatClient = chatClientBuilder.build();\n\n            var response = chatClient.prompt()\n                .user(\"What is the weather in Amsterdam and Paris?\")\n                .functions(\"weatherFunction\") // reference by bean name.\n                .call()\n                .content();\n\n            System.out.println(response);\n        };\n    }\n\n    @Bean\n    @Description(\"Get the weather in location\")\n    public Function&lt;WeatherRequest, WeatherResponse&gt; weatherFunction() {\n        return new MockWeatherService();\n    }\n\n    public static class MockWeatherService implements Function&lt;WeatherRequest, WeatherResponse&gt; {\n\n        public record WeatherRequest(String location, String unit) {}\n        public record WeatherResponse(double temp, String unit) {}\n\n        @Override\n        public WeatherResponse apply(WeatherRequest request) {\n            double temperature = request.location().contains(\"Amsterdam\") ? 20 : 25;\n            return new WeatherResponse(temperature, request.unit);\n        }\n    }\n}\n\nIn this example, when the model needs weather information, it will automatically call the <code>weatherFunction</code> bean, which can then fetch real-time weather data.\nThe expected response is: \"The weather in Amsterdam is currently 20 degrees Celsius, and the weather in Paris is currently 25 degrees Celsius.\"\n\nRead more about OpenAI <a href=\"https://docs.spring.io/spring-ai/reference/api/chat/functions/openai-chat-functions.html\">Function Calling</a>.',0x00,'asciidoc::dmr-chat.adoc::Function Calling::Tool Example::0'),
('d8db55cc-afb4-444f-a898-662aed051a95','<strong>Create an API Key</strong>:\nVisit <a href=\"https://console.groq.com/keys\">here</a> to create an API Key.\nThe Spring AI project defines a configuration property named <code>spring.ai.openai.api-key</code> that you should set to the value of the <code>API Key</code> obtained from groq.com.\n<strong>Set the Groq URL</strong>:\nYou have to set the <code>spring.ai.openai.base-url</code> property to <code>https://api.groq.com/openai</code>.\n<strong>Select a Groq Model</strong>:\nUse the <code>spring.ai.openai.chat.model=&lt;model name&gt;</code> property to select from the available <a href=\"https://console.groq.com/docs/models\">Groq Models</a>.\n\n\nYou can set these configuration properties in your <code>application.properties</code> file:\n\nspring.ai.openai.api-key=&lt;your-groq-api-key&gt;\nspring.ai.openai.base-url=https://api.groq.com/openai\nspring.ai.openai.chat.model=llama3-70b-8192\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference custom environment variables:\n\n# In application.yml\nspring:\n  ai:\n    openai:\n      api-key: ${GROQ_API_KEY}\n      base-url: ${GROQ_BASE_URL}\n      chat:\n        model: ${GROQ_MODEL}\n\n# In your environment or .env file\nexport GROQ_API_KEY=&lt;your-groq-api-key&gt;\nexport GROQ_BASE_URL=https://api.groq.com/openai\nexport GROQ_MODEL=llama3-70b-8192\n\nYou can also set these configurations programmatically in your application code:\n\n// Retrieve configuration from secure sources or environment variables\nString apiKey = System.getenv(\"GROQ_API_KEY\");\nString baseUrl = System.getenv(\"GROQ_BASE_URL\");\nString model = System.getenv(\"GROQ_MODEL\");',0x00,'asciidoc::groq-chat.adoc::Prerequisites::0'),
('b177ad9c-a75d-4061-932b-669e1cef3813','OpenAI models that offer input audio multimodal support include <code>gpt-4o-audio-preview</code>.\nRefer to the <a href=\"https://platform.openai.com/docs/guides/audio\">Audio</a> guide for more information.\n\nThe OpenAI <a href=\"https://platform.openai.com/docs/api-reference/chat/create#chat-create-messages\">User Message API</a> can incorporate a list of base64-encoded audio files with the message.\nSpring AI’s <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/messages/Message.java\">Message</a> interface facilitates multimodal AI models by introducing the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-commons/src/main/java/org/springframework/ai/content/Media.java\">Media</a> type.\nThis type encompasses data and details regarding media attachments in messages, utilizing Spring’s <code>org.springframework.util.MimeType</code> and a <code>org.springframework.core.io.Resource</code> for the raw media data.\nCurrently, OpenAI support only the following media types: <code>audio/mp3</code> and <code>audio/wav</code>.\n\nBelow is a code example excerpted from <a href=\"https://github.com/spring-projects/spring-ai/blob/c9a3e66f90187ce7eae7eb78c462ec622685de6c/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/chat/OpenAiChatModelIT.java#L442\">OpenAiChatModelIT.java</a>, illustrating the fusion of user text with an audio file using the <code>gpt-4o-audio-preview</code> model.\n\nvar audioResource = new ClassPathResource(\"speech1.mp3\");\n\nvar userMessage = new UserMessage(\"What is this recording about?\",\n        List.of(new Media(MimeTypeUtils.parseMimeType(\"audio/mp3\"), audioResource)));\n\nChatResponse response = chatModel.call(new Prompt(List.of(userMessage),\n        OpenAiChatOptions.builder().model(OpenAiApi.ChatModel.GPT_4_O_AUDIO_PREVIEW).build()));\n\nYou can pass multiple audio files as well.',0x00,'asciidoc::openai-chat.adoc::Multimodal::Audio::0'),
('deb483d9-a7d9-4ec7-b191-671e06ead8a0','Keep advisors focused on specific tasks for better modularity.\nUse the <code>adviseContext</code> to share state between advisors when necessary.\nImplement both streaming and non-streaming versions of your advisor for maximum flexibility.\nCarefully consider the order of advisors in your chain to ensure proper data flow.',0x00,'asciidoc::advisors.adoc::Implementing an Advisor::Best Practices::0'),
('d2cf052a-7784-432c-a24b-6751301e7fd7','To connect to Couchbase and use the <code>CouchbaseSearchVectorStore</code>, you need to provide access details for your instance.\nConfiguration can be provided via Spring Boot&#8217;s <code>application.properties</code>:\n\nspring.ai.openai.api-key=&lt;key&gt;\nspring.couchbase.connection-string=&lt;conn_string&gt;\nspring.couchbase.username=&lt;username&gt;\nspring.couchbase.password=&lt;password&gt;\n\nIf you prefer to use environment variables for sensitive information like passwords or API keys, you have multiple options:\n\nOption 1: Using Spring Expression Language (SpEL)\n\nYou can use custom environment variable names and reference them in your application configuration using SpEL:\n\n# In application.yml\nspring:\n  ai:\n    openai:\n      api-key: ${OPENAI_API_KEY}\n  couchbase:\n    connection-string: ${COUCHBASE_CONN_STRING}\n    username: ${COUCHBASE_USER}\n    password: ${COUCHBASE_PASSWORD}\n\n# In your environment or .env file\nexport OPENAI_API_KEY=&lt;api-key&gt;\nexport COUCHBASE_CONN_STRING=&lt;couchbase connection string like couchbase://localhost&gt;\nexport COUCHBASE_USER=&lt;couchbase username&gt;\nexport COUCHBASE_PASSWORD=&lt;couchbase password&gt;\n\nOption 2: Accessing Environment Variables Programmatically\n\nAlternatively, you can access environment variables in your Java code:\n\nString apiKey = System.getenv(\"OPENAI_API_KEY\");\n\nThis approach gives you flexibility in naming your environment variables while keeping sensitive information out of your application configuration files.\n\nIf you choose to create a shell script for ease in future work, be sure to run it prior to starting your application by \"sourcing\" the file, i.e. <code>source &lt;your_script_name&gt;.sh</code>.\n\nSpring Boot&#8217;s auto-configuration feature for the Couchbase Cluster will create a bean instance that will be used by the <code>CouchbaseSearchVectorStore</code>.\n\nThe Spring Boot properties starting with <code>spring.couchbase.*</code> are used to configure the Couchbase cluster instance:\n\n\n\nProperties starting with the <code>spring.ai.vectorstore.couchbase.*</code> prefix are used to configure <code>CouchbaseSearchVectorStore</code>.\n\n\n\nThe following similarity functions are available:\n\nl2_norm\ndot_product\n\n\nThe following index optimizations are available:\n\nrecall\nlatency\n\n\nMore details about each in the <a href=\"https://docs.couchbase.com/server/current/search/child-field-options-reference.html\">Couchbase Documentation</a> on vector searches.',0x00,'asciidoc::couchbase.adoc::Auto-configuration::Configuration Properties::0'),
('aaa56e75-4dc5-43f1-bc02-67a2b19686d9','AWS Bedrock provides cache-specific metrics through the response metadata.\nCache metrics are accessible via the metadata Map:\n\nChatResponse response = chatModel.call(/* ... */);\n\n// Access cache metrics from metadata Map\nInteger cacheWrite = (Integer) response.getMetadata()\n    .getMetadata()\n    .get(\"cacheWriteInputTokens\");\nInteger cacheRead = (Integer) response.getMetadata()\n    .getMetadata()\n    .get(\"cacheReadInputTokens\");\n\nCache-specific metrics include:\n\n<code>cacheWriteInputTokens</code>: Returns the number of tokens used when creating a cache entry\n<code>cacheReadInputTokens</code>: Returns the number of tokens read from an existing cache entry\n\n\nWhen you first send a cached prompt:\n- <code>cacheWriteInputTokens</code> will be greater than 0\n- <code>cacheReadInputTokens</code> will be 0\n\nWhen you send the same cached prompt again (within 5-minute TTL):\n- <code>cacheWriteInputTokens</code> will be 0\n- <code>cacheReadInputTokens</code> will be greater than 0',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Token Usage Tracking::0'),
('9bcfea32-fce0-4e46-b2ab-67bcaf556fcb','Many modern AI models now provide native support for structured output, which offers more reliable results compared to prompt-based formatting. Spring AI supports this through the <a href=\"api/chatclient.html#_native_structured_output\">Native Structured Output</a> feature.\n\nWhen using native structured output, the JSON schema generated by <code>BeanOutputConverter</code> is sent directly to the model&#8217;s structured output API, eliminating the need for format instructions in the prompt. This approach provides:\n\n<strong>Higher reliability</strong>: The model guarantees output conforming to the schema\n<strong>Cleaner prompts</strong>: No need to append format instructions\n<strong>Better performance</strong>: Models can optimize for structured output internally',0x00,'asciidoc::structured-output-converter.adoc::Native Structured Output::0'),
('b4250db3-4c68-4a8a-abd5-67e81a5ec0d8','ETL framework for Data Engineering.  This provides the basis of loading data into a vector database, helping implement the Retrieval Augmented Generation pattern that enables you to bring your data to the AI model to incorporate into its response.',0x00,'asciidoc::index.adoc::Introduction::ETL Data Engineering::0'),
('b0d7d93c-e748-461e-9387-67f9f6c64d24','Spring AI artifacts are published in the Spring Milestone and Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout your entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::deepseek-chat.adoc::Prerequisites::Add Repositories and BOM::0'),
('dee795f0-a1b3-47a0-ba92-68ae13a6d9d9','On startup, the <code>AzureVectorStore</code> can  attempt to create a new index within your AI Search service instance if you&#8217;ve opted in by setting the relevant <code>initialize-schema</code> <code>boolean</code> property to <code>true</code> in the constructor or, if using Spring Boot, setting <code>&#8230;&#8203;initialize-schema=true</code>  in your <code>application.properties</code> file.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nAlternatively, you can create the index manually.\n\nTo set up an AzureVectorStore, you will need the settings retrieved from the prerequisites above along with your index name:\n\nAzure AI Search Endpoint\nAzure AI Search Key\n(optional) Azure OpenAI API Endpoint\n(optional) Azure OpenAI API Key\n\n\nYou can provide these values as OS environment variables.\n\nexport AZURE_AI_SEARCH_API_KEY=&lt;My AI Search API Key&gt;\nexport AZURE_AI_SEARCH_ENDPOINT=&lt;My AI Search Index&gt;\nexport OPENAI_API_KEY=&lt;My Azure AI API Key&gt; (Optional)\n\n<div class=\"paragraph\">\n<p>You can replace Azure Open AI implementation with any valid OpenAI implementation that supports the Embeddings interface. For example, you could use Spring AI&#8217;s Open AI or <code>TransformersEmbedding</code> implementations for embeddings instead of the Azure implementation.</p>\n</div>',0x00,'asciidoc::azure.adoc::Configuration::0'),
('d7df6c1f-ff89-47a3-9342-68e6bf059f31','<div class=\"paragraph\">\n<p>This section walks you through setting up the <code>GemFireVectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://tanzu.vmware.com/gemfire\">GemFire</a> is a distributed, in-memory, key-value store performing read and write operations at blazingly fast speeds. It offers highly available parallel message queues, continuous availability, and an event-driven architecture you can scale dynamically without downtime. As your data size requirements increase to support high-performance, real-time apps, GemFire can easily scale linearly.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://docs.vmware.com/en/VMware-GemFire-VectorDB/1.0/gemfire-vectordb/overview.html\">GemFire VectorDB</a> extends GemFire&#8217;s capabilities, serving as a versatile vector database that efficiently stores, retrieves, and performs vector similarity searches.</p>\n</div>',0x00,'asciidoc::gemfire.adoc::0'),
('c85daa45-347d-4367-98c7-69004fb3b49e','Here&#8217;s a simple example of how to use Groq function calling with Spring AI:\n\n@SpringBootApplication\npublic class GroqApplication {\n\n    public static void main(String[] args) {\n        SpringApplication.run(GroqApplication.class, args);\n    }\n\n    @Bean\n    CommandLineRunner runner(ChatClient.Builder chatClientBuilder) {\n        return args -&gt; {\n            var chatClient = chatClientBuilder.build();\n\n            var response = chatClient.prompt()\n                .user(\"What is the weather in Amsterdam and Paris?\")\n                .functions(\"weatherFunction\") // reference by bean name.\n                .call()\n                .content();\n\n            System.out.println(response);\n        };\n    }\n\n    @Bean\n    @Description(\"Get the weather in location\")\n    public Function&lt;WeatherRequest, WeatherResponse&gt; weatherFunction() {\n        return new MockWeatherService();\n    }\n\n    public static class MockWeatherService implements Function&lt;WeatherRequest, WeatherResponse&gt; {\n\n        public record WeatherRequest(String location, String unit) {}\n        public record WeatherResponse(double temp, String unit) {}\n\n        @Override\n        public WeatherResponse apply(WeatherRequest request) {\n            double temperature = request.location().contains(\"Amsterdam\") ? 20 : 25;\n            return new WeatherResponse(temperature, request.unit);\n        }\n    }\n}\n\nIn this example, when the model needs weather information, it will automatically call the <code>weatherFunction</code> bean, which can then fetch real-time weather data.\nThe expected response looks like this: \"The weather in Amsterdam is currently 20 degrees Celsius, and the weather in Paris is currently 25 degrees Celsius.\"\n\nRead more about OpenAI <a href=\"https://docs.spring.io/spring-ai/reference/api/chat/functions/openai-chat-functions.html\">Function Calling</a>.',0x00,'asciidoc::groq-chat.adoc::Function Calling::Tool Example::0'),
('cbdcdcd3-f19b-4968-b9fc-6a29fb8550af','The following snippet shows how to use <code>ListOutputConverter</code> to convert the model output into a list of ice cream flavors.\n\nList&lt;String&gt; flavors = ChatClient.create(chatModel).prompt()\n                .user(u -&gt; u.text(\"List five {subject}\")\n                            .param(\"subject\", \"ice cream flavors\"))\n                .call()\n                .entity(new ListOutputConverter(new DefaultConversionService()));\n\nor using the low-level <code>ChatModel API</code> directly:\n\nListOutputConverter listOutputConverter = new ListOutputConverter(new DefaultConversionService());\n\nString format = this.listOutputConverter.getFormat();\nString template = \"\"\"\n        List five {subject}\n        {format}\n        \"\"\";\n\nPrompt prompt = PromptTemplate.builder().template(this.template).variables(Map.of(\"subject\", \"ice cream flavors\", \"format\", this.format)).build().create();\n\nGeneration generation = this.chatModel.call(this.prompt).getResult();\n\nList&lt;String&gt; list = this.listOutputConverter.convert(this.generation.getOutput().getText());',0x00,'asciidoc::structured-output-converter.adoc::Using Converters::List Output Converter::0'),
('a6c8ccfe-0503-469f-b570-6a4ebe4d2af6','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::cohere-chat.adoc::Prerequisites::Add Repositories and BOM::0'),
('da4fcd88-6dd9-4153-8c8b-6a6ef44a32d4','The API consists of <code>CallAdvisor</code> and <code>CallAdvisorChain</code> for non-streaming scenarios, and <code>StreamAdvisor</code> and <code>StreamAdvisorChain</code> for streaming scenarios.\nIt also includes <code>ChatClientRequest</code> to represent the unsealed Prompt request, <code>ChatClientResponse</code> for the Chat Completion response. Both hold an <code>advise-context</code> to share state across the advisor chain.\n\nThe <code>adviseCall()</code> and the <code>adviseStream()</code> are the key advisor methods, typically performing actions such as examining the unsealed Prompt data, customizing and augmenting the Prompt data, invoking the next entity in the advisor chain, optionally blocking the request, examining the chat completion response, and throwing exceptions to indicate processing errors.\n\nIn addition the <code>getOrder()</code> method determines advisor order in the chain, while <code>getName()</code> provides a unique advisor name.\n\nThe Advisor Chain, created by the Spring AI framework, allows sequential invocation of multiple advisors ordered by their <code>getOrder()</code> values.\nThe lower values are executed first.\nThe last advisor, added automatically, sends the request to the LLM.\n\nFollowing flow diagram illustrates the interaction between the advisor chain and the Chat Model:\n\nThe Spring AI framework creates an <code>ChatClientRequest</code> from user&#8217;s <code>Prompt</code> along with an empty advisor <code>context</code> object.\nEach advisor in the chain processes the request, potentially modifying it. Alternatively, it can choose to block the request by not making the call to invoke the next entity. In the latter case, the advisor is responsible for filling out the response.\nThe final advisor, provided by the framework, sends the request to the <code>Chat Model</code>.\nThe Chat Model&#8217;s response is then passed back through the advisor chain and converted into <code>ChatClientResponse</code>. Later includes the shared advisor <code>context</code> instance.\nEach advisor can process or modify the response.\nThe final <code>ChatClientResponse</code> is returned to the client by extracting the <code>ChatCompletion</code>.',0x00,'asciidoc::advisors.adoc::Core Components::0'),
('c8d796d0-9057-4d9c-9e68-6a9758f5fff9','Before:\n\nFunctionCallback.builder()\n    .function(\"getCurrentWeather\", new MockWeatherService())\n    .description(\"Get the weather in location\")\n    .inputType(MockWeatherService.Request.class)\n    .build()\n\nAfter:\n\nFunctionToolCallback.builder(\"getCurrentWeather\", new MockWeatherService())\n    .description(\"Get the weather in location\")\n    .inputType(MockWeatherService.Request.class)\n    .build()',0x00,'asciidoc::tools-migration.adoc::Migration Examples::1. Basic Function Callback::0'),
('1432fc13-a87a-48da-967b-6adbedf1c431','<strong>Choose the Right Strategy</strong>:\n<strong>Meet Token Requirements</strong>: Focus on caching content that meets the minimum token requirements (1024+ tokens for most models).\n<strong>Reuse Identical Content</strong>: Caching works best with exact matches of prompt content.\nEven small changes will require a new cache entry.\n<strong>Monitor Token Usage</strong>: Track cache effectiveness using the metadata metrics:\n<strong>Strategic Cache Placement</strong>: The implementation automatically places cache breakpoints at optimal locations based on your chosen strategy, ensuring compliance with AWS Bedrock&#8217;s 4-breakpoint limit.\n<strong>Cache Lifetime</strong>: AWS Bedrock caches have a fixed 5-minute TTL (Time To Live).\nEach cache access resets the timer.\n<strong>Model Compatibility</strong>: Be aware of model-specific limitations:\n<strong>Tool Stability</strong>: When using <code>TOOLS_ONLY</code>, <code>SYSTEM_AND_TOOLS</code>, or <code>CONVERSATION_HISTORY</code> strategies, ensure tools remain stable.\nChanging tool definitions will invalidate all downstream cache breakpoints due to cascade invalidation.',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Best Practices::0'),
('e42c2f03-3acd-41c7-840f-6b41e24a05dd','<div class=\"paragraph\">\n<p>This section will walk you through setting up the <code>CouchbaseSearchVectorStore</code> to store document embeddings and perform similarity searches using Couchbase.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://docs.couchbase.com/server/current/vector-search/vector-search.html\">Couchbase</a> is a distributed, JSON document database, with all the desired capabilities of a relational DBMS. Among other features, it allows users to query information using vector-based storage and retrieval.</p>\n</div>',0x00,'asciidoc::couchbase.adoc::0'),
('11241587-258a-409a-b3a1-6b41fcb36fe3','OpenAI models that offer audio input support include <code>gpt-4o-audio-preview</code>.\nRefer to the <a href=\"https://platform.openai.com/docs/guides/audio\">Audio</a> guide for more information.\n\nSpring AI supports base64-encoded audio files with the message.\nCurrently, OpenAI supports the following media types: <code>audio/mp3</code> and <code>audio/wav</code>.\n\nExample of audio input:\n\nvar audioResource = new ClassPathResource(\"speech1.mp3\");\n\nvar userMessage = new UserMessage(\n    \"What is this recording about?\",\n    List.of(new Media(MimeTypeUtils.parseMimeType(\"audio/mp3\"), audioResource)));\n\nChatResponse response = chatModel.call(\n    new Prompt(userMessage,\n        OpenAiSdkChatOptions.builder()\n            .model(\"gpt-4o-audio-preview\")\n            .build()));',0x00,'asciidoc::openai-sdk-chat.adoc::Multimodal::Audio::0'),
('19efd055-5c63-4ce1-9a03-6b4aa538cf48','// Define comprehensive code review guidelines\nString reviewGuidelines = \"\"\"\n    You are a senior software engineer conducting code reviews. Apply these criteria:\n    - Security vulnerabilities and best practices\n    - Performance optimizations and memory usage\n    - Code maintainability and readability\n    - Testing coverage and edge cases\n    - Design patterns and architecture compliance\n    \"\"\";\n\nList&lt;String&gt; codeFiles = Arrays.asList(\n    \"UserService.java\", \"PaymentController.java\", \"SecurityConfig.java\"\n);\n\nList&lt;String&gt; reviews = new ArrayList&lt;&gt;();\n\nfor (String filename : codeFiles) {\n    String sourceCode = loadSourceFile(filename);\n\n    ChatResponse review = chatModel.call(\n        new Prompt(\n            List.of(\n                new SystemMessage(reviewGuidelines), // Cached across all reviews\n                new UserMessage(\"Review this \" + filename + \" code:\\n\\n\" + sourceCode)\n            ),\n            BedrockChatOptions.builder()\n                .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n                .cacheOptions(BedrockCacheOptions.builder()\n                    .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n                    .build())\n                .maxTokens(800)\n                .build()\n        )\n    );\n\n    reviews.add(review.getResult().getOutput().getText());\n}\n\n// Guidelines cached after first request, subsequent reviews are faster and cheaper\n\nCustomer Support with Knowledge Base\n\nCreate a customer support system that caches your product knowledge base for consistent, accurate responses:\n\n// Load comprehensive product knowledge\nString knowledgeBase = \"\"\"\n    PRODUCT DOCUMENTATION:\n    - API endpoints and authentication methods\n    - Common troubleshooting procedures\n    - Billing and subscription details\n    - Integration guides and examples\n    - Known issues and workarounds\n    \"\"\" + loadProductDocs(); // ~2500 tokens\n\n@Service\npublic class CustomerSupportService {\n\n    public String handleCustomerQuery(String customerQuery, String customerId) {\n        ChatResponse response = chatModel.call(\n            new Prompt(\n                List.of(\n                    new SystemMessage(\"You are a helpful customer support agent. \" +\n                        \"Use this knowledge base to provide accurate solutions: \" + knowledgeBase),\n                    new UserMessage(\"Customer \" + customerId + \" asks: \" + customerQuery)\n                ),\n                BedrockChatOptions.builder()\n                    .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n                    .cacheOptions(BedrockCacheOptions.builder()\n                        .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n                        .build())\n                    .maxTokens(600)\n                    .build()\n            )\n        );\n\n        return response.getResult().getOutput().getText();\n    }\n}\n\n// Knowledge base is cached across all customer queries\n// Multiple support agents can benefit from the same cached content',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Real-World Use Cases::1'),
('e65a6151-5bbd-4b36-bc05-6b7a563e9b52','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-oci-genai/src/main/java/org/springframework/ai/oci/cohere/OCICohereChatModel.java\">OCICohereChatModel</a> implements the <code>ChatModel</code> and uses the OCI Java SDK to connect to the OCI GenAI service.\n\nAdd the <code>spring-ai-oci-genai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-oci-genai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-oci-genai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>OCICohereChatModel</code> and use it for text generations:\n\nvar CONFIG_FILE = Paths.get(System.getProperty(\"user.home\"), \".oci\", \"config\").toString();\nvar COMPARTMENT_ID = System.getenv(\"OCI_COMPARTMENT_ID\");\nvar MODEL_ID = System.getenv(\"OCI_CHAT_MODEL_ID\");\n\nConfigFileAuthenticationDetailsProvider authProvider = new ConfigFileAuthenticationDetailsProvider(\n        CONFIG_FILE,\n        \"DEFAULT\"\n);\nvar genAi = GenerativeAiInferenceClient.builder()\n        .region(Region.valueOf(\"us-chicago-1\"))\n        .build(authProvider);\n\nvar chatModel = new OCICohereChatModel(genAi, OCICohereChatOptions.builder()\n        .model(MODEL_ID)\n        .compartment(COMPARTMENT_ID)\n        .servingMode(\"on-demand\")\n        .build());\n\nChatResponse response = chatModel.call(\n        new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>OCICohereChatOptions</code> provides the configuration information for the chat requests.\nThe <code>OCICohereChatOptions.Builder</code> is fluent options builder.',0x00,'asciidoc::cohere-chat.adoc::Manual Configuration::0'),
('de436418-d203-4a94-a354-6c112828d122','The <code>VectorStore</code> interface extends <code>VectorStoreRetriever</code> and adds mutation capabilities:\n\npublic interface VectorStore extends DocumentWriter, VectorStoreRetriever {\n\n    default String getName() {\n		return this.getClass().getSimpleName();\n	}\n\n    void add(List&lt;Document&gt; documents);\n\n    void delete(List&lt;String&gt; idList);\n\n    void delete(Filter.Expression filterExpression);\n\n    default void delete(String filterExpression) { ... }\n\n    default &lt;T&gt; Optional&lt;T&gt; getNativeClient() {\n		return Optional.empty();\n	}\n}\n\nThe <code>VectorStore</code> interface combines both read and write operations, allowing you to add, delete, and search for documents in a vector database.',0x00,'asciidoc::vectordbs.adoc::API Overview::VectorStore Interface::0'),
('dfe2c978-0a33-48b9-878d-6c2300b1d3be','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Neo4j Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-neo4j&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-neo4j\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nPlease have a look at the list of <a href=\"#neo4jvector-properties\">Configuration Properties</a> for the vector store to learn about the default values and configuration options.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nThe vector store implementation can initialize the requisite schema for you, but you must opt-in by specifying the <code>initializeSchema</code> boolean in the appropriate constructor or by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nNow you can auto-wire the <code>Neo4jVectorStore</code> as a vector store in your application.\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList&lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to Neo4j\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::neo4j.adoc::Auto-configuration::0'),
('25e6b294-d2d4-47c3-9456-6c7201de4957','The ETL pipeline is composed of the following interfaces and implementations.\nDetailed ETL class diagram is shown in the <a href=\"#etl-class-diagram\">ETL Class Diagram</a> section.',0x00,'asciidoc::etl-pipeline.adoc::ETL Interfaces::0'),
('d29fea1b-881f-48c3-8fc9-6c86d838128b','There are two ways to configure the connection to Cassandra:\n\nUsing an injected CqlSession (recommended):\n\n\n@Bean\npublic VectorStore vectorStore(CqlSession session, EmbeddingModel embeddingModel) {\n    return CassandraVectorStore.builder(embeddingModel)\n        .session(session)\n        .keyspace(\"my_keyspace\")\n        .table(\"my_vectors\")\n        .build();\n}\n\nUsing connection details directly in the builder:\n\n\n@Bean\npublic VectorStore vectorStore(EmbeddingModel embeddingModel) {\n    return CassandraVectorStore.builder(embeddingModel)\n        .contactPoint(new InetSocketAddress(\"localhost\", 9042))\n        .localDatacenter(\"datacenter1\")\n        .keyspace(\"my_keyspace\")\n        .build();\n}',0x00,'asciidoc::apache-cassandra.adoc::Usage::Connection Configuration::0'),
('39b6be11-8891-4213-8e45-6c9b1f475292','<strong>Use Google GenAI Embeddings when:</strong>\n- You want quick prototyping with API keys\n- You need the latest embedding features from the Developer API\n- You want flexibility to switch between API key and Vertex AI modes\n- You&#8217;re already using Google GenAI for chat\n\n<strong>Use Vertex AI Text Embeddings when:</strong>\n- You have existing Vertex AI infrastructure\n- You need multimodal embeddings (currently only available in Vertex AI)\n- Your organization requires Google Cloud-only deployment',0x00,'asciidoc::google-genai-embeddings-text.adoc::Migration from Vertex AI Text Embeddings::When to Use Google GenAI vs Vertex AI Text Embeddings::0'),
('1cbe1c4b-e500-4998-8d16-6cbcad9ccf44','Now you can use the method-level annotation (<code>@Tool</code>) to register tools with Spring AI:\n\nclass Home {\n\n    @Tool(description = \"Turn light On or Off in a room.\")\n    void turnLight(String roomName, boolean on) {\n        // ...\n        logger.info(\"Turn light in room: {} to: {}\", roomName, on);\n    }\n}\n\nString response = ChatClient.create(this.chatModel).prompt()\n        .user(\"Turn the light in the living room On.\")\n        .tools(new Home())\n        .call()\n        .content();',0x00,'asciidoc::tools-migration.adoc::Declarative Specification with @Tool::0'),
('e1f26648-f5de-4ba0-b1a0-6ceaf60ce4de','Instead of using the Spring Boot auto-configuration, you can manually configure the Neo4j vector store. For this you need to add the <code>spring-ai-neo4j-store</code> to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-neo4j-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-neo4j-store\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nCreate a Neo4j <code>Driver</code> bean.\nRead the <a href=\"https://neo4j.com/docs/java-manual/current/client-applications/\">Neo4j Documentation</a> for more in-depth information about the configuration of a custom driver.\n\n@Bean\npublic Driver driver() {\n    return GraphDatabase.driver(\"neo4j://&lt;host&gt;:&lt;bolt-port&gt;\",\n            AuthTokens.basic(\"&lt;username&gt;\", \"&lt;password&gt;\"));\n}\n\nThen create the <code>Neo4jVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore vectorStore(Driver driver, EmbeddingModel embeddingModel) {\n    return Neo4jVectorStore.builder(driver, embeddingModel)\n        .databaseName(\"neo4j\")                // Optional: defaults to \"neo4j\"\n        .distanceType(Neo4jDistanceType.COSINE) // Optional: defaults to COSINE\n        .embeddingDimension(1536)                      // Optional: defaults to 1536\n        .label(\"Document\")                     // Optional: defaults to \"Document\"\n        .embeddingProperty(\"embedding\")        // Optional: defaults to \"embedding\"\n        .indexName(\"custom-index\")             // Optional: defaults to \"spring-ai-document-index\"\n        .initializeSchema(true)                // Optional: defaults to false\n        .batchingStrategy(new TokenCountBatchingStrategy()) // Optional: defaults to TokenCountBatchingStrategy\n        .build();\n}\n\n// This can be any EmbeddingModel implementation\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}',0x00,'asciidoc::neo4j.adoc::Manual Configuration::0'),
('08fa3db2-12cc-4c0f-9683-6d21bfae4b21','<div class=\"paragraph\">\n<p>With <a href=\"https://ollama.ai/\">Ollama</a> you can run various Large Language Models (LLMs) locally and generate text from them.\nSpring AI supports the Ollama chat completion capabilities with the <code>OllamaChatModel</code> API.</p>\n</div>\n<div class=\"admonitionblock tip\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Tip</div>\n</td>\n<td class=\"content\">\nOllama offers an OpenAI API compatible endpoint as well.\nThe <a href=\"#_openai_api_compatibility\">OpenAI API compatibility</a> section explains how to use the <a href=\"api/chat/openai-chat.html\">Spring AI OpenAI</a> to connect to an Ollama server.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::ollama-chat.adoc::0'),
('6f58008a-561a-4cd0-81f8-6d39a5c689f9','<div class=\"paragraph\">\n<p>The <a href=\"https://cloud.google.com/vertex-ai/docs/generative-ai/multimodal/overview\">Vertex AI Gemini API</a> allows developers to build generative AI applications using the Gemini model.\nThe Vertex AI Gemini API supports multimodal prompts as input and output text or code.\nA multimodal model is a model that is capable of processing information from multiple modalities, including images, videos, and text. For example, you can send the model a photo of a plate of cookies and ask it to give you a recipe for those cookies.</p>\n</div>\n<div class=\"paragraph\">\n<p>Gemini is a family of generative AI models developed by Google DeepMind that is designed for multimodal use cases. The Gemini API gives you access to the <a href=\"https://cloud.google.com/vertex-ai/generative-ai/docs/models/gemini/2-0-flash\">Gemini 2.0 Flash</a> and <a href=\"https://cloud.google.com/vertex-ai/generative-ai/docs/models/gemini/2-0-flash-lite\">Gemini 2.0 Flash-Lite</a>.\nFor specifications of the Vertex AI Gemini API models, see <a href=\"https://cloud.google.com/vertex-ai/generative-ai/docs/models#gemini-models\">Model information</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://cloud.google.com/vertex-ai/generative-ai/docs/model-reference/inference\">Gemini API Reference</a></p>\n</div>',0x00,'asciidoc::vertexai-gemini-chat.adoc::0'),
('f26136d0-3d67-4e3f-a8b2-6d50d0b9ce06','docker run -it --rm --name chroma -p 8000:8000 ghcr.io/chroma-core/chroma:1.0.0\n\nStarts a chroma store at <a href=\"http://localhost:8000/api/v1\" class=\"bare\">http://localhost:8000/api/v1</a>',0x00,'asciidoc::chroma.adoc::Manual Configuration::Run Chroma Locally::0'),
('57d97910-ec7a-40d1-a371-6d6dd8f7c936','Configuration properties renamed from <code>spring.ai.chat.memory.&lt;storage&gt;&#8230;&#8203;</code> to <code>spring.ai.chat.memory.repository.&lt;storage&gt;&#8230;&#8203;</code>\n\n\n<strong>Migration Required:</strong>\n- Update your Maven/Gradle dependencies to use the new artifact IDs.\n- Update any imports, class references, or configuration that used the old package or class names.\n\nMessage Aggregator Refactoring\n\nChanges\n\n<code>MessageAggregator</code> class has been moved from <code>org.springframework.ai.chat.model</code> package in the <code>spring-ai-client-chat</code> module to the <code>spring-ai-model</code> module (same package name)\nThe <code>aggregateChatClientResponse</code> method has been removed from <code>MessageAggregator</code> and moved to a new class <code>ChatClientMessageAggregator</code> in the <code>org.springframework.ai.chat.client</code> package\n\n\nMigration Guide\n\nIf you were directly using the <code>aggregateChatClientResponse</code> method from <code>MessageAggregator</code>, you need to use the new <code>ChatClientMessageAggregator</code> class instead:\n\n// Before\nnew MessageAggregator().aggregateChatClientResponse(chatClientResponses, aggregationHandler);\n\n// After\nnew ChatClientMessageAggregator().aggregateChatClientResponse(chatClientResponses, aggregationHandler);\n\nDon&#8217;t forget to add the appropriate import:\n\nimport org.springframework.ai.chat.client.ChatClientMessageAggregator;\n\nWatson\n\nThe Watson AI model was removed as it was based on the older text generation that is considered outdated as there is a new chat generation model available.\nHopefully Watson will reappear in a future version of Spring AI\n\nMoonShot and QianFan\n\nMoonshot and Qianfan have been removed since they are not accessible from outside China.  These have been moved to the Spring AI Community repository.\n\nRemoved Vector Store\n\nRemoved HanaDB vector store autoconfiguration (<a href=\"https://github.com/spring-projects/spring-ai/commit/f3b46244942c5072c2e2fa89e62cde71c61bbf25\">f3b4624</a>)\n\n\nMemory Management\n\nRemoved CassandraChatMemory implementation (<a href=\"https://github.com/spring-projects/spring-ai/commit/11e3c8f9a6636d77f203968b83625d3e5694c408\">11e3c8f</a>)\nSimplified chat memory advisor hierarchy and removed deprecated API (<a href=\"https://github.com/spring-projects/spring-ai/commit/848a3fd31fadd07c9ba77f6dc30425389d095e9a\">848a3fd</a>)\nRemoved deprecations in JdbcChatMemory (<a href=\"https://github.com/spring-projects/spring-ai/commit/356a68f15eea07a040bd27c66442472fc55e6475\">356a68f</a>)\nRefactored chat memory repository artifacts for clarity (<a href=\"https://github.com/spring-projects/spring-ai/commit/2d517eec5cd7ce5f88149b876ed57a06ad353e11\">2d517ee</a>)\nRefactored chat memory repository autoconfigurations and Spring Boot starters for clarity (<a href=\"https://github.com/spring-projects/spring-ai/commit/f6dba1bf083d847cdc07888ba62746683e3d61bb\">f6dba1b</a>)\n\n\nMessage and Template APIs',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-RC1::Breaking Changes::1'),
('41f7b0fe-c6c0-4e37-827d-6dd26a9167de','The <code>FileDocumentWriter</code> is a <code>DocumentWriter</code> implementation that writes the content of a list of <code>Document</code> objects into a file.\n\nUsage\n\n@Component\nclass MyDocumentWriter {\n\n    public void writeDocuments(List&lt;Document&gt; documents) {\n        FileDocumentWriter writer = new FileDocumentWriter(\"output.txt\", true, MetadataMode.ALL, false);\n        writer.accept(documents);\n    }\n}\n\nConstructors\n\nThe <code>FileDocumentWriter</code> provides three constructors:\n\n<code>FileDocumentWriter(String fileName)</code>\n<code>FileDocumentWriter(String fileName, boolean withDocumentMarkers)</code>\n<code>FileDocumentWriter(String fileName, boolean withDocumentMarkers, MetadataMode metadataMode, boolean append)</code>\n\n\nParameters\n\n<code>fileName</code>: The name of the file to write the documents to.\n<code>withDocumentMarkers</code>: Whether to include document markers in the output (default: false).\n<code>metadataMode</code>: Specifies what document content to be written to the file (default: MetadataMode.NONE).\n<code>append</code>: If true, data will be written to the end of the file rather than the beginning (default: false).\n\n\nBehavior\n\nThe <code>FileDocumentWriter</code> processes documents as follows:\n\nIt opens a FileWriter for the specified file name.\nFor each document in the input list:\nThe file is closed after all documents have been written.\n\n\nDocument Markers\n\nWhen <code>withDocumentMarkers</code> is set to true, the writer includes markers for each document in the following format:\n\n### Doc: [index], pages:[start_page_number,end_page_number]\n\nMetadata Handling\n\nThe writer uses two specific metadata keys:\n\n<code>page_number</code>: Represents the starting page number of the document.\n<code>end_page_number</code>: Represents the ending page number of the document.\n\n\nThese are used when writing document markers.\n\nExample\n\nList&lt;Document&gt; documents = // initialize your documents\nFileDocumentWriter writer = new FileDocumentWriter(\"output.txt\", true, MetadataMode.ALL, true);\nwriter.accept(documents);\n\nThis will write all documents to \"output.txt\", including document markers, using all available metadata, and appending to the file if it already exists.\n\nNotes\n\nThe writer uses <code>FileWriter</code>, so it writes text files with the default character encoding of the operating system.\nIf an error occurs during writing, a <code>RuntimeException</code> is thrown with the original exception as its cause.\nThe <code>metadataMode</code> parameter allows control over how existing metadata is incorporated into the written content.\nThis writer is particularly useful for debugging or creating human-readable outputs of document collections.',0x00,'asciidoc::etl-pipeline.adoc::Writers::File::0'),
('fa904a6b-a70e-4d7b-987e-6e0dd6756745','Some OpenAI-compatible servers that support reasoning models (such as DeepSeek R1, vLLM with reasoning parsers) expose the model&#8217;s internal chain of thought via a <code>reasoning_content</code> field in their API responses.\nThis field contains the step-by-step reasoning process the model used to arrive at its final answer.\n\nSpring AI maps this field from the JSON response to the <code>reasoningContent</code> key in the AssistantMessage metadata.\n\n<div class=\"paragraph\">\n<p><strong>Important distinction about <code>reasoning_content</code> availability:</strong></p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p><strong>OpenAI-compatible servers</strong> (DeepSeek, vLLM): Expose <code>reasoning_content</code> in Chat Completions API responses ✅</p>\n</li>\n<li>\n<p><strong>Official OpenAI models</strong> (GPT-5, o1, o3): Do <strong>NOT</strong> expose reasoning text in Chat Completions API responses ❌</p>\n</li>\n</ul>\n</div>\n<div class=\"paragraph\">\n<p>Official OpenAI reasoning models hide the chain-of-thought content when using the Chat Completions API.\nThey only expose <code>reasoning_tokens</code> count in usage statistics.\nTo access actual reasoning text from official OpenAI models, you must use OpenAI&#8217;s Responses API (a separate endpoint not currently supported by this client).</p>\n</div>\n<div class=\"paragraph\">\n<p><strong>Fallback behavior:</strong> When <code>reasoning_content</code> is not provided by the server (e.g., official OpenAI Chat Completions), the <code>reasoningContent</code> metadata field will be an empty string.</p>\n</div>\n\nAccessing Reasoning Content\n\nWhen using a compatible server, you can access the reasoning content from the response metadata.\n\n<strong>Using ChatModel directly:</strong>\n\n// Configure to use DeepSeek R1 or vLLM with a reasoning model\nChatResponse response = chatModel.call(\n    new Prompt(\"Which number is larger: 9.11 or 9.8?\")\n);\n\n// Get the assistant message\nAssistantMessage message = response.getResult().getOutput();\n\n// Access the reasoning content from metadata\nString reasoning = message.getMetadata().get(\"reasoningContent\");\nif (reasoning != null &amp;&amp; !reasoning.isEmpty()) {\n    System.out.println(\"Model\'s reasoning process:\");\n    System.out.println(reasoning);\n}\n\n// The final answer is in the regular content\nSystem.out.println(\"\\nFinal answer:\");\nSystem.out.println(message.getContent());\n\n<strong>Using ChatClient:</strong>\n\nChatClient chatClient = ChatClient.create(chatModel);\n\nString result = chatClient.prompt()\n    .user(\"Which number is larger: 9.11 or 9.8?\")\n    .call()\n    .chatResponse()\n    .getResult()\n    .getOutput()\n    .getContent();\n\n// To access reasoning content with ChatClient, retrieve the full response\nChatResponse response = chatClient.prompt()\n    .user(\"Which number is larger: 9.11 or 9.8?\")\n    .call()\n    .chatResponse();\n\nAssistantMessage message = response.getResult().getOutput();\nString reasoning = message.getMetadata().get(\"reasoningContent\");',0x00,'asciidoc::openai-chat.adoc::Using Extra Parameters with OpenAI-Compatible Servers::Reasoning Content from Reasoning Models::0'),
('55b0f936-2824-492d-98be-6e827b2809d2','Currently, Spring AI provides <code>AbstractConversionServiceOutputConverter</code>, <code>AbstractMessageOutputConverter</code>, <code>BeanOutputConverter</code>, <code>MapOutputConverter</code> and <code>ListOutputConverter</code> implementations:\n\n<code>AbstractConversionServiceOutputConverter&lt;T&gt;</code> - Offers a pre-configured <a href=\"https://docs.spring.io/spring-framework/docs/current/javadoc-api/org/springframework/core/convert/support/GenericConversionService.html\">GenericConversionService</a> for transforming LLM output into the desired format. No default <code>FormatProvider</code> implementation is provided.\n<code>AbstractMessageOutputConverter&lt;T&gt;</code> - Supplies a pre-configured <a href=\"https://docs.spring.io/spring-framework/docs/current/javadoc-api/org/springframework/jms/support/converter/MessageConverter.html\">MessageConverter</a> for converting LLM output into the desired format. No default <code>FormatProvider</code> implementation is provided.\n<code>BeanOutputConverter&lt;T&gt;</code> - Configured with a designated Java class (e.g., Bean) or a <a href=\"https://docs.spring.io/spring-framework/docs/current/javadoc-api/org/springframework/core/ParameterizedTypeReference.html\">ParameterizedTypeReference</a>, this converter employs a <code>FormatProvider</code> implementation that directs the AI Model to produce a JSON response compliant with a <code>DRAFT_2020_12</code>, <code>JSON Schema</code> derived from the specified Java class. Subsequently, it utilizes an <code>ObjectMapper</code> to deserialize the JSON output into a Java object instance of the target class.\n<code>MapOutputConverter</code> - Extends the functionality of <code>AbstractMessageOutputConverter</code> with a <code>FormatProvider</code> implementation that guides the AI Model to generate an RFC8259 compliant JSON response. Additionally, it incorporates a converter implementation that utilizes the provided <code>MessageConverter</code> to translate the JSON payload into a <code>java.util.Map&lt;String, Object&gt;</code> instance.\n<code>ListOutputConverter</code> - Extends the  <code>AbstractConversionServiceOutputConverter</code> and includes a <code>FormatProvider</code> implementation tailored for comma-delimited list output. The converter implementation employs the provided <code>ConversionService</code> to transform the model text output into a <code>java.util.List</code>.',0x00,'asciidoc::structured-output-converter.adoc::Structured Output API::Available Converters::0'),
('3936e17f-918a-484f-b785-6ee8a6928a95','Similarly, you can add metadata to system messages:\n\n// Adding metadata to system messages\nString response = chatClient.prompt()\n    .system(s -&gt; s.text(\"You are a helpful assistant.\")\n        .metadata(\"version\", \"1.0\")\n        .metadata(\"model\", \"gpt-4\"))\n    .user(\"Tell me a joke\")\n    .call()\n    .content();',0x00,'asciidoc::chatclient.adoc::Message Metadata::Adding Metadata to System Messages::0'),
('3593a6ee-a018-4c77-9a8f-6f094614d69d','<div class=\"paragraph\">\n<p><a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/conversation-inference.html\">Amazon Bedrock Converse API</a> provides a unified interface for conversational AI models with enhanced capabilities including function/tool calling, multimodal inputs, and streaming responses.</p>\n</div>\n<div class=\"paragraph\">\n<p>The Bedrock Converse API has the following high-level features:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p>Tool/Function Calling: Support for function definitions and tool use during conversations</p>\n</li>\n<li>\n<p>Multimodal Input: Ability to process both text and image inputs in conversations</p>\n</li>\n<li>\n<p>Streaming Support: Real-time streaming of model responses</p>\n</li>\n<li>\n<p>System Messages: Support for system-level instructions and context setting</p>\n</li>\n</ul>\n</div>\n<div class=\"admonitionblock tip\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Tip</div>\n</td>\n<td class=\"content\">\nThe Bedrock Converse API provides a unified interface across multiple model providers while handling AWS-specific authentication and infrastructure concerns.\nCurrently, the Converse API <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/conversation-inference-supported-models-features.html\">Supported Models</a> include:\n<code>Amazon Titan</code>, <code>Amazon Nova</code>, <code>AI21 Labs</code>, <code>Anthropic Claude</code>, <code>Cohere Command</code>, <code>Meta Llama</code>, <code>Mistral AI</code>.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\n<div class=\"paragraph\">\n<p>Following the Bedrock recommendations, Spring AI is transitioning to using Amazon Bedrock&#8217;s Converse API for all chat conversation implementations in Spring AI.\nWhile the existing <a href=\"api/bedrock-chat.html\">InvokeModel API</a> supports conversation applications, we strongly recommend adopting the Converse API for all Chat conversation models.</p>\n</div>\n<div class=\"paragraph\">\n<p>The Converse API does not support embedding operations, so these will remain in the current API and the embedding model functionality in the existing <code>InvokeModel API</code> will be maintained</p>\n</div>\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::bedrock-converse.adoc::0'),
('99665095-3113-498a-a60f-6f13059a8eee','The <code>AzureOpenAiEmbeddingOptions</code> provides the configuration information for the embedding requests.\nThe <code>AzureOpenAiEmbeddingOptions</code> offers a builder to create the options.\n\nAt start time use the <code>AzureOpenAiEmbeddingModel</code> constructor to set the  default options used for all embedding requests.\nAt run-time you can override the default options, by passing a <code>AzureOpenAiEmbeddingOptions</code> instance with your to the  <code>EmbeddingRequest</code> request.\n\nFor example to override the default model name for a specific request:\n\nEmbeddingResponse embeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n        AzureOpenAiEmbeddingOptions.builder()\n        .model(\"Different-Embedding-Model-Deployment-Name\")\n        .build()));',0x00,'asciidoc::azure-openai-embeddings.adoc::Runtime Options::0'),
('e9ecf42d-d978-435d-a6c6-6f2d1f69fe75','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-anthropic</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the Anthropic chat model:\n\nspring.ai.anthropic.api-key=YOUR_API_KEY\nspring.ai.anthropic.chat.options.model=claude-3-5-sonnet-latest\nspring.ai.anthropic.chat.options.temperature=0.7\nspring.ai.anthropic.chat.options.max-tokens=450\n\nReplace the <code>api-key</code> with your Anthropic credentials.\n\nThis will create a <code>AnthropicChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final AnthropicChatModel chatModel;\n\n    @Autowired\n    public ChatController(AnthropicChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::anthropic-chat.adoc::Sample Controller::0'),
('ea822a0d-1156-483d-8866-6f523c783a36','System Prompting\n\nSystem prompting sets the overall context and purpose for the language model, defining the \"big picture\" of what the model should be doing. It establishes the behavioral framework, constraints, and high-level objectives for the model&#8217;s responses, separate from the specific user queries.\n\nSystem prompts act as a persistent \"mission statement\" throughout the conversation, allowing you to set global parameters like output format, tone, ethical boundaries, or role definitions. Unlike user prompts which focus on specific tasks, system prompts frame how all user prompts should be interpreted.\n\n// Implementation of Section 2.3.1: System prompting\npublic void pt_system_prompting_1(ChatClient chatClient) {\n    String movieReview = chatClient\n            .prompt()\n            .system(\"Classify movie reviews as positive, neutral or negative. Only return the label in uppercase.\")\n            .user(\"\"\"\n                    Review: \"Her\" is a disturbing study revealing the direction\n                    humanity is headed if AI is allowed to keep evolving,\n                    unchecked. It\'s so disturbing I couldn\'t watch it.\n\n                    Sentiment:\n                    \"\"\")\n            .options(ChatOptions.builder()\n                    .model(\"claude-3-7-sonnet-latest\")\n                    .temperature(1.0)\n                    .topK(40)\n                    .topP(0.8)\n                    .maxTokens(5)\n                    .build())\n            .call()\n            .content();\n}\n\nSystem prompting is particularly powerful when combined with Spring AI&#8217;s entity mapping capabilities:\n\n// Implementation of Section 2.3.1: System prompting with JSON output\nrecord MovieReviews(Movie[] movie_reviews) {\n    enum Sentiment {\n        POSITIVE, NEUTRAL, NEGATIVE\n    }\n\n    record Movie(Sentiment sentiment, String name) {\n    }\n}\n\nMovieReviews movieReviews = chatClient\n        .prompt()\n        .system(\"\"\"\n                Classify movie reviews as positive, neutral or negative. Return\n                valid JSON.\n                \"\"\")\n        .user(\"\"\"\n                Review: \"Her\" is a disturbing study revealing the direction\n                humanity is headed if AI is allowed to keep evolving,\n                unchecked. It\'s so disturbing I couldn\'t watch it.\n\n                JSON Response:\n                \"\"\")\n        .call()\n        .entity(MovieReviews.class);\n\nSystem prompts are especially valuable for multi-turn conversations, ensuring consistent behavior across multiple queries, and for establishing format constraints like JSON output that should apply to all responses.\n\n<strong>Reference:</strong> OpenAI. (2022). \"System Message.\" <a href=\"https://platform.openai.com/docs/guides/chat/introduction\">https://platform.openai.com/docs/guides/chat/introduction</a>\n\nRole Prompting',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.3 System, contextual and role prompting::0'),
('9346c6ac-b248-4d76-8101-6f5703056568','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-huggingface</code> to your pom (or gradle) dependencies.\n\nAdd an <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the Hugging Face chat model:\n\nspring.ai.huggingface.chat.api-key=YOUR_API_KEY\nspring.ai.huggingface.chat.url=YOUR_INFERENCE_ENDPOINT_URL\n\nreplace the <code>api-key</code> and <code>url</code> with your Hugging Face values.\n\nThis will create a <code>HuggingfaceChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final HuggingfaceChatModel chatModel;\n\n    @Autowired\n    public ChatController(HuggingfaceChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n}',0x00,'asciidoc::huggingface.adoc::Sample Controller (Auto-configuration)::0'),
('46b41e69-162e-4d01-a978-6f7709077080','The Spring AI API covers a wide range of functionalities.\nEach major feature is detailed in its own dedicated section.\nTo provide an overview, the following key functionalities are available:',0x00,'asciidoc::index.adoc::Introduction::0'),
('b8a7ce11-858b-44ad-a341-6f96623afdda','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nAdd the <code>spring-ai-starter-model-bedrock</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n  &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n  &lt;artifactId&gt;spring-ai-starter-model-bedrock&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-bedrock\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Auto-configuration::0'),
('b056945a-d0b0-4b35-9d97-6fcd23d7fdad','In the most simple use case, Spring AI provides Spring Boot autoconfiguration, creating a prototype <code>ChatClient.Builder</code> bean for you to inject into your class.\nHere is a simple example of retrieving a <code>String</code> response to a simple user request.\n\n@RestController\nclass MyController {\n\n    private final ChatClient chatClient;\n\n    public MyController(ChatClient.Builder chatClientBuilder) {\n        this.chatClient = chatClientBuilder.build();\n    }\n\n    @GetMapping(\"/ai\")\n    String generation(String userInput) {\n        return this.chatClient.prompt()\n            .user(userInput)\n            .call()\n            .content();\n    }\n}\n\nIn this simple example, the user input sets the contents of the user message.\nThe <code>call()</code> method sends a request to the AI model, and the <code>content()</code> method returns the AI model&#8217;s response as a <code>String</code>.',0x00,'asciidoc::chatclient.adoc::Creating a ChatClient::Using an autoconfigured ChatClient.Builder::0'),
('a8b08a9b-6155-43bb-8782-6ff12621bbec','The Embedding Model API is built on top of the generic <a href=\"https://github.com/spring-projects/spring-ai/tree/main/spring-ai-model/src/main/java/org/springframework/ai/model\">Spring AI Model API</a>, which is a part of the Spring AI library.\nAs such, the EmbeddingModel interface extends the <code>Model</code> interface, which provides a standard set of methods for interacting with AI models. The <code>EmbeddingRequest</code> and <code>EmbeddingResponse</code> classes extend from the <code>ModelRequest</code> and <code>ModelResponse</code> are used to encapsulate the input and output of the embedding models, respectively.\n\nThe Embedding API in turn is used by higher-level components to implement Embedding Models for specific embedding models, such as OpenAI, Titan, Azure OpenAI, Ollie, and others.\n\nFollowing diagram illustrates the Embedding API and its relationship with the Spring AI Model API and the Embedding Models:\n\n<span class=\"image\"><img src=\"embeddings-api.jpg\" alt=\"embeddings api\" width=\"900\" title=\"Embeddings API\"></span>',0x00,'asciidoc::embeddings.adoc::API Overview::0'),
('70305297-678b-476c-9c4e-70281ab80e9f','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-zhipuai/src/main/java/org/springframework/ai/zhipuai/ZhiPuAiChatOptions.java\">ZhiPuAiChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>ZhiPuAiChatModel(api, options)</code> constructor or the <code>spring.ai.zhipuai.chat.options.*</code> properties.\n\nAt run-time you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        ZhiPuAiChatOptions.builder()\n            .model(ZhiPuAiApi.ChatModel.GLM_4_Air.getValue())\n            .temperature(0.5)\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-zhipuai/src/main/java/org/springframework/ai/zhipuai/ZhiPuAiChatOptions.java\">ZhiPuAiChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::zhipuai-chat.adoc::Runtime Options::0'),
('89c68e8b-beba-486b-a157-7047dd4be5e4','As shown <a href=\"#AiMetadata-GenerationMetadata\">above</a>, <code>Usage</code> data can be obtained from the <code>GenerationMetadata</code> object. The <code>Usage</code> interface is defined as:\n\ninterface Usage {\n\n	Long getPromptTokens();\n\n	Long getGenerationTokens();\n\n	default Long getTotalTokens() {\n		return getPromptTokens() + getGenerationTokens();\n	}\n\n}\n\nThe method names are self-explanatory, but tells you the tokens that the AI required to process the <code>Prompt</code> and generate a response.\n\n<code>totalTokens</code> is the sum of <code>promptTokens</code> and <code>generationTokens</code>. Spring AI computes this by default, but the information is returned in the AI response from OpenAI.',0x00,'asciidoc::aimetadata.adoc::Usage::0'),
('74723847-e731-402a-95c1-706d3626d751','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OpenAI Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::openai-embeddings.adoc::Auto-configuration::0'),
('ee805f81-1630-4032-91cd-708877b4ecdd','The Cassandra Vector Store implementation provides access to the underlying native Cassandra client (<code>CqlSession</code>) through the <code>getNativeClient()</code> method:\n\nCassandraVectorStore vectorStore = context.getBean(CassandraVectorStore.class);\nOptional&lt;CqlSession&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    CqlSession session = nativeClient.get();\n    // Use the native client for Cassandra-specific operations\n}\n\nThe native client gives you access to Cassandra-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::apache-cassandra.adoc::Accessing the Native Client::0'),
('1c18685d-8b40-46cc-8501-70b40429266a','Enable prompt caching by setting <code>cacheOptions</code> on <code>BedrockChatOptions</code> and choosing a <code>strategy</code>.\n\nSystem-Only Caching\n\nThe most common use case - cache system instructions across multiple requests:\n\n// Cache system message content\nChatResponse response = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(\"You are a helpful AI assistant with extensive knowledge...\"),\n            new UserMessage(\"What is machine learning?\")\n        ),\n        BedrockChatOptions.builder()\n            .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(500)\n            .build()\n    )\n);\n\nTools-Only Caching\n\nCache large tool definitions while keeping system prompts dynamic (Claude models only):\n\n// Cache tool definitions only\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"What\'s the weather in San Francisco?\",\n        BedrockChatOptions.builder()\n            .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.TOOLS_ONLY)\n                .build())\n            .toolCallbacks(weatherToolCallbacks)  // Large tool definitions\n            .maxTokens(500)\n            .build()\n    )\n);\n\nThis strategy is only supported on Claude models.\nAmazon Nova models will return a <code>ValidationException</code>.\n\nSystem and Tools Caching\n\nCache both system instructions and tool definitions for maximum reuse (Claude models only):\n\n// Cache system message and tool definitions\nChatResponse response = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(\"You are a weather analysis assistant...\"),\n            new UserMessage(\"What\'s the weather like in Tokyo?\")\n        ),\n        BedrockChatOptions.builder()\n            .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_AND_TOOLS)\n                .build())\n            .toolCallbacks(weatherToolCallbacks)\n            .maxTokens(500)\n            .build()\n    )\n);\n\nThis strategy uses 2 cache breakpoints (one for tools, one for system).\nOnly supported on Claude models.\n\nConversation History Caching\n\nCache growing conversation history for multi-turn chatbots and assistants:',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Enabling Prompt Caching::0'),
('70ca1975-8769-4ec6-b184-70d3ed44c6cf','Following class diagram illustrates the Vertex AI Gemini native Java API:',0x00,'asciidoc::vertexai-gemini-chat.adoc::Low-level Java Client::0'),
('2c3ae3ab-ed8b-4332-9d1d-70f950c7800a','You can leverage the generic, portable <a href=\"https://docs.spring.io/spring-ai/reference/api/vectordbs.html#_metadata_filters\">metadata filters</a> with the Couchbase store.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.defaults()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\"));\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.defaults()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .filterExpression(b.and(\n        b.in(\"author\",\"john\", \"jill\"),\n        b.eq(\"article_type\", \"blog\")).build()));\n\nThese filter expressions are converted into the equivalent Couchbase SQL++ filters.',0x00,'asciidoc::couchbase.adoc::Metadata Filtering::0'),
('d93b897f-7a02-436a-88c4-710622fa51c9','<strong>SDK</strong>: Google GenAI uses the new <code>com.google.genai.Client</code> instead of Vertex AI SDK\n<strong>Authentication</strong>: Supports both API key and Google Cloud credentials\n<strong>Package Names</strong>: Classes are in <code>org.springframework.ai.google.genai.text</code> instead of <code>org.springframework.ai.vertexai.embedding</code>\n<strong>Property Prefix</strong>: Uses <code>spring.ai.google.genai.embedding</code> instead of <code>spring.ai.vertex.ai.embedding</code>\n<strong>Connection Details</strong>: Uses <code>GoogleGenAiEmbeddingConnectionDetails</code> instead of <code>VertexAiEmbeddingConnectionDetails</code>',0x00,'asciidoc::google-genai-embeddings-text.adoc::Migration from Vertex AI Text Embeddings::Key Differences::0'),
('251036e5-68ca-4841-8495-7115b584821c','/**\n * A {@link ObservationConvention} for {@link VectorStoreObservationContext}.\n *\n * @author Christian Tzolov\n * @since 1.0.0\n */\npublic interface VectorStoreObservationConvention extends ObservationConvention<VectorStoreObservationContext> {\n\n    @Override\n    default boolean supportsContext(Observation.Context context) {\n        return context instanceof VectorStoreObservationContext;\n    }\n}',0x01,'cu::VectorStoreObservationConvention.java'),
('0a0551a4-6dc7-4eb5-bf37-711bd86e91b5','Instead of using the Spring Boot auto-configuration, you can manually configure the Qdrant vector store. For this you need to add the <code>spring-ai-qdrant-store</code> to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-qdrant-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-qdrant-store\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nCreate a Qdrant client bean:\n\n@Bean\npublic QdrantClient qdrantClient() {\n    QdrantGrpcClient.Builder grpcClientBuilder =\n        QdrantGrpcClient.newBuilder(\n            \"&lt;QDRANT_HOSTNAME&gt;\",\n            &lt;QDRANT_GRPC_PORT&gt;,\n            &lt;IS_TLS&gt;);\n    grpcClientBuilder.withApiKey(\"&lt;QDRANT_API_KEY&gt;\");\n\n    return new QdrantClient(grpcClientBuilder.build());\n}\n\nThen create the <code>QdrantVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore vectorStore(QdrantClient qdrantClient, EmbeddingModel embeddingModel) {\n    return QdrantVectorStore.builder(qdrantClient, embeddingModel)\n        .collectionName(\"custom-collection\")     // Optional: defaults to \"vector_store\"\n        .initializeSchema(true)                  // Optional: defaults to false\n        .batchingStrategy(new TokenCountBatchingStrategy()) // Optional: defaults to TokenCountBatchingStrategy\n        .build();\n}\n\n// This can be any EmbeddingModel implementation\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}',0x00,'asciidoc::qdrant.adoc::Manual Configuration::0'),
('9608aa64-1ca8-45d0-b39b-7170f52ba1cf','The <code>SummaryMetadataEnricher</code> is a <code>DocumentTransformer</code> that uses a generative AI model to create summaries for documents and add them as metadata. It can generate summaries for the current document, as well as adjacent documents (previous and next).\n\nUsage\n\n@Configuration\nclass EnricherConfig {\n\n    @Bean\n    public SummaryMetadataEnricher summaryMetadata(OpenAiChatModel aiClient) {\n        return new SummaryMetadataEnricher(aiClient,\n            List.of(SummaryType.PREVIOUS, SummaryType.CURRENT, SummaryType.NEXT));\n    }\n}\n\n@Component\nclass MySummaryEnricher {\n\n    private final SummaryMetadataEnricher enricher;\n\n    MySummaryEnricher(SummaryMetadataEnricher enricher) {\n        this.enricher = enricher;\n    }\n\n    List&lt;Document&gt; enrichDocuments(List&lt;Document&gt; documents) {\n        return this.enricher.apply(documents);\n    }\n}\n\nConstructor\n\nThe <code>SummaryMetadataEnricher</code> provides two constructors:\n\n<code>SummaryMetadataEnricher(ChatModel chatModel, List&lt;SummaryType&gt; summaryTypes)</code>\n<code>SummaryMetadataEnricher(ChatModel chatModel, List&lt;SummaryType&gt; summaryTypes, String summaryTemplate, MetadataMode metadataMode)</code>\n\n\nParameters\n\n<code>chatModel</code>: The AI model used for generating summaries.\n<code>summaryTypes</code>: A list of <code>SummaryType</code> enum values indicating which summaries to generate (PREVIOUS, CURRENT, NEXT).\n<code>summaryTemplate</code>: A custom template for summary generation (optional).\n<code>metadataMode</code>: Specifies how to handle document metadata when generating summaries (optional).\n\n\nBehavior\n\nThe <code>SummaryMetadataEnricher</code> processes documents as follows:\n\nFor each input document, it creates a prompt using the document&#8217;s content and the specified summary template.\nIt sends this prompt to the provided <code>ChatModel</code> to generate a summary.\nDepending on the specified <code>summaryTypes</code>, it adds the following metadata to each document:\nThe enriched documents are returned.\n\n\nCustomization\n\nThe summary generation prompt can be customized by providing a custom <code>summaryTemplate</code>. The default template is:\n\n\"\"\"\nHere is the content of the section:\n{context_str}\n\nSummarize the key topics and entities of the section.\n\nSummary:\n\"\"\"\n\nExample',0x00,'asciidoc::etl-pipeline.adoc::Transformers::SummaryMetadataEnricher::0'),
('518818f6-aa74-46ba-a526-71a84d788143','/**\n * Low-cardinality observation key names for vector store operations.\n */\npublic enum LowCardinalityKeyNames implements KeyName {\n\n    /**\n     * Spring AI kind.\n     */\n    SPRING_AI_KIND {\n\n        @Override\n        public String asString() {\n            return \"spring.ai.kind\";\n        }\n    }\n    ,\n    /**\n     * The name of the operation or command being executed.\n     */\n    DB_OPERATION_NAME {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_OPERATION_NAME.value();\n        }\n    }\n    ,\n    /**\n     * The database management system (DBMS) product as identified by the client\n     * instrumentation.\n     */\n    DB_SYSTEM {\n\n        @Override\n        public String asString() {\n            return VectorStoreObservationAttributes.DB_SYSTEM.value();\n        }\n    }\n\n}',0x01,'cu::VectorStoreObservationDocumentation.java'),
('0e23e63d-25a4-4fe0-b0f2-71ae5e3119b7','Anthropic&#8217;s <a href=\"https://docs.anthropic.com/en/docs/build-with-claude/prompt-caching\">prompt caching feature</a> allows you to cache frequently used prompts to reduce costs and improve response times for repeated interactions.\nWhen you cache a prompt, subsequent identical requests can reuse the cached content, significantly reducing the number of input tokens processed.\n\n<div class=\"paragraph\">\n<p><strong>Supported Models</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Prompt caching is currently supported on Claude Opus 4, Claude Sonnet 4, Claude Sonnet 3.7, Claude Sonnet 3.5, Claude Haiku 3.5, Claude Haiku 3, and Claude Opus 3.</p>\n</div>\n<div class=\"paragraph\">\n<p><strong>Token Requirements</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Different models have different minimum token thresholds for cache effectiveness:\n- Claude Sonnet 4: 1024+ tokens\n- Claude Haiku models: 2048+ tokens\n- Other models: 1024+ tokens</p>\n</div>',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::0'),
('15b91413-af05-4b74-abcb-71d80aaef64b','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Mistral AI Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-mistral-ai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-mistral-ai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::mistralai-chat.adoc::Auto-configuration::0'),
('ff3e5a7f-9e5c-4156-b507-72f8c555b668','@SuppressWarnings(\"CheckReturnValue\")\npublic static class BooleanConstantContext extends ConstantContext {\n\n    public TerminalNode BOOLEAN_VALUE() {\n        return getToken(FiltersParser.BOOLEAN_VALUE, 0);\n    }\n\n    public BooleanConstantContext(ConstantContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterBooleanConstant(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitBooleanConstant(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitBooleanConstant(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('942f0b18-cf28-4068-aa40-733934d0d24a','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::huggingface.adoc::Prerequisites::Add Repositories and BOM::0'),
('a28a8760-8589-46b2-94cd-73bb39859fba','Ollama&#8217;s OpenAI-compatible endpoint supports the <code>reasoning_content</code> field for thinking-capable models (such as <code>qwen3:*-thinking</code>, <code>deepseek-r1</code>, <code>deepseek-v3.1</code>).\nWhen using the Spring AI OpenAI client with Ollama, the model&#8217;s reasoning process is automatically captured and made available through the response metadata.\n\nThis is an alternative to using Ollama&#8217;s native thinking mode API (documented in <a href=\"#_thinking_mode_reasoning\">Thinking Mode (Reasoning)</a> above).\nBoth approaches work with Ollama&#8217;s thinking models, but the OpenAI-compatible endpoint uses the <code>reasoning_content</code> field name instead of <code>thinking</code>.\n\nHere&#8217;s an example of accessing reasoning content from Ollama through the OpenAI client:\n\n// Configure Spring AI OpenAI client to point to Ollama\n@Configuration\nclass OllamaConfig {\n    @Bean\n    OpenAiChatModel ollamaChatModel() {\n        var openAiApi = new OpenAiApi(\"http://localhost:11434\", \"ollama\");\n        return new OpenAiChatModel(openAiApi,\n            OpenAiChatOptions.builder()\n                .model(\"deepseek-r1\")  // or qwen3, deepseek-v3.1, etc.\n                .build());\n    }\n}\n\n// Use the model with thinking-capable models\nChatResponse response = chatModel.call(\n    new Prompt(\"How many letter \'r\' are in the word \'strawberry\'?\"));\n\n// Access the reasoning process from metadata\nString reasoning = response.getResult().getMetadata().get(\"reasoningContent\");\nif (reasoning != null &amp;&amp; !reasoning.isEmpty()) {\n    System.out.println(\"Model\'s reasoning process:\");\n    System.out.println(reasoning);\n}\n\n// Get the final answer\nString answer = response.getResult().getOutput().getContent();\nSystem.out.println(\"Answer: \" + answer);\n\nThinking-capable models in Ollama (0.12+) automatically enable thinking mode when accessed through the OpenAI-compatible endpoint.\nThe reasoning content is captured automatically without requiring additional configuration.\n\nCheck the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/chat/proxy/OllamaWithOpenAiChatModelIT.java\">OllamaWithOpenAiChatModelIT.java</a> tests for examples of using Ollama over Spring AI OpenAI.',0x00,'asciidoc::ollama-chat.adoc::OpenAI API Compatibility::Reasoning Content via OpenAI Compatibility::0'),
('8320f978-7cf9-4147-934b-73bb95945618','Choose one of the following authentication methods:',0x00,'asciidoc::google-genai-embeddings-text.adoc::Prerequisites::0'),
('2b7854dc-701a-4fbd-8c0c-74805285a1df','NVIDIA LLM API supports Tool/Function calling when selecting a model that supports it.\n\nYou can register custom Java functions with your ChatModel and have the provided model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.',0x00,'asciidoc::nvidia-chat.adoc::Function Calling::0'),
('a5091ab9-7029-45b5-a5d3-74902758e4d0','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/api/OpenAiApi.java\">OpenAiApi</a> provides is lightweight Java client for OpenAI Chat API <a href=\"https://platform.openai.com/docs/api-reference/chat\">OpenAI Chat API</a>.\n\nFollowing class diagram illustrates the <code>OpenAiApi</code> chat interfaces and building blocks:\n\nHere is a simple snippet showing how to use the API programmatically:\n\nOpenAiApi openAiApi = OpenAiApi.builder()\n            .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n            .build();\n\nChatCompletionMessage chatCompletionMessage =\n    new ChatCompletionMessage(\"Hello world\", Role.USER);\n\n// Sync request\nResponseEntity&lt;ChatCompletion&gt; response = this.openAiApi.chatCompletionEntity(\n    new ChatCompletionRequest(List.of(this.chatCompletionMessage), \"gpt-3.5-turbo\", 0.8, false));\n\n// Streaming request\nFlux&lt;ChatCompletionChunk&gt; streamResponse = this.openAiApi.chatCompletionStream(\n        new ChatCompletionRequest(List.of(this.chatCompletionMessage), \"gpt-3.5-turbo\", 0.8, true));\n\nFollow the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/api/OpenAiApi.java\">OpenAiApi.java</a>\'s JavaDoc for further information.',0x00,'asciidoc::openai-chat.adoc::Low-level OpenAiApi Client::0'),
('65979e88-e24d-414b-88f6-7534101f1165','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/main/java/org/springframework/ai/mistralai/MistralAiChatModel.java\">MistralAiChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"#low-level-api\">Low-level MistralAiApi Client</a> to connect to the Mistral AI service.\n\nAdd the <code>spring-ai-mistral-ai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-mistral-ai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-mistral-ai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>MistralAiChatModel</code> and use it for text generations:\n\nvar mistralAiApi = new MistralAiApi(System.getenv(\"MISTRAL_AI_API_KEY\"));\n\nvar chatModel = new MistralAiChatModel(this.mistralAiApi, MistralAiChatOptions.builder()\n                .model(MistralAiApi.ChatModel.LARGE.getValue())\n                .temperature(0.4)\n                .maxTokens(200)\n                .build());\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; response = this.chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>MistralAiChatOptions</code> provides the configuration information for the chat requests.\nThe <code>MistralAiChatOptions.Builder</code> is a fluent options-builder.',0x00,'asciidoc::mistralai-chat.adoc::Manual Configuration::0'),
('6c7011f0-eb2e-4a5b-b04e-75a756b6b64c','<div class=\"paragraph\">\n<p>This section offers jumping off points for how to get started using Spring AI.</p>\n</div>\n<div class=\"paragraph\">\n<p>You should follow the steps in each of the following sections according to your needs.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nSpring AI supports Spring Boot 3.4.x and 3.5.x.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::getting-started.adoc::0'),
('285e0a6f-f143-4877-b69e-75b7dea5b9d7','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-minimax</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the MiniMax chat model:\n\nspring.ai.minimax.api-key=YOUR_API_KEY\nspring.ai.minimax.chat.options.model=abab6.5g-chat\nspring.ai.minimax.chat.options.temperature=0.7\n\nreplace the <code>api-key</code> with your MiniMax credentials.\n\nThis will create a <code>MiniMaxChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final MiniMaxChatModel chatModel;\n\n    @Autowired\n    public ChatController(MiniMaxChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        var prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::minimax-chat.adoc::Sample Controller::0'),
('916505c3-0503-4c30-836b-75faa3407882','<strong>Choose the Right Strategy</strong>:\n<strong>Understand Cascade Invalidation</strong>: Anthropic&#8217;s cache hierarchy (<code>tools → system → messages</code>) means changes flow downward:\n<strong>SYSTEM_AND_TOOLS Independence</strong>: With <code>SYSTEM_AND_TOOLS</code>, changing the system message does NOT invalidate the tool cache, allowing efficient reuse of cached tools even when system prompts vary.\n<strong>Meet Token Requirements</strong>: Focus on caching content that meets the minimum token requirements (1024+ tokens for Sonnet 4, 2048+ for Haiku models).\n<strong>Reuse Identical Content</strong>: Caching works best with exact matches of prompt content. Even small changes will require a new cache entry.\n<strong>Monitor Token Usage</strong>: Use the cache usage statistics to track cache effectiveness:\n<code><code>java\nAnthropicApi.Usage usage = (AnthropicApi.Usage) response.getMetadata().getUsage().getNativeUsage();\nif (usage != null) {\n    System.out.println(\"Cache creation: \" + usage.cacheCreationInputTokens());\n    System.out.println(\"Cache read: \" + usage.cacheReadInputTokens());\n}\n</code></code>\n<strong>Strategic Cache Placement</strong>: The implementation automatically places cache breakpoints at optimal locations based on your chosen strategy, ensuring compliance with Anthropic&#8217;s 4-breakpoint limit.\n<strong>Cache Lifetime</strong>: Default TTL is 5 minutes; set 1-hour TTL per message type via <code>messageTypeTtl(&#8230;&#8203;)</code>. Each cache access resets the timer.\n<strong>Tool Caching Limitations</strong>: Be aware that tool-based interactions may not provide cache usage metadata in the response.',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Best Practices::0'),
('f56d58b1-815f-43a4-9b97-76042ee981d2','Advisor retrievalAugmentationAdvisor = RetrievalAugmentationAdvisor.builder()\n        .queryTransformers(RewriteQueryTransformer.builder()\n                .chatClientBuilder(chatClientBuilder.build().mutate())\n                .build())\n        .documentRetriever(VectorStoreDocumentRetriever.builder()\n                .similarityThreshold(0.50)\n                .vectorStore(vectorStore)\n                .build())\n        .build();\n\nString answer = chatClient.prompt()\n        .advisors(retrievalAugmentationAdvisor)\n        .user(question)\n        .call()\n        .content();\n\nYou can also use the <code>DocumentPostProcessor</code> API to post-process the retrieved documents before passing them to the model. For example, you can use such an interface to perform re-ranking of the retrieved documents based on their relevance to the query, remove irrelevant or redundant documents, or compress the content of each document to reduce noise and redundancy.',0x00,'asciidoc::retrieval-augmented-generation.adoc::Advisors::RetrievalAugmentationAdvisor::1'),
('e8c4b684-9d2c-4fc8-a5d4-76338a1e4030','The metadata is included in the generated UserMessage and SystemMessage objects and can be accessed through the message&#8217;s <code>getMetadata()</code> method.\nThis is particularly useful when processing messages in advisors or when examining the conversation history.',0x00,'asciidoc::chatclient.adoc::Message Metadata::Accessing Metadata::0'),
('21f0485d-84f1-426b-82a4-769bb687e973','Let&#8217;s see how to start using tool calling in Spring AI. We&#8217;ll implement two simple tools: one for information retrieval and one for taking action. The information retrieval tool will be used to get the current date and time in the user&#8217;s time zone. The action tool will be used to set an alarm for a specified time.',0x00,'asciidoc::tools.adoc::Quick Start::0'),
('0fdfd453-3fa8-4683-87c7-76df5d2cf73b','To configure an Azure <code>SearchIndexClient</code> in your application, you can use the following code:\n\n@Bean\npublic SearchIndexClient searchIndexClient() {\n  return new SearchIndexClientBuilder().endpoint(System.getenv(\"AZURE_AI_SEARCH_ENDPOINT\"))\n    .credential(new AzureKeyCredential(System.getenv(\"AZURE_AI_SEARCH_API_KEY\")))\n    .buildClient();\n}\n\nTo create a vector store, you can use the following code by injecting the <code>SearchIndexClient</code> bean created in the above sample along with an <code>EmbeddingModel</code> provided by the Spring AI library that implements the desired Embeddings interface.\n\n@Bean\npublic VectorStore vectorStore(SearchIndexClient searchIndexClient, EmbeddingModel embeddingModel) {\n\n  return AzureVectorStore.builder(searchIndexClient, embeddingModel)\n    .initializeSchema(true)\n    // Define the metadata fields to be used\n    // in the similarity search filters.\n    .filterMetadataFields(List.of(MetadataField.text(\"country\"), MetadataField.int64(\"year\"),\n            MetadataField.date(\"activationDate\")))\n    .defaultTopK(5)\n    .defaultSimilarityThreshold(0.7)\n    .indexName(\"spring-ai-document-index\")\n    .build();\n}\n\n<div class=\"paragraph\">\n<p>You must list explicitly all metadata field names and types for any metadata key used in the filter expression. The list above registers filterable metadata fields: <code>country</code> of type <code>TEXT</code>, <code>year</code> of type <code>INT64</code>, and <code>active</code> of type <code>BOOLEAN</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>If the filterable metadata fields are expanded with new entries, you have to (re)upload/update the documents with this metadata.</p>\n</div>\n\nIn your main code, create some documents:\n\nList&lt;Document&gt; documents = List.of(\n	new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"country\", \"BG\", \"year\", 2020)),\n	new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n	new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"country\", \"NL\", \"year\", 2023)));\n\nAdd the documents to your vector store:\n\nvectorStore.add(documents);\n\nAnd finally, retrieve documents similar to a query:\n\nList&lt;Document&gt; results = vectorStore.similaritySearch(\n    SearchRequest.builder()\n      .query(\"Spring\")\n      .topK(5).build());\n\nIf all goes well, you should retrieve the document containing the text \"Spring AI rocks!!\".',0x00,'asciidoc::azure.adoc::Sample Code::0'),
('a71736e4-398c-4421-8472-7719e37d6f17','public static final class Builder {\n\n    private ChatClient.Builder chatClientBuilder;\n\n    private PromptTemplate promptTemplate;\n\n    private Boolean includeOriginal;\n\n    private Integer numberOfQueries;\n\n    private Builder() {\n    }\n\n    public Builder chatClientBuilder(ChatClient.Builder chatClientBuilder) {\n        this.chatClientBuilder = chatClientBuilder;\n        return this;\n    }\n\n    public Builder promptTemplate(PromptTemplate promptTemplate) {\n        this.promptTemplate = promptTemplate;\n        return this;\n    }\n\n    public Builder includeOriginal(Boolean includeOriginal) {\n        this.includeOriginal = includeOriginal;\n        return this;\n    }\n\n    public Builder numberOfQueries(Integer numberOfQueries) {\n        this.numberOfQueries = numberOfQueries;\n        return this;\n    }\n\n    public MultiQueryExpander build() {\n        return new MultiQueryExpander(this.chatClientBuilder, this.promptTemplate, this.includeOriginal, this.numberOfQueries);\n    }\n}',0x01,'cu::MultiQueryExpander.java'),
('e8a1ffa6-a52a-44eb-98c8-773c076b23a9','To quickly get started with a local Weaviate instance, you can run it in Docker:\n\ndocker run -it --rm --name weaviate \\\n    -e AUTHENTICATION_ANONYMOUS_ACCESS_ENABLED=true \\\n    -e PERSISTENCE_DATA_PATH=/var/lib/weaviate \\\n    -e QUERY_DEFAULTS_LIMIT=25 \\\n    -e DEFAULT_VECTORIZER_MODULE=none \\\n    -e CLUSTER_HOSTNAME=node1 \\\n    -p 8080:8080 \\\n    semitechnologies/weaviate:1.22.4\n\nThis starts a Weaviate instance accessible at <a href=\"http://localhost:8080\" class=\"bare\">http://localhost:8080</a>.',0x00,'asciidoc::weaviate.adoc::Run Weaviate in Docker::0'),
('09958c2c-07ad-49cd-ac28-7743e14b309d','The Routing pattern implements intelligent task distribution, enabling specialized handling for different types of input.\n\n<strong>When to Use:</strong>\n- Complex tasks with distinct categories of input\n- When different inputs require specialized processing\n- When classification can be handled accurately\n\n@Autowired\nprivate ChatClient chatClient;\n\nRoutingWorkflow workflow = new RoutingWorkflow(chatClient);\n\nMap&lt;String, String&gt; routes = Map.of(\n    \"billing\", \"You are a billing specialist. Help resolve billing issues...\",\n    \"technical\", \"You are a technical support engineer. Help solve technical problems...\",\n    \"general\", \"You are a customer service representative. Help with general inquiries...\"\n);\n\nString input = \"My account was charged twice last week\";\nString response = workflow.route(input, routes);',0x00,'asciidoc::effective-agents.adoc::Agentic Systems::3. <a href=\"https://github.com/spring-projects/spring-ai-examples/tree/main/agentic-patterns/routing-workflow\">Routing Workflow</a>::0'),
('de2e76ef-2122-4fef-bd81-776751e7f8cf','<div class=\"paragraph\">\n<p>This section will walk you through setting up the <code>AzureVectorStore</code> to store document embeddings and perform similarity searches using the Azure AI Search Service.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://azure.microsoft.com/en-us/products/ai-services/ai-search/\">Azure AI Search</a> is a versatile cloud-hosted cloud information retrieval system that is part of Microsoft&#8217;s larger AI platform. Among other features, it allows users to query information using vector-based storage and retrieval.</p>\n</div>',0x00,'asciidoc::azure.adoc::0'),
('ece66b71-93c5-4caa-9999-776de0793154','You will need to create an API with ZhiPuAI to access ZhiPu AI language models.\n\nCreate an account at <a href=\"https://open.bigmodel.cn/login\">ZhiPu AI registration page</a> and generate the token on the <a href=\"https://open.bigmodel.cn/usercenter/apikeys\">API Keys page</a>.\n\nThe Spring AI project defines a configuration property named <code>spring.ai.zhipuai.api-key</code> that you should set to the value of the <code>API Key</code> obtained from the API Keys page.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.zhipuai.api-key=&lt;your-zhipuai-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference an environment variable:\n\n# In application.yml\nspring:\n  ai:\n    zhipuai:\n      api-key: ${ZHIPUAI_API_KEY}\n\n# In your environment or .env file\nexport ZHIPUAI_API_KEY=&lt;your-zhipuai-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"ZHIPUAI_API_KEY\");',0x00,'asciidoc::zhipuai-embeddings.adoc::Prerequisites::0'),
('c204bf96-de13-4b94-99b6-7776392eeedb','/**\n * String identifier representing an expression key. (e.g. the country in the country\n * == \"NL\" expression).\n *\n * @param key expression key\n */\npublic record Key(String key) implements Operand {\n}',0x01,'cu::Filter.java'),
('d3f8d929-272b-4dd0-adb8-77cc06910dcd','Perplexity does not support explicit function calling. Instead, it integrates search results directly into responses.',0x00,'asciidoc::perplexity-chat.adoc::Function Calling::0'),
('569c4df7-9209-4584-8bc1-77e6e6192f06','Memory Management\n\nRemoved CassandraChatMemory implementation (<a href=\"https://github.com/spring-projects/spring-ai/commit/11e3c8f9a6636d77f203968b83625d3e5694c408\">11e3c8f</a>)\nSimplified chat memory advisor hierarchy and removed deprecated API (<a href=\"https://github.com/spring-projects/spring-ai/commit/848a3fd31fadd07c9ba77f6dc30425389d095e9a\">848a3fd</a>)\nRemoved deprecations in JdbcChatMemory (<a href=\"https://github.com/spring-projects/spring-ai/commit/356a68f15eea07a040bd27c66442472fc55e6475\">356a68f</a>)\nRefactored chat memory repository artifacts for clarity (<a href=\"https://github.com/spring-projects/spring-ai/commit/2d517eec5cd7ce5f88149b876ed57a06ad353e11\">2d517ee</a>)\nRefactored chat memory repository autoconfigurations and Spring Boot starters for clarity (<a href=\"https://github.com/spring-projects/spring-ai/commit/f6dba1bf083d847cdc07888ba62746683e3d61bb\">f6dba1b</a>)\n\n\nClient APIs\n\nRemoved deprecations in ChatClient and Advisors (<a href=\"https://github.com/spring-projects/spring-ai/commit/4fe74d886e26d52abf6f2f5545264d422a0be4b2\">4fe74d8</a>)\nBreaking changes to chatclient tool calling (<a href=\"https://github.com/spring-projects/spring-ai/commit/5b7849de088b3c93c7ec894fcaddc85a611a8572\">5b7849d</a>)\nRemoved deprecations from OllamaApi and AnthropicApi (<a href=\"https://github.com/spring-projects/spring-ai/commit/46be8987d6bc385bf74b9296aa4308c7a8658d2f\">46be898</a>)\n\n\nMessage and Template APIs\n\nRemoved deprecated UserMessage constructors (<a href=\"https://github.com/spring-projects/spring-ai/commit/06edee406978d172a1f87f4c7b255282f9d55e4c\">06edee4</a>)\nRemoved deprecated PromptTemplate constructors (<a href=\"https://github.com/spring-projects/spring-ai/commit/722c77e812f3f3ea40cf2258056fcf1578b15c62\">722c77e</a>)\nRemoved deprecated methods from Media (<a href=\"https://github.com/spring-projects/spring-ai/commit/228ef10bfbfe279d7d09f2a7ba166db873372118\">228ef10</a>)\nRefactored StTemplateRenderer: renamed supportStFunctions to validateStFunctions (<a href=\"https://github.com/spring-projects/spring-ai/commit/0e15197298c0848b78a746f3d740191e6a6aee7a\">0e15197</a>)\nRemoved left over TemplateRender interface after moving it (<a href=\"https://github.com/spring-projects/spring-ai/commit/52675d854ccecbc702cec24c4f070520eca64938\">52675d8</a>)\n\n\nModel Implementations\n\nRemoved Watson text generation model (<a href=\"https://github.com/spring-projects/spring-ai/commit/9e71b163e315199fe7b46495d87a0828a807b88f\">9e71b16</a>)\nRemoved Qianfan code (<a href=\"https://github.com/spring-projects/spring-ai/commit/bfcaad7b5495c5927a62b44169e8713e044c2497\">bfcaad7</a>)\nRemoved HanaDB vector store autoconfiguration (<a href=\"https://github.com/spring-projects/spring-ai/commit/f3b46244942c5072c2e2fa89e62cde71c61bbf25\">f3b4624</a>)\nRemoved deepseek options from OpenAiApi (<a href=\"https://github.com/spring-projects/spring-ai/commit/59b36d14dab72d76f2f3d49ce9385a69faaabbba\">59b36d1</a>)\n\n\nPackage Structure Changes',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M8::Removed Implementations and APIs::0'),
('362a7532-7ff6-4485-8b4a-78543861a1b7','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/cohere/api/CohereEmbeddingBedrockApi.java\">CohereEmbeddingBedrockApi</a> provides is lightweight Java client on top of AWS Bedrock <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/model-parameters-cohere-command.html\">Cohere Command models</a>.\n\nFollowing class diagram illustrates the CohereEmbeddingBedrockApi interface and building blocks:\n\nThe CohereEmbeddingBedrockApi supports the <code>cohere.embed-english-v3</code> and <code>cohere.embed-multilingual-v3</code> models for single and batch embedding computation.\n\nHere is a simple snippet how to use the api programmatically:\n\nCohereEmbeddingBedrockApi api = new CohereEmbeddingBedrockApi(\n		CohereEmbeddingModel.COHERE_EMBED_MULTILINGUAL_V1.id(),\n		EnvironmentVariableCredentialsProvider.create(),\n		Region.US_EAST_1.id(), new ObjectMapper());\n\nCohereEmbeddingRequest request = new CohereEmbeddingRequest(\n		List.of(\"I like to eat apples\", \"I like to eat oranges\"),\n		CohereEmbeddingRequest.InputType.search_document,\n		CohereEmbeddingRequest.Truncate.NONE);\n\nCohereEmbeddingResponse response = this.api.embedding(this.request);',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Low-level CohereEmbeddingBedrockApi Client::0'),
('c08387a5-c58c-48dc-8b5e-789c2cf4dc53','<div class=\"paragraph\">\n<p>This section walks you through setting up MongoDB Atlas as a vector store to use with Spring AI.</p>\n</div>',0x00,'asciidoc::mongodb.adoc::0'),
('8cb8e251-ef6f-4418-86b4-791206147046','docker run --rm --name oracle23ai -p 1521:1521 -e APP_USER=mlops -e APP_USER_PASSWORD=mlops -e ORACLE_PASSWORD=mlops gvenzl/oracle-free:23-slim\n\nYou can then connect to the database using:\n\nsql mlops/mlops@localhost/freepdb1',0x00,'asciidoc::oracle.adoc::Run Oracle Database 23ai locally::0'),
('e27a479a-c5df-4d32-b2f7-794c5bc0091d','The Spring AI Bill of Materials (BOM) declares the recommended versions of all the dependencies used by a given release of Spring AI.\nThis is a BOM-only version and it just contains dependency management and no plugin declarations or direct references to Spring or Spring Boot.\nYou can use the Spring Boot parent POM, or use the BOM from Spring Boot (<code>spring-boot-dependencies</code>) to manage Spring Boot versions.\n\nAdd the BOM to your project:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependencyManagement&gt;\n    &lt;dependencies&gt;\n        &lt;dependency&gt;\n            &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n            &lt;artifactId&gt;spring-ai-bom&lt;/artifactId&gt;\n            &lt;version&gt;1.0.0&lt;/version&gt;\n            &lt;type&gt;pom&lt;/type&gt;\n            &lt;scope&gt;import&lt;/scope&gt;\n        &lt;/dependency&gt;\n    &lt;/dependencies&gt;\n&lt;/dependencyManagement&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n  implementation platform(\"org.springframework.ai:spring-ai-bom:1.0.0\")\n  // Replace the following with the specific module dependencies (e.g., spring-ai-openai) or starter modules (e.g., spring-ai-starter-model-openai) that you wish to use\n  implementation \'org.springframework.ai:spring-ai-openai\'\n}</code></pre>\n</div>\n</div>\n<div class=\"paragraph\">\n<p>Gradle users can also use the Spring AI BOM by leveraging Gradle (5.0+) native support for declaring dependency constraints using a Maven BOM. This is implemented by adding a \'platform\' dependency handler method to the dependencies section of your Gradle build script.</p>\n</div>\n</dd>\n</dl>\n</div>',0x00,'asciidoc::getting-started.adoc::Dependency Management::0'),
('e524e5c8-ef9d-4306-85bb-7994d7dbd0f9','This will create a <code>EmbeddingModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the <code>EmbeddingModel</code> implementation.\n\nspring.ai.postgresml.embedding.options.transformer=distilbert-base-uncased\nspring.ai.postgresml.embedding.options.vectorType=PG_ARRAY\nspring.ai.postgresml.embedding.options.metadataMode=EMBED\nspring.ai.postgresml.embedding.options.kwargs.device=cpu\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::postgresml-embeddings.adoc::Sample Controller::0'),
('9a1dc933-b480-4be0-983f-79bebc5b88a3','Observability\n\nRefactored content observation to use logging instead of tracing (<a href=\"https://github.com/spring-projects/spring-ai/commit/ca843e85887aa1da6300c77550c379c103500897\">ca843e8</a>)\n\n\nAzure OpenAI\n\nAdded Entra ID identity management for Azure OpenAI with clean autoconfiguration (<a href=\"https://github.com/spring-projects/spring-ai/commit/3dc86d33ce90ebd68ec3997a0eb4704ab7774e99\">3dc86d3</a>)',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M8::Behavior Changes::0'),
('f84f4d42-a5d4-4ba8-8395-79cc482140c3','The naming pattern for Spring AI starter artifacts has changed.\nYou&#8217;ll need to update your dependencies according to the following patterns:\n\nModel starters: <code>spring-ai-{model}-spring-boot-starter</code> → <code>spring-ai-starter-model-{model}</code>\nVector Store starters: <code>spring-ai-{store}-store-spring-boot-starter</code> → <code>spring-ai-starter-vector-store-{store}</code>\nMCP starters: <code>spring-ai-mcp-{type}-spring-boot-starter</code> → <code>spring-ai-starter-mcp-{type}</code>\n\n\nExamples\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;!-- BEFORE --&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-openai-spring-boot-starter&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\n&lt;!-- AFTER --&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">// BEFORE\nimplementation \'org.springframework.ai:spring-ai-openai-spring-boot-starter\'\nimplementation \'org.springframework.ai:spring-ai-redis-store-spring-boot-starter\'\n\n// AFTER\nimplementation \'org.springframework.ai:spring-ai-starter-model-openai\'\nimplementation \'org.springframework.ai:spring-ai-starter-vector-store-redis\'</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nChanges to Spring AI Autoconfiguration Artifacts\n\nThe Spring AI autoconfiguration has changed from a single monolithic artifact to individual autoconfiguration artifacts per model, vector store, and other components.\nThis change was made to minimize the impact of different versions of dependent libraries conflicting, such as Google Protocol Buffers, Google RPC, and others.\nBy separating autoconfiguration into component-specific artifacts, you can avoid pulling in unnecessary dependencies and reduce the risk of version conflicts in your application.\n\nThe original monolithic artifact is no longer available:\n\n&lt;!-- NO LONGER AVAILABLE --&gt;\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-spring-boot-autoconfigure&lt;/artifactId&gt;\n    &lt;version&gt;${project.version}&lt;/version&gt;\n&lt;/dependency&gt;\n\nInstead, each component now has its own autoconfiguration artifact following these patterns:\n\nModel autoconfiguration: <code>spring-ai-autoconfigure-model-{model}</code>\nVector Store autoconfiguration: <code>spring-ai-autoconfigure-vector-store-{store}</code>\nMCP autoconfiguration: <code>spring-ai-autoconfigure-mcp-{type}</code>\n\n\nExamples of New Autoconfiguration Artifacts',0x00,'asciidoc::upgrade-notes.adoc::Common Changes Across Versions::Artifact ID Changes::0'),
('8bcfcda6-0b81-411d-b471-7a07716c0091','Microsoft Foundry is automatically detected when using a Microsoft Foundry URL. You can configure it using properties:\n\nspring.ai.openai-sdk.base-url=https://&lt;your-deployment-url&gt;.openai.azure.com\nspring.ai.openai-sdk.api-key=&lt;your-api-key&gt;\nspring.ai.openai-sdk.microsoft-deployment-name=&lt;your-deployment-name&gt;\n\nOr using environment variables:\n\nexport OPENAI_BASE_URL=https://&lt;your-deployment-url&gt;.openai.azure.com\nexport OPENAI_API_KEY=&lt;your-api-key&gt;\n\n<strong>Passwordless Authentication (Recommended for Azure):</strong>\n\nMicrosoft Foundry supports passwordless authentication without providing an API key, which is more secure when running on Azure.\n\nTo enable passwordless authentication, add the <code>com.azure:azure-identity</code> dependency:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;com.azure&lt;/groupId&gt;\n    &lt;artifactId&gt;azure-identity&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nThen configure without an API key:\n\nspring.ai.openai-sdk.base-url=https://&lt;your-deployment-url&gt;.openai.azure.com\nspring.ai.openai-sdk.microsoft-deployment-name=&lt;your-deployment-name&gt;\n# No api-key needed - will use Azure credentials from environment',0x00,'asciidoc::openai-sdk-embeddings.adoc::Authentication::Using Microsoft Foundry::0'),
('c07557ff-a51f-4a5d-8b4e-7a0f2590a1e2','<div class=\"paragraph\">\n<p><em>Tool calling</em> (also known as <em>function calling</em>) is a common pattern in AI applications allowing a model to interact with a set of APIs, or <em>tools</em>, augmenting its capabilities.</p>\n</div>\n<div class=\"paragraph\">\n<p>Tools are mainly used for:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p><strong>Information Retrieval</strong>. Tools in this category can be used to retrieve information from external sources, such as a database, a web service, a file system, or a web search engine. The goal is to augment the knowledge of the model, allowing it to answer questions that it would not be able to answer otherwise. As such, they can be used in Retrieval Augmented Generation (RAG) scenarios. For example, a tool can be used to retrieve the current weather for a given location, to retrieve the latest news articles, or to query a database for a specific record.</p>\n</li>\n<li>\n<p><strong>Taking Action</strong>. Tools in this category can be used to take action in a software system, such as sending an email, creating a new record in a database, submitting a form, or triggering a workflow. The goal is to automate tasks that would otherwise require human intervention or explicit programming. For example, a tool can be used to book a flight for a customer interacting with a chatbot, to fill out a form on a web page, or to implement a Java class based on an automated test (TDD) in a code generation scenario.</p>\n</li>\n</ul>\n</div>\n<div class=\"paragraph\">\n<p>Even though we typically refer to <em>tool calling</em> as a model capability, it is actually up to the client application to provide the tool calling logic. The model can only request a tool call and provide the input arguments, whereas the application is responsible for executing the tool call from the input arguments and returning the result. The model never gets access to any of the APIs provided as tools, which is a critical security consideration.</p>\n</div>\n<div class=\"paragraph\">\n<p>Spring AI provides convenient APIs to define tools, resolve tool call requests from a model, and execute the tool calls. The following sections provide an overview of the tool calling capabilities in Spring AI.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nCheck the <a href=\"api/chat/comparison.html\">Chat Model Comparisons</a> to see which AI models support tool calling invocation.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"admonitionblock tip\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Tip</div>\n</td>\n<td class=\"content\">\nFollow the guide to migrate from the deprecated <a href=\"api/tools-migration.html\">FunctionCallback to ToolCallback API</a>.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::tools.adoc::0'),
('0f2ccbb7-3e50-4bdc-a5f1-7a506ecdc876','Similarity scores are calculated using the formula <code>score = 1.0 - distance</code>, where:\n\nScore: A value between <code>0.0</code> and <code>1.0</code>, where <code>1.0</code> indicates perfect similarity and <code>0.0</code> indicates no similarity\nDistance: The raw distance value calculated using the configured distance type (<code>COSINE</code> or <code>EUCLIDEAN</code>)\n\n\nThis means that documents with smaller distances (more similar) will have higher scores, making the results more intuitive to interpret.',0x00,'asciidoc::mariadb.adoc::Similarity Scores::Score Calculation::0'),
('480e3ad3-3311-4429-883d-7aa5defc7536','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/main/java/org/springframework/ai/mistralai/api/MistralAiApi.java\">MistralAiApi</a> provides is lightweight Java client for <a href=\"https://docs.mistral.ai/api/\">Mistral AI API</a>.\n\nHere is a simple snippet showing how to use the API programmatically:\n\nMistralAiApi mistralAiApi = new MistralAiApi(System.getenv(\"MISTRAL_AI_API_KEY\"));\n\nChatCompletionMessage chatCompletionMessage =\n    new ChatCompletionMessage(\"Hello world\", Role.USER);\n\n// Sync request\nResponseEntity&lt;ChatCompletion&gt; response = this.mistralAiApi.chatCompletionEntity(\n    new ChatCompletionRequest(List.of(this.chatCompletionMessage), MistralAiApi.ChatModel.LARGE.getValue(), 0.8, false));\n\n// Streaming request\nFlux&lt;ChatCompletionChunk&gt; streamResponse = this.mistralAiApi.chatCompletionStream(\n        new ChatCompletionRequest(List.of(this.chatCompletionMessage), MistralAiApi.ChatModel.LARGE.getValue(), 0.8, true));\n\nFollow the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/main/java/org/springframework/ai/mistralai/api/MistralAiApi.java\">MistralAiApi.java</a>\'s JavaDoc for further information.\n\nMistralAiApi Samples\n\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/test/java/org/springframework/ai/mistralai/api/MistralAiApiIT.java\">MistralAiApiIT.java</a> tests provide some general examples of how to use the lightweight library.\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/test/java/org/springframework/ai/mistralai/api/tool/PaymentStatusFunctionCallingIT.java\">PaymentStatusFunctionCallingIT.java</a> tests show how to use the low-level API to call tool functions.\nBased on the <a href=\"https://docs.mistral.ai/guides/function-calling/\">Mistral AI Function Calling</a> tutorial.',0x00,'asciidoc::mistralai-chat.adoc::Manual Configuration::Low-level MistralAiApi Client::0'),
('457e890e-999b-4fb8-a6fb-7ac9bc101c26','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the MongoDB Atlas Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-mongodb-atlas&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file:\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-mongodb-atlas\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nThe vector store implementation can initialize the requisite schema for you, but you must opt-in by setting <code>spring.ai.vectorstore.mongodb.initialize-schema=true</code> in the <code>application.properties</code> file.\nAlternatively you can opt-out the initialization and create the index manually using the MongoDB Atlas UI, Atlas Administration API, or Atlas CLI, which can be useful if the index needs advanced mapping or additional configuration.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nPlease have a look at the list of <a href=\"#mongodbvector-properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nNow you can auto-wire the <code>MongoDBAtlasVectorStore</code> as a vector store in your application:\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList&lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to MongoDB Atlas\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::mongodb.adoc::Auto-configuration::0'),
('71611456-1468-4f9c-8988-7ad147d7bc1b','This functionality has been moved to the Spring AI Community repository.\n\nPlease visit <a href=\"https://github.com/spring-ai-community/qianfan\" class=\"bare\">https://github.com/spring-ai-community/qianfan</a> for the latest version.',0x00,'asciidoc::qianfan-embeddings.adoc::0'),
('68f30740-95df-4732-b9fb-7ae18daea1da','GitHub Models is automatically detected when using the GitHub Models base URL. You&#8217;ll need to create a GitHub Personal Access Token (PAT) with the <code>models:read</code> scope.\n\nspring.ai.openai-sdk.base-url=https://models.inference.ai.azure.com\nspring.ai.openai-sdk.api-key=github_pat_XXXXXXXXXXX\n\nOr using environment variables:\n\nexport OPENAI_BASE_URL=https://models.inference.ai.azure.com\nexport OPENAI_API_KEY=github_pat_XXXXXXXXXXX\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) in your properties:\n\nspring.ai.openai-sdk.api-key=${OPENAI_API_KEY}',0x00,'asciidoc::openai-sdk-chat.adoc::Authentication::Using GitHub Models::0'),
('74b4ad2e-a5c7-4112-96c4-7b1b3709c04e','If you are using OpenAI directly, create an account at <a href=\"https://platform.openai.com/signup\">OpenAI signup page</a> and generate an API key on the <a href=\"https://platform.openai.com/account/api-keys\">API Keys page</a>.\n\nThe base URL doesn&#8217;t need to be set as it defaults to <code><a href=\"https://api.openai.com/v1\" class=\"bare\">https://api.openai.com/v1</a></code>:\n\nspring.ai.openai-sdk.api-key=&lt;your-openai-api-key&gt;\n# base-url is optional, defaults to https://api.openai.com/v1\n\nOr using environment variables:\n\nexport OPENAI_API_KEY=&lt;your-openai-api-key&gt;\n# OPENAI_BASE_URL is optional, defaults to https://api.openai.com/v1',0x00,'asciidoc::openai-sdk-embeddings.adoc::Authentication::Using OpenAI::0'),
('ec783976-11f0-42b6-ac41-7b1f2006f27e','<code>MongoChatMemoryRepository</code> is a built-in implementation that uses MongoDB to store messages. It is suitable for applications that require a flexible, document-oriented database for chat memory persistence.\n\nFirst, add the following dependency to your project:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-chat-memory-repository-mongodb&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-chat-memory-repository-mongodb\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nSpring AI provides auto-configuration for the <code>MongoChatMemoryRepository</code>, which you can use directly in your application.\n\n@Autowired\nMongoChatMemoryRepository chatMemoryRepository;\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nIf you&#8217;d rather create the <code>MongoChatMemoryRepository</code> manually, you can do so by providing a <code>MongoTemplate</code> instance:\n\nChatMemoryRepository chatMemoryRepository = MongoChatMemoryRepository.builder()\n    .mongoTemplate(mongoTemplate)\n    .build();\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nConfiguration Properties\n\n\n\nCollection Initialization\n\nThe auto-configuration will automatically create the <code>ai_chat_memory</code> collection on startup if it does not already exist.',0x00,'asciidoc::chat-memory.adoc::Memory Storage::MongoChatMemoryRepository::0'),
('1109fef4-3d81-4ce3-9f75-7b36571f1160','ToolCallingManager toolCallingManager = DefaultToolCallingManager.builder().build();\nChatMemory chatMemory = MessageWindowChatMemory.builder().build();\nString conversationId = UUID.randomUUID().toString();\n\nChatOptions chatOptions = ToolCallingChatOptions.builder()\n    .toolCallbacks(ToolCallbacks.from(new MathTools()))\n    .internalToolExecutionEnabled(false)\n    .build();\nPrompt prompt = new Prompt(\n        List.of(new SystemMessage(\"You are a helpful assistant.\"), new UserMessage(\"What is 6 * 8?\")),\n        chatOptions);\nchatMemory.add(conversationId, prompt.getInstructions());\n\nPrompt promptWithMemory = new Prompt(chatMemory.get(conversationId), chatOptions);\nChatResponse chatResponse = chatModel.call(promptWithMemory);\nchatMemory.add(conversationId, chatResponse.getResult().getOutput());\n\nwhile (chatResponse.hasToolCalls()) {\n    ToolExecutionResult toolExecutionResult = toolCallingManager.executeToolCalls(promptWithMemory,\n            chatResponse);\n    chatMemory.add(conversationId, toolExecutionResult.conversationHistory()\n        .get(toolExecutionResult.conversationHistory().size() - 1));\n    promptWithMemory = new Prompt(chatMemory.get(conversationId), chatOptions);\n    chatResponse = chatModel.call(promptWithMemory);\n    chatMemory.add(conversationId, chatResponse.getResult().getOutput());\n}\n\nUserMessage newUserMessage = new UserMessage(\"What did I ask you earlier?\");\nchatMemory.add(conversationId, newUserMessage);\n\nChatResponse newResponse = chatModel.call(new Prompt(chatMemory.get(conversationId)));',0x00,'asciidoc::tools.adoc::Tool Execution::User-Controlled Tool Execution::1'),
('87e9088f-dfff-498b-8c83-7b9709c8de6e','<div class=\"paragraph\">\n<p>This section walks you through setting up <code>Neo4jVectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://neo4j.com\">Neo4j</a> is an open-source NoSQL graph database.\nIt is a fully transactional database (ACID) that stores data structured as graphs consisting of nodes, connected by relationships.\nInspired by the structure of the real world, it allows for high query performance on complex data while remaining intuitive and simple for the developer.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://neo4j.com/docs/cypher-manual/current/indexes-for-vector-search/\">Neo4j&#8217;s Vector Search</a> allows users to query vector embeddings from large datasets.\nAn embedding is a numerical representation of a data object, such as text, image, audio, or document.\nEmbeddings can be stored on <em>Node</em> properties and can be queried with the <code>db.index.vector.queryNodes()</code> function.\nThose indexes are powered by Lucene using a Hierarchical Navigable Small World Graph (HNSW) to perform a k approximate nearest neighbors (k-ANN) query over the vector fields.</p>\n</div>',0x00,'asciidoc::neo4j.adoc::0'),
('864cc6df-4215-4da8-9727-7bbbcdb6f4c2','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-ollama</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.yaml</code> file, under the <code>src/main/resources</code> directory, to enable and configure the Ollama chat model:\n\nspring:\n  ai:\n    ollama:\n      base-url: http://localhost:11434\n      chat:\n        options:\n          model: mistral\n          temperature: 0.7\n\nReplace the <code>base-url</code> with your Ollama server URL.\n\nThis will create an <code>OllamaChatModel</code> implementation that you can inject into your classes.\nHere is an example of a simple <code>@RestController</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final OllamaChatModel chatModel;\n\n    @Autowired\n    public ChatController(OllamaChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map&lt;String,String&gt; generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n\n}',0x00,'asciidoc::ollama-chat.adoc::Sample Controller::0'),
('aa4452f7-ffe1-4de7-a275-7bcda64174ce','The <code>Message</code> interface encapsulates a <code>Prompt</code> textual content, a collection of metadata attributes, and a categorization known as <code>MessageType</code>.\n\nThe interface is defined as follows:\n\npublic interface Content {\n\n	String getContent();\n\n	Map&lt;String, Object&gt; getMetadata();\n}\n\npublic interface Message extends Content {\n\n	MessageType getMessageType();\n}\n\nThe multimodal message types implement also the <code>MediaContent</code> interface providing a list of <code>Media</code> content objects.\n\npublic interface MediaContent extends Content {\n\n	Collection&lt;Media&gt; getMedia();\n\n}\n\nVarious implementations of the <code>Message</code> interface correspond to different categories of messages that an AI model can process.\nThe Models distinguish between message categories based on conversational roles.\n\nThese roles are effectively mapped by the <code>MessageType</code>, as discussed below.\n\nRoles\n\nEach message is assigned a specific role.\nThese roles categorize the messages, clarifying the context and purpose of each segment of the prompt for the AI model.\nThis structured approach enhances the nuance and effectiveness of communication with the AI, as each part of the prompt plays a distinct and defined role in the interaction.\n\nThe primary roles are:\n\nSystem Role: Guides the AI&#8217;s behavior and response style, setting parameters or rules for how the AI interprets and replies to the input. It&#8217;s akin to providing instructions to the AI before initiating a conversation.\nUser Role: Represents the user&#8217;s input – their questions, commands, or statements to the AI. This role is fundamental as it forms the basis of the AI&#8217;s response.\nAssistant Role: The AI&#8217;s response to the user&#8217;s input.\nMore than just an answer or reaction, it&#8217;s crucial for maintaining the flow of the conversation.\nBy tracking the AI&#8217;s previous responses (its \'Assistant Role\' messages), the system ensures coherent and contextually relevant interactions.\nThe Assistant message may contain Function Tool Call request information as well.\nIt&#8217;s like a special feature in the AI, used when needed to perform specific functions such as calculations, fetching data, or other tasks beyond just talking.\nTool/Function Role: The Tool/Function Role focuses on returning additional information in response to Tool Call Assistant Messages.\n\n\nRoles are represented as an enumeration in Spring AI as shown below\n\npublic enum MessageType {\n\n	USER(\"user\"),\n\n	ASSISTANT(\"assistant\"),\n\n	SYSTEM(\"system\"),\n\n	TOOL(\"tool\");\n\n    ...\n}',0x00,'asciidoc::prompt.adoc::API Overview::Message::0'),
('07a74c77-ff9a-4ef6-93f0-7c1e2c225288','<a href=\"api/vectordbs/azure.html\">Azure Vector Search</a> - The <a href=\"https://learn.microsoft.com/en-us/azure/search/vector-search-overview\">Azure</a> vector store.\n<a href=\"api/vectordbs/apache-cassandra.html\">Apache Cassandra</a> - The <a href=\"https://cassandra.apache.org/doc/latest/cassandra/vector-search/overview.html\">Apache Cassandra</a> vector store.\n<a href=\"api/vectordbs/chroma.html\">Chroma Vector Store</a> - The <a href=\"https://www.trychroma.com/\">Chroma</a> vector store.\n<a href=\"api/vectordbs/elasticsearch.html\">Elasticsearch Vector Store</a> - The <a href=\"https://www.elastic.co/\">Elasticsearch</a> vector store.\n<a href=\"api/vectordbs/gemfire.html\">GemFire Vector Store</a> - The <a href=\"https://tanzu.vmware.com/content/blog/vmware-gemfire-vector-database-extension\">GemFire</a> vector store.\n<a href=\"api/vectordbs/mariadb.html\">MariaDB Vector Store</a> - The <a href=\"https://mariadb.com/\">MariaDB</a> vector store.\n<a href=\"api/vectordbs/milvus.html\">Milvus Vector Store</a> - The <a href=\"https://milvus.io/\">Milvus</a> vector store.\n<a href=\"api/vectordbs/mongodb.html\">MongoDB Atlas Vector Store</a> - The <a href=\"https://www.mongodb.com/atlas/database\">MongoDB Atlas</a> vector store.\n<a href=\"api/vectordbs/neo4j.html\">Neo4j Vector Store</a> - The <a href=\"https://neo4j.com/\">Neo4j</a> vector store.\n<a href=\"api/vectordbs/opensearch.html\">OpenSearch Vector Store</a> - The <a href=\"https://opensearch.org/platform/search/vector-database.html\">OpenSearch</a> vector store.\n<a href=\"api/vectordbs/oracle.html\">Oracle Vector Store</a> - The <a href=\"https://docs.oracle.com/en/database/oracle/oracle-database/23/vecse/overview-ai-vector-search.html\">Oracle Database</a> vector store.\n<a href=\"api/vectordbs/pgvector.html\">PgVector Store</a> - The <a href=\"https://github.com/pgvector/pgvector\">PostgreSQL/PGVector</a> vector store.\n<a href=\"api/vectordbs/pinecone.html\">Pinecone Vector Store</a> - <a href=\"https://www.pinecone.io/\">Pinecone</a> vector store.\n<a href=\"api/vectordbs/qdrant.html\">Qdrant Vector Store</a> - <a href=\"https://www.qdrant.tech/\">Qdrant</a> vector store.\n<a href=\"api/vectordbs/redis.html\">Redis Vector Store</a> - The <a href=\"https://redis.io/\">Redis</a> vector store.\n<a href=\"api/vectordbs/hana.html\">SAP Hana Vector Store</a> - The <a href=\"https://news.sap.com/2024/04/sap-hana-cloud-vector-engine-ai-with-business-context/\">SAP HANA</a> vector store.\n<a href=\"api/vectordbs/typesense.html\">Typesense Vector Store</a> - The <a href=\"https://typesense.org/docs/0.24.0/api/vector-search.html\">Typesense</a> vector store.\n<a href=\"api/vectordbs/weaviate.html\">Weaviate Vector Store</a> - The <a href=\"https://weaviate.io/\">Weaviate</a> vector store.\n<a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-vector-store/src/main/java/org/springframework/ai/vectorstore/SimpleVectorStore.java\">SimpleVectorStore</a> - A simple implementation of persistent vector storage, good for educational purposes.',0x00,'asciidoc::vectordbs.adoc::VectorStore Implementations::1'),
('4fb1815b-ff95-4f42-ab8b-7d61e7c0248c','spring.ai.google.genai.embedding.api-key=YOUR_API_KEY\nspring.ai.google.genai.embedding.text.options.model=text-embedding-004',0x00,'asciidoc::google-genai-embeddings-text.adoc::Sample Controller::Using Gemini Developer API (API Key)::0'),
('95da7cf5-dcfa-4eb4-a8c6-7d64e067b72c','@SuppressWarnings(\"CheckReturnValue\")\npublic static class NotExpressionContext extends BooleanExpressionContext {\n\n    public TerminalNode NOT() {\n        return getToken(FiltersParser.NOT, 0);\n    }\n\n    public BooleanExpressionContext booleanExpression() {\n        return getRuleContext(BooleanExpressionContext.class, 0);\n    }\n\n    public NotExpressionContext(BooleanExpressionContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterNotExpression(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitNotExpression(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitNotExpression(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('2a747ebb-d91e-48b2-869f-7da8a5dde062','This feature set lets you implement common use cases, such as &#8220;Q&amp;A over your documentation&#8221; or &#8220;Chat with your documentation.&#8221;\n\nThe <a href=\"concepts.html\">concepts section</a> provides a high-level overview of AI concepts and their representation in Spring AI.\n\nThe <a href=\"getting-started.html\">Getting Started</a> section shows you how to create your first AI application.\nSubsequent sections delve into each component and common use cases with a code-focused approach.',0x00,'asciidoc::index.adoc::1'),
('6143f803-2070-4578-b4c6-7db7d278f720','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-bedrock</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the Titan Embedding model:\n\nspring.ai.bedrock.aws.region=eu-central-1\nspring.ai.bedrock.aws.access-key=${AWS_ACCESS_KEY_ID}\nspring.ai.bedrock.aws.secret-key=${AWS_SECRET_ACCESS_KEY}\n\nspring.ai.model.embedding=bedrock-titan\n\nreplace the <code>regions</code>, <code>access-key</code> and <code>secret-key</code> with your AWS credentials.\n\nThis will create a <code>EmbeddingController</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::bedrock-titan-embedding.adoc::Sample Controller::0'),
('2eb467ca-e331-4578-a756-7dc66821463c','Each of the following sections in the documentation shows which dependencies you need to add to your project build system.\n\n<a href=\"api/chatmodel.html\">Chat Models</a>\n<a href=\"api/embeddings.html\">Embeddings Models</a>\n<a href=\"api/imageclient.html\">Image Generation Models</a>\n<a href=\"api/audio/transcriptions.html\">Transcription Models</a>\n<a href=\"api/audio/speech.html\">Text-To-Speech (TTS) Models</a>\n<a href=\"api/vectordbs.html\">Vector Databases</a>',0x00,'asciidoc::getting-started.adoc::Add dependencies for specific components::0'),
('72ec582d-a218-4168-8e65-7dd4704c678c','/**\n * A component for expanding the input query into a list of queries, addressing challenges\n * such as poorly formed queries by providing alternative query formulations, or by\n * breaking down complex problems into simpler sub-queries.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic interface QueryExpander extends Function<Query, List<Query>> {\n\n    /**\n     * Expands the given query into a list of queries.\n     * @param query The original query to be expanded\n     * @return A list of expanded queries\n     */\n    List<Query> expand(Query query);\n\n    default List<Query> apply(Query query) {\n        return expand(query);\n    }\n}',0x01,'cu::QueryExpander.java'),
('7fea8235-6e97-4034-96ac-7e1c6f8628d1','Uniform interface across different LLM providers\nBuilt-in error handling and retries\nFlexible prompt management',0x00,'asciidoc::effective-agents.adoc::Spring AI&#8217;s Implementation Advantages::<a href=\"https://docs.spring.io/spring-ai/reference/api/chatclient.html\">Consistent API</a>::0'),
('2df48313-75e9-4cf8-81d5-7e4ccbaba5e8','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with Elasticsearch as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; \'article_type\' == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(b.and(\n                b.in(\"author\", \"john\", \"jill\"),\n                b.eq(\"article_type\", \"blog\")).build()).build());\n\nThose (portable) filter expressions get automatically converted into the proprietary Elasticsearch <a href=\"https://www.elastic.co/guide/en/elasticsearch/reference/current/query-dsl-query-string-query.html\">Query string query</a>.\n\nFor example, this portable filter expression:\n\nauthor in [\'john\', \'jill\'] &amp;&amp; \'article_type\' == \'blog\'\n\nis converted into the proprietary Elasticsearch filter format:\n\n(metadata.author:john OR jill) AND metadata.article_type:blog',0x00,'asciidoc::elasticsearch.adoc::Metadata Filtering::0'),
('ab94985c-c259-4df4-b8f9-7e5ee138a7a4','# Chroma Vector Store connection properties\nspring.ai.vectorstore.chroma.client.host=&lt;your Chroma instance host&gt;  // for Chroma Cloud: api.trychroma.com\nspring.ai.vectorstore.chroma.client.port=&lt;your Chroma instance port&gt; // for Chroma Cloud: 443\nspring.ai.vectorstore.chroma.client.key-token=&lt;your access token (if configure)&gt; // for Chroma Cloud: use the API key\nspring.ai.vectorstore.chroma.client.username=&lt;your username (if configure)&gt;\nspring.ai.vectorstore.chroma.client.password=&lt;your password (if configure)&gt;\n\n# Chroma Vector Store tenant and database properties (required for Chroma Cloud)\nspring.ai.vectorstore.chroma.tenant-name=&lt;your tenant name&gt; // default: SpringAiTenant\nspring.ai.vectorstore.chroma.database-name=&lt;your database name&gt; // default: SpringAiDatabase\n\n# Chroma Vector Store collection properties\nspring.ai.vectorstore.chroma.initialize-schema=&lt;true or false&gt;\nspring.ai.vectorstore.chroma.collection-name=&lt;your collection name&gt;\n\n# Chroma Vector Store configuration properties\n\n# OpenAI API key if the OpenAI auto-configuration is used.\nspring.ai.openai.api.key=&lt;OpenAI Api-key&gt;\n\nPlease have a look at the list of <a href=\"#_configuration_properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\n\nNow you can auto-wire the Chroma Vector Store in your application and use it\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList &lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::chroma.adoc::Auto-configuration::1'),
('03e8054e-28b0-442c-af21-7eaae53e2c83','Instead of using the Spring Boot auto-configuration, you can create the <code>PostgresMlEmbeddingModel</code> manually.\nFor this add the <code>spring-ai-postgresml</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-postgresml&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-postgresml\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create an <code>PostgresMlEmbeddingModel</code> instance and use it to compute the similarity between two input texts:\n\nvar jdbcTemplate = new JdbcTemplate(dataSource); // your posgresml data source\n\nPostgresMlEmbeddingModel embeddingModel = new PostgresMlEmbeddingModel(this.jdbcTemplate,\n        PostgresMlEmbeddingOptions.builder()\n            .transformer(\"distilbert-base-uncased\") // huggingface transformer model name.\n            .vectorType(VectorType.PG_VECTOR) //vector type in PostgreSQL.\n            .kwargs(Map.of(\"device\", \"cpu\")) // optional arguments.\n            .metadataMode(MetadataMode.EMBED) // Document metadata mode.\n            .build());\n\nembeddingModel.afterPropertiesSet(); // initialize the jdbc template and database.\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n	.embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));\n\nWhen created manually, you must call the <code>afterPropertiesSet()</code> after setting the properties and before using the client.\nIt is more convenient (and preferred) to create the PostgresMlEmbeddingModel as a <code>@Bean</code>.\nThen you don’t have to call the <code>afterPropertiesSet()</code> manually:\n\n@Bean\npublic EmbeddingModel embeddingModel(JdbcTemplate jdbcTemplate) {\n    return new PostgresMlEmbeddingModel(jdbcTemplate,\n        PostgresMlEmbeddingOptions.builder()\n             ....\n            .build());\n}',0x00,'asciidoc::postgresml-embeddings.adoc::Manual configuration::0'),
('47310005-3fcf-450a-9a20-7eaff179dba9','@Autowired VectorStore vectorStore;\n\n// ...\n\nList&lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to Oracle Vector Store\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::oracle.adoc::Auto-Configuration::1'),
('2aecad7f-5440-473b-9935-7ed77ca19238','Multimodality refers to a model&#8217;s ability to simultaneously understand and process information from various sources, including text, images, audio, and other data formats.\n\nSome of the models available in Ollama with multimodality support are <a href=\"https://ollama.com/library/llava\">LLaVA</a> and <a href=\"https://ollama.com/library/bakllava\">BakLLaVA</a> (see the <a href=\"https://ollama.com/search?c=vision\">full list</a>).\nFor further details, refer to the <a href=\"https://llava-vl.github.io/\">LLaVA: Large Language and Vision Assistant</a>.\n\nThe Ollama <a href=\"https://github.com/ollama/ollama/blob/main/docs/api.md#parameters-1\">Message API</a> provides an \"images\" parameter to incorporate a list of base64-encoded images with the message.\n\nSpring AI’s <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/messages/Message.java\">Message</a> interface facilitates multimodal AI models by introducing the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-commons/src/main/java/org/springframework/ai/content/Media.java\">Media</a> type.\nThis type encompasses data and details regarding media attachments in messages, utilizing Spring’s <code>org.springframework.util.MimeType</code> and a <code>org.springframework.core.io.Resource</code> for the raw media data.\n\nBelow is a straightforward code example excerpted from <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-ollama/src/test/java/org/springframework/ai/ollama/OllamaChatModelMultimodalIT.java\">OllamaChatModelMultimodalIT.java</a>, illustrating the fusion of user text with an image.\n\nvar imageResource = new ClassPathResource(\"/multimodal.test.png\");\n\nvar userMessage = new UserMessage(\"Explain what do you see on this picture?\",\n        new Media(MimeTypeUtils.IMAGE_PNG, this.imageResource));\n\nChatResponse response = chatModel.call(new Prompt(this.userMessage,\n        OllamaChatOptions.builder().model(OllamaModel.LLAVA)).build());\n\nThe example shows a model taking as an input the <code>multimodal.test.png</code> image:\n\nalong with the text message \"Explain what do you see on this picture?\", and generating a response like this:\n\nThe image shows a small metal basket filled with ripe bananas and red apples. The basket is placed on a surface,\nwhich appears to be a table or countertop, as there\'s a hint of what seems like a kitchen cabinet or drawer in\nthe background. There\'s also a gold-colored ring visible behind the basket, which could indicate that this\nphoto was taken in an area with metallic decorations or fixtures. The overall setting suggests a home environment\nwhere fruits are being displayed, possibly for convenience or aesthetic purposes.',0x00,'asciidoc::ollama-chat.adoc::Multimodal::0'),
('a5732ccb-3acd-42ec-9b72-7efbc2e533f0','Streaming Reasoning Content\n\nWhen using streaming responses, reasoning content is accumulated across chunks just like regular message content:\n\nFlux&lt;ChatResponse&gt; responseFlux = chatModel.stream(\n    new Prompt(\"Solve this logic puzzle...\")\n);\n\nStringBuilder reasoning = new StringBuilder();\nStringBuilder answer = new StringBuilder();\n\nresponseFlux.subscribe(chunk -&gt; {\n    AssistantMessage message = chunk.getResult().getOutput();\n\n    // Accumulate reasoning if present\n    String reasoningChunk = message.getMetadata().get(\"reasoningContent\");\n    if (reasoningChunk != null) {\n        reasoning.append(reasoningChunk);\n    }\n\n    // Accumulate the final answer\n    if (message.getContent() != null) {\n        answer.append(message.getContent());\n    }\n});\n\nExample: DeepSeek R1\n\nDeepSeek R1 is a reasoning model that exposes its internal reasoning process:\n\nspring.ai.openai.api-key=${DEEPSEEK_API_KEY}\nspring.ai.openai.base-url=https://api.deepseek.com\nspring.ai.openai.chat.options.model=deepseek-reasoner\n\nWhen you make requests to DeepSeek R1, responses will include both the reasoning content (the model&#8217;s thought process) and the final answer.\n\nRefer to the <a href=\"https://api-docs.deepseek.com/guides/reasoning_model\">DeepSeek API documentation</a> for more details on reasoning models.\n\nExample: vLLM with Reasoning Parser\n\nvLLM supports reasoning models when configured with a reasoning parser:\n\nvllm serve deepseek-ai/DeepSeek-R1-Distill-Qwen-1.5B \\\n    --enable-reasoning \\\n    --reasoning-parser deepseek_r1\n\nspring.ai.openai.base-url=http://localhost:8000/v1\nspring.ai.openai.chat.options.model=deepseek-ai/DeepSeek-R1-Distill-Qwen-1.5B\n\nConsult the <a href=\"https://docs.vllm.ai/en/latest/features/reasoning_outputs.html\">vLLM reasoning outputs documentation</a> for supported reasoning models and parsers.\n\n<div class=\"paragraph\">\n<p>The availability of <code>reasoning_content</code> depends entirely on the inference server you&#8217;re using.\nNot all OpenAI-compatible servers expose reasoning content, even when using reasoning-capable models.\nAlways refer to your server&#8217;s API documentation to understand what fields are available in responses.</p>\n</div>',0x00,'asciidoc::openai-chat.adoc::Using Extra Parameters with OpenAI-Compatible Servers::Reasoning Content from Reasoning Models::1'),
('2e82bd96-99a0-4e2b-9083-7f43d6f864d1','<div class=\"paragraph\">\n<p>Azure&#8217;s OpenAI extends the OpenAI capabilities, offering safe text generation and Embeddings computation models for various task:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p>Similarity embeddings are good at capturing semantic similarity between two or more pieces of text.</p>\n</li>\n<li>\n<p>Text search embeddings help measure whether long documents are relevant to a short query.</p>\n</li>\n<li>\n<p>Code search embeddings are useful for embedding code snippets and embedding natural language search queries.</p>\n</li>\n</ul>\n</div>\n<div class=\"paragraph\">\n<p>The Azure OpenAI embeddings rely on <code>cosine similarity</code> to compute similarity between documents and a query.</p>\n</div>',0x00,'asciidoc::azure-openai-embeddings.adoc::0'),
('3cfbf334-1a35-46e1-abe9-7f43f84e61a2','The prefix <code>spring.ai.bedrock.aws</code> is the property prefix to configure the connection to AWS Bedrock.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=bedrock-titan (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match bedrock-titan)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.bedrock.titan.embedding</code> (defined in <code>BedrockTitanEmbeddingProperties</code>) is the property prefix that configures the embedding model implementation for Titan.\n\n\n\nSupported values are: <code>amazon.titan-embed-image-v1</code>, <code>amazon.titan-embed-text-v1</code> and <code>amazon.titan-embed-text-v2:0</code>.\nModel ID values can also be found in the <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/model-ids-arns.html\">AWS Bedrock documentation for base model IDs</a>.',0x00,'asciidoc::bedrock-titan-embedding.adoc::Auto-configuration::Embedding Properties::0'),
('37a5cd9c-aaa7-42c5-98b4-7f5611bc7340','<div class=\"paragraph\">\n<p>Spring AI supports OpenAI&#8217;s language models through the OpenAI Java SDK, providing a robust and officially-maintained integration with OpenAI&#8217;s services including Microsoft Foundry and GitHub Models.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nThis implementation uses the official <a href=\"https://github.com/openai/openai-java\">OpenAI Java SDK</a> from OpenAI. For the alternative Spring AI implementation, see <a href=\"api/chat/openai-chat.html\">OpenAI Chat</a>.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"paragraph\">\n<p>The OpenAI SDK module automatically detects the service provider (OpenAI, Microsoft Foundry, or GitHub Models) based on the base URL you provide.</p>\n</div>',0x00,'asciidoc::openai-sdk-chat.adoc::0'),
('44f95577-74de-400f-8b03-7f5cc32d2f1f','To compute the embeddings for a vector database, you need to pick an embedding model that matches the higher-level AI model being used.\n\nFor example, with OpenAI&#8217;s ChatGPT, we use the <code>OpenAiEmbeddingModel</code> and a model named <code>text-embedding-ada-002</code>.\n\nThe Spring Boot starter&#8217;s auto-configuration for OpenAI makes an implementation of <code>EmbeddingModel</code> available in the Spring application context for dependency injection.',0x00,'asciidoc::vectordbs.adoc::Example Usage::0'),
('04097702-e542-42c6-b219-7f7effd9df88','Multi-Tenant SaaS Application\n\nCache shared tool definitions across different tenants while customizing system prompts per tenant:\n\n// Shared tool definitions (cached once, used across all tenants)\nList&lt;FunctionToolCallback&gt; sharedTools = createLargeToolRegistry(); // ~2000 tokens\n\n// Tenant-specific configuration\n@Service\npublic class MultiTenantAIService {\n\n    public String processRequest(String tenantId, String userQuery) {\n        // Load tenant-specific system prompt (changes per tenant)\n        String tenantPrompt = loadTenantSystemPrompt(tenantId);\n\n        ChatResponse response = chatModel.call(\n            new Prompt(\n                List.of(\n                    new SystemMessage(tenantPrompt), // Tenant-specific, not cached\n                    new UserMessage(userQuery)\n                ),\n                BedrockChatOptions.builder()\n                    .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n                    .cacheOptions(BedrockCacheOptions.builder()\n                        .strategy(BedrockCacheStrategy.TOOLS_ONLY)\n                        .build())\n                    .toolCallbacks(sharedTools) // Shared tools - cached\n                    .maxTokens(500)\n                    .build()\n            )\n        );\n\n        return response.getResult().getOutput().getText();\n    }\n}\n\n// Tools cached once, each tenant gets customized system prompt',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Real-World Use Cases::2'),
('f85e869c-9177-45d0-b604-7f870526995d','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OCI GenAI Embedding Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-oci-genai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-oci-genai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::oci-genai-embeddings.adoc::Auto-configuration::0'),
('4620c55f-da96-4922-9bdc-7f872a9b3210','<a href=\"https://cloud.google.com/vertex-ai/docs/reference\">VertexAI API</a> provides high-quality custom machine learning models with minimal machine learning expertise and effort.\n\nSpring AI provides integration with VertexAI API through the following client(s):\n\n<a href=\"api/chat/vertexai-gemini-chat.html\">api/chat/vertexai-gemini-chat.html</a>',0x00,'asciidoc::google-vertexai.adoc::0'),
('b917de0e-ea00-4a95-ba10-7fb0940ea246','The Spring AI Chat Model API is built on top of the Spring AI <code>Generic Model API</code> providing Chat specific abstractions and implementations.\nThis allows an easy integration and switching between different AI services while maintaining a consistent API for the client application.\nThe following class diagram illustrates the main classes and interfaces of the Spring AI Chat Model API.',0x00,'asciidoc::chatmodel.adoc::Chat Model API::0'),
('335d61db-9cad-4328-af81-7fccb36e7a61','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::azure-openai-embeddings.adoc::Prerequisites::Add Repositories and BOM::0'),
('216abb0f-f044-4c97-9480-80492f223472','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::openai-sdk-embeddings.adoc::Authentication::Add Repositories and BOM::0'),
('2bf34c1f-3b15-4f8b-8305-8056b5659377','Anthropic Claude models support a \"thinking\" feature that allows the model to show its reasoning process before providing a final answer. This feature enables more transparent and detailed problem-solving, particularly for complex questions that require step-by-step reasoning.\n\n<div class=\"paragraph\">\n<p><strong>Supported Models</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>The thinking feature is supported by the following Claude models:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p>Claude 4 models (<code>claude-opus-4-20250514</code>, <code>claude-sonnet-4-20250514</code>)</p>\n</li>\n<li>\n<p>Claude 3.7 Sonnet (<code>claude-3-7-sonnet-20250219</code>)</p>\n</li>\n</ul>\n</div>\n<div class=\"paragraph\">\n<p><strong>Model capabilities:</strong></p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p><strong>Claude 3.7 Sonnet</strong>: Returns full thinking output. Behavior is consistent but does not support summarized or interleaved thinking.</p>\n</li>\n<li>\n<p><strong>Claude 4 models</strong>: Support summarized thinking, interleaved thinking, and enhanced tool integration.</p>\n</li>\n</ul>\n</div>\n<div class=\"paragraph\">\n<p>API request structure is the same across all supported models, but output behavior varies.</p>\n</div>',0x00,'asciidoc::anthropic-chat.adoc::Thinking::0'),
('5e93ef58-6031-4594-a641-8069f9eefc91','When using Ollama through the OpenAI-compatible endpoint, you can pass Ollama-specific parameters:\n\nOpenAiChatOptions options = OpenAiChatOptions.builder()\n    .model(\"llama3.2\")\n    .extraBody(Map.of(\n        \"num_predict\", 100,\n        \"top_k\", 40,\n        \"repeat_penalty\", 1.1\n    ))\n    .build();\n\nChatResponse response = chatModel.call(new Prompt(\"Generate text\", options));\n\nConsult the <a href=\"https://github.com/ollama/ollama/blob/main/docs/api.md\">Ollama API documentation</a> for available parameters.\n\n<div class=\"paragraph\">\n<p>The <code>extraBody</code> parameter accepts any <code>Map&lt;String, Object&gt;</code>, allowing you to pass whatever parameters your target server supports.\nSpring AI does not validate these parameters—they are passed directly to the server.\nThis design provides maximum flexibility for working with diverse OpenAI-compatible implementations.</p>\n</div>',0x00,'asciidoc::openai-chat.adoc::Using Extra Parameters with OpenAI-Compatible Servers::Example: Ollama Server::0'),
('4ce8c2fb-bfb3-477f-9c3a-80c6a12e61fc','You can use the following properties in your Spring Boot configuration to further configure the <code>GemFireVectorStore</code>.',0x00,'asciidoc::gemfire.adoc::Auto-configuration::Configuration properties::0'),
('cb4c04d0-8c56-437c-93a4-8119db6408e7','@SuppressWarnings(\"CheckReturnValue\")\npublic static class IdentifierContext extends ParserRuleContext {\n\n    public List<TerminalNode> IDENTIFIER() {\n        return getTokens(FiltersParser.IDENTIFIER);\n    }\n\n    public TerminalNode IDENTIFIER(int i) {\n        return getToken(FiltersParser.IDENTIFIER, i);\n    }\n\n    public TerminalNode DOT() {\n        return getToken(FiltersParser.DOT, 0);\n    }\n\n    public TerminalNode QUOTED_STRING() {\n        return getToken(FiltersParser.QUOTED_STRING, 0);\n    }\n\n    public IdentifierContext(ParserRuleContext parent, int invokingState) {\n        super(parent, invokingState);\n    }\n\n    @Override\n    public int getRuleIndex() {\n        return RULE_identifier;\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterIdentifier(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitIdentifier(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitIdentifier(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('85f73130-8640-417a-8ac7-814938a5828b','Generation modules are responsible for generating the final response based on the user query and retrieved documents.\n\nQuery Augmentation\n\nA component for augmenting an input query with additional data, useful to provide a large language model\nwith the necessary context to answer the user query.\n\nContextualQueryAugmenter\n\nThe <code>ContextualQueryAugmenter</code> augments the user query with contextual data from the content of the provided documents.\n\nQueryAugmenter queryAugmenter = ContextualQueryAugmenter.builder().build();\n\nBy default, the <code>ContextualQueryAugmenter</code> does not allow the retrieved context to be empty. When that happens,\nit instructs the model not to answer the user query.\n\nYou can enable the <code>allowEmptyContext</code> option to allow the model to generate a response even when the retrieved context is empty.\n\nQueryAugmenter queryAugmenter = ContextualQueryAugmenter.builder()\n        .allowEmptyContext(true)\n        .build();\n\nThe prompts used by this component can be customized via the <code>promptTemplate()</code> and <code>emptyContextPromptTemplate()</code> methods\navailable in the builder.',0x00,'asciidoc::retrieval-augmented-generation.adoc::Modules::Generation::0'),
('6e3b0170-9c78-4563-935b-815d043167f8','You will need to create an API with Mistral AI to access Mistral AI language models.\nCreate an account at <a href=\"https://auth.mistral.ai/ui/registration\">Mistral AI registration page</a> and generate the token on the <a href=\"https://console.mistral.ai/api-keys/\">API Keys page</a>.',0x00,'asciidoc::mistralai-chat.adoc::Prerequisites::0'),
('aa069513-fcbc-4cfe-85c0-819f7031c820','This feature is particularly powerful when combined with system prompts that instruct the model to return structured data.\n\nModel-Specific Options\n\nWhile the portable <code>ChatOptions</code> provides a consistent interface across different LLM providers, Spring AI also offers model-specific options classes that expose provider-specific features and configurations. These model-specific options allow you to leverage the unique capabilities of each LLM provider.\n\n// Using OpenAI-specific options\nOpenAiChatOptions openAiOptions = OpenAiChatOptions.builder()\n        .model(\"gpt-4o\")\n        .temperature(0.2)\n        .frequencyPenalty(0.5)      // OpenAI-specific parameter\n        .presencePenalty(0.3)       // OpenAI-specific parameter\n        .responseFormat(new ResponseFormat(\"json_object\"))  // OpenAI-specific JSON mode\n        .seed(42)                   // OpenAI-specific deterministic generation\n        .build();\n\nString result = chatClient.prompt(\"...\")\n        .options(openAiOptions)\n        .call()\n        .content();\n\n// Using Anthropic-specific options\nAnthropicChatOptions anthropicOptions = AnthropicChatOptions.builder()\n        .model(\"claude-3-7-sonnet-latest\")\n        .temperature(0.2)\n        .topK(40)                   // Anthropic-specific parameter\n        .thinking(AnthropicApi.ThinkingType.ENABLED, 1000)  // Anthropic-specific thinking configuration\n        .build();\n\nString result = chatClient.prompt(\"...\")\n        .options(anthropicOptions)\n        .call()\n        .content();\n\nEach model provider has its own implementation of chat options (e.g., <code>OpenAiChatOptions</code>, <code>AnthropicChatOptions</code>, <code>MistralAiChatOptions</code>) that exposes provider-specific parameters while still implementing the common interface. This approach gives you the flexibility to use portable options for cross-provider compatibility or model-specific options when you need access to unique features of a particular provider.\n\nNote that when using model-specific options, your code becomes tied to that specific provider, reducing portability. It&#8217;s a trade-off between accessing advanced provider-specific features versus maintaining provider independence in your application.',0x00,'asciidoc::prompt-engineering-patterns.adoc::1. Configuration::LLM Output Configuration::1'),
('a02355cc-323b-4367-9cbf-81af71e0933e','<a href=\"https://www.mongodb.com/products/platform/atlas-database\">MongoDB Atlas</a> is the fully-managed cloud database from MongoDB available in AWS, Azure, and GCP.\nAtlas supports native Vector Search and full text search on your MongoDB document data.\n\n<a href=\"https://www.mongodb.com/products/platform/atlas-vector-search\">MongoDB Atlas Vector Search</a> allows you to store your embeddings in MongoDB documents, create vector search indexes, and perform KNN searches with an approximate nearest neighbor algorithm (Hierarchical Navigable Small Worlds).\nYou can use the <code>$vectorSearch</code> aggregation operator in a MongoDB aggregation stage to perform a search on your vector embeddings.',0x00,'asciidoc::mongodb.adoc::What is MongoDB Atlas?::0'),
('383a26ee-b3b2-437b-888e-81d645e94b97','public static class DescriptiveErrorListener extends BaseErrorListener {\n\n    public static final DescriptiveErrorListener INSTANCE = new DescriptiveErrorListener();\n\n    public final List<String> errorMessages = new CopyOnWriteArrayList<>();\n\n    @Override\n    public void syntaxError(Recognizer<?, ?> recognizer, Object offendingSymbol, int line, int charPositionInLine, String msg, RecognitionException e) {\n        String sourceName = recognizer.getInputStream().getSourceName();\n        var errorMessage = String.format(\"Source: %s, Line: %s:%s, Error: %s\", sourceName, line, charPositionInLine, msg);\n        this.errorMessages.add(errorMessage);\n    }\n}',0x01,'cu::FilterExpressionTextParser.java'),
('217fd2b0-32f7-4d2b-a521-82192c70a37d','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-vertex-ai-gemini/src/main/java/org/springframework/ai/vertexai/gemini/VertexAiGeminiChatOptions.java\">VertexAiGeminiChatOptions.java</a> provides model configurations, such as the temperature, the topK, etc.\n\nOn start-up, the default options can be configured with the <code>VertexAiGeminiChatModel(api, options)</code> constructor or the <code>spring.ai.vertex.ai.chat.options.*</code> properties.\n\nAt runtime, you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example, to override the default temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        VertexAiGeminiChatOptions.builder()\n            .temperature(0.4)\n        .build()\n    ));\n\nIn addition to the model specific <code>VertexAiGeminiChatOptions</code> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::vertexai-gemini-chat.adoc::Runtime options::0'),
('3a62d302-9e00-4de6-b531-821b4bb72725','If you prefer to configure <code>PineconeVectorStore</code> manually, you can do so by using the <code>PineconeVectorStore#Builder</code>.\n\nAdd these dependencies to your project:\n\nOpenAI: Required for calculating embeddings.\n\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nPinecone\n\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-pinecone-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::pinecone.adoc::Manual Configuration::0'),
('925ae138-8c23-436f-aa72-8226cc900a79','Chain of Thought prompting encourages the model to reason step-by-step through a problem, which improves accuracy for complex reasoning tasks. By explicitly asking the model to show its work or think through a problem in logical steps, you can dramatically improve performance on tasks requiring multi-step reasoning.\n\nCoT works by encouraging the model to generate intermediate reasoning steps before producing a final answer, similar to how humans solve complex problems. This makes the model&#8217;s thinking process explicit and helps it arrive at more accurate conclusions.\n\n// Implementation of Section 2.5: Chain of Thought (CoT) - Zero-shot approach\npublic void pt_chain_of_thought_zero_shot(ChatClient chatClient) {\n    String output = chatClient\n            .prompt(\"\"\"\n                    When I was 3 years old, my partner was 3 times my age. Now,\n                    I am 20 years old. How old is my partner?\n\n                    Let\'s think step by step.\n                    \"\"\")\n            .call()\n            .content();\n}\n\n// Implementation of Section 2.5: Chain of Thought (CoT) - Few-shot approach\npublic void pt_chain_of_thought_singleshot_fewshots(ChatClient chatClient) {\n    String output = chatClient\n            .prompt(\"\"\"\n                    Q: When my brother was 2 years old, I was double his age. Now\n                    I am 40 years old. How old is my brother? Let\'s think step\n                    by step.\n                    A: When my brother was 2 years, I was 2 * 2 = 4 years old.\n                    That\'s an age difference of 2 years and I am older. Now I am 40\n                    years old, so my brother is 40 - 2 = 38 years old. The answer\n                    is 38.\n                    Q: When I was 3 years old, my partner was 3 times my age. Now,\n                    I am 20 years old. How old is my partner? Let\'s think step\n                    by step.\n                    A:\n                    \"\"\")\n            .call()\n            .content();\n}\n\nThe key phrase \"Let&#8217;s think step by step\" triggers the model to show its reasoning process. CoT is especially valuable for mathematical problems, logical reasoning tasks, and any question requiring multi-step reasoning. It helps reduce errors by making intermediate reasoning explicit.\n\n<strong>Reference:</strong> Wei, J., et al. (2022). \"Chain-of-Thought Prompting Elicits Reasoning in Large Language Models.\" arXiv:2201.11903. <a href=\"https://arxiv.org/abs/2201.11903\">https://arxiv.org/abs/2201.11903</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.5 Chain of Thought (CoT)::0'),
('b34af861-ff00-45e3-9356-8239510ec4c0','When building tools from a function, the <code>ToolDefinition</code> is automatically generated for you. When you use the <code>FunctionToolCallback.Builder</code> to build a <code>FunctionToolCallback</code> instance, you can provide the tool name, description, and input schema that will be used to generate the <code>ToolDefinition</code>. See <a href=\"#_functions_as_tools\">Functions as Tools</a> for more details.',0x00,'asciidoc::tools.adoc::Tool Specification::Tool Definition::1'),
('736e9592-e129-428d-a4dd-825b96d0246f','<div class=\"paragraph\">\n<p>Enabling and disabling of the chat auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.chat</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.chat=ollama (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.chat=none (or any value which doesn&#8217;t match ollama)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.ollama.chat.options</code> is the property prefix that configures the Ollama chat model.\nIt includes the Ollama request (advanced) parameters such as the <code>model</code>, <code>keep-alive</code>, and <code>format</code> as well as the Ollama model <code>options</code> properties.\n\nHere are the advanced request parameter for the Ollama chat model:\n\n\n\nThe remaining <code>options</code> properties are based on the <a href=\"https://github.com/ollama/ollama/blob/main/docs/modelfile.md#valid-parameters-and-values\">Ollama Valid Parameters and Values</a> and <a href=\"https://github.com/ollama/ollama/blob/main/api/types.go\">Ollama Types</a>. The default values are based on the <a href=\"https://github.com/ollama/ollama/blob/b538dc3858014f94b099730a592751a5454cab0a/api/types.go#L364\">Ollama Types Defaults</a>.\n\n\n\nAll properties prefixed with <code>spring.ai.ollama.chat.options</code> can be overridden at runtime by adding request-specific <a href=\"#chat-options\">Runtime Options</a> to the <code>Prompt</code> call.',0x00,'asciidoc::ollama-chat.adoc::Auto-configuration::Chat Properties::0'),
('cc541d19-e454-4d67-ac52-82bb9ab7f41b','If you prefer not to use the Spring Boot auto-configuration, you can manually configure the <code>AzureOpenAiEmbeddingModel</code> in your application.\nFor this add the <code>spring-ai-azure-openai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-azure-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-azure-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nThe <code>spring-ai-azure-openai</code> dependency also provide the access to the <code>AzureOpenAiEmbeddingModel</code>. For more information about the <code>AzureOpenAiChatModel</code> refer to the <a href=\"../embeddings/azure-openai-embeddings.html\">Azure OpenAI Embeddings</a> section.\n\nNext, create an <code>AzureOpenAiEmbeddingModel</code> instance and use it to compute the similarity between two input texts:\n\nvar openAIClient = OpenAIClientBuilder()\n        .credential(new AzureKeyCredential(System.getenv(\"AZURE_OPENAI_API_KEY\")))\n		.endpoint(System.getenv(\"AZURE_OPENAI_ENDPOINT\"))\n		.buildClient();\n\nvar embeddingModel = new AzureOpenAiEmbeddingModel(this.openAIClient)\n    .withDefaultOptions(AzureOpenAiEmbeddingOptions.builder()\n        .model(\"text-embedding-ada-002\")\n        .user(\"user-6\")\n        .build());\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n	.embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));\n\nthe <code>text-embedding-ada-002</code> is actually the <code>Deployment Name</code> as presented in the Azure AI Portal.',0x00,'asciidoc::azure-openai-embeddings.adoc::Manual Configuration::0'),
('bccf9d23-5141-451a-9243-8335ab9994ce','The project has undergone significant changes to its module and artifact structure. Previously, <code>spring-ai-core</code> contained all central interfaces, but this has now been split into specialized domain modules to reduce unnecessary dependencies in your applications.\n\nspring-ai-commons\n\nBase module with no dependencies on other Spring AI modules. Contains:\n- Core domain models (<code>Document</code>, <code>TextSplitter</code>)\n- JSON utilities and resource handling\n- Structured logging and observability support\n\nspring-ai-model\n\nProvides AI capability abstractions:\n- Interfaces like <code>ChatModel</code>, <code>EmbeddingModel</code>, and <code>ImageModel</code>\n- Message types and prompt templates\n- Function-calling framework (<code>ToolDefinition</code>, <code>ToolCallback</code>)\n- Content filtering and observation support\n\nspring-ai-vector-store\n\nUnified vector database abstraction:\n- <code>VectorStore</code> interface for similarity search\n- Advanced filtering with SQL-like expressions\n- <code>SimpleVectorStore</code> for in-memory usage\n- Batching support for embeddings\n\nspring-ai-client-chat\n\nHigh-level conversational AI APIs:\n- <code>ChatClient</code> interface\n- Conversation persistence via <code>ChatMemory</code>\n- Response conversion with <code>OutputConverter</code>\n- Advisor-based interception\n- Synchronous and reactive streaming support\n\nspring-ai-advisors-vector-store\n\nBridges chat with vector stores for RAG:\n- <code>QuestionAnswerAdvisor</code>: injects context into prompts\n- <code>VectorStoreChatMemoryAdvisor</code>: stores/retrieves conversation history\n\nspring-ai-model-chat-memory-cassandra\n\nApache Cassandra persistence for <code>ChatMemory</code>:\n- <code>CassandraChatMemory</code> implementation\n- Type-safe CQL with Cassandra&#8217;s QueryBuilder\n==== spring-ai-model-chat-memory-neo4j\n\nNeo4j graph database persistence for chat conversations.\n\nspring-ai-rag\n\nComprehensive framework for Retrieval Augmented Generation:\n- Modular architecture for RAG pipelines\n- <code>RetrievalAugmentationAdvisor</code> as main entry point\n- Functional programming principles with composable components',0x00,'asciidoc::upgrade-notes.adoc::Common Changes Across Versions::Module Structure::0'),
('84689885-6798-4837-98c1-8366f35970a0','For <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/conversation-inference-supported-models-features.html\">models</a> that support vision multimodality, such as Amazon Nova, Anthropic Claude, Llama 3.2, the Bedrock Converse API Amazon allows you to include multiple images in the payload. Those models can analyze the passed images and answer questions, classify an image, as well as summarize images based on provided instructions.\n\nCurrently, Bedrock Converse supports the <code>base64</code> encoded images of <code>image/jpeg</code>, <code>image/png</code>, <code>image/gif</code> and <code>image/webp</code> mime types.\n\nSpring AI&#8217;s <code>Message</code> interface supports multimodal AI models by introducing the <code>Media</code> type.\nIt contains data and information about media attachments in messages, using Spring&#8217;s <code>org.springframework.util.MimeType</code> and a <code>java.lang.Object</code> for the raw media data.\n\nBelow is a simple code example, demonstrating the combination of user text with an image.\n\nString response = ChatClient.create(chatModel)\n    .prompt()\n    .user(u -&gt; u.text(\"Explain what do you see on this picture?\")\n        .media(Media.Format.IMAGE_PNG, new ClassPathResource(\"/test.png\")))\n    .call()\n    .content();\n\nlogger.info(response);\n\nIt takes as an input the <code>test.png</code> image:\n\nalong with the text message \"Explain what do you see on this picture?\", and generates a response something like:\n\nThe image shows a close-up view of a wire fruit basket containing several pieces of fruit.\n...',0x00,'asciidoc::bedrock-converse.adoc::Multimodal::Images::0'),
('547cf944-a45c-4ade-995b-83b23b01e87b','Removed all code deprecations (<a href=\"https://github.com/spring-projects/spring-ai/commit/76bee8ceb2854839f93a6c52876f50bb24219355\">76bee8c</a>) and (<a href=\"https://github.com/spring-projects/spring-ai/commit/b6ce7f3e4a7aafe6b9031043f63813dde6e73605\">b6ce7f3</a>)',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-RC1::General Cleanup::0'),
('7fd99c28-c1be-4c7d-a527-83d639ccaeeb','spring.ai.google.genai.embedding.project-id=YOUR_PROJECT_ID\nspring.ai.google.genai.embedding.location=YOUR_PROJECT_LOCATION\nspring.ai.google.genai.embedding.text.options.model=text-embedding-004\n\nThis will create a <code>GoogleGenAiTextEmbeddingModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the embedding model for embeddings generations.\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::google-genai-embeddings-text.adoc::Sample Controller::Using Vertex AI::0'),
('33458d5f-e64b-4c4e-9a34-83e066c5593b','Spring AI offers the <code>ChatMemoryRepository</code> abstraction for storing chat memory. This section describes the built-in repositories provided by Spring AI and how to use them, but you can also implement your own repository if needed.',0x00,'asciidoc::chat-memory.adoc::Memory Storage::0'),
('2506d377-4c4b-4e86-b21f-840d37a26cd4','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>OpenAiChatModel(api, options)</code> constructor or the <code>spring.ai.openai.chat.options.*</code> properties.\n\nAt run-time you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        OpenAiChatOptions.builder()\n            .model(\"mixtral-8x7b-32768\")\n            .temperature(0.4)\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::groq-chat.adoc::Runtime Options::0'),
('7775b424-3519-4ac8-9263-841f506f0ea1','You will need to create an API with OpenAI to access OpenAI embeddings models.\n\nCreate an account at <a href=\"https://platform.openai.com/signup\">OpenAI signup page</a> and generate the token on the <a href=\"https://platform.openai.com/account/api-keys\">API Keys page</a>.\n\nThe Spring AI project defines a configuration property named <code>spring.ai.openai.api-key</code> that you should set to the value of the <code>API Key</code> obtained from openai.com.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.openai.api-key=&lt;your-openai-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference an environment variable:\n\n# In application.yml\nspring:\n  ai:\n    openai:\n      api-key: ${OPENAI_API_KEY}\n\n# In your environment or .env file\nexport OPENAI_API_KEY=&lt;your-openai-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"OPENAI_API_KEY\");',0x00,'asciidoc::openai-embeddings.adoc::Prerequisites::0'),
('de94452f-5d83-485d-82be-846e8f3414e6','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the VertexAI Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-vertex-ai-embedding&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-vertex-ai-embedding\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::vertexai-embeddings-text.adoc::Auto-configuration::0'),
('aefeca5b-5a83-4529-8abb-84950d1eb8e3','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/cohere/BedrockCohereEmbeddingOptions.java\">BedrockCohereEmbeddingOptions.java</a> provides model configurations, such as <code>input-type</code> or <code>truncate</code>.\n\nOn start-up, the default options can be configured with the <code>BedrockCohereEmbeddingModel(api, options)</code> constructor or the <code>spring.ai.bedrock.cohere.embedding.options.*</code> properties.\n\nAt runtime you can override the default options by adding new, request-specific, options to the <code>EmbeddingRequest</code> call.\nFor example to override the default input type for a specific request:\n\nEmbeddingResponse embeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n        BedrockCohereEmbeddingOptions.builder()\n        .inputType(InputType.SEARCH_DOCUMENT)\n        .build()));',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Runtime Options::0'),
('b937e3e2-8fca-4d23-93b5-8496bf7ab495','The <code>ChatClient</code> prompt and completion data is typically big and possibly containing sensitive information.\nFor those reasons, it is not exported by default.\n\nSpring AI supports logging the prompt and completion data to help with debugging and troubleshooting.\n\n\n\nIf you enable logging of the chat client prompt and completion data, there&#8217;s a risk of exposing sensitive or private information. Please, be careful!',0x00,'asciidoc::index.adoc::Chat Client::Prompt and Completion Data::0'),
('a2bfc5ac-5840-44a0-a8d2-851be9a132e2','Labels',0x00,'asciidoc::index.adoc::More Metrics Reference::Vector Store Metrics::0'),
('e9382a70-e4af-4c5c-aa56-856a7e631ea2','/**\n * Combines documents retrieved based on multiple queries and from multiple data sources\n * by concatenating them into a single collection of documents. In case of duplicate\n * documents, the first occurrence is kept. The score of each document is kept as is. The\n * result is a list of unique documents sorted by their score in descending order.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic class ConcatenationDocumentJoiner implements DocumentJoiner {\n\n    private static final Logger logger = LoggerFactory.getLogger(ConcatenationDocumentJoiner.class);\n\n    @Override\n    public List<Document> join(Map<Query, List<List<Document>>> documentsForQuery) {\n        Assert.notNull(documentsForQuery, \"documentsForQuery cannot be null\");\n        Assert.noNullElements(documentsForQuery.keySet(), \"documentsForQuery cannot contain null keys\");\n        Assert.noNullElements(documentsForQuery.values(), \"documentsForQuery cannot contain null values\");\n        logger.debug(\"Joining documents by concatenation\");\n        return new ArrayList<>(documentsForQuery.values().stream().flatMap(List::stream).flatMap(List::stream).collect(Collectors.toMap(Document::getId, Function.identity(), (existing, duplicate) -> existing)).values().stream().sorted(Comparator.comparingDouble((Document doc) -> doc.getScore() != null ? doc.getScore() : 0.0).reversed()).toList());\n    }\n}',0x01,'cu::ConcatenationDocumentJoiner.java'),
('d688e717-5d27-408d-aba5-856c5aae6859','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::vertexai-embeddings-text.adoc::Prerequisites::Add Repositories and BOM::0'),
('8a0925a0-0102-418f-a408-86321d264ab3','Here&#8217;s a simple example of how to use NVIDIA LLM API function calling with Spring AI:\n\nspring.ai.openai.api-key=${NVIDIA_API_KEY}\nspring.ai.openai.base-url=https://integrate.api.nvidia.com\nspring.ai.openai.chat.options.model=meta/llama-3.1-70b-instruct\nspring.ai.openai.chat.options.max-tokens=2048\n\n@SpringBootApplication\npublic class NvidiaLlmApplication {\n\n    public static void main(String[] args) {\n        SpringApplication.run(NvidiaLlmApplication.class, args);\n    }\n\n    @Bean\n    CommandLineRunner runner(ChatClient.Builder chatClientBuilder) {\n        return args -&gt; {\n            var chatClient = chatClientBuilder.build();\n\n            var response = chatClient.prompt()\n                .user(\"What is the weather in Amsterdam and Paris?\")\n                .functions(\"weatherFunction\") // reference by bean name.\n                .call()\n                .content();\n\n            System.out.println(response);\n        };\n    }\n\n    @Bean\n    @Description(\"Get the weather in location\")\n    public Function&lt;WeatherRequest, WeatherResponse&gt; weatherFunction() {\n        return new MockWeatherService();\n    }\n\n    public static class MockWeatherService implements Function&lt;WeatherRequest, WeatherResponse&gt; {\n\n        public record WeatherRequest(String location, String unit) {}\n        public record WeatherResponse(double temp, String unit) {}\n\n        @Override\n        public WeatherResponse apply(WeatherRequest request) {\n            double temperature = request.location().contains(\"Amsterdam\") ? 20 : 25;\n            return new WeatherResponse(temperature, request.unit);\n        }\n    }\n}\n\nIn this example, when the model needs weather information, it will automatically call the <code>weatherFunction</code> bean, which can then fetch real-time weather data.\nThe expected response looks like this: \"The weather in Amsterdam is currently 20 degrees Celsius, and the weather in Paris is currently 25 degrees Celsius.\"\n\nRead more about OpenAI <a href=\"https://docs.spring.io/spring-ai/reference/api/chat/functions/openai-chat-functions.html\">Function Calling</a>.',0x00,'asciidoc::nvidia-chat.adoc::Function Calling::Tool Example::0'),
('e039cd26-524c-419d-b522-86436e2cde09','It is common to use the <code>call()</code> method of <code>ChatModel</code> that takes a <code>Prompt</code> instance and returns a <code>ChatResponse</code>.\n\nThe <code>Prompt</code> class functions as a container for an organized series of <code>Message</code> objects and a request <code>ChatOptions</code>.\nEvery <code>Message</code> embodies a unique role within the prompt, differing in its content and intent.\nThese roles can encompass a variety of elements, from user inquiries to AI-generated responses to relevant background information.\nThis arrangement enables intricate and detailed interactions with AI models, as the prompt is constructed from multiple messages, each assigned a specific role to play in the dialogue.\n\nBelow is a truncated version of the Prompt class, with constructors and utility methods omitted for brevity:\n\npublic class Prompt implements ModelRequest&lt;List&lt;Message&gt;&gt; {\n\n    private final List&lt;Message&gt; messages;\n\n    private ChatOptions chatOptions;\n}',0x00,'asciidoc::prompt.adoc::API Overview::Prompt::0'),
('06c11634-16ea-4cbf-a4b5-86696fd92581','/**\n * Unit tests for {@link VectorStoreQueryResponseObservationHandler}.\n *\n * @author Christian Tzolov\n * @author Thomas Vitale\n * @author Jonatan Ivanov\n */\n@ExtendWith(OutputCaptureExtension.class)\nclass VectorStoreQueryResponseObservationHandlerTests {\n\n    private final VectorStoreQueryResponseObservationHandler observationHandler = new VectorStoreQueryResponseObservationHandler();\n\n    @Test\n    void whenNotSupportedObservationContextThenReturnFalse() {\n        var context = new Observation.Context();\n        assertThat(this.observationHandler.supportsContext(context)).isFalse();\n    }\n\n    @Test\n    void whenSupportedObservationContextThenReturnTrue() {\n        var context = VectorStoreObservationContext.builder(\"db\", VectorStoreObservationContext.Operation.ADD).build();\n        assertThat(this.observationHandler.supportsContext(context)).isTrue();\n    }\n\n    @Test\n    void whenEmptyQueryResponseThenOutputNothing(CapturedOutput output) {\n        var context = VectorStoreObservationContext.builder(\"db\", VectorStoreObservationContext.Operation.ADD).build();\n        this.observationHandler.onStop(context);\n        assertThat(output).contains(\"\"\"\n            INFO  o.s.a.v.o.VectorStoreQueryResponseObservationHandler -- Vector Store Query Response:\n            []\n            \"\"\");\n    }\n\n    @Test\n    void whenNonEmptyQueryResponseThenOutputIt(CapturedOutput output) {\n        var context = VectorStoreObservationContext.builder(\"db\", VectorStoreObservationContext.Operation.ADD).build();\n        context.setQueryResponse(List.of(new Document(\"doc1\"), new Document(\"doc2\")));\n        this.observationHandler.onStop(context);\n        assertThat(output).contains(\"\"\"\n            INFO  o.s.a.v.o.VectorStoreQueryResponseObservationHandler -- Vector Store Query Response:\n            [\"doc1\", \"doc2\"]\n            \"\"\");\n    }\n}',0x01,'cu::VectorStoreQueryResponseObservationHandlerTests.java'),
('5a9b6fe8-df4e-4c06-9225-8672037289a3','/**\n * Represents expression value constant or constant array. Support Numeric, Boolean\n * and String data types.\n *\n * @param value value constant or constant array\n */\npublic record Value(Object value) implements Operand {\n}',0x01,'cu::Filter.java'),
('beb67203-8aa0-40f1-ad07-8680e2b576d1','AWS Bedrock pricing for prompt caching (approximate, varies by model):\n\n<strong>Cache writes</strong>: ~25% more expensive than base input tokens\n<strong>Cache reads</strong>: ~90% cheaper (only 10% of base input token price)\n<strong>Break-even point</strong>: After just 1 cache read, you&#8217;ve saved money\n\n\n<strong>Example cost calculation</strong>:\n\n// System prompt: 2000 tokens\n// User question: 50 tokens\n\n// Without caching (5 requests):\n// Cost: 5 × (2000 + 50) = 10,250 tokens at base rate\n\n// With caching (5 requests):\n// Request 1: 2000 tokens × 1.25 (cache write) + 50 = 2,550 tokens\n// Requests 2-5: 4 × (2000 × 0.10 (cache read) + 50) = 4 × 250 = 1,000 tokens\n// Total: 2,550 + 1,000 = 3,550 tokens equivalent\n\n// Savings: (10,250 - 3,550) / 10,250 = 65% cost reduction',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Cost Considerations::0'),
('532fdf03-31be-4888-b5d4-86932519cd2b','Ollama is OpenAI API-compatible and you can use the <a href=\"api/chat/openai-chat.html\">Spring AI OpenAI</a> client to talk to Ollama and use tools.\nFor this, you need to configure the OpenAI base URL to your Ollama instance: <code>spring.ai.openai.chat.base-url=http://localhost:11434</code> and select one of the provided Ollama models: <code>spring.ai.openai.chat.options.model=mistral</code>.\n\nWhen using the OpenAI client with Ollama, you can pass Ollama-specific parameters (like <code>top_k</code>, <code>repeat_penalty</code>, <code>num_predict</code>) using the <a href=\"api/chat/openai-chat.html#openai-compatible-servers\"><code>extraBody</code> option</a>.\nThis allows you to leverage Ollama&#8217;s full capabilities while using the OpenAI client.',0x00,'asciidoc::ollama-chat.adoc::OpenAI API Compatibility::0'),
('fcb8f877-2185-4d5f-8b73-8699b02200a0','/**\n * An immutable {@link Content} implementation representing content, metadata, and its\n * embeddings. This class is thread-safe and all its fields are final and deeply\n * immutable. The embedding vector is required for all instances of this class.\n */\npublic final class SimpleVectorStoreContent implements Content {\n\n    private final String id;\n\n    private final String text;\n\n    private final Map<String, Object> metadata;\n\n    private final float[] embedding;\n\n    /**\n     * Creates a new instance with the given content, empty metadata, and embedding\n     * vector.\n     * @param text the content text, must not be null\n     * @param embedding the embedding vector, must not be null\n     */\n    @JsonCreator(mode = JsonCreator.Mode.PROPERTIES)\n    public SimpleVectorStoreContent(@JsonProperty(\"text\") @JsonAlias(\"content\") String text, @JsonProperty(\"embedding\") float[] embedding) {\n        this(text, new HashMap<>(), embedding);\n    }\n\n    /**\n     * Creates a new instance with the given content, metadata, and embedding vector.\n     * @param text the content text, must not be null\n     * @param metadata the metadata map, must not be null\n     * @param embedding the embedding vector, must not be null\n     */\n    public SimpleVectorStoreContent(String text, Map<String, Object> metadata, float[] embedding) {\n        this(text, metadata, new RandomIdGenerator(), embedding);\n    }\n\n    /**\n     * Creates a new instance with the given content, metadata, custom ID generator, and\n     * embedding vector.\n     * @param text the content text, must not be null\n     * @param metadata the metadata map, must not be null\n     * @param idGenerator the ID generator to use, must not be null\n     * @param embedding the embedding vector, must not be null\n     */\n    public SimpleVectorStoreContent(String text, Map<String, Object> metadata, IdGenerator idGenerator, float[] embedding) {\n        this(idGenerator.generateId(text, metadata), text, metadata, embedding);\n    }\n\n    /**\n     * Creates a new instance with all fields specified.\n     * @param id the unique identifier, must not be empty\n     * @param text the content text, must not be null\n     * @param metadata the metadata map, must not be null\n     * @param embedding the embedding vector, must not be null\n     * @throws IllegalArgumentException if any parameter is null or if id is empty\n     */\n    public SimpleVectorStoreContent(String id, String text, Map<String, Object> metadata, float[] embedding) {\n        Assert.hasText(id, \"id must not be null or empty\");\n        Assert.notNull(text, \"content must not be null\");\n        Assert.notNull(metadata, \"metadata must not be null\");\n        Assert.notNull(embedding, \"embedding must not be null\");\n        Assert.isTrue(embedding.length > 0, \"embedding vector must not be empty\");\n        this.id = id;\n        this.text = text;\n        this.metadata = Map.copyOf(metadata);\n        this.embedding = Arrays.copyOf(embedding, embedding.length);\n    }\n\n    public String getId() {\n        return this.id;\n    }\n\n    @Override\n    public String getText() {\n        return this.text;\n    }\n\n    @Override\n    public Map<String, Object> getMetadata() {\n        return this.metadata;\n    }\n\n    /**\n     * Returns a defensive copy of the embedding vector.\n     * @return a new array containing the embedding vector\n     */\n    public float[] getEmbedding() {\n        return Arrays.copyOf(this.embedding, this.embedding.length);\n    }\n\n    public Document toDocument(Double score) {\n        var metadata = new HashMap<>(this.metadata);\n        metadata.put(DocumentMetadata.DISTANCE.value(), 1.0 - score);\n        return Document.builder().id(this.id).text(this.text).metadata(metadata).score(score).build();\n    }\n\n    @Override\n    public boolean equals(Object o) {\n        if (this == o) {\n            return true;\n        }\n        if (o == null || getClass() != o.getClass()) {\n            return false;\n        }\n        SimpleVectorStoreContent that = (SimpleVectorStoreContent) o;\n        return Objects.equals(this.id, that.id) && Objects.equals(this.text, that.text) && Objects.equals(this.metadata, that.metadata) && Arrays.equals(this.embedding, that.embedding);\n    }\n\n    @Override\n    public int hashCode() {\n        int result = Objects.hashCode(this.id);\n        result = 31 * result + Objects.hashCode(this.text);\n        result = 31 * result + Objects.hashCode(this.metadata);\n        result = 31 * result + Arrays.hashCode(this.embedding);\n        return result;\n    }\n\n    @Override\n    public String toString() {\n        return \"SimpleVectorStoreContent{\" + \"id=\'\" + this.id + \'\\\'\' + \", content=\'\" + this.text + \'\\\'\' + \", metadata=\" + this.metadata + \", embedding=\" + Arrays.toString(this.embedding) + \'}\';\n    }\n}',0x01,'cu::SimpleVectorStoreContent.java'),
('fac230f5-a108-4e47-a411-8699c2e42d11','When working with vector stores, it&#8217;s often necessary to embed large numbers of documents.\nWhile it might seem straightforward to make a single call to embed all documents at once, this approach can lead to issues.\nEmbedding models process text as tokens and have a maximum token limit, often referred to as the context window size.\nThis limit restricts the amount of text that can be processed in a single embedding request.\nAttempting to embed too many tokens in one call can result in errors or truncated embeddings.\n\nTo address this token limit, Spring AI implements a batching strategy.\nThis approach breaks down large sets of documents into smaller batches that fit within the embedding model&#8217;s maximum context window.\nBatching not only solves the token limit issue but can also lead to improved performance and more efficient use of API rate limits.\n\nSpring AI provides this functionality through the <code>BatchingStrategy</code> interface, which allows for processing documents in sub-batches based on their token counts.\n\nThe core <code>BatchingStrategy</code> interface is defined as follows:\n\npublic interface BatchingStrategy {\n    List&lt;List&lt;Document&gt;&gt; batch(List&lt;Document&gt; documents);\n}\n\nThis interface defines a single method, <code>batch</code>, which takes a list of documents and returns a list of document batches.',0x00,'asciidoc::vectordbs.adoc::Batching Strategy::0'),
('e1a7dd34-2c01-483f-9a01-86c587df890a','Here is the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/model/StreamingChatModel.java\">StreamingChatModel</a> interface definition:\n\npublic interface StreamingChatModel extends StreamingModel&lt;Prompt, ChatResponse&gt; {\n\n    default Flux&lt;String&gt; stream(String message) {...}\n\n    @Override\n	Flux&lt;ChatResponse&gt; stream(Prompt prompt);\n}\n\nThe <code>stream()</code> method takes a <code>String</code> or <code>Prompt</code> parameter similar to <code>ChatModel</code> but it streams the responses using the reactive Flux API.',0x00,'asciidoc::chatmodel.adoc::API Overview::StreamingChatModel::0'),
('2e3d3677-737b-4129-b3ab-86d2fc9bc050','These guides will be updated to explore how to build more advanced Agents that combine these foundational patterns with sophisticated features:\n\n<strong>Pattern Composition</strong>\n- Combining multiple patterns to create more powerful workflows\n- Building hybrid systems that leverage the strengths of each pattern\n- Creating flexible architectures that can adapt to changing requirements\n\n<strong>Advanced Agent Memory Management</strong>\n- Implementing persistent memory across conversations\n- Managing context windows efficiently\n- Developing strategies for long-term knowledge retention\n\n<strong>Tools and Model-Context Protocol (MCP) Integration</strong>\n- Leveraging external tools through standardized interfaces\n- Implementing MCP for enhanced model interactions\n- Building extensible agent architectures',0x00,'asciidoc::effective-agents.adoc::Future Work::0'),
('16588ab3-02b9-4cb2-9692-880fd1ab735c','The thinking content is available in the response metadata:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Calculate 17 × 23\",\n        OllamaChatOptions.builder()\n            .model(\"deepseek-r1\")\n            .enableThinking()\n            .build()\n    ));\n\n// Get the reasoning process\nString thinking = response.getResult().getMetadata().get(\"thinking\");\nSystem.out.println(\"Reasoning: \" + thinking);\n// Output: \"17 × 20 = 340, 17 × 3 = 51, 340 + 51 = 391\"\n\n// Get the final answer\nString answer = response.getResult().getOutput().getContent();\nSystem.out.println(\"Answer: \" + answer);\n// Output: \"The answer is 391\"',0x00,'asciidoc::ollama-chat.adoc::Thinking Mode (Reasoning)::Accessing Thinking Content::0'),
('da5ad77f-2ac1-47fa-8330-8825e40ec87d','Instead of using the Spring Boot auto-configuration, you can manually configure the Redis vector store. For this you need to add the <code>spring-ai-redis-store</code> to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-redis-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-redis-store\'\n}\n\nCreate a <code>JedisPooled</code> bean:\n\n@Bean\npublic JedisPooled jedisPooled() {\n    return new JedisPooled(\"&lt;host&gt;\", 6379);\n}\n\nThen create the <code>RedisVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore vectorStore(JedisPooled jedisPooled, EmbeddingModel embeddingModel) {\n    return RedisVectorStore.builder(jedisPooled, embeddingModel)\n        .indexName(\"custom-index\")                // Optional: defaults to \"spring-ai-index\"\n        .prefix(\"custom-prefix\")                  // Optional: defaults to \"embedding:\"\n        .metadataFields(                         // Optional: define metadata fields for filtering\n            MetadataField.tag(\"country\"),\n            MetadataField.numeric(\"year\"))\n        .initializeSchema(true)                   // Optional: defaults to false\n        .batchingStrategy(new TokenCountBatchingStrategy()) // Optional: defaults to TokenCountBatchingStrategy\n        .build();\n}\n\n// This can be any EmbeddingModel implementation\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}\n\n<div class=\"paragraph\">\n<p>You must list explicitly all metadata field names and types (<code>TAG</code>, <code>TEXT</code>, or <code>NUMERIC</code>) for any metadata field used in filter expressions.\nThe <code>metadataFields</code> above registers filterable metadata fields: <code>country</code> of type <code>TAG</code>, <code>year</code> of type <code>NUMERIC</code>.</p>\n</div>',0x00,'asciidoc::redis.adoc::Manual Configuration::0'),
('83033cbd-ccea-4178-a0ff-8873ee97074c','<div class=\"paragraph\">\n<p>With <a href=\"https://ollama.ai/\">Ollama</a> you can run various <a href=\"https://ollama.com/search?c=embedding\">AI Models</a> locally and generate embeddings from them.\nAn embedding is a vector (list) of floating point numbers.\nThe distance between two vectors measures their relatedness.\nSmall distances suggest high relatedness and large distances suggest low relatedness.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <code>OllamaEmbeddingModel</code> implementation leverages the Ollama <a href=\"https://github.com/ollama/ollama/blob/main/docs/api.md#generate-embeddings\">Embeddings API</a> endpoint.</p>\n</div>',0x00,'asciidoc::ollama-embeddings.adoc::0'),
('65299501-8d2e-49dd-beb1-88a6c239000f','Instead of using the Spring Boot auto-configuration, you can manually configure the Couchbase vector store. For this you need to add the <code>spring-ai-couchbase-store</code> to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-couchbase-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-couchbase-store\'\n}\n\nCreate a Couchbase <code>Cluster</code> bean.\nRead the <a href=\"https://docs.couchbase.com/java-sdk/current/hello-world/start-using-sdk.html\">Couchbase Documentation</a> for more in-depth information about the configuration of a custom Cluster instance.\n\n@Bean\npublic Cluster cluster() {\n    return Cluster.connect(\"couchbase://localhost\", \"username\", \"password\");\n}\n\nand then create the <code>CouchbaseSearchVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore couchbaseSearchVectorStore(Cluster cluster,\n                                              EmbeddingModel embeddingModel,\n                                              Boolean initializeSchema) {\n    return CouchbaseSearchVectorStore\n            .builder(cluster, embeddingModel)\n            .bucketName(\"test\")\n            .scopeName(\"test\")\n            .collectionName(\"test\")\n            .initializeSchema(initializeSchema)\n            .build();\n}\n\n// This can be any EmbeddingModel implementation.\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(OpenAiApi.builder().apiKey(this.openaiKey).build());\n}',0x00,'asciidoc::couchbase.adoc::Manual Configuration::0'),
('1c702d1f-16a8-4f62-b958-890e9dcf5f49','// Cache conversation history with ChatClient and memory (cache breakpoint on last user message)\nChatClient chatClient = ChatClient.builder(chatModel)\n    .defaultSystem(\"You are a personalized career counselor...\")\n    .defaultAdvisors(MessageChatMemoryAdvisor.builder(chatMemory)\n        .conversationId(conversationId)\n        .build())\n    .build();\n\nString response = chatClient.prompt()\n    .user(\"What career advice would you give me?\")\n    .options(AnthropicChatOptions.builder()\n        .model(\"claude-sonnet-4\")\n        .cacheOptions(AnthropicCacheOptions.builder()\n            .strategy(AnthropicCacheStrategy.CONVERSATION_HISTORY)\n            .build())\n        .maxTokens(500)\n        .build())\n    .call()\n    .content();\n\nUsing ChatClient Fluent API\n\nString response = ChatClient.create(chatModel)\n    .prompt()\n    .system(\"You are an expert document analyst...\")\n    .user(\"Analyze this large document: \" + document)\n    .options(AnthropicChatOptions.builder()\n        .model(\"claude-sonnet-4\")\n        .cacheOptions(AnthropicCacheOptions.builder()\n            .strategy(AnthropicCacheStrategy.SYSTEM_ONLY)\n            .build())\n        .build())\n    .call()\n    .content();',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Enabling Prompt Caching::1'),
('aee117cc-dcee-42a6-90d5-8947e219f9cc','/**\n * Converts {@link Expression} into Pinecone metadata filter expression format.\n * (<a href=\"https://docs.pinecone.io/docs/metadata-filtering\">Metadata filtering</a>)\n *\n * @author Christian Tzolov\n */\npublic class PineconeFilterExpressionConverter extends AbstractFilterExpressionConverter {\n\n    @Override\n    protected void doExpression(Expression exp, StringBuilder context) {\n        context.append(\"{\");\n        if (exp.type() == ExpressionType.AND || exp.type() == ExpressionType.OR) {\n            context.append(getOperationSymbol(exp));\n            context.append(\"[\");\n            this.convertOperand(exp.left(), context);\n            context.append(\",\");\n            this.convertOperand(exp.right(), context);\n            context.append(\"]\");\n        } else {\n            this.convertOperand(exp.left(), context);\n            context.append(\"{\");\n            context.append(getOperationSymbol(exp));\n            this.convertOperand(exp.right(), context);\n            context.append(\"}\");\n        }\n        context.append(\"}\");\n    }\n\n    private String getOperationSymbol(Expression exp) {\n        return \"\\\"$\" + exp.type().toString().toLowerCase() + \"\\\": \";\n    }\n\n    @Override\n    protected void doKey(Key key, StringBuilder context) {\n        var identifier = (hasOuterQuotes(key.key())) ? removeOuterQuotes(key.key()) : key.key();\n        context.append(\"\\\"\").append(identifier).append(\"\\\": \");\n    }\n}',0x01,'cu::PineconeFilterExpressionConverter.java'),
('ffaceb90-3f59-493f-8410-896843b5e85c','The Google GenAI embeddings API supports different task types to optimize embeddings for specific use cases:\n\n<code>RETRIEVAL_QUERY</code>: Optimized for search queries in retrieval systems\n<code>RETRIEVAL_DOCUMENT</code>: Optimized for documents in retrieval systems\n<code>SEMANTIC_SIMILARITY</code>: Optimized for measuring semantic similarity between texts\n<code>CLASSIFICATION</code>: Optimized for text classification tasks\n<code>CLUSTERING</code>: Optimized for clustering similar texts\n<code>QUESTION_ANSWERING</code>: Optimized for question-answering systems\n<code>FACT_VERIFICATION</code>: Optimized for fact verification tasks\n\n\nExample of using different task types:\n\n// For indexing documents\nGoogleGenAiTextEmbeddingOptions docOptions = GoogleGenAiTextEmbeddingOptions.builder()\n    .model(\"text-embedding-004\")\n    .taskType(TaskType.RETRIEVAL_DOCUMENT)\n    .title(\"Product Documentation\")  // Optional title for documents\n    .build();\n\n// For search queries\nGoogleGenAiTextEmbeddingOptions queryOptions = GoogleGenAiTextEmbeddingOptions.builder()\n    .model(\"text-embedding-004\")\n    .taskType(TaskType.RETRIEVAL_QUERY)\n    .build();',0x00,'asciidoc::google-genai-embeddings-text.adoc::Task Types::0'),
('28b5d779-d391-4fb2-b6ab-89ca3fffd7e9','Install the <a href=\"https://cloud.google.com/sdk/docs/install\">gcloud</a> CLI, appropriate for your OS.\nAuthenticate by running the following command.\nReplace <code>PROJECT_ID</code> with your Google Cloud project ID and <code>ACCOUNT</code> with your Google Cloud username.\n\n\ngcloud config set project &lt;PROJECT_ID&gt; &amp;&amp;\ngcloud auth application-default login &lt;ACCOUNT&gt;',0x00,'asciidoc::google-genai-embeddings-text.adoc::Prerequisites::Option 2: Vertex AI (Google Cloud)::0'),
('6a506e62-fe52-4a3d-9800-89e938814f3a','Some embedding models, such as Vertex AI text embedding, support an <code>auto_truncate</code> feature. When enabled, the model silently truncates text inputs that exceed the maximum size and continues processing; when disabled, it throws an explicit error for inputs that are too large.\n\nWhen using auto-truncation with the batching strategy, you must configure your batching strategy with a much higher input token count than the model&#8217;s actual maximum. This prevents the batching strategy from raising exceptions for large documents, allowing the embedding model to handle truncation internally.\n\nConfiguration for Auto-Truncation\n\nWhen enabling auto-truncation, set your batching strategy&#8217;s maximum input token count much higher than the model&#8217;s actual limit. This prevents the batching strategy from raising exceptions for large documents, allowing the embedding model to handle truncation internally.\n\nHere&#8217;s an example configuration for using Vertex AI with auto-truncation and custom <code>BatchingStrategy</code> and then using them in the PgVectorStore:\n\n@Configuration\npublic class AutoTruncationEmbeddingConfig {\n\n    @Bean\n    public VertexAiTextEmbeddingModel vertexAiEmbeddingModel(\n            VertexAiEmbeddingConnectionDetails connectionDetails) {\n\n        VertexAiTextEmbeddingOptions options = VertexAiTextEmbeddingOptions.builder()\n                .model(VertexAiTextEmbeddingOptions.DEFAULT_MODEL_NAME)\n                .autoTruncate(true)  // Enable auto-truncation\n                .build();\n\n        return new VertexAiTextEmbeddingModel(connectionDetails, options);\n    }\n\n    @Bean\n    public BatchingStrategy batchingStrategy() {\n        // Only use a high token limit if auto-truncation is enabled in your embedding model.\n        // Set a much higher token count than the model actually supports\n        // (e.g., 132,900 when Vertex AI supports only up to 20,000)\n        return new TokenCountBatchingStrategy(\n                EncodingType.CL100K_BASE,\n                132900,  // Artificially high limit\n                0.1      // 10% reserve\n        );\n    }\n\n    @Bean\n    public VectorStore vectorStore(JdbcTemplate jdbcTemplate, EmbeddingModel embeddingModel, BatchingStrategy batchingStrategy) {\n        return PgVectorStore.builder(jdbcTemplate, embeddingModel)\n            // other properties omitted here\n            .build();\n    }\n}\n\nIn this configuration:\n\nThe embedding model has auto-truncation enabled, allowing it to handle oversized inputs gracefully.\nThe batching strategy uses an artificially high token limit (132,900) that&#8217;s much larger than the actual model limit (20,000).\nThe vector store uses the configured embedding model and the custom <code>BatchingStrategy</code> bean.\n\n\nWhy This Works\n\nThis approach works because:',0x00,'asciidoc::vectordbs.adoc::Batching Strategy::Working with Auto-Truncation::0'),
('30537618-3861-4d4a-b003-8a39532d4220','The vector store implementation can initialize the requisite schema for you, but you must opt-in by specifying the <code>initializeSchema</code> boolean in the appropriate constructor or by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\nAlternatively you can opt-out the initialization and create the index manually using the Elasticsearch client, which can be useful if the index needs advanced mapping or additional configuration.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nPlease have a look at the list of <a href=\"#elasticsearchvector-properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\nThese properties can be also set by configuring the <code>ElasticsearchVectorStoreOptions</code> bean.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nNow you can auto-wire the <code>ElasticsearchVectorStore</code> as a vector store in your application.\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList &lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to Elasticsearch\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::elasticsearch.adoc::Auto-configuration::1'),
('d6fda00a-960d-406e-b1cd-8a99b90d138e','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with Weaviate store as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(\"country in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"country\", \"UK\", \"NL\"),\n        b.gte(\"year\", 2020)).build()).build());\n\nThose (portable) filter expressions get automatically converted into the proprietary Weaviate <a href=\"https://weaviate.io/developers/weaviate/api/graphql/filters\">where filters</a>.\n\nFor example, this portable filter expression:\n\ncountry in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\n\nis converted into the proprietary Weaviate GraphQL filter format:\n\noperator: And\noperands:\n    [{\n        operator: Or\n        operands:\n            [{\n                path: [\"meta_country\"]\n                operator: Equal\n                valueText: \"UK\"\n            },\n            {\n                path: [\"meta_country\"]\n                operator: Equal\n                valueText: \"NL\"\n            }]\n    },\n    {\n        path: [\"meta_year\"]\n        operator: GreaterThanEqual\n        valueNumber: 2020\n    }]',0x00,'asciidoc::weaviate.adoc::Metadata filtering::0'),
('3ae9f105-1c3a-4d2a-96a4-8ac97ae09195','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/main/java/org/springframework/ai/mistralai/api/MistralOcrApi.java\">MistralOcrApi</a> provides a lightweight Java client for <a href=\"https://docs.mistral.ai/api/#tag/OCR\">Mistral AI OCR API</a>.\n\nHere is a simple snippet showing how to use the API programmatically:\n\nMistralOcrApi mistralAiApi = new MistralOcrApi(System.getenv(\"MISTRAL_AI_API_KEY\"));\n\nString documentUrl = \"https://arxiv.org/pdf/2201.04234\";\nMistralOcrApi.OCRRequest request = new MistralOcrApi.OCRRequest(\n        MistralOcrApi.OCRModel.MISTRAL_OCR_LATEST.getValue(), \"test_id\",\n        new MistralOcrApi.OCRRequest.DocumentURLChunk(documentUrl), List.of(0, 1, 2), true, 5, 50);\n\nResponseEntity&lt;MistralOcrApi.OCRResponse&gt; response = mistralAiApi.ocr(request);\n\nFollow the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/main/java/org/springframework/ai/mistralai/api/MistralOcrApi.java\">MistralOcrApi.java</a>\'s JavaDoc for further information.\n\nMistralOcrApi Sample\n\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/test/java/org/springframework/ai/mistralai/api/MistralOcrApiIT.java\">MistralOcrApiIT.java</a> tests provide some general examples of how to use the lightweight library.',0x00,'asciidoc::mistralai-chat.adoc::Prerequisites::Low-level MistralOcrApi Client::0'),
('36dadd3c-0c12-405d-9069-8b7201840f15','<div class=\"paragraph\">\n<p>Spring AI supports OpenAI&#8217;s text embeddings models through the OpenAI Java SDK, providing a robust and officially-maintained integration with OpenAI&#8217;s services including Microsoft Foundry and GitHub Models.</p>\n</div>\n<div class=\"admonitionblock note\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Note</div>\n</td>\n<td class=\"content\">\nThis implementation uses the official <a href=\"https://github.com/openai/openai-java\">OpenAI Java SDK</a> from OpenAI. For the alternative Spring AI implementation, see <a href=\"api/embeddings/openai-embeddings.html\">OpenAI Embeddings</a>.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"paragraph\">\n<p>OpenAI&#8217;s text embeddings measure the relatedness of text strings.\nAn embedding is a vector (list) of floating point numbers. The distance between two vectors measures their relatedness. Small distances suggest high relatedness and large distances suggest low relatedness.</p>\n</div>\n<div class=\"paragraph\">\n<p>The OpenAI SDK module automatically detects the service provider (OpenAI, Microsoft Foundry, or GitHub Models) based on the base URL you provide.</p>\n</div>',0x00,'asciidoc::openai-sdk-embeddings.adoc::0'),
('cba7af0c-251d-4332-b539-8b88cece9e7a','This section provides a guide to the <code>EmbeddingModel</code> interface and associated classes.\n\npublic interface EmbeddingModel extends Model&lt;EmbeddingRequest, EmbeddingResponse&gt; {\n\n	@Override\n	EmbeddingResponse call(EmbeddingRequest request);\n\n\n	/**\n	 * Embeds the given document\'s content into a vector.\n	 * @param document the document to embed.\n	 * @return the embedded vector.\n	 */\n	float[] embed(Document document);\n\n	/**\n	 * Embeds the given text into a vector.\n	 * @param text the text to embed.\n	 * @return the embedded vector.\n	 */\n	default float[] embed(String text) {\n		Assert.notNull(text, \"Text must not be null\");\n		return this.embed(List.of(text)).iterator().next();\n	}\n\n	/**\n	 * Embeds a batch of texts into vectors.\n	 * @param texts list of texts to embed.\n	 * @return list of list of embedded vectors.\n	 */\n	default List&lt;float[]&gt; embed(List&lt;String&gt; texts) {\n		Assert.notNull(texts, \"Texts must not be null\");\n		return this.call(new EmbeddingRequest(texts, EmbeddingOptions.EMPTY))\n			.getResults()\n			.stream()\n			.map(Embedding::getOutput)\n			.toList();\n	}\n\n	/**\n	 * Embeds a batch of texts into vectors and returns the {@link EmbeddingResponse}.\n	 * @param texts list of texts to embed.\n	 * @return the embedding response.\n	 */\n	default EmbeddingResponse embedForResponse(List&lt;String&gt; texts) {\n		Assert.notNull(texts, \"Texts must not be null\");\n		return this.call(new EmbeddingRequest(texts, EmbeddingOptions.EMPTY));\n	}\n\n	/**\n	 * @return the number of dimensions of the embedded vectors. It is generative\n	 * specific.\n	 */\n	default int dimensions() {\n		return embed(\"Test String\").size();\n	}\n\n}\n\nThe embed methods offer various options for converting text into embeddings, accommodating single strings, structured <code>Document</code> objects, or batches of text.\n\nMultiple shortcut methods are provided for embedding text, including the <code>embed(String text)</code> method, which takes a single string and returns the corresponding embedding vector.\nAll shortcuts are implemented around the <code>call</code> method, which is the primary method for invoking the embedding model.\n\nTypically the embedding returns a lists of floats, representing the embeddings in a numerical vector format.\n\nThe <code>embedForResponse</code> method provides a more comprehensive output, potentially including additional information about the embeddings.\n\nThe dimensions method is a handy tool for developers to quickly ascertain the size of the embedding vectors, which is important for understanding the embedding space and for subsequent processing steps.\n\nEmbeddingRequest\n\nThe <code>EmbeddingRequest</code> is a <code>ModelRequest</code> that takes a list of text objects and optional embedding request options.\nThe following listing shows a truncated version of the EmbeddingRequest class, excluding constructors and other utility methods:',0x00,'asciidoc::embeddings.adoc::API Overview::EmbeddingModel::0'),
('bb637d6b-9577-414a-8650-8ba99bfb8eae','In 1.0 M2, there were separate <code>RequestAdvisor</code> and <code>ResponseAdvisor</code> interfaces.\nIn 1.0 M3, these interfaces have been replaced with:\nThe <code>StreamResponseMode</code>, previously part of <code>ResponseAdvisor</code>, has been removed.\nIn 1.0.0 these interfaces have been replaced:',0x00,'asciidoc::advisors.adoc::Breaking API Changes::Advisor Interfaces::0'),
('acd3c665-364f-43b0-a577-8c34c0fec5cd','Client genAiClient = Client.builder()\n    .apiKey(System.getenv(\"GOOGLE_API_KEY\"))\n    .build();\n\nvar chatModel = new GoogleGenAiChatModel(genAiClient,\n    GoogleGenAiChatOptions.builder()\n        .model(ChatModel.GEMINI_2_0_FLASH)\n        .temperature(0.4)\n    .build());\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));',0x00,'asciidoc::google-genai-chat.adoc::Manual Configuration::Using API Key::0'),
('a6e2a9f3-7a57-43c2-9c4c-8c57f6237231','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai-sdk/src/main/java/org/springframework/ai/openaisdk/OpenAiSdkChatModel.java\">OpenAiSdkChatModel</a> implements the <code>ChatModel</code> and uses the official OpenAI Java SDK to connect to the OpenAI service.\n\nAdd the <code>spring-ai-openai-sdk</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-openai-sdk&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file:\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-openai-sdk\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create an <code>OpenAiSdkChatModel</code> and use it for text generations:\n\nvar chatOptions = OpenAiSdkChatOptions.builder()\n    .model(\"gpt-4o\")\n    .temperature(0.7)\n    .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n    .build();\n\nvar chatModel = new OpenAiSdkChatModel(chatOptions);\n\nChatResponse response = chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; response = chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));',0x00,'asciidoc::openai-sdk-chat.adoc::Manual Configuration::0'),
('696764ce-c4f0-4828-bd28-8c79da0aae9d','Ollama can access, out of the box, all <a href=\"https://huggingface.co/models?library=gguf&amp;sort=trending\">GGUF Hugging Face </a> Chat Models.\nYou can pull any of these models by name: <code>ollama pull hf.co/&lt;username&gt;/&lt;model-repository&gt;</code> or configure the auto-pulling strategy: <a href=\"#auto-pulling-models\">Auto-pulling Models</a>:\n\nspring.ai.ollama.chat.options.model=hf.co/bartowski/gemma-2-2b-it-GGUF\nspring.ai.ollama.init.pull-model-strategy=always\n\n<code>spring.ai.ollama.chat.options.model</code>: Specifies the <a href=\"https://huggingface.co/models?library=gguf&amp;sort=trending\">Hugging Face GGUF model</a> to use.\n<code>spring.ai.ollama.init.pull-model-strategy=always</code>: (optional) Enables automatic model pulling at startup time.\nFor production, you should pre-download the models to avoid delays: <code>ollama pull hf.co/bartowski/gemma-2-2b-it-GGUF</code>.',0x00,'asciidoc::ollama-chat.adoc::HuggingFace Models::0'),
('33baed18-ba6a-4c0e-aeba-8c9f556bd1cc','<div class=\"paragraph\">\n<p>Hugging Face Text Generation Inference (TGI) is a specialized deployment solution for serving Large Language Models (LLMs) in the cloud, making them accessible via an API. TGI provides optimized performance for text generation tasks through features like continuous batching, token streaming, and efficient memory management.</p>\n</div>\n<div class=\"admonitionblock important\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Important</div>\n</td>\n<td class=\"content\">\nText Generation Inference requires models to be compatible with its architecture-specific optimizations. While many popular LLMs are supported, not all models on Hugging Face Hub can be deployed using TGI. If you need to deploy other types of models, consider using standard Hugging Face Inference Endpoints instead.\n</td>\n</tr>\n</table>\n</div>\n<div class=\"admonitionblock tip\">\n<table>\n<tr>\n<td class=\"icon\">\n<div class=\"title\">Tip</div>\n</td>\n<td class=\"content\">\nFor a complete and up-to-date list of supported models and architectures, see the <a href=\"https://huggingface.co/docs/text-generation-inference/en/supported_models\">Text Generation Inference supported models documentation</a>.\n</td>\n</tr>\n</table>\n</div>',0x00,'asciidoc::huggingface.adoc::0'),
('a1d74a6b-022b-41a8-975a-8cb8f4fb287d','All vector store implementations in Spring AI are instrumented to provide metrics and distributed tracing data through Micrometer.\n\nThe <code>db.vector.client.operation</code> observations are recorded when interacting with the Vector Store.\nThey measure the time spent on the <code>query</code>, <code>add</code> and <code>remove</code> operations and propagate the related tracing information.',0x00,'asciidoc::index.adoc::Vector Stores::0'),
('ba894ae6-23db-4fe2-bca4-8cbe39afb9f6','Please refer to <a href=\"https://github.com/spring-ai-community/awesome-spring-ai\">this page</a> for more resources and samples related to Spring AI.',0x00,'asciidoc::getting-started.adoc::Spring AI samples::0'),
('34f666f0-aac9-433a-b230-8d2b910f8dea','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-oci-genai/src/main/java/org/springframework/ai/oci/cohere/OCICohereChatOptions.java\">OCICohereChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>OCICohereChatModel(api, options)</code> constructor or the <code>spring.ai.oci.genai.cohere.chat.options.*</code> properties.\n\nAt run-time you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        OCICohereChatOptions.builder()\n            .model(\"my-model-ocid\")\n            .compartment(\"my-compartment-ocid\")\n            .temperature(0.5)\n        .build()\n    ));',0x00,'asciidoc::cohere-chat.adoc::Runtime Options::0'),
('5972d948-978f-4952-918c-8d59d3e8c7de','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nStart by adding the Oracle Vector Store boot starter dependency to your project:\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-starter-vector-store-oracle&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-oracle\'\n}\n\nIf you need this vector store to initialize the schema for you then you&#8217;ll need to pass true for the <code>initializeSchema</code> boolean parameter in the appropriate constructor or by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nThe Vector Store, also requires an <code>EmbeddingModel</code> instance to calculate embeddings for the documents.\nYou can pick one of the available <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel Implementations</a>.\n\nFor example to use the <a href=\"api/embeddings/openai-embeddings.html\">OpenAI EmbeddingModel</a> add the following dependency to your project:\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nTo connect to and configure the <code>OracleVectorStore</code>, you need to provide access details for your database.\nA simple configuration can either be provided via Spring Boot&#8217;s <code>application.yml</code>\n\nspring:\n  datasource:\n    url: jdbc:oracle:thin:@//localhost:1521/freepdb1\n    username: mlops\n    password: mlops\n  ai:\n	vectorstore:\n	  oracle:\n		index-type: IVF\n		distance-type: COSINE\n		dimensions: 1536\n\nCheck the list of <a href=\"#oracle-properties\">configuration parameters</a> to learn about the default values and configuration options.\n\nNow you can Auto-wire the <code>OracleVectorStore</code> in your application and use it:',0x00,'asciidoc::oracle.adoc::Auto-Configuration::0'),
('c1c3ac8d-cde0-4d24-a0c2-8d62f70868bf','Connection Properties\n\nThe prefix <code>spring.ai.openai-sdk</code> is used as the property prefix that lets you configure the OpenAI SDK client.\n\n\n\nMicrosoft Foundry (Azure OpenAI) Properties\n\nThe OpenAI SDK implementation provides native support for Microsoft Foundry (Azure OpenAI) with automatic configuration:\n\n\n\nMicrosoft Foundry supports passwordless authentication. Add the <code>com.azure:azure-identity</code> dependency and the implementation will automatically attempt to use Azure credentials from the environment when no API key is provided.\n\nGitHub Models Properties\n\nNative support for GitHub Models is available:\n\n\n\nGitHub Models requires a Personal Access Token with the <code>models:read</code> scope. Set it via the <code>OPENAI_API_KEY</code> environment variable or the <code>spring.ai.openai-sdk.api-key</code> property.\n\nChat Model Properties\n\nThe prefix <code>spring.ai.openai-sdk.chat</code> is the property prefix for configuring the chat model implementation:\n\n\n\n<div class=\"paragraph\">\n<p>When using GPT-5 models such as <code>gpt-5</code>, <code>gpt-5-mini</code>, and <code>gpt-5-nano</code>, the <code>temperature</code> parameter is not supported.\nThese models are optimized for reasoning and do not use temperature.\nSpecifying a temperature value will result in an error.\nIn contrast, conversational models like <code>gpt-5-chat</code> do support the <code>temperature</code> parameter.</p>\n</div>\n\nAll properties prefixed with <code>spring.ai.openai-sdk.chat.options</code> can be overridden at runtime by adding request-specific <a href=\"#chat-options\">Runtime Options</a> to the <code>Prompt</code> call.',0x00,'asciidoc::openai-sdk-chat.adoc::Auto-configuration::Configuration Properties::0'),
('a1a59d20-76fe-4fd6-bbf6-8e173e87eea9','The <code>SimpleLoggerAdvisor</code> is an advisor that logs the <code>request</code> and <code>response</code> data of the <code>ChatClient</code>.\nThis can be useful for debugging and monitoring your AI interactions.\n\nSpring AI supports observability for LLM and vector store interactions.\nRefer to the <a href=\"observability/index.html\">Observability</a> guide for more information.\n\nTo enable logging, add the <code>SimpleLoggerAdvisor</code> to the advisor chain when creating your ChatClient.\nIt&#8217;s recommended to add it toward the end of the chain:\n\nChatResponse response = ChatClient.create(chatModel).prompt()\n        .advisors(new SimpleLoggerAdvisor())\n        .user(\"Tell me a joke?\")\n        .call()\n        .chatResponse();\n\nTo see the logs, set the logging level for the advisor package to <code>DEBUG</code>:\n\nlogging.level.org.springframework.ai.chat.client.advisor=DEBUG\n\nAdd this to your <code>application.properties</code> or <code>application.yaml</code> file.\n\nYou can customize what data from <code>AdvisedRequest</code> and <code>ChatResponse</code> is logged by using the following constructor:\n\nSimpleLoggerAdvisor(\n    Function&lt;ChatClientRequest, String&gt; requestToString,\n    Function&lt;ChatResponse, String&gt; responseToString,\n    int order\n)\n\nExample usage:\n\nSimpleLoggerAdvisor customLogger = new SimpleLoggerAdvisor(\n    request -&gt; \"Custom request: \" + request.prompt().getUserMessage(),\n    response -&gt; \"Custom response: \" + response.getResult(),\n    0\n);\n\nThis allows you to tailor the logged information to your specific needs.\n\nBe cautious about logging sensitive information in production environments.',0x00,'asciidoc::chatclient.adoc::Advisors::Logging::0'),
('ae306bbf-de24-45cb-bb53-8e5c8d53c145','/**\n * @author Christian Tzolov\n * @author Sun Yuhan\n */\npublic class FilterExpressionTextParserTests {\n\n    FilterExpressionTextParser parser = new FilterExpressionTextParser();\n\n    @Test\n    public void testEQ() {\n        // country == \"BG\"\n        Expression exp = this.parser.parse(\"country == \'BG\'\");\n        assertThat(exp).isEqualTo(new Expression(EQ, new Key(\"country\"), new Value(\"BG\")));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"country == \'BG\'\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void tesEqAndGte() {\n        // genre == \"drama\" AND year >= 2020\n        Expression exp = this.parser.parse(\"genre == \'drama\' && year >= 2020\");\n        assertThat(exp).isEqualTo(new Expression(AND, new Expression(EQ, new Key(\"genre\"), new Value(\"drama\")), new Expression(GTE, new Key(\"year\"), new Value(2020))));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"genre == \'drama\' && year >= 2020\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void tesIn() {\n        // genre in [\"comedy\", \"documentary\", \"drama\"]\n        Expression exp = this.parser.parse(\"genre in [\'comedy\', \'documentary\', \'drama\']\");\n        assertThat(exp).isEqualTo(new Expression(IN, new Key(\"genre\"), new Value(List.of(\"comedy\", \"documentary\", \"drama\"))));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"genre in [\'comedy\', \'documentary\', \'drama\']\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void testNe() {\n        // year >= 2020 OR country == \"BG\" AND city != \"Sofia\"\n        Expression exp = this.parser.parse(\"year >= 2020 OR country == \\\"BG\\\" AND city != \\\"Sofia\\\"\");\n        assertThat(exp).isEqualTo(new Expression(OR, new Expression(GTE, new Key(\"year\"), new Value(2020)), new Expression(AND, new Expression(EQ, new Key(\"country\"), new Value(\"BG\")), new Expression(NE, new Key(\"city\"), new Value(\"Sofia\")))));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"year >= 2020 OR country == \\\"BG\\\" AND city != \\\"Sofia\\\"\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void testGroup() {\n        // (year >= 2020 OR country == \"BG\") AND city NIN [\"Sofia\", \"Plovdiv\"]\n        Expression exp = this.parser.parse(\"(year >= 2020 OR country == \\\"BG\\\") AND city NIN [\\\"Sofia\\\", \\\"Plovdiv\\\"]\");\n        assertThat(exp).isEqualTo(new Expression(AND, new Group(new Expression(OR, new Expression(GTE, new Key(\"year\"), new Value(2020)), new Expression(EQ, new Key(\"country\"), new Value(\"BG\")))), new Expression(NIN, new Key(\"city\"), new Value(List.of(\"Sofia\", \"Plovdiv\")))));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"(year >= 2020 OR country == \\\"BG\\\") AND city NIN [\\\"Sofia\\\", \\\"Plovdiv\\\"]\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void tesBoolean() {\n        // isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]\n        Expression exp = this.parser.parse(\"isOpen == true AND year >= 2020 AND country IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"]\");\n        assertThat(exp).isEqualTo(new Expression(AND, new Expression(AND, new Expression(EQ, new Key(\"isOpen\"), new Value(true)), new Expression(GTE, new Key(\"year\"), new Value(2020))), new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"isOpen == true AND year >= 2020 AND country IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"]\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void tesNot() {\n        // NOT(isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"])\n        Expression exp = this.parser.parse(\"not(isOpen == true AND year >= 2020 AND country IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"])\");\n        assertThat(exp).isEqualTo(new Expression(NOT, new Group(new Expression(AND, new Expression(AND, new Expression(EQ, new Key(\"isOpen\"), new Value(true)), new Expression(GTE, new Key(\"year\"), new Value(2020))), new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\"))))), null));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"not(isOpen == true AND year >= 2020 AND country IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"])\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void tesNotNin() {\n        // NOT(country NOT IN [\"BG\", \"NL\", \"US\"])\n        Expression exp = this.parser.parse(\"not(country NOT IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"])\");\n        assertThat(exp).isEqualTo(new Expression(NOT, new Group(new Expression(NIN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))), null));\n    }\n\n    @Test\n    public void tesNotNin2() {\n        // NOT country NOT IN [\"BG\", \"NL\", \"US\"]\n        Expression exp = this.parser.parse(\"NOT country NOT IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"]\");\n        assertThat(exp).isEqualTo(new Expression(NOT, new Expression(NIN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\"))), null));\n    }\n\n    @Test\n    public void tesNestedNot() {\n        // NOT(isOpen == true AND year >= 2020 AND NOT(country IN [\"BG\", \"NL\", \"US\"]))\n        Expression exp = this.parser.parse(\"not(isOpen == true AND year >= 2020 AND NOT(country IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"]))\");\n        assertThat(exp).isEqualTo(new Expression(NOT, new Group(new Expression(AND, new Expression(AND, new Expression(EQ, new Key(\"isOpen\"), new Value(true)), new Expression(GTE, new Key(\"year\"), new Value(2020))), new Expression(NOT, new Group(new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))), null))), null));\n        assertThat(this.parser.getCache().get(\"WHERE \" + \"not(isOpen == true AND year >= 2020 AND NOT(country IN [\\\"BG\\\", \\\"NL\\\", \\\"US\\\"]))\")).isEqualTo(exp);\n    }\n\n    @Test\n    public void testDecimal() {\n        // temperature >= -15.6 && temperature <= +20.13\n        String expText = \"temperature >= -15.6 && temperature <= +20.13\";\n        Expression exp = this.parser.parse(expText);\n        assertThat(exp).isEqualTo(new Expression(AND, new Expression(GTE, new Key(\"temperature\"), new Value(-15.6)), new Expression(LTE, new Key(\"temperature\"), new Value(20.13))));\n        assertThat(this.parser.getCache().get(\"WHERE \" + expText)).isEqualTo(exp);\n    }\n\n    @Test\n    public void testLong() {\n        Expression exp2 = this.parser.parse(\"biz_id == 3L\");\n        Expression exp3 = this.parser.parse(\"biz_id == -5L\");\n        assertThat(exp2).isEqualTo(new Expression(EQ, new Key(\"biz_id\"), new Value(3L)));\n        assertThat(exp3).isEqualTo(new Expression(EQ, new Key(\"biz_id\"), new Value(-5L)));\n    }\n\n    @Test\n    public void testIdentifiers() {\n        Expression exp = this.parser.parse(\"\'country.1\' == \'BG\'\");\n        assertThat(exp).isEqualTo(new Expression(EQ, new Key(\"\'country.1\'\"), new Value(\"BG\")));\n        exp = this.parser.parse(\"\'country_1_2_3\' == \'BG\'\");\n        assertThat(exp).isEqualTo(new Expression(EQ, new Key(\"\'country_1_2_3\'\"), new Value(\"BG\")));\n        exp = this.parser.parse(\"\\\"country 1 2 3\\\" == \'BG\'\");\n        assertThat(exp).isEqualTo(new Expression(EQ, new Key(\"\\\"country 1 2 3\\\"\"), new Value(\"BG\")));\n    }\n\n    @Test\n    public void testUnescapedIdentifierWithUnderscores() {\n        Expression exp = this.parser.parse(\"file_name == \'medicaid-wa-faqs.pdf\'\");\n        assertThat(exp).isEqualTo(new Expression(EQ, new Key(\"file_name\"), new Value(\"medicaid-wa-faqs.pdf\")));\n    }\n}',0x01,'cu::FilterExpressionTextParserTests.java'),
('5ce12e99-421a-457a-9a4c-8eaf28b53b11','Before:\n\nChatClient.builder(chatModel)\n    .defaultFunctions(FunctionCallback.builder()\n        .function(\"getCurrentWeather\", new MockWeatherService())\n        .description(\"Get the weather in location\")\n        .inputType(MockWeatherService.Request.class)\n        .build())\n    .build()\n\nAfter:\n\nChatClient.builder(chatModel)\n    .defaultTools(FunctionToolCallback.builder(\"getCurrentWeather\", new MockWeatherService())\n        .description(\"Get the weather in location\")\n        .inputType(MockWeatherService.Request.class)\n        .build())\n    .build()',0x00,'asciidoc::tools-migration.adoc::Migration Examples::5. Default Functions in ChatClient Builder::0'),
('010abeb6-a46b-49d5-862e-8ec4ef119ee0','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Prerequisites::Add Repositories and BOM::0'),
('296ccbfb-66c3-4eb3-9bcf-8ec8524f587a','Instead of specifying tools programmatically, you can define tools as Spring beans and let Spring AI resolve them dynamically at runtime using the <code>ToolCallbackResolver</code> interface (via the <code>SpringBeanToolCallbackResolver</code> implementation). This option gives you the possibility to use any <code>Function</code>, <code>Supplier</code>, <code>Consumer</code>, or <code>BiFunction</code> bean as a tool. The bean name will be used as the tool name, and the <code>@Description</code> annotation from Spring Framework can be used to provide a description for the tool, used by the model to understand when and how to call the tool. If you don&#8217;t provide a description, the method name will be used as the tool description. However, it&#8217;s strongly recommended to provide a detailed description because that&#8217;s paramount for the model to understand the tool&#8217;s purpose and how to use it. Failing in providing a good description can lead to the model not using the tool when it should or using it incorrectly.\n\n@Configuration(proxyBeanMethods = false)\nclass WeatherTools {\n\n    WeatherService weatherService = new WeatherService();\n\n	@Bean\n	@Description(\"Get the weather in location\")\n	Function&lt;WeatherRequest, WeatherResponse&gt; currentWeather() {\n		return weatherService;\n	}\n\n}\n\nSome types are not supported. See <a href=\"#_function_tool_limitations\">Function Tool Limitations</a> for more details.\n\nThe JSON schema for the input parameters of the tool will be generated automatically. You can use the <code>@ToolParam</code> annotation to provide additional information about the input parameters, such as a description or whether the parameter is required or optional. By default, all input parameters are considered required. See <a href=\"#_json_schema\">JSON Schema</a> for more details.\n\nrecord WeatherRequest(@ToolParam(description = \"The name of a city or a country\") String location, Unit unit) {}\n\nThis tool specification approach has the drawback of not guaranteeing type safety, as the tool resolution is done at runtime. To mitigate this, you can specify the tool name explicitly using the <code>@Bean</code> annotation and storing the value in a constant, so that you can use it in a chat request instead of hard-coding the tool name.\n\n@Configuration(proxyBeanMethods = false)\nclass WeatherTools {\n\n    public static final String CURRENT_WEATHER_TOOL = \"currentWeather\";\n\n	@Bean(CURRENT_WEATHER_TOOL)\n	@Description(\"Get the weather in location\")\n	Function&lt;WeatherRequest, WeatherResponse&gt; currentWeather() {\n		...\n	}\n\n}\n\nAdding Tools to <code>ChatClient</code>\n\nWhen using the dynamic specification approach, you can pass the tool name (i.e. the function bean name) to the <code>toolNames()</code> method of <code>ChatClient</code>.\nThe tool will only be available for the specific chat request it&#8217;s added to.',0x00,'asciidoc::tools.adoc::Functions as Tools::Dynamic Specification: <code>@Bean</code>::0'),
('8538bae0-f399-4a1e-ab29-8ee0e2a2d74a','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/titan/BedrockTitanEmbeddingModel.java\">BedrockTitanEmbeddingModel</a> implements the <code>EmbeddingModel</code> and uses the <a href=\"#low-level-api\">Low-level TitanEmbeddingBedrockApi Client</a> to connect to the Bedrock Titan service.\n\nAdd the <code>spring-ai-bedrock</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-bedrock&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-bedrock\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create an <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/titan/BedrockTitanEmbeddingModel.java\">BedrockTitanEmbeddingModel</a> and use it for text embeddings:\n\nvar titanEmbeddingApi = new TitanEmbeddingBedrockApi(\n	TitanEmbeddingModel.TITAN_EMBED_IMAGE_V1.id(), Region.US_EAST_1.id());\n\nvar embeddingModel = new BedrockTitanEmbeddingModel(this.titanEmbeddingApi);\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n	.embedForResponse(List.of(\"Hello World\")); // NOTE titan does not support batch embedding.',0x00,'asciidoc::bedrock-titan-embedding.adoc::Manual Configuration::0'),
('79d4f399-f332-422b-b417-8f0679a900be','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-anthropic/src/main/java/org/springframework/ai/anthropic/AnthropicChatModel.java\">AnthropicChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"#low-level-api\">Low-level AnthropicApi Client</a> to connect to the Anthropic service.\n\nAdd the <code>spring-ai-anthropic</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-anthropic&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-anthropic\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>AnthropicChatModel</code> and use it for text generations:\n\nvar anthropicApi = new AnthropicApi(System.getenv(\"ANTHROPIC_API_KEY\"));\nvar anthropicChatOptions = AnthropicChatOptions.builder()\n            .model(\"claude-3-7-sonnet-20250219\")\n            .temperature(0.4)\n            .maxTokens(200)\n        .build()\nvar chatModel = AnthropicChatModel.builder().anthropicApi(anthropicApi)\n                .defaultOptions(anthropicChatOptions).build();\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; response = this.chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>AnthropicChatOptions</code> provides the configuration information for the chat requests.\nThe <code>AnthropicChatOptions.Builder</code> is fluent options builder.',0x00,'asciidoc::anthropic-chat.adoc::Manual Configuration::0'),
('cc75a339-ec3f-4684-b7de-8f12e052ce7f','The <code>BeanOutputConverter</code> supports custom property ordering in the generated JSON schema through the <code>@JsonPropertyOrder</code> annotation.\nThis annotation allows you to specify the exact sequence in which properties should appear in the schema, regardless of their declaration order in the class or record.\n\nFor example, to ensure specific ordering of properties in the <code>ActorsFilms</code> record:\n\n@JsonPropertyOrder({\"actor\", \"movies\"})\nrecord ActorsFilms(String actor, List&lt;String&gt; movies) {}\n\nThis annotation works with both records and regular Java classes.\n\nGeneric Bean Types\n\nUse the <code>ParameterizedTypeReference</code> constructor to specify a more complex target class structure.\nFor example, to represent a list of actors and their filmographies:\n\nList&lt;ActorsFilms&gt; actorsFilms = ChatClient.create(chatModel).prompt()\n        .user(\"Generate the filmography of 5 movies for Tom Hanks and Bill Murray.\")\n        .call()\n        .entity(new ParameterizedTypeReference&lt;List&lt;ActorsFilms&gt;&gt;() {});\n\nor using the low-level <code>ChatModel</code> API directly:\n\nBeanOutputConverter&lt;List&lt;ActorsFilms&gt;&gt; outputConverter = new BeanOutputConverter&lt;&gt;(\n        new ParameterizedTypeReference&lt;List&lt;ActorsFilms&gt;&gt;() { });\n\nString format = this.outputConverter.getFormat();\nString template = \"\"\"\n        Generate the filmography of 5 movies for Tom Hanks and Bill Murray.\n        {format}\n        \"\"\";\n\nPrompt prompt = PromptTemplate.builder().template(this.template).variables(Map.of(\"format\", this.format)).build().create();\n\nGeneration generation = chatModel.call(this.prompt).getResult();\n\nList&lt;ActorsFilms&gt; actorsFilms = this.outputConverter.convert(this.generation.getOutput().getText());',0x00,'asciidoc::structured-output-converter.adoc::Using Converters::Property Ordering in Generated Schema::0'),
('4da35430-6db0-4d82-a220-8f2ccd92a6be','Retry Properties\n\nThe prefix <code>spring.ai.retry</code> is used as the property prefix that lets you configure the retry mechanism for the OpenAI chat model.\n\n\n\nConnection Properties\n\nThe prefix <code>spring.ai.openai</code> is used as the property prefix that lets you connect to OpenAI.\n\n\n\nConfiguration Properties\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the chat auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.chat</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.chat=openai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.chat=none (or any value which doesn&#8217;t match openai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.openai.chat</code> is the property prefix that lets you configure the chat model implementation for OpenAI.\n\n\n\nAll properties prefixed with <code>spring.ai.openai.chat.options</code> can be overridden at runtime by adding a request specific <a href=\"#chat-options\">Runtime Options</a> to the <code>Prompt</code> call.',0x00,'asciidoc::groq-chat.adoc::Auto-configuration::Chat Properties::0'),
('2f1a85fa-5dce-4528-8089-8f3d4a6d0643','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nAdd the <code>spring-ai-starter-model-bedrock-converse</code> dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-bedrock-converse&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-gradle\" data-lang=\"gradle\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-bedrock-converse\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::bedrock-converse.adoc::Auto-configuration::0'),
('a4b6dd03-6a39-4690-82e2-8f9a1e488637','When using the programmatic specification approach, you can add default tools to a <code>ChatModel</code> at construction time by passing the <code>FunctionToolCallback</code> instance to the <code>toolCallbacks()</code> method of the <code>ToolCallingChatOptions</code> instance used to create the <code>ChatModel</code>.\nIf both default and runtime tools are provided, the runtime tools will completely override the default tools.\n\nDefault tools are shared across all the chat requests performed by that <code>ChatModel</code> instance. They are useful for tools that are commonly used across different chat requests, but they can also be dangerous if not used carefully, risking to make them available when they shouldn&#8217;t.\n\nToolCallback toolCallback = ...\nChatModel chatModel = OllamaChatModel.builder()\n    .ollamaApi(OllamaApi.builder().build())\n    .defaultOptions(ToolCallingChatOptions.builder()\n            .toolCallbacks(toolCallback)\n            .build())\n    .build();',0x00,'asciidoc::tools.adoc::Functions as Tools::Programmatic Specification: <code>FunctionToolCallback</code>::2'),
('0d943ff2-af77-4083-b086-9023350bd68a','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::anthropic-chat.adoc::Prerequisites::Add Repositories and BOM::0'),
('4ad176f7-0a53-44ad-b8fc-90346c64c70c','If you are not using Spring Boot, you can manually configure the Onnx Transformers Embedding Model.\nFor this add the <code>spring-ai-transformers</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n  &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n  &lt;artifactId&gt;spring-ai-transformers&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nthen create a new <code>TransformersEmbeddingModel</code> instance and use the <code>setTokenizerResource(tokenizerJsonUri)</code> and <code>setModelResource(modelOnnxUri)</code> methods to set the URIs  of the exported <code>tokenizer.json</code> and <code>model.onnx</code> files. (<code>classpath:</code>, <code>file:</code> or <code>https:</code> URI schemas are supported).\n\nIf the model is not explicitly set, <code>TransformersEmbeddingModel</code> defaults to <a href=\"https://huggingface.co/sentence-transformers/all-MiniLM-L6-v2\">sentence-transformers/all-MiniLM-L6-v2</a>:\n\n\n\nThe following snippet illustrates how to use the <code>TransformersEmbeddingModel</code> manually:\n\nTransformersEmbeddingModel embeddingModel = new TransformersEmbeddingModel();\n\n// (optional) defaults to classpath:/onnx/all-MiniLM-L6-v2/tokenizer.json\nembeddingModel.setTokenizerResource(\"classpath:/onnx/all-MiniLM-L6-v2/tokenizer.json\");\n\n// (optional) defaults to classpath:/onnx/all-MiniLM-L6-v2/model.onnx\nembeddingModel.setModelResource(\"classpath:/onnx/all-MiniLM-L6-v2/model.onnx\");\n\n// (optional) defaults to ${java.io.tmpdir}/spring-ai-onnx-model\n// Only the http/https resources are cached by default.\nembeddingModel.setResourceCacheDirectory(\"/tmp/onnx-zoo\");\n\n// (optional) Set the tokenizer padding if you see an errors like:\n// \"ai.onnxruntime.OrtException: Supplied array is ragged, ...\"\nembeddingModel.setTokenizerOptions(Map.of(\"padding\", \"true\"));\n\nembeddingModel.afterPropertiesSet();\n\nList&lt;List&lt;Double&gt;&gt; embeddings = this.embeddingModel.embed(List.of(\"Hello world\", \"World is big\"));\n\nIf you create an instance of <code>TransformersEmbeddingModel</code> manually, you must call the <code>afterPropertiesSet()</code> method after setting the properties and before using the client.\n\nThe first <code>embed()</code> call downloads the large ONNX model and caches it on the local file system.\nTherefore, the first call might take longer than usual.\nUse the <code>#setResourceCacheDirectory(&lt;path&gt;)</code> method to set the local folder where the ONNX models as stored.\nThe default cache folder is <code>${java.io.tmpdir}/spring-ai-onnx-model</code>.\n\nIt is more convenient (and preferred) to create the TransformersEmbeddingModel as a <code>Bean</code>.\nThen you don&#8217;t have to call the <code>afterPropertiesSet()</code> manually.\n\n@Bean\npublic EmbeddingModel embeddingModel() {\n   return new TransformersEmbeddingModel();\n}',0x00,'asciidoc::onnx.adoc::Manual Configuration::0'),
('f6a87c47-da33-41d4-9c76-905998a4029f','You can also use thinking with streaming responses:\n\nChatClient chatClient = ChatClient.create(chatModel);\n\n// For Claude 3.7 Sonnet - explicit thinking configuration\nFlux&lt;ChatResponse&gt; responseFlux = chatClient.prompt()\n    .options(AnthropicChatOptions.builder()\n        .model(\"claude-3-7-sonnet-latest\")\n        .temperature(1.0)\n        .maxTokens(8192)\n        .thinking(AnthropicApi.ThinkingType.ENABLED, 2048)\n        .build())\n    .user(\"Are there an infinite number of prime numbers such that n mod 4 == 3?\")\n    .stream();\n\n// For Claude 4 models - thinking is enabled by default\nFlux&lt;ChatResponse&gt; responseFlux4 = chatClient.prompt()\n    .options(AnthropicChatOptions.builder()\n        .model(\"claude-opus-4-0\")\n        .maxTokens(8192)\n        // No explicit thinking configuration needed\n        .build())\n    .user(\"Are there an infinite number of prime numbers such that n mod 4 == 3?\")\n    .stream();\n\n// For streaming, you might want to collect just the text responses\nString textContent = responseFlux.collectList()\n    .block()\n    .stream()\n    .map(ChatResponse::getResults)\n    .flatMap(List::stream)\n    .map(Generation::getOutput)\n    .map(AssistantMessage::getText)\n    .filter(text -&gt; text != null &amp;&amp; !text.isBlank())\n    .collect(Collectors.joining());',0x00,'asciidoc::anthropic-chat.adoc::Thinking::Streaming Example::0'),
('e7338a2f-67ec-4734-934c-90eeb5a7cacd','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-bedrock</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the Cohere Embedding model:\n\nspring.ai.bedrock.aws.region=eu-central-1\nspring.ai.bedrock.aws.access-key=${AWS_ACCESS_KEY_ID}\nspring.ai.bedrock.aws.secret-key=${AWS_SECRET_ACCESS_KEY}\n\nspring.ai.model.embedding=bedrock-cohere\nspring.ai.bedrock.cohere.embedding.options.input-type=search-document\n\nreplace the <code>regions</code>, <code>access-key</code> and <code>secret-key</code> with your AWS credentials.\n\nThis will create a <code>BedrockCohereEmbeddingModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Sample Controller::0'),
('59f1e2ef-da60-46b5-b180-90f0703ccd4e','Spring AI does not provide a dedicated module for SAP Hana vector store.\nUsers are expected to provide their own configuration in the applications using the standard vector store module for SAP Hana vector store in Spring AI - <code>spring-ai-hanadb-store</code>.\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nPlease have a look at the list of <a href=\"#hanacloudvectorstore-properties\">HanaCloudVectorStore Properties</a> for the vector store to learn about the default values and configuration options.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.',0x00,'asciidoc::hana.adoc::Auto-configuration::0'),
('279b2551-90b5-42ee-b38d-91c03f1a7c8d','Citations contain different location information depending on the document type:\n\nCharacter Location (Plain Text)\n\nFor plain text documents, citations include character indices:\n\nCitation citation = citations.get(0);\nif (citation.getType() == Citation.LocationType.CHAR_LOCATION) {\n    int start = citation.getStartCharIndex();\n    int end = citation.getEndCharIndex();\n    String text = citation.getCitedText();\n    System.out.println(\"Characters \" + start + \"-\" + end + \": \" + text);\n}\n\nPage Location (PDF)\n\nFor PDF documents, citations include page numbers:\n\nCitation citation = citations.get(0);\nif (citation.getType() == Citation.LocationType.PAGE_LOCATION) {\n    int startPage = citation.getStartPageNumber();\n    int endPage = citation.getEndPageNumber();\n    System.out.println(\"Pages \" + startPage + \"-\" + endPage);\n}\n\nContent Block Location (Custom Content)\n\nFor custom content, citations reference specific content blocks:\n\nCitation citation = citations.get(0);\nif (citation.getType() == Citation.LocationType.CONTENT_BLOCK_LOCATION) {\n    int startBlock = citation.getStartBlockIndex();\n    int endBlock = citation.getEndBlockIndex();\n    System.out.println(\"Content blocks \" + startBlock + \"-\" + endBlock);\n}',0x00,'asciidoc::anthropic-chat.adoc::Citations::Citation Types::0'),
('b00d590c-e32c-40b6-a934-9255341f4d48','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with GemFire VectorStore as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(5)\n        .similarityThreshold(0.7)\n        .filterExpression(\"country == \'BG\' &amp;&amp; year &gt;= 2020\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(5)\n        .similarityThreshold(0.7)\n        .filterExpression(b.and(\n                b.eq(\"country\", \"BG\"),\n                b.gte(\"year\", 2020)).build()).build());\n\nThose (portable) filter expressions get automatically converted into the proprietary GemFire VectorDB query format.\n\nFor example, this portable filter expression:\n\ncountry == \'BG\' &amp;&amp; year &gt;= 2020\n\nis converted into the proprietary GemFire VectorDB filter format:\n\ncountry:BG AND year:[2020 TO *]\n\nThe GemFire VectorStore supports a wide range of filter operations:\n\n<strong>Equality</strong>: <code>country == \'BG\'</code> → <code>country:BG</code>\n<strong>Inequality</strong>: <code>city != \'Sofia\'</code> → <code>city: NOT Sofia</code>\n<strong>Greater Than</strong>: <code>year &gt; 2020</code> → <code>year:{2020 TO *]</code>\n<strong>Greater Than or Equal</strong>: <code>year &gt;= 2020</code> → <code>year:[2020 TO *]</code>\n<strong>Less Than</strong>: <code>year &lt; 2025</code> → <code>year:[* TO 2025}</code>\n<strong>Less Than or Equal</strong>: <code>year &#8656; 2025</code> → <code>year:[* TO 2025]</code>\n<strong>IN</strong>: <code>country in [\'BG\', \'NL\']</code> → <code>country:(BG OR NL)</code>\n<strong>NOT IN</strong>: <code>country nin [\'BG\', \'NL\']</code> → <code>NOT country:(BG OR NL)</code>\n<strong>AND/OR</strong>: Logical operators for combining conditions\n<strong>Grouping</strong>: Use parentheses for complex expressions\n<strong>Date Filtering</strong>: Date values in ISO 8601 format (e.g., <code>2024-01-07T14:29:12Z</code>)\n\n\n<div class=\"paragraph\">\n<p>To use metadata filtering with GemFire VectorStore, you must specify the metadata fields that can be filtered when creating the vector store. This is done using the <code>fields</code> parameter in the builder:</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-java\" data-lang=\"java\">GemFireVectorStore.builder(embeddingModel)\n    .fields(new String[] {\"country\", \"year\", \"activationDate\"})\n    .build();</code></pre>\n</div>\n</div>\n<div class=\"paragraph\">\n<p>Or via configuration properties:</p>\n</div>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-properties\" data-lang=\"properties\">spring.ai.vectorstore.gemfire.fields=country,year,activationDate</code></pre>\n</div>\n</div>',0x00,'asciidoc::gemfire.adoc::Metadata Filtering::0'),
('754843cd-0b73-4d1d-9cb5-92bef05c2b27','/**\n * @author Christian Tzolov\n */\npublic class FilterExpressionBuilderTests {\n\n    FilterExpressionBuilder b = new FilterExpressionBuilder();\n\n    @Test\n    public void testEQ() {\n        // country == \"BG\"\n        assertThat(this.b.eq(\"country\", \"BG\").build()).isEqualTo(new Expression(EQ, new Key(\"country\"), new Value(\"BG\")));\n    }\n\n    @Test\n    public void tesEqAndGte() {\n        // genre == \"drama\" AND year >= 2020\n        Expression exp = this.b.and(this.b.eq(\"genre\", \"drama\"), this.b.gte(\"year\", 2020)).build();\n        assertThat(exp).isEqualTo(new Expression(AND, new Expression(EQ, new Key(\"genre\"), new Value(\"drama\")), new Expression(GTE, new Key(\"year\"), new Value(2020))));\n    }\n\n    @Test\n    public void testIn() {\n        // genre in [\"comedy\", \"documentary\", \"drama\"]\n        var exp = this.b.in(\"genre\", \"comedy\", \"documentary\", \"drama\").build();\n        assertThat(exp).isEqualTo(new Expression(IN, new Key(\"genre\"), new Value(List.of(\"comedy\", \"documentary\", \"drama\"))));\n    }\n\n    @Test\n    public void testNe() {\n        // year >= 2020 OR country == \"BG\" AND city != \"Sofia\"\n        var exp = this.b.and(this.b.or(this.b.gte(\"year\", 2020), this.b.eq(\"country\", \"BG\")), this.b.ne(\"city\", \"Sofia\")).build();\n        assertThat(exp).isEqualTo(new Expression(AND, new Expression(OR, new Expression(GTE, new Key(\"year\"), new Value(2020)), new Expression(EQ, new Key(\"country\"), new Value(\"BG\"))), new Expression(NE, new Key(\"city\"), new Value(\"Sofia\"))));\n    }\n\n    @Test\n    public void testGroup() {\n        // (year >= 2020 OR country == \"BG\") AND city NIN [\"Sofia\", \"Plovdiv\"]\n        var exp = this.b.and(this.b.group(this.b.or(this.b.gte(\"year\", 2020), this.b.eq(\"country\", \"BG\"))), this.b.nin(\"city\", \"Sofia\", \"Plovdiv\")).build();\n        assertThat(exp).isEqualTo(new Expression(AND, new Group(new Expression(OR, new Expression(GTE, new Key(\"year\"), new Value(2020)), new Expression(EQ, new Key(\"country\"), new Value(\"BG\")))), new Expression(NIN, new Key(\"city\"), new Value(List.of(\"Sofia\", \"Plovdiv\")))));\n    }\n\n    @Test\n    public void tesIn2() {\n        // isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]\n        var exp = this.b.and(this.b.and(this.b.eq(\"isOpen\", true), this.b.gte(\"year\", 2020)), this.b.in(\"country\", \"BG\", \"NL\", \"US\")).build();\n        assertThat(exp).isEqualTo(new Expression(AND, new Expression(AND, new Expression(EQ, new Key(\"isOpen\"), new Value(true)), new Expression(GTE, new Key(\"year\"), new Value(2020))), new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))));\n    }\n\n    @Test\n    public void tesNot() {\n        // isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]\n        var exp = this.b.not(this.b.and(this.b.and(this.b.eq(\"isOpen\", true), this.b.gte(\"year\", 2020)), this.b.in(\"country\", \"BG\", \"NL\", \"US\"))).build();\n        assertThat(exp).isEqualTo(new Expression(NOT, new Expression(AND, new Expression(AND, new Expression(EQ, new Key(\"isOpen\"), new Value(true)), new Expression(GTE, new Key(\"year\"), new Value(2020))), new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))), null));\n    }\n\n    @Test\n    public void testLessThanOperators() {\n        // value < 1\n        var ltExp = this.b.lt(\"value\", 1).build();\n        assertThat(ltExp).isEqualTo(new Expression(LT, new Key(\"value\"), new Value(1)));\n        // value <= 1\n        var lteExp = this.b.lte(\"value\", 1).build();\n        assertThat(lteExp).isEqualTo(new Expression(LTE, new Key(\"value\"), new Value(1)));\n    }\n\n    @Test\n    public void testGreaterThanOperators() {\n        // value > 1\n        var gtExp = this.b.gt(\"value\", 1).build();\n        assertThat(gtExp).isEqualTo(new Expression(GT, new Key(\"value\"), new Value(1)));\n        // value >= 10\n        var gteExp = this.b.gte(\"value\", 10).build();\n        assertThat(gteExp).isEqualTo(new Expression(GTE, new Key(\"value\"), new Value(10)));\n    }\n\n    @Test\n    public void testNullValues() {\n        // status == null\n        var exp = this.b.eq(\"status\", null).build();\n        assertThat(exp).isEqualTo(new Expression(EQ, new Key(\"status\"), new Value(null)));\n    }\n\n    @Test\n    public void testEmptyInClause() {\n        // category IN []\n        var exp = this.b.in(\"category\").build();\n        assertThat(exp).isEqualTo(new Expression(IN, new Key(\"category\"), new Value(List.of())));\n    }\n\n    @Test\n    public void testSingleValueInClause() {\n        // type IN [\"basic\"]\n        var exp = this.b.in(\"type\", \"basic\").build();\n        assertThat(exp).isEqualTo(new Expression(IN, new Key(\"type\"), new Value(List.of(\"basic\"))));\n    }\n\n    @Test\n    public void testComplexNestedGroups() {\n        // ((level >= 1 AND level <= 5) OR status == \"special\") AND (region IN [\"north\",\n        // \"south\"] OR enabled == true)\n        var exp = this.b.and(this.b.or(this.b.group(this.b.and(this.b.gte(\"level\", 1), this.b.lte(\"level\", 5))), this.b.eq(\"status\", \"special\")), this.b.group(this.b.or(this.b.in(\"region\", \"north\", \"south\"), this.b.eq(\"enabled\", true)))).build();\n        Expression expected = new Expression(AND, new Expression(OR, new Group(new Expression(AND, new Expression(GTE, new Key(\"level\"), new Value(1)), new Expression(LTE, new Key(\"level\"), new Value(5)))), new Expression(EQ, new Key(\"status\"), new Value(\"special\"))), new Group(new Expression(OR, new Expression(IN, new Key(\"region\"), new Value(List.of(\"north\", \"south\"))), new Expression(EQ, new Key(\"enabled\"), new Value(true)))));\n        assertThat(exp).isEqualTo(expected);\n    }\n\n    @Test\n    public void testNotWithSimpleExpression() {\n        // NOT (active == true)\n        var exp = this.b.not(this.b.eq(\"active\", true)).build();\n        assertThat(exp).isEqualTo(new Expression(NOT, new Expression(EQ, new Key(\"active\"), new Value(true)), null));\n    }\n\n    @Test\n    public void testNotWithGroup() {\n        // NOT (level >= 3 AND region == \"east\")\n        var exp = this.b.not(this.b.group(this.b.and(this.b.gte(\"level\", 3), this.b.eq(\"region\", \"east\")))).build();\n        Expression expected = new Expression(NOT, new Group(new Expression(AND, new Expression(GTE, new Key(\"level\"), new Value(3)), new Expression(EQ, new Key(\"region\"), new Value(\"east\")))), null);\n        assertThat(exp).isEqualTo(expected);\n    }\n\n    @Test\n    public void testMultipleNotOperators() {\n        // NOT (NOT (active == true))\n        var exp = this.b.not(this.b.not(this.b.eq(\"active\", true))).build();\n        Expression expected = new Expression(NOT, new Expression(NOT, new Expression(EQ, new Key(\"active\"), new Value(true)), null), null);\n        assertThat(exp).isEqualTo(expected);\n    }\n\n    @Test\n    public void testSpecialCharactersInKeys() {\n        // \"item.name\" == \"test\" AND \"meta-data\" != null\n        var exp = this.b.and(this.b.eq(\"item.name\", \"test\"), this.b.ne(\"meta-data\", null)).build();\n        Expression expected = new Expression(AND, new Expression(EQ, new Key(\"item.name\"), new Value(\"test\")), new Expression(NE, new Key(\"meta-data\"), new Value(null)));\n        assertThat(exp).isEqualTo(expected);\n    }\n\n    @Test\n    public void testEmptyStringValues() {\n        // description == \"\" OR label != \"\"\n        var exp = this.b.or(this.b.eq(\"description\", \"\"), this.b.ne(\"label\", \"\")).build();\n        Expression expected = new Expression(OR, new Expression(EQ, new Key(\"description\"), new Value(\"\")), new Expression(NE, new Key(\"label\"), new Value(\"\")));\n        assertThat(exp).isEqualTo(expected);\n    }\n}',0x01,'cu::FilterExpressionBuilderTests.java'),
('da794c98-667e-437f-82e8-92c620dbd1ba','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-ollama/src/main/java/org/springframework/ai/ollama/api/OllamaApi.java\">OllamaApi</a> provides a lightweight Java client for the Ollama Chat Completion API <a href=\"https://github.com/ollama/ollama/blob/main/docs/api.md#generate-a-chat-completion\">Ollama Chat Completion API</a>.\n\nThe following class diagram illustrates the <code>OllamaApi</code> chat interfaces and building blocks:\n\nThe <code>OllamaApi</code> is a low-level API and is not recommended for direct use. Use the <code>OllamaChatModel</code> instead.\n\nHere is a simple snippet showing how to use the API programmatically:\n\nOllamaApi ollamaApi = new OllamaApi(\"YOUR_HOST:YOUR_PORT\");\n\n// Sync request\nvar request = ChatRequest.builder(\"orca-mini\")\n    .stream(false) // not streaming\n    .messages(List.of(\n            Message.builder(Role.SYSTEM)\n                .content(\"You are a geography teacher. You are talking to a student.\")\n                .build(),\n            Message.builder(Role.USER)\n                .content(\"What is the capital of Bulgaria and what is the size? \"\n                        + \"What is the national anthem?\")\n                .build()))\n    .options(OllamaChatOptions.builder().temperature(0.9).build())\n    .build();\n\nChatResponse response = this.ollamaApi.chat(this.request);\n\n// Streaming request\nvar request2 = ChatRequest.builder(\"orca-mini\")\n    .ttream(true) // streaming\n    .messages(List.of(Message.builder(Role.USER)\n        .content(\"What is the capital of Bulgaria and what is the size? \" + \"What is the national anthem?\")\n        .build()))\n    .options(OllamaChatOptions.builder().temperature(0.9).build().toMap())\n    .build();\n\nFlux&lt;ChatResponse&gt; streamingResponse = this.ollamaApi.streamingChat(this.request2);',0x00,'asciidoc::ollama-chat.adoc::Low-level OllamaApi Client::0'),
('6323eada-a1c1-4bf4-a551-930ec78ed1e3','For Microsoft Foundry:\n\nvar embeddingOptions = OpenAiSdkEmbeddingOptions.builder()\n    .baseUrl(\"https://your-resource.openai.azure.com\")\n    .apiKey(System.getenv(\"OPENAI_API_KEY\"))\n    .deploymentName(\"text-embedding-ada-002\")\n    .azureOpenAIServiceVersion(AzureOpenAIServiceVersion.V2024_10_01_PREVIEW)\n    .azure(true)  // Enables Microsoft Foundry mode\n    .build();\n\nvar embeddingModel = new OpenAiSdkEmbeddingModel(embeddingOptions);\n\nMicrosoft Foundry supports passwordless authentication. Add the <code>com.azure:azure-identity</code> dependency to your project. If you don&#8217;t provide an API key, the implementation will automatically attempt to use Azure credentials from your environment.',0x00,'asciidoc::openai-sdk-embeddings.adoc::Manual Configuration::Microsoft Foundry Configuration::0'),
('c973c93b-fcf2-40cf-96b8-932f43cbb946','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Redis Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-redis&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-redis\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nThe vector store implementation can initialize the requisite schema for you, but you must opt-in by specifying the <code>initializeSchema</code> boolean in the appropriate constructor or by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nPlease have a look at the list of <a href=\"#redisvector-properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nNow you can auto-wire the <code>RedisVectorStore</code> as a vector store in your application.\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList &lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to Redis\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::redis.adoc::Auto-configuration::0'),
('a8415dc0-e5a4-45fc-b04e-933c750a4f1a','Instead of using the Spring Boot auto-configuration, you can manually configure the MongoDB Atlas vector store. For this you need to add the <code>spring-ai-mongodb-atlas-store</code> to your project:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-mongodb-atlas-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file:\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-mongodb-atlas-store\'\n}\n\nCreate a <code>MongoTemplate</code> bean:\n\n@Bean\npublic MongoTemplate mongoTemplate() {\n    return new MongoTemplate(MongoClients.create(\"&lt;mongodb atlas connection string&gt;\"), \"&lt;database name&gt;\");\n}\n\nThen create the <code>MongoDBAtlasVectorStore</code> bean using the builder pattern:\n\n@Bean\npublic VectorStore vectorStore(MongoTemplate mongoTemplate, EmbeddingModel embeddingModel) {\n    return MongoDBAtlasVectorStore.builder(mongoTemplate, embeddingModel)\n        .collectionName(\"custom_vector_store\")           // Optional: defaults to \"vector_store\"\n        .vectorIndexName(\"custom_vector_index\")          // Optional: defaults to \"vector_index\"\n        .pathName(\"custom_embedding\")                    // Optional: defaults to \"embedding\"\n        .numCandidates(500)                             // Optional: defaults to 200\n        .metadataFieldsToFilter(List.of(\"author\", \"year\")) // Optional: defaults to empty list\n        .initializeSchema(true)                         // Optional: defaults to false\n        .batchingStrategy(new TokenCountBatchingStrategy()) // Optional: defaults to TokenCountBatchingStrategy\n        .build();\n}\n\n// This can be any EmbeddingModel implementation\n@Bean\npublic EmbeddingModel embeddingModel() {\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}',0x00,'asciidoc::mongodb.adoc::Manual Configuration::0'),
('84db6177-2a9c-40e0-9cad-936f08464471','Starting with Sonnet 3.5 <a href=\"https://docs.anthropic.com/en/docs/build-with-claude/pdf-support\">PDF support (beta)</a> is provided.\nUse the <code>application/pdf</code> media type to attach a PDF file to the message:\n\nvar pdfData = new ClassPathResource(\"/spring-ai-reference-overview.pdf\");\n\nvar userMessage = new UserMessage(\n        \"You are a very professional document summarization specialist. Please summarize the given document.\",\n        List.of(new Media(new MimeType(\"application\", \"pdf\"), pdfData)));\n\nvar response = this.chatModel.call(new Prompt(List.of(userMessage)));',0x00,'asciidoc::anthropic-chat.adoc::Multimodal::PDF::0'),
('ae64435c-82a6-4ffa-b4db-939f7a1b1456','Choose one of the following authentication methods:',0x00,'asciidoc::google-genai-chat.adoc::Prerequisites::0'),
('ed66b724-6e01-4ae1-a381-93b341f01ce8','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-minimax/src/main/java/org/springframework/ai/minimax/MiniMaxChatOptions.java\">MiniMaxChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>MiniMaxChatModel(api, options)</code> constructor or the <code>spring.ai.minimax.chat.options.*</code> properties.\n\nAt run-time you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        MiniMaxChatOptions.builder()\n            .model(MiniMaxApi.ChatModel.ABAB_6_5_S_Chat.getValue())\n            .temperature(0.5)\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-minimax/src/main/java/org/springframework/ai/minimax/MiniMaxChatOptions.java\">MiniMaxChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::minimax-chat.adoc::Runtime Options::0'),
('46d62357-9eee-436e-aaf2-93c8b02f04f8','public class EmbeddingRequest implements ModelRequest&lt;List&lt;String&gt;&gt; {\n	private final List&lt;String&gt; inputs;\n	private final EmbeddingOptions options;\n	// other methods omitted\n}\n\nEmbeddingResponse\n\nThe structure of the <code>EmbeddingResponse</code> class is as follows:\n\npublic class EmbeddingResponse implements ModelResponse&lt;Embedding&gt; {\n\n	private List&lt;Embedding&gt; embeddings;\n	private EmbeddingResponseMetadata metadata = new EmbeddingResponseMetadata();\n	// other methods omitted\n}\n\nThe <code>EmbeddingResponse</code> class holds the AI Model&#8217;s output, with each <code>Embedding</code> instance containing the result vector data from a single text input.\n\nThe <code>EmbeddingResponse</code> class also carries a <code>EmbeddingResponseMetadata</code> metadata about the AI Model&#8217;s response.\n\nEmbedding\n\nThe <code>Embedding</code> represents a single embedding vector.\n\npublic class Embedding implements ModelResult&lt;float[]&gt; {\n	private float[] embedding;\n	private Integer index;\n	private EmbeddingResultMetadata metadata;\n	// other methods omitted\n}',0x00,'asciidoc::embeddings.adoc::API Overview::EmbeddingModel::1'),
('512b7444-b73b-4db8-811c-940ce44bc50c','/**\n * Common properties for vector stores.\n *\n * @author Josh Long\n * @author Soby Chacko\n */\npublic class CommonVectorStoreProperties {\n\n    /**\n     * Vector stores do not initialize schema by default on application startup. The\n     * applications explicitly need to opt-in for initializing the schema on startup. The\n     * recommended way to initialize the schema on startup is to set the initialize-schema\n     * property on the vector store. See {@link #setInitializeSchema(boolean)}.\n     */\n    private boolean initializeSchema = false;\n\n    public boolean isInitializeSchema() {\n        return this.initializeSchema;\n    }\n\n    public void setInitializeSchema(boolean initializeSchema) {\n        this.initializeSchema = initializeSchema;\n    }\n}',0x01,'cu::CommonVectorStoreProperties.java'),
('1c2d852d-8455-4932-8d3c-948ae3f9c86e','public class VectorStoreRuntimeHintsTests {\n\n    @Test\n    void vectorStoreRuntimeHints() {\n        var runtimeHints = new RuntimeHints();\n        var vectorStoreHints = new VectorStoreRuntimeHints();\n        vectorStoreHints.registerHints(runtimeHints, null);\n        assertThat(runtimeHints).matches(resource().forResource(\"antlr4/org/springframework/ai/vectorstore/filter/antlr4/Filters.g4\"));\n    }\n\n    @Test\n    void registerHintsWithNullClassLoader() {\n        var runtimeHints = new RuntimeHints();\n        var vectorStoreHints = new VectorStoreRuntimeHints();\n        // Should not throw exception with null ClassLoader\n        assertThatCode(() -> vectorStoreHints.registerHints(runtimeHints, null)).doesNotThrowAnyException();\n    }\n\n    @Test\n    void ensureResourceHintsAreRegistered() {\n        var runtimeHints = new RuntimeHints();\n        var vectorStoreHints = new VectorStoreRuntimeHints();\n        vectorStoreHints.registerHints(runtimeHints, null);\n        // Ensure the specific ANTLR resource is registered\n        assertThat(runtimeHints).matches(resource().forResource(\"antlr4/org/springframework/ai/vectorstore/filter/antlr4/Filters.g4\"));\n    }\n\n    @Test\n    void verifyResourceHintsForDifferentPaths() {\n        var runtimeHints = new RuntimeHints();\n        var vectorStoreHints = new VectorStoreRuntimeHints();\n        vectorStoreHints.registerHints(runtimeHints, null);\n        // Test that the exact resource path is registered\n        assertThat(runtimeHints).matches(resource().forResource(\"antlr4/org/springframework/ai/vectorstore/filter/antlr4/Filters.g4\"));\n        // Verify that similar but incorrect paths are not matched\n        assertThat(runtimeHints).doesNotMatch(resource().forResource(\"antlr4/Filters.g4\"));\n        assertThat(runtimeHints).doesNotMatch(resource().forResource(\"org/springframework/ai/vectorstore/Filters.g4\"));\n    }\n}',0x01,'cu::VectorStoreRuntimeHintsTests.java'),
('1ff9932a-962a-4fd9-a27f-94a95295750d','Creating a <code>ChatClient</code> with a default system text in an <code>@Configuration</code> class simplifies runtime code.\nBy setting defaults, you only need to specify the user text when calling <code>ChatClient</code>, eliminating the need to set a system text for each request in your runtime code path.',0x00,'asciidoc::chatclient.adoc::Using Defaults::0'),
('daa471dc-8403-4bf5-b530-94dae6c74a91','Ensures uniform content formats across all documents.',0x00,'asciidoc::etl-pipeline.adoc::Transformers::ContentFormatTransformer::0'),
('f48a3da3-4b06-4353-b054-9504f79d4fb0','Refer to the <a href=\"ROOT:api/retrieval-augmented-generation.html\">Retrieval Augmented Generation</a> guide.',0x00,'asciidoc::chatclient.adoc::Advisors::Retrieval Augmented Generation::0'),
('e03b8d69-68ee-4947-8715-950ab297dfab','You can automate the upgrade process to 1.0.0-M7 using the Claude Code CLI tool with a provided prompt:\n\nDownload the <a href=\"https://docs.anthropic.com/en/docs/agents-and-tools/claude-code/overview\">Claude Code CLI tool</a>\nCopy the prompt from the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/src/prompts/update-to-m7.txt\">update-to-m7.txt</a> file\nPaste the prompt into the Claude Code CLI\nThe AI will analyze your project and make the necessary changes\n\n\nThe automated upgrade prompt currently handles artifact ID changes, package relocations, and module structure changes, but does not yet include automatic changes for upgrading to MCP 0.9.0. If you&#8217;re using MCP, you&#8217;ll need to manually update your code following the guidance in the <a href=\"upgrade-notes.html#mcp-java-sdk-upgrade-to-0-9-0\">MCP Java SDK Upgrade</a> section.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M7::Automating upgrading using AI::0'),
('8aa7da04-169b-437c-bdba-951ea71c5dfd','<a href=\"https://github.com/jbellis/jvector\">JVector</a> is a pure Java embedded vector search engine.\n\nIt stands out from other HNSW Vector Similarity Search implementations by being:\n\nAlgorithmic-fast. JVector uses state of the art graph algorithms inspired by DiskANN and related research that offer high recall and low latency.\nImplementation-fast. JVector uses the Panama SIMD API to accelerate index build and queries.\nMemory efficient. JVector compresses vectors using product quantization so they can stay in memory during searches.\nDisk-aware. JVector&#8217;s disk layout is designed to do the minimum necessary iops at query time.\nConcurrent. Index builds scale linearly to at least 32 threads. Double the threads, half the build time.\nIncremental. Query your index as you build it. No delay between adding a vector and being able to find it in search results.\nEasy to embed. API designed for easy embedding, by people using it in production.',0x00,'asciidoc::apache-cassandra.adoc::What is JVector?::0'),
('07d9f7e4-ca8f-4ff5-8502-95402252521c','The Google GenAI implementation is built on the new Google GenAI Java SDK, which provides a modern, streamlined API for accessing Gemini models.',0x00,'asciidoc::google-genai-chat.adoc::Low-level Java Client::0'),
('09eb87a1-628b-41f4-bd11-95a08de3bce5','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai-sdk/src/main/java/org/springframework/ai/openaisdk/OpenAiSdkChatOptions.java\">OpenAiSdkChatOptions.java</a> class provides model configurations such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>OpenAiSdkChatModel(options)</code> constructor or the <code>spring.ai.openai-sdk.chat.options.*</code> properties.\n\nAt run-time, you can override the default options by adding new, request-specific options to the <code>Prompt</code> call.\nFor example, to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        OpenAiSdkChatOptions.builder()\n            .model(\"gpt-4o\")\n            .temperature(0.4)\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai-sdk/src/main/java/org/springframework/ai/openaisdk/OpenAiSdkChatOptions.java\">OpenAiSdkChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::openai-sdk-chat.adoc::Runtime Options::0'),
('25b1ce1b-d24c-4d25-89c2-95c09a60b41f','<div class=\"paragraph\">\n<p>This section walks you through setting up <code>CassandraVectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>',0x00,'asciidoc::apache-cassandra.adoc::0'),
('78ffac9a-1e06-415c-a7bc-961783ae09f8','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-openai-sdk</code> to your pom (or gradle) dependencies.\n\nAdd an <code>application.properties</code> file under the <code>src/main/resources</code> directory to configure the OpenAI SDK chat model:\n\nspring.ai.openai-sdk.api-key=YOUR_API_KEY\nspring.ai.openai-sdk.chat.options.model=gpt-5-mini\nspring.ai.openai-sdk.chat.options.temperature=0.7\n\nReplace the <code>api-key</code> with your OpenAI credentials.\n\nThis will create an <code>OpenAiSdkChatModel</code> implementation that you can inject into your classes.\nHere is an example of a simple <code>@RestController</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final OpenAiSdkChatModel chatModel;\n\n    @Autowired\n    public ChatController(OpenAiSdkChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map&lt;String,String&gt; generate(\n            @RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n    public Flux&lt;ChatResponse&gt; generateStream(\n            @RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::openai-sdk-chat.adoc::Sample Controller::0'),
('ce08bbfc-6e62-4b34-939a-96320d567384','/**\n * Parse a textual, vector-store agnostic, filter expression language into\n * {@link Filter.Expression}.\n *\n * The vector-store agnostic, filter expression language is defined by a formal ANTLR4\n * grammar (Filters.g4). The language looks and feels like a subset of the well known SQL\n * WHERE filter expressions. For example, you can use the parser like this:\n *\n * <pre>{@code\n *\n * var parser = new FilterExpressionTextParser();\n *\n * exp1 = parser.parse(\"country == \'BG\'\"); // creates:\n *  |\n *  +->	new Expression(EQ, new Key(\"country\"), new Value(\"BG\"));\n *\n * exp2 = parser.parse(\"genre == \'drama\' && year >= 2020\"); // creates:\n *  |\n *  +->	new Expression(AND,\n * 			new Expression(EQ, new Key(\"genre\"), new Value(\"drama\")),\n * 			new Expression(GTE, new Key(\"year\"), new Value(2020)));\n *\n * exp3 = parser.parse(\"genre in [\'comedy\', \'documentary\', \'drama\']\");\n *  |\n *  +->	new Expression(IN, new Key(\"genre\"), new Value(List.of(\"comedy\", \"documentary\", \"drama\")));\n *\n * exp4 = parser.parse(\"year >= 2020 || country == \'BG\' && city != \'Sofia\'\");\n *  |\n *  +->	new Expression(OR,\n * 			new Expression(GTE, new Key(\"year\"), new Value(2020)),\n * 			new Expression(AND,\n * 					new Expression(EQ, new Key(\"country\"), new Value(\"BG\")),\n * 					new Expression(NE, new Key(\"city\"), new Value(\"Sofia\"))));\n *\n * exp5 = parser.parse(\"(year >= 2020 || country == \\\"BG\\\") && city NOT IN [\'Sofia\', \\\"Plovdiv\\\"]\"); // creates:\n *  |\n *  +->	new Expression(AND,\n * 			new Group(new Expression(OR, new Expression(EQ, new Key(\"country\"), new Value(\"BG\")),\n * 				new Expression(GTE, new Key(\"year\"), new Value(2020)))),\n * 			new Expression(NIN, new Key(\"city\"), new Value(List.of(\"Sofia\", \"Varna\"))));\n *\n * exp6 = parser.parse(\"isOpen == true && year >= 2020 && country IN [\'BG\', \'NL\', \'US\']\"); // creates:\n *  |\n *  +->	new Expression(AND,\n * 			new Expression(EQ, new Key(\"isOpen\"), new Value(true)),\n * 			new Expression(AND,\n * 				new Expression(GTE, new Key(\"year\"), new Value(2020)),\n * 				new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))));\n *\n * exp7 = parser.parse(\"price >= 15.6 && price <= 20.13\"); // creates:\n *  |\n *  +->	new Expression(AND,\n * 			new Expression(GTE, new Key(\"price\"), new Value(15.6)),\n * 			new Expression(LTE, new Key(\"price\"), new Value(20.13)));\n *\n * }</pre>\n *\n * @author Christian Tzolov\n * @author Sun Yuhan\n */\npublic class FilterExpressionTextParser {\n\n    private static final String WHERE_PREFIX = \"WHERE\";\n\n    private final DescriptiveErrorListener errorListener;\n\n    private final ANTLRErrorStrategy errorHandler;\n\n    private final Map<String, Filter.Expression> cache = new ConcurrentHashMap<>();\n\n    public FilterExpressionTextParser() {\n        this(new BailErrorStrategy());\n    }\n\n    public FilterExpressionTextParser(ANTLRErrorStrategy handler) {\n        this.errorListener = DescriptiveErrorListener.INSTANCE;\n        this.errorHandler = handler;\n    }\n\n    public Filter.Expression parse(String textFilterExpression) {\n        Assert.hasText(textFilterExpression, \"Expression should not be empty!\");\n        // Prefix the expression with the compulsory WHERE keyword.\n        if (!textFilterExpression.toUpperCase().startsWith(WHERE_PREFIX)) {\n            textFilterExpression = String.format(\"%s %s\", WHERE_PREFIX, textFilterExpression);\n        }\n        if (this.cache.containsKey(textFilterExpression)) {\n            return this.cache.get(textFilterExpression);\n        }\n        var lexer = new FiltersLexer(CharStreams.fromString(textFilterExpression));\n        var tokens = new CommonTokenStream(lexer);\n        var parser = new FiltersParser(tokens);\n        parser.removeErrorListeners();\n        this.errorListener.errorMessages.clear();\n        parser.addErrorListener(this.errorListener);\n        if (this.errorHandler != null) {\n            parser.setErrorHandler(this.errorHandler);\n        }\n        var filterExpressionVisitor = new FilterExpressionVisitor();\n        try {\n            Filter.Operand operand = filterExpressionVisitor.visit(parser.where());\n            var filterExpression = filterExpressionVisitor.castToExpression(operand);\n            this.cache.putIfAbsent(textFilterExpression, filterExpression);\n            return filterExpression;\n        } catch (ParseCancellationException e) {\n            var msg = String.join(\"\", this.errorListener.errorMessages);\n            var rootCause = NestedExceptionUtils.getRootCause(e);\n            throw new FilterExpressionParseException(msg, rootCause);\n        }\n    }\n\n    public void clearCache() {\n        this.cache.clear();\n    }\n\n    /**\n     * For testing only\n     */\n    Map<String, Filter.Expression> getCache() {\n        return this.cache;\n    }\n\n    public static class FilterExpressionParseException extends RuntimeException {\n\n        public FilterExpressionParseException(String message, Throwable cause) {\n            super(message, cause);\n        }\n    }\n\n    public static class FilterExpressionVisitor extends FiltersBaseVisitor<Filter.Operand> {\n\n        private static final Map<String, Filter.ExpressionType> COMP_EXPRESSION_TYPE_MAP = Map.of(\"==\", Filter.ExpressionType.EQ, \"!=\", Filter.ExpressionType.NE, \">\", Filter.ExpressionType.GT, \">=\", Filter.ExpressionType.GTE, \"<\", Filter.ExpressionType.LT, \"<=\", Filter.ExpressionType.LTE);\n\n        @Override\n        public Filter.Operand visitWhere(FiltersParser.WhereContext ctx) {\n            return this.visit(ctx.booleanExpression());\n        }\n\n        @Override\n        public Filter.Operand visitIdentifier(FiltersParser.IdentifierContext ctx) {\n            return new Filter.Key(ctx.getText());\n        }\n\n        @Override\n        public Filter.Operand visitTextConstant(FiltersParser.TextConstantContext ctx) {\n            String onceQuotedText = removeOuterQuotes(ctx.getText());\n            return new Filter.Value(onceQuotedText);\n        }\n\n        private String removeOuterQuotes(String in) {\n            return in.substring(1, in.length() - 1);\n        }\n\n        @Override\n        public Filter.Operand visitIntegerConstant(FiltersParser.IntegerConstantContext ctx) {\n            return new Filter.Value(Integer.valueOf(ctx.getText()));\n        }\n\n        @Override\n        public Filter.Operand visitDecimalConstant(FiltersParser.DecimalConstantContext ctx) {\n            return new Filter.Value(Double.valueOf(ctx.getText()));\n        }\n\n        @Override\n        public Filter.Operand visitBooleanConstant(FiltersParser.BooleanConstantContext ctx) {\n            return new Filter.Value(Boolean.valueOf(ctx.getText()));\n        }\n\n        @Override\n        public Filter.Operand visitConstantArray(FiltersParser.ConstantArrayContext ctx) {\n            List<Object> list = new ArrayList<>();\n            ctx.constant().forEach(constantCtx -> list.add(((Filter.Value) this.visit(constantCtx)).value()));\n            return new Filter.Value(list);\n        }\n\n        @Override\n        public Filter.Operand visitInExpression(FiltersParser.InExpressionContext ctx) {\n            return new Filter.Expression(Filter.ExpressionType.IN, this.visitIdentifier(ctx.identifier()), this.visitConstantArray(ctx.constantArray()));\n        }\n\n        @Override\n        public Filter.Operand visitNinExpression(FiltersParser.NinExpressionContext ctx) {\n            return new Filter.Expression(Filter.ExpressionType.NIN, this.visitIdentifier(ctx.identifier()), this.visitConstantArray(ctx.constantArray()));\n        }\n\n        @Override\n        public Filter.Operand visitCompareExpression(FiltersParser.CompareExpressionContext ctx) {\n            return new Filter.Expression(this.covertCompare(ctx.compare().getText()), this.visitIdentifier(ctx.identifier()), this.visit(ctx.constant()));\n        }\n\n        private Filter.ExpressionType covertCompare(String compare) {\n            if (!COMP_EXPRESSION_TYPE_MAP.containsKey(compare)) {\n                throw new RuntimeException(\"Unknown compare operator: \" + compare);\n            }\n            return COMP_EXPRESSION_TYPE_MAP.get(compare);\n        }\n\n        @Override\n        public Filter.Operand visitAndExpression(FiltersParser.AndExpressionContext ctx) {\n            return new Filter.Expression(Filter.ExpressionType.AND, this.visit(ctx.left), this.visit(ctx.right));\n        }\n\n        @Override\n        public Filter.Operand visitOrExpression(FiltersParser.OrExpressionContext ctx) {\n            return new Filter.Expression(Filter.ExpressionType.OR, this.visit(ctx.left), this.visit(ctx.right));\n        }\n\n        @Override\n        public Filter.Operand visitGroupExpression(FiltersParser.GroupExpressionContext ctx) {\n            return new Filter.Group(castToExpression(this.visit(ctx.booleanExpression())));\n        }\n\n        @Override\n        public Filter.Operand visitNotExpression(NotExpressionContext ctx) {\n            return new Filter.Expression(Filter.ExpressionType.NOT, this.visit(ctx.booleanExpression()), null);\n        }\n\n        @Override\n        public Filter.Operand visitLongConstant(FiltersParser.LongConstantContext ctx) {\n            String text = ctx.getText();\n            // Remove the trailing \'l\' or \'L\'\n            long value = Long.parseLong(text.substring(0, text.length() - 1));\n            return new Filter.Value(value);\n        }\n\n        public Filter.Expression castToExpression(Filter.Operand expression) {\n            if (expression instanceof Filter.Group group) {\n                // Remove the top-level grouping.\n                return group.content();\n            } else if (expression instanceof Filter.Expression exp) {\n                return exp;\n            }\n            throw new RuntimeException(\"Invalid expression: \" + expression);\n        }\n    }\n\n    public static class DescriptiveErrorListener extends BaseErrorListener {\n\n        public static final DescriptiveErrorListener INSTANCE = new DescriptiveErrorListener();\n\n        public final List<String> errorMessages = new CopyOnWriteArrayList<>();\n\n        @Override\n        public void syntaxError(Recognizer<?, ?> recognizer, Object offendingSymbol, int line, int charPositionInLine, String msg, RecognitionException e) {\n            String sourceName = recognizer.getInputStream().getSourceName();\n            var errorMessage = String.format(\"Source: %s, Line: %s:%s, Error: %s\", sourceName, line, charPositionInLine, msg);\n            this.errorMessages.add(errorMessage);\n        }\n    }\n}',0x01,'cu::FilterExpressionTextParser.java'),
('76d43a8d-b440-4a27-aaff-96b13cb09a8f','<div class=\"paragraph\">\n<p>Spring AI supports the various AI language models from MiniMax. You can interact with MiniMax language models and create a multilingual conversational assistant based on MiniMax models.</p>\n</div>',0x00,'asciidoc::minimax-chat.adoc::0'),
('5e17a445-5ea4-4b5f-8aa4-9703766a1b64','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-google-genai/src/main/java/org/springframework/ai/google/genai/GoogleGenAiChatModel.java\">GoogleGenAiChatModel</a> implements the <code>ChatModel</code> and uses the <code>com.google.genai.Client</code> to connect to the Google GenAI service.\n\nAdd the <code>spring-ai-google-genai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-google-genai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-google-genai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>GoogleGenAiChatModel</code> and use it for text generations:',0x00,'asciidoc::google-genai-chat.adoc::Manual Configuration::0'),
('855ebb05-1761-4f96-b01f-9716fd533fa2','The <code>PagePdfDocumentReader</code> uses Apache PdfBox library to parse PDF documents\n\nAdd the dependency to your project using Maven or Gradle.\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-pdf-document-reader&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-pdf-document-reader\'\n}\n\nExample\n\n@Component\npublic class MyPagePdfDocumentReader {\n\n	List&lt;Document&gt; getDocsFromPdf() {\n\n		PagePdfDocumentReader pdfReader = new PagePdfDocumentReader(\"classpath:/sample1.pdf\",\n				PdfDocumentReaderConfig.builder()\n					.withPageTopMargin(0)\n					.withPageExtractedTextFormatter(ExtractedTextFormatter.builder()\n						.withNumberOfTopTextLinesToDelete(0)\n						.build())\n					.withPagesPerDocument(1)\n					.build());\n\n		return pdfReader.read();\n    }\n\n}',0x00,'asciidoc::etl-pipeline.adoc::DocumentReaders::PDF Page::0'),
('57209b9e-2c8f-4819-a2cc-973146d4d8f2','<a href=\"https://cassandra.apache.org\">Apache Cassandra®</a> is a true open source distributed database renowned for linear scalability, proven fault-tolerance and low latency, making it the perfect platform for mission-critical transactional data.\n\nIts Vector Similarity Search (VSS) is based on the JVector library that ensures best-in-class performance and relevancy.\n\nA vector search in Apache Cassandra is done as simply as:\n\nSELECT content FROM table ORDER BY content_vector ANN OF query_embedding;\n\nMore docs on this can be read <a href=\"https://cassandra.apache.org/doc/latest/cassandra/getting-started/vector-search-quickstart.html\">here</a>.\n\nThis Spring AI Vector Store is designed to work for both brand-new RAG applications and be able to be retrofitted on top of existing data and tables.\n\nThe store can also be used for non-RAG use-cases in an existing database, e.g. semantic searches, geo-proximity searches, etc.\n\nThe store will automatically create, or enhance, the schema as needed according to its configuration. If you don&#8217;t want the schema modifications, configure the store with <code>initializeSchema</code>.\n\nWhen using spring-boot-autoconfigure <code>initializeSchema</code> defaults to <code>false</code>, per Spring Boot standards, and you must opt-in to schema creation/modifications by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.',0x00,'asciidoc::apache-cassandra.adoc::What is Apache Cassandra?::0'),
('6aa511d6-3063-43db-b5eb-973ce4bedb65','You can register custom Java functions with the <code>MistralAiChatModel</code> and have the Mistral AI model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.\nRead more about <a href=\"api/tools.html\">Tool Calling</a>.',0x00,'asciidoc::mistralai-chat.adoc::Function Calling::0'),
('ebf5da00-4a18-449c-b455-9780d3a60b84','Azure OpenAI has model-specific requirements for token limiting parameters:\n\n\n\nThe parameters <code>maxTokens</code> and <code>maxCompletionTokens</code> are <strong>mutually exclusive</strong>. Setting both parameters simultaneously will result in an API error from Azure OpenAI. The Spring AI Azure OpenAI client will automatically clear the previously set parameter when you set the other one, with a warning message.\n\nvar options = AzureOpenAiChatOptions.builder()\n    .deploymentName(\"o1-preview\")\n    .maxCompletionTokens(500)  // Required for reasoning models\n    .build();\n\nvar options = AzureOpenAiChatOptions.builder()\n    .deploymentName(\"gpt-4o\")\n    .maxTokens(500)  // Required for non-reasoning models\n    .build();',0x00,'asciidoc::azure-openai-chat.adoc::Auto-configuration::Token Limit Parameters: Model-Specific Usage::0'),
('fd176ed7-199f-483c-9e65-9781a6ee7c16','The ChatClient supports adding metadata to both user and system messages.\nMetadata provides additional context and information about messages that can be used by the AI model or downstream processing.',0x00,'asciidoc::chatclient.adoc::Message Metadata::0'),
('645efbde-2592-4e82-942f-97c41b733e49','<strong>Start Simple</strong>\nBegin with basic workflows before adding complexity\nUse the simplest pattern that meets your requirements\nAdd sophistication only when needed\n<strong>Design for Reliability</strong>\nImplement clear error handling\nUse type-safe responses where possible\nBuild in validation at each step\n<strong>Consider Trade-offs</strong>\nBalance latency vs. accuracy\nEvaluate when to use parallel processing\nChoose between fixed workflows and dynamic agents',0x00,'asciidoc::effective-agents.adoc::Best Practices and Recommendations::0'),
('db2b0685-32b8-4bfe-9ecb-97d90168e902','The previous configuration properties for enabling/disabling model auto-configuration have been removed:\n\n<code>spring.ai.&lt;provider&gt;.chat.enabled</code>\n<code>spring.ai.&lt;provider&gt;.embedding.enabled</code>\n<code>spring.ai.&lt;provider&gt;.image.enabled</code>\n<code>spring.ai.&lt;provider&gt;.moderation.enabled</code>\n\n\nBy default, if a model provider (e.g., OpenAI, Ollama) is found on the classpath, its corresponding auto-configuration for relevant model types (chat, embedding, etc.) is enabled. If multiple providers for the same model type are present (e.g., both <code>spring-ai-openai-spring-boot-starter</code> and <code>spring-ai-ollama-spring-boot-starter</code>), you can use the following properties to select <strong>which</strong> provider&#8217;s auto-configuration should be active, effectively disabling the others for that specific model type.\n\nTo disable auto-configuration for a specific model type entirely, even if only one provider is present, set the corresponding property to a value that does not match any provider on the classpath (e.g., <code>none</code> or <code>disabled</code>).\n\nYou can refer to the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/model/SpringAIModels.java\"><code>SpringAIModels</code></a> enumeration for a list of well-known provider values.\n\n<code>spring.ai.model.audio.speech=&lt;model-provider|none&gt;</code>\n<code>spring.ai.model.audio.transcription=&lt;model-provider|none&gt;</code>\n<code>spring.ai.model.chat=&lt;model-provider|none&gt;</code>\n<code>spring.ai.model.embedding=&lt;model-provider|none&gt;</code>\n<code>spring.ai.model.embedding.multimodal=&lt;model-provider|none&gt;</code>\n<code>spring.ai.model.embedding.text=&lt;model-provider|none&gt;</code>\n<code>spring.ai.model.image=&lt;model-provider|none&gt;</code>\n<code>spring.ai.model.moderation=&lt;model-provider|none&gt;</code>',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M7::Enabling/Disabling Model Auto-Configuration::0'),
('af3749da-03ce-4c2a-852f-97dc36656790','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with MongoDB Atlas as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(5)\n        .similarityThreshold(0.7)\n        .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(5)\n        .similarityThreshold(0.7)\n        .filterExpression(b.and(\n                b.in(\"author\", \"john\", \"jill\"),\n                b.eq(\"article_type\", \"blog\")).build()).build());\n\nThose (portable) filter expressions get automatically converted into the proprietary MongoDB Atlas filter expressions.\n\nFor example, this portable filter expression:\n\nauthor in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\n\nis converted into the proprietary MongoDB Atlas filter format:\n\n{\n  \"$and\": [\n    {\n      \"$or\": [\n        { \"metadata.author\": \"john\" },\n        { \"metadata.author\": \"jill\" }\n      ]\n    },\n    {\n      \"metadata.article_type\": \"blog\"\n    }\n  ]\n}',0x00,'asciidoc::mongodb.adoc::Metadata Filtering::0'),
('3f8fcdf4-d3c0-48b8-bf9b-97e2162f179c','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-deepseek/src/main/java/org/springframework/ai/deepseek/api/DeepSeekApi.java\">DeepSeekApi</a> is a lightweight Java client for <a href=\"https://platform.deepseek.com/api-docs/\">DeepSeek API</a>.\n\nHere is a simple snippet showing how to use the API programmatically:\n\nDeepSeekApi deepSeekApi =\n    new DeepSeekApi(System.getenv(\"DEEPSEEK_API_KEY\"));\n\nChatCompletionMessage chatCompletionMessage =\n    new ChatCompletionMessage(\"Hello world\", Role.USER);\n\n// Sync request\nResponseEntity&lt;ChatCompletion&gt; response = deepSeekApi.chatCompletionEntity(\n    new ChatCompletionRequest(List.of(chatCompletionMessage), DeepSeekApi.ChatModel.DEEPSEEK_CHAT.getValue(), 0.7, false));\n\n// Streaming request\nFlux&lt;ChatCompletionChunk&gt; streamResponse = deepSeekApi.chatCompletionStream(\n    new ChatCompletionRequest(List.of(chatCompletionMessage), DeepSeekApi.ChatModel.DEEPSEEK_CHAT.getValue(), 0.7, true));\n\nFollow the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-deepseek/src/main/java/org/springframework/ai/deepseek/api/DeepSeekApi.java\">DeepSeekApi.java</a>\'s JavaDoc for further information.\n\nDeepSeekApi Samples\n\nThe <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-deepseek/src/test/java/org/springframework/ai/deepseek/api/DeepSeekApiIT.java\">DeepSeekApiIT.java</a> test provides some general examples of how to use the lightweight library.',0x00,'asciidoc::deepseek-chat.adoc::Manual Configuration::Low-level DeepSeekApi Client::0'),
('8e490309-0197-4a67-b6fa-97f39775dcf8','Access to ChromaDB. Compatible with <a href=\"https://trychroma.com/signup\">Chroma Cloud</a>, or  <a href=\"#run Chroma Locally\">setup local ChromaDB</a> in the appendix shows how to set up a DB locally with a Docker container.\n<code>EmbeddingModel</code> instance to compute the document embeddings. Several options are available:\n\n\nOn startup, the <code>ChromaVectorStore</code> creates the required collection if one is not provisioned already.',0x00,'asciidoc::chroma.adoc::Prerequisites::0'),
('3e406072-cbf0-4ae0-a6d7-980c444deaae','Automatic Prompt Engineering uses the AI to generate and evaluate alternative prompts. This meta-technique leverages the language model itself to create, refine, and benchmark different prompt variations to find optimal formulations for specific tasks.\n\nBy systematically generating and evaluating prompt variations, APE can find more effective prompts than manual engineering, especially for complex tasks. It&#8217;s a way of using AI to improve its own performance.\n\n// Implementation of Section 2.8: Automatic Prompt Engineering\npublic void pt_automatic_prompt_engineering(ChatClient chatClient) {\n    // Generate variants of the same request\n    String orderVariants = chatClient\n            .prompt(\"\"\"\n                    We have a band merchandise t-shirt webshop, and to train a\n                    chatbot we need various ways to order: \"One Metallica t-shirt\n                    size S\". Generate 10 variants, with the same semantics but keep\n                    the same meaning.\n                    \"\"\")\n            .options(ChatOptions.builder()\n                    .temperature(1.0)  // High temperature for creativity\n                    .build())\n            .call()\n            .content();\n\n    // Evaluate and select the best variant\n    String output = chatClient\n            .prompt()\n            .user(u -&gt; u.text(\"\"\"\n                    Please perform BLEU (Bilingual Evaluation Understudy) evaluation on the following variants:\n                    ----\n                    {variants}\n                    ----\n\n                    Select the instruction candidate with the highest evaluation score.\n                    \"\"\").param(\"variants\", orderVariants))\n            .call()\n            .content();\n}\n\nAPE is particularly valuable for optimizing prompts for production systems, addressing challenging tasks where manual prompt engineering has reached its limits, and for systematically improving prompt quality at scale.\n\n<strong>Reference:</strong> Zhou, Y., et al. (2022). \"Large Language Models Are Human-Level Prompt Engineers.\" arXiv:2211.01910. <a href=\"https://arxiv.org/abs/2211.01910\">https://arxiv.org/abs/2211.01910</a>',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.8 Automatic Prompt Engineering::0'),
('78c62311-9a8c-411e-a8b8-984731ccc4dd','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-openai-sdk</code> to your pom (or gradle) dependencies.\n\nAdd an <code>application.properties</code> file under the <code>src/main/resources</code> directory to configure the OpenAI SDK embedding model:\n\nspring.ai.openai-sdk.api-key=YOUR_API_KEY\nspring.ai.openai-sdk.embedding.options.model=text-embedding-ada-002\n\nReplace the <code>api-key</code> with your OpenAI credentials.\n\nThis will create an <code>OpenAiSdkEmbeddingModel</code> implementation that you can inject into your classes.\nHere is an example of a simple <code>@RestController</code> class that uses the embedding model.\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map&lt;String, Object&gt; embed(\n            @RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::openai-sdk-embeddings.adoc::Sample Controller::0'),
('b681a606-897a-4153-b7ae-986df63ccaf9','You first need access to an Ollama instance. There are a few options, including the following:\n\n<a href=\"https://ollama.com/download\">Download and install Ollama</a> on your local machine.\nConfigure and <a href=\"api/testcontainers.html\">run Ollama via Testcontainers</a>.\nBind to an Ollama instance via <a href=\"api/cloud-bindings.html\">Kubernetes Service Bindings</a>.\n\n\nYou can pull the models you want to use in your application from the <a href=\"https://ollama.com/search?c=embedding\">Ollama model library</a>:\n\nollama pull &lt;model-name&gt;\n\nYou can also pull any of the thousands, free, <a href=\"https://huggingface.co/models?library=gguf&amp;sort=trending\">GGUF Hugging Face Models</a>:\n\nollama pull hf.co/&lt;username&gt;/&lt;model-repository&gt;\n\nAlternatively, you can enable the option to download automatically any needed model: <a href=\"#auto-pulling-models\">Auto-pulling Models</a>.',0x00,'asciidoc::ollama-embeddings.adoc::Prerequisites::0'),
('5e2c5af1-3749-4e5c-95c1-989d09bb9364','// Implementation of Section 2.9.1: Prompts for writing code\npublic void pt_code_prompting_writing_code(ChatClient chatClient) {\n    String bashScript = chatClient\n            .prompt(\"\"\"\n                    Write a code snippet in Bash, which asks for a folder name.\n                    Then it takes the contents of the folder and renames all the\n                    files inside by prepending the name draft to the file name.\n                    \"\"\")\n            .options(ChatOptions.builder()\n                    .temperature(0.1)  // Low temperature for deterministic code\n                    .build())\n            .call()\n            .content();\n}\n\n// Implementation of Section 2.9.2: Prompts for explaining code\npublic void pt_code_prompting_explaining_code(ChatClient chatClient) {\n    String code = \"\"\"\n            #!/bin/bash\n            echo \"Enter the folder name: \"\n            read folder_name\n            if [ ! -d \"$folder_name\" ]; then\n            echo \"Folder does not exist.\"\n            exit 1\n            fi\n            files=( \"$folder_name\"/* )\n            for file in \"${files[@]}\"; do\n            new_file_name=\"draft_$(basename \"$file\")\"\n            mv \"$file\" \"$new_file_name\"\n            done\n            echo \"Files renamed successfully.\"\n            \"\"\";\n\n    String explanation = chatClient\n            .prompt()\n            .user(u -&gt; u.text(\"\"\"\n                    Explain to me the below Bash code:\n                    ```\n                    {code}\n                    ```\n                    \"\"\").param(\"code\", code))\n            .call()\n            .content();\n}\n\n// Implementation of Section 2.9.3: Prompts for translating code\npublic void pt_code_prompting_translating_code(ChatClient chatClient) {\n    String bashCode = \"\"\"\n            #!/bin/bash\n            echo \"Enter the folder name: \"\n            read folder_name\n            if [ ! -d \"$folder_name\" ]; then\n            echo \"Folder does not exist.\"\n            exit 1\n            fi\n            files=( \"$folder_name\"/* )\n            for file in \"${files[@]}\"; do\n            new_file_name=\"draft_$(basename \"$file\")\"\n            mv \"$file\" \"$new_file_name\"\n            done\n            echo \"Files renamed successfully.\"\n            \"\"\";\n\n    String pythonCode = chatClient\n            .prompt()\n            .user(u -&gt; u.text(\"\"\"\n                    Translate the below Bash code to a Python snippet:\n                    {code}\n                    \"\"\").param(\"code\", bashCode))\n            .call()\n            .content();\n}\n\nCode prompting is especially valuable for automated code documentation, prototyping, learning programming concepts, and translating between programming languages. The effectiveness can be further enhanced by combining it with techniques like few-shot prompting or chain-of-thought.',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::2.9 Code Prompting::1'),
('6015b09f-ad69-45f7-978f-9958d9dfba3e','The MongoDB Atlas Vector Store implementation provides access to the underlying native MongoDB client (<code>MongoClient</code>) through the <code>getNativeClient()</code> method:\n\nMongoDBAtlasVectorStore vectorStore = context.getBean(MongoDBAtlasVectorStore.class);\nOptional&lt;MongoClient&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    MongoClient client = nativeClient.get();\n    // Use the native client for MongoDB-specific operations\n}\n\nThe native client gives you access to MongoDB-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::mongodb.adoc::Accessing the Native Client::0'),
('2222d836-6462-4d62-902a-997894d6afac','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-deepseek</code> to your pom (or gradle) dependencies.\n\nAdd an <code>application.properties</code> file under the <code>src/main/resources</code> directory to enable and configure the DeepSeek Chat model:\n\nspring.ai.deepseek.api-key=YOUR_API_KEY\nspring.ai.deepseek.chat.options.model=deepseek-chat\nspring.ai.deepseek.chat.options.temperature=0.8\n\nReplace the <code>api-key</code> with your DeepSeek credentials.\n\nThis will create a <code>DeepSeekChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generation.\n\n@RestController\npublic class ChatController {\n\n    private final DeepSeekChatModel chatModel;\n\n    @Autowired\n    public ChatController(DeepSeekChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        var prompt = new Prompt(new UserMessage(message));\n        return chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::deepseek-chat.adoc::Sample Controller (Auto-configuration)::0'),
('0b59a7b2-e830-4a84-a531-9997efd6b0f1','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/titan/api/TitanEmbeddingBedrockApi.java\">TitanEmbeddingBedrockApi</a> provides is lightweight Java client on top of AWS Bedrock <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/titan-multiemb-models.html\">Titan Embedding models</a>.\n\nFollowing class diagram illustrates the TitanEmbeddingBedrockApi interface and building blocks:\n\nThe TitanEmbeddingBedrockApi supports the <code>amazon.titan-embed-image-v1</code> and <code>amazon.titan-embed-image-v1</code> models for single and batch embedding computation.\n\nHere is a simple snippet how to use the api programmatically:\n\nTitanEmbeddingBedrockApi titanEmbedApi = new TitanEmbeddingBedrockApi(\n		TitanEmbeddingModel.TITAN_EMBED_TEXT_V1.id(), Region.US_EAST_1.id());\n\nTitanEmbeddingRequest request = TitanEmbeddingRequest.builder()\n	.withInputText(\"I like to eat apples.\")\n	.build();\n\nTitanEmbeddingResponse response = this.titanEmbedApi.embedding(this.request);\n\nTo embed an image you need to convert it into <code>base64</code> format:\n\nTitanEmbeddingBedrockApi titanEmbedApi = new TitanEmbeddingBedrockApi(\n		TitanEmbeddingModel.TITAN_EMBED_IMAGE_V1.id(), Region.US_EAST_1.id());\n\nbyte[] image = new DefaultResourceLoader()\n	.getResource(\"classpath:/spring_framework.png\")\n	.getContentAsByteArray();\n\n\nTitanEmbeddingRequest request = TitanEmbeddingRequest.builder()\n	.withInputImage(Base64.getEncoder().encodeToString(this.image))\n	.build();\n\nTitanEmbeddingResponse response = this.titanEmbedApi.embedding(this.request);',0x00,'asciidoc::bedrock-titan-embedding.adoc::Low-level TitanEmbeddingBedrockApi Client::0'),
('5702b640-4795-4c58-9e41-99afddd6b17a','Later, when a user question is passed into the AI model, a similarity search is done to retrieve similar documents, which are then \"stuffed\" into the prompt as context for the user&#8217;s question.\n\nFor read-only operations, you can use either the <code>VectorStore</code> interface or the more focused <code>VectorStoreRetriever</code> interface:\n\n@Autowired\nVectorStoreRetriever retriever; // Could also use VectorStore here\n\nString question = \"&lt;question from user&gt;\";\nList&lt;Document&gt; similarDocuments = retriever.similaritySearch(question);\n\n// Or with more specific search parameters\nSearchRequest request = SearchRequest.builder()\n    .query(question)\n    .topK(5)                       // Return top 5 results\n    .similarityThreshold(0.7)      // Only return results with similarity score &gt;= 0.7\n    .build();\n\nList&lt;Document&gt; filteredDocuments = retriever.similaritySearch(request);\n\nAdditional options can be passed into the <code>similaritySearch</code> method to define how many documents to retrieve and a threshold of the similarity search.',0x00,'asciidoc::vectordbs.adoc::Example Usage::Reading from a Vector Store::0'),
('a040e05e-cf42-458c-9bbf-99ed47c9a312','Retry Properties\n\nThe prefix <code>spring.ai.retry</code> is used as the property prefix that lets you configure the retry mechanism for the OpenAI chat model.\n\n\n\nConnection Properties\n\nThe prefix <code>spring.ai.openai</code> is used as the property prefix that lets you connect to OpenAI.\n\n\n\nConfiguration Properties\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the chat auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.chat</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.chat=openai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.chat=none (or any value which doesn&#8217;t match openai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.openai.chat</code> is the property prefix that lets you configure the chat model implementation for OpenAI.\n\n\n\nAll properties prefixed with <code>spring.ai.openai.chat.options</code> can be overridden at runtime by adding a request specific <a href=\"#chat-options\">Runtime Options</a> to the <code>Prompt</code> call.',0x00,'asciidoc::nvidia-chat.adoc::Auto-configuration::Chat Properties::0'),
('4893ed28-a25d-4b70-94fe-99f52708c237','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-deepseek/src/main/java/org/springframework/ai/deepseek/DeepSeekChatModel.java\">DeepSeekChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"#low-level-api\">Low-level DeepSeekApi Client</a> to connect to the DeepSeek service.\n\nAdd the <code>spring-ai-deepseek</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-deepseek&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-deepseek\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>DeepSeekChatModel</code> and use it for text generation:\n\nDeepSeekApi deepSeekApi = DeepSeekApi.builder()\n        .apiKey(System.getenv(\"DEEPSEEK_API_KEY\"))\n        .build();\nDeepSeekChatOptions options = DeepSeekChatOptions.builder()\n        .model(DeepSeekApi.ChatModel.DEEPSEEK_CHAT.getValue())\n        .temperature(0.4)\n        .maxTokens(200)\n        .build();\nDeepSeekChatModel chatModel = DeepSeekChatModel.builder()\n        .deepSeekApi(deepSeekApi)\n        .defaultOptions(options)\n        .build();\nChatResponse response = chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; streamResponse = chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>DeepSeekChatOptions</code> provides the configuration information for the chat requests.\nThe <code>DeepSeekChatOptions.Builder</code> is a fluent options builder.',0x00,'asciidoc::deepseek-chat.adoc::Manual Configuration::0'),
('28fba84e-4f11-415f-ae18-99fcfab47143','Azure OpenAI\nOpenAI',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 0.8.0::0.7.1-SNAPSHOT Dependencies::0'),
('5a08e869-6208-4bc8-a324-9a168272c5bd','Vector Builders have been refactored for consistency.\nCurrent VectorStore implementation constructors have been deprecated, use the builder pattern.\nVectorStore implementation packages have been moved into unique package names, avoiding conflicts across artifact.  For example <code>org.springframework.ai.vectorstore</code> to <code>org.springframework.ai.pgvector.vectorstore</code>.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0.M5::0'),
('15466364-eac1-47e0-9486-9a25cd1cd6c1','/**\n * Portable runtime generative for metadata filter expressions. This generic generative is\n * used to define store agnostic filter expressions than later can be converted into\n * vector-store specific, native, expressions.\n *\n * The expression generative supports constant comparison\n * {@code (e.g. ==, !=, <, <=, >, >=) }, IN/NON-IN checks and AND and OR to compose\n * multiple expressions.\n *\n * For example:\n *\n * <pre>{@code\n * // 1: country == \"BG\"\n * new Expression(EQ, new Key(\"country\"), new Value(\"BG\"));\n *\n * // 2: genre == \"drama\" AND year >= 2020\n * new Expression(AND, new Expression(EQ, new Key(\"genre\"), new Value(\"drama\")),\n * 		new Expression(GTE, new Key(\"year\"), new Value(2020)));\n *\n * // 3: genre in [\"comedy\", \"documentary\", \"drama\"]\n * new Expression(IN, new Key(\"genre\"), new Value(List.of(\"comedy\", \"documentary\", \"drama\")));\n *\n * // 4: year >= 2020 OR country == \"BG\" AND city != \"Sofia\"\n * new Expression(OR, new Expression(GTE, new Key(\"year\"), new Value(2020)),\n * 		new Expression(AND, new Expression(EQ, new Key(\"country\"), new Value(\"BG\")),\n * 				new Expression(NE, new Key(\"city\"), new Value(\"Sofia\"))));\n *\n * // 5: (year >= 2020 OR country == \"BG\") AND city NIN [\"Sofia\", \"Plovdiv\"]\n * new Expression(AND,\n * 		new Group(new Expression(OR, new Expression(EQ, new Key(\"country\"), new Value(\"BG\")),\n * 				new Expression(GTE, new Key(\"year\"), new Value(2020)))),\n * 		new Expression(NIN, new Key(\"city\"), new Value(List.of(\"Sofia\", \"Varna\"))));\n *\n * // 6: isOpen == true AND year >= 2020 AND country IN [\"BG\", \"NL\", \"US\"]\n * new Expression(AND, new Expression(EQ, new Key(\"isOpen\"), new Value(true)),\n * 		new Expression(AND, new Expression(GTE, new Key(\"year\"), new Value(2020)),\n * 				new Expression(IN, new Key(\"country\"), new Value(List.of(\"BG\", \"NL\", \"US\")))));\n *\n * }</pre>\n *\n * Usually you will not create expression manually but use either the\n * {@link FilterExpressionBuilder} DSL or the {@link FilterExpressionTextParser} for\n * parsing generic text expressions.\n *\n * @author Christian Tzolov\n */\npublic class Filter {\n\n    /**\n     * Filter expression operations. <br/>\n     *\n     * - EQ, NE, GT, GTE, LT, LTE operations supports \"Key ExprType Value\"\n     * expressions.<br/>\n     *\n     * - AND, OR are binary operations that support \"(Expression|Group) ExprType\n     * (Expression|Group)\" expressions. <br/>\n     *\n     * - IN, NIN support \"Key (IN|NIN) ArrayValue\" expression. <br/>\n     */\n    public enum ExpressionType {\n\n        AND,\n        OR,\n        EQ,\n        NE,\n        GT,\n        GTE,\n        LT,\n        LTE,\n        IN,\n        NIN,\n        NOT\n    }\n\n    /**\n     * Mark interface representing the supported expression types: {@link Key},\n     * {@link Value}, {@link Expression} and {@link Group}.\n     */\n    public interface Operand {\n    }\n\n    /**\n     * String identifier representing an expression key. (e.g. the country in the country\n     * == \"NL\" expression).\n     *\n     * @param key expression key\n     */\n    public record Key(String key) implements Operand {\n    }\n\n    /**\n     * Represents expression value constant or constant array. Support Numeric, Boolean\n     * and String data types.\n     *\n     * @param value value constant or constant array\n     */\n    public record Value(Object value) implements Operand {\n    }\n\n    /**\n     * Triple that represents and filter boolean expression as\n     * <code>left type right</code>.\n     *\n     * @param type Specify the expression type.\n     * @param left For comparison and inclusion expression types, the operand must be of\n     * type {@link Key} and for the AND|OR expression types the left operand must be\n     * another {@link Expression}.\n     * @param right For comparison and inclusion expression types, the operand must be of\n     * type {@link Value} or array of values. For the AND|OR type the right operand must\n     * be another {@link Expression}.\n     */\n    public record Expression(ExpressionType type, Operand left, Operand right) implements Operand {\n\n        public Expression(ExpressionType type, Operand operand) {\n            this(type, operand, null);\n        }\n    }\n\n    /**\n     * Represents expression grouping (e.g. (...) ) that indicates that the group needs to\n     * be evaluated with a precedence.\n     *\n     * @param content Inner expression to be evaluated as a part of the group.\n     */\n    public record Group(Expression content) implements Operand {\n    }\n}',0x01,'cu::Filter.java'),
('2fb34318-8894-41cb-972e-9acfaf29cf85','This will create a <code>EmbeddingModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the <code>EmbeddingC</code> implementation.\n\nspring.ai.minimax.api-key=YOUR_API_KEY\nspring.ai.minimax.embedding.options.model=embo-01\n\n@RestController\npublic class EmbeddingController {\n\n    private final EmbeddingModel embeddingModel;\n\n    @Autowired\n    public EmbeddingController(EmbeddingModel embeddingModel) {\n        this.embeddingModel = embeddingModel;\n    }\n\n    @GetMapping(\"/ai/embedding\")\n    public Map embed(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        EmbeddingResponse embeddingResponse = this.embeddingModel.embedForResponse(List.of(message));\n        return Map.of(\"embedding\", embeddingResponse);\n    }\n}',0x00,'asciidoc::minimax-embeddings.adoc::Sample Controller::0'),
('a898f0cb-63dc-47d7-94d3-9b6388d04b75','You can use the following properties in your Spring Boot configuration to customize the Weaviate vector store.\n\n\n\nObject class names should start with an uppercase letter, and field names should start with a lowercase letter.\nSee <a href=\"https://weaviate.io/developers/weaviate/concepts/data#data-object-concepts\">data-object-concepts</a>',0x00,'asciidoc::weaviate.adoc::WeaviateVectorStore properties::0'),
('280b8925-961e-4b78-86a8-9b932ddf495a','The Weaviate Vector Store implementation provides access to the underlying native Weaviate client (<code>WeaviateClient</code>) through the <code>getNativeClient()</code> method:\n\nWeaviateVectorStore vectorStore = context.getBean(WeaviateVectorStore.class);\nOptional&lt;WeaviateClient&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    WeaviateClient client = nativeClient.get();\n    // Use the native client for Weaviate-specific operations\n}\n\nThe native client gives you access to Weaviate-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::weaviate.adoc::Accessing the Native Client::0'),
('1be73caa-1685-4d00-94e8-9c0a0c11ca59','AWS Bedrock&#8217;s <a href=\"https://docs.aws.amazon.com/bedrock/latest/userguide/prompt-caching.html\">prompt caching feature</a> allows you to cache frequently used prompts to reduce costs and improve response times for repeated interactions.\nWhen you cache a prompt, subsequent identical requests can reuse the cached content, significantly reducing the number of input tokens processed.\n\n<div class=\"paragraph\">\n<p><strong>Supported Models</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Prompt caching is supported on Claude 3.x, Claude 4.x, and Amazon Nova models available through AWS Bedrock.</p>\n</div>\n<div class=\"paragraph\">\n<p><strong>Token Requirements</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Different models have different minimum token thresholds for cache effectiveness:\n- Claude Sonnet 4 and most models: 1024+ tokens\n- Model-specific requirements may vary - consult AWS Bedrock documentation</p>\n</div>',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::0'),
('42e4100e-6452-4518-bbf2-9c66b49e7f73','spring.ai.google.genai.project-id=PROJECT_ID\nspring.ai.google.genai.location=LOCATION\nspring.ai.google.genai.chat.options.model=gemini-2.0-flash\nspring.ai.google.genai.chat.options.temperature=0.5\n\nReplace the <code>project-id</code> with your Google Cloud Project ID and <code>location</code> is Google Cloud Region\nlike <code>us-central1</code>, <code>europe-west1</code>, etc&#8230;&#8203;\n\n<div class=\"paragraph\">\n<p>Each model has its own set of supported regions, you can find the list of supported regions in the model page.</p>\n</div>\n\nThis will create a <code>GoogleGenAiChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final GoogleGenAiChatModel chatModel;\n\n    @Autowired\n    public ChatController(GoogleGenAiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::google-genai-chat.adoc::Sample Controller::Using Vertex AI::0'),
('7a72b5ea-3439-4606-862a-9cb2d0b196a5','<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=transformers (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match transformers)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>',0x00,'asciidoc::onnx.adoc::Auto-configuration::Embedding Properties::0'),
('f6537996-07e4-499e-aebb-9cbf3e4e5e34','Connection Properties\n\nThe prefix <code>spring.ai.google.genai.embedding</code> is used as the property prefix that lets you connect to Google GenAI Embedding API.\n\n<div class=\"paragraph\">\n<p>The connection properties are shared with the Google GenAI Chat module. If you&#8217;re using both chat and embeddings, you only need to configure the connection once using either <code>spring.ai.google.genai</code> prefix (for chat) or <code>spring.ai.google.genai.embedding</code> prefix (for embeddings).</p>\n</div>\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding.text=google-genai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding.text=none (or any value which doesn&#8217;t match google-genai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nText Embedding Properties\n\nThe prefix <code>spring.ai.google.genai.embedding.text</code> is the property prefix that lets you configure the embedding model implementation for Google GenAI Text Embedding.',0x00,'asciidoc::google-genai-embeddings-text.adoc::Auto-configuration::Embedding Properties::0'),
('37279cf7-f8cc-45f3-be26-9dba94a9ba59','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Pinecone Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-pinecone&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-pinecone\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nHere is an example of the needed bean:\n\n@Bean\npublic EmbeddingModel embeddingModel() {\n    // Can be any other EmbeddingModel implementation.\n    return new OpenAiEmbeddingModel(new OpenAiApi(System.getenv(\"OPENAI_API_KEY\")));\n}\n\nTo connect to Pinecone you need to provide access details for your instance.\nA simple configuration can either be provided via Spring Boot&#8217;s <em>application.properties</em>,\n\nspring.ai.vectorstore.pinecone.apiKey=&lt;your api key&gt;\nspring.ai.vectorstore.pinecone.index-name=&lt;your index name&gt;\n\n# API key if needed, e.g. OpenAI\nspring.ai.openai.api.key=&lt;api-key&gt;\n\nPlease have a look at the list of <a href=\"#_configuration_properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\n\nNow you can Auto-wire the Pinecone Vector Store in your application and use it\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList &lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = this.vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::pinecone.adoc::Auto-configuration::0'),
('cfe2c29c-d32d-4815-8d3f-9dfca1676259','This table compares various Chat Models supported by Spring AI, detailing their capabilities:\n\n<a href=\"api/multimodality.html\">Multimodality</a>: The types of input the model can process (e.g., text, image, audio, video).\n<a href=\"api/tools.html\">Tools/Function Calling</a>: Whether the model supports function calling or tool use.\nStreaming: If the model offers streaming responses.\nRetry: Support for retry mechanisms.\n<a href=\"observability/index.html\">Observability</a>: Features for monitoring and debugging.\n<a href=\"api/structured-output-converter.html#_built_in_json_mode\">Built-in JSON</a>: Native support for JSON output.\nLocal deployment: Whether the model can be run locally.\nOpenAI API Compatibility: If the model is compatible with OpenAI&#8217;s API.',0x00,'asciidoc::comparison.adoc::0'),
('fab2ce84-0aa5-46ea-b45d-9e9e9042ce8c','GoogleGenAiEmbeddingConnectionDetails connectionDetails =\n    GoogleGenAiEmbeddingConnectionDetails.builder()\n        .apiKey(System.getenv(\"GOOGLE_API_KEY\"))\n        .build();\n\nGoogleGenAiTextEmbeddingOptions options = GoogleGenAiTextEmbeddingOptions.builder()\n    .model(GoogleGenAiTextEmbeddingOptions.DEFAULT_MODEL_NAME)\n    .taskType(TaskType.RETRIEVAL_DOCUMENT)\n    .build();\n\nvar embeddingModel = new GoogleGenAiTextEmbeddingModel(connectionDetails, options);\n\nEmbeddingResponse embeddingResponse = embeddingModel\n	.embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));',0x00,'asciidoc::google-genai-embeddings-text.adoc::Manual Configuration::Using API Key::0'),
('d04aea9c-2356-41ac-ac80-9f1696bfe805','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with Redis as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(\"country in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(b.and(\n                b.in(\"country\", \"UK\", \"NL\"),\n                b.gte(\"year\", 2020)).build()).build());\n\nThose (portable) filter expressions get automatically converted into <a href=\"https://redis.io/docs/interact/search-and-query/query/\">Redis search queries</a>.\n\nFor example, this portable filter expression:\n\ncountry in [\'UK\', \'NL\'] &amp;&amp; year &gt;= 2020\n\nis converted into the proprietary Redis filter format:\n\n@country:{UK | NL} @year:[2020 inf]',0x00,'asciidoc::redis.adoc::Metadata Filtering::0'),
('ae9841d7-d34f-4c8c-9200-9f38230c718a','Each section below implements a specific prompt engineering technique from the guide.\nBy following both the \"Prompt Engineering\" guide and these implementations, you&#8217;ll develop a thorough understanding of not just what prompt engineering techniques are available, but how to effectively implement them in production Java applications.',0x00,'asciidoc::prompt-engineering-patterns.adoc::2. Prompt Engineering Techniques::0'),
('256e636e-c421-4932-b5b1-9f527988ef18','You will need an active <a href=\"https://signup.oraclecloud.com/\">Oracle Cloud Infrastructure (OCI)</a> account to use the OCI GenAI Cohere Chat client. The client offers four different ways to connect, including simple authentication with a user and private key, workload identity, instance principal, or OCI configuration file authentication.',0x00,'asciidoc::cohere-chat.adoc::Prerequisites::0'),
('c8518e39-907a-484c-9349-9fb1daa6ef8f','Spring AI will generate the JSON schema for the input parameters of the <code>@Tool</code>-annotated method automatically. The schema is used by the model to understand how to call the tool and prepare the tool request. The <code>@ToolParam</code> annotation can be used to provide additional information about the input parameters, such as a description or whether the parameter is required or optional. By default, all input parameters are considered required.\n\nimport java.time.LocalDateTime;\nimport java.time.format.DateTimeFormatter;\nimport org.springframework.ai.tool.annotation.Tool;\nimport org.springframework.ai.tool.annotation.ToolParam;\n\nclass DateTimeTools {\n\n    @Tool(description = \"Set a user alarm for the given time\")\n    void setAlarm(@ToolParam(description = \"Time in ISO-8601 format\") String time) {\n        LocalDateTime alarmTime = LocalDateTime.parse(time, DateTimeFormatter.ISO_DATE_TIME);\n        System.out.println(\"Alarm set for \" + alarmTime);\n    }\n\n}\n\nThe <code>@ToolParam</code> annotation allows you to provide key information about a tool parameter:\n\n<code>description</code>: The description for the parameter, which can be used by the model to understand better how to use it. For example, what format the parameter should be in, what values are allowed, and so on.\n<code>required</code>: Whether the parameter is required or optional. By default, all parameters are considered required.\n\n\nIf a parameter is annotated as <code>@Nullable</code>, it will be considered optional unless explicitly marked as required using the <code>@ToolParam</code> annotation.\n\nBesides the <code>@ToolParam</code> annotation, you can also use the <code>@Schema</code> annotation from Swagger or <code>@JsonProperty</code> from Jackson. See <a href=\"#_json_schema\">JSON Schema</a> for more details.\n\nAdding Tools to <code>ChatClient</code>\n\nWhen using the declarative specification approach, you can pass the tool class instance to the <code>tools()</code> method when invoking a <code>ChatClient</code>. Such tools will only be available for the specific chat request they are added to.\n\nChatClient.create(chatModel)\n    .prompt(\"What day is tomorrow?\")\n    .tools(new DateTimeTools())\n    .call()\n    .content();\n\nUnder the hood, the <code>ChatClient</code> will generate a <code>ToolCallback</code> from each <code>@Tool</code>-annotated method in the tool class instance and pass them to the model. In case you prefer to generate the <code>ToolCallback</code>(s) yourself, you can use the <code>ToolCallbacks</code> utility class.\n\nToolCallback[] dateTimeTools = ToolCallbacks.from(new DateTimeTools());\n\nAdding Default Tools to <code>ChatClient</code>\n\nWhen using the declarative specification approach, you can add default tools to a <code>ChatClient.Builder</code> by passing the tool class instance to the <code>defaultTools()</code> method.\nIf both default and runtime tools are provided, the runtime tools will completely override the default tools.',0x00,'asciidoc::tools.adoc::Methods as Tools::Declarative Specification: <code>@Tool</code>::1'),
('d811928d-9507-43c8-a8a7-9fe1402bd67c','public static final class EmbeddingMath {\n\n    private EmbeddingMath() {\n        throw new UnsupportedOperationException(\"This is a utility class and cannot be instantiated\");\n    }\n\n    public static double cosineSimilarity(float[] vectorX, float[] vectorY) {\n        if (vectorX == null || vectorY == null) {\n            throw new RuntimeException(\"Vectors must not be null\");\n        }\n        if (vectorX.length != vectorY.length) {\n            throw new IllegalArgumentException(\"Vectors lengths must be equal\");\n        }\n        float dotProduct = dotProduct(vectorX, vectorY);\n        float normX = norm(vectorX);\n        float normY = norm(vectorY);\n        if (normX == 0 || normY == 0) {\n            throw new IllegalArgumentException(\"Vectors cannot have zero norm\");\n        }\n        return dotProduct / (Math.sqrt(normX) * Math.sqrt(normY));\n    }\n\n    public static float dotProduct(float[] vectorX, float[] vectorY) {\n        if (vectorX.length != vectorY.length) {\n            throw new IllegalArgumentException(\"Vectors lengths must be equal\");\n        }\n        float result = 0;\n        for (int i = 0; i < vectorX.length; ++i) {\n            result += vectorX[i] * vectorY[i];\n        }\n        return result;\n    }\n\n    public static float norm(float[] vector) {\n        return dotProduct(vector, vector);\n    }\n}',0x01,'cu::SimpleVectorStore.java'),
('47558f10-ca9b-43d1-a30c-a1217436589b','Spring AI provides built-in support for specifying tools from functions, either programmatically using the low-level <code>FunctionToolCallback</code> implementation or dynamically as <code>@Bean</code>(s) resolved at runtime.',0x00,'asciidoc::tools.adoc::Functions as Tools::0'),
('f4fb7130-adea-483f-90fa-a1440f6c48d9','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-zhipuai/src/main/java/org/springframework/ai/zhipuai/ZhiPuAiChatModel.java\">ZhiPuAiChatModel</a> implements the <code>ChatModel</code> and <code>StreamingChatModel</code> and uses the <a href=\"#low-level-api\">Low-level ZhiPuAiApi Client</a> to connect to the ZhiPuAI service.\n\nAdd the <code>spring-ai-zhipuai</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-zhipuai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-zhipuai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create a <code>ZhiPuAiChatModel</code> and use it for text generations:\n\nvar zhiPuAiApi = new ZhiPuAiApi(System.getenv(\"ZHIPU_AI_API_KEY\"));\n\nvar chatModel = new ZhiPuAiChatModel(this.zhiPuAiApi, ZhiPuAiChatOptions.builder()\n                .model(ZhiPuAiApi.ChatModel.GLM_4_Air.getValue())\n                .temperature(0.4)\n                .maxTokens(200)\n                .build());\n\nChatResponse response = this.chatModel.call(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\n// Or with streaming responses\nFlux&lt;ChatResponse&gt; streamResponse = this.chatModel.stream(\n    new Prompt(\"Generate the names of 5 famous pirates.\"));\n\nThe <code>ZhiPuAiChatOptions</code> provides the configuration information for the chat requests.\nThe <code>ZhiPuAiChatOptions.Builder</code> is fluent options builder.',0x00,'asciidoc::zhipuai-chat.adoc::Manual Configuration::0'),
('ad24c033-9c3f-48ce-a2a1-a1b1d133daa0','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-google-genai-embedding</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the Google GenAI embedding model:',0x00,'asciidoc::google-genai-embeddings-text.adoc::Sample Controller::0'),
('6ba2fde9-dbb5-4856-9d6a-a1b43b6336a3','The prefix <code>spring.ai.bedrock.aws</code> is the property prefix to configure the connection to AWS Bedrock.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the chat auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.chat</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.chat=bedrock-converse (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.chat=none (or any value which doesn&#8217;t match bedrock-converse)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.bedrock.converse.chat</code> is the property prefix that configures the chat model implementation for the Converse API.',0x00,'asciidoc::bedrock-converse.adoc::Auto-configuration::Chat Properties::0'),
('9fce818b-c4a1-49cf-96ba-a2065861b1eb','The <code>GenerationMetadata</code> interface is defined as:\n\ninterface GenerationMetadata {\n\n	default RateLimit getRateLimit() {\n		return RateLimit.NULL;\n	}\n\n	default Usage getUsage() {\n		return Usage.NULL;\n	}\n\n}\n\nAn instance of <code>GenerationMetadata</code> is automatically created by Spring AI when an AI request is made through the AI provider&#8217;s API and an AI response is returned. You can get access to the AI provider metadata from the <code>ChatResponse</code> using:\n\n@Service\nclass MyService {\n\n	ApplicationObjectType askTheAi(ServiceRequest request) {\n\n        Prompt prompt = createPrompt(request);\n\n        ChatResponse response = chatModel.call(prompt);\n\n        // Process the chat response\n\n        GenerationMetadata metadata = response.getMetadata();\n\n        // Inspect the AI metadata returned in the chat response of the AI providers API\n\n        Long totalTokensUsedInAiPromptAndResponse = metadata.getUsage().getTotalTokens();\n\n        // Act on this information somehow\n	}\n}\n\nYou might imagine that you can rate limit your own Spring applications using AI, or restrict <code>Prompt</code> sizes, which affect your token usage, in an automated, intelligent and realtime manner.\n\nMinimally, you can simply gather these metrics to monitor and report on your consumption.',0x00,'asciidoc::aimetadata.adoc::<code>GenerationMetadata</code> interface::0'),
('1941d37c-2734-4a96-94fd-a2481110a61a','The <code>spring.ai.advisor</code> observations are recorded when an advisor is executed.\nThey measure the time spent in the advisor (including the time spend on the inner advisors) and propagate the related tracing information.',0x00,'asciidoc::index.adoc::Chat Client::Chat Client Advisors::0'),
('d01815d5-3feb-48ec-b31f-a24fbdd5fccd','The prefix <code>spring.ai.azure.openai</code> is the property prefix to configure the connection to Azure OpenAI.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding=azure-openai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding=none (or any value which doesn&#8217;t match azure-openai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.azure.openai.embedding</code> is the property prefix that configures the <code>EmbeddingModel</code> implementation for Azure OpenAI\n\n\n\nAll properties prefixed with <code>spring.ai.azure.openai.embedding.options</code> can be overridden at runtime by adding a request specific <a href=\"#embedding-options\">Runtime Options</a> to the <code>EmbeddingRequest</code> call.',0x00,'asciidoc::azure-openai-embeddings.adoc::Auto-configuration::Embedding Properties::0'),
('33fbd7f4-0d03-4ad0-aa93-a254e95bc737','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::zhipuai-embeddings.adoc::Prerequisites::Add Repositories and BOM::0'),
('6ff030aa-2a3f-4f21-9fbd-a2aa935b1e8f','The Oracle Vector Store implementation provides access to the underlying native Oracle client (<code>OracleConnection</code>) through the <code>getNativeClient()</code> method:\n\nOracleVectorStore vectorStore = context.getBean(OracleVectorStore.class);\nOptional&lt;OracleConnection&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    OracleConnection connection = nativeClient.get();\n    // Use the native client for Oracle-specific operations\n}\n\nThe native client gives you access to Oracle-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::oracle.adoc::Accessing the Native Client::0'),
('89a2bf65-1d67-4cde-9cd5-a2e2d878a5d9','To load the full wikipedia dataset:\n\nDownload <code>simplewiki-sstable.tar</code> from <a href=\"https://s.apache.org/simplewiki-sstable-tar\" class=\"bare\">https://s.apache.org/simplewiki-sstable-tar</a> (this will take a while, the file is tens of GBs)\nLoad the data:\n\n\ntar -xf simplewiki-sstable.tar -C ${CASSANDRA_DATA}/data/wikidata/articles-*/\nnodetool import wikidata articles ${CASSANDRA_DATA}/data/wikidata/articles-*/\n\n<div class=\"ulist\">\n<ul>\n<li>\n<p>If you have existing data in this table, check the tarball&#8217;s files don&#8217;t clobber existing sstables when doing the <code>tar</code>.</p>\n</li>\n<li>\n<p>An alternative to <code>nodetool import</code> is to just restart Cassandra.</p>\n</li>\n<li>\n<p>If there are any failures in the indexes they will be rebuilt automatically.</p>\n</li>\n</ul>\n</div>',0x00,'asciidoc::apache-cassandra.adoc::Advanced Example: Vector Store on top of Wikipedia Dataset::Loading the Complete Wikipedia Dataset::0'),
('e5373400-5b14-4f5c-b271-a329a2724cfa','Context Field\n\nOptionally provide context about the document that won&#8217;t be cited but can guide Claude&#8217;s understanding:\n\nCitationDocument document = CitationDocument.builder()\n    .plainText(\"...\")\n    .title(\"Legal Contract\")\n    .context(\"This is a merger agreement dated January 2024 between Company A and Company B\")\n    .build();\n\nControlling Citations\n\nBy default, citations are disabled for all documents (opt-in behavior).\nTo enable citations, explicitly set <code>citationsEnabled(true)</code>:\n\nCitationDocument document = CitationDocument.builder()\n    .plainText(\"The Eiffel Tower was completed in 1889...\")\n    .title(\"Historical Facts\")\n    .citationsEnabled(true)  // Explicitly enable citations for this document\n    .build();\n\nYou can also provide documents without citations for background context:\n\nCitationDocument backgroundDoc = CitationDocument.builder()\n    .plainText(\"Background information about the industry...\")\n    .title(\"Context Document\")\n    // citationsEnabled defaults to false - Claude will use this but not cite it\n    .build();\n\n<div class=\"paragraph\">\n<p>Anthropic requires consistent citation settings across all documents in a request.\nYou cannot mix citation-enabled and citation-disabled documents in the same request.</p>\n</div>',0x00,'asciidoc::anthropic-chat.adoc::Citations::Citation Document Options::0'),
('e0cc98c3-753b-4604-adc6-a32fd017399b','@SuppressWarnings(\"CheckReturnValue\")\npublic static class IntegerConstantContext extends ConstantContext {\n\n    public TerminalNode INTEGER_VALUE() {\n        return getToken(FiltersParser.INTEGER_VALUE, 0);\n    }\n\n    public TerminalNode MINUS() {\n        return getToken(FiltersParser.MINUS, 0);\n    }\n\n    public TerminalNode PLUS() {\n        return getToken(FiltersParser.PLUS, 0);\n    }\n\n    public IntegerConstantContext(ConstantContext ctx) {\n        copyFrom(ctx);\n    }\n\n    @Override\n    public void enterRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).enterIntegerConstant(this);\n    }\n\n    @Override\n    public void exitRule(ParseTreeListener listener) {\n        if (listener instanceof FiltersListener)\n            ((FiltersListener) listener).exitIntegerConstant(this);\n    }\n\n    @Override\n    public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n        if (visitor instanceof FiltersVisitor)\n            return ((FiltersVisitor<? extends T>) visitor).visitIntegerConstant(this);\n        else\n            return visitor.visitChildren(this);\n    }\n}',0x01,'cu::FiltersParser.java'),
('eecc997c-32d6-4fd4-8fb2-a3766920f904','// ############################################################\n// # NOTE: This is ANTLR4 auto-generated code. Do not modify! #\n// ############################################################\n/**\n * This interface defines a complete generic visitor for a parse tree produced by\n * {@link FiltersParser}.\n *\n * @param <T> The return type of the visit operation. Use {@link Void} for operations with\n * no return type.\n */\npublic interface FiltersVisitor<T> extends ParseTreeVisitor<T> {\n\n    /**\n     * Visit a parse tree produced by {@link FiltersParser#where}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitWhere(FiltersParser.WhereContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code NinExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitNinExpression(FiltersParser.NinExpressionContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code AndExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitAndExpression(FiltersParser.AndExpressionContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code InExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitInExpression(FiltersParser.InExpressionContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code NotExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitNotExpression(FiltersParser.NotExpressionContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code CompareExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitCompareExpression(FiltersParser.CompareExpressionContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code OrExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitOrExpression(FiltersParser.OrExpressionContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code GroupExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitGroupExpression(FiltersParser.GroupExpressionContext ctx);\n\n    /**\n     * Visit a parse tree produced by {@link FiltersParser#constantArray}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitConstantArray(FiltersParser.ConstantArrayContext ctx);\n\n    /**\n     * Visit a parse tree produced by {@link FiltersParser#compare}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitCompare(FiltersParser.CompareContext ctx);\n\n    /**\n     * Visit a parse tree produced by {@link FiltersParser#identifier}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitIdentifier(FiltersParser.IdentifierContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code LongConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitLongConstant(FiltersParser.LongConstantContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code IntegerConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitIntegerConstant(FiltersParser.IntegerConstantContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code DecimalConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitDecimalConstant(FiltersParser.DecimalConstantContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code TextConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitTextConstant(FiltersParser.TextConstantContext ctx);\n\n    /**\n     * Visit a parse tree produced by the {@code BooleanConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     * @return the visitor result\n     */\n    T visitBooleanConstant(FiltersParser.BooleanConstantContext ctx);\n}',0x01,'cu::FiltersVisitor.java'),
('11067484-abfc-43b4-a5ea-a377d365610a','Multimodality refers to a model&#8217;s ability to simultaneously understand and process information from various sources, including text, images, audio, and other data formats.',0x00,'asciidoc::openai-sdk-chat.adoc::Multimodal::0'),
('54d6cd70-c990-4fcb-9523-a38b53e1c067','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OpenSearch Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-opensearch&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file:\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-opensearch\'\n}\n\nFor both self-hosted and Amazon OpenSearch Service, use the same dependency.\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nPlease have a look at the list of <a href=\"#_configuration_properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nNow you can auto-wire the <code>OpenSearchVectorStore</code> as a vector store in your application:\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList&lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to OpenSearch\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::opensearch.adoc::Auto-configuration::0'),
('4646cea4-6257-47ec-bbd5-a3b10adaaa74','DiskANN (Disk-based Approximate Nearest Neighbor Search) is an innovative technology used in Azure Cosmos DB to enhance the performance of vector searches.\nIt enables efficient and scalable similarity searches across high-dimensional data by indexing embeddings stored in Cosmos DB.\n\nDiskANN provides the following benefits:\n\n<strong>Efficiency</strong>: By utilizing disk-based structures, DiskANN significantly reduces the time required to find nearest neighbors compared to traditional methods.\n<strong>Scalability</strong>: It can handle large datasets that exceed memory capacity, making it suitable for various applications, including machine learning and AI-driven solutions.\n<strong>Low Latency</strong>: DiskANN minimizes latency during search operations, ensuring that applications can retrieve results quickly even with substantial data volumes.\n\n\nIn the context of Spring AI for Azure Cosmos DB, vector searches will create and leverage DiskANN indexes to ensure optimal performance for similarity queries.',0x00,'asciidoc::azure-cosmos-db.adoc::What is DiskANN?::0'),
('889538ef-d6e8-4786-bd3d-a403f0617900','Removed all deprecations from 1.0.0-M8 (<a href=\"https://github.com/spring-projects/spring-ai/commit/76bee8ceb2854839f93a6c52876f50bb24219355\">76bee8c</a>)\nGeneral deprecation cleanup (<a href=\"https://github.com/spring-projects/spring-ai/commit/b6ce7f3e4a7aafe6b9031043f63813dde6e73605\">b6ce7f3</a>)',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M8::General Cleanup::0'),
('783f1201-58f3-4ba2-8286-a4819b483abd','This is an image of a fruit bowl with a simple design. The bowl is made of metal with curved wire edges that\ncreate an open structure, allowing the fruit to be visible from all angles. Inside the bowl, there are two\nyellow bananas resting on top of what appears to be a red apple. The bananas are slightly overripe, as\nindicated by the brown spots on their peels. The bowl has a metal ring at the top, likely to serve as a handle\nfor carrying. The bowl is placed on a flat surface with a neutral-colored background that provides a clear\nview of the fruit inside.',0x00,'asciidoc::openai-chat.adoc::Multimodal::Vision::1'),
('928588b0-688a-4663-999b-a487690ca7dc','The prefix <code>spring.ai.vertex.ai.embedding</code> is used as the property prefix that lets you connect to VertexAI Embedding API.\n\n\n\n<div class=\"paragraph\">\n<p>Enabling and disabling of the embedding auto-configurations are now configured via top level properties with the prefix <code>spring.ai.model.embedding</code>.</p>\n</div>\n<div class=\"paragraph\">\n<p>To enable, spring.ai.model.embedding.text=vertexai (It is enabled by default)</p>\n</div>\n<div class=\"paragraph\">\n<p>To disable, spring.ai.model.embedding.text=none (or any value which doesn&#8217;t match vertexai)</p>\n</div>\n<div class=\"paragraph\">\n<p>This change is done to allow configuration of multiple models.</p>\n</div>\n\nThe prefix <code>spring.ai.vertex.ai.embedding.text</code> is the property prefix that lets you configure the embedding model implementation for VertexAI Text Embedding.',0x00,'asciidoc::vertexai-embeddings-text.adoc::Auto-configuration::Embedding Properties::0'),
('94539dd5-16bd-4254-b2ae-a4a485e81dd6','@SuppressWarnings(\"CheckReturnValue\")\npublic static class ConstantContext extends ParserRuleContext {\n\n    public ConstantContext(ParserRuleContext parent, int invokingState) {\n        super(parent, invokingState);\n    }\n\n    @Override\n    public int getRuleIndex() {\n        return RULE_constant;\n    }\n\n    public ConstantContext() {\n    }\n\n    public void copyFrom(ConstantContext ctx) {\n        super.copyFrom(ctx);\n    }\n}',0x01,'cu::FiltersParser.java'),
('1a478718-076d-435c-9a31-a4ab6404726a','<code>InMemoryChatMemoryRepository</code> stores messages in memory using a <code>ConcurrentHashMap</code>.\n\nBy default, if no other repository is already configured, Spring AI auto-configures a <code>ChatMemoryRepository</code> bean of type <code>InMemoryChatMemoryRepository</code> that you can use directly in your application.\n\n@Autowired\nChatMemoryRepository chatMemoryRepository;\n\nIf you&#8217;d rather create the <code>InMemoryChatMemoryRepository</code> manually, you can do so as follows:\n\nChatMemoryRepository repository = new InMemoryChatMemoryRepository();',0x00,'asciidoc::chat-memory.adoc::Memory Storage::In-Memory Repository::0'),
('bf3f064a-566a-49f0-ba2c-a5a67be25b3c','public class ReReadingAdvisor implements BaseAdvisor {\n\n	private static final String DEFAULT_RE2_ADVISE_TEMPLATE = \"\"\"\n			{re2_input_query}\n			Read the question again: {re2_input_query}\n			\"\"\";\n\n	private final String re2AdviseTemplate;\n\n	private int order = 0;\n\n	public ReReadingAdvisor() {\n		this(DEFAULT_RE2_ADVISE_TEMPLATE);\n	}\n\n	public ReReadingAdvisor(String re2AdviseTemplate) {\n		this.re2AdviseTemplate = re2AdviseTemplate;\n	}\n\n	@Override\n	public ChatClientRequest before(ChatClientRequest chatClientRequest, AdvisorChain advisorChain) { // <b class=\"conum\">(1)</b>\n		String augmentedUserText = PromptTemplate.builder()\n			.template(this.re2AdviseTemplate)\n			.variables(Map.of(\"re2_input_query\", chatClientRequest.prompt().getUserMessage().getText()))\n			.build()\n			.render();\n\n		return chatClientRequest.mutate()\n			.prompt(chatClientRequest.prompt().augmentUserMessage(augmentedUserText))\n			.build();\n	}\n\n	@Override\n	public ChatClientResponse after(ChatClientResponse chatClientResponse, AdvisorChain advisorChain) {\n		return chatClientResponse;\n	}\n\n	@Override\n	public int getOrder() { // <b class=\"conum\">(2)</b>\n		return this.order;\n	}\n\n	public ReReadingAdvisor withOrder(int order) {\n		this.order = order;\n		return this;\n	}\n\n}\n\nThe <code>before</code> method augments the user&#8217;s input query applying the Re-Reading technique.\nYou can control the order of execution by setting the order value. Lower values execute first.\n\n\nSpring AI Built-in Advisors\n\nSpring AI framework provides several built-in advisors to enhance your AI interactions. Here&#8217;s an overview of the available advisors:\n\nChat Memory Advisors\n\nThese advisors manage conversation history in a chat memory store:\n\n<code>MessageChatMemoryAdvisor</code>\n<code>PromptChatMemoryAdvisor</code>\n<code>VectorStoreChatMemoryAdvisor</code>\n\n\nQuestion Answering Advisor\n\n<code>QuestionAnswerAdvisor</code>\n<code>RetrievalAugmentationAdvisor</code>\n\n\nReasoning Advisor\n\n<code>ReReadingAdvisor</code>\n\n\nContent Safety Advisor\n\n<code>SafeGuardAdvisor</code>',0x00,'asciidoc::advisors.adoc::Implementing an Advisor::Examples::1'),
('4f4cc312-cd8a-44df-8f15-a5d5483ea2e6','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-client-chat/src/main/java/org/springframework/ai/chat/prompt/Prompt.java\">Prompt</a> is a <code>ModelRequest</code> that encapsulates a list of <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/messages/Message.java\">Message</a> objects and optional model request options.\nThe following listing shows a truncated version of the <code>Prompt</code> class, excluding constructors and other utility methods:\n\npublic class Prompt implements ModelRequest&lt;List&lt;Message&gt;&gt; {\n\n    private final List&lt;Message&gt; messages;\n\n    private ChatOptions modelOptions;\n\n	@Override\n	public ChatOptions getOptions() {...}\n\n	@Override\n	public List&lt;Message&gt; getInstructions() {...}\n\n    // constructors and utility methods omitted\n}\n\nMessage\n\nThe <code>Message</code> interface encapsulates a <code>Prompt</code> textual content, a collection of metadata attributes, and a categorization known as <code>MessageType</code>.\n\nThe interface is defined as follows:\n\npublic interface Content {\n\n	String getText();\n\n	Map&lt;String, Object&gt; getMetadata();\n}\n\npublic interface Message extends Content {\n\n	MessageType getMessageType();\n}\n\nThe multimodal message types implement also the <code>MediaContent</code> interface providing a list of <code>Media</code> content objects.\n\npublic interface MediaContent extends Content {\n\n	Collection&lt;Media&gt; getMedia();\n\n}\n\nThe <code>Message</code> interface has various implementations that correspond to the categories of messages that an AI model can process:\n\nThe chat completion endpoint, distinguish between message categories based on conversational roles, effectively mapped by the <code>MessageType</code>.\n\nFor instance, OpenAI recognizes message categories for distinct conversational roles such as <code>system</code>, <code>user</code>, <code>function</code>, or <code>assistant</code>.\n\nWhile the term <code>MessageType</code> might imply a specific message format, in this context it effectively designates the role a message plays in the dialogue.\n\nFor AI models that do not use specific roles, the <code>UserMessage</code> implementation acts as a standard category, typically representing user-generated inquiries or instructions.\nTo understand the practical application and the relationship between <code>Prompt</code> and <code>Message</code>, especially in the context of these roles or message categories, see the detailed explanations in the <a href=\"api/prompt.html\">Prompts</a> section.\n\nChat Options\n\nRepresents the options that can be passed to the AI model. The <code>ChatOptions</code> class is a subclass of <code>ModelOptions</code> and is used to define few portable options that can be passed to the AI model.\nThe <code>ChatOptions</code> class is defined as follows:',0x00,'asciidoc::chatmodel.adoc::API Overview::Prompt::0'),
('b47bb714-5f3e-4acf-bc6c-a61853c83263','OpenAI-compatible inference servers like vLLM, Ollama, and others often support additional parameters beyond those defined in OpenAI&#8217;s standard API.\nFor example, these servers may accept parameters such as <code>top_k</code>, <code>repetition_penalty</code>, or other sampling controls that the official OpenAI API does not recognize.\n\nThe <code>extraBody</code> option allows you to pass arbitrary parameters to these servers.\nAny key-value pairs provided in <code>extraBody</code> are included at the top level of the JSON request, enabling you to leverage server-specific features while using Spring AI&#8217;s OpenAI client.\n\n<div class=\"paragraph\">\n<p>The <code>extraBody</code> parameter is intended for use with OpenAI-compatible servers, not the official OpenAI API.\nWhile the official OpenAI API will ignore unknown parameters, they serve no purpose there.\nAlways consult your specific server&#8217;s documentation to determine which parameters are supported.</p>\n</div>',0x00,'asciidoc::openai-chat.adoc::Using Extra Parameters with OpenAI-Compatible Servers::0'),
('a904f12e-1fd1-4b40-940b-a62473a19bca','<div class=\"paragraph\">\n<p>This section walks you through setting up <code>OpenSearchVectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://opensearch.org\">OpenSearch</a> is an open-source search and analytics engine originally forked from Elasticsearch, distributed under the Apache License 2.0. It enhances AI application development by simplifying the integration and management of AI-generated assets. OpenSearch supports vector, lexical, and hybrid search capabilities, leveraging advanced vector database functionalities to facilitate low-latency queries and similarity searches as detailed on the <a href=\"https://opensearch.org/platform/search/vector-database.html\">vector database page</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://opensearch.org/docs/latest/search-plugins/knn/index/\">OpenSearch k-NN</a> functionality allows users to query vector embeddings from large datasets. An embedding is a numerical representation of a data object, such as text, image, audio, or document. Embeddings can be stored in the index and queried using various similarity functions.</p>\n</div>',0x00,'asciidoc::opensearch.adoc::0'),
('059d8ed8-85f1-4ec3-bc4f-a62808f96142','The <code>ToolCallAdvisor</code> implements the tool calling loop as part of the advisor chain, rather than relying on the model&#8217;s internal tool execution. This enables other advisors in the chain to intercept and observe the tool calling process.\n\nKey features:\n\nDisables the model&#8217;s internal tool execution by setting <code>setInternalToolExecutionEnabled(false)</code>\nLoops through the advisor chain until no more tool calls are present\nSupports \"return direct\" functionality - when a tool execution has <code>returnDirect=true</code>, it interrupts the tool calling loop and returns the tool execution result directly to the client application instead of sending it back to the LLM\nUses <code>callAdvisorChain.copy(this)</code> to create a sub-chain for recursive calls\nIncludes null safety checks to handle cases where the chat response might be null\n\n\nExample usage:\n\nvar toolCallAdvisor = ToolCallAdvisor.builder()\n    .toolCallingManager(toolCallingManager)\n    .advisorOrder(BaseAdvisor.HIGHEST_PRECEDENCE + 300)\n    .build();\n\nvar chatClient = ChatClient.builder(chatModel)\n    .defaultAdvisors(toolCallAdvisor)\n    .build();\n\nReturn Direct Functionality\n\nThe \"return direct\" feature allows tools to bypass the LLM and return their results directly to the client application. This is useful when:\n\nThe tool&#8217;s output is the final answer and doesn&#8217;t need LLM processing\nYou want to reduce latency by avoiding an additional LLM call\nThe tool result should be returned as-is without interpretation\n\n\nWhen a tool execution has <code>returnDirect=true</code>, the <code>ToolCallAdvisor</code> will:\n\nExecute the tool call as normal\nDetect the <code>returnDirect</code> flag in the <code>ToolExecutionResult</code>\nBreak out of the tool calling loop\nReturn the tool execution result directly to the client application as a <code>ChatResponse</code> with the tool&#8217;s output as the generation content',0x00,'asciidoc::advisors-recursive.adoc::Built-in Recursive Advisors::ToolCallAdvisor::0'),
('ae035de6-f338-448e-8a09-a658f8a049b9','You can register custom Java functions with the <code>OllamaChatModel</code> and have the Ollama model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.\nRead more about <a href=\"api/tools.html\">Tool Calling</a>.\n\nYou need Ollama 0.2.8 or newer to use the functional calling capabilities and Ollama 0.4.6 or newer to use them in streaming mode.',0x00,'asciidoc::ollama-chat.adoc::Function Calling::0'),
('3267fa89-e70b-4ea9-a395-a68e066f3176','Google GenAI provides support for PDF input types.\nUse the <code>application/pdf</code> media type to attach a PDF file to the message:\n\nvar pdfData = new ClassPathResource(\"/spring-ai-reference-overview.pdf\");\n\nvar userMessage = UserMessage.builder()\n			.text(\"You are a very professional document summarization specialist. Please summarize the given document.\")\n			.media(List.of(new Media(new MimeType(\"application\", \"pdf\"), pdfData)))\n			.build();\n\nvar response = this.chatModel.call(new Prompt(List.of(userMessage)));',0x00,'asciidoc::google-genai-chat.adoc::Multimodal::PDF::0'),
('2cf2a0c4-e995-4d1a-8b81-a6aa21a62a4d','The <code>gpt-4o-audio-preview</code> model can generate audio responses.\n\nExample of generating audio output:\n\nvar userMessage = new UserMessage(\"Tell me a joke about Spring Framework\");\n\nChatResponse response = chatModel.call(\n    new Prompt(userMessage,\n        OpenAiSdkChatOptions.builder()\n            .model(\"gpt-4o-audio-preview\")\n            .outputModalities(List.of(\"text\", \"audio\"))\n            .outputAudio(new AudioParameters(Voice.ALLOY, AudioResponseFormat.WAV))\n            .build()));\n\nString text = response.getResult().getOutput().getContent(); // audio transcript\nbyte[] waveAudio = response.getResult().getOutput().getMedia().get(0).getDataAsByteArray(); // audio data',0x00,'asciidoc::openai-sdk-chat.adoc::Multimodal::Output Audio::0'),
('44a6506e-5335-4e46-a9aa-a6d702ecad21','public static class FilterExpressionVisitor extends FiltersBaseVisitor<Filter.Operand> {\n\n    private static final Map<String, Filter.ExpressionType> COMP_EXPRESSION_TYPE_MAP = Map.of(\"==\", Filter.ExpressionType.EQ, \"!=\", Filter.ExpressionType.NE, \">\", Filter.ExpressionType.GT, \">=\", Filter.ExpressionType.GTE, \"<\", Filter.ExpressionType.LT, \"<=\", Filter.ExpressionType.LTE);\n\n    @Override\n    public Filter.Operand visitWhere(FiltersParser.WhereContext ctx) {\n        return this.visit(ctx.booleanExpression());\n    }\n\n    @Override\n    public Filter.Operand visitIdentifier(FiltersParser.IdentifierContext ctx) {\n        return new Filter.Key(ctx.getText());\n    }\n\n    @Override\n    public Filter.Operand visitTextConstant(FiltersParser.TextConstantContext ctx) {\n        String onceQuotedText = removeOuterQuotes(ctx.getText());\n        return new Filter.Value(onceQuotedText);\n    }\n\n    private String removeOuterQuotes(String in) {\n        return in.substring(1, in.length() - 1);\n    }\n\n    @Override\n    public Filter.Operand visitIntegerConstant(FiltersParser.IntegerConstantContext ctx) {\n        return new Filter.Value(Integer.valueOf(ctx.getText()));\n    }\n\n    @Override\n    public Filter.Operand visitDecimalConstant(FiltersParser.DecimalConstantContext ctx) {\n        return new Filter.Value(Double.valueOf(ctx.getText()));\n    }\n\n    @Override\n    public Filter.Operand visitBooleanConstant(FiltersParser.BooleanConstantContext ctx) {\n        return new Filter.Value(Boolean.valueOf(ctx.getText()));\n    }\n\n    @Override\n    public Filter.Operand visitConstantArray(FiltersParser.ConstantArrayContext ctx) {\n        List<Object> list = new ArrayList<>();\n        ctx.constant().forEach(constantCtx -> list.add(((Filter.Value) this.visit(constantCtx)).value()));\n        return new Filter.Value(list);\n    }\n\n    @Override\n    public Filter.Operand visitInExpression(FiltersParser.InExpressionContext ctx) {\n        return new Filter.Expression(Filter.ExpressionType.IN, this.visitIdentifier(ctx.identifier()), this.visitConstantArray(ctx.constantArray()));\n    }\n\n    @Override\n    public Filter.Operand visitNinExpression(FiltersParser.NinExpressionContext ctx) {\n        return new Filter.Expression(Filter.ExpressionType.NIN, this.visitIdentifier(ctx.identifier()), this.visitConstantArray(ctx.constantArray()));\n    }\n\n    @Override\n    public Filter.Operand visitCompareExpression(FiltersParser.CompareExpressionContext ctx) {\n        return new Filter.Expression(this.covertCompare(ctx.compare().getText()), this.visitIdentifier(ctx.identifier()), this.visit(ctx.constant()));\n    }\n\n    private Filter.ExpressionType covertCompare(String compare) {\n        if (!COMP_EXPRESSION_TYPE_MAP.containsKey(compare)) {\n            throw new RuntimeException(\"Unknown compare operator: \" + compare);\n        }\n        return COMP_EXPRESSION_TYPE_MAP.get(compare);\n    }\n\n    @Override\n    public Filter.Operand visitAndExpression(FiltersParser.AndExpressionContext ctx) {\n        return new Filter.Expression(Filter.ExpressionType.AND, this.visit(ctx.left), this.visit(ctx.right));\n    }\n\n    @Override\n    public Filter.Operand visitOrExpression(FiltersParser.OrExpressionContext ctx) {\n        return new Filter.Expression(Filter.ExpressionType.OR, this.visit(ctx.left), this.visit(ctx.right));\n    }\n\n    @Override\n    public Filter.Operand visitGroupExpression(FiltersParser.GroupExpressionContext ctx) {\n        return new Filter.Group(castToExpression(this.visit(ctx.booleanExpression())));\n    }\n\n    @Override\n    public Filter.Operand visitNotExpression(NotExpressionContext ctx) {\n        return new Filter.Expression(Filter.ExpressionType.NOT, this.visit(ctx.booleanExpression()), null);\n    }\n\n    @Override\n    public Filter.Operand visitLongConstant(FiltersParser.LongConstantContext ctx) {\n        String text = ctx.getText();\n        // Remove the trailing \'l\' or \'L\'\n        long value = Long.parseLong(text.substring(0, text.length() - 1));\n        return new Filter.Value(value);\n    }\n\n    public Filter.Expression castToExpression(Filter.Operand expression) {\n        if (expression instanceof Filter.Group group) {\n            // Remove the top-level grouping.\n            return group.content();\n        } else if (expression instanceof Filter.Expression exp) {\n            return exp;\n        }\n        throw new RuntimeException(\"Invalid expression: \" + expression);\n    }\n}',0x01,'cu::FilterExpressionTextParser.java'),
('95a6bee1-88d7-49f9-bfc3-a6e7446ab94d','Post-Retrieval modules are responsible for processing the retrieved documents to achieve the best possible generation results.\n\nDocument Post-Processing\n\nA component for post-processing retrieved documents based on a query, addressing challenges such as <em>lost-in-the-middle</em>, context length restrictions from the model, and the need to reduce noise and redundancy in the retrieved information.\n\nFor example, it could rank documents based on their relevance to the query, remove irrelevant or redundant documents, or compress the content of each document to reduce noise and redundancy.',0x00,'asciidoc::retrieval-augmented-generation.adoc::Modules::Post-Retrieval::0'),
('8e4f6747-537c-4e26-a8b3-a6ebedb764a9','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with Neo4j store as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; \'article_type\' == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"author\", \"john\", \"jill\"),\n        b.eq(\"article_type\", \"blog\")).build()).build());\n\nThose (portable) filter expressions get automatically converted into the proprietary Neo4j <code>WHERE</code> <a href=\"https://neo4j.com/developer/cypher/filtering-query-results/\">filter expressions</a>.\n\nFor example, this portable filter expression:\n\nauthor in [\'john\', \'jill\'] &amp;&amp; \'article_type\' == \'blog\'\n\nis converted into the proprietary Neo4j filter format:\n\nnode.`metadata.author` IN [\"john\",\"jill\"] AND node.`metadata.\'article_type\'` = \"blog\"',0x00,'asciidoc::neo4j.adoc::Metadata Filtering::0'),
('ae76a21d-a998-4658-a9eb-a7784546927e','To run things in Java, we need to <strong>serialize the Tokenizer and the Transformer Model</strong> into <code>ONNX</code> format.\n\nSerialize with optimum-cli - One, quick, way to achieve this, is to use the <a href=\"https://huggingface.co/docs/optimum/exporters/onnx/usage_guides/export_a_model#exporting-a-model-to-onnx-using-the-cli\">optimum-cli</a> command line tool.\nThe following snippet prepares a python virtual environment, installs the required packages and serializes (e.g. exports) the specified model using <code>optimum-cli</code> :\n\npython3 -m venv venv\nsource ./venv/bin/activate\n(venv) pip install --upgrade pip\n(venv) pip install optimum onnx onnxruntime sentence-transformers\n(venv) optimum-cli export onnx --model sentence-transformers/all-MiniLM-L6-v2 onnx-output-folder\n\nThe snippet exports the <a href=\"https://huggingface.co/sentence-transformers/all-MiniLM-L6-v2\">sentence-transformers/all-MiniLM-L6-v2</a> transformer into the <code>onnx-output-folder</code> folder. The latter includes the <code>tokenizer.json</code> and <code>model.onnx</code> files used by the embedding model.\n\nIn place of the all-MiniLM-L6-v2 you can pick any huggingface transformer identifier or provide direct file path.',0x00,'asciidoc::onnx.adoc::Prerequisites::0'),
('687fbec8-319b-4436-a2ef-a78baeffba48','The ChatClient validates metadata to ensure data integrity:\n\nMetadata keys cannot be null or empty\nMetadata values cannot be null\nWhen passing a Map, neither keys nor values can contain null elements\n\n\n// This will throw an IllegalArgumentException\nchatClient.prompt()\n    .user(u -&gt; u.text(\"Hello\")\n        .metadata(null, \"value\"))  // Invalid: null key\n    .call()\n    .content();\n\n// This will also throw an IllegalArgumentException\nchatClient.prompt()\n    .user(u -&gt; u.text(\"Hello\")\n        .metadata(\"key\", null))    // Invalid: null value\n    .call()\n    .content();',0x00,'asciidoc::chatclient.adoc::Message Metadata::Metadata Validation::0');
INSERT INTO `source` VALUES
('ac587862-dc74-4587-8327-a7e30605a9f0','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nThen add the PgVectorStore boot starter dependency to your project:\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-starter-vector-store-pgvector&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-pgvector\'\n}\n\nThe vector store implementation can initialize the required schema for you, but you must opt-in by specifying the <code>initializeSchema</code> boolean in the appropriate constructor or by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\n\nThis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nThe Vector Store also requires an <code>EmbeddingModel</code> instance to calculate embeddings for the documents.\nYou can pick one of the available <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel Implementations</a>.\n\nFor example, to use the <a href=\"api/embeddings/openai-embeddings.html\">OpenAI EmbeddingModel</a>, add the following dependency to your project:\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nTo connect to and configure the <code>PgVectorStore</code>, you need to provide access details for your instance.\nA simple configuration can be provided via Spring Boot&#8217;s <code>application.yml</code>.\n\nspring:\n  datasource:\n    url: jdbc:postgresql://localhost:5432/postgres\n    username: postgres\n    password: postgres\n  ai:\n	vectorstore:\n	  pgvector:\n		index-type: HNSW\n		distance-type: COSINE_DISTANCE\n		dimensions: 1536\n		max-document-batch-size: 10000 # Optional: Maximum number of documents per batch',0x00,'asciidoc::pgvector.adoc::Auto-Configuration::0'),
('89d66b6d-9ac4-420d-8200-a820c3ecde8c','Spring AI provides an elegant Java API for implementing all major prompt engineering techniques. By combining these techniques with Spring&#8217;s powerful entity mapping and fluent API, developers can build sophisticated AI-powered applications with clean, maintainable code.\n\nThe most effective approach often involves combining multiple techniques - for example, using system prompts with few-shot examples, or chain-of-thought with role prompting. Spring AI&#8217;s flexible API makes these combinations straightforward to implement.\n\nFor production applications, remember to:\n\nTest prompts with different parameters (temperature, top-k, top-p)\nConsider using self-consistency for critical decision-making\nLeverage Spring AI&#8217;s entity mapping for type-safe responses\nUse contextual prompting to provide application-specific knowledge\n\n\nWith these techniques and Spring AI&#8217;s powerful abstractions, you can create robust AI-powered applications that deliver consistent, high-quality results.',0x00,'asciidoc::prompt-engineering-patterns.adoc::Conclusion::0'),
('14938bd2-b01c-44a1-ba77-a8be9f47bba6','The <code>spring.ai.tool</code> observations are recorded when performing tool calling in the context of a chat model interaction. They measure the time spent on toll call completion and propagate the related tracing information.',0x00,'asciidoc::index.adoc::Tool Calling::0'),
('eb5efd16-82a6-4250-b35a-a8c3eafcf22e','public static final class Builder {\n\n    private ChatClient.Builder chatClientBuilder;\n\n    @Nullable\n    private PromptTemplate promptTemplate;\n\n    private Builder() {\n    }\n\n    public Builder chatClientBuilder(ChatClient.Builder chatClientBuilder) {\n        this.chatClientBuilder = chatClientBuilder;\n        return this;\n    }\n\n    public Builder promptTemplate(PromptTemplate promptTemplate) {\n        this.promptTemplate = promptTemplate;\n        return this;\n    }\n\n    public CompressionQueryTransformer build() {\n        return new CompressionQueryTransformer(this.chatClientBuilder, this.promptTemplate);\n    }\n}',0x01,'cu::CompressionQueryTransformer.java'),
('aac7d589-4a6b-4cb6-9b39-a90f75c4e422','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Typesense Vector Store.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-typesense&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-typesense\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nPlease have a look at the list of <a href=\"#_configuration_properties\">configuration parameters</a> for the vector store to learn about the default values and configuration options.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nThe vector store implementation can initialize the requisite schema for you but you must opt-in by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\n\nAdditionally you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nNow you can auto-wire the <code>TypesenseVectorStore</code> as a vector store in your application:\n\n@Autowired VectorStore vectorStore;\n\n// ...\n\nList&lt;Document&gt; documents = List.of(\n    new Document(\"Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!! Spring AI rocks!!\", Map.of(\"meta1\", \"meta1\")),\n    new Document(\"The World is Big and Salvation Lurks Around the Corner\"),\n    new Document(\"You walk forward facing the past and you turn back toward the future.\", Map.of(\"meta2\", \"meta2\")));\n\n// Add the documents to Typesense\nvectorStore.add(documents);\n\n// Retrieve documents similar to a query\nList&lt;Document&gt; results = vectorStore.similaritySearch(SearchRequest.builder().query(\"Spring\").topK(5).build());',0x00,'asciidoc::typesense.adoc::Auto-configuration::0'),
('eaf66aca-43ff-483c-89e9-a92eb0dc814a','<div class=\"paragraph\">\n<p>This section walks you through setting up the Pinecone <code>VectorStore</code> to store document embeddings and perform similarity searches.</p>\n</div>\n<div class=\"paragraph\">\n<p><a href=\"https://www.pinecone.io/\">Pinecone</a> is a popular cloud-based vector database, which allows you to store and search vectors efficiently.</p>\n</div>',0x00,'asciidoc::pinecone.adoc::0'),
('0e62766f-7089-4717-b570-a959fa251dd1','To use the 1.0.0-SNAPSHOT version, you need to add the snapshot repositories to your build file.\nFor detailed instructions, refer to the <a href=\"getting-started.html#snapshots-add-snapshot-repositories\">Snapshots - Add Snapshot Repositories</a> section in the Getting Started guide.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-SNAPSHOT::Add Snapshot Repositories::0'),
('6d1fc5e2-079e-4da7-a061-a98bb5555aea','You can leverage existing <a href=\":api/structured-output-converter.html#_bean_output_converter\">BeanOutputConverter</a> utilities:\n\nrecord MathReasoning(\n    @JsonProperty(required = true, value = \"steps\") Steps steps,\n    @JsonProperty(required = true, value = \"final_answer\") String finalAnswer) {\n\n    record Steps(\n        @JsonProperty(required = true, value = \"items\") Items[] items) {\n\n        record Items(\n            @JsonProperty(required = true, value = \"explanation\") String explanation,\n            @JsonProperty(required = true, value = \"output\") String output) {\n        }\n    }\n}\n\nvar outputConverter = new BeanOutputConverter&lt;&gt;(MathReasoning.class);\nString jsonSchema = outputConverter.getJsonSchema();\n\nPrompt prompt = new Prompt(\n    \"how can I solve 8x + 7 = -23\",\n    OpenAiSdkChatOptions.builder()\n        .model(\"gpt-4o-mini\")\n        .responseFormat(ResponseFormat.builder()\n            .type(ResponseFormat.Type.JSON_SCHEMA)\n            .jsonSchema(jsonSchema)\n            .build())\n        .build());\n\nChatResponse response = chatModel.call(prompt);\nMathReasoning mathReasoning = outputConverter.convert(\n    response.getResult().getOutput().getContent());',0x00,'asciidoc::openai-sdk-chat.adoc::Structured Outputs::Integrating with BeanOutputConverter::0'),
('3ac169cf-e1b9-4818-b399-aa003d50b81b','Use the <code>CitationDocument</code> builder to create documents that can be cited:\n\nPlain Text Documents\n\nCitationDocument document = CitationDocument.builder()\n    .plainText(\"The Eiffel Tower was completed in 1889 in Paris, France. \" +\n               \"It stands 330 meters tall and was designed by Gustave Eiffel.\")\n    .title(\"Eiffel Tower Facts\")\n    .citationsEnabled(true)\n    .build();\n\nPDF Documents\n\n// From file path\nCitationDocument document = CitationDocument.builder()\n    .pdfFile(\"path/to/document.pdf\")\n    .title(\"Technical Specification\")\n    .citationsEnabled(true)\n    .build();\n\n// From byte array\nbyte[] pdfBytes = loadPdfBytes();\nCitationDocument document = CitationDocument.builder()\n    .pdf(pdfBytes)\n    .title(\"Product Manual\")\n    .citationsEnabled(true)\n    .build();\n\nCustom Content Blocks\n\nFor fine-grained citation control, use custom content blocks:\n\nCitationDocument document = CitationDocument.builder()\n    .customContent(\n        \"The Great Wall of China is approximately 21,196 kilometers long.\",\n        \"It was built over many centuries, starting in the 7th century BC.\",\n        \"The wall was constructed to protect Chinese states from invasions.\"\n    )\n    .title(\"Great Wall Facts\")\n    .citationsEnabled(true)\n    .build();',0x00,'asciidoc::anthropic-chat.adoc::Citations::Creating Citation Documents::0'),
('4e7b6b14-fd77-4a38-9fe8-aa6f7b7be7d0','/**\n * Assertion utility class that assists in validating arguments for prompt-related\n * operations.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic final class PromptAssert {\n\n    private PromptAssert() {\n    }\n\n    /**\n     * Assert that the given prompt template contains the required placeholders.\n     * @param promptTemplate the prompt template to check\n     * @param placeholders the placeholders that must be present in the prompt template\n     */\n    public static void templateHasRequiredPlaceholders(PromptTemplate promptTemplate, String... placeholders) {\n        Assert.notNull(promptTemplate, \"promptTemplate cannot be null\");\n        Assert.notEmpty(placeholders, \"placeholders cannot be null or empty\");\n        List<String> missingPlaceholders = new ArrayList<>();\n        for (String placeholder : placeholders) {\n            if (!promptTemplate.getTemplate().contains(placeholder)) {\n                missingPlaceholders.add(placeholder);\n            }\n        }\n        if (!missingPlaceholders.isEmpty()) {\n            throw new IllegalArgumentException(\"The following placeholders must be present in the prompt template: %s\".formatted(String.join(\",\", missingPlaceholders)));\n        }\n    }\n}',0x01,'cu::PromptAssert.java'),
('d3b5527b-b301-4d30-bb20-aa8a553c26ed','<strong>Separation of Concerns</strong>: Clearly separates read operations from write operations.\n<strong>Interface Segregation</strong>: Clients that only need retrieval functionality aren&#8217;t exposed to mutation methods.\n<strong>Functional Interface</strong>: Can be implemented with lambda expressions or method references for simple use cases.\n<strong>Reduced Dependencies</strong>: Components that only need to perform searches don&#8217;t need to depend on the full <code>VectorStore</code> interface.',0x00,'asciidoc::vectordbs.adoc::Retrieval Operations with VectorStoreRetriever::Benefits of Using VectorStoreRetriever::0'),
('5e3ddc56-2c02-4127-a438-aaa2a1cad4e4','<div class=\"paragraph\">\n<p>A vector database is a specialized type of database that plays an essential role in AI applications.</p>\n</div>\n<div class=\"paragraph\">\n<p>In vector databases, queries differ from traditional relational databases.\nInstead of exact matches, they perform similarity searches.\nWhen given a vector as a query, a vector database returns vectors that are &#8220;similar&#8221; to the query vector.\nFurther details on how this similarity is calculated at a high-level is provided in a <a href=\"api/vectordbs/understand-vectordbs.html#vectordbs-similarity\">Vector Similarity</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>Vector databases are used to integrate your data with AI models.\nThe first step in their usage is to load your data into a vector database.\nThen, when a user query is to be sent to the AI model, a set of similar documents is first retrieved.\nThese documents then serve as the context for the user&#8217;s question and are sent to the AI model, along with the user&#8217;s query.\nThis technique is known as <a href=\"concepts.html#concept-rag\">Retrieval Augmented Generation (RAG)</a>.</p>\n</div>\n<div class=\"paragraph\">\n<p>The following sections describe the Spring AI interface for using multiple vector database implementations and some high-level sample usage.</p>\n</div>\n<div class=\"paragraph\">\n<p>The last section is intended to demystify the underlying approach of similarity searching in vector databases.</p>\n</div>',0x00,'asciidoc::vectordbs.adoc::0'),
('dfd726de-dfd0-4c53-80ab-aabc9d93c7fa','Spring AI allows you to configure your response format either programmatically using the <code>OpenAiChatOptions</code> builder or through application properties.\n\nUsing the Chat Options Builder\n\nYou can set the response format programmatically with the <code>OpenAiChatOptions</code> builder as shown below:\n\nString jsonSchema = \"\"\"\n        {\n            \"type\": \"object\",\n            \"properties\": {\n                \"steps\": {\n                    \"type\": \"array\",\n                    \"items\": {\n                        \"type\": \"object\",\n                        \"properties\": {\n                            \"explanation\": { \"type\": \"string\" },\n                            \"output\": { \"type\": \"string\" }\n                        },\n                        \"required\": [\"explanation\", \"output\"],\n                        \"additionalProperties\": false\n                    }\n                },\n                \"final_answer\": { \"type\": \"string\" }\n            },\n            \"required\": [\"steps\", \"final_answer\"],\n            \"additionalProperties\": false\n        }\n        \"\"\";\n\nPrompt prompt = new Prompt(\"how can I solve 8x + 7 = -23\",\n        OpenAiChatOptions.builder()\n            .model(ChatModel.GPT_4_O_MINI)\n            .responseFormat(new ResponseFormat(ResponseFormat.Type.JSON_SCHEMA, this.jsonSchema))\n            .build());\n\nChatResponse response = this.openAiChatModel.call(this.prompt);\n\nAdhere to the OpenAI <a href=\"https://platform.openai.com/docs/guides/structured-outputs/supported-schemas\">subset of the JSON Schema language</a> format.\n\nIntegrating with BeanOutputConverter Utilities\n\nYou can leverage existing <a href=\":api/structured-output-converter.html#_bean_output_converter\">BeanOutputConverter</a> utilities to automatically generate the JSON Schema from your domain objects and later convert the structured response into domain-specific instances:',0x00,'asciidoc::openai-chat.adoc::Structured Outputs::Configuration::0'),
('60e8079e-6378-4040-8f6d-aac3785bfe1c','<div class=\"paragraph\">\n<p><a href=\"https://www.oracle.com/artificial-intelligence/generative-ai/generative-ai-service/\">OCI GenAI Service</a> offers generative AI chat with on-demand models, or dedicated AI clusters.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <a href=\"https://docs.oracle.com/en-us/iaas/Content/generative-ai/chat-models.htm\">OCI Chat Models Page</a> and <a href=\"https://docs.oracle.com/en-us/iaas/Content/generative-ai/use-playground-embed.htm\">OCI Generative AI Playground</a> provide detailed information about using and hosting chat models on OCI.</p>\n</div>',0x00,'asciidoc::cohere-chat.adoc::0'),
('74ea0618-3160-4b1f-8cbd-aad0e6d4e8b9','You need a SAP HANA Cloud vector engine account - Refer <a href=\"api/vectordbs/hanadb-provision-a-trial-account.html\">SAP HANA Cloud vector engine - provision a trial account</a> guide to create a trial account.\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the vector store.',0x00,'asciidoc::hana.adoc::Prerequisites::0'),
('0eb879df-ab13-4a90-b343-abb944238055','A vector database stores data that the AI model is unaware of. When a user question is sent to the AI model, a <code>QuestionAnswerAdvisor</code> queries the vector database for documents related to the user question.\n\nThe response from the vector database is appended to the user text to provide context for the AI model to generate a response.\n\nAssuming you have already loaded data into a <code>VectorStore</code>, you can perform Retrieval Augmented Generation (RAG) by providing an instance of <code>QuestionAnswerAdvisor</code> to the <code>ChatClient</code>.\n\nChatResponse response = ChatClient.builder(chatModel)\n        .build().prompt()\n        .advisors(QuestionAnswerAdvisor.builder(vectorStore).build())\n        .user(userText)\n        .call()\n        .chatResponse();\n\nIn this example, the <code>QuestionAnswerAdvisor</code> will perform a similarity search over all documents in the Vector Database. To restrict the types of documents that are searched, the <code>SearchRequest</code> takes an SQL like filter expression that is portable across all <code>VectorStores</code>.\n\nThis filter expression can be configured when creating the <code>QuestionAnswerAdvisor</code> and hence will always apply to all <code>ChatClient</code> requests, or it can be provided at runtime per request.\n\nHere is how to create an instance of <code>QuestionAnswerAdvisor</code> where the threshold is <code>0.8</code> and to return the top <code>6</code> results.\n\nvar qaAdvisor = QuestionAnswerAdvisor.builder(vectorStore)\n        .searchRequest(SearchRequest.builder().similarityThreshold(0.8d).topK(6).build())\n        .build();\n\nDynamic Filter Expressions\n\nUpdate the <code>SearchRequest</code> filter expression at runtime using the <code>FILTER_EXPRESSION</code> advisor context parameter:\n\nChatClient chatClient = ChatClient.builder(chatModel)\n    .defaultAdvisors(QuestionAnswerAdvisor.builder(vectorStore)\n        .searchRequest(SearchRequest.builder().build())\n        .build())\n    .build();\n\n// Update filter expression at runtime\nString content = this.chatClient.prompt()\n    .user(\"Please answer my question XYZ\")\n    .advisors(a -&gt; a.param(QuestionAnswerAdvisor.FILTER_EXPRESSION, \"type == \'Spring\'\"))\n    .call()\n    .content();\n\nThe <code>FILTER_EXPRESSION</code> parameter allows you to dynamically filter the search results based on the provided expression.\n\nCustom Template\n\nThe <code>QuestionAnswerAdvisor</code> uses a default template to augment the user question with the retrieved documents. You can customize this behavior by providing your own <code>PromptTemplate</code> object via the <code>.promptTemplate()</code> builder method.',0x00,'asciidoc::retrieval-augmented-generation.adoc::Advisors::QuestionAnswerAdvisor::0'),
('f1783e01-28c7-4c9a-89fa-ac516aa38576','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::mistralai-embeddings.adoc::Prerequisites::Add Repositories and BOM::0'),
('d569bc1d-d7f3-40e1-a45a-ad407c843420','/**\n * Abstract base class for {@link VectorStore} implementations that provides observation\n * capabilities.\n *\n * @author Christian Tzolov\n * @author Soby Chacko\n * @since 1.0.0\n */\npublic abstract class AbstractObservationVectorStore implements VectorStore {\n\n    private static final VectorStoreObservationConvention DEFAULT_OBSERVATION_CONVENTION = new DefaultVectorStoreObservationConvention();\n\n    private final ObservationRegistry observationRegistry;\n\n    @Nullable\n    private final VectorStoreObservationConvention customObservationConvention;\n\n    protected final EmbeddingModel embeddingModel;\n\n    protected final BatchingStrategy batchingStrategy;\n\n    private AbstractObservationVectorStore(EmbeddingModel embeddingModel, ObservationRegistry observationRegistry, @Nullable VectorStoreObservationConvention customObservationConvention, BatchingStrategy batchingStrategy) {\n        this.embeddingModel = embeddingModel;\n        this.observationRegistry = observationRegistry;\n        this.customObservationConvention = customObservationConvention;\n        this.batchingStrategy = batchingStrategy;\n    }\n\n    /**\n     * Creates a new AbstractObservationVectorStore instance with the specified builder\n     * settings. Initializes observation-related components and the embedding model.\n     * @param builder the builder containing configuration settings\n     */\n    public AbstractObservationVectorStore(AbstractVectorStoreBuilder<?> builder) {\n        this(builder.getEmbeddingModel(), builder.getObservationRegistry(), builder.getCustomObservationConvention(), builder.getBatchingStrategy());\n    }\n\n    /**\n     * Create a new {@link AbstractObservationVectorStore} instance.\n     * @param documents the documents to add\n     */\n    @Override\n    public void add(List<Document> documents) {\n        validateNonTextDocuments(documents);\n        VectorStoreObservationContext observationContext = this.createObservationContextBuilder(VectorStoreObservationContext.Operation.ADD.value()).build();\n        VectorStoreObservationDocumentation.AI_VECTOR_STORE.observation(this.customObservationConvention, DEFAULT_OBSERVATION_CONVENTION, () -> observationContext, this.observationRegistry).observe(() -> this.doAdd(documents));\n    }\n\n    private void validateNonTextDocuments(List<Document> documents) {\n        if (documents == null) {\n            return;\n        }\n        for (Document document : documents) {\n            if (document != null && !document.isText()) {\n                throw new IllegalArgumentException(\"Only text documents are supported for now. One of the documents contains non-text content.\");\n            }\n        }\n    }\n\n    @Override\n    public void delete(List<String> deleteDocIds) {\n        VectorStoreObservationContext observationContext = this.createObservationContextBuilder(VectorStoreObservationContext.Operation.DELETE.value()).build();\n        VectorStoreObservationDocumentation.AI_VECTOR_STORE.observation(this.customObservationConvention, DEFAULT_OBSERVATION_CONVENTION, () -> observationContext, this.observationRegistry).observe(() -> this.doDelete(deleteDocIds));\n    }\n\n    @Override\n    public void delete(Filter.Expression filterExpression) {\n        VectorStoreObservationContext observationContext = this.createObservationContextBuilder(VectorStoreObservationContext.Operation.DELETE.value()).build();\n        VectorStoreObservationDocumentation.AI_VECTOR_STORE.observation(this.customObservationConvention, DEFAULT_OBSERVATION_CONVENTION, () -> observationContext, this.observationRegistry).observe(() -> this.doDelete(filterExpression));\n    }\n\n    @Override\n    // Micrometer Observation#observe returns the value of the Supplier, which is never\n    // null\n    @SuppressWarnings(\"DataFlowIssue\")\n    public List<Document> similaritySearch(SearchRequest request) {\n        VectorStoreObservationContext searchObservationContext = this.createObservationContextBuilder(VectorStoreObservationContext.Operation.QUERY.value()).queryRequest(request).build();\n        return VectorStoreObservationDocumentation.AI_VECTOR_STORE.observation(this.customObservationConvention, DEFAULT_OBSERVATION_CONVENTION, () -> searchObservationContext, this.observationRegistry).observe(() -> {\n            var documents = this.doSimilaritySearch(request);\n            searchObservationContext.setQueryResponse(documents);\n            return documents;\n        });\n    }\n\n    /**\n     * Perform the actual add operation.\n     * @param documents the documents to add\n     */\n    public abstract void doAdd(List<Document> documents);\n\n    /**\n     * Perform the actual delete operation.\n     * @param idList the list of document IDs to delete\n     */\n    public abstract void doDelete(List<String> idList);\n\n    /**\n     * Template method for concrete implementations to provide filter-based deletion\n     * logic.\n     * @param filterExpression Filter expression to identify documents to delete\n     */\n    protected void doDelete(Filter.Expression filterExpression) {\n        // this is temporary until we implement this method in all concrete vector stores,\n        // at which point\n        // this method will become an abstract method.\n        throw new UnsupportedOperationException();\n    }\n\n    /**\n     * Perform the actual similarity search operation.\n     * @param request the search request\n     * @return the list of documents that match the query request conditions\n     */\n    public abstract List<Document> doSimilaritySearch(SearchRequest request);\n\n    /**\n     * Create a new {@link VectorStoreObservationContext.Builder} instance.\n     * @param operationName the operation name\n     * @return the observation context builder\n     */\n    public abstract VectorStoreObservationContext.Builder createObservationContextBuilder(String operationName);\n}',0x01,'cu::AbstractObservationVectorStore.java'),
('51754920-7018-4947-842c-ad9cf1508c44','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::postgresml-embeddings.adoc::Add Repositories and BOM::0'),
('bf876b75-ac6e-4e90-9c9b-adc3c968ae72','The <code>deepseek-reasoner</code> is a reasoning model developed by DeepSeek. Before delivering the final answer, the model first generates a Chain of Thought (CoT) to enhance the accuracy of its responses. Our API provides users with access to the CoT content generated by <code>deepseek-reasoner</code>, enabling them to view, display, and distill it.\n\nYou can use the <code>DeepSeekAssistantMessage</code> to get the CoT content generated by <code>deepseek-reasoner</code>.\n\npublic void deepSeekReasonerExample() {\n    DeepSeekChatOptions promptOptions = DeepSeekChatOptions.builder()\n            .model(DeepSeekApi.ChatModel.DEEPSEEK_REASONER.getValue())\n            .build();\n    Prompt prompt = new Prompt(\"9.11 and 9.8, which is greater?\", promptOptions);\n    ChatResponse response = chatModel.call(prompt);\n\n    // Get the CoT content generated by deepseek-reasoner, only available when using deepseek-reasoner model\n    DeepSeekAssistantMessage deepSeekAssistantMessage = (DeepSeekAssistantMessage) response.getResult().getOutput();\n    String reasoningContent = deepSeekAssistantMessage.getReasoningContent();\n    String text = deepSeekAssistantMessage.getText();\n}',0x00,'asciidoc::deepseek-chat.adoc::Reasoning Model (deepseek-reasoner)::0'),
('9d560abc-b97e-4621-b141-adc5e6fcf515','Legal Document Analysis\n\nAnalyze large legal contracts or compliance documents efficiently by caching document content across multiple questions:\n\n// Load a legal contract (PDF or text)\nString legalContract = loadDocument(\"merger-agreement.pdf\"); // ~3000 tokens\n\n// System prompt with legal expertise\nString legalSystemPrompt = \"You are an expert legal analyst specializing in corporate law. \" +\n    \"Analyze the following contract and provide precise answers about terms, obligations, and risks: \" +\n    legalContract;\n\n// First analysis - creates cache\nChatResponse riskAnalysis = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(legalSystemPrompt),\n            new UserMessage(\"What are the key termination clauses and associated penalties?\")\n        ),\n        BedrockChatOptions.builder()\n            .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(1000)\n            .build()\n    )\n);\n\n// Subsequent questions reuse cached document - 90% cost savings\nChatResponse obligationAnalysis = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(legalSystemPrompt), // Same content - cache hit\n            new UserMessage(\"List all financial obligations and payment schedules.\")\n        ),\n        BedrockChatOptions.builder()\n            .model(\"us.anthropic.claude-3-7-sonnet-20250219-v1:0\")\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(1000)\n            .build()\n    )\n);\n\nBatch Code Review\n\nProcess multiple code files with consistent review criteria while caching the review guidelines:',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Real-World Use Cases::0'),
('f870d47b-1383-4a7e-84bd-adda3bb6f7b2','Shows how to setup a project that uses SAP Hana Cloud as the vector DB and leverage OpenAI to implement RAG pattern\n\nCreate a table <code>CRICKET_WORLD_CUP</code> in SAP Hana DB:\n\n\nCREATE TABLE CRICKET_WORLD_CUP (\n    _ID VARCHAR2(255) PRIMARY KEY,\n    CONTENT CLOB,\n    EMBEDDING REAL_VECTOR(1536)\n)\n\nAdd the following dependencies in your <code>pom.xml</code>\n\n\nYou may set the property <code>spring-ai-version</code> as <code>&lt;spring-ai-version&gt;1.0.0-SNAPSHOT&lt;/spring-ai-version&gt;</code>:\n\n&lt;dependencyManagement&gt;\n    &lt;dependencies&gt;\n        &lt;dependency&gt;\n            &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n            &lt;artifactId&gt;spring-ai-bom&lt;/artifactId&gt;\n            &lt;version&gt;${spring-ai-version}&lt;/version&gt;\n            &lt;type&gt;pom&lt;/type&gt;\n            &lt;scope&gt;import&lt;/scope&gt;\n        &lt;/dependency&gt;\n    &lt;/dependencies&gt;\n&lt;/dependencyManagement&gt;\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-boot-starter-web&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-pdf-document-reader&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-hana&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.projectlombok&lt;/groupId&gt;\n    &lt;artifactId&gt;lombok&lt;/artifactId&gt;\n    &lt;version&gt;1.18.30&lt;/version&gt;\n    &lt;scope&gt;provided&lt;/scope&gt;\n&lt;/dependency&gt;\n\nAdd the following properties in <code>application.properties</code> file:\n\n\nspring.ai.openai.api-key=${OPENAI_API_KEY}\nspring.ai.openai.embedding.options.model=text-embedding-ada-002\n\nspring.datasource.driver-class-name=com.sap.db.jdbc.Driver\nspring.datasource.url=${HANA_DATASOURCE_URL}\nspring.datasource.username=${HANA_DATASOURCE_USERNAME}\nspring.datasource.password=${HANA_DATASOURCE_PASSWORD}\n\nspring.ai.vectorstore.hanadb.tableName=CRICKET_WORLD_CUP\nspring.ai.vectorstore.hanadb.topK=3',0x00,'asciidoc::hana.adoc::Build a Sample RAG application::0'),
('95dfbe97-e713-4de1-ae1c-aed4d0d620d3','Google&#8217;s Gemini AI models support this capability by comprehending and integrating text, code, audio, images, and video.\nFor more details, refer to the blog post <a href=\"https://blog.google/technology/ai/google-gemini-ai/#introducing-gemini\">Introducing Gemini</a>.\n\nSpring AI&#8217;s <code>Message</code> interface supports multimodal AI models by introducing the Media type.\nThis type contains data and information about media attachments in messages, using Spring&#8217;s <code>org.springframework.util.MimeType</code> and a <code>java.lang.Object</code> for the raw media data.\n\nBelow is a simple code example extracted from <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-vertex-ai-gemini/src/test/java/org/springframework/ai/vertexai/gemini/VertexAiGeminiChatModelIT.java\">VertexAiGeminiChatModelIT#multiModalityTest()</a>, demonstrating the combination of user text with an image.\n\nbyte[] data = new ClassPathResource(\"/vertex-test.png\").getContentAsByteArray();\n\nvar userMessage = new UserMessage(\"Explain what do you see on this picture?\",\n        List.of(new Media(MimeTypeUtils.IMAGE_PNG, this.data)));\n\nChatResponse response = chatModel.call(new Prompt(List.of(this.userMessage)));',0x00,'asciidoc::vertexai-gemini-chat.adoc::Multimodal::Image, Audio, Video::0'),
('67e59638-af0b-4eca-81ce-aed69e1c1de8','You can use the following properties in your Spring Boot configuration to customize the Azure vector store.',0x00,'asciidoc::azure.adoc::Configuration Properties::0'),
('646a1e82-5384-4808-9369-af5572b46e3e','/**\n * @author Christian Tzolov\n * @author Ilayaperumal Gopinathan\n */\npublic class SearchRequestTests {\n\n    @Test\n    public void createDefaults() {\n        var emptyRequest = SearchRequest.builder().build();\n        assertThat(emptyRequest.getQuery()).isEqualTo(\"\");\n        checkDefaults(emptyRequest);\n    }\n\n    @Test\n    public void createQuery() {\n        var emptyRequest = SearchRequest.builder().query(\"New Query\").build();\n        assertThat(emptyRequest.getQuery()).isEqualTo(\"New Query\");\n        checkDefaults(emptyRequest);\n    }\n\n    @Test\n    public void createFrom() {\n        var originalRequest = SearchRequest.builder().query(\"New Query\").topK(696).similarityThreshold(0.678).filterExpression(\"country == \'NL\'\").build();\n        var newRequest = SearchRequest.from(originalRequest).build();\n        assertThat(newRequest).isNotSameAs(originalRequest);\n        assertThat(newRequest.getQuery()).isEqualTo(originalRequest.getQuery());\n        assertThat(newRequest.getTopK()).isEqualTo(originalRequest.getTopK());\n        assertThat(newRequest.getFilterExpression()).isEqualTo(originalRequest.getFilterExpression());\n        assertThat(newRequest.getSimilarityThreshold()).isEqualTo(originalRequest.getSimilarityThreshold());\n    }\n\n    @Test\n    public void queryString() {\n        var emptyRequest = SearchRequest.builder().build();\n        assertThat(emptyRequest.getQuery()).isEqualTo(\"\");\n        var emptyRequest1 = SearchRequest.from(emptyRequest).query(\"New Query\").build();\n        assertThat(emptyRequest1.getQuery()).isEqualTo(\"New Query\");\n    }\n\n    @Test\n    public void similarityThreshold() {\n        var request = SearchRequest.builder().query(\"Test\").similarityThreshold(0.678).build();\n        assertThat(request.getSimilarityThreshold()).isEqualTo(0.678);\n        var request1 = SearchRequest.from(request).similarityThreshold(0.9).build();\n        assertThat(request1.getSimilarityThreshold()).isEqualTo(0.9);\n        assertThatThrownBy(() -> SearchRequest.from(request).similarityThreshold(-1)).isInstanceOf(IllegalArgumentException.class).hasMessageContaining(\"Similarity threshold must be in [0,1] range.\");\n        assertThatThrownBy(() -> SearchRequest.from(request).similarityThreshold(1.1)).isInstanceOf(IllegalArgumentException.class).hasMessageContaining(\"Similarity threshold must be in [0,1] range.\");\n    }\n\n    @Test\n    public void topK() {\n        var request = SearchRequest.builder().query(\"Test\").topK(66).build();\n        assertThat(request.getTopK()).isEqualTo(66);\n        var request1 = SearchRequest.from(request).topK(89).build();\n        assertThat(request1.getTopK()).isEqualTo(89);\n        assertThatThrownBy(() -> SearchRequest.from(request).topK(-1)).isInstanceOf(IllegalArgumentException.class).hasMessageContaining(\"TopK should be positive.\");\n    }\n\n    @Test\n    public void filterExpression() {\n        var request = SearchRequest.builder().query(\"Test\").filterExpression(\"country == \'BG\' && year >= 2022\").build();\n        assertThat(request.getFilterExpression()).isEqualTo(new Filter.Expression(Filter.ExpressionType.AND, new Filter.Expression(Filter.ExpressionType.EQ, new Filter.Key(\"country\"), new Filter.Value(\"BG\")), new Filter.Expression(Filter.ExpressionType.GTE, new Filter.Key(\"year\"), new Filter.Value(2022))));\n        assertThat(request.hasFilterExpression()).isTrue();\n        var request1 = SearchRequest.from(request).filterExpression(\"active == true\").build();\n        assertThat(request1.getFilterExpression()).isEqualTo(new Filter.Expression(Filter.ExpressionType.EQ, new Filter.Key(\"active\"), new Filter.Value(true)));\n        assertThat(request1.hasFilterExpression()).isTrue();\n        var request2 = SearchRequest.from(request).filterExpression(new FilterExpressionBuilder().eq(\"country\", \"NL\").build()).build();\n        assertThat(request2.getFilterExpression()).isEqualTo(new Filter.Expression(Filter.ExpressionType.EQ, new Filter.Key(\"country\"), new Filter.Value(\"NL\")));\n        assertThat(request2.hasFilterExpression()).isTrue();\n        var request3 = SearchRequest.from(request).filterExpression((String) null).build();\n        assertThat(request3.getFilterExpression()).isNull();\n        assertThat(request3.hasFilterExpression()).isFalse();\n        var request4 = SearchRequest.from(request).filterExpression((Filter.Expression) null).build();\n        assertThat(request4.getFilterExpression()).isNull();\n        assertThat(request4.hasFilterExpression()).isFalse();\n        assertThatThrownBy(() -> SearchRequest.from(request).filterExpression(\"FooBar\")).isInstanceOf(FilterExpressionParseException.class).hasMessageContaining(\"Error: no viable alternative at input \'FooBar\'\");\n    }\n\n    private void checkDefaults(SearchRequest request) {\n        assertThat(request.getFilterExpression()).isNull();\n        assertThat(request.getSimilarityThreshold()).isEqualTo(SearchRequest.SIMILARITY_THRESHOLD_ACCEPT_ALL);\n        assertThat(request.getTopK()).isEqualTo(SearchRequest.DEFAULT_TOP_K);\n    }\n}',0x01,'cu::SearchRequestTests.java'),
('41530f5c-9519-40a6-93fb-af6f3164a447','Spring AI provides out-of-the-box support for common RAG flows using the <code>Advisor</code> API.\n\nTo use the <code>QuestionAnswerAdvisor</code> or <code>VectorStoreChatMemoryAdvisor</code>, you need to add the <code>spring-ai-advisors-vector-store</code> dependency to your project:\n\n&lt;dependency&gt;\n   &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n   &lt;artifactId&gt;spring-ai-advisors-vector-store&lt;/artifactId&gt;\n&lt;/dependency&gt;',0x00,'asciidoc::retrieval-augmented-generation.adoc::Advisors::0'),
('24e369f2-b648-4a65-9dd0-af88a9c881c0','By default, Spring Boot auto-configuration will create an API key bean using the <code>spring.ai.openai.api-key</code> property:\n\nspring.ai.openai.api-key=your-api-key-here',0x00,'asciidoc::openai-chat.adoc::API Key Management::Default Configuration::0'),
('3ea7d7db-c5fa-470c-9742-afd6e9eb407a','The <code>VectorStoreRetriever</code> interface provides a read-only view of a vector store, exposing only the similarity search functionality. This follows the principle of least privilege and is particularly useful in RAG (Retrieval-Augmented Generation) applications where you only need to retrieve documents without modifying the underlying data.',0x00,'asciidoc::vectordbs.adoc::Retrieval Operations with VectorStoreRetriever::0'),
('04de4702-70f1-4fd7-a026-b0428a56a737','When running vLLM with a Llama model, you might want to use sampling parameters specific to vLLM:\n\nspring.ai.openai.base-url=http://localhost:8000/v1\nspring.ai.openai.chat.options.model=meta-llama/Llama-3-70B-Instruct\nspring.ai.openai.chat.options.extra-body.top_k=40\nspring.ai.openai.chat.options.extra-body.top_p=0.95\nspring.ai.openai.chat.options.extra-body.repetition_penalty=1.05\nspring.ai.openai.chat.options.extra-body.min_p=0.05\n\nRefer to the <a href=\"https://docs.vllm.ai/en/latest/\">vLLM documentation</a> for a complete list of supported sampling parameters.',0x00,'asciidoc::openai-chat.adoc::Using Extra Parameters with OpenAI-Compatible Servers::Example: vLLM Server::0'),
('c5c7ee92-3a65-407f-90cf-b0b2c7f7cc0c','From within the <code>src/test/resources/</code> folder run:\n\ndocker-compose up\n\nTo clean the environment:\n\ndocker-compose down; rm -Rf ./volumes\n\nThen connect to the vector store on <a href=\"http://localhost:19530\">http://localhost:19530</a> or for management <a href=\"http://localhost:9001\">http://localhost:9001</a> (user: <code>minioadmin</code>, pass: <code>minioadmin</code>)',0x00,'asciidoc::milvus.adoc::Starting Milvus Store::0'),
('fcd2b7a5-0460-4a19-aec3-b0cbb40dba6d','public static final class Builder {\n\n    private ChatClient.Builder chatClientBuilder;\n\n    @Nullable\n    private PromptTemplate promptTemplate;\n\n    @Nullable\n    private String targetSearchSystem;\n\n    private Builder() {\n    }\n\n    public Builder chatClientBuilder(ChatClient.Builder chatClientBuilder) {\n        this.chatClientBuilder = chatClientBuilder;\n        return this;\n    }\n\n    public Builder promptTemplate(PromptTemplate promptTemplate) {\n        this.promptTemplate = promptTemplate;\n        return this;\n    }\n\n    public Builder targetSearchSystem(String targetSearchSystem) {\n        this.targetSearchSystem = targetSearchSystem;\n        return this;\n    }\n\n    public RewriteQueryTransformer build() {\n        return new RewriteQueryTransformer(this.chatClientBuilder, this.promptTemplate, this.targetSearchSystem);\n    }\n}',0x01,'cu::RewriteQueryTransformer.java'),
('9f0cc746-d4cd-4cf6-9d82-b0d5322d38b9','Renamed POM artifact names:\n- spring-ai-qdrant &#8594; spring-ai-qdrant-store\n- spring-ai-cassandra &#8594; spring-ai-cassandra-store\n- spring-ai-pinecone &#8594; spring-ai-pinecone-store\n- spring-ai-redis &#8594; spring-ai-redis-store\n- spring-ai-qdrant &#8594; spring-ai-qdrant-store\n- spring-ai-gemfire &#8594; spring-ai-gemfire-store\n- spring-ai-azure-vector-store-spring-boot-starter &#8594; spring-ai-azure-store-spring-boot-starter\n- spring-ai-redis-spring-boot-starter &#8594; spring-ai-starter-vector-store-redis',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0.M1::Artifact name changes::0'),
('a9a578a3-1ae9-4eb4-9bd5-b0ead934897b','At the <code>ChatClient.Builder</code> level, you can specify the default prompt configuration.\n\n<code>defaultOptions(ChatOptions chatOptions)</code>: Pass in either portable options defined in the <code>ChatOptions</code> class or model-specific options such as those in <code>OpenAiChatOptions</code>.\nFor more information on model-specific <code>ChatOptions</code> implementations, refer to the JavaDocs.\n<code>defaultFunction(String name, String description, java.util.function.Function&lt;I, O&gt; function)</code>: The <code>name</code> is used to refer to the function in user text.\nThe <code>description</code> explains the function&#8217;s purpose and helps the AI model choose the correct function for an accurate response.\nThe <code>function</code> argument is a Java function instance that the model will execute when necessary.\n<code>defaultFunctions(String&#8230;&#8203; functionNames)</code>: The bean names of `java.util.Function`s defined in the application context.\n<code>defaultUser(String text)</code>, <code>defaultUser(Resource text)</code>, <code>defaultUser(Consumer&lt;UserSpec&gt; userSpecConsumer)</code>: These methods let you define the user text.\nThe <code>Consumer&lt;UserSpec&gt;</code> allows you to use a lambda to specify the user text and any default parameters.\n<code>defaultAdvisors(Advisor&#8230;&#8203; advisor)</code>: Advisors allow modification of the data used to create the <code>Prompt</code>.\nThe <code>QuestionAnswerAdvisor</code> implementation enables the pattern of <code>Retrieval Augmented Generation</code> by appending the prompt with context information related to the user text.\n<code>defaultAdvisors(Consumer&lt;AdvisorSpec&gt; advisorSpecConsumer)</code>: This method allows you to define a <code>Consumer</code> to configure multiple advisors using the <code>AdvisorSpec</code>. Advisors can modify the data used to create the final <code>Prompt</code>.\nThe <code>Consumer&lt;AdvisorSpec&gt;</code> lets you specify a lambda to add advisors, such as <code>QuestionAnswerAdvisor</code>, which supports <code>Retrieval Augmented Generation</code> by appending the prompt with relevant context information based on the user text.\n\n\nYou can override these defaults at runtime using the corresponding methods without the <code>default</code> prefix.\n\n<code>options(ChatOptions chatOptions)</code>\n<code>function(String name, String description,\njava.util.function.Function&lt;I, O&gt; function)</code>\n<code>functions(String&#8230;&#8203; functionNames)</code>\n<code>user(String text)</code>, <code>user(Resource text)</code>, <code>user(Consumer&lt;UserSpec&gt; userSpecConsumer)</code>\n<code>advisors(Advisor&#8230;&#8203; advisor)</code>\n<code>advisors(Consumer&lt;AdvisorSpec&gt; advisorSpecConsumer)</code>',0x00,'asciidoc::chatclient.adoc::Using Defaults::Other defaults::0'),
('02f1021d-64e2-4d56-95e8-b0f07e58fa1b','<code>returnDirect</code>: Whether the tool result should be returned directly to the client or passed back to the model. See <a href=\"#_return_direct\">Return Direct</a> for more details.\n\n\nToolCallback toolCallback = FunctionToolCallback\n    .builder(\"currentWeather\", new WeatherService())\n    .description(\"Get the weather in location\")\n    .inputType(WeatherRequest.class)\n    .build();\n\nThe function inputs and outputs can be either <code>Void</code> or POJOs. The input and output POJOs must be serializable, as the result will be serialized and sent back to the model. The function as well as the input and output types must be public.\n\nSome types are not supported. See <a href=\"#_function_tool_limitations\">Function Tool Limitations</a> for more details.\n\nAdding Tools to <code>ChatClient</code>\n\nWhen using the programmatic specification approach, you can pass the <code>FunctionToolCallback</code> instance to the <code>toolCallbacks()</code> method of <code>ChatClient</code>. The tool will only be available for the specific chat request it&#8217;s added to.\n\nToolCallback toolCallback = ...\nChatClient.create(chatModel)\n    .prompt(\"What\'s the weather like in Copenhagen?\")\n    .toolCallbacks(toolCallback)\n    .call()\n    .content();\n\nAdding Default Tools to <code>ChatClient</code>\n\nWhen using the programmatic specification approach, you can add default tools to a <code>ChatClient.Builder</code> by passing the <code>FunctionToolCallback</code> instance to the <code>defaultToolCallbacks()</code> method.\nIf both default and runtime tools are provided, the runtime tools will completely override the default tools.\n\nDefault tools are shared across all the chat requests performed by all the <code>ChatClient</code> instances built from the same <code>ChatClient.Builder</code>. They are useful for tools that are commonly used across different chat requests, but they can also be dangerous if not used carefully, risking to make them available when they shouldn&#8217;t.\n\nChatModel chatModel = ...\nToolCallback toolCallback = ...\nChatClient chatClient = ChatClient.builder(chatModel)\n    .defaultToolCallbacks(toolCallback)\n    .build();\n\nAdding Tools to <code>ChatModel</code>\n\nWhen using the programmatic specification approach, you can pass the <code>FunctionToolCallback</code> instance to the <code>toolCallbacks()</code> method of <code>ToolCallingChatOptions</code>. The tool will only be available for the specific chat request it&#8217;s added to.\n\nChatModel chatModel = ...\nToolCallback toolCallback = ...\nChatOptions chatOptions = ToolCallingChatOptions.builder()\n    .toolCallbacks(toolCallback)\n    .build():\nPrompt prompt = new Prompt(\"What\'s the weather like in Copenhagen?\", chatOptions);\nchatModel.call(prompt);\n\nAdding Default Tools to <code>ChatModel</code>',0x00,'asciidoc::tools.adoc::Functions as Tools::Programmatic Specification: <code>FunctionToolCallback</code>::1'),
('22a3bdeb-7f21-43ab-8ba2-b1b1665d257c','docker run -it --rm --name postgres -p 5432:5432 -e POSTGRES_USER=postgres -e POSTGRES_PASSWORD=postgres pgvector/pgvector\n\nYou can connect to this server like this:\n\npsql -U postgres -h localhost -p 5432',0x00,'asciidoc::pgvector.adoc::Run Postgres &amp; PGVector DB locally::0'),
('cd6a8d3e-338f-4da5-8fb2-b1efca9d156a','Obtain your Azure OpenAI <code>endpoint</code> and <code>api-key</code> from the Azure OpenAI Service section on the <a href=\"https://portal.azure.com\">Azure Portal</a>.\n\nSpring AI defines two configuration properties:\n\n<code>spring.ai.azure.openai.api-key</code>: Set this to the value of the <code>API Key</code> obtained from Azure.\n<code>spring.ai.azure.openai.endpoint</code>: Set this to the endpoint URL obtained when provisioning your model in Azure.\n\n\nYou can set these configuration properties in your <code>application.properties</code> or <code>application.yml</code> file:\n\nspring.ai.azure.openai.api-key=&lt;your-azure-api-key&gt;\nspring.ai.azure.openai.endpoint=&lt;your-azure-endpoint-url&gt;\n\nIf you prefer to use environment variables for sensitive information like API keys, you can use Spring Expression Language (SpEL) in your configuration:\n\n# In application.yml\nspring:\n  ai:\n    azure:\n      openai:\n        api-key: ${AZURE_OPENAI_API_KEY}\n        endpoint: ${AZURE_OPENAI_ENDPOINT}\n\n# In your environment or .env file\nexport AZURE_OPENAI_API_KEY=&lt;your-azure-openai-api-key&gt;\nexport AZURE_OPENAI_ENDPOINT=&lt;your-azure-endpoint-url&gt;',0x00,'asciidoc::azure-openai-embeddings.adoc::Prerequisites::Azure API Key &amp; Endpoint::0'),
('6beec86b-3ad6-472d-9175-b1ffad9bfdb2','Groq API endpoints support <a href=\"https://console.groq.com/docs/tool-use\">tool/function calling</a> when selecting one of the Tool/Function supporting models.\n\nCheck the Tool <a href=\"https://console.groq.com/docs/tool-use\">Supported Models</a>.\n\nYou can register custom Java functions with your ChatModel and have the provided Groq model intelligently choose to output a JSON object containing arguments to call one or many of the registered functions.\nThis is a powerful technique to connect the LLM capabilities with external tools and APIs.',0x00,'asciidoc::groq-chat.adoc::Function Calling::0'),
('7a52502c-d408-46e7-9b43-b2074bd6272b','The MariaDB Vector Store implementation provides access to the underlying native JDBC client (<code>JdbcTemplate</code>) through the <code>getNativeClient()</code> method:\n\nMariaDBVectorStore vectorStore = context.getBean(MariaDBVectorStore.class);\nOptional&lt;JdbcTemplate&gt; nativeClient = vectorStore.getNativeClient();\n\nif (nativeClient.isPresent()) {\n    JdbcTemplate jdbc = nativeClient.get();\n    // Use the native client for MariaDB-specific operations\n}\n\nThe native client gives you access to MariaDB-specific features and operations that might not be exposed through the <code>VectorStore</code> interface.',0x00,'asciidoc::mariadb.adoc::Accessing the Native Client::0'),
('528dcef7-857c-4fdb-828c-b20db9f88d84','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Azure PostgresML Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-postgresml-embedding&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-postgresml-embedding\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nUse the <code>spring.ai.postgresml.embedding.options.*</code> properties to configure your <code>PostgresMlEmbeddingModel</code>. links',0x00,'asciidoc::postgresml-embeddings.adoc::Auto-configuration::0'),
('a02cc721-dfe7-4c52-a0a4-b20dec8cdb8a','The <code>PromptTemplate</code> provided here customizes how the advisor merges retrieved context with the user query. This is distinct from configuring a <code>TemplateRenderer</code> on the <code>ChatClient</code> itself (using <code>.templateRenderer()</code>), which affects the rendering of the initial user/system prompt content <strong>before</strong> the advisor runs. See <a href=\"api/chatclient.html#_prompt_templates\">ChatClient Prompt Templates</a> for more details on client-level template rendering.\n\nThe custom <code>PromptTemplate</code> can use any <code>TemplateRenderer</code> implementation (by default, it uses <code>StPromptTemplate</code> based on the <a href=\"https://www.stringtemplate.org/\">StringTemplate</a> engine). The important requirement is that the template must contain the following two placeholders:\n\na <code>query</code> placeholder to receive the user question.\na <code>question_answer_context</code> placeholder to receive the retrieved context.\n\n\nPromptTemplate customPromptTemplate = PromptTemplate.builder()\n    .renderer(StTemplateRenderer.builder().startDelimiterToken(\'&lt;\').endDelimiterToken(\'&gt;\').build())\n    .template(\"\"\"\n            &lt;query&gt;\n\n            Context information is below.\n\n			---------------------\n			&lt;question_answer_context&gt;\n			---------------------\n\n			Given the context information and no prior knowledge, answer the query.\n\n			Follow these rules:\n\n			1. If the answer is not in the context, just say that you don\'t know.\n			2. Avoid statements like \"Based on the context...\" or \"The provided information...\".\n            \"\"\")\n    .build();\n\n    String question = \"Where does the adventure of Anacletus and Birba take place?\";\n\n    QuestionAnswerAdvisor qaAdvisor = QuestionAnswerAdvisor.builder(vectorStore)\n        .promptTemplate(customPromptTemplate)\n        .build();\n\n    String response = ChatClient.builder(chatModel).build()\n        .prompt(question)\n        .advisors(qaAdvisor)\n        .call()\n        .content();\n\nThe <code>QuestionAnswerAdvisor.Builder.userTextAdvise()</code> method is deprecated in favor of using <code>.promptTemplate()</code> for more flexible customization.',0x00,'asciidoc::retrieval-augmented-generation.adoc::Advisors::QuestionAnswerAdvisor::1'),
('d6918ddd-beb4-4be3-a4d2-b2ce06aefaae','<code>JdbcChatMemoryRepository</code> is a built-in implementation that uses JDBC to store messages in a relational database. It supports multiple databases out-of-the-box and is suitable for applications that require persistent storage of chat memory.\n\nFirst, add the following dependency to your project:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-chat-memory-repository-jdbc&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-chat-memory-repository-jdbc\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nSpring AI provides auto-configuration for the <code>JdbcChatMemoryRepository</code>, that you can use directly in your application.\n\n@Autowired\nJdbcChatMemoryRepository chatMemoryRepository;\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nIf you&#8217;d rather create the <code>JdbcChatMemoryRepository</code> manually, you can do so by providing a <code>JdbcTemplate</code> instance and a <code>JdbcChatMemoryRepositoryDialect</code>:\n\nChatMemoryRepository chatMemoryRepository = JdbcChatMemoryRepository.builder()\n    .jdbcTemplate(jdbcTemplate)\n    .dialect(new PostgresChatMemoryRepositoryDialect())\n    .build();\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nSupported Databases and Dialect Abstraction\n\nSpring AI supports multiple relational databases via a dialect abstraction. The following databases are supported out-of-the-box:\n\nPostgreSQL\nMySQL / MariaDB\nSQL Server\nHSQLDB\nOracle Database\n\n\nThe correct dialect can be auto-detected from the JDBC URL when using <code>JdbcChatMemoryRepositoryDialect.from(DataSource)</code>. You can extend support for other databases by implementing the <code>JdbcChatMemoryRepositoryDialect</code> interface.\n\nConfiguration Properties\n\n\n\nSchema Initialization\n\nThe auto-configuration will automatically create the <code>SPRING_AI_CHAT_MEMORY</code> table on startup, using a vendor-specific SQL script for your database. By default, schema initialization runs only for embedded databases (H2, HSQL, Derby, etc.).\n\nYou can control schema initialization using the <code>spring.ai.chat.memory.repository.jdbc.initialize-schema</code> property:',0x00,'asciidoc::chat-memory.adoc::Memory Storage::JdbcChatMemoryRepository::0'),
('bb99a602-bcdc-4bcd-95d1-b307f765d085','package com.interviewpedia.spring.ai.hana;\n\nimport lombok.extern.slf4j.Slf4j;\nimport org.springframework.ai.chat.model.ChatModel;\nimport org.springframework.ai.chat.messages.UserMessage;\nimport org.springframework.ai.chat.prompt.Prompt;\nimport org.springframework.ai.chat.prompt.SystemPromptTemplate;\nimport org.springframework.ai.document.Document;\nimport org.springframework.ai.reader.pdf.PagePdfDocumentReader;\nimport org.springframework.ai.transformer.splitter.TokenTextSplitter;\nimport org.springframework.ai.vectorstore.hanadb.HanaCloudVectorStore;\nimport org.springframework.ai.vectorstore.VectorStore;\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.core.io.Resource;\nimport org.springframework.http.ResponseEntity;\nimport org.springframework.web.bind.annotation.GetMapping;\nimport org.springframework.web.bind.annotation.PostMapping;\nimport org.springframework.web.bind.annotation.RequestParam;\nimport org.springframework.web.bind.annotation.RestController;\nimport org.springframework.web.multipart.MultipartFile;\n\nimport java.io.IOException;\nimport java.util.List;\nimport java.util.Map;\nimport java.util.function.Function;\nimport java.util.function.Supplier;\nimport java.util.stream.Collectors;\n\n@RestController\n@Slf4j\npublic class CricketWorldCupHanaController {\n    private final VectorStore hanaCloudVectorStore;\n    private final ChatModel chatModel;\n\n    @Autowired\n    public CricketWorldCupHanaController(ChatModel chatModel, VectorStore hanaCloudVectorStore) {\n        this.chatModel = chatModel;\n        this.hanaCloudVectorStore = hanaCloudVectorStore;\n    }\n\n    @PostMapping(\"/ai/hana-vector-store/cricket-world-cup/purge-embeddings\")\n    public ResponseEntity&lt;String&gt; purgeEmbeddings() {\n        int deleteCount = ((HanaCloudVectorStore) this.hanaCloudVectorStore).purgeEmbeddings();\n        log.info(\"{} embeddings purged from CRICKET_WORLD_CUP table in Hana DB\", deleteCount);\n        return ResponseEntity.ok().body(String.format(\"%d embeddings purged from CRICKET_WORLD_CUP table in Hana DB\", deleteCount));\n    }\n\n    @PostMapping(\"/ai/hana-vector-store/cricket-world-cup/upload\")\n    public ResponseEntity&lt;String&gt; handleFileUpload(@RequestParam(\"pdf\") MultipartFile file) throws IOException {\n        Resource pdf = file.getResource();\n        Supplier&lt;List&lt;Document&gt;&gt; reader = new PagePdfDocumentReader(pdf);\n        Function&lt;List&lt;Document&gt;, List&lt;Document&gt;&gt; splitter = new TokenTextSplitter();\n        List&lt;Document&gt; documents = splitter.apply(reader.get());\n        log.info(\"{} documents created from pdf file: {}\", documents.size(), pdf.getFilename());\n		this.hanaCloudVectorStore.accept(documents);\n        return ResponseEntity.ok().body(String.format(\"%d documents created from pdf file: %s\",\n                documents.size(), pdf.getFilename()));\n    }\n\n    @GetMapping(\"/ai/hana-vector-store/cricket-world-cup\")\n    public Map&lt;String, String&gt; hanaVectorStoreSearch(@RequestParam(value = \"message\") String message) {\n        var documents = this.hanaCloudVectorStore.similaritySearch(message);\n        var inlined = documents.stream().map(Document::getText).collect(Collectors.joining(System.lineSeparator()));\n        var similarDocsMessage = new SystemPromptTemplate(\"Based on the following: {documents}\")\n                .createMessage(Map.of(\"documents\", inlined));\n\n        var userMessage = new UserMessage(message);\n        Prompt prompt = new Prompt(List.of(similarDocsMessage, userMessage));\n        String generation = this.chatModel.call(prompt).getResult().getOutput().getContent();\n        log.info(\"Generation: {}\", generation);\n        return Map.of(\"generation\", generation);\n    }\n}',0x00,'asciidoc::hana.adoc::Build a Sample RAG application::Create an <code>Entity</code> class named <code>CricketWorldCup</code> that extends from <code>HanaVectorEntity</code>:::2'),
('98d20d89-cd9c-4dd3-affc-b39cadad3e1c','The MariaDB Vector Store automatically calculates similarity scores for documents returned from similarity searches.\nThese scores provide a normalized measure of how closely each document matches your search query.',0x00,'asciidoc::mariadb.adoc::Similarity Scores::0'),
('a83fc01b-d7d6-4e2c-95ab-b3b0e0e5872a','Multimodality refers to a model&#8217;s ability to simultaneously understand and process information from various (input) sources, including <code>text</code>, <code>pdf</code>, <code>images</code>, <code>audio</code>, and other data formats.',0x00,'asciidoc::google-genai-chat.adoc::Multimodal::0'),
('9233c042-8ad5-4966-ac0d-b3ffa13eeb93','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Azure ZhiPuAI Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-zhipuai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-zhipuai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::zhipuai-embeddings.adoc::Auto-configuration::0'),
('8eb5644d-510b-4851-9c76-b408fdb90018','<a href=\"https://github.com/openai/openai-java\">Official OpenAI Java SDK</a>\n<a href=\"https://platform.openai.com/docs/api-reference/chat\">OpenAI Chat API Documentation</a>\n<a href=\"https://platform.openai.com/docs/models\">OpenAI Models</a>\n<a href=\"https://learn.microsoft.com/en-us/azure/ai-foundry/\">Microsoft Foundry Documentation</a>\n<a href=\"https://github.com/marketplace/models\">GitHub Models</a>',0x00,'asciidoc::openai-sdk-chat.adoc::Additional Resources::0'),
('ea23223d-535a-4ae9-b9df-b42f34c9333b','Tool calling includes observability support with spring.ai.tool observations that measure completion time and propagate tracing information. See <a href=\"observability/index.html#_tool_calling\">Tool Calling Observability</a>.\n\nOptionally, Spring AI can export tool call arguments and results as span attributes, disabled by default for sensitivity reasons. Details: <a href=\"observability/index.html#_tool_call_arguments_and_result_data\">Tool Call Arguments and Result Data</a>.',0x00,'asciidoc::tools.adoc::Observability::0'),
('929d0b1e-77d0-4d91-87d0-b45c5b90b8a0','Spring AI makes it easy to have the AI model invoke your services as <code>@Tool</code>-annotated methods or POJO <code>java.util.Function</code> objects.\n\nCheck the Spring AI <a href=\":api/tools.html\">Tool Calling</a> documentation.',0x00,'asciidoc::index.adoc::Introduction::Tool Calling API::0'),
('3fa72e09-8c8b-4c4f-81c8-b51a1ad8ccdb','OpenAI provides custom <a href=\"https://platform.openai.com/docs/guides/structured-outputs\">Structured Outputs</a> APIs that ensure your model generates responses conforming strictly to your provided <code>JSON Schema</code>.\nIn addition to the existing Spring AI model-agnostic <a href=\":api/structured-output-converter.html\">Structured Output Converter</a>, these APIs offer enhanced control and precision.\n\nCurrently, OpenAI supports a <a href=\"https://platform.openai.com/docs/guides/structured-outputs/supported-schemas\">subset of the JSON Schema language</a> format.',0x00,'asciidoc::openai-chat.adoc::Structured Outputs::0'),
('d6ac520c-ca6d-4ad9-80ed-b51e8835d114','Legal Document Analysis\n\nAnalyze large legal contracts or compliance documents efficiently by caching document content across multiple questions:\n\n// Load a legal contract (PDF or text)\nString legalContract = loadDocument(\"merger-agreement.pdf\"); // ~3000 tokens\n\n// System prompt with legal expertise\nString legalSystemPrompt = \"You are an expert legal analyst specializing in corporate law. \" +\n    \"Analyze the following contract and provide precise answers about terms, obligations, and risks: \" +\n    legalContract;\n\n// First analysis - creates cache\nChatResponse riskAnalysis = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(legalSystemPrompt),\n            new UserMessage(\"What are the key termination clauses and associated penalties?\")\n        ),\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .cacheOptions(AnthropicCacheOptions.builder()\n                .strategy(AnthropicCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(1000)\n            .build()\n    )\n);\n\n// Subsequent questions reuse cached document - 90% cost savings\nChatResponse obligationAnalysis = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(legalSystemPrompt), // Same content - cache hit\n            new UserMessage(\"List all financial obligations and payment schedules.\")\n        ),\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .cacheOptions(AnthropicCacheOptions.builder()\n                .strategy(AnthropicCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(1000)\n            .build()\n    )\n);\n\nBatch Code Review\n\nProcess multiple code files with consistent review criteria while caching the review guidelines:',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Real-World Use Cases::0'),
('61cefe21-aa7f-4819-bd0a-b5267f9b6c43','<div class=\"paragraph\">\n<p>The Chat Model API offers developers the ability to integrate AI-powered chat completion capabilities into their applications. It leverages pre-trained language models, such as GPT (Generative Pre-trained Transformer), to generate human-like responses to user inputs in natural language.</p>\n</div>\n<div class=\"paragraph\">\n<p>The API typically works by sending a prompt or partial conversation to the AI model, which then generates a completion or continuation of the conversation based on its training data and understanding of natural language patterns. The completed response is then returned to the application, which can present it to the user or use it for further processing.</p>\n</div>\n<div class=\"paragraph\">\n<p>The <code>Spring AI Chat Model API</code> is designed to be a simple and portable interface for interacting with various <a href=\"concepts.html#_models\">AI Models</a>, allowing developers to switch between different models with minimal code changes.\nThis design aligns with Spring&#8217;s philosophy of modularity and interchangeability.</p>\n</div>\n<div class=\"paragraph\">\n<p>Also with the help of companion classes like <code>Prompt</code> for input encapsulation and <code>ChatResponse</code> for output handling, the Chat Model API unifies the communication with AI Models.\nIt manages the complexity of request preparation and response parsing, offering a direct and simplified API interaction.</p>\n</div>\n<div class=\"paragraph\">\n<p>You can find more about available implementations in the <a href=\"api/chatmodel.html#_available_implementations\">Available Implementations</a> section as well as detailed comparison in the <a href=\"api/chat/comparison.html\">Chat Models Comparison</a> section.</p>\n</div>',0x00,'asciidoc::chatmodel.adoc::0'),
('f997a6d7-1978-454b-8d12-b5510eec4f37','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the Chroma Vector Store.\nTo enable it, add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-vector-store-chroma&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-chroma\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nThe vector store implementation can initialize the requisite schema for you, but you must opt-in by specifying the <code>initializeSchema</code> boolean in the appropriate constructor or by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nAdditionally, you will need a configured <code>EmbeddingModel</code> bean. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\n\nHere is an example of the needed bean:\n\n@Bean\npublic EmbeddingModel embeddingModel() {\n    // Can be any other EmbeddingModel implementation.\n    return new OpenAiEmbeddingModel(OpenAiApi.builder().apiKey(System.getenv(\"OPENAI_API_KEY\")).build());\n}\n\nTo connect to Chroma you need to provide access details for your instance.\nA simple configuration can either be provided via Spring Boot&#8217;s <em>application.properties</em>,',0x00,'asciidoc::chroma.adoc::Auto-configuration::0'),
('40ed4929-5e70-4b2a-addf-b5e228dc3373','The 1.0.0-M7 includes the same structural changes as 1.0.0-SNAPSHOT.\n\nFor details, refer to:\n- <a href=\"upgrade-notes.html#common-artifact-id-changes\">Common Artifact ID Changes</a>\n- <a href=\"upgrade-notes.html#common-package-changes\">Common Package Changes</a>\n- <a href=\"upgrade-notes.html#common-module-structure\">Common Module Structure</a>',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M7::Artifact ID, Package, and Module Changes::0'),
('029fbf35-2667-4df4-ba30-b5e823b3c1fb','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-openai</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the OpenAi chat model:\n\nspring.ai.openai.api-key=&lt;GROQ_API_KEY&gt;\nspring.ai.openai.base-url=https://api.groq.com/openai\nspring.ai.openai.chat.options.model=llama3-70b-8192\nspring.ai.openai.chat.options.temperature=0.7\n\nreplace the <code>api-key</code> with your OpenAI credentials.\n\nThis will create a <code>OpenAiChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final OpenAiChatModel chatModel;\n\n    @Autowired\n    public ChatController(OpenAiChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", this.chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        Prompt prompt = new Prompt(new UserMessage(message));\n        return this.chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::groq-chat.adoc::Sample Controller::0'),
('ea35a447-11fc-4483-a82e-b5fc876dfdb7','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions.java</a> provides model configurations, such as the model to use, the temperature, the frequency penalty, etc.\n\nOn start-up, the default options can be configured with the <code>OpenAiChatModel(api, options)</code> constructor or the <code>spring.ai.openai.chat.options.*</code> properties.\n\nAt run-time you can override the default options by adding new, request specific, options to the <code>Prompt</code> call.\nFor example to override the default model and temperature for a specific request:\n\nChatResponse response = chatModel.call(\n    new Prompt(\n        \"Generate the names of 5 famous pirates.\",\n        OpenAiChatOptions.builder()\n            .model(\"mixtral-8x7b-32768\")\n            .temperature(0.4)\n        .build()\n    ));\n\nIn addition to the model specific <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-openai/src/main/java/org/springframework/ai/openai/OpenAiChatOptions.java\">OpenAiChatOptions</a> you can use a portable <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/ChatOptions.java\">ChatOptions</a> instance, created with the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/prompt/DefaultChatOptionsBuilder.java\">ChatOptions#builder()</a>.',0x00,'asciidoc::nvidia-chat.adoc::Runtime Options::0'),
('3b089866-fcd6-4a1b-bfb2-b6075e0cf11e','A running Elasticsearch instance. The following options are available:\n\n<a href=\"https://hub.docker.com/_/elasticsearch/\">Docker</a>\n<a href=\"https://www.elastic.co/guide/en/elasticsearch/reference/current/install-elasticsearch.html#elasticsearch-install-packages\">Self-Managed Elasticsearch</a>\n<a href=\"https://www.elastic.co/cloud/elasticsearch-service/signup?page=docs&amp;placement=docs-body\">Elastic Cloud</a>',0x00,'asciidoc::elasticsearch.adoc::Prerequisites::0'),
('b61739be-2313-4843-b123-b6466d959df9','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with OpenSearch as well.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; \'article_type\' == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"author\", \"john\", \"jill\"),\n        b.eq(\"article_type\", \"blog\")).build()).build());\n\nThose (portable) filter expressions get automatically converted into the proprietary OpenSearch <a href=\"https://opensearch.org/docs/latest/query-dsl/full-text/query-string/\">Query string query</a>.\n\nFor example, this portable filter expression:\n\nauthor in [\'john\', \'jill\'] &amp;&amp; \'article_type\' == \'blog\'\n\nis converted into the proprietary OpenSearch filter format:\n\n(metadata.author:john OR jill) AND metadata.article_type:blog',0x00,'asciidoc::opensearch.adoc::Metadata Filtering::0'),
('e00e1e00-13b2-4a80-a88b-b6492db4c578','/**\n * Represents expression grouping (e.g. (...) ) that indicates that the group needs to\n * be evaluated with a precedence.\n *\n * @param content Inner expression to be evaluated as a part of the group.\n */\npublic record Group(Expression content) implements Operand {\n}',0x01,'cu::Filter.java'),
('148e52b6-e572-4f35-aa14-b64a943fe149','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nThen add the Milvus VectorStore boot starter dependency to your project:\n\n&lt;dependency&gt;\n	&lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n	&lt;artifactId&gt;spring-ai-starter-vector-store-milvus&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-vector-store-milvus\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add Maven Central and/or Snapshot Repositories to your build file.\n\nThe vector store implementation can initialize the requisite schema for you, but you must opt-in by specifying the <code>initializeSchema</code> boolean in the appropriate constructor or by setting <code>&#8230;&#8203;initialize-schema=true</code> in the <code>application.properties</code> file.\n\nthis is a breaking change! In earlier versions of Spring AI, this schema initialization happened by default.\n\nThe Vector Store, also requires an <code>EmbeddingModel</code> instance to calculate embeddings for the documents.\nYou can pick one of the available <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel Implementations</a>.\n\nTo connect to and configure the <code>MilvusVectorStore</code>, you need to provide access details for your instance.\nA simple configuration can either be provided via Spring Boot&#8217;s <code>application.yml</code>\n\nspring:\n	ai:\n		vectorstore:\n			milvus:\n				client:\n					host: \"localhost\"\n					port: 19530\n					username: \"root\"\n					password: \"milvus\"\n				databaseName: \"default\"\n				collectionName: \"vector_store\"\n				embeddingDimension: 1536\n				indexType: IVF_FLAT\n				metricType: COSINE\n\nCheck the list of <a href=\"#milvus-properties\">configuration parameters</a> to learn about the default values and configuration options.\n\nNow you can Auto-wire the Milvus Vector Store in your application and use it',0x00,'asciidoc::milvus.adoc::Dependencies::0'),
('f59ed104-2fec-4650-a60d-b6ef51ad47df','An Atlas cluster running MongoDB version 6.0.11, 7.0.2, or later. To get started with MongoDB Atlas, you can follow the instructions <a href=\"https://www.mongodb.com/docs/atlas/getting-started/\">here</a>. Ensure that your IP address is included in your Atlas project&#8217;s <a href=\"https://www.mongodb.com/docs/atlas/security/ip-access-list/#std-label-access-list\">access list</a>.\nA running MongoDB Atlas instance with Vector Search enabled\nCollection with vector search index configured\nCollection schema with id (string), content (string), metadata (document), and embedding (vector) fields\nProper access permissions for index and collection operations',0x00,'asciidoc::mongodb.adoc::Prerequisites::0'),
('71eea02b-6b1b-4ca3-a5b4-b7a252186103','Enable prompt caching by setting <code>cacheOptions</code> on <code>AnthropicChatOptions</code> and choosing a <code>strategy</code>.\n\nSystem-Only Caching\n\nBest for: Stable system prompts with &lt;20 tools (tools cached implicitly via automatic lookback).\n\n// Cache system message content (tools cached implicitly)\nChatResponse response = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(\"You are a helpful AI assistant with extensive knowledge...\"),\n            new UserMessage(\"What is machine learning?\")\n        ),\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .cacheOptions(AnthropicCacheOptions.builder()\n                .strategy(AnthropicCacheStrategy.SYSTEM_ONLY)\n                .build())\n            .maxTokens(500)\n            .build()\n    )\n);\n\nTools-Only Caching\n\nBest for: Large stable tool sets with dynamic system prompts (multi-tenant apps, A/B testing).\n\n// Cache tool definitions, system prompt processed fresh each time\nChatResponse response = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(\"You are a \" + persona + \" assistant...\"), // Dynamic per-tenant\n            new UserMessage(\"What\'s the weather like in San Francisco?\")\n        ),\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .cacheOptions(AnthropicCacheOptions.builder()\n                .strategy(AnthropicCacheStrategy.TOOLS_ONLY)\n                .build())\n            .toolCallbacks(weatherToolCallback) // Large tool set cached\n            .maxTokens(500)\n            .build()\n    )\n);\n\nSystem and Tools Caching\n\nBest for: 20+ tools (beyond automatic lookback) or when both components should be cached independently.\n\n// Cache both tool definitions and system message with independent breakpoints\n// Changing system won\'t invalidate tool cache (but changing tools invalidates both)\nChatResponse response = chatModel.call(\n    new Prompt(\n        List.of(\n            new SystemMessage(\"You are a weather analysis assistant...\"),\n            new UserMessage(\"What\'s the weather like in San Francisco?\")\n        ),\n        AnthropicChatOptions.builder()\n            .model(\"claude-sonnet-4\")\n            .cacheOptions(AnthropicCacheOptions.builder()\n                .strategy(AnthropicCacheStrategy.SYSTEM_AND_TOOLS)\n                .build())\n            .toolCallbacks(weatherToolCallback) // 20+ tools\n            .maxTokens(500)\n            .build()\n    )\n);\n\nConversation History Caching',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Enabling Prompt Caching::0'),
('0e2fcbd5-71a3-4b19-8014-b7acf56785b1','A running Typesense instance. The following options are available:\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>TypesenseVectorStore</code>.',0x00,'asciidoc::typesense.adoc::Prerequisites::0'),
('896e0e66-57da-4442-8d62-b7b0013c1259','Renaming of AiClient and related classes and package names\n\nRename AiClient to ChatClient\nRename AiResponse to ChatResponse\nRename AiStreamClient to StreamingChatClient\nRename package org.sf.ai.client to org.sf.ai.chat\n\n\nRename artifact ID of\n\n<code>transformers-embedding</code> to <code>spring-ai-transformers</code>\n\n\nMoved Maven modules from top-level directory and <code>embedding-clients</code> subdirectory to all be under a single <code>models</code> directory.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 0.8.0::December 19, 2023 Update::0'),
('f3b46013-a28a-48ec-a00e-b803b66eed49','A GemFire cluster with the GemFire VectorDB extension enabled\nAn <code>EmbeddingModel</code> bean to compute the document embeddings. Refer to the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> section for more information.\nAn option that runs locally on your machine is <a href=\"api/embeddings/onnx.html\">ONNX</a> and the all-MiniLM-L6-v2 Sentence Transformers.',0x00,'asciidoc::gemfire.adoc::Prerequisites::0'),
('97b10742-17b4-484e-a8d5-b83bb643676a','Qdrant Instance: Set up a Qdrant instance by following the <a href=\"https://qdrant.tech/documentation/guides/installation/\">installation instructions</a> in the Qdrant documentation.\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>QdrantVectorStore</code>.\n\n\nIt is recommended that the Qdrant collection is <a href=\"https://qdrant.tech/documentation/concepts/collections/#create-a-collection\">created</a> in advance with the appropriate dimensions and configurations.\nIf the collection is not created, the <code>QdrantVectorStore</code> will attempt to create one using the <code>Cosine</code> similarity and the dimension of the configured <code>EmbeddingModel</code>.',0x00,'asciidoc::qdrant.adoc::Prerequisites::0'),
('a91fe9e9-dec8-47fd-9b46-b85d337bb3ca','Spring AI artifacts are published in Maven Central and Spring Snapshot repositories.\nRefer to the <a href=\"getting-started.html#artifact-repositories\">Artifact Repositories</a> section to add these repositories to your build system.\n\nTo help with dependency management, Spring AI provides a BOM (bill of materials) to ensure that a consistent version of Spring AI is used throughout the entire project. Refer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build system.',0x00,'asciidoc::openai-sdk-chat.adoc::Authentication::Add Repositories and BOM::0'),
('764ca213-62dd-4762-b7df-b8d2a9df527a','public static final class Builder {\n\n    private PromptTemplate promptTemplate;\n\n    private PromptTemplate emptyContextPromptTemplate;\n\n    private Boolean allowEmptyContext;\n\n    private Function<List<Document>, String> documentFormatter;\n\n    public Builder promptTemplate(PromptTemplate promptTemplate) {\n        this.promptTemplate = promptTemplate;\n        return this;\n    }\n\n    public Builder emptyContextPromptTemplate(PromptTemplate emptyContextPromptTemplate) {\n        this.emptyContextPromptTemplate = emptyContextPromptTemplate;\n        return this;\n    }\n\n    public Builder allowEmptyContext(Boolean allowEmptyContext) {\n        this.allowEmptyContext = allowEmptyContext;\n        return this;\n    }\n\n    public Builder documentFormatter(Function<List<Document>, String> documentFormatter) {\n        this.documentFormatter = documentFormatter;\n        return this;\n    }\n\n    public ContextualQueryAugmenter build() {\n        return new ContextualQueryAugmenter(this.promptTemplate, this.emptyContextPromptTemplate, this.allowEmptyContext, this.documentFormatter);\n    }\n}',0x01,'cu::ContextualQueryAugmenter.java'),
('ae70075d-cacb-453e-86b4-b8f9ae75fa56','<code>CassandraChatMemoryRepository</code> uses Apache Cassandra to store messages.  It is suitable for applications that require persistent storage of chat memory, especially for availability, durability, scale, and when taking advantage of time-to-live (TTL) feature.\n\n<code>CassandraChatMemoryRepository</code> has a time-series schema, keeping record of all past chat windows, valuable for governance and auditing.  Setting time-to-live to some value, for example three years, is recommended.\n\nTo use <code>CassandraChatMemoryRepository</code> first, add the dependency to your project:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-chat-memory-repository-cassandra&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-chat-memory-repository-cassandra\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nSpring AI provides auto-configuration for the <code>CassandraChatMemoryRepository</code> that you can use directly in your application.\n\n@Autowired\nCassandraChatMemoryRepository chatMemoryRepository;\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nIf you&#8217;d rather create the <code>CassandraChatMemoryRepository</code> manually, you can do so by providing a <code>CassandraChatMemoryRepositoryConfig</code> instance:\n\nChatMemoryRepository chatMemoryRepository = CassandraChatMemoryRepository\n    .create(CassandraChatMemoryRepositoryConfig.builder().withCqlSession(cqlSession));\n\nChatMemory chatMemory = MessageWindowChatMemory.builder()\n    .chatMemoryRepository(chatMemoryRepository)\n    .maxMessages(10)\n    .build();\n\nConfiguration Properties\n\n\n\nSchema Initialization\n\nThe auto-configuration will automatically create the <code>ai_chat_memory</code> table.\n\nYou can disable the schema initialization by setting the property <code>spring.ai.chat.memory.repository.cassandra.initialize-schema</code> to <code>false</code>.',0x00,'asciidoc::chat-memory.adoc::Memory Storage::CassandraChatMemoryRepository::0'),
('307cf854-492d-4294-a1f1-b9188a0f2919','Effectively evaluating the output of an AI system in response to user requests is very important to ensuring the accuracy and usefulness of the final application.\nSeveral emerging techniques enable the use of the pre-trained model itself for this purpose.\n\nThis evaluation process involves analyzing whether the generated response aligns with the user&#8217;s intent and the context of the query. Metrics such as relevance, coherence, and factual correctness are used to gauge the quality of the AI-generated response.\n\nOne approach involves presenting both the user&#8217;s request and the AI model&#8217;s response to the model, querying whether the response aligns with the provided data.\n\nFurthermore, leveraging the information stored in the vector database as supplementary data can enhance the evaluation process, aiding in the determination of response relevance.\n\nThe Spring AI project provides an <code>Evaluator</code> API which currently gives access to basic strategies to evaluate model responses.\nFollow the <a href=\":api/testing.html\">Evaluation Testing</a> documentation for further information.',0x00,'asciidoc::concepts.adoc::Evaluating AI responses::0'),
('e65e2dba-cea6-4f3d-9c0c-b92458f32f4e','/**\n * @author Jemin Huh\n */\npublic class SimpleVectorStoreFilterExpressionConverterTests {\n\n    final FilterExpressionConverter converter = new SimpleVectorStoreFilterExpressionConverter();\n\n    @Test\n    public void testDate() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(1704637752148L))));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'activationDate\'] == \'2024-01-07T14:29:12Z\'\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"activationDate\", \"2024-01-07T14:29:12Z\", \"year\", 2020, \"country\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n        vectorExpr = this.converter.convertExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(\"1970-01-01T00:00:02Z\")));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'activationDate\'] == \'1970-01-01T00:00:02Z\'\");\n        context.setVariable(\"metadata\", Map.of(\"activationDate\", \"1970-01-01T00:00:02Z\", \"year\", 2020, \"country\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void testDatesConcurrently() {\n        IntStream.range(0, 10).parallel().forEach(i -> {\n            String vectorExpr = this.converter.convertExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(1704637752148L))));\n            String vectorExpr2 = this.converter.convertExpression(new Filter.Expression(EQ, new Filter.Key(\"activationDate\"), new Filter.Value(new Date(1704637753150L))));\n            assertThat(vectorExpr).isEqualTo(\"#metadata[\'activationDate\'] == \'2024-01-07T14:29:12Z\'\");\n            assertThat(vectorExpr2).isEqualTo(\"#metadata[\'activationDate\'] == \'2024-01-07T14:29:13Z\'\");\n        });\n    }\n\n    @Test\n    public void testEQ() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(EQ, new Filter.Key(\"country\"), new Filter.Value(\"BG\")));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'country\'] == \'BG\'\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"city\", \"Seoul\", \"year\", 2020, \"country\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void tesEqAndGte() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(AND, new Filter.Expression(EQ, new Filter.Key(\"genre\"), new Filter.Value(\"drama\")), new Filter.Expression(GTE, new Filter.Key(\"year\"), new Filter.Value(2020))));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'genre\'] == \'drama\' and #metadata[\'year\'] >= 2020\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"genre\", \"drama\", \"year\", 2020, \"country\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void tesIn() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(IN, new Filter.Key(\"genre\"), new Filter.Value(List.of(\"comedy\", \"documentary\", \"drama\"))));\n        assertThat(vectorExpr).isEqualTo(\"{\'comedy\',\'documentary\',\'drama\'}.contains(#metadata[\'genre\'])\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"genre\", \"drama\", \"year\", 2020, \"country\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void testNe() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(OR, new Filter.Expression(GTE, new Filter.Key(\"year\"), new Filter.Value(2020)), new Filter.Expression(AND, new Filter.Expression(EQ, new Filter.Key(\"country\"), new Filter.Value(\"BG\")), new Filter.Expression(NE, new Filter.Key(\"city\"), new Filter.Value(\"Sofia\")))));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'year\'] >= 2020 or #metadata[\'country\'] == \'BG\' and #metadata[\'city\'] != \'Sofia\'\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"city\", \"Seoul\", \"year\", 2020, \"country\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void testGroup() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(AND, new Filter.Group(new Filter.Expression(OR, new Filter.Expression(GTE, new Filter.Key(\"year\"), new Filter.Value(2020)), new Filter.Expression(EQ, new Filter.Key(\"country\"), new Filter.Value(\"BG\")))), new Filter.Expression(NIN, new Filter.Key(\"city\"), new Filter.Value(List.of(\"Sofia\", \"Plovdiv\")))));\n        assertThat(vectorExpr).isEqualTo(\"(#metadata[\'year\'] >= 2020 or #metadata[\'country\'] == \'BG\') and not {\'Sofia\',\'Plovdiv\'}.contains(#metadata[\'city\'])\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"city\", \"Seoul\", \"year\", 2020, \"country\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void tesBoolean() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(AND, new Filter.Expression(AND, new Filter.Expression(EQ, new Filter.Key(\"isOpen\"), new Filter.Value(true)), new Filter.Expression(GTE, new Filter.Key(\"year\"), new Filter.Value(2020))), new Filter.Expression(IN, new Filter.Key(\"country\"), new Filter.Value(List.of(\"BG\", \"NL\", \"US\")))));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'isOpen\'] == true and #metadata[\'year\'] >= 2020 and {\'BG\',\'NL\',\'US\'}.contains(#metadata[\'country\'])\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"isOpen\", true, \"year\", 2020, \"country\", \"NL\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n        vectorExpr = this.converter.convertExpression(new Filter.Expression(AND, new Filter.Expression(AND, new Filter.Expression(EQ, new Filter.Key(\"isOpen\"), new Filter.Value(true)), new Filter.Expression(GTE, new Filter.Key(\"year\"), new Filter.Value(2020))), new Filter.Expression(NIN, new Filter.Key(\"country\"), new Filter.Value(List.of(\"BG\", \"NL\", \"US\")))));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'isOpen\'] == true and #metadata[\'year\'] >= 2020 and not {\'BG\',\'NL\',\'US\'}.contains(#metadata[\'country\'])\");\n        context.setVariable(\"metadata\", Map.of(\"isOpen\", true, \"year\", 2020, \"country\", \"KR\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void testDecimal() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(AND, new Filter.Expression(GTE, new Filter.Key(\"temperature\"), new Filter.Value(-15.6)), new Filter.Expression(LTE, new Filter.Key(\"temperature\"), new Filter.Value(20.13))));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'temperature\'] >= -15.6 and #metadata[\'temperature\'] <= 20.13\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"temperature\", -15.6));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n        context.setVariable(\"metadata\", Map.of(\"temperature\", 20.13));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n        context.setVariable(\"metadata\", Map.of(\"temperature\", -1.6));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n\n    @Test\n    public void testComplexIdentifiers() {\n        String vectorExpr = this.converter.convertExpression(new Filter.Expression(EQ, new Filter.Key(\"\\\"country 1 2 3\\\"\"), new Filter.Value(\"BG\")));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'country 1 2 3\'] == \'BG\'\");\n        vectorExpr = this.converter.convertExpression(new Filter.Expression(EQ, new Filter.Key(\"\'country 1 2 3\'\"), new Filter.Value(\"BG\")));\n        assertThat(vectorExpr).isEqualTo(\"#metadata[\'country 1 2 3\'] == \'BG\'\");\n        StandardEvaluationContext context = new StandardEvaluationContext();\n        ExpressionParser parser = new SpelExpressionParser();\n        context.setVariable(\"metadata\", Map.of(\"country 1 2 3\", \"BG\"));\n        Assertions.assertEquals(Boolean.TRUE, parser.parseExpression(vectorExpr).getValue(context, Boolean.class));\n    }\n}',0x01,'cu::SimpleVectorStoreFilterExpressionConverterTests.java'),
('3fd12878-4985-4649-b517-b926531f0377','You can add metadata to user messages using the <code>metadata()</code> methods:\n\n// Adding individual metadata key-value pairs\nString response = chatClient.prompt()\n    .user(u -&gt; u.text(\"What\'s the weather like?\")\n        .metadata(\"messageId\", \"msg-123\")\n        .metadata(\"userId\", \"user-456\")\n        .metadata(\"priority\", \"high\"))\n    .call()\n    .content();\n\n// Adding multiple metadata entries at once\nMap&lt;String, Object&gt; userMetadata = Map.of(\n    \"messageId\", \"msg-123\",\n    \"userId\", \"user-456\",\n    \"timestamp\", System.currentTimeMillis()\n);\n\nString response = chatClient.prompt()\n    .user(u -&gt; u.text(\"What\'s the weather like?\")\n        .metadata(userMetadata))\n    .call()\n    .content();',0x00,'asciidoc::chatclient.adoc::Message Metadata::Adding Metadata to User Messages::0'),
('0c4bbf4d-b798-4b9d-a029-b930eafe2c99','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-mistral-ai/src/main/java/org/springframework/ai/mistralai/MistralAiEmbeddingOptions.java\">MistralAiEmbeddingOptions.java</a> provides the MistralAI configurations, such as the model to use and etc.\n\nThe default options can be configured using the <code>spring.ai.mistralai.embedding.options</code> properties as well.\n\nAt start-time use the <code>MistralAiEmbeddingModel</code> constructor to set the  default options used for all embedding requests.\nAt run-time you can override the default options, using a <code>MistralAiEmbeddingOptions</code> instance as part of your <code>EmbeddingRequest</code>.\n\nFor example to override the default model name for a specific request:\n\n// Using mistral-embed for general text\nEmbeddingResponse textEmbeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"Hello World\", \"World is big and salvation is near\"),\n        MistralAiEmbeddingOptions.builder()\n            .withModel(\"mistral-embed\")\n        .build()));\n\n// Using codestral-embed for code\nEmbeddingResponse codeEmbeddingResponse = embeddingModel.call(\n    new EmbeddingRequest(List.of(\"public class HelloWorld {}\", \"def hello_world():\"),\n        MistralAiEmbeddingOptions.builder()\n            .withModel(\"codestral-embed\")\n        .build()));',0x00,'asciidoc::mistralai-embeddings.adoc::Runtime Options::0'),
('edd1a0d5-56a9-4d48-965c-b9948d24e38b','The <code>method()</code> configuration in function callbacks has been replaced with a more explicit method tool configuration using <code>ToolDefinition</code> and <code>MethodToolCallback</code>.\nWhen using method-based callbacks, you now need to explicitly find the method using <code>ReflectionUtils</code> and provide it to the builder. Alternatively, you can use the declarative approach with the <code>@Tool</code> annotation.\nFor non-static methods, you must now provide both the method and the target object:\n\n\nMethodToolCallback.builder()\n    .toolDefinition(ToolDefinition.builder(toolMethod)\n        .description(\"Description\")\n        .build())\n    .toolMethod(toolMethod)\n    .toolObject(targetObject)\n    .build()',0x00,'asciidoc::tools-migration.adoc::Breaking Changes::0'),
('1db1c0c1-7697-4100-8933-b9fc205ddc60','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the MiniMax Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-minimax&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-minimax\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::minimax-chat.adoc::Auto-configuration::0'),
('128df7c2-b98d-480d-8b0e-ba007a60fffc','<strong><a href=\"https://www.promptingguide.ai/techniques/zeroshot\">Zero-shot</a>, <a href=\"https://www.promptingguide.ai/techniques/fewshot\">Few-shot Learning</a></strong>:<br>\nEnables the model to make accurate predictions or responses with minimal to no prior examples of the specific problem type, understanding and acting on new tasks using learned generalizations.\n<strong><a href=\"https://www.promptingguide.ai/techniques/cot\">Chain-of-Thought</a></strong>:<br>\nLinks multiple AI responses to create a coherent and contextually aware conversation. It helps the AI maintain the thread of the discussion, ensuring relevance and continuity.\n<strong><a href=\"https://www.promptingguide.ai/techniques/react\">ReAct (Reason + Act)</a></strong>:<br>\nIn this method, the AI first analyzes (reasons about) the input, then determines the most appropriate course of action or response. It combines understanding with decision-making.\n\n\nMicrosoft Guidance\n\n<strong><a href=\"https://github.com/microsoft/guidance\">Framework for Prompt Creation and Optimization</a></strong>:<br>\nMicrosoft offers a structured approach to developing and refining prompts. This framework guides users in creating effective prompts that elicit the desired responses from AI models, optimizing the interaction for clarity and efficiency.',0x00,'asciidoc::prompt.adoc::Prompt Engineering::Creating effective prompts::1'),
('89f3e47d-bef5-4434-a4f8-ba2bad35811e','&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-azure-store&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::azure.adoc::Dependencies::2. Azure (AI Search) Vector Store::0'),
('ee8e7405-2e07-43e0-b62d-ba2d2590091b','Spring AI updates to use Spring Boot 3.4.2 for the dependency management. You can refer <a href=\"https://github.com/spring-projects/spring-boot/blob/v3.4.2/spring-boot-project/spring-boot-dependencies/build.gradle\">here</a> for the dependencies managed by Spring Boot 3.4.2\n\nRequired Actions\n\nIf you are upgrading to Spring Boot 3.4.2, please make sure to refer to <a href=\"https://github.com/spring-projects/spring-boot/wiki/Spring-Boot-3.4-Release-Notes#upgrading-from-spring-boot-33\">this</a> documentation for the changes required to configure the REST Client. Notably, if you don’t have an HTTP client library on the classpath, this will likely result in the use of <code>JdkClientHttpRequestFactory</code> where <code>SimpleClientHttpRequestFactory</code> would have been used previously. To switch to use <code>SimpleClientHttpRequestFactory</code>, you need to set <code>spring.http.client.factory=simple</code>.\nIf you are using a different version of Spring Boot (say Spring Boot 3.3.x) and need a specific version of a dependency, you can override it in your build configuration.',0x00,'asciidoc::upgrade-notes.adoc::Upgrading to 1.0.0-M6::Changes to use Spring Boot 3.4.2 for dependency management::0'),
('6bc1fbcf-e2a0-4fb2-b416-ba416eb0b4f9','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/cohere/BedrockCohereEmbeddingModel.java\">BedrockCohereEmbeddingModel</a> implements the <code>EmbeddingModel</code> and uses the <a href=\"#low-level-api\">Low-level CohereEmbeddingBedrockApi Client</a> to connect to the Bedrock Cohere service.\n\nAdd the <code>spring-ai-bedrock</code> dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-bedrock&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-bedrock\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.\n\nNext, create an <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-bedrock/src/main/java/org/springframework/ai/bedrock/cohere/BedrockCohereEmbeddingModel.java\">BedrockCohereEmbeddingModel</a> and use it for text embeddings:\n\nvar cohereEmbeddingApi =new CohereEmbeddingBedrockApi(\n		CohereEmbeddingModel.COHERE_EMBED_MULTILINGUAL_V1.id(),\n		EnvironmentVariableCredentialsProvider.create(), Region.US_EAST_1.id(), new ObjectMapper());\n\n\nvar embeddingModel = new BedrockCohereEmbeddingModel(this.cohereEmbeddingApi);\n\nEmbeddingResponse embeddingResponse = this.embeddingModel\n	.embedForResponse(List.of(\"Hello World\", \"World is big and salvation is near\"));',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Manual Configuration::0'),
('087b56b4-942f-4030-a5d5-baa2c22b9f34','Currently, the Perplexity API doesn&#8217;t support media content.',0x00,'asciidoc::perplexity-chat.adoc::Multimodal::0'),
('17cd980d-fe5c-499c-9553-bab155f0e185','Microsoft Foundry is automatically detected when using a Microsoft Foundry URL. You can configure it using properties:\n\nspring.ai.openai-sdk.base-url=https://&lt;your-deployment-url&gt;.openai.azure.com\nspring.ai.openai-sdk.api-key=&lt;your-api-key&gt;\nspring.ai.openai-sdk.microsoft-deployment-name=&lt;your-deployment-name&gt;\n\nOr using environment variables:\n\nexport OPENAI_BASE_URL=https://&lt;your-deployment-url&gt;.openai.azure.com\nexport OPENAI_API_KEY=&lt;your-api-key&gt;\n\n<strong>Passwordless Authentication (Recommended for Azure):</strong>\n\nMicrosoft Foundry supports passwordless authentication without providing an API key, which is more secure when running on Azure.\n\nTo enable passwordless authentication, add the <code>com.azure:azure-identity</code> dependency:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;com.azure&lt;/groupId&gt;\n    &lt;artifactId&gt;azure-identity&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nThen configure without an API key:\n\nspring.ai.openai-sdk.base-url=https://&lt;your-deployment-url&gt;.openai.azure.com\nspring.ai.openai-sdk.microsoft-deployment-name=&lt;your-deployment-name&gt;\n# No api-key needed - will use Azure credentials from environment',0x00,'asciidoc::openai-sdk-chat.adoc::Authentication::Using Microsoft Foundry::0'),
('1194e370-9b51-48a2-aa46-bab1bd58ba14','The execution order of advisors in the chain is determined by the <code>getOrder()</code> method. Key points to understand:\n\nAdvisors with lower order values are executed first.\nThe advisor chain operates as a stack:\nTo control execution order:\nHigher values are interpreted as lower priority.\nIf multiple advisors have the same order value, their execution order is not guaranteed.\n\n\n<div class=\"paragraph\">\n<p>The seeming contradiction between order and execution sequence is due to the stack-like nature of the advisor chain:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p>An advisor with the highest precedence (lowest order value) is added to the top of the stack.</p>\n</li>\n<li>\n<p>It will be the first to process the request as the stack unwinds.</p>\n</li>\n<li>\n<p>It will be the last to process the response as the stack rewinds.</p>\n</li>\n</ul>\n</div>\n\nAs a reminder, here are the semantics of the Spring <code>Ordered</code> interface:\n\npublic interface Ordered {\n\n    /**\n     * Constant for the highest precedence value.\n     * @see java.lang.Integer#MIN_VALUE\n     */\n    int HIGHEST_PRECEDENCE = Integer.MIN_VALUE;\n\n    /**\n     * Constant for the lowest precedence value.\n     * @see java.lang.Integer#MAX_VALUE\n     */\n    int LOWEST_PRECEDENCE = Integer.MAX_VALUE;\n\n    /**\n     * Get the order value of this object.\n     * &lt;p&gt;Higher values are interpreted as lower priority. As a consequence,\n     * the object with the lowest value has the highest priority (somewhat\n     * analogous to Servlet {@code load-on-startup} values).\n     * &lt;p&gt;Same order values will result in arbitrary sort positions for the\n     * affected objects.\n     * @return the order value\n     * @see #HIGHEST_PRECEDENCE\n     * @see #LOWEST_PRECEDENCE\n     */\n    int getOrder();\n}\n\n<div class=\"paragraph\">\n<p>For use cases that need to be first in the chain on both the input and output sides:</p>\n</div>\n<div class=\"olist arabic\">\n<ol class=\"arabic\">\n<li>\n<p>Use separate advisors for each side.</p>\n</li>\n<li>\n<p>Configure them with different order values.</p>\n</li>\n<li>\n<p>Use the advisor context to share state between them.</p>\n</li>\n</ol>\n</div>',0x00,'asciidoc::advisors.adoc::Core Components::Advisor Order::0'),
('d31b9db6-df2e-4b05-9554-bae3f0e397ec','Spring AI provides Spring Boot auto-configuration for the OpenAI SDK Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai-sdk&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai-sdk\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::openai-sdk-chat.adoc::Auto-configuration::0'),
('9f0bde7b-11f8-47b3-95ae-baef42e773b9','// Define comprehensive code review guidelines\nString reviewGuidelines = \"\"\"\n    You are a senior software engineer conducting code reviews. Apply these criteria:\n    - Security vulnerabilities and best practices\n    - Performance optimizations and memory usage\n    - Code maintainability and readability\n    - Testing coverage and edge cases\n    - Design patterns and architecture compliance\n    \"\"\";\n\nList&lt;String&gt; codeFiles = Arrays.asList(\n    \"UserService.java\", \"PaymentController.java\", \"SecurityConfig.java\"\n);\n\nList&lt;String&gt; reviews = new ArrayList&lt;&gt;();\n\nfor (String filename : codeFiles) {\n    String sourceCode = loadSourceFile(filename);\n\n    ChatResponse review = chatModel.call(\n        new Prompt(\n            List.of(\n                new SystemMessage(reviewGuidelines), // Cached across all reviews\n                new UserMessage(\"Review this \" + filename + \" code:\\n\\n\" + sourceCode)\n            ),\n            AnthropicChatOptions.builder()\n                .model(\"claude-sonnet-4\")\n                .cacheOptions(AnthropicCacheOptions.builder()\n                    .strategy(AnthropicCacheStrategy.SYSTEM_ONLY)\n                    .build())\n                .maxTokens(800)\n                .build()\n        )\n    );\n\n    reviews.add(review.getResult().getOutput().getText());\n}\n\n// Guidelines cached after first request, subsequent reviews are faster and cheaper\n\nMulti-Tenant SaaS with Shared Tools\n\nBuild a multi-tenant application where tools are shared but system prompts are customized per tenant:',0x00,'asciidoc::anthropic-chat.adoc::Prompt Caching::Real-World Use Cases::1'),
('5de6a49c-f51d-4cc8-a9b9-bafcb93a8b48','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nAdd these dependencies to your project:',0x00,'asciidoc::azure.adoc::Dependencies::0'),
('1948a987-0256-42ef-a6f5-bb60ee1655c5','/**\n * This interface defines a complete listener for a parse tree produced by\n * {@link FiltersParser}.\n */\npublic interface FiltersListener extends ParseTreeListener {\n\n    /**\n     * Enter a parse tree produced by {@link FiltersParser#where}.\n     * @param ctx the parse tree\n     */\n    void enterWhere(FiltersParser.WhereContext ctx);\n\n    /**\n     * Exit a parse tree produced by {@link FiltersParser#where}.\n     * @param ctx the parse tree\n     */\n    void exitWhere(FiltersParser.WhereContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code NinExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void enterNinExpression(FiltersParser.NinExpressionContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code NinExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void exitNinExpression(FiltersParser.NinExpressionContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code AndExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void enterAndExpression(FiltersParser.AndExpressionContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code AndExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void exitAndExpression(FiltersParser.AndExpressionContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code InExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void enterInExpression(FiltersParser.InExpressionContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code InExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void exitInExpression(FiltersParser.InExpressionContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code NotExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void enterNotExpression(FiltersParser.NotExpressionContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code NotExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void exitNotExpression(FiltersParser.NotExpressionContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code CompareExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void enterCompareExpression(FiltersParser.CompareExpressionContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code CompareExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void exitCompareExpression(FiltersParser.CompareExpressionContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code OrExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void enterOrExpression(FiltersParser.OrExpressionContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code OrExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void exitOrExpression(FiltersParser.OrExpressionContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code GroupExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void enterGroupExpression(FiltersParser.GroupExpressionContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code GroupExpression} labeled alternative in\n     * {@link FiltersParser#booleanExpression}.\n     * @param ctx the parse tree\n     */\n    void exitGroupExpression(FiltersParser.GroupExpressionContext ctx);\n\n    /**\n     * Enter a parse tree produced by {@link FiltersParser#constantArray}.\n     * @param ctx the parse tree\n     */\n    void enterConstantArray(FiltersParser.ConstantArrayContext ctx);\n\n    /**\n     * Exit a parse tree produced by {@link FiltersParser#constantArray}.\n     * @param ctx the parse tree\n     */\n    void exitConstantArray(FiltersParser.ConstantArrayContext ctx);\n\n    /**\n     * Enter a parse tree produced by {@link FiltersParser#compare}.\n     * @param ctx the parse tree\n     */\n    void enterCompare(FiltersParser.CompareContext ctx);\n\n    /**\n     * Exit a parse tree produced by {@link FiltersParser#compare}.\n     * @param ctx the parse tree\n     */\n    void exitCompare(FiltersParser.CompareContext ctx);\n\n    /**\n     * Enter a parse tree produced by {@link FiltersParser#identifier}.\n     * @param ctx the parse tree\n     */\n    void enterIdentifier(FiltersParser.IdentifierContext ctx);\n\n    /**\n     * Exit a parse tree produced by {@link FiltersParser#identifier}.\n     * @param ctx the parse tree\n     */\n    void exitIdentifier(FiltersParser.IdentifierContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code LongConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void enterLongConstant(FiltersParser.LongConstantContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code LongConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void exitLongConstant(FiltersParser.LongConstantContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code IntegerConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void enterIntegerConstant(FiltersParser.IntegerConstantContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code IntegerConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void exitIntegerConstant(FiltersParser.IntegerConstantContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code DecimalConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void enterDecimalConstant(FiltersParser.DecimalConstantContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code DecimalConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void exitDecimalConstant(FiltersParser.DecimalConstantContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code TextConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void enterTextConstant(FiltersParser.TextConstantContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code TextConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void exitTextConstant(FiltersParser.TextConstantContext ctx);\n\n    /**\n     * Enter a parse tree produced by the {@code BooleanConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void enterBooleanConstant(FiltersParser.BooleanConstantContext ctx);\n\n    /**\n     * Exit a parse tree produced by the {@code BooleanConstant} labeled alternative in\n     * {@link FiltersParser#constant}.\n     * @param ctx the parse tree\n     */\n    void exitBooleanConstant(FiltersParser.BooleanConstantContext ctx);\n}',0x01,'cu::FiltersListener.java'),
('9aa2588e-756f-447e-bfe9-bb82366216a1','This functionality has been moved to the Spring AI Community repository.\n\nPlease visit <a href=\"https://github.com/spring-ai-community/qianfan\" class=\"bare\">https://github.com/spring-ai-community/qianfan</a> for the latest version.',0x00,'asciidoc::qianfan-chat.adoc::0'),
('5cd3ce26-2508-4046-93fa-bc6dff9fc61c','The <code>ToolMetadata.Builder</code> allows you to build a <code>ToolMetadata</code> instance and define additional settings for the tool:\n\n<code>returnDirect</code>: Whether the tool result should be returned directly to the client or passed back to the model. See <a href=\"#_return_direct\">Return Direct</a> for more details.\n\n\nMethod method = ReflectionUtils.findMethod(DateTimeTools.class, \"getCurrentDateTime\");\nToolCallback toolCallback = MethodToolCallback.builder()\n    .toolDefinition(ToolDefinitions.builder(method)\n            .description(\"Get the current date and time in the user\'s timezone\")\n            .build())\n    .toolMethod(method)\n    .toolObject(new DateTimeTools())\n    .build();\n\nThe method can be either static or instance, and it can have any visibility (public, protected, package-private, or private). The class that contains the method can be either a top-level class or a nested class, and it can also have any visibility (as long as it&#8217;s accessible where you&#8217;re planning to instantiate it).\n\nSpring AI provides built-in support for AOT compilation of the tool methods as long as the class containing the methods is a Spring bean (e.g. <code>@Component</code>). Otherwise, you&#8217;ll need to provide the necessary configuration to the GraalVM compiler. For example, by annotating the class with <code>@RegisterReflection(memberCategories = MemberCategory.INVOKE_DECLARED_METHODS)</code>.\n\nYou can define any number of arguments for the method (including no argument) with most types (primitives, POJOs, enums, lists, arrays, maps, and so on). Similarly, the method can return most types, including <code>void</code>. If the method returns a value, the return type must be a serializable type, as the result will be serialized and sent back to the model.\n\nSome types are not supported. See <a href=\"#_method_tool_limitations\">Method Tool Limitations</a> for more details.\n\nIf the method is static, you can omit the <code>toolObject()</code> method, as it&#8217;s not needed.\n\nclass DateTimeTools {\n\n    static String getCurrentDateTime() {\n        return LocalDateTime.now().atZone(LocaleContextHolder.getTimeZone().toZoneId()).toString();\n    }\n\n}\n\nMethod method = ReflectionUtils.findMethod(DateTimeTools.class, \"getCurrentDateTime\");\nToolCallback toolCallback = MethodToolCallback.builder()\n    .toolDefinition(ToolDefinitions.builder(method)\n            .description(\"Get the current date and time in the user\'s timezone\")\n            .build())\n    .toolMethod(method)\n    .build();\n\nSpring AI will generate the JSON schema for the input parameters of the method automatically. The schema is used by the model to understand how to call the tool and prepare the tool request. The <code>@ToolParam</code> annotation can be used to provide additional information about the input parameters, such as a description or whether the parameter is required or optional. By default, all input parameters are considered required.',0x00,'asciidoc::tools.adoc::Methods as Tools::Programmatic Specification: <code>MethodToolCallback</code>::1'),
('9231c592-4578-4307-baee-bcee8a0c07fc','<a href=\"https://start.spring.io/\">Create</a> a new Spring Boot project and add the <code>spring-ai-starter-model-oci-genai</code> to your pom (or gradle) dependencies.\n\nAdd a <code>application.properties</code> file, under the <code>src/main/resources</code> directory, to enable and configure the OCI GenAI Cohere chat model:\n\nspring.ai.oci.genai.authenticationType=file\nspring.ai.oci.genai.file=/path/to/oci/config/file\nspring.ai.oci.genai.cohere.chat.options.compartment=my-compartment-ocid\nspring.ai.oci.genai.cohere.chat.options.servingMode=on-demand\nspring.ai.oci.genai.cohere.chat.options.model=my-chat-model-ocid\n\nreplace the <code>file</code>, <code>compartment</code>, and <code>model</code> with your values from your OCI account.\n\nThis will create a <code>OCICohereChatModel</code> implementation that you can inject into your class.\nHere is an example of a simple <code>@Controller</code> class that uses the chat model for text generations.\n\n@RestController\npublic class ChatController {\n\n    private final OCICohereChatModel chatModel;\n\n    @Autowired\n    public ChatController(OCICohereChatModel chatModel) {\n        this.chatModel = chatModel;\n    }\n\n    @GetMapping(\"/ai/generate\")\n    public Map generate(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        return Map.of(\"generation\", chatModel.call(message));\n    }\n\n    @GetMapping(\"/ai/generateStream\")\n	public Flux&lt;ChatResponse&gt; generateStream(@RequestParam(value = \"message\", defaultValue = \"Tell me a joke\") String message) {\n        var prompt = new Prompt(new UserMessage(message));\n        return chatModel.stream(prompt);\n    }\n}',0x00,'asciidoc::cohere-chat.adoc::Sample Controller::0'),
('448e4bb0-d9d8-4e2d-a7d1-bd234b4c4e47','Claude 4 models integrate thinking and tool use capabilities:\n\n<strong>Claude 3.7 Sonnet</strong>: Supports both thinking and tool use, but they operate separately and require more explicit configuration\n<strong>Claude 4 models</strong>: Natively interleave thinking and tool use, providing deeper reasoning during tool interactions',0x00,'asciidoc::anthropic-chat.adoc::Thinking::Tool Use Integration::0'),
('ef5208d4-e250-4674-bcf8-bd4a37756bc6','These are the available implementations of the <code>VectorStore</code> interface:',0x00,'asciidoc::vectordbs.adoc::VectorStore Implementations::0'),
('0d44bd03-329d-412c-9928-bd8e2a14bbbb','/**\n * A component for post-processing retrieved documents based on a query, addressing\n * challenges such as \"lost-in-the-middle\", context length restrictions from the model,\n * and the need to reduce noise and redundancy in the retrieved information.\n * <p>\n * For example, it could rank documents based on their relevance to the query, remove\n * irrelevant or redundant documents, or compress the content of each document to reduce\n * noise and redundancy.\n *\n * @author Thomas Vitale\n * @since 1.0.0\n */\npublic interface DocumentPostProcessor extends BiFunction<Query, List<Document>, List<Document>> {\n\n    List<Document> process(Query query, List<Document> documents);\n\n    default List<Document> apply(Query query, List<Document> documents) {\n        return process(query, documents);\n    }\n}',0x01,'cu::DocumentPostProcessor.java'),
('724b5f44-efad-408d-b204-bdb1e38dd2e2','To access models using an API key, obtain your Azure OpenAI <code>endpoint</code> and <code>api-key</code> from the Azure OpenAI Service section on the <a href=\"https://portal.azure.com\">Azure Portal</a>.\n\nSpring AI defines two configuration properties:\n\n<code>spring.ai.azure.openai.api-key</code>: Set this to the value of the <code>API Key</code> obtained from Azure.\n<code>spring.ai.azure.openai.endpoint</code>: Set this to the endpoint URL obtained when provisioning your model in Azure.\n\n\nYou can set these configuration properties in your <code>application.properties</code> or <code>application.yml</code> file:\n\nspring.ai.azure.openai.api-key=&lt;your-azure-api-key&gt;\nspring.ai.azure.openai.endpoint=&lt;your-azure-endpoint-url&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference custom environment variables:\n\n# In application.yml\nspring:\n  ai:\n    azure:\n      openai:\n        api-key: ${AZURE_OPENAI_API_KEY}\n        endpoint: ${AZURE_OPENAI_ENDPOINT}\n\n# In your environment or .env file\nexport AZURE_OPENAI_API_KEY=&lt;your-azure-openai-api-key&gt;\nexport AZURE_OPENAI_ENDPOINT=&lt;your-azure-openai-endpoint-url&gt;',0x00,'asciidoc::azure-openai-chat.adoc::Prerequisites::Azure API Key &amp; Endpoint::0'),
('3eb2ecb8-050b-43a0-a456-bddac628d1fd','AWS Bedrock follows a hierarchical cache model with cascade invalidation:\n\n<strong>Cache Hierarchy</strong>: <code>Tools → System → Messages</code>\n\nChanges at each level invalidate that level and all subsequent levels:\n\n\n\n<strong>Example with <code>SYSTEM_AND_TOOLS</code> strategy</strong>:\n\n// Request 1: Cache both tools and system\nChatResponse r1 = chatModel.call(\n    new Prompt(\n        List.of(new SystemMessage(\"System prompt\"), new UserMessage(\"Question\")),\n        BedrockChatOptions.builder()\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_AND_TOOLS)\n                .build())\n            .toolCallbacks(tools)\n            .build()\n    )\n);\n// Result: Both caches created\n\n// Request 2: Change only system prompt (tools same)\nChatResponse r2 = chatModel.call(\n    new Prompt(\n        List.of(new SystemMessage(\"DIFFERENT system prompt\"), new UserMessage(\"Question\")),\n        BedrockChatOptions.builder()\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_AND_TOOLS)\n                .build())\n            .toolCallbacks(tools) // SAME tools\n            .build()\n    )\n);\n// Result: Tools cache HIT (reused), system cache MISS (recreated)\n\n// Request 3: Change tools (system same as Request 2)\nChatResponse r3 = chatModel.call(\n    new Prompt(\n        List.of(new SystemMessage(\"DIFFERENT system prompt\"), new UserMessage(\"Question\")),\n        BedrockChatOptions.builder()\n            .cacheOptions(BedrockCacheOptions.builder()\n                .strategy(BedrockCacheStrategy.SYSTEM_AND_TOOLS)\n                .build())\n            .toolCallbacks(newTools) // DIFFERENT tools\n            .build()\n    )\n);\n// Result: BOTH caches MISS (tools change invalidates everything downstream)',0x00,'asciidoc::bedrock-converse.adoc::Prompt Caching::Cache Invalidation and Cascade Behavior::0'),
('67ca828d-4137-42b6-8a5f-be01d2ee227b','Anthropic&#8217;s <a href=\"https://docs.anthropic.com/en/docs/build-with-claude/citations\">Citations API</a> allows Claude to reference specific parts of provided documents when generating responses.\nWhen citation documents are included in a prompt, Claude can cite the source material, and citation metadata (character ranges, page numbers, or content blocks) is returned in the response metadata.\n\nCitations help improve:\n\n<strong>Accuracy verification</strong>: Users can verify Claude&#8217;s responses against source material\n<strong>Transparency</strong>: See exactly which parts of documents informed the response\n<strong>Compliance</strong>: Meet requirements for source attribution in regulated industries\n<strong>Trust</strong>: Build confidence by showing where information came from\n\n\n<div class=\"paragraph\">\n<p><strong>Supported Models</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Citations are supported on Claude 3.7 Sonnet and Claude 4 models (Opus and Sonnet).</p>\n</div>\n<div class=\"paragraph\">\n<p><strong>Document Types</strong></p>\n</div>\n<div class=\"paragraph\">\n<p>Three types of citation documents are supported:</p>\n</div>\n<div class=\"ulist\">\n<ul>\n<li>\n<p><strong>Plain Text</strong>: Text content with character-level citations</p>\n</li>\n<li>\n<p><strong>PDF</strong>: PDF documents with page-level citations</p>\n</li>\n<li>\n<p><strong>Custom Content</strong>: User-defined content blocks with block-level citations</p>\n</li>\n</ul>\n</div>',0x00,'asciidoc::anthropic-chat.adoc::Citations::0'),
('5904e9d3-760e-4df4-9f42-be642f5bdde4','Search results are automatically ordered by similarity score in descending order (highest score first).\nThis ensures that the most relevant documents appear at the top of your results.',0x00,'asciidoc::mariadb.adoc::Similarity Scores::Search Results Ordering::0'),
('36f9501e-dda4-43e6-b0ff-bea0e25319cf','You will need to create an API with MiniMax to access MiniMax language models.\n\nCreate an account at <a href=\"https://www.minimaxi.com/login\">MiniMax registration page</a> and generate the token on the <a href=\"https://www.minimaxi.com/user-center/basic-information/interface-key\">API Keys page</a>.\n\nThe Spring AI project defines a configuration property named <code>spring.ai.minimax.api-key</code> that you should set to the value of the <code>API Key</code> obtained from the API Keys page.\n\nYou can set this configuration property in your <code>application.properties</code> file:\n\nspring.ai.minimax.api-key=&lt;your-minimax-api-key&gt;\n\nFor enhanced security when handling sensitive information like API keys, you can use Spring Expression Language (SpEL) to reference an environment variable:\n\n# In application.yml\nspring:\n  ai:\n    minimax:\n      api-key: ${MINIMAX_API_KEY}\n\n# In your environment or .env file\nexport MINIMAX_API_KEY=&lt;your-minimax-api-key&gt;\n\nYou can also set this configuration programmatically in your application code:\n\n// Retrieve API key from a secure source or environment variable\nString apiKey = System.getenv(\"MINIMAX_API_KEY\");',0x00,'asciidoc::minimax-embeddings.adoc::Prerequisites::0'),
('06cb9089-9859-446b-be2d-beba89beb1b4','For convenience, you can also delete documents using a string-based filter expression:\n\nvoid delete(String filterExpression);\n\nThis method converts the provided string filter into a <code>Filter.Expression</code> object internally.\nIt&#8217;s useful when you have filter criteria in string format.\n\n// Create and add documents\nDocument bgDocument = new Document(\"The World is Big\",\n    Map.of(\"country\", \"Bulgaria\"));\nDocument nlDocument = new Document(\"The World is Big\",\n    Map.of(\"country\", \"Netherlands\"));\nvectorStore.add(List.of(bgDocument, nlDocument));\n\n// Delete Bulgarian documents using string filter\nvectorStore.delete(\"country == \'Bulgaria\'\");\n\n// Verify remaining documents\nSearchRequest request = SearchRequest.builder()\n    .query(\"World\")\n    .topK(5)\n    .build();\nList&lt;Document&gt; results = vectorStore.similaritySearch(request);\n// results will only contain the Netherlands document',0x00,'asciidoc::vectordbs.adoc::Deleting Documents from Vector Store::Delete by String Filter Expression::0'),
('67228b12-2651-4f64-8003-bed4aec02259','Refer to the <a href=\"api/bedrock.html\">Spring AI documentation on Amazon Bedrock</a> for setting up API access.',0x00,'asciidoc::bedrock-cohere-embedding.adoc::Prerequisites::0'),
('6084ddae-9a80-42c3-88e2-bee2f34e523b','class SimpleVectorStoreTests {\n\n    @TempDir(cleanup = CleanupMode.ON_SUCCESS)\n    Path tempDir;\n\n    private SimpleVectorStore vectorStore;\n\n    private EmbeddingModel mockEmbeddingModel;\n\n    @BeforeEach\n    void setUp() {\n        this.mockEmbeddingModel = mock(EmbeddingModel.class);\n        when(this.mockEmbeddingModel.dimensions()).thenReturn(3);\n        when(this.mockEmbeddingModel.embed(any(String.class))).thenReturn(new float[] { 0.1f, 0.2f, 0.3f });\n        when(this.mockEmbeddingModel.embed(any(Document.class))).thenReturn(new float[] { 0.1f, 0.2f, 0.3f });\n        this.vectorStore = new SimpleVectorStore(SimpleVectorStore.builder(this.mockEmbeddingModel));\n    }\n\n    @Test\n    void shouldAddAndRetrieveDocument() {\n        Document doc = Document.builder().id(\"1\").text(\"test content\").metadata(Map.of(\"key\", \"value\")).build();\n        this.vectorStore.add(List.of(doc));\n        List<Document> results = this.vectorStore.similaritySearch(\"test content\");\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"test content\");\n            assertThat(result.getMetadata()).containsEntry(\"key\", \"value\");\n        });\n    }\n\n    @Test\n    void shouldAddMultipleDocuments() {\n        List<Document> docs = Arrays.asList(Document.builder().id(\"1\").text(\"first\").build(), Document.builder().id(\"2\").text(\"second\").build());\n        this.vectorStore.add(docs);\n        List<Document> results = this.vectorStore.similaritySearch(\"first\");\n        assertThat(results).hasSize(2).extracting(Document::getId).containsExactlyInAnyOrder(\"1\", \"2\");\n    }\n\n    @Test\n    void shouldHandleEmptyDocumentList() {\n        assertThatThrownBy(() -> this.vectorStore.add(Collections.emptyList())).isInstanceOf(IllegalArgumentException.class).hasMessage(\"Documents list cannot be empty\");\n    }\n\n    @Test\n    void shouldHandleNullDocumentList() {\n        assertThatThrownBy(() -> this.vectorStore.add(null)).isInstanceOf(NullPointerException.class).hasMessage(\"Documents list cannot be null\");\n    }\n\n    @Test\n    void shouldDeleteDocuments() {\n        Document doc = Document.builder().id(\"1\").text(\"test content\").build();\n        this.vectorStore.add(List.of(doc));\n        assertThat(this.vectorStore.similaritySearch(\"test\")).hasSize(1);\n        this.vectorStore.delete(List.of(\"1\"));\n        assertThat(this.vectorStore.similaritySearch(\"test\")).isEmpty();\n    }\n\n    @Test\n    void shouldHandleDeleteOfNonexistentDocument() {\n        this.vectorStore.delete(List.of(\"nonexistent-id\"));\n        // Should not throw exception\n        assertDoesNotThrow(() -> this.vectorStore.delete(List.of(\"nonexistent-id\")));\n    }\n\n    @Test\n    void shouldPerformSimilaritySearchWithThreshold() {\n        // Configure mock to return different embeddings for different queries\n        when(this.mockEmbeddingModel.embed(\"query\")).thenReturn(new float[] { 0.9f, 0.9f, 0.9f });\n        Document doc = Document.builder().id(\"1\").text(\"test content\").build();\n        this.vectorStore.add(List.of(doc));\n        SearchRequest request = SearchRequest.builder().query(\"query\").similarityThreshold(0.99f).topK(5).build();\n        List<Document> results = this.vectorStore.similaritySearch(request);\n        assertThat(results).isEmpty();\n    }\n\n    @Test\n    void shouldSaveAndLoadVectorStore() throws IOException {\n        Document doc = Document.builder().id(\"1\").text(\"test content\").metadata(new HashMap<>(Map.of(\"key\", \"value\"))).build();\n        this.vectorStore.add(List.of(doc));\n        File saveFile = this.tempDir.resolve(\"vector-store.json\").toFile();\n        this.vectorStore.save(saveFile);\n        SimpleVectorStore loadedStore = SimpleVectorStore.builder(this.mockEmbeddingModel).build();\n        loadedStore.load(saveFile);\n        List<Document> results = loadedStore.similaritySearch(\"test content\");\n        assertThat(results).hasSize(1).first().satisfies(result -> {\n            assertThat(result.getId()).isEqualTo(\"1\");\n            assertThat(result.getText()).isEqualTo(\"test content\");\n            assertThat(result.getMetadata()).containsEntry(\"key\", \"value\");\n        });\n    }\n\n    @Test\n    void shouldHandleLoadFromInvalidResource() throws IOException {\n        Resource mockResource = mock(Resource.class);\n        when(mockResource.getInputStream()).thenThrow(new IOException(\"Resource not found\"));\n        assertThatThrownBy(() -> this.vectorStore.load(mockResource)).isInstanceOf(RuntimeException.class).hasCauseInstanceOf(IOException.class).hasMessageContaining(\"Resource not found\");\n    }\n\n    @Test\n    void shouldHandleSaveToInvalidLocation() {\n        File invalidFile = new File(\"/invalid/path/file.json\");\n        assertThatThrownBy(() -> this.vectorStore.save(invalidFile)).isInstanceOf(RuntimeException.class).hasCauseInstanceOf(IOException.class);\n    }\n\n    @Test\n    void shouldHandleConcurrentOperations() throws InterruptedException {\n        int numThreads = 10;\n        Thread[] threads = new Thread[numThreads];\n        for (int i = 0; i < numThreads; i++) {\n            final String id = String.valueOf(i);\n            threads[i] = new Thread(() -> {\n                Document doc = Document.builder().id(id).text(\"content \" + id).build();\n                this.vectorStore.add(List.of(doc));\n            });\n            threads[i].start();\n        }\n        for (Thread thread : threads) {\n            thread.join();\n        }\n        SearchRequest request = SearchRequest.builder().query(\"test\").topK(numThreads).build();\n        List<Document> results = this.vectorStore.similaritySearch(request);\n        assertThat(results).hasSize(numThreads);\n        // Verify all documents were properly added\n        Set<String> resultIds = results.stream().map(Document::getId).collect(Collectors.toSet());\n        Set<String> expectedIds = new java.util.HashSet<>();\n        for (int i = 0; i < numThreads; i++) {\n            expectedIds.add(String.valueOf(i));\n        }\n        assertThat(resultIds).containsExactlyInAnyOrderElementsOf(expectedIds);\n        // Verify content integrity\n        results.forEach(doc -> assertThat(doc.getText()).isEqualTo(\"content \" + doc.getId()));\n    }\n\n    @Test\n    void shouldRejectInvalidSimilarityThreshold() {\n        assertThatThrownBy(() -> SearchRequest.builder().query(\"test\").similarityThreshold(2.0f).build()).isInstanceOf(IllegalArgumentException.class).hasMessage(\"Similarity threshold must be in [0,1] range.\");\n    }\n\n    @Test\n    void shouldRejectNegativeTopK() {\n        assertThatThrownBy(() -> SearchRequest.builder().query(\"test\").topK(-1).build()).isInstanceOf(IllegalArgumentException.class).hasMessage(\"TopK should be positive.\");\n    }\n\n    @Test\n    void shouldHandleCosineSimilarityEdgeCases() {\n        float[] zeroVector = new float[] { 0f, 0f, 0f };\n        float[] normalVector = new float[] { 1f, 1f, 1f };\n        assertThatThrownBy(() -> SimpleVectorStore.EmbeddingMath.cosineSimilarity(zeroVector, normalVector)).isInstanceOf(IllegalArgumentException.class).hasMessage(\"Vectors cannot have zero norm\");\n    }\n\n    @Test\n    void shouldHandleVectorLengthMismatch() {\n        float[] vector1 = new float[] { 1f, 2f };\n        float[] vector2 = new float[] { 1f, 2f, 3f };\n        assertThatThrownBy(() -> SimpleVectorStore.EmbeddingMath.cosineSimilarity(vector1, vector2)).isInstanceOf(IllegalArgumentException.class).hasMessage(\"Vectors lengths must be equal\");\n    }\n\n    @Test\n    void shouldHandleNullVectors() {\n        float[] vector = new float[] { 1f, 2f, 3f };\n        assertThatThrownBy(() -> SimpleVectorStore.EmbeddingMath.cosineSimilarity(null, vector)).isInstanceOf(RuntimeException.class).hasMessage(\"Vectors must not be null\");\n        assertThatThrownBy(() -> SimpleVectorStore.EmbeddingMath.cosineSimilarity(vector, null)).isInstanceOf(RuntimeException.class).hasMessage(\"Vectors must not be null\");\n    }\n\n    @Test\n    void shouldFailNonTextDocuments() {\n        Media media = new Media(MimeType.valueOf(\"image/png\"), new ByteArrayResource(new byte[] { 0x00 }));\n        Document imgDoc = Document.builder().media(media).metadata(Map.of(\"fileName\", \"pixel.png\")).build();\n        Exception exception = assertThrows(IllegalArgumentException.class, () -> this.vectorStore.add(List.of(imgDoc)));\n        assertEquals(\"Only text documents are supported for now. One of the documents contains non-text content.\", exception.getMessage());\n    }\n\n    @Test\n    void shouldHandleDocumentWithoutId() {\n        Document doc = Document.builder().text(\"content without id\").build();\n        this.vectorStore.add(List.of(doc));\n        List<Document> results = this.vectorStore.similaritySearch(\"content\");\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getId()).isNotEmpty();\n    }\n\n    @Test\n    void shouldHandleDocumentWithEmptyText() {\n        Document doc = Document.builder().id(\"1\").text(\"\").build();\n        assertDoesNotThrow(() -> this.vectorStore.add(List.of(doc)));\n        List<Document> results = this.vectorStore.similaritySearch(\"anything\");\n        assertThat(results).hasSize(1);\n    }\n\n    @Test\n    void shouldReplaceDocumentWithSameId() {\n        Document doc1 = Document.builder().id(\"1\").text(\"original\").metadata(Map.of(\"version\", \"1\")).build();\n        Document doc2 = Document.builder().id(\"1\").text(\"updated\").metadata(Map.of(\"version\", \"2\")).build();\n        this.vectorStore.add(List.of(doc1));\n        this.vectorStore.add(List.of(doc2));\n        List<Document> results = this.vectorStore.similaritySearch(\"updated\");\n        assertThat(results).hasSize(1);\n        assertThat(results.get(0).getText()).isEqualTo(\"updated\");\n        assertThat(results.get(0).getMetadata()).containsEntry(\"version\", \"2\");\n    }\n\n    @Test\n    void shouldHandleSearchWithEmptyQuery() {\n        Document doc = Document.builder().id(\"1\").text(\"content\").build();\n        this.vectorStore.add(List.of(doc));\n        List<Document> results = this.vectorStore.similaritySearch(\"\");\n        assertThat(results).hasSize(1);\n    }\n}',0x01,'cu::SimpleVectorStoreTests.java'),
('25ea7ecd-7fa3-4a80-a569-bf9b6599e4ce','Authentication is done using a base URL and an API Key. The implementation provides flexible configuration options through Spring Boot properties or environment variables.',0x00,'asciidoc::openai-sdk-embeddings.adoc::Authentication::0'),
('290b3925-351c-4b71-b392-bfe4c5a10cb4','The <code>spring.ai.chat.client.observations.include-input</code> property is deprecated, replaced by <code>spring.ai.chat.client.observations.log-prompt</code>. See <a href=\"#_prompt_content\">Prompt Content</a>.\n\nThe <code>ChatClient</code> input data is typically big and possibly containing sensitive information.\nFor those reasons, it is not exported by default.\n\nSpring AI supports logging input data to help with debugging and troubleshooting.\n\n\n\nIf you enable the inclusion of the input content in the observations, there&#8217;s a risk of exposing sensitive or private information. Please, be careful!',0x00,'asciidoc::index.adoc::Chat Client::Input Data (Deprecated)::0'),
('206de30d-90dc-4bdb-862c-c03ddec58de6','The <a href=\"https://github.com/spring-projects/spring-ai/blob/main/models/spring-ai-anthropic/src/test/java/org/springframework/ai/anthropic/chat/api/AnthropicApiIT.java\">AnthropicApiIT.java</a> test provides some general examples how to use the lightweight library.',0x00,'asciidoc::anthropic-chat.adoc::Low-level AnthropicApi Client::Low-level API Examples::0'),
('2d2043c8-9fe5-4438-8fe0-c064490b3153','To connect to MariaDB and use the <code>MariaDBVectorStore</code>, you need to provide access details for your instance.\nA simple configuration can be provided via Spring Boot&#8217;s <code>application.yml</code>:\n\nspring:\n  datasource:\n    url: jdbc:mariadb://localhost/db\n    username: myUser\n    password: myPassword\n  ai:\n    vectorstore:\n      mariadb:\n        initialize-schema: true\n        distance-type: COSINE\n        dimensions: 1536\n\nIf you run MariaDB Vector as a Spring Boot dev service via <a href=\"https://docs.spring.io/spring-boot/reference/features/dev-services.html#features.dev-services.docker-compose\">Docker Compose</a>\nor <a href=\"https://docs.spring.io/spring-boot/reference/features/dev-services.html#features.dev-services.testcontainers\">Testcontainers</a>,\nyou don&#8217;t need to configure URL, username and password since they are autoconfigured by Spring Boot.\n\nProperties starting with <code>spring.ai.vectorstore.mariadb.*</code> are used to configure the <code>MariaDBVectorStore</code>:\n\n\n\nIf you configure a custom schema and/or table name, consider enabling schema validation by setting <code>spring.ai.vectorstore.mariadb.schema-validation=true</code>.\nThis ensures the correctness of the names and reduces the risk of SQL injection attacks.',0x00,'asciidoc::mariadb.adoc::Auto-Configuration::Configuration Properties::0'),
('5a15ba84-84c2-468e-ad0f-c08d56e4c244','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the OpenAI Chat Client.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> or Gradle <code>build.gradle</code> build files:\n\n<div class=\"dlist\">\n<dl>\n<dt class=\"hdlist1\">Maven</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-xml\" data-lang=\"xml\">&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-openai&lt;/artifactId&gt;\n&lt;/dependency&gt;</code></pre>\n</div>\n</div>\n</dd>\n<dt class=\"hdlist1\">Gradle</dt>\n<dd>\n<div class=\"listingblock\">\n<div class=\"content\">\n<pre class=\"highlight\"><code class=\"language-groovy\" data-lang=\"groovy\">dependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-openai\'\n}</code></pre>\n</div>\n</div>\n</dd>\n</dl>\n</div>\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::openai-chat.adoc::Auto-configuration::0'),
('8d328edc-ed7c-45c4-9b2b-c09366f62c41','&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-openai-spring-boot-starter&lt;/artifactId&gt;\n&lt;/dependency&gt;',0x00,'asciidoc::effective-agents.adoc::Spring AI&#8217;s Implementation Advantages::<a href=\"https://docs.spring.io/spring-ai/reference/api/chat/comparison.html\">Model Portability</a>::0'),
('e04bae49-807d-4624-b5af-c0ae992ece8a','Large Language Models (LLMs) are frozen after training, leading to stale knowledge, and they are unable to access or modify external data.\n\nThe <a href=\":api/tools.html\">Tool Calling</a> mechanism addresses these shortcomings.\nIt allows you to register your own services as tools to connect the large language models to the APIs of external systems.\nThese systems can provide LLMs with real-time data and perform data processing actions on their behalf.\n\nSpring AI greatly simplifies code you need to write to support tool invocation.\nIt handles the tool invocation conversation for you.\nYou can provide your tool as a <code>@Tool</code>-annotated method and provide it in your prompt options to make it available to the model.\nAdditionally, you can define and reference multiple tools in a single prompt.\n\nWhen we want to make a tool available to the model, we include its definition in the chat request. Each tool definition comprises of a name, a description, and the schema of the input parameters.\nWhen the model decides to call a tool, it sends a response with the tool name and the input parameters modeled after the defined schema.\nThe application is responsible for using the tool name to identify and execute the tool with the provided input parameters.\nThe result of the tool call is processed by the application.\nThe application sends the tool call result back to the model.\nThe model generates the final response using the tool call result as additional context.\n\n\nFollow the <a href=\":api/tools.html\">Tool Calling</a> documentation for further information on how to use this feature with different AI models.',0x00,'asciidoc::concepts.adoc::Bringing Your Data &amp; APIs to the AI Model::Tool Calling::0'),
('165b6dd7-26b2-4506-aee5-c0d473ef3e9f','The thinking feature provides several benefits:\n\n<strong>Transparency</strong>: See the model&#8217;s reasoning process and how it arrived at its conclusion\n<strong>Debugging</strong>: Identify where the model might be making logical errors\n<strong>Education</strong>: Use the step-by-step reasoning as a teaching tool\n<strong>Complex Problem Solving</strong>: Better results on math, logic, and reasoning tasks\n\n\nNote that enabling thinking requires a higher token budget, as the thinking process itself consumes tokens from your allocation.',0x00,'asciidoc::anthropic-chat.adoc::Thinking::Benefits of Using Thinking::0'),
('d882e7ab-4fe9-4122-bdd8-c0e01a83c55d','<div class=\"paragraph\">\n<p>There has been a significant change in the Spring AI auto-configuration, starter modules\' artifact names.\nPlease refer to the <a href=\"https://docs.spring.io/spring-ai/reference/upgrade-notes.html\">upgrade notes</a> for more information.</p>\n</div>\n\nSpring AI provides Spring Boot auto-configuration for the MistralAI Embedding Model.\nTo enable it add the following dependency to your project&#8217;s Maven <code>pom.xml</code> file:\n\n&lt;dependency&gt;\n    &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt;\n    &lt;artifactId&gt;spring-ai-starter-model-mistral-ai&lt;/artifactId&gt;\n&lt;/dependency&gt;\n\nor to your Gradle <code>build.gradle</code> build file.\n\ndependencies {\n    implementation \'org.springframework.ai:spring-ai-starter-model-mistral-ai\'\n}\n\nRefer to the <a href=\"getting-started.html#dependency-management\">Dependency Management</a> section to add the Spring AI BOM to your build file.',0x00,'asciidoc::mistralai-embeddings.adoc::Auto-configuration::0'),
('1d06a824-5b60-4066-bdf3-c0e085d54417','A running Weaviate instance. The following options are available:\nIf required, an API key for the <a href=\"api/embeddings.html#available-implementations\">EmbeddingModel</a> to generate the embeddings stored by the <code>WeaviateVectorStore</code>.',0x00,'asciidoc::weaviate.adoc::Prerequisites::0'),
('49fae5d5-d94e-4c0f-8f95-c1307a45eb35','OpenAI models that offer vision multimodal support include <code>gpt-4</code>, <code>gpt-4o</code>, and <code>gpt-4o-mini</code>.\nRefer to the <a href=\"https://platform.openai.com/docs/guides/vision\">Vision</a> guide for more information.\n\nThe OpenAI <a href=\"https://platform.openai.com/docs/api-reference/chat/create#chat-create-messages\">User Message API</a> can incorporate a list of base64-encoded images or image urls with the message.\nSpring AI’s <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-model/src/main/java/org/springframework/ai/chat/messages/Message.java\">Message</a> interface facilitates multimodal AI models by introducing the <a href=\"https://github.com/spring-projects/spring-ai/blob/main/spring-ai-commons/src/main/java/org/springframework/ai/content/Media.java\">Media</a> type.\nThis type encompasses data and details regarding media attachments in messages, utilizing Spring’s <code>org.springframework.util.MimeType</code> and a <code>org.springframework.core.io.Resource</code> for the raw media data.\n\nBelow is a code example excerpted from <a href=\"https://github.com/spring-projects/spring-ai/blob/c9a3e66f90187ce7eae7eb78c462ec622685de6c/models/spring-ai-openai/src/test/java/org/springframework/ai/openai/chat/OpenAiChatModelIT.java#L293\">OpenAiChatModelIT.java</a>, illustrating the fusion of user text with an image using the <code>gpt-4o</code> model.\n\nvar imageResource = new ClassPathResource(\"/multimodal.test.png\");\n\nvar userMessage = new UserMessage(\"Explain what do you see on this picture?\",\n        new Media(MimeTypeUtils.IMAGE_PNG, this.imageResource));\n\nChatResponse response = chatModel.call(new Prompt(this.userMessage,\n        OpenAiChatOptions.builder().model(OpenAiApi.ChatModel.GPT_4_O.getValue()).build()));\n\nGPT_4_VISION_PREVIEW will continue to be available only to existing users of this model starting June 17, 2024. If you are not an existing user, please use the GPT_4_O or GPT_4_TURBO models. More details <a href=\"https://platform.openai.com/docs/deprecations/2024-06-06-gpt-4-32k-and-vision-preview-models\">here</a>\n\nor the image URL equivalent using the <code>gpt-4o</code> model:\n\nvar userMessage = new UserMessage(\"Explain what do you see on this picture?\",\n        new Media(MimeTypeUtils.IMAGE_PNG,\n                URI.create(\"https://docs.spring.io/spring-ai/reference/_images/multimodal.test.png\")));\n\nChatResponse response = chatModel.call(new Prompt(this.userMessage,\n        OpenAiChatOptions.builder().model(OpenAiApi.ChatModel.GPT_4_O.getValue()).build()));\n\nYou can pass multiple images as well.\n\nThe example shows a model taking as an input the <code>multimodal.test.png</code> image:\n\nalong with the text message \"Explain what do you see on this picture?\", and generating a response like this:',0x00,'asciidoc::openai-chat.adoc::Multimodal::Vision::0'),
('7aea2887-38e0-4843-8504-c1491c959e89','Tokens serve as the building blocks of how an AI model works.\nOn input, models convert words to tokens. On output, they convert tokens back to words.\n\nIn English, one token roughly corresponds to 75% of a word. For reference, Shakespeare&#8217;s complete works, totaling around 900,000 words, translate to approximately 1.2 million tokens.\n\nPerhaps more important is that Tokens = Money.\nIn the context of hosted AI models, your charges are determined by the number of tokens used. Both input and output contribute to the overall token count.\n\nAlso, models are subject to token limits, which restrict the amount of text processed in a single API call.\nThis threshold is often referred to as the \"context window\". The model does not process any text that exceeds this limit.\n\nFor instance, ChatGPT3 has a 4K token limit, while GPT4 offers varying options, such as 8K, 16K, and 32K.\nAnthropic&#8217;s Claude AI model features a 100K token limit, and Meta&#8217;s recent research yielded a 1M token limit model.\n\nTo summarize the collected works of Shakespeare with GPT4, you need to devise software engineering strategies to chop up the data and present the data within the model&#8217;s context window limits.\nThe Spring AI project helps you with this task.',0x00,'asciidoc::concepts.adoc::Tokens::0'),
('41598382-90b8-4cff-89fd-c1b44f99f457','You can leverage the generic, portable <a href=\"api/vectordbs.html#metadata-filters\">metadata filters</a> with MariaDB Vector store.\n\nFor example, you can use either the text expression language:\n\nvectorStore.similaritySearch(\n    SearchRequest.builder()\n        .query(\"The World\")\n        .topK(TOP_K)\n        .similarityThreshold(SIMILARITY_THRESHOLD)\n        .filterExpression(\"author in [\'john\', \'jill\'] &amp;&amp; article_type == \'blog\'\").build());\n\nor programmatically using the <code>Filter.Expression</code> DSL:\n\nFilterExpressionBuilder b = new FilterExpressionBuilder();\n\nvectorStore.similaritySearch(SearchRequest.builder()\n    .query(\"The World\")\n    .topK(TOP_K)\n    .similarityThreshold(SIMILARITY_THRESHOLD)\n    .filterExpression(b.and(\n        b.in(\"author\", \"john\", \"jill\"),\n        b.eq(\"article_type\", \"blog\")).build()).build());\n\nThese filter expressions are automatically converted into the equivalent MariaDB JSON path expressions.',0x00,'asciidoc::mariadb.adoc::Metadata Filtering::0'),
('0572599f-a3f1-4328-beda-c1c4563bfa26','@SuppressWarnings({ \"all\", \"warnings\", \"unchecked\", \"unused\", \"cast\", \"CheckReturnValue\" })\npublic class FiltersParser extends Parser {\n\n    protected static final DFA[] _decisionToDFA;\n\n    protected static final PredictionContextCache _sharedContextCache = new PredictionContextCache();\n\n    public static final int LONG_SUFFIX = 1, WHERE = 2, DOT = 3, COMMA = 4, LEFT_SQUARE_BRACKETS = 5, RIGHT_SQUARE_BRACKETS = 6, LEFT_PARENTHESIS = 7, RIGHT_PARENTHESIS = 8, EQUALS = 9, MINUS = 10, PLUS = 11, GT = 12, GE = 13, LT = 14, LE = 15, NE = 16, AND = 17, OR = 18, IN = 19, NIN = 20, NOT = 21, BOOLEAN_VALUE = 22, QUOTED_STRING = 23, INTEGER_VALUE = 24, DECIMAL_VALUE = 25, IDENTIFIER = 26, WS = 27;\n\n    public static final int RULE_where = 0, RULE_booleanExpression = 1, RULE_constantArray = 2, RULE_compare = 3, RULE_identifier = 4, RULE_constant = 5;\n\n    private static String[] makeRuleNames() {\n        return new String[] { \"where\", \"booleanExpression\", \"constantArray\", \"compare\", \"identifier\", \"constant\" };\n    }\n\n    public static final String[] ruleNames = makeRuleNames();\n\n    private static String[] makeLiteralNames() {\n        return new String[] { null, null, null, \"\'.\'\", \"\',\'\", \"\'[\'\", \"\']\'\", \"\'(\'\", \"\')\'\", \"\'==\'\", \"\'-\'\", \"\'+\'\", \"\'>\'\", \"\'>=\'\", \"\'<\'\", \"\'<=\'\", \"\'!=\'\" };\n    }\n\n    private static final String[] _LITERAL_NAMES = makeLiteralNames();\n\n    private static String[] makeSymbolicNames() {\n        return new String[] { null, \"LONG_SUFFIX\", \"WHERE\", \"DOT\", \"COMMA\", \"LEFT_SQUARE_BRACKETS\", \"RIGHT_SQUARE_BRACKETS\", \"LEFT_PARENTHESIS\", \"RIGHT_PARENTHESIS\", \"EQUALS\", \"MINUS\", \"PLUS\", \"GT\", \"GE\", \"LT\", \"LE\", \"NE\", \"AND\", \"OR\", \"IN\", \"NIN\", \"NOT\", \"BOOLEAN_VALUE\", \"QUOTED_STRING\", \"INTEGER_VALUE\", \"DECIMAL_VALUE\", \"IDENTIFIER\", \"WS\" };\n    }\n\n    private static final String[] _SYMBOLIC_NAMES = makeSymbolicNames();\n\n    public static final Vocabulary VOCABULARY = new VocabularyImpl(_LITERAL_NAMES, _SYMBOLIC_NAMES);\n\n    /**\n     * @deprecated Use {@link #VOCABULARY} instead.\n     */\n    @Deprecated\n    public static final String[] tokenNames;\n\n    static {\n        tokenNames = new String[_SYMBOLIC_NAMES.length];\n        for (int i = 0; i < tokenNames.length; i++) {\n            tokenNames[i] = VOCABULARY.getLiteralName(i);\n            if (tokenNames[i] == null) {\n                tokenNames[i] = VOCABULARY.getSymbolicName(i);\n            }\n            if (tokenNames[i] == null) {\n                tokenNames[i] = \"<INVALID>\";\n            }\n        }\n    }\n\n    @Override\n    @Deprecated\n    public String[] getTokenNames() {\n        return tokenNames;\n    }\n\n    @Override\n    public Vocabulary getVocabulary() {\n        return VOCABULARY;\n    }\n\n    @Override\n    public String getGrammarFileName() {\n        return \"Filters.g4\";\n    }\n\n    @Override\n    public String[] getRuleNames() {\n        return ruleNames;\n    }\n\n    @Override\n    public String getSerializedATN() {\n        return _serializedATN;\n    }\n\n    @Override\n    public ATN getATN() {\n        return _ATN;\n    }\n\n    public FiltersParser(TokenStream input) {\n        super(input);\n        _interp = new ParserATNSimulator(this, _ATN, _decisionToDFA, _sharedContextCache);\n    }\n\n    @SuppressWarnings(\"CheckReturnValue\")\n    public static class WhereContext extends ParserRuleContext {\n\n        public TerminalNode WHERE() {\n            return getToken(FiltersParser.WHERE, 0);\n        }\n\n        public BooleanExpressionContext booleanExpression() {\n            return getRuleContext(BooleanExpressionContext.class, 0);\n        }\n\n        public TerminalNode EOF() {\n            return getToken(FiltersParser.EOF, 0);\n        }\n\n        public WhereContext(ParserRuleContext parent, int invokingState) {\n            super(parent, invokingState);\n        }\n\n        @Override\n        public int getRuleIndex() {\n            return RULE_where;\n        }\n\n        @Override\n        public void enterRule(ParseTreeListener listener) {\n            if (listener instanceof FiltersListener)\n                ((FiltersListener) listener).enterWhere(this);\n        }\n\n        @Override\n        public void exitRule(ParseTreeListener listener) {\n            if (listener instanceof FiltersListener)\n                ((FiltersListener) listener).exitWhere(this);\n        }\n\n        @Override\n        public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n            if (visitor instanceof FiltersVisitor)\n                return ((FiltersVisitor<? extends T>) visitor).visitWhere(this);\n            else\n                return visitor.visitChildren(this);\n        }\n    }\n\n    public final WhereContext where() throws RecognitionException {\n        WhereContext _localctx = new WhereContext(_ctx, getState());\n        enterRule(_localctx, 0, RULE_where);\n        try {\n            enterOuterAlt(_localctx, 1);\n            {\n                setState(12);\n                match(WHERE);\n                setState(13);\n                booleanExpression(0);\n                setState(14);\n                match(EOF);\n            }\n        } catch (RecognitionException re) {\n            _localctx.exception = re;\n            _errHandler.reportError(this, re);\n            _errHandler.recover(this, re);\n        } finally {\n            exitRule();\n        }\n        return _localctx;\n    }\n\n    @SuppressWarnings(\"CheckReturnValue\")\n    public static class BooleanExpressionContext extends ParserRuleContext {\n\n        public BooleanExpressionContext(ParserRuleContext parent, int invokingState) {\n            super(parent, invokingState);\n        }\n\n        @Override\n        public int getRuleIndex() {\n            return RULE_booleanExpression;\n        }\n\n        public BooleanExpressionContext() {\n        }\n\n        public void copyFrom(BooleanExpressionContext ctx) {\n            super.copyFrom(ctx);\n        }\n    }\n\n    @SuppressWarnings(\"CheckReturnValue\")\n    public static class NinExpressionContext extends BooleanExpressionContext {\n\n        public IdentifierContext identifier() {\n            return getRuleContext(IdentifierContext.class, 0);\n        }\n\n        public ConstantArrayContext constantArray() {\n            return getRuleContext(ConstantArrayContext.class, 0);\n        }\n\n        public TerminalNode NOT() {\n            return getToken(FiltersParser.NOT, 0);\n        }\n\n        public TerminalNode IN() {\n            return getToken(FiltersParser.IN, 0);\n        }\n\n        public TerminalNode NIN() {\n            return getToken(FiltersParser.NIN, 0);\n        }\n\n        public NinExpressionContext(BooleanExpressionContext ctx) {\n            copyFrom(ctx);\n        }\n\n        @Override\n        public void enterRule(ParseTreeListener listener) {\n            if (listener instanceof FiltersListener)\n                ((FiltersListener) listener).enterNinExpression(this);\n        }\n\n        @Override\n        public void exitRule(ParseTreeListener listener) {\n            if (listener instanceof FiltersListener)\n                ((FiltersListener) listener).exitNinExpression(this);\n        }\n\n        @Override\n        public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n            if (visitor instanceof FiltersVisitor)\n                return ((FiltersVisitor<? extends T>) visitor).visitNinExpression(this);\n            else\n                return visitor.visitChildren(this);\n        }\n    }\n\n    @SuppressWarnings(\"CheckReturnValue\")\n    public static class AndExpressionContext extends BooleanExpressionContext {\n\n        public BooleanExpressionContext left;\n\n        public Token operator;\n\n        public BooleanExpressionContext right;\n\n        public List<BooleanExpressionContext> booleanExpression() {\n            return getRuleContexts(BooleanExpressionContext.class);\n        }\n\n        public BooleanExpressionContext booleanExpression(int i) {\n            return getRuleContext(BooleanExpressionContext.class, i);\n        }\n\n        public TerminalNode AND() {\n            return getToken(FiltersParser.AND, 0);\n        }\n\n        public AndExpressionContext(BooleanExpressionContext ctx) {\n            copyFrom(ctx);\n        }\n\n        @Override\n        public void enterRule(ParseTreeListener listener) {\n            if (listener instanceof FiltersListener)\n                ((FiltersListener) listener).enterAndExpression(this);\n        }\n\n        @Override\n        public void exitRule(ParseTreeListener listener) {\n            if (listener instanceof FiltersListener)\n                ((FiltersListener) listener).exitAndExpression(this);\n        }\n\n        @Override\n        public <T> T accept(ParseTreeVisitor<? extends T> visitor) {\n            if (visitor instanceof FiltersVisitor)\n                return ((FiltersVisitor<? extends T>) visitor).visitAndExpression(this);\n            else\n                return visitor.visitChildren(this);\n        }\n    }\n\n    @SuppressWarnings(\"CheckReturnValue\")\n    public static class InExpressionContext extends BooleanExpressionContext {\n\n        public IdentifierContext identifier() {\n            return getRuleContext(IdentifierContext.class, 0);\n        }\n\n        public TerminalNode IN() {\n            return getToken(FiltersParser.IN, 0);\n        }\n\n        public ConstantArrayContext constantArray() {\n            return getRuleContext(ConstantArrayContext.class, 0);\n        }\n\n        public InExpressionContext(BooleanExpressionContext ctx) {\n            copyFrom(ctx);\n        }\n\n        @Override\n        public void enterRule(ParseTreeListener listener) {\n            if (listener instanceof FiltersListener)\n   